# Keep IST for consistent formatting
LOCAL_TZ = ZoneInfo("Asia/Kolkata")


def _safe_cache_ttl(raw_value, default: int) -> int:
    try:
        return max(0, int(raw_value))
    except Exception:
        return max(0, int(default))


ITEM_MASTER_QUERY_CACHE_TTL_SECONDS = _safe_cache_ttl(
    getattr(config, "ITEM_MASTER_QUERY_CACHE_TTL_SECONDS", 60),
    60,
)
ITEM_MASTER_QUERY_CACHE = {}
ITEM_MASTER_QUERY_CACHE_LOCK = Lock()
IVITEM_SCHEMA_READY_LOCK = Lock()
IVITEM_TECHNICAL_SPECS_READY_UNITS = set()
IVITEM_CONTRACTED_RATE_READY_UNITS = set()
CANTEEN_META_CACHE_TTL_SECONDS = _safe_cache_ttl(
    getattr(config, "CANTEEN_META_CACHE_TTL_SECONDS", 120),
    120,
)
CANTEEN_META_CACHE = {}
CANTEEN_META_CACHE_LOCK = Lock()
PATIENT_SEARCH_CACHE_TTL_SECONDS = _safe_cache_ttl(
    getattr(config, "PATIENT_SEARCH_CACHE_TTL_SECONDS", 45),
    45,
)
PATIENT_SEARCH_CACHE = {}
PATIENT_SEARCH_CACHE_LOCK = Lock()


def _cache_unit_key(unit: str | None) -> str:
    return str(unit or "").strip().upper()


def _clone_item_master_cache_payload(payload):
    if isinstance(payload, pd.DataFrame):
        try:
            return payload.copy(deep=True)
        except Exception:
            return payload
    try:
        return copy.deepcopy(payload)
    except Exception:
        return payload


def _item_master_query_cache_get(name: str, *parts):
    if ITEM_MASTER_QUERY_CACHE_TTL_SECONDS <= 0:
        return None
    key = (name, *parts)
    now = time.time()
    with ITEM_MASTER_QUERY_CACHE_LOCK:
        entry = ITEM_MASTER_QUERY_CACHE.get(key)
        if not entry:
            return None
        if float(entry.get("expires_at") or 0) <= now:
            ITEM_MASTER_QUERY_CACHE.pop(key, None)
            return None
        return _clone_item_master_cache_payload(entry.get("payload"))


def _item_master_query_cache_put(name: str, payload, *parts):
    if ITEM_MASTER_QUERY_CACHE_TTL_SECONDS <= 0 or payload is None:
        return
    key = (name, *parts)
    with ITEM_MASTER_QUERY_CACHE_LOCK:
        ITEM_MASTER_QUERY_CACHE[key] = {
            "payload": _clone_item_master_cache_payload(payload),
            "expires_at": time.time() + ITEM_MASTER_QUERY_CACHE_TTL_SECONDS,
        }


def invalidate_item_master_query_cache(unit: str | None = None):
    unit_key = _cache_unit_key(unit)
    with ITEM_MASTER_QUERY_CACHE_LOCK:
        for cache_key in list(ITEM_MASTER_QUERY_CACHE.keys()):
            if unit_key and (len(cache_key) < 2 or cache_key[1] != unit_key):
                continue
            ITEM_MASTER_QUERY_CACHE.pop(cache_key, None)


def _canteen_meta_cache_get(name: str, unit: str):
    if CANTEEN_META_CACHE_TTL_SECONDS <= 0:
        return None
    key = (str(name or "").strip().lower(), _cache_unit_key(unit))
    now = time.time()
    with CANTEEN_META_CACHE_LOCK:
        entry = CANTEEN_META_CACHE.get(key)
        if not entry:
            return None
        if float(entry.get("expires_at") or 0) <= now:
            CANTEEN_META_CACHE.pop(key, None)
            return None
        payload = entry.get("payload")
        if isinstance(payload, pd.DataFrame):
            try:
                return payload.copy(deep=True)
            except Exception:
                return payload
        return copy.deepcopy(payload)


def _canteen_meta_cache_put(name: str, unit: str, payload):
    if CANTEEN_META_CACHE_TTL_SECONDS <= 0 or payload is None:
        return
    key = (str(name or "").strip().lower(), _cache_unit_key(unit))
    if isinstance(payload, pd.DataFrame):
        try:
            cached_payload = payload.copy(deep=True)
        except Exception:
            cached_payload = payload
    else:
        cached_payload = copy.deepcopy(payload)
    with CANTEEN_META_CACHE_LOCK:
        CANTEEN_META_CACHE[key] = {
            "payload": cached_payload,
            "expires_at": time.time() + CANTEEN_META_CACHE_TTL_SECONDS,
        }


def invalidate_canteen_meta_cache(unit: str | None = None):
    unit_key = _cache_unit_key(unit)
    with CANTEEN_META_CACHE_LOCK:
        for cache_key in list(CANTEEN_META_CACHE.keys()):
            if unit_key and (len(cache_key) < 2 or cache_key[1] != unit_key):
                continue
            CANTEEN_META_CACHE.pop(cache_key, None)


def _patient_search_cache_get(unit: str, query: str, limit: int):
    if PATIENT_SEARCH_CACHE_TTL_SECONDS <= 0:
        return None
    key = (_cache_unit_key(unit), str(query or "").strip().upper(), int(limit or 0))
    now = time.time()
    with PATIENT_SEARCH_CACHE_LOCK:
        entry = PATIENT_SEARCH_CACHE.get(key)
        if not entry:
            return None
        if float(entry.get("expires_at") or 0) <= now:
            PATIENT_SEARCH_CACHE.pop(key, None)
            return None
        payload = entry.get("payload")
        if isinstance(payload, pd.DataFrame):
            try:
                return payload.copy(deep=True)
            except Exception:
                return payload
        return copy.deepcopy(payload)


def _patient_search_cache_put(unit: str, query: str, limit: int, payload):
    if PATIENT_SEARCH_CACHE_TTL_SECONDS <= 0 or payload is None:
        return
    cached_payload = payload
    if isinstance(payload, pd.DataFrame):
        try:
            cached_payload = payload.copy(deep=True)
        except Exception:
            cached_payload = payload
    else:
        cached_payload = copy.deepcopy(payload)
    key = (_cache_unit_key(unit), str(query or "").strip().upper(), int(limit or 0))
    with PATIENT_SEARCH_CACHE_LOCK:
        PATIENT_SEARCH_CACHE[key] = {
            "payload": cached_payload,
            "expires_at": time.time() + PATIENT_SEARCH_CACHE_TTL_SECONDS,
        }


def _schema_ready_contains(store: set[str], unit: str | None) -> bool:
    unit_key = _cache_unit_key(unit)
    if not unit_key:
        return False
    with IVITEM_SCHEMA_READY_LOCK:
        return unit_key in store


def _mark_schema_ready(store: set[str], unit: str | None):
    unit_key = _cache_unit_key(unit)
    if not unit_key:
        return
    with IVITEM_SCHEMA_READY_LOCK:
        store.add(unit_key)


def _clean_utr_text(value) -> str:
    if value is None:
        return ""
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    if isinstance(value, bool):
        txt = str(value).strip()
    elif isinstance(value, int):
        txt = str(int(value))
    elif isinstance(value, float):
        txt = str(int(value)) if value.is_integer() else format(value, "f").rstrip("0").rstrip(".")
    elif isinstance(value, Decimal):
        txt = format(value, "f").rstrip("0").rstrip(".")
    else:
        txt = str(value).strip()
    return txt.replace(",", "")

def fetch_revenue(unit, from_date, to_date):
    """
    Fetches revenue summary from a specific unit (AHL/ACI/BALLIA)
    using stored procedure Usp_CorpsubmitBillSummaryupdate.
    (Unchanged from your version)
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"âš ï¸ Could not connect to {unit}")
        return None

    try:
        query = f"""
        EXEC Usp_CorpsubmitBillSummaryupdate
            @FromDate = '{from_date}',
            @ToDate = '{to_date}'
        """
        df = pd.read_sql(query, conn)
        df['Unit'] = unit
        return df
    except Exception as e:
        print(f"âŒ Error fetching revenue from {unit}: {e}")
        return None
    finally:
        conn.close()


# ===================== Corporate Bill Summary (Ballia) =====================
def fetch_corporate_bill_summary(unit: str, from_date: str, to_date: str, visit_type: int = 0):
    """
    Calls dbo.Usp_Get_Corp_Bill_Summary_ByType for a given unit (Ballia expected).
    visit_type: 0=All, 1=IPD, 2=OPD, 3=DPV
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"ï¿½sï¿½ï¿½,? Could not connect to {unit} for corporate bill summary")
        return None
    try:
        sql = "EXEC dbo.Usp_Get_Corp_Bill_Summary_ByType ?, ?, ?"
        df = pd.read_sql(sql, conn, params=[from_date, to_date, visit_type])
        if df is None or df.empty:
            return df
        df.columns = [c.strip() for c in df.columns]
        df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"ï¿½?O Error fetching corporate summary ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Collections / Receipts Summary =====================
def fetch_receipt_summary(unit: str, from_date: str, to_date: str):
    """
    Executes dbo.Usp_ReceiptSummary for the given unit and date range.
    Returns raw dataframe with columns stripped + Unit column stamped.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"âš ï¸ Could not connect to {unit} for receipt summary")
        return None
    try:
        sql = "EXEC dbo.Usp_ReceiptSummary ?, ?"
        df = pd.read_sql(sql, conn, params=[from_date, to_date])
        if df is None or df.empty:
            return df
        df.columns = [c.strip() for c in df.columns]
        df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"âš ï¸ Error fetching receipt summary ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


