def _canteen_unit_key(unit: str) -> str:
    return str(unit or "").strip().upper()


def _canteen_clean_text(value, max_length: int | None = None) -> str:
    if value is None:
        return ""
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    text = str(value).replace("\r", " ").replace("\n", " ").strip()
    text = re.sub(r"\s+", " ", text)
    if max_length and max_length > 0:
        return text[:max_length]
    return text


def _canteen_parse_datetime(value=None):
    if value is None or str(value).strip() == "":
        return datetime.now(tz=LOCAL_TZ).replace(tzinfo=None)
    if isinstance(value, datetime):
        return value.replace(tzinfo=None)
    if isinstance(value, date):
        return datetime.combine(value, datetime.min.time())
    raw = str(value).strip()
    for fmt in (
        "%Y-%m-%d %H:%M:%S",
        "%Y-%m-%d %H:%M",
        "%Y-%m-%dT%H:%M:%S",
        "%Y-%m-%dT%H:%M",
        "%Y-%m-%d",
        "%d-%m-%Y %H:%M:%S",
        "%d-%m-%Y %H:%M",
        "%d-%m-%Y",
    ):
        try:
            return datetime.strptime(raw[:19], fmt)
        except Exception:
            continue
    try:
        return datetime.fromisoformat(raw.replace("Z", ""))
    except Exception:
        return datetime.now(tz=LOCAL_TZ).replace(tzinfo=None)


def _canteen_resolve_date_range(from_date=None, to_date=None):
    today = datetime.now(tz=LOCAL_TZ).date()
    default_start = today.replace(day=1)
    start_dt = _canteen_parse_datetime(from_date).date() if from_date else default_start
    end_dt = _canteen_parse_datetime(to_date).date() if to_date else today
    if start_dt > end_dt:
        start_dt, end_dt = end_dt, start_dt
    return start_dt.isoformat(), end_dt.isoformat()


def _canteen_round_money(value) -> float:
    return float(_to_decimal(value, Decimal("0")).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))


def _canteen_normalize_billing_category(value: str = "") -> str:
    key = _canteen_clean_text(value, 60).lower().replace("-", "_").replace(" ", "_")
    if key in {"room", "room_service", "roomservice", "room_service_billing"}:
        return CANTEEN_BILLING_CATEGORY_ROOM_SERVICE
    if key in {"bulk", "large", "large_order", "large_orders", "institutional", "bulk_institutional", "bulk_orders"}:
        return CANTEEN_BILLING_CATEGORY_BULK
    return CANTEEN_BILLING_CATEGORY_GENERAL


def _canteen_billing_category_label(category_key: str) -> str:
    return CANTEEN_BILLING_CATEGORY_LABELS.get(
        _canteen_normalize_billing_category(category_key),
        CANTEEN_BILLING_CATEGORY_LABELS[CANTEEN_BILLING_CATEGORY_GENERAL],
    )


def _canteen_normalize_customer_kind(value: str = "") -> str:
    key = _canteen_clean_text(value, 60).lower().replace("-", "_").replace(" ", "_")
    if key in {"staff", "management", "office_staff", "employee"}:
        return "staff"
    return "patient"


def _canteen_customer_kind_label(kind: str) -> str:
    key = _canteen_normalize_customer_kind(kind)
    return "Staff" if key == "staff" else "Patient"


def _canteen_normalize_bulk_subcategory(value: str = "") -> str:
    key = _canteen_clean_text(value, 80).lower().replace("-", "_").replace(" ", "_").replace("/", "_")
    if key in {"double", "double_duty", "double_duty_staff", "double_duty_staff_orders"}:
        return "double_duty"
    if key in {"student", "students", "college", "college_students", "institutional", "student_institutional", "student_institutional_orders"}:
        return "student_institutional"
    if key in {"party", "party_order", "party_orders"}:
        return "party"
    return ""


def _canteen_bulk_subcategory_label(subcategory_key: str) -> str:
    key = _canteen_normalize_bulk_subcategory(subcategory_key)
    return CANTEEN_BULK_SUBCATEGORY_LABELS.get(key, "")


def _canteen_bulk_notification_roles(subcategory_key: str) -> list[str]:
    key = _canteen_normalize_bulk_subcategory(subcategory_key)
    return list(CANTEEN_BULK_NOTIFICATION_ROLE_KEYS.get(key, []))


