def _canteen_billing_types_ready(unit: str) -> bool:
    unit_key = _canteen_unit_key(unit)
    with CANTEEN_BILLING_TYPES_LOCK:
        return unit_key in CANTEEN_BILLING_TYPES_READY_UNITS


def ensure_canteen_billing_type_rows(unit: str) -> bool:
    unit_key = _canteen_unit_key(unit)
    if unit_key not in CANTEEN_ALLOWED_UNITS:
        return False
    if _canteen_billing_types_ready(unit_key):
        return True
    conn = get_canteen_sql_connection(unit_key)
    if not conn:
        print(f"Canteen billing types: could not connect to {unit_key}")
        return False
    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cur = conn.cursor()
        cur.execute(
            """
            SELECT
                  CAST(ISNULL(id, 0) AS INT) AS TypeID
                , LTRIM(RTRIM(ISNULL(Typename, N''))) AS TypeName
                , CAST(ISNULL(credittag, 0) AS INT) AS CreditTag
            FROM dbo.tbl_typemst WITH (UPDLOCK, HOLDLOCK);
            """
        )
        existing_rows = _rows_as_dicts(cur) if cur.description is not None else []
        existing_map = {
            _to_int(row.get("TypeID"), 0) or 0: {
                "type_name": _canteen_clean_text(row.get("TypeName"), 120),
                "credit_tag": _to_int(row.get("CreditTag"), 0) or 0,
            }
            for row in existing_rows
            if (_to_int(row.get("TypeID"), 0) or 0) > 0
        }
        expected_rows = {
            CANTEEN_ROOM_SERVICE_PATIENT_TYPE_ID: ("Room Service-Patient", 0),
            CANTEEN_ROOM_SERVICE_DELIVERY_TYPE_ID: ("Room Service-Delivery", 0),
            CANTEEN_PREPAID_TYPE_ID: ("Prepaid", 0),
        }
        changed = False
        for type_id_int, (type_name_text, credit_tag_int) in expected_rows.items():
            existing = existing_map.get(type_id_int)
            if existing:
                if existing.get("type_name") != type_name_text or (_to_int(existing.get("credit_tag"), 0) or 0) != credit_tag_int:
                    cur.execute(
                        """
                        UPDATE dbo.tbl_typemst
                        SET
                            Typename = ?,
                            credittag = ?
                        WHERE id = ?;
                        """,
                        (type_name_text, credit_tag_int, type_id_int),
                    )
                    changed = True
            else:
                cur.execute(
                    """
                    INSERT INTO dbo.tbl_typemst (id, Typename, credittag)
                    VALUES (?, ?, ?);
                    """,
                    (type_id_int, type_name_text, credit_tag_int),
                )
                changed = True
        if changed:
            conn.commit()
            invalidate_canteen_meta_cache(unit_key)
        else:
            try:
                conn.rollback()
            except Exception:
                pass
        with CANTEEN_BILLING_TYPES_LOCK:
            CANTEEN_BILLING_TYPES_READY_UNITS.add(unit_key)
        return True
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        print(f"Failed to ensure canteen billing types for {unit_key}: {e}")
        return False
    finally:
        try:
            conn.close()
        except Exception:
            pass


def canteen_ui_type_snapshot(type_id: int | None = None, type_name: str = "", credit_tag: int | None = None) -> dict:
    try:
        type_id_int = int(type_id or 0)
    except Exception:
        type_id_int = 0
    name_key = _canteen_clean_text(type_name).lower()
    credit_tag_int = _to_int(credit_tag, 0) or 0

    if type_id_int == CANTEEN_STEWARD_TYPE_ID or "steward" in name_key or "stuward" in name_key:
        return {
            "key": "steward",
            "type_id": CANTEEN_STEWARD_TYPE_ID,
            "type_name": "Steward",
            "credit_tag": 0,
            "legacy_type_ids": [CANTEEN_STEWARD_TYPE_ID],
        }
    if type_id_int == CANTEEN_PREPAID_TYPE_ID or "prepaid" in name_key:
        return {
            "key": "prepaid",
            "type_id": CANTEEN_PREPAID_TYPE_ID,
            "type_name": "Prepaid",
            "credit_tag": 0,
            "legacy_type_ids": [CANTEEN_PREPAID_TYPE_ID],
        }
    if type_id_int == CANTEEN_ROOM_SERVICE_DELIVERY_TYPE_ID or ("delivery" in name_key and "room" in name_key):
        return {
            "key": "room_service_delivery",
            "type_id": CANTEEN_ROOM_SERVICE_DELIVERY_TYPE_ID,
            "type_name": "Room Service-Delivery",
            "credit_tag": 0,
            "legacy_type_ids": [CANTEEN_ROOM_SERVICE_DELIVERY_TYPE_ID],
        }
    if type_id_int in CANTEEN_ROOM_SERVICE_TYPE_IDS or "room" in name_key:
        return {
            "key": "room_service_patient",
            "type_id": CANTEEN_ROOM_SERVICE_PATIENT_TYPE_ID,
            "type_name": "Room Service-Patient",
            "credit_tag": 0,
            "legacy_type_ids": sorted(CANTEEN_ROOM_SERVICE_TYPE_IDS),
        }
    if (
        type_id_int in CANTEEN_CREDIT_TYPE_IDS
        or "credit" in name_key
        or "stc" in name_key
        or ("staff" in name_key and "canteen staff" not in name_key)
        or credit_tag_int > 0
    ):
        return {
            "key": "credit",
            "type_id": 3,
            "type_name": "Credit",
            "credit_tag": 1,
            "legacy_type_ids": sorted(CANTEEN_CREDIT_TYPE_IDS),
        }
    if type_id_int in CANTEEN_CASH_TYPE_IDS or "cash" in name_key or type_id_int <= 0:
        return {
            "key": "cash",
            "type_id": 1,
            "type_name": "Cash",
            "credit_tag": 0,
            "legacy_type_ids": sorted(CANTEEN_CASH_TYPE_IDS),
        }
    return {
        "key": "cash",
        "type_id": 1,
        "type_name": "Cash",
        "credit_tag": 0,
        "legacy_type_ids": [type_id_int] if type_id_int > 0 else sorted(CANTEEN_CASH_TYPE_IDS),
    }


def canteen_legacy_type_ids_for_ui_type(type_id: int | None = None, type_name: str = "") -> list[int]:
    snapshot = canteen_ui_type_snapshot(type_id=type_id, type_name=type_name)
    legacy_ids = [(_to_int(value, 0) or 0) for value in (snapshot.get("legacy_type_ids") or [])]
    return [value for value in legacy_ids if value > 0]


def _canteen_type_allows_due(type_id: int | None = None, type_name: str = "", credit_tag: int | None = None) -> bool:
    snapshot = canteen_ui_type_snapshot(type_id=type_id, type_name=type_name, credit_tag=credit_tag)
    key = str(snapshot.get("key") or "").strip().lower()
    return key in {"credit", "room_service_patient", "room_service_delivery"} or (_to_int(credit_tag, 0) or 0) > 0


def _canteen_rate_key(type_id: int | None, type_name: str = "") -> str:
    snapshot = canteen_ui_type_snapshot(type_id=type_id, type_name=type_name)
    if str(snapshot.get("key") or "").strip().lower() in {"room_service_patient", "room_service_delivery"}:
        return "roomservice"
    return "rate"


def _canteen_effective_rate(row: dict, type_id: int | None = None, type_name: str = "") -> float:
    key = _canteen_rate_key(type_id, type_name)
    ordered_keys = [key]
    if key != "rate":
        ordered_keys.append("rate")
    if key != "staffrate":
        ordered_keys.append("staffrate")
    if key != "roomservice":
        ordered_keys.append("roomservice")
    for candidate in ordered_keys:
        amount = _safe_float(row.get(candidate), None)
        if amount is None:
            continue
        if amount > 0 or candidate == "rate":
            return round(amount, 2)
    return 0.0


