def _canteen_login_db_connection():
    cfg = getattr(config, "LOGIN_DB", {}) or {}
    driver = cfg.get("DRIVER") or "{ODBC Driver 18 for SQL Server}"
    server = cfg.get("SERVER") or ""
    database = cfg.get("DATABASE") or cfg.get("DB") or ""
    uid = cfg.get("UID") or cfg.get("USER") or ""
    pwd = cfg.get("PWD") or ""
    timeout = int(cfg.get("Connection Timeout") or cfg.get("TIMEOUT") or 5)
    conn_str = (
        f"DRIVER={driver};"
        f"SERVER={server};"
        f"DATABASE={database};"
        f"UID={uid};"
        f"PWD={pwd};"
        "Encrypt=yes;"
        "TrustServerCertificate=yes;"
    )
    return pyodbc.connect(conn_str, timeout=timeout, autocommit=True)


def _canteen_chunked(values, size: int = 900):
    items = list(values or [])
    step = max(1, int(size or 900))
    for start in range(0, len(items), step):
        yield items[start:start + step]


def _canteen_scope_rank(scope_text: str, unit: str) -> int:
    unit_key = _canteen_unit_key(unit)
    scope_key = _canteen_clean_text(scope_text).upper()
    if not scope_key:
        return 2
    parts = [part.strip().upper() for part in re.split(r"[,|/]+", scope_key) if part.strip()]
    if unit_key and unit_key in parts:
        return 0
    if "*" in parts or "ALL" in parts:
        return 1
    return 3


def _canteen_fetch_hid_user_map(unit: str, account_ids) -> dict[int, str]:
    ids = sorted({_to_int(value, 0) or 0 for value in (account_ids or []) if (_to_int(value, 0) or 0) > 0})
    if not ids:
        return {}
    conn = None
    try:
        conn = _canteen_login_db_connection()
        records = []
        for chunk in _canteen_chunked(ids):
            placeholders = ",".join("?" for _ in chunk)
            sql = f"""
            SELECT
                  CAST(AccountId AS INT) AS AccountID
                , LTRIM(RTRIM(ISNULL(UserName, N''))) AS UserName
                , LTRIM(RTRIM(ISNULL(UnitScope, N''))) AS UnitScope
                , CAST(ISNULL(IsActive, 1) AS BIT) AS IsActive
                , CAST(ISNULL(Id, 0) AS INT) AS RowID
            FROM dbo.HID_User_Mst WITH (NOLOCK)
            WHERE CAST(AccountId AS INT) IN ({placeholders});
            """
            chunk_df = pd.read_sql(sql, conn, params=chunk)
            if chunk_df is not None and not chunk_df.empty:
                records.extend(chunk_df.to_dict(orient="records"))
        chosen = {}
        for row in records:
            account_id = _to_int(row.get("AccountID"), 0) or 0
            if account_id <= 0:
                continue
            username = _canteen_clean_text(row.get("UserName"), 120)
            if not username:
                continue
            candidate = (
                _canteen_scope_rank(row.get("UnitScope"), unit),
                0 if bool(row.get("IsActive", True)) else 1,
                -(_to_int(row.get("RowID"), 0) or 0),
                username.lower(),
            )
            current = chosen.get(account_id)
            if current is None or candidate < current[0]:
                chosen[account_id] = (candidate, username)
        return {account_id: value[1] for account_id, value in chosen.items()}
    except Exception as e:
        print(f"Canteen HID user lookup failed for {unit}: {e}")
        return {}
    finally:
        try:
            if conn is not None:
                conn.close()
        except Exception:
            pass


def _canteen_fetch_legacy_bill_user_map(conn, account_ids) -> dict[int, str]:
    ids = sorted({_to_int(value, 0) or 0 for value in (account_ids or []) if (_to_int(value, 0) or 0) > 0})
    if not ids or conn is None:
        return {}
    try:
        rows = []
        for chunk in _canteen_chunked(ids):
            placeholders = ",".join("?" for _ in chunk)
            sql = f"""
            SELECT
                  CAST(id AS INT) AS LegacyUserID
                , LTRIM(RTRIM(ISNULL(Name, N''))) AS LegacyUserName
            FROM dbo.LABUserMasterUp WITH (NOLOCK)
            WHERE CAST(id AS INT) IN ({placeholders});
            """
            chunk_df = pd.read_sql(sql, conn, params=chunk)
            if chunk_df is not None and not chunk_df.empty:
                rows.extend(chunk_df.to_dict(orient="records"))
        out = {}
        for row in rows:
            legacy_id = _to_int(row.get("LegacyUserID"), 0) or 0
            legacy_name = _canteen_clean_text(row.get("LegacyUserName"), 120)
            if legacy_id > 0 and legacy_name and legacy_id not in out:
                out[legacy_id] = legacy_name
        return out
    except Exception as e:
        print(f"Canteen legacy user lookup failed: {e}")
        return {}


def _canteen_fetch_bill_meta_map(conn, unit: str, bill_ids) -> dict[int, dict]:
    ids = sorted({_to_int(value, 0) or 0 for value in (bill_ids or []) if (_to_int(value, 0) or 0) > 0})
    if not ids or conn is None or not ensure_canteen_bill_meta_table(unit):
        return {}
    try:
        rows = []
        for chunk in _canteen_chunked(ids):
            placeholders = ",".join("?" for _ in chunk)
            sql = f"""
            SELECT
                  CAST(BillID AS INT) AS BillID
                , CAST(ISNULL(CreatedByAccountID, 0) AS INT) AS CreatedByAccountID
                , LTRIM(RTRIM(ISNULL(CreatedByUserName, N''))) AS CreatedByUserName
                , LTRIM(RTRIM(ISNULL(CreatedSource, N''))) AS CreatedSource
            FROM dbo.HID_CanteenBillMeta WITH (NOLOCK)
            WHERE CAST(BillID AS INT) IN ({placeholders});
            """
            chunk_df = pd.read_sql(sql, conn, params=chunk)
            if chunk_df is not None and not chunk_df.empty:
                rows.extend(chunk_df.to_dict(orient="records"))
        out = {}
        for row in rows:
            bill_id = _to_int(row.get("BillID"), 0) or 0
            if bill_id <= 0:
                continue
            out[bill_id] = {
                "created_by_account_id": _to_int(row.get("CreatedByAccountID"), 0) or 0,
                "created_by_username": _canteen_clean_text(row.get("CreatedByUserName"), 120),
                "created_source": _canteen_clean_text(row.get("CreatedSource"), 20),
            }
        return out
    except Exception as e:
        print(f"Canteen bill meta lookup failed for {unit}: {e}")
        return {}


def _canteen_upsert_bill_meta(
    cursor,
    unit: str,
    bill_id: int,
    *,
    actor_user_id: int = 0,
    actor_username: str = "",
    billing_category: str = "",
    customer_kind: str = "",
    bulk_subcategory: str = "",
    pricing_category: str = "",
    payment_classification: str = "",
    requested_type_id: int = 0,
    requested_type_name: str = "",
):
    bill_id_int = _to_int(bill_id, 0) or 0
    if bill_id_int <= 0 or cursor is None or not ensure_canteen_bill_meta_table(unit):
        return False
    actor_user_id_int = _to_int(actor_user_id, 0) or 0
    actor_username_text = _canteen_clean_text(actor_username, 120)
    billing_category_key = _canteen_normalize_billing_category(billing_category)
    customer_kind_key = _canteen_normalize_customer_kind(customer_kind) if billing_category_key == CANTEEN_BILLING_CATEGORY_ROOM_SERVICE else ""
    bulk_subcategory_key = _canteen_normalize_bulk_subcategory(bulk_subcategory) if billing_category_key == CANTEEN_BILLING_CATEGORY_BULK else ""
    pricing_category_key = _canteen_clean_text(pricing_category, 40).lower() or (
        "room_service" if billing_category_key == CANTEEN_BILLING_CATEGORY_ROOM_SERVICE else "counter"
    )
    payment_classification_key = _canteen_clean_text(payment_classification, 40).lower()
    requested_type_id_int = _to_int(requested_type_id, 0) or None
    requested_type_name_text = _canteen_clean_text(requested_type_name, 120) or None
    try:
        cursor.execute(
            """
            UPDATE dbo.HID_CanteenBillMeta
            SET
                CreatedByAccountID = ?,
                CreatedByUserName = ?,
                BillingCategory = ?,
                BillingCategoryName = ?,
                CustomerKind = ?,
                CustomerKindName = ?,
                BulkSubcategory = ?,
                BulkSubcategoryName = ?,
                PricingCategory = ?,
                PaymentClassification = ?,
                RequestedTypeID = ?,
                RequestedTypeName = ?,
                CreatedSource = N'HID',
                UpdatedOn = GETDATE()
            WHERE BillID = ?;
            """,
            (
                actor_user_id_int if actor_user_id_int > 0 else None,
                actor_username_text or None,
                billing_category_key,
                _canteen_billing_category_label(billing_category_key),
                customer_kind_key or None,
                _canteen_customer_kind_label(customer_kind_key) if customer_kind_key else None,
                bulk_subcategory_key or None,
                _canteen_bulk_subcategory_label(bulk_subcategory_key) or None,
                pricing_category_key or None,
                payment_classification_key or None,
                requested_type_id_int,
                requested_type_name_text,
                bill_id_int,
            ),
        )
        if cursor.rowcount <= 0:
            cursor.execute(
                """
                INSERT INTO dbo.HID_CanteenBillMeta (
                    BillID, CreatedByAccountID, CreatedByUserName,
                    BillingCategory, BillingCategoryName,
                    CustomerKind, CustomerKindName,
                    BulkSubcategory, BulkSubcategoryName,
                    PricingCategory, PaymentClassification,
                    RequestedTypeID, RequestedTypeName,
                    CreatedSource, CreatedOn, UpdatedOn
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, N'HID', GETDATE(), GETDATE());
                """,
                (
                    bill_id_int,
                    actor_user_id_int if actor_user_id_int > 0 else None,
                    actor_username_text or None,
                    billing_category_key,
                    _canteen_billing_category_label(billing_category_key),
                    customer_kind_key or None,
                    _canteen_customer_kind_label(customer_kind_key) if customer_kind_key else None,
                    bulk_subcategory_key or None,
                    _canteen_bulk_subcategory_label(bulk_subcategory_key) or None,
                    pricing_category_key or None,
                    payment_classification_key or None,
                    requested_type_id_int,
                    requested_type_name_text,
                ),
            )
        return True
    except Exception as e:
        print(f"Canteen bill meta upsert failed for {unit} / bill {bill_id_int}: {e}")
        return False


