def _canteen_attach_bill_creator_columns(conn, unit: str, df):
    if df is None:
        return None
    work = df.copy()
    if work.empty:
        if "CreatedByAccountID" not in work.columns:
            work["CreatedByAccountID"] = pd.Series(dtype="Int64")
        if "CreatedByName" not in work.columns:
            work["CreatedByName"] = pd.Series(dtype="object")
        if "CreatedBySource" not in work.columns:
            work["CreatedBySource"] = pd.Series(dtype="object")
        return work
    work.columns = [str(col).strip() for col in work.columns]
    bill_id_col = next((col for col in ("BillID", "Bill_ID", "bill_id") if col in work.columns), None)
    if not bill_id_col:
        work["CreatedByAccountID"] = 0
        work["CreatedByName"] = ""
        work["CreatedBySource"] = ""
        return work

    bill_ids = sorted({
        _to_int(value, 0) or 0
        for value in work[bill_id_col].tolist()
        if (_to_int(value, 0) or 0) > 0
    })
    if not bill_ids:
        work["CreatedByAccountID"] = 0
        work["CreatedByName"] = ""
        work["CreatedBySource"] = ""
        return work

    bill_actor_map: dict[int, int] = {}
    try:
        for chunk in _canteen_chunked(bill_ids):
            placeholders = ",".join("?" for _ in chunk)
            actor_df = pd.read_sql(
                f"""
                SELECT
                      CAST(Bill_ID AS INT) AS BillID
                    , CAST(ISNULL(UpdatedBy, 0) AS INT) AS CreatedByAccountID
                FROM dbo.Billing_Mst WITH (NOLOCK)
                WHERE Bill_ID IN ({placeholders});
                """,
                conn,
                params=chunk,
            )
            if actor_df is None or actor_df.empty:
                continue
            actor_df.columns = [str(col).strip() for col in actor_df.columns]
            for row in actor_df.to_dict(orient="records"):
                bill_id = _to_int(row.get("BillID"), 0) or 0
                if bill_id > 0:
                    bill_actor_map[bill_id] = _to_int(row.get("CreatedByAccountID"), 0) or 0
    except Exception as e:
        print(f"Canteen bill actor lookup failed for {unit}: {e}")

    meta_map = _canteen_fetch_bill_meta_map(conn, unit, bill_ids)
    actor_ids = sorted({
        account_id
        for account_id in list(bill_actor_map.values()) + [meta.get("created_by_account_id") for meta in meta_map.values()]
        if (_to_int(account_id, 0) or 0) > 0
    })
    legacy_user_map = _canteen_fetch_legacy_bill_user_map(conn, actor_ids)
    hid_user_map = _canteen_fetch_hid_user_map(unit, actor_ids)

    created_by_ids = []
    created_by_names = []
    created_by_sources = []
    for row in work.to_dict(orient="records"):
        bill_id = _to_int(row.get(bill_id_col), 0) or 0
        meta = meta_map.get(bill_id) or {}
        actor_id = _to_int(meta.get("created_by_account_id"), 0) or bill_actor_map.get(bill_id, 0) or 0
        creator_name = _canteen_clean_text(meta.get("created_by_username"), 120)
        creator_source = _canteen_clean_text(meta.get("created_source"), 20)
        if not creator_name and actor_id > 0:
            creator_name = legacy_user_map.get(actor_id) or hid_user_map.get(actor_id) or ""
            if actor_id in legacy_user_map:
                creator_source = "legacy"
            elif actor_id in hid_user_map:
                creator_source = "hid"
        created_by_ids.append(actor_id)
        created_by_names.append(creator_name)
        created_by_sources.append(creator_source)

    work["CreatedByAccountID"] = created_by_ids
    work["CreatedByName"] = created_by_names
    work["CreatedBySource"] = created_by_sources
    return work


def fetch_canteen_types(unit: str):
    unit_key = _canteen_unit_key(unit)
    if unit_key not in CANTEEN_ALLOWED_UNITS:
        return pd.DataFrame()
    ensure_canteen_billing_type_rows(unit_key)
    cached = _canteen_meta_cache_get("types", unit_key)
    if cached is not None:
        return cached
    conn = get_canteen_sql_connection(unit_key)
    if not conn:
        print(f"Canteen types: could not connect to {unit_key}")
        return None
    try:
        df = pd.read_sql(
            """
            SELECT
                  CAST(ISNULL(id, 0) AS INT) AS TypeID
                , LTRIM(RTRIM(ISNULL(Typename, N''))) AS TypeName
                , CAST(ISNULL(credittag, 0) AS INT) AS CreditTag
            FROM dbo.tbl_typemst
            WHERE LTRIM(RTRIM(ISNULL(Typename, N''))) <> N''
            ORDER BY CAST(ISNULL(id, 0) AS INT);
            """,
            conn,
        )
        if df is None or df.empty:
            empty_df = pd.DataFrame(columns=["TypeID", "TypeName", "CreditTag"])
            _canteen_meta_cache_put("types", unit_key, empty_df)
            return empty_df
        df.columns = [str(col).strip() for col in df.columns]
        _canteen_meta_cache_put("types", unit_key, df)
        return df
    except Exception as e:
        print(f"Canteen types fetch failed for {unit_key}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_canteen_billing_types(unit: str):
    raw_df = fetch_canteen_types(unit)
    if raw_df is None:
        return None
    if raw_df.empty:
        return pd.DataFrame(columns=["TypeID", "TypeName", "CreditTag", "TypeKey"])

    available_keys = set()
    for row in raw_df.to_dict(orient="records"):
        snapshot = canteen_ui_type_snapshot(
            type_id=row.get("TypeID"),
            type_name=row.get("TypeName"),
            credit_tag=row.get("CreditTag"),
        )
        key = str(snapshot.get("key") or "").strip().lower()
        if key in {"cash", "room_service_patient", "room_service_delivery"}:
            available_keys.add(key)

    ordered_rows = []
    for key, fallback_type_id, fallback_name in (
        ("cash", 1, "Cash"),
        ("room_service_patient", CANTEEN_ROOM_SERVICE_PATIENT_TYPE_ID, "Room Service-Patient"),
        ("room_service_delivery", CANTEEN_ROOM_SERVICE_DELIVERY_TYPE_ID, "Room Service-Delivery"),
    ):
        if key not in available_keys and key != "cash":
            continue
        snapshot = canteen_ui_type_snapshot(type_id=fallback_type_id, type_name=fallback_name)
        ordered_rows.append(
            {
                "TypeID": int(snapshot.get("type_id") or 0),
                "TypeName": str(snapshot.get("type_name") or "").strip(),
                "CreditTag": int(snapshot.get("credit_tag") or 0),
                "TypeKey": str(snapshot.get("key") or "").strip(),
            }
        )
    return pd.DataFrame(ordered_rows, columns=["TypeID", "TypeName", "CreditTag", "TypeKey"])


