def _canteen_cancel_status_is_active(value) -> bool:
    text = _canteen_clean_text(value).lower()
    return text in {"1", "true", "yes", "y", "cancelled", "canceled"}


def _canteen_request_type_key(value) -> str:
    text = _canteen_clean_text(value, 40).upper()
    if text == "PAYMENT_MODE_CHANGE":
        return "PAYMENT_MODE_CHANGE"
    if text == "WALLET_TOPUP_PAYMENT_MODE_CHANGE":
        return "WALLET_TOPUP_PAYMENT_MODE_CHANGE"
    if text == "RECEIPT_TYPE_CHANGE":
        return "RECEIPT_TYPE_CHANGE"
    if text == "RECEIPT_CANCELLATION":
        return "RECEIPT_CANCELLATION"
    if text == "WALLET_TOPUP_CANCELLATION":
        return "WALLET_TOPUP_CANCELLATION"
    return "CANCELLATION"


def _canteen_request_type_label(value) -> str:
    request_type = _canteen_request_type_key(value)
    if request_type == "PAYMENT_MODE_CHANGE":
        return "Payment Mode Change"
    if request_type == "WALLET_TOPUP_PAYMENT_MODE_CHANGE":
        return "Wallet Top-up Payment Mode Change"
    if request_type == "RECEIPT_TYPE_CHANGE":
        return "Receipt Type Change"
    if request_type == "RECEIPT_CANCELLATION":
        return "Receipt Cancellation"
    if request_type == "WALLET_TOPUP_CANCELLATION":
        return "Wallet Top-up Cancellation"
    return "Bill Cancellation"


def _canteen_parse_text_list(value) -> list[str]:
    raw = _canteen_clean_text(value)
    if not raw:
        return []
    try:
        parsed = json.loads(raw)
    except Exception:
        parsed = None
    if isinstance(parsed, list):
        items = [_canteen_clean_text(item, 200) for item in parsed]
        return [item for item in items if item]
    if raw.startswith("[") and raw.endswith("]"):
        return []
    return [part.strip() for part in raw.split(",") if str(part).strip()]


def _canteen_cancellation_row_to_dict(row: dict) -> dict:
    bill_date = row.get("BillDate")
    requested_on = row.get("RequestedOn")
    processed_on = row.get("ProcessedOn")
    recalled_on = row.get("RecalledOn")
    request_type = _canteen_request_type_key(row.get("RequestType"))
    receipt_ids_list = _canteen_parse_text_list(row.get("ReceiptIDs"))
    receipt_nos_list = _canteen_parse_text_list(row.get("ReceiptNos"))
    receipt_no = _canteen_clean_text(row.get("ReceiptNo"), 80)
    if receipt_no and receipt_no not in receipt_nos_list:
        receipt_nos_list.insert(0, receipt_no)
    return {
        "request_id": _to_int(row.get("RequestID"), 0) or 0,
        "request_type": request_type,
        "request_type_label": _canteen_request_type_label(request_type),
        "unit": _canteen_clean_text(row.get("Unit"), 20),
        "bill_id": _to_int(row.get("BillID"), 0) or 0,
        "bill_no": _canteen_clean_text(row.get("BillNo"), 80),
        "bill_date": bill_date.strftime("%Y-%m-%d %H:%M:%S") if isinstance(bill_date, datetime) else _canteen_clean_text(bill_date),
        "customer_label": _canteen_clean_text(row.get("CustomerLabel"), 200),
        "type_name": _canteen_clean_text(row.get("TypeName"), 100),
        "net_amount": _safe_float(row.get("NetAmount"), 0),
        "received_amount": _safe_float(row.get("ReceivedAmount"), 0),
        "due_amount": _safe_float(row.get("DueAmount"), 0),
        "wallet_txn_id": _to_int(row.get("WalletTxnID"), 0) or 0,
        "receipt_id": _to_int(row.get("ReceiptID"), 0) or 0,
        "receipt_no": receipt_no,
        "receipt_ids": ", ".join(receipt_ids_list),
        "receipt_ids_list": receipt_ids_list,
        "receipt_nos": ", ".join(receipt_nos_list),
        "receipt_nos_list": receipt_nos_list,
        "receipt_amount": _safe_float(row.get("ReceiptAmount"), 0),
        "current_payment_mode_id": _to_int(row.get("CurrentPaymentModeID"), 0) or 0,
        "current_payment_mode": _canteen_clean_text(row.get("CurrentPaymentMode"), 120),
        "requested_payment_mode_id": _to_int(row.get("RequestedPaymentModeID"), 0) or 0,
        "requested_payment_mode": _canteen_clean_text(row.get("RequestedPaymentMode"), 120),
        "current_type_id": _to_int(row.get("CurrentTypeID"), 0) or 0,
        "current_type_name": _canteen_clean_text(row.get("CurrentTypeName"), 120) or _canteen_clean_text(row.get("TypeName"), 100),
        "requested_type_id": _to_int(row.get("RequestedTypeID"), 0) or 0,
        "requested_type_name": _canteen_clean_text(row.get("RequestedTypeName"), 120),
        "status": _canteen_clean_text(row.get("Status"), 20).upper() or "PENDING",
        "reason": _canteen_clean_text(row.get("Reason"), 500),
        "requested_by_account_id": _to_int(row.get("RequestedByAccountID"), 0) or 0,
        "requested_by": _canteen_clean_text(row.get("RequestedByUserName"), 120),
        "requested_on": requested_on.strftime("%Y-%m-%d %H:%M:%S") if isinstance(requested_on, datetime) else _canteen_clean_text(requested_on),
        "recalled_by": _canteen_clean_text(row.get("RecalledByUserName"), 120),
        "recalled_on": recalled_on.strftime("%Y-%m-%d %H:%M:%S") if isinstance(recalled_on, datetime) else _canteen_clean_text(recalled_on),
        "processed_by": _canteen_clean_text(row.get("ProcessedByUserName"), 120),
        "processed_on": processed_on.strftime("%Y-%m-%d %H:%M:%S") if isinstance(processed_on, datetime) else _canteen_clean_text(processed_on),
        "decision_note": _canteen_clean_text(row.get("DecisionNote"), 500),
        "applied_bill_cancel": bool(row.get("AppliedBillCancel")),
        "applied_receipt_cancel": bool(row.get("AppliedReceiptCancel")),
        "applied_wallet_cancel": bool(row.get("AppliedWalletCancel")),
        "applied_payment_mode": bool(row.get("AppliedPaymentMode")),
        "applied_type_change": bool(row.get("AppliedTypeChange")),
    }


def _fetch_canteen_cancellation_bill_snapshot(unit: str, bill_id: int) -> dict | None:
    unit_key = _canteen_unit_key(unit)
    bill_id_int = _to_int(bill_id, 0) or 0
    if unit_key not in CANTEEN_ALLOWED_UNITS or bill_id_int <= 0:
        return None
    ensure_canteen_customer_meta_table(unit_key)
    conn = get_canteen_sql_connection(unit_key)
    if not conn:
        return None
    try:
        bill_sql = f"""
        SELECT TOP 1
              CAST(bm.Bill_ID AS INT) AS BillID
            , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
            , CAST(bm.BillDate AS DATETIME) AS BillDate
            , COALESCE(
                  NULLIF(LTRIM(RTRIM(ISNULL(cm.LedgerName, N''))), N''),
                  NULLIF(LTRIM(RTRIM(ISNULL(tp.Name, N''))), N''),
                  NULLIF(LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))), N''),
                  N'Walk-In'
              ) AS CustomerLabel
            , LTRIM(RTRIM(ISNULL(tt.Typename, N''))) AS TypeName
            , CAST(ISNULL(bm.NetAmount, 0) AS FLOAT) AS NetAmount
            , CAST(ISNULL(bm.DueAmount, 0) AS FLOAT) AS DueAmount
            , CAST(ISNULL(bm.CancelStatus, 0) AS NVARCHAR(20)) AS CancelStatus
        FROM dbo.Billing_Mst bm WITH (NOLOCK)
        LEFT JOIN dbo.TMPPatient tp WITH (NOLOCK)
            ON tp.TmpPatientID = bm.TmpPatientId
        {_canteen_customer_meta_join_sql()}
        LEFT JOIN dbo.tbl_typemst tt WITH (NOLOCK)
            ON CAST(ISNULL(tt.id, 0) AS INT) = CAST(ISNULL(bm.BillTypeID, 0) AS INT)
        WHERE bm.Bill_ID = ?;
        """
        bill_df = pd.read_sql(bill_sql, conn, params=[bill_id_int])
        if bill_df is None or bill_df.empty:
            return None
        bill = bill_df.iloc[0].to_dict()
        receipt_df = pd.read_sql(
            """
            SELECT
                  CAST(Receipt_ID AS INT) AS ReceiptID
                , LTRIM(RTRIM(ISNULL(Receipt_No, N''))) AS ReceiptNo
                , CAST(ISNULL(Amount, 0) AS FLOAT) AS Amount
                , CAST(Receipt_Date AS DATETIME) AS ReceiptDate
                , LTRIM(RTRIM(ISNULL(PaymentMode, N''))) AS PaymentMode
            FROM dbo.Receipt_mst WITH (NOLOCK)
            WHERE InvoiceNo = ?
              AND LTRIM(RTRIM(ISNULL(ReceiptType, N''))) = N'P'
              AND ISNULL(CancelStatus, 0) = 0
            ORDER BY Receipt_ID;
            """,
            conn,
            params=[bill_id_int],
        )
        receipts = [] if receipt_df is None or receipt_df.empty else receipt_df.to_dict(orient="records")
        receipt_amount = sum(_safe_float(row.get("Amount"), 0) for row in receipts)
        return {
            "unit": unit_key,
            "bill_id": bill_id_int,
            "bill_no": _canteen_clean_text(bill.get("BillNo"), 80),
            "bill_date": bill.get("BillDate"),
            "customer_label": _canteen_clean_text(bill.get("CustomerLabel"), 200),
            "type_name": _canteen_clean_text(bill.get("TypeName"), 100),
            "net_amount": _safe_float(bill.get("NetAmount"), 0),
            "due_amount": _safe_float(bill.get("DueAmount"), 0),
            "received_amount": receipt_amount,
            "cancelled": _canteen_cancel_status_is_active(bill.get("CancelStatus")),
            "receipts": [
                {
                    "receipt_id": _to_int(row.get("ReceiptID"), 0) or 0,
                    "receipt_no": _canteen_clean_text(row.get("ReceiptNo"), 80),
                    "amount": _safe_float(row.get("Amount"), 0),
                    "receipt_date": row.get("ReceiptDate"),
                    "payment_mode": _canteen_clean_text(row.get("PaymentMode"), 80),
                }
                for row in receipts
            ],
        }
    except Exception as e:
        print(f"Canteen cancellation snapshot fetch failed for {unit_key} bill {bill_id_int}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _canteen_get_payment_mode_row(cursor, payment_mode_id: int) -> dict | None:
    payment_mode_int = _to_int(payment_mode_id, 0) or 0
    if cursor is None or payment_mode_int <= 0:
        return None
    cursor.execute(
        """
        SELECT TOP 1
              CAST(id AS INT) AS PayModeID
            , LTRIM(RTRIM(ISNULL(paymentmode, N''))) AS PayModeName
        FROM dbo.tblpaymode WITH (NOLOCK)
        WHERE CAST(ISNULL(id, 0) AS INT) = ?;
        """,
        (payment_mode_int,),
    )
    rows = _rows_as_dicts(cursor) if cursor.description is not None else []
    return rows[0] if rows else None


def _fetch_canteen_receipt_snapshot(unit: str, receipt_id: int) -> dict | None:
    unit_key = _canteen_unit_key(unit)
    receipt_id_int = _to_int(receipt_id, 0) or 0
    if unit_key not in CANTEEN_ALLOWED_UNITS or receipt_id_int <= 0:
        return None
    ensure_canteen_customer_meta_table(unit_key)
    ensure_canteen_bill_meta_table(unit_key)
    conn = get_canteen_sql_connection(unit_key)
    if not conn:
        return None
    try:
        sql = f"""
        SELECT TOP 1
              CAST(r.Receipt_ID AS INT) AS ReceiptID
            , LTRIM(RTRIM(ISNULL(r.Receipt_No, N''))) AS ReceiptNo
            , CAST(r.Receipt_Date AS DATETIME) AS ReceiptDate
            , CAST(ISNULL(r.Amount, 0) AS FLOAT) AS ReceiptAmount
            , LTRIM(RTRIM(ISNULL(r.Note, N''))) AS Note
            , CAST(ISNULL(r.CancelStatus, 0) AS INT) AS CancelStatus
            , CAST(ISNULL(r.InvoiceNo, 0) AS INT) AS BillID
            , LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) AS RawPaymentMode
            , CAST(ISNULL(r.Bank_ID, 0) AS INT) AS PaymentModeID
            , COALESCE(
                  NULLIF(LTRIM(RTRIM(ISNULL(pm.paymentmode, N''))), N''),
                  NULLIF(CASE WHEN LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) <> N'P' THEN LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) ELSE N'' END, N''),
                  N'Cash'
              ) AS PaymentModeName
            , LTRIM(RTRIM(ISNULL(r.ReceiptType, N''))) AS ReceiptType
            , CAST(ISNULL(bm.Bill_ID, 0) AS INT) AS BillIDResolved
            , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
            , CAST(bm.BillDate AS DATETIME) AS BillDate
            , CAST(ISNULL(bm.NetAmount, 0) AS FLOAT) AS NetAmount
            , CAST(ISNULL(bm.DueAmount, 0) AS FLOAT) AS DueAmount
            , CAST(ISNULL(bm.BillTypeID, 0) AS INT) AS TypeID
            , LTRIM(RTRIM(ISNULL(tt.Typename, N''))) AS TypeName
            , LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))) AS RegistrationNo
            , CAST(ISNULL(bm.TmpPatientId, 0) AS INT) AS TmpPatientID
            , LTRIM(RTRIM(ISNULL(tp.Name, N''))) AS CustomerName
            , LTRIM(RTRIM(ISNULL(tp.code, N''))) AS CustomerCode
            , LTRIM(RTRIM(ISNULL(cm.LedgerCode, N''))) AS LedgerCode
            , LTRIM(RTRIM(ISNULL(cm.LedgerName, N''))) AS LedgerName
            , LTRIM(RTRIM(ISNULL(cm.DepartmentName, N''))) AS DepartmentName
            , COALESCE(NULLIF(LTRIM(RTRIM(ISNULL(bmeta.BillingCategory, N''))), N''), CASE WHEN CAST(ISNULL(bm.BillTypeID, 0) AS INT) IN (6, 13) THEN N'room_service' ELSE N'general' END) AS BillingCategory
            , COALESCE(NULLIF(LTRIM(RTRIM(ISNULL(bmeta.BillingCategoryName, N''))), N''), CASE WHEN CAST(ISNULL(bm.BillTypeID, 0) AS INT) IN (6, 13) THEN N'Room Service Billing' ELSE N'General Billing' END) AS BillingCategoryName
            , LTRIM(RTRIM(ISNULL(bmeta.BulkSubcategory, N''))) AS BulkSubcategory
            , LTRIM(RTRIM(ISNULL(bmeta.BulkSubcategoryName, N''))) AS BulkSubcategoryName
            , COALESCE(NULLIF(LTRIM(RTRIM(ISNULL(bmeta.PaymentClassification, N''))), N''), CASE WHEN CAST(ISNULL(bm.BillTypeID, 0) AS INT) = 14 THEN N'wallet' WHEN ISNULL(bm.DueAmount, 0) > 0 AND ISNULL(r.Amount, 0) <= 0 THEN N'credit' ELSE N'cash' END) AS PaymentClassification
        FROM dbo.Receipt_mst r WITH (NOLOCK)
        LEFT JOIN dbo.Billing_Mst bm WITH (NOLOCK)
            ON bm.Bill_ID = r.InvoiceNo
        LEFT JOIN dbo.HID_CanteenBillMeta bmeta WITH (NOLOCK)
            ON bmeta.BillID = bm.Bill_ID
        LEFT JOIN dbo.tblpaymode pm WITH (NOLOCK)
            ON CAST(ISNULL(pm.id, 0) AS INT) = CAST(ISNULL(r.Bank_ID, 0) AS INT)
        LEFT JOIN dbo.tbl_typemst tt WITH (NOLOCK)
            ON CAST(ISNULL(tt.id, 0) AS INT) = CAST(ISNULL(bm.BillTypeID, 0) AS INT)
        LEFT JOIN dbo.TMPPatient tp WITH (NOLOCK)
            ON tp.TmpPatientID = COALESCE(NULLIF(bm.TmpPatientId, 0), NULLIF(r.TmpPatientId, 0))
        {_canteen_customer_meta_join_sql()}
        WHERE r.Receipt_ID = ?
          AND LTRIM(RTRIM(ISNULL(r.ReceiptType, N''))) = N'P';
        """
        df = pd.read_sql(sql, conn, params=[receipt_id_int])
        if df is None or df.empty:
            return None
        row = df.iloc[0].to_dict()
        customer_label = (
            _canteen_clean_text(row.get("LedgerName"))
            or _canteen_clean_text(row.get("CustomerName"))
            or _canteen_clean_text(row.get("RegistrationNo"))
            or "Walk-In"
        )
        return {
            "receipt_id": _to_int(row.get("ReceiptID"), 0) or 0,
            "receipt_no": _canteen_clean_text(row.get("ReceiptNo"), 80),
            "receipt_date": row.get("ReceiptDate"),
            "receipt_amount": _safe_float(row.get("ReceiptAmount"), 0),
            "note": _canteen_clean_text(row.get("Note"), 250),
            "cancelled": bool(_to_int(row.get("CancelStatus"), 0) or 0),
            "bill_id": _to_int(row.get("BillIDResolved") or row.get("BillID"), 0) or 0,
            "bill_no": _canteen_clean_text(row.get("BillNo"), 80),
            "bill_date": row.get("BillDate"),
            "net_amount": _safe_float(row.get("NetAmount"), 0),
            "due_amount": _safe_float(row.get("DueAmount"), 0),
            "type_id": _to_int(row.get("TypeID"), 0) or 0,
            "type_name": _canteen_clean_text(row.get("TypeName"), 100),
            "customer_label": customer_label,
            "payment_mode_id": _to_int(row.get("PaymentModeID"), 0) or 0,
            "payment_mode": _canteen_clean_text(row.get("PaymentModeName"), 120),
            "receipt_type": _canteen_clean_text(row.get("ReceiptType"), 20),
        }
    except Exception as e:
        print(f"Canteen receipt snapshot fetch failed for {unit_key} receipt {receipt_id_int}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _fetch_canteen_wallet_topup_snapshot(unit: str, wallet_txn_id: int) -> dict | None:
    unit_key = _canteen_unit_key(unit)
    wallet_txn_id_int = _to_int(wallet_txn_id, 0) or 0
    if unit_key not in CANTEEN_ALLOWED_UNITS or wallet_txn_id_int <= 0:
        return None
    ensure_canteen_customer_meta_table(unit_key)
    ensure_canteen_wallet_transaction_table(unit_key)
    conn = get_canteen_sql_connection(unit_key)
    if not conn:
        return None
    try:
        sql = f"""
        SELECT TOP 1
              CAST(wt.WalletTxnID AS BIGINT) AS WalletTxnID
            , CAST(ISNULL(wt.TmpPatientID, 0) AS INT) AS TmpPatientID
            , LTRIM(RTRIM(ISNULL(wt.TxnType, N''))) AS TxnType
            , CAST(ISNULL(wt.Amount, 0) AS FLOAT) AS Amount
            , CAST(ISNULL(wt.OpeningBalance, 0) AS FLOAT) AS OpeningBalance
            , CAST(ISNULL(wt.ClosingBalance, 0) AS FLOAT) AS ClosingBalance
            , CAST(ISNULL(wt.BillID, 0) AS INT) AS BillID
            , LTRIM(RTRIM(ISNULL(wt.BillNo, N''))) AS BillNo
            , CAST(ISNULL(wt.ReceiptID, 0) AS INT) AS ReceiptID
            , COALESCE(
                  NULLIF(LTRIM(RTRIM(ISNULL(wt.ReceiptNo, N''))), N''),
                  N'WT-' + CONVERT(NVARCHAR(30), wt.WalletTxnID)
              ) AS ReceiptNo
            , CAST(ISNULL(wt.PaymentModeID, 0) AS INT) AS PaymentModeID
            , LTRIM(RTRIM(ISNULL(wt.PaymentModeName, N''))) AS PaymentModeName
            , LTRIM(RTRIM(ISNULL(wt.Remarks, N''))) AS Remarks
            , LTRIM(RTRIM(ISNULL(wt.SourceContext, N''))) AS SourceContext
            , CAST(ISNULL(wt.IsCancelled, 0) AS INT) AS IsCancelled
            , CAST(wt.CreatedAt AS DATETIME) AS CreatedAt
            , LTRIM(RTRIM(ISNULL(tp.Name, N''))) AS CustomerName
            , LTRIM(RTRIM(ISNULL(tp.code, N''))) AS CustomerCode
            , CAST(ISNULL(tp.PatientType, 0) AS INT) AS TypeID
            , LTRIM(RTRIM(ISNULL(cm.LedgerCode, N''))) AS LedgerCode
            , LTRIM(RTRIM(ISNULL(cm.LedgerName, N''))) AS LedgerName
            , LTRIM(RTRIM(ISNULL(cm.DepartmentName, N''))) AS DepartmentName
            , CAST(ISNULL(cm.WalletBalance, 0) AS FLOAT) AS CurrentWalletBalance
        FROM dbo.HID_CanteenWalletTransaction wt WITH (NOLOCK)
        INNER JOIN dbo.TMPPatient tp WITH (NOLOCK)
            ON tp.TmpPatientID = wt.TmpPatientID
        {_canteen_customer_meta_join_sql()}
        WHERE wt.WalletTxnID = ?
          AND LTRIM(RTRIM(ISNULL(wt.TxnType, N''))) = N'TOPUP';
        """
        df = pd.read_sql(sql, conn, params=[wallet_txn_id_int])
        if df is None or df.empty:
            return None
        row = df.iloc[0].to_dict()
        customer_label = (
            _canteen_clean_text(row.get("LedgerName"))
            or _canteen_clean_text(row.get("CustomerName"))
            or _canteen_clean_text(row.get("CustomerCode"))
            or "Customer"
        )
        return {
            "wallet_txn_id": _to_int(row.get("WalletTxnID"), 0) or 0,
            "tmp_patient_id": _to_int(row.get("TmpPatientID"), 0) or 0,
            "txn_type": _canteen_clean_text(row.get("TxnType"), 20),
            "amount": _safe_float(row.get("Amount"), 0),
            "opening_balance": _safe_float(row.get("OpeningBalance"), 0),
            "closing_balance": _safe_float(row.get("ClosingBalance"), 0),
            "bill_id": _to_int(row.get("BillID"), 0) or 0,
            "bill_no": _canteen_clean_text(row.get("BillNo"), 80),
            "receipt_id": _to_int(row.get("ReceiptID"), 0) or 0,
            "receipt_no": _canteen_clean_text(row.get("ReceiptNo"), 80),
            "payment_mode_id": _to_int(row.get("PaymentModeID"), 0) or 0,
            "payment_mode": _canteen_clean_text(row.get("PaymentModeName"), 120),
            "remarks": _canteen_clean_text(row.get("Remarks"), 500),
            "source_context": _canteen_clean_text(row.get("SourceContext"), 40),
            "cancelled": bool(_to_int(row.get("IsCancelled"), 0) or 0),
            "created_at": row.get("CreatedAt"),
            "customer_label": customer_label,
            "type_id": _to_int(row.get("TypeID"), 0) or 0,
            "type_name": "Wallet Top-up",
            "current_wallet_balance": _safe_float(row.get("CurrentWalletBalance"), 0),
        }
    except Exception as e:
        print(f"Canteen wallet top-up snapshot fetch failed ({unit_key}, {wallet_txn_id_int}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_canteen_cancellation_request_statuses(unit: str, bill_ids) -> dict[int, dict]:
    unit_key = _canteen_unit_key(unit)
    ids = sorted({_to_int(value, 0) or 0 for value in (bill_ids or []) if (_to_int(value, 0) or 0) > 0})
    if not ids or not ensure_canteen_cancellation_request_table():
        return {}
    conn = None
    try:
        conn = _canteen_login_db_connection()
        results = {}
        for chunk in _canteen_chunked(ids):
            placeholders = ",".join("?" for _ in chunk)
            sql = f"""
            SELECT *
            FROM dbo.HID_CanteenCancellationRequest WITH (NOLOCK)
            WHERE Unit = ?
              AND RequestType = N'CANCELLATION'
              AND Status = N'PENDING'
              AND BillID IN ({placeholders})
            ORDER BY RequestedOn DESC;
            """
            df = pd.read_sql(sql, conn, params=[unit_key, *chunk])
            if df is None or df.empty:
                continue
            for row in df.to_dict(orient="records"):
                bill_id = _to_int(row.get("BillID"), 0) or 0
                if bill_id > 0 and bill_id not in results:
                    results[bill_id] = _canteen_cancellation_row_to_dict(row)
        return results
    except Exception as e:
        print(f"Canteen cancellation status fetch failed: {e}")
        return {}
    finally:
        try:
            if conn:
                conn.close()
        except Exception:
            pass


