def fetch_canteen_modification_requests(
    unit: str = "",
    status: str = "PENDING",
    limit: int = 250,
    *,
    request_type: str = "",
) -> list[dict]:
    unit_key = _canteen_unit_key(unit)
    status_key = _canteen_clean_text(status, 20).upper()
    request_type_raw = _canteen_clean_text(request_type, 40).upper()
    request_type_key = request_type_raw if request_type_raw in {"CANCELLATION", "PAYMENT_MODE_CHANGE", "RECEIPT_CANCELLATION", "RECEIPT_TYPE_CHANGE", "WALLET_TOPUP_CANCELLATION", "WALLET_TOPUP_PAYMENT_MODE_CHANGE"} else ""
    row_limit = max(1, min(int(limit or 250), 1000))
    if not ensure_canteen_cancellation_request_table():
        return []
    conn = None
    try:
        conn = _canteen_login_db_connection()
        sql = """
        SELECT TOP (?) *
        FROM dbo.HID_CanteenCancellationRequest WITH (NOLOCK)
        WHERE (? = N'' OR Unit = ?)
          AND (
                (? <> N'' AND RequestType = ?)
                OR (? = N'' AND RequestType <> N'RECEIPT_TYPE_CHANGE')
              )
          AND (? = N'' OR Status = ?)
        ORDER BY
          CASE WHEN Status = N'PENDING' THEN 0 ELSE 1 END,
          RequestedOn DESC,
          RequestID DESC;
        """
        df = pd.read_sql(
            sql,
            conn,
            params=[
                row_limit,
                unit_key,
                unit_key,
                request_type_key,
                request_type_key,
                request_type_key,
                status_key,
                status_key,
            ],
        )
        if df is None or df.empty:
            return []
        return [_canteen_cancellation_row_to_dict(row) for row in df.to_dict(orient="records")]
    except Exception as e:
        print(f"Canteen modification requests fetch failed: {e}")
        return []
    finally:
        try:
            if conn:
                conn.close()
        except Exception:
            pass


def fetch_canteen_cancellation_requests(unit: str = "", status: str = "PENDING", limit: int = 250) -> list[dict]:
    return fetch_canteen_modification_requests(unit=unit, status=status, limit=limit, request_type="CANCELLATION")


def _recalculate_canteen_bill_due_amount(cursor, bill_id: int) -> float:
    bill_id_int = _to_int(bill_id, 0) or 0
    if cursor is None or bill_id_int <= 0:
        return 0.0
    cursor.execute(
        """
        SELECT TOP 1 CAST(ISNULL(NetAmount, 0) AS FLOAT) AS NetAmount
        FROM dbo.Billing_Mst WITH (ROWLOCK, UPDLOCK)
        WHERE Bill_ID = ?;
        """,
        (bill_id_int,),
    )
    bill_rows = _rows_as_dicts(cursor) if cursor.description is not None else []
    if not bill_rows:
        return 0.0
    net_amount = _safe_float(bill_rows[0].get("NetAmount"), 0)
    cursor.execute(
        """
        SELECT CAST(ISNULL(SUM(ISNULL(Amount, 0)), 0) AS FLOAT) AS ActiveReceiptAmount
        FROM dbo.Receipt_mst WITH (ROWLOCK, UPDLOCK)
        WHERE InvoiceNo = ?
          AND LTRIM(RTRIM(ISNULL(ReceiptType, N''))) = N'P'
          AND ISNULL(CancelStatus, 0) = 0;
        """,
        (bill_id_int,),
    )
    receipt_rows = _rows_as_dicts(cursor) if cursor.description is not None else []
    active_receipt_amount = _safe_float((receipt_rows[0] if receipt_rows else {}).get("ActiveReceiptAmount"), 0)
    new_due_amount = round(max(net_amount - active_receipt_amount, 0.0), 2)
    cursor.execute(
        """
        UPDATE dbo.Billing_Mst
        SET DueAmount = ?,
            UpdatedOn = GETDATE()
        WHERE Bill_ID = ?;
        """,
        (new_due_amount, bill_id_int),
    )
    return new_due_amount


def _canteen_credit_type_row_for_cancellation(unit: str) -> dict:
    type_map = _canteen_type_map(unit)
    for candidate_id in (3, 2, 4, 5, 7, 8, 11):
        row = type_map.get(candidate_id)
        if row:
            return {
                "type_id": _to_int(row.get("type_id"), 0) or candidate_id,
                "type_name": _canteen_clean_text(row.get("type_name"), 120) or "Credit",
            }
    return {"type_id": 3, "type_name": "Credit"}


def _mark_canteen_bill_credit_after_receipt_cancellation(cursor, unit: str, bill_id: int, due_amount) -> bool:
    bill_id_int = _to_int(bill_id, 0) or 0
    due_val = _to_decimal(due_amount, Decimal("0.00")).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    if cursor is None or bill_id_int <= 0 or due_val <= Decimal("0.00"):
        return False

    credit_type = _canteen_credit_type_row_for_cancellation(unit)
    credit_type_id = _to_int(credit_type.get("type_id"), 0) or 3
    credit_type_name = _canteen_clean_text(credit_type.get("type_name"), 120) or "Credit"

    cursor.execute(
        """
        UPDATE dbo.Billing_Mst
        SET BillTypeID = ?,
            UpdatedOn = GETDATE()
        WHERE Bill_ID = ?
          AND ISNULL(CancelStatus, 0) = 0;
        """,
        (credit_type_id, bill_id_int),
    )

    if not ensure_canteen_bill_meta_table(unit):
        return True

    cursor.execute(
        """
        UPDATE dbo.HID_CanteenBillMeta
        SET PaymentClassification = N'credit',
            RequestedTypeID = ?,
            RequestedTypeName = ?,
            UpdatedOn = GETDATE()
        WHERE BillID = ?;
        """,
        (credit_type_id, credit_type_name, bill_id_int),
    )
    if cursor.rowcount <= 0:
        cursor.execute(
            """
            INSERT INTO dbo.HID_CanteenBillMeta (
                BillID,
                BillingCategory,
                BillingCategoryName,
                PricingCategory,
                PaymentClassification,
                RequestedTypeID,
                RequestedTypeName,
                CreatedSource,
                CreatedOn,
                UpdatedOn
            )
            VALUES (
                ?,
                N'general',
                N'General Billing',
                N'counter',
                N'credit',
                ?,
                ?,
                N'HID',
                GETDATE(),
                GETDATE()
            );
            """,
            (bill_id_int, credit_type_id, credit_type_name),
        )
    return True


def decide_canteen_modification_request(
    request_id: int,
    *,
    action: str,
    note: str = "",
    actor_user_id: int = 0,
    actor_username: str = "",
) -> dict:
    request_id_int = _to_int(request_id, 0) or 0
    action_key = _canteen_clean_text(action, 20).lower()
    note_text = _canteen_clean_text(note, 500)
    actor_user_id_int = _to_int(actor_user_id, 0) or 0
    actor_username_text = _canteen_clean_text(actor_username, 120)
    if request_id_int <= 0 or action_key not in {"approve", "approved", "reject", "rejected"}:
        return {"status": "error", "message": "Select approve or reject for a valid canteen modification request."}
    if not ensure_canteen_cancellation_request_table():
        return {"status": "error", "message": "Canteen modification request table is not ready."}

    central_conn = None
    canteen_conn = None
    try:
        central_conn = _canteen_login_db_connection()
        try:
            central_conn.autocommit = False
        except Exception:
            pass
        central_cur = central_conn.cursor()
        central_cur.execute(
            """
            SELECT TOP 1 *
            FROM dbo.HID_CanteenCancellationRequest WITH (ROWLOCK, UPDLOCK)
            WHERE RequestID = ?;
            """,
            (request_id_int,),
        )
        rows = _rows_as_dicts(central_cur) if central_cur.description is not None else []
        if not rows:
            central_conn.rollback()
            return {"status": "error", "message": "Canteen modification request was not found."}
        request_row = rows[0]
        request_type = _canteen_request_type_key(request_row.get("RequestType"))
        if _canteen_clean_text(request_row.get("Status"), 20).upper() != "PENDING":
            central_conn.rollback()
            return {"status": "error", "message": "Only pending canteen modification requests can be processed."}

        approved = action_key in {"approve", "approved"}
        unit_key = _canteen_unit_key(request_row.get("Unit"))
        bill_id_int = _to_int(request_row.get("BillID"), 0) or 0
        wallet_txn_id_int = _to_int(request_row.get("WalletTxnID"), 0) or 0
        receipt_id_int = _to_int(request_row.get("ReceiptID"), 0) or 0
        applied_receipts = 0
        applied_wallet_cancel = False
        applied_payment_mode = False
        applied_type_change = False
        if approved:
            if unit_key not in CANTEEN_ALLOWED_UNITS:
                central_conn.rollback()
                return {"status": "error", "message": "Canteen modification request has invalid unit details."}
            canteen_conn = get_canteen_sql_connection(unit_key)
            if not canteen_conn:
                central_conn.rollback()
                return {"status": "error", "message": f"Could not connect to {unit_key} canteen database."}
            try:
                canteen_conn.autocommit = False
            except Exception:
                pass
            canteen_cur = canteen_conn.cursor()
            if request_type == "PAYMENT_MODE_CHANGE":
                requested_mode_id_int = _to_int(request_row.get("RequestedPaymentModeID"), 0) or 0
                requested_mode_name = _canteen_clean_text(request_row.get("RequestedPaymentMode"), 120)
                if receipt_id_int <= 0 or requested_mode_id_int <= 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Payment mode change request is missing receipt or mode details."}
                mode_row = _canteen_get_payment_mode_row(canteen_cur, requested_mode_id_int)
                if not mode_row:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Requested payment mode is no longer available."}
                requested_mode_name = _canteen_clean_text(mode_row.get("PayModeName"), 120) or requested_mode_name
                canteen_cur.execute(
                    """
                    SELECT TOP 1
                          Receipt_ID
                        , ISNULL(CancelStatus, 0) AS CancelStatus
                        , CAST(ISNULL(Bank_ID, 0) AS INT) AS BankID
                        , LTRIM(RTRIM(ISNULL(PaymentMode, N''))) AS PaymentMode
                    FROM dbo.Receipt_mst WITH (ROWLOCK, UPDLOCK)
                    WHERE Receipt_ID = ?
                      AND LTRIM(RTRIM(ISNULL(ReceiptType, N''))) = N'P';
                    """,
                    (receipt_id_int,),
                )
                receipt_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                if not receipt_rows:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Receipt was not found while processing approval."}
                receipt_row = receipt_rows[0]
                if _to_int(receipt_row.get("CancelStatus"), 0) or 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Cancelled receipts cannot be updated."}
                current_mode_id = _to_int(receipt_row.get("BankID"), 0) or 0
                current_mode_name = _canteen_clean_text(receipt_row.get("PaymentMode"), 120)
                current_mode_row = _canteen_get_payment_mode_row(canteen_cur, current_mode_id) if current_mode_id > 0 else None
                current_mode_name = _canteen_clean_text((current_mode_row or {}).get("PayModeName"), 120) or current_mode_name
                if current_mode_id == requested_mode_id_int and current_mode_name.lower() == requested_mode_name.lower():
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "The requested payment mode is already applied on this receipt."}
                updated_by_value = actor_user_id_int if actor_user_id_int > 0 else actor_username_text
                canteen_cur.execute(
                    """
                    UPDATE dbo.Receipt_mst
                    SET PaymentMode = ?,
                        Bank_ID = ?,
                        UpdatedBy = ?
                    WHERE Receipt_ID = ?
                      AND LTRIM(RTRIM(ISNULL(ReceiptType, N''))) = N'P'
                      AND ISNULL(CancelStatus, 0) = 0;
                    """,
                    (requested_mode_name, requested_mode_id_int, updated_by_value, receipt_id_int),
                )
                applied_payment_mode = True
                request_row["RequestedPaymentMode"] = requested_mode_name
            elif request_type == "WALLET_TOPUP_PAYMENT_MODE_CHANGE":
                requested_mode_id_int = _to_int(request_row.get("RequestedPaymentModeID"), 0) or 0
                requested_mode_name = _canteen_clean_text(request_row.get("RequestedPaymentMode"), 120)
                if wallet_txn_id_int <= 0 or requested_mode_id_int <= 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Wallet top-up payment mode request is missing transaction or mode details."}
                mode_row = _canteen_get_payment_mode_row(canteen_cur, requested_mode_id_int)
                if not mode_row:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Requested payment mode is no longer available."}
                requested_mode_name = _canteen_clean_text(mode_row.get("PayModeName"), 120) or requested_mode_name
                canteen_cur.execute(
                    """
                    SELECT TOP 1
                          CAST(ISNULL(WalletTxnID, 0) AS BIGINT) AS WalletTxnID
                        , CAST(ISNULL(PaymentModeID, 0) AS INT) AS PaymentModeID
                        , LTRIM(RTRIM(ISNULL(PaymentModeName, N''))) AS PaymentModeName
                        , CAST(ISNULL(IsCancelled, 0) AS INT) AS IsCancelled
                    FROM dbo.HID_CanteenWalletTransaction WITH (ROWLOCK, UPDLOCK)
                    WHERE WalletTxnID = ?
                      AND LTRIM(RTRIM(ISNULL(TxnType, N''))) = N'TOPUP';
                    """,
                    (wallet_txn_id_int,),
                )
                wallet_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                if not wallet_rows:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Wallet top-up was not found while processing approval."}
                wallet_row = wallet_rows[0]
                if _to_int(wallet_row.get("IsCancelled"), 0) or 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Cancelled wallet top-ups cannot be updated."}
                current_mode_id = _to_int(wallet_row.get("PaymentModeID"), 0) or 0
                current_mode_name = _canteen_clean_text(wallet_row.get("PaymentModeName"), 120)
                if current_mode_id == requested_mode_id_int and current_mode_name.lower() == requested_mode_name.lower():
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "The requested payment mode is already applied on this wallet top-up."}
                canteen_cur.execute(
                    """
                    UPDATE dbo.HID_CanteenWalletTransaction
                    SET PaymentModeID = ?,
                        PaymentModeName = ?
                    WHERE WalletTxnID = ?
                      AND LTRIM(RTRIM(ISNULL(TxnType, N''))) = N'TOPUP'
                      AND ISNULL(IsCancelled, 0) = 0;
                    """,
                    (requested_mode_id_int, requested_mode_name, wallet_txn_id_int),
                )
                applied_payment_mode = True
                request_row["RequestedPaymentMode"] = requested_mode_name
            elif request_type == "RECEIPT_TYPE_CHANGE":
                requested_type_id_int = _to_int(request_row.get("RequestedTypeID"), 0) or 0
                requested_type_name = _canteen_clean_text(request_row.get("RequestedTypeName"), 120)
                if receipt_id_int <= 0 or bill_id_int <= 0 or requested_type_id_int <= 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Receipt type change request is missing receipt or type details."}
                type_row = _canteen_type_map(unit_key).get(requested_type_id_int) or {}
                requested_type_name = _canteen_clean_text(type_row.get("type_name"), 120) or requested_type_name
                if not requested_type_name:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Requested receipt type is no longer available."}
                snapshot = _fetch_canteen_receipt_snapshot(unit_key, receipt_id_int)
                if not snapshot:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Receipt was not found while processing approval."}
                if snapshot.get("cancelled"):
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Cancelled receipts cannot be updated."}
                canteen_cur.execute(
                    """
                    SELECT TOP 1
                          Bill_ID
                        , CAST(ISNULL(CancelStatus, 0) AS NVARCHAR(20)) AS CancelStatus
                        , CAST(ISNULL(BillTypeID, 0) AS INT) AS BillTypeID
                    FROM dbo.Billing_Mst WITH (ROWLOCK, UPDLOCK)
                    WHERE Bill_ID = ?;
                    """,
                    (bill_id_int,),
                )
                bill_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                if not bill_rows:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Canteen bill was not found while processing approval."}
                bill_row = bill_rows[0]
                if _canteen_cancel_status_is_active(bill_row.get("CancelStatus")):
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Cancelled bills cannot be updated."}
                current_type_id = _to_int(bill_row.get("BillTypeID"), 0) or 0
                current_type_name = _canteen_clean_text(request_row.get("CurrentTypeName"), 120) or _canteen_clean_text(snapshot.get("type_name"), 120)
                if current_type_id == requested_type_id_int and current_type_name.lower() == requested_type_name.lower():
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "The requested receipt type is already applied on this receipt."}
                canteen_cur.execute(
                    """
                    UPDATE dbo.Billing_Mst
                    SET BillTypeID = ?,
                        UpdatedOn = GETDATE()
                    WHERE Bill_ID = ?;
                    """,
                    (requested_type_id_int, bill_id_int),
                )
                applied_type_change = True
                request_row["CurrentTypeID"] = current_type_id
                request_row["CurrentTypeName"] = current_type_name
                request_row["RequestedTypeID"] = requested_type_id_int
                request_row["RequestedTypeName"] = requested_type_name
            elif request_type == "RECEIPT_CANCELLATION":
                if receipt_id_int <= 0 or bill_id_int <= 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Receipt cancellation request has invalid receipt details."}
                canteen_cur.execute(
                    """
                    SELECT TOP 1
                          r.Receipt_ID
                        , CAST(ISNULL(r.CancelStatus, 0) AS INT) AS CancelStatus
                        , CAST(ISNULL(r.InvoiceNo, 0) AS INT) AS BillID
                    FROM dbo.Receipt_mst r WITH (ROWLOCK, UPDLOCK)
                    WHERE r.Receipt_ID = ?
                      AND LTRIM(RTRIM(ISNULL(r.ReceiptType, N''))) = N'P';
                    """,
                    (receipt_id_int,),
                )
                receipt_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                if not receipt_rows:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Receipt was not found while processing approval."}
                receipt_row = receipt_rows[0]
                if _to_int(receipt_row.get("CancelStatus"), 0) or 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Selected receipt is already cancelled."}
                canteen_cur.execute(
                    """
                    SELECT TOP 1 Bill_ID, CAST(ISNULL(CancelStatus, 0) AS NVARCHAR(20)) AS CancelStatus
                    FROM dbo.Billing_Mst WITH (ROWLOCK, UPDLOCK)
                    WHERE Bill_ID = ?;
                    """,
                    (bill_id_int,),
                )
                bill_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                if not bill_rows:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Canteen bill was not found while processing approval."}
                if _canteen_cancel_status_is_active(bill_rows[0].get("CancelStatus")):
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Receipts on a cancelled bill cannot be updated."}
                canteen_cur.execute(
                    """
                    UPDATE dbo.Receipt_mst
                    SET CancelStatus = 1,
                        CancelReasonid = 1,
                        CancelDate = GETDATE(),
                        CanceledBy = ?
                    WHERE Receipt_ID = ?
                      AND LTRIM(RTRIM(ISNULL(ReceiptType, N''))) = N'P'
                      AND ISNULL(CancelStatus, 0) = 0;
                    """,
                    (actor_user_id_int, receipt_id_int),
                )
                new_due_amount = _recalculate_canteen_bill_due_amount(canteen_cur, bill_id_int)
                _mark_canteen_bill_credit_after_receipt_cancellation(canteen_cur, unit_key, bill_id_int, new_due_amount)
                applied_receipts = 1
            elif request_type == "WALLET_TOPUP_CANCELLATION":
                if wallet_txn_id_int <= 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Wallet top-up cancellation request has invalid transaction details."}
                canteen_cur.execute(
                    """
                    SELECT TOP 1
                          CAST(ISNULL(WalletTxnID, 0) AS BIGINT) AS WalletTxnID
                        , CAST(ISNULL(TmpPatientID, 0) AS INT) AS TmpPatientID
                        , CAST(ISNULL(Amount, 0) AS DECIMAL(18,2)) AS Amount
                        , COALESCE(
                              NULLIF(LTRIM(RTRIM(ISNULL(ReceiptNo, N''))), N''),
                              N'WT-' + CONVERT(NVARCHAR(30), WalletTxnID)
                          ) AS ReceiptNo
                        , LTRIM(RTRIM(ISNULL(PaymentModeName, N''))) AS PaymentModeName
                        , CAST(ISNULL(PaymentModeID, 0) AS INT) AS PaymentModeID
                        , CAST(ISNULL(IsCancelled, 0) AS INT) AS IsCancelled
                    FROM dbo.HID_CanteenWalletTransaction WITH (ROWLOCK, UPDLOCK)
                    WHERE WalletTxnID = ?
                      AND LTRIM(RTRIM(ISNULL(TxnType, N''))) = N'TOPUP';
                    """,
                    (wallet_txn_id_int,),
                )
                wallet_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                if not wallet_rows:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Wallet top-up was not found while processing approval."}
                wallet_row = wallet_rows[0]
                if _to_int(wallet_row.get("IsCancelled"), 0) or 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Selected wallet top-up is already cancelled."}
                wallet_tmp_patient_id = _to_int(wallet_row.get("TmpPatientID"), 0) or 0
                wallet_amount = _to_decimal(wallet_row.get("Amount"), Decimal("0.00")).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
                if wallet_tmp_patient_id <= 0 or wallet_amount <= Decimal("0.00"):
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Wallet top-up details are incomplete for cancellation."}
                current_wallet_balance = _canteen_customer_wallet_balance(canteen_cur, wallet_tmp_patient_id, for_update=True)
                if current_wallet_balance < wallet_amount:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Wallet balance has already been partially or fully used. Wallet top-up cannot be cancelled until balance is restored."}
                new_wallet_balance = (current_wallet_balance - wallet_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
                if new_wallet_balance < Decimal("0.00"):
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Wallet top-up cancellation would make the wallet balance negative."}
                if not _canteen_update_customer_wallet_balance(canteen_cur, wallet_tmp_patient_id, new_wallet_balance):
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Failed to update customer wallet balance for cancellation."}
                _canteen_append_wallet_transaction(
                    canteen_cur,
                    unit_key,
                    tmp_patient_id=wallet_tmp_patient_id,
                    txn_type="ADJUSTMENT",
                    amount=wallet_amount * Decimal("-1"),
                    opening_balance=current_wallet_balance,
                    closing_balance=new_wallet_balance,
                    bill_id=_to_int(request_row.get("BillID"), 0) or 0,
                    bill_no=_canteen_clean_text(request_row.get("BillNo"), 80),
                    receipt_no=_canteen_clean_text(wallet_row.get("ReceiptNo"), 80),
                    payment_mode_id=_to_int(wallet_row.get("PaymentModeID"), 0) or None,
                    payment_mode_name=_canteen_clean_text(wallet_row.get("PaymentModeName"), 120),
                    remarks=note_text or _canteen_clean_text(request_row.get("Reason"), 500) or f"Wallet top-up reversal for {_canteen_clean_text(wallet_row.get('ReceiptNo'), 80)}",
                    source_context="TOPUP_CANCELLATION",
                    actor_user_id=actor_user_id_int,
                    actor_username=actor_username_text,
                )
                canteen_cur.execute(
                    """
                    UPDATE dbo.HID_CanteenWalletTransaction
                    SET IsCancelled = 1,
                        CancelledAt = SYSDATETIME(),
                        CancelledByAccountID = ?,
                        CancelledByUserName = ?,
                        CancellationRemarks = ?
                    WHERE WalletTxnID = ?
                      AND LTRIM(RTRIM(ISNULL(TxnType, N''))) = N'TOPUP'
                      AND ISNULL(IsCancelled, 0) = 0;
                    """,
                    (actor_user_id_int or None, actor_username_text or None, note_text or _canteen_clean_text(request_row.get("Reason"), 500) or None, wallet_txn_id_int),
                )
                applied_wallet_cancel = True
            else:
                if bill_id_int <= 0:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Cancellation request has invalid bill details."}
                canteen_cur.execute(
                    """
                    SELECT TOP 1 Bill_ID, CancelStatus
                    FROM dbo.Billing_Mst WITH (ROWLOCK, UPDLOCK)
                    WHERE Bill_ID = ?;
                    """,
                    (bill_id_int,),
                )
                bill_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                if not bill_rows:
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Canteen bill was not found while processing approval."}
                if _canteen_cancel_status_is_active(bill_rows[0].get("CancelStatus")):
                    canteen_conn.rollback()
                    central_conn.rollback()
                    return {"status": "error", "message": "Canteen bill is already cancelled."}
                canteen_cur.execute(
                    """
                    SELECT Receipt_ID
                    FROM dbo.Receipt_mst WITH (ROWLOCK, UPDLOCK)
                    WHERE InvoiceNo = ?
                      AND LTRIM(RTRIM(ISNULL(ReceiptType, N''))) = N'P'
                      AND ISNULL(CancelStatus, 0) = 0;
                    """,
                    (bill_id_int,),
                )
                receipt_rows = _rows_as_dicts(canteen_cur) if canteen_cur.description is not None else []
                applied_receipts = len(receipt_rows)
                canteen_cur.execute(
                    """
                    UPDATE dbo.Receipt_mst
                    SET CancelStatus = 1,
                        CancelReasonid = 1,
                        CancelDate = GETDATE(),
                        CanceledBy = ?
                    WHERE InvoiceNo = ?
                      AND LTRIM(RTRIM(ISNULL(ReceiptType, N''))) = N'P'
                      AND ISNULL(CancelStatus, 0) = 0;
                    """,
                    (actor_user_id_int, bill_id_int),
                )
                canteen_cur.execute(
                    """
                    UPDATE dbo.Billing_Mst
                    SET CancelStatus = 1,
                        CancelReasonID = 1,
                        CanceledBy = ?,
                        CanceledOn = GETDATE(),
                        DueAmount = 0,
                        UpdatedOn = GETDATE()
                    WHERE Bill_ID = ?;
                    """,
                    (actor_user_id_int, bill_id_int),
                )
            canteen_conn.commit()

        next_status = "APPROVED" if approved else "REJECTED"
        central_cur.execute(
            """
            UPDATE dbo.HID_CanteenCancellationRequest
            SET Status = ?,
                ProcessedByAccountID = ?,
                ProcessedByUserName = ?,
                ProcessedOn = SYSDATETIME(),
                DecisionNote = ?,
                AppliedBillCancel = ?,
                AppliedReceiptCancel = ?,
                AppliedWalletCancel = ?,
                AppliedPaymentMode = ?,
                AppliedTypeChange = ?
            WHERE RequestID = ? AND Status = N'PENDING';
            """,
            (
                next_status,
                actor_user_id_int,
                actor_username_text,
                note_text,
                1 if approved and request_type == "CANCELLATION" else 0,
                1 if approved and ((request_type == "CANCELLATION" and applied_receipts > 0) or request_type == "RECEIPT_CANCELLATION") else 0,
                1 if approved and applied_wallet_cancel else 0,
                1 if approved and applied_payment_mode else 0,
                1 if approved and applied_type_change else 0,
                request_id_int,
            ),
        )
        central_conn.commit()
        request_row["Status"] = next_status
        request_row["ProcessedByAccountID"] = actor_user_id_int
        request_row["ProcessedByUserName"] = actor_username_text
        request_row["ProcessedOn"] = datetime.now(tz=LOCAL_TZ).replace(tzinfo=None)
        request_row["DecisionNote"] = note_text
        request_row["AppliedBillCancel"] = approved and request_type == "CANCELLATION"
        request_row["AppliedReceiptCancel"] = approved and ((request_type == "CANCELLATION" and applied_receipts > 0) or request_type == "RECEIPT_CANCELLATION")
        request_row["AppliedWalletCancel"] = approved and applied_wallet_cancel
        request_row["AppliedPaymentMode"] = approved and applied_payment_mode
        request_row["AppliedTypeChange"] = approved and applied_type_change
        success_messages = {
            "CANCELLATION": "Bill cancellation approved and applied.",
            "RECEIPT_CANCELLATION": "Receipt cancellation approved and applied.",
            "WALLET_TOPUP_CANCELLATION": "Wallet top-up cancellation approved and applied.",
            "PAYMENT_MODE_CHANGE": "Payment mode change approved and applied.",
            "WALLET_TOPUP_PAYMENT_MODE_CHANGE": "Wallet top-up payment mode change approved and applied.",
            "RECEIPT_TYPE_CHANGE": "Receipt type change approved and applied.",
        }
        rejected_messages = {
            "CANCELLATION": "Bill cancellation request rejected.",
            "RECEIPT_CANCELLATION": "Receipt cancellation request rejected.",
            "WALLET_TOPUP_CANCELLATION": "Wallet top-up cancellation request rejected.",
            "PAYMENT_MODE_CHANGE": "Payment mode change request rejected.",
            "WALLET_TOPUP_PAYMENT_MODE_CHANGE": "Wallet top-up payment mode change request rejected.",
            "RECEIPT_TYPE_CHANGE": "Receipt type change request rejected.",
        }
        return {
            "status": "success",
            "message": (success_messages.get(request_type) if approved else rejected_messages.get(request_type)) or "Canteen modification request processed.",
            "request": _canteen_cancellation_row_to_dict(request_row),
            "applied_receipt_count": applied_receipts,
        }
    except Exception as e:
        try:
            if canteen_conn:
                canteen_conn.rollback()
        except Exception:
            pass
        try:
            if central_conn:
                central_conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Failed to process canteen modification request: {e}"}
    finally:
        try:
            if canteen_conn:
                canteen_conn.close()
        except Exception:
            pass
        try:
            if central_conn:
                central_conn.close()
        except Exception:
            pass


def decide_canteen_cancellation_request(
    request_id: int,
    *,
    action: str,
    note: str = "",
    actor_user_id: int = 0,
    actor_username: str = "",
) -> dict:
    return decide_canteen_modification_request(
        request_id,
        action=action,
        note=note,
        actor_user_id=actor_user_id,
        actor_username=actor_username,
    )


def fetch_canteen_collection_rows(
    unit: str,
    *,
    from_date=None,
    to_date=None,
    query: str = "",
    type_id: int | None = None,
    limit: int = 5000,
):
    unit_key = _canteen_unit_key(unit)
    if unit_key not in CANTEEN_ALLOWED_UNITS:
        return pd.DataFrame()
    ensure_canteen_customer_meta_table(unit_key)
    ensure_canteen_receipt_meta_table(unit_key)
    ensure_canteen_bill_meta_table(unit_key)
    conn = get_canteen_sql_connection(unit_key)
    if not conn:
        print(f"Canteen collections: could not connect to {unit_key}")
        return None
    try:
        start_iso, end_iso = _canteen_resolve_date_range(from_date, to_date)
        query_text = _canteen_clean_text(query).lower()
        query_like = f"%{query_text}%"
        type_id_int = _to_int(type_id, 0) or 0
        row_limit = max(1, min(int(limit or 5000), 25000))
        sql = f"""
        SELECT TOP (?)
              CAST(r.Receipt_ID AS INT) AS ReceiptID
            , LTRIM(RTRIM(ISNULL(r.Receipt_No, N''))) AS ReceiptNo
            , CAST(r.Receipt_Date AS DATETIME) AS ReceiptDate
            , CAST(r.Receipt_Time AS DATETIME) AS ReceiptTime
            , CAST(ISNULL(r.Amount, 0) AS FLOAT) AS Amount
            , LTRIM(RTRIM(ISNULL(r.Note, N''))) AS Note
            , CAST(ISNULL(r.InvoiceNo, 0) AS INT) AS BillID
            , LTRIM(RTRIM(ISNULL(r.PaymentAgainst, N''))) AS PaymentAgainst
            , LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) AS RawPaymentMode
            , CAST(ISNULL(r.Bank_ID, 0) AS INT) AS PaymentModeID
            , COALESCE(
                  NULLIF(LTRIM(RTRIM(ISNULL(pm.paymentmode, N''))), N''),
                  NULLIF(CASE WHEN LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) <> N'P' THEN LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) ELSE N'' END, N''),
                  N'Cash'
              ) AS PaymentModeName
            , LTRIM(RTRIM(ISNULL(r.ReceiptType, N''))) AS ReceiptType
            , CAST(ISNULL(r.TmpPatientId, 0) AS INT) AS ReceiptTmpPatientID
            , LTRIM(RTRIM(ISNULL(r.UpdatedBy, N''))) AS CollectionByRaw
            , CAST(ISNULL(COALESCE(NULLIF(rmeta.CollectedByAccountID, 0), TRY_CONVERT(INT, r.UpdatedBy)), 0) AS INT) AS CollectionByAccountID
            , LTRIM(RTRIM(ISNULL(rmeta.CollectedByUserName, N''))) AS ReceiptMetaCollectionByName
            , LTRIM(RTRIM(ISNULL(rmeta.CollectedSource, N''))) AS ReceiptMetaCollectionSource
            , LTRIM(RTRIM(ISNULL(lu.Name, N''))) AS LegacyCollectionByName
            , CAST(ISNULL(bm.Bill_ID, 0) AS INT) AS BillIDResolved
            , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
            , CAST(bm.BillDate AS DATETIME) AS BillDate
            , CAST(ISNULL(bm.NetAmount, 0) AS FLOAT) AS BillNetAmount
            , CAST(ISNULL(bm.DueAmount, 0) AS FLOAT) AS BillDueAmount
            , CAST(ISNULL(bm.BillTypeID, 0) AS INT) AS TypeID
            , LTRIM(RTRIM(ISNULL(tt.Typename, N''))) AS TypeName
            , LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))) AS RegistrationNo
            , CAST(ISNULL(bm.TmpPatientId, 0) AS INT) AS TmpPatientID
            , LTRIM(RTRIM(ISNULL(tp.Name, N''))) AS CustomerName
            , LTRIM(RTRIM(ISNULL(tp.code, N''))) AS CustomerCode
            , LTRIM(RTRIM(ISNULL(cm.LedgerCode, N''))) AS LedgerCode
            , LTRIM(RTRIM(ISNULL(cm.LedgerName, N''))) AS LedgerName
            , LTRIM(RTRIM(ISNULL(cm.DepartmentName, N''))) AS DepartmentName
            , COALESCE(NULLIF(LTRIM(RTRIM(ISNULL(bmeta.BillingCategory, N''))), N''), CASE WHEN CAST(ISNULL(bm.BillTypeID, 0) AS INT) IN (6, 13) THEN N'room_service' ELSE N'general' END) AS BillingCategory
            , COALESCE(NULLIF(LTRIM(RTRIM(ISNULL(bmeta.BillingCategoryName, N''))), N''), CASE WHEN CAST(ISNULL(bm.BillTypeID, 0) AS INT) IN (6, 13) THEN N'Room Service Billing' ELSE N'General Billing' END) AS BillingCategoryName
            , LTRIM(RTRIM(ISNULL(bmeta.BulkSubcategory, N''))) AS BulkSubcategory
            , LTRIM(RTRIM(ISNULL(bmeta.BulkSubcategoryName, N''))) AS BulkSubcategoryName
            , COALESCE(NULLIF(LTRIM(RTRIM(ISNULL(bmeta.PaymentClassification, N''))), N''), CASE WHEN CAST(ISNULL(bm.BillTypeID, 0) AS INT) = 14 THEN N'wallet' WHEN ISNULL(bm.DueAmount, 0) > 0 AND ISNULL(r.Amount, 0) <= 0 THEN N'credit' ELSE N'cash' END) AS PaymentClassification
        FROM dbo.Receipt_mst r WITH (NOLOCK)
        LEFT JOIN dbo.Billing_Mst bm WITH (NOLOCK)
            ON bm.Bill_ID = r.InvoiceNo
        LEFT JOIN dbo.HID_CanteenBillMeta bmeta WITH (NOLOCK)
            ON bmeta.BillID = bm.Bill_ID
        LEFT JOIN dbo.LABUserMasterUp bill_lu WITH (NOLOCK)
            ON CAST(ISNULL(bill_lu.id, 0) AS INT) = CAST(ISNULL(COALESCE(NULLIF(bmeta.CreatedByAccountID, 0), bm.UpdatedBy), 0) AS INT)
        LEFT JOIN dbo.tblpaymode pm WITH (NOLOCK)
            ON CAST(ISNULL(pm.id, 0) AS INT) = CAST(ISNULL(r.Bank_ID, 0) AS INT)
        LEFT JOIN dbo.tbl_typemst tt WITH (NOLOCK)
            ON CAST(ISNULL(tt.id, 0) AS INT) = CAST(ISNULL(bm.BillTypeID, 0) AS INT)
        LEFT JOIN dbo.TMPPatient tp WITH (NOLOCK)
            ON tp.TmpPatientID = COALESCE(NULLIF(bm.TmpPatientId, 0), NULLIF(r.TmpPatientId, 0))
        {_canteen_customer_meta_join_sql()}
        LEFT JOIN dbo.HID_CanteenReceiptMeta rmeta WITH (NOLOCK)
            ON rmeta.ReceiptID = r.Receipt_ID
        LEFT JOIN dbo.LABUserMasterUp lu WITH (NOLOCK)
            ON CAST(ISNULL(lu.id, 0) AS INT) = CAST(ISNULL(COALESCE(NULLIF(rmeta.CollectedByAccountID, 0), TRY_CONVERT(INT, r.UpdatedBy)), 0) AS INT)
        WHERE
            ISNULL(r.CancelStatus, 0) = 0
            AND LTRIM(RTRIM(ISNULL(r.ReceiptType, N''))) = N'P'
            AND CONVERT(date, r.Receipt_Date) BETWEEN CONVERT(date, ?) AND CONVERT(date, ?)
            AND (? = 0 OR CAST(ISNULL(bm.BillTypeID, 0) AS INT) = ?)
            AND (
                ? = N''
                OR LOWER(LTRIM(RTRIM(ISNULL(r.Receipt_No, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(bm.BillNo, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(bm.Registration_No, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(tp.Name, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(tp.code, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(cm.LedgerCode, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(cm.LedgerName, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(cm.DepartmentName, N'')))) LIKE ?
                OR LOWER(COALESCE(
                    NULLIF(LTRIM(RTRIM(ISNULL(pm.paymentmode, N''))), N''),
                    NULLIF(CASE WHEN LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) <> N'P' THEN LTRIM(RTRIM(ISNULL(r.PaymentMode, N''))) ELSE N'' END, N''),
                    N'Cash'
                )) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(lu.Name, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(rmeta.CollectedByUserName, N'')))) LIKE ?
                OR LOWER(COALESCE(
                    NULLIF(LTRIM(RTRIM(ISNULL(bmeta.CreatedByUserName, N''))), N''),
                    NULLIF(LTRIM(RTRIM(ISNULL(bill_lu.Name, N''))), N''),
                    N''
                )) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(bmeta.BillingCategoryName, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(bmeta.BulkSubcategoryName, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(bmeta.PaymentClassification, N'')))) LIKE ?
            )
        ORDER BY r.Receipt_Date DESC, r.Receipt_ID DESC;
        """
        df = pd.read_sql(
            sql,
            conn,
            params=[
                row_limit,
                start_iso,
                end_iso,
                type_id_int,
                type_id_int,
                query_text,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
            ],
        )
        columns = [
            "Unit", "WalletTxnID", "ReceiptID", "ReceiptNo", "ReceiptDate", "ReceiptTime", "Amount", "Note", "BillID",
            "PaymentAgainst", "RawPaymentMode", "PaymentModeID", "PaymentModeName", "ReceiptType",
            "ReceiptTmpPatientID", "CollectionByRaw", "CollectionByAccountID", "LegacyCollectionByName",
            "BillIDResolved", "BillNo", "BillDate", "BillNetAmount", "BillDueAmount", "TypeID", "TypeName",
            "RegistrationNo", "TmpPatientID", "CustomerName", "CustomerCode", "LedgerCode", "LedgerName",
            "DepartmentName", "CollectionByName", "CollectionBySource", "CreatedByAccountID", "CreatedByName",
            "CreatedBySource", "BillingCategory", "BillingCategoryName", "BulkSubcategory", "BulkSubcategoryName",
            "PaymentClassification",
        ]
        if df is None:
            return None
        df.columns = [str(col).strip() for col in df.columns]
        df["Unit"] = unit_key

        if ensure_canteen_wallet_transaction_table(unit_key):
            wallet_df = pd.read_sql(
                f"""
                SELECT TOP (?)
                      CAST(0 AS INT) AS ReceiptID
                    , COALESCE(
                          NULLIF(LTRIM(RTRIM(ISNULL(wt.ReceiptNo, N''))), N''),
                          N'WT-' + CONVERT(NVARCHAR(30), wt.WalletTxnID)
                      ) AS ReceiptNo
                    , CAST(wt.CreatedAt AS DATETIME) AS ReceiptDate
                    , CAST(wt.CreatedAt AS DATETIME) AS ReceiptTime
                    , CAST(ISNULL(wt.Amount, 0) AS FLOAT) AS Amount
                    , LTRIM(RTRIM(ISNULL(wt.Remarks, N''))) AS Note
                    , CAST(ISNULL(wt.BillID, 0) AS INT) AS BillID
                    , N'Wallet Top-up' AS PaymentAgainst
                    , LTRIM(RTRIM(ISNULL(wt.PaymentModeName, N''))) AS RawPaymentMode
                    , CAST(ISNULL(wt.PaymentModeID, 0) AS INT) AS PaymentModeID
                    , COALESCE(NULLIF(LTRIM(RTRIM(ISNULL(wt.PaymentModeName, N''))), N''), N'Wallet') AS PaymentModeName
                    , N'WALLET_TOPUP' AS ReceiptType
                    , CAST(ISNULL(wt.TmpPatientID, 0) AS INT) AS ReceiptTmpPatientID
                    , LTRIM(RTRIM(ISNULL(wt.CreatedByUserName, N''))) AS CollectionByRaw
                    , CAST(ISNULL(wt.CreatedByAccountID, 0) AS INT) AS CollectionByAccountID
                    , LTRIM(RTRIM(ISNULL(wt.CreatedByUserName, N''))) AS ReceiptMetaCollectionByName
                    , N'hid' AS ReceiptMetaCollectionSource
                    , CAST(NULL AS NVARCHAR(120)) AS LegacyCollectionByName
                    , CAST(ISNULL(wt.BillID, 0) AS INT) AS BillIDResolved
                    , LTRIM(RTRIM(ISNULL(wt.BillNo, N''))) AS BillNo
                    , CAST(NULL AS DATETIME) AS BillDate
                    , CAST(0 AS FLOAT) AS BillNetAmount
                    , CAST(0 AS FLOAT) AS BillDueAmount
                    , CAST(ISNULL(tp.PatientType, 0) AS INT) AS TypeID
                    , N'Wallet Top-up' AS TypeName
                    , CAST(NULL AS NVARCHAR(80)) AS RegistrationNo
                    , CAST(ISNULL(tp.TmpPatientID, 0) AS INT) AS TmpPatientID
                    , LTRIM(RTRIM(ISNULL(tp.Name, N''))) AS CustomerName
                    , LTRIM(RTRIM(ISNULL(tp.code, N''))) AS CustomerCode
                    , LTRIM(RTRIM(ISNULL(cm.LedgerCode, N''))) AS LedgerCode
                    , LTRIM(RTRIM(ISNULL(cm.LedgerName, N''))) AS LedgerName
                    , LTRIM(RTRIM(ISNULL(cm.DepartmentName, N''))) AS DepartmentName
                    , N'general' AS BillingCategory
                    , N'General Billing' AS BillingCategoryName
                    , CAST(NULL AS NVARCHAR(60)) AS BulkSubcategory
                    , CAST(NULL AS NVARCHAR(160)) AS BulkSubcategoryName
                    , N'cash' AS PaymentClassification
                    , CAST(ISNULL(wt.WalletTxnID, 0) AS BIGINT) AS WalletTxnID
                FROM dbo.HID_CanteenWalletTransaction wt WITH (NOLOCK)
                INNER JOIN dbo.TMPPatient tp WITH (NOLOCK)
                    ON tp.TmpPatientID = wt.TmpPatientID
                {_canteen_customer_meta_join_sql()}
                WHERE
                    ISNULL(wt.IsCancelled, 0) = 0
                    AND
                    wt.CreatedAt >= CONVERT(DATETIME2, ?)
                    AND wt.CreatedAt < DATEADD(day, 1, CONVERT(DATETIME2, ?))
                    AND LTRIM(RTRIM(ISNULL(wt.TxnType, N''))) = N'TOPUP'
                    AND (? = 0 OR CAST(ISNULL(tp.PatientType, 0) AS INT) = ?)
                    AND (
                        ? = N''
                        OR LOWER(COALESCE(
                            NULLIF(LTRIM(RTRIM(ISNULL(wt.ReceiptNo, N''))), N''),
                            N'wt-' + CONVERT(NVARCHAR(30), wt.WalletTxnID)
                        )) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(tp.Name, N'')))) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(tp.code, N'')))) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(cm.LedgerCode, N'')))) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(cm.LedgerName, N'')))) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(cm.DepartmentName, N'')))) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(wt.PaymentModeName, N'')))) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(wt.Remarks, N'')))) LIKE ?
                        OR LOWER(LTRIM(RTRIM(ISNULL(wt.CreatedByUserName, N'')))) LIKE ?
                        OR LOWER(N'wallet top-up') LIKE ?
                    )
                ORDER BY wt.CreatedAt DESC, wt.WalletTxnID DESC;
                """,
                conn,
                params=[
                    row_limit,
                    start_iso,
                    end_iso,
                    type_id_int,
                    type_id_int,
                    query_text,
                    query_like,
                    query_like,
                    query_like,
                    query_like,
                    query_like,
                    query_like,
                    query_like,
                    query_like,
                    query_like,
                    query_like,
                ],
            )
            if wallet_df is not None and not wallet_df.empty:
                wallet_df.columns = [str(col).strip() for col in wallet_df.columns]
                wallet_df["Unit"] = unit_key
                wallet_concat_df = wallet_df.copy()
                drop_all_na_cols = [
                    col
                    for col in wallet_concat_df.columns
                    if col in df.columns and wallet_concat_df[col].isna().all()
                ]
                if drop_all_na_cols:
                    wallet_concat_df = wallet_concat_df.drop(columns=drop_all_na_cols)
                df = pd.concat([df, wallet_concat_df], ignore_index=True, sort=False)

        if df.empty:
            return pd.DataFrame(columns=columns)

        collection_ids = sorted({
            _to_int(value, 0) or 0
            for value in df.get("CollectionByAccountID", pd.Series(dtype=object)).tolist()
            if (_to_int(value, 0) or 0) > 0
        })
        hid_user_map = _canteen_fetch_hid_user_map(unit_key, collection_ids)
        collection_names = []
        collection_sources = []
        for row in df.to_dict(orient="records"):
            account_id = _to_int(row.get("CollectionByAccountID"), 0) or 0
            meta_name = _canteen_clean_text(row.get("ReceiptMetaCollectionByName"), 120)
            meta_source = _canteen_clean_text(row.get("ReceiptMetaCollectionSource"), 20)
            legacy_name = _canteen_clean_text(row.get("LegacyCollectionByName"), 120)
            hid_name = hid_user_map.get(account_id, "") if account_id > 0 else ""
            raw_name = _canteen_clean_text(row.get("CollectionByRaw"), 120)
            if raw_name in {"0", "-1"}:
                raw_name = ""
            collection_names.append(meta_name or legacy_name or hid_name or raw_name or "Unknown")
            if meta_name:
                collection_sources.append(meta_source or "hid")
            elif legacy_name:
                collection_sources.append("legacy")
            elif hid_name:
                collection_sources.append("hid")
            else:
                collection_sources.append("")
        df["CollectionByName"] = collection_names
        df["CollectionBySource"] = collection_sources

        df = _canteen_attach_bill_creator_columns(conn, unit_key, df)
        if "WalletTxnID" not in df.columns:
            df["WalletTxnID"] = 0
        df["_sort_date"] = pd.to_datetime(df.get("ReceiptDate"), errors="coerce")
        df["_sort_receipt_id"] = pd.to_numeric(df.get("ReceiptID"), errors="coerce").fillna(0)
        df["_sort_wallet_txn_id"] = pd.to_numeric(df.get("WalletTxnID"), errors="coerce").fillna(0)
        df = df.sort_values(
            by=["_sort_date", "_sort_receipt_id", "_sort_wallet_txn_id"],
            ascending=[False, False, False],
            kind="stable",
        ).drop(columns=["_sort_date", "_sort_receipt_id", "_sort_wallet_txn_id"], errors="ignore")
        for col in columns:
            if col not in df.columns:
                df[col] = None
        return df[columns].reset_index(drop=True)
    except Exception as e:
        print(f"Canteen collections fetch failed for {unit_key}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_canteen_report_rows(
    unit: str,
    report_key: str,
    *,
    from_date=None,
    to_date=None,
    type_id: int | None = None,
    query: str = "",
    limit: int = CANTEEN_DEFAULT_REPORT_LIMIT,
):
    unit_key = _canteen_unit_key(unit)
    report_name = _canteen_clean_text(report_key).lower()
    if unit_key not in CANTEEN_ALLOWED_UNITS:
        return pd.DataFrame()
    conn = get_canteen_sql_connection(unit_key)
    if not conn:
        print(f"Canteen report fetch: could not connect to {unit_key}")
        return None
    try:
        start_iso, end_iso = _canteen_resolve_date_range(from_date, to_date)
        type_id_int = _to_int(type_id, 0) or 0
        row_limit = max(1, min(int(limit or CANTEEN_DEFAULT_REPORT_LIMIT), 5000))
        if report_name == "menu_wise":
            df = pd.read_sql("EXEC dbo.usp_RptmenuwiseRaised ?, ?;", conn, params=[start_iso, end_iso])
            if df is None or df.empty:
                return pd.DataFrame(columns=["Bill_ID", "BillNo", "Itemname", "BillDate", "Quantity", "Rate", "Amount", "Registration_No", "CreatedByAccountID", "CreatedByName", "CreatedBySource"])
            df.columns = [str(col).strip() for col in df.columns]
            df = _canteen_attach_bill_creator_columns(conn, unit_key, df)
            if query:
                query_text = _canteen_clean_text(query).lower()
                mask = df.fillna("").astype(str).apply(lambda col: col.str.lower().str.contains(query_text, regex=False))
                df = df[mask.any(axis=1)].copy()
            return df.head(row_limit).reset_index(drop=True)

        if report_name == "bill_register":
            df = fetch_canteen_due_rows(
                unit_key,
                from_date=start_iso,
                to_date=end_iso,
                query=query,
                type_id=type_id_int,
                only_outstanding=False,
                limit=row_limit,
            )
            if df is None or df.empty:
                return pd.DataFrame(columns=["Bill_ID", "BillNo", "Registration_No", "BillDate", "NetAmount", "received", "DueAmount", "Typename", "BillingCategoryName", "BulkSubcategoryName", "PaymentClassification", "CreatedByAccountID", "CreatedByName", "CreatedBySource"])
            df = df.copy()
            df.columns = [str(col).strip() for col in df.columns]
            rename_map = {
                "BillID": "Bill_ID",
                "RegistrationNo": "Registration_No",
                "TypeName": "Typename",
                "ReceivedAmount": "received",
            }
            df.rename(columns=rename_map, inplace=True)
            for col in ["Bill_ID", "BillNo", "Registration_No", "BillDate", "NetAmount", "received", "DueAmount", "Typename", "BillingCategoryName", "BulkSubcategoryName", "PaymentClassification", "CreatedByAccountID", "CreatedByName", "CreatedBySource"]:
                if col not in df.columns:
                    df[col] = None
            return df[["Bill_ID", "BillNo", "Registration_No", "BillDate", "NetAmount", "received", "DueAmount", "Typename", "BillingCategoryName", "BulkSubcategoryName", "PaymentClassification", "CreatedByAccountID", "CreatedByName", "CreatedBySource"]].reset_index(drop=True)

        if report_name == "dues":
            return fetch_canteen_due_rows(
                unit_key,
                from_date=start_iso,
                to_date=end_iso,
                query=query,
                type_id=type_id_int,
                only_outstanding=True,
                limit=row_limit,
            )

        if report_name == "collections":
            return fetch_canteen_collection_rows(
                unit_key,
                from_date=start_iso,
                to_date=end_iso,
                query=query,
                type_id=type_id_int,
                limit=row_limit,
            )

        if report_name == "wallet_summary":
            return fetch_canteen_wallet_summary_rows(
                unit_key,
                from_date=start_iso,
                to_date=end_iso,
                query=query,
                type_id=type_id_int,
                limit=row_limit,
            )

        if report_name == "wallet_ledger":
            return fetch_canteen_wallet_ledger_rows(
                unit_key,
                from_date=start_iso,
                to_date=end_iso,
                query=query,
                type_id=type_id_int,
                limit=row_limit,
            )

        ensure_canteen_customer_meta_table(unit_key)
        ensure_canteen_bill_meta_table(unit_key)
        query_text = _canteen_clean_text(query).lower()
        query_like = f"%{query_text}%"
        sql = f"""
        SELECT TOP (?)
              COALESCE(
                    NULLIF(LTRIM(RTRIM(ISNULL(cm.LedgerName, N''))), N''),
                    NULLIF(LTRIM(RTRIM(ISNULL(tp.Name, N''))), N''),
                    NULLIF(LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))), N''),
                    N'Walk-In'
                ) AS LedgerName
            , LTRIM(RTRIM(ISNULL(cm.LedgerCode, N''))) AS LedgerCode
            , CAST(ISNULL(bm.TmpPatientId, 0) AS INT) AS TmpPatientID
            , CAST(ISNULL(bm.BillTypeID, 0) AS INT) AS TypeID
            , LTRIM(RTRIM(ISNULL(tt.Typename, N''))) AS TypeName
            , CAST(bm.Bill_ID AS INT) AS BillID
            , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
            , CAST(bm.BillDate AS DATETIME) AS BillDate
            , LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))) AS RegistrationNo
            , CAST(ISNULL(bm.NetAmount, 0) AS FLOAT) AS NetAmount
            , CAST(ISNULL(rec.ReceivedAmount, 0) AS FLOAT) AS ReceivedAmount
            , CAST(ISNULL(bm.DueAmount, 0) AS FLOAT) AS DueAmount
            , CAST(rec.LastReceiptDate AS DATETIME) AS LastReceiptDate
        FROM dbo.Billing_Mst bm
        LEFT JOIN dbo.TMPPatient tp
            ON tp.TmpPatientID = bm.TmpPatientId
        {_canteen_customer_meta_join_sql()}
        LEFT JOIN dbo.HID_CanteenBillMeta bmeta WITH (NOLOCK)
            ON bmeta.BillID = bm.Bill_ID
        LEFT JOIN dbo.LABUserMasterUp blu WITH (NOLOCK)
            ON CAST(ISNULL(blu.id, 0) AS INT) = CAST(ISNULL(COALESCE(NULLIF(bmeta.CreatedByAccountID, 0), bm.UpdatedBy), 0) AS INT)
        LEFT JOIN dbo.tbl_typemst tt
            ON CAST(ISNULL(tt.id, 0) AS INT) = CAST(ISNULL(bm.BillTypeID, 0) AS INT)
        OUTER APPLY (
            SELECT
                  CAST(ISNULL(SUM(ISNULL(r.Amount, 0)), 0) AS FLOAT) AS ReceivedAmount
                , MAX(r.Receipt_Date) AS LastReceiptDate
            FROM dbo.Receipt_mst r
            WHERE r.InvoiceNo = bm.Bill_ID
              AND LTRIM(RTRIM(ISNULL(r.ReceiptType, N''))) = N'P'
              AND ISNULL(r.CancelStatus, 0) = 0
        ) rec
        WHERE
            ISNULL(bm.CancelStatus, 0) = 0
            AND CONVERT(date, bm.BillDate) BETWEEN CONVERT(date, ?) AND CONVERT(date, ?)
            AND (? = 0 OR CAST(ISNULL(bm.BillTypeID, 0) AS INT) = ?)
            AND (
                ? = N''
                OR LOWER(LTRIM(RTRIM(ISNULL(cm.LedgerName, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(cm.LedgerCode, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(tp.Name, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(tp.code, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(bm.BillNo, N'')))) LIKE ?
                OR LOWER(LTRIM(RTRIM(ISNULL(bm.Registration_No, N'')))) LIKE ?
                OR LOWER(COALESCE(
                    NULLIF(LTRIM(RTRIM(ISNULL(bmeta.CreatedByUserName, N''))), N''),
                    NULLIF(LTRIM(RTRIM(ISNULL(blu.Name, N''))), N''),
                    N''
                )) LIKE ?
            )
        ORDER BY
            COALESCE(
                NULLIF(LTRIM(RTRIM(ISNULL(cm.LedgerName, N''))), N''),
                NULLIF(LTRIM(RTRIM(ISNULL(tp.Name, N''))), N''),
                NULLIF(LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))), N''),
                N'Walk-In'
            ),
            bm.BillDate,
            bm.Bill_ID;
        """
        df = pd.read_sql(
            sql,
            conn,
            params=[
                row_limit,
                start_iso,
                end_iso,
                type_id_int,
                type_id_int,
                query_text,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
                query_like,
            ],
        )
        if df is None or df.empty:
            return pd.DataFrame(columns=[
                "LedgerName", "LedgerCode", "TmpPatientID", "TypeID", "TypeName", "BillID", "BillNo",
                "BillDate", "RegistrationNo", "NetAmount", "ReceivedAmount", "DueAmount", "LastReceiptDate",
                "CreatedByAccountID", "CreatedByName", "CreatedBySource",
            ])
        df.columns = [str(col).strip() for col in df.columns]
        return _canteen_attach_bill_creator_columns(conn, unit_key, df)
    except Exception as e:
        print(f"Canteen report fetch failed for {unit_key}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Asset Management =====================
ASSET_CENTER_UNIT = "AHL"
ASSET_ALLOWED_LOCATION_CODES = {"AHL", "ACI", "BALLIA"}
ASSET_STATUS_LABELS = {
    1: "Active",
    2: "In Use",
    3: "In Store",
    4: "Under Repair",
    5: "Condemned / Disposed",
    6: "Lost",
}
ASSET_WARRANTY_BUCKET_LABELS = {
    "expired": "Expired",
    "due_30": "Due in 30 Days",
    "due_90": "Due in 90 Days",
    "covered": "Covered",
    "unknown": "Unknown",
}
ASSET_COVERAGE_TYPES = {"Warranty", "AMC", "CMC", "Not Covered"}
ASSET_COVERAGE_PENDING_LABEL = "Pending Coverage Update"
ASSET_COVERAGE_ALERT_LABELS = {
    "red": "Expired / Pending Update",
    "orange": "Due in 15 Days",
    "yellow": "Due in 30 Days",
    "blue": "Due in 60/90 Days",
    "green": "No Urgent Alert",
}

_ASSET_BOOTSTRAP_LOCK = Lock()
_ASSET_MOVEMENT_TABLE_READY = False
_ASSET_MASTER_VALUE_COLUMN_READY = False
_ASSET_COVERAGE_TABLE_READY = False
_ASSET_BREAKDOWN_TABLE_READY = False
_ASSET_NOTIFICATION_TABLE_READY = False
ASSET_MANAGEMENT_CACHE_TTL_SECONDS = _safe_cache_ttl(
    getattr(config, "ASSET_MANAGEMENT_CACHE_TTL_SECONDS", 90),
    90,
)
ASSET_MANAGEMENT_CACHE = {}
ASSET_MANAGEMENT_CACHE_LOCK = Lock()


def _asset_db_connection():
    return get_sql_connection(ASSET_CENTER_UNIT)


def _asset_cache_key_part(value):
    if isinstance(value, pd.DataFrame):
        return ("df", tuple(value.columns), len(value))
    if isinstance(value, dict):
        return tuple(sorted((str(k), _asset_cache_key_part(v)) for k, v in value.items()))
    if isinstance(value, (list, tuple, set)):
        return tuple(_asset_cache_key_part(item) for item in value)
    return str(value or "").strip().upper()


def _asset_cache_get(name: str, *parts):
    if ASSET_MANAGEMENT_CACHE_TTL_SECONDS <= 0:
        return None
    key = (str(name or "").strip(), *(_asset_cache_key_part(part) for part in parts))
    now = time.time()
    with ASSET_MANAGEMENT_CACHE_LOCK:
        entry = ASSET_MANAGEMENT_CACHE.get(key)
        if not entry:
            return None
        if float(entry.get("expires_at") or 0) <= now:
            ASSET_MANAGEMENT_CACHE.pop(key, None)
            return None
        payload = entry.get("payload")
    if isinstance(payload, pd.DataFrame):
        return payload.copy(deep=True)
    try:
        return copy.deepcopy(payload)
    except Exception:
        return payload


def _asset_cache_put(name: str, payload, *parts):
    if ASSET_MANAGEMENT_CACHE_TTL_SECONDS <= 0 or payload is None:
        return
    key = (str(name or "").strip(), *(_asset_cache_key_part(part) for part in parts))
    if isinstance(payload, pd.DataFrame):
        cached_payload = payload.copy(deep=True)
    else:
        try:
            cached_payload = copy.deepcopy(payload)
        except Exception:
            cached_payload = payload
    with ASSET_MANAGEMENT_CACHE_LOCK:
        ASSET_MANAGEMENT_CACHE[key] = {
            "payload": cached_payload,
            "expires_at": time.time() + ASSET_MANAGEMENT_CACHE_TTL_SECONDS,
        }


def invalidate_asset_management_cache():
    with ASSET_MANAGEMENT_CACHE_LOCK:
        ASSET_MANAGEMENT_CACHE.clear()


def _asset_login_db_connection():
    cfg = getattr(config, "LOGIN_DB", {}) or {}
    driver = cfg.get("DRIVER") or "{ODBC Driver 18 for SQL Server}"
    server = cfg.get("SERVER") or ""
    database = cfg.get("DATABASE") or cfg.get("DB") or ""
    uid = cfg.get("UID") or cfg.get("USER") or ""
    pwd = cfg.get("PWD") or ""
    timeout = int(cfg.get("Connection Timeout") or cfg.get("TIMEOUT") or 5)
    conn_str = (
        f"DRIVER={driver};"
        f"SERVER={server};"
        f"DATABASE={database};"
        f"UID={uid};"
        f"PWD={pwd};"
        "Encrypt=yes;"
        "TrustServerCertificate=yes;"
    )
    return pyodbc.connect(conn_str, timeout=timeout, autocommit=True)


def _asset_clean_text(value, default: str = "") -> str:
    if value is None:
        return default
    try:
        if pd.isna(value):
            return default
    except Exception:
        pass
    return str(value).strip()


def _asset_clean_limited(value, max_len: int, default: str = "") -> str:
    text = _asset_clean_text(value, default)
    if max_len and len(text) > int(max_len):
        return text[: int(max_len)]
    return text


def _asset_upper_text(value, default: str = "") -> str:
    return _asset_clean_text(value, default).upper()


def _asset_status_label(value) -> str:
    return ASSET_STATUS_LABELS.get(_to_int(value, 1) or 1, "Active")


def _asset_now():
    try:
        return datetime.now(tz=LOCAL_TZ).replace(tzinfo=None)
    except Exception:
        return datetime.now()


def _asset_machine_type_label(machine_type_id, current_value: str = "") -> str:
    existing = _asset_clean_text(current_value)
    if existing:
        return existing
    machine_type = _to_int(machine_type_id)
    if machine_type == 1:
        return "Medical"
    if machine_type == 2:
        return "Non-Medical"
    if machine_type == 3:
        return "Information Technology (IT)"
    return "Unknown"


def _asset_normalize_location_codes(location_codes):
    if location_codes is None:
        return None
    items = []
    if isinstance(location_codes, (list, tuple, set)):
        items = list(location_codes)
    elif isinstance(location_codes, str):
        txt = location_codes.strip()
        if not txt:
            return []
        try:
            parsed = json.loads(txt)
            if isinstance(parsed, (list, tuple, set)):
                items = list(parsed)
            else:
                items = re.split(r"[,\|/]+", txt)
        except Exception:
            items = re.split(r"[,\|/]+", txt)
    else:
        items = [location_codes]

    out = []
    seen = set()
    for item in items:
        code = _asset_upper_text(item)
        if not code or code in seen:
            continue
        if code not in ASSET_ALLOWED_LOCATION_CODES:
            continue
        out.append(code)
        seen.add(code)
    return out


def _asset_scope_sql(location_codes, alias: str = "loc"):
    codes = _asset_normalize_location_codes(location_codes)
    if codes is None:
        return "", []
    if not codes:
        return " AND 1 = 0 ", []
    placeholders = ",".join("?" for _ in codes)
    sql = f" AND UPPER(LTRIM(RTRIM(ISNULL({alias}.location_code, '')))) IN ({placeholders}) "
    return sql, codes


def _asset_scope_match(unit_scope, location_codes) -> bool:
    scope_codes = _asset_normalize_location_codes(location_codes)
    if scope_codes is None or not scope_codes:
        return True
    raw = _asset_clean_text(unit_scope)
    if not raw or raw == "*":
        return True
    try:
        parsed = json.loads(raw)
        if isinstance(parsed, (list, tuple, set)):
            tokens = list(parsed)
        else:
            tokens = re.split(r"[,\|/]+", raw)
    except Exception:
        tokens = re.split(r"[,\|/]+", raw)
    token_set = {_asset_upper_text(token) for token in tokens if _asset_upper_text(token)}
    if "*" in token_set:
        return True
    return bool(token_set & set(scope_codes))


def _asset_parse_warranty_years(raw):
    txt = _asset_clean_text(raw)
    if not txt:
        return None
    match = re.search(r"-?\d+(\.\d+)?", txt)
    if not match:
        return None
    try:
        years = int(float(match.group(0)))
        return years if years >= 0 else None
    except Exception:
        return None


def _asset_warranty_years_param(raw):
    years = _asset_parse_warranty_years(raw)
    if years is None and _asset_clean_text(raw):
        raise ValueError("Warranty must be entered as number of years, for example 1 or 5.")
    return years


def _asset_money_value(raw):
    text = _asset_clean_text(raw).replace(",", "")
    if text.upper().startswith("RS."):
        text = text[3:].strip()
    if not text:
        return None
    try:
        amount = _to_decimal(text, None)
        if amount is None or amount < Decimal("0"):
            return None
        return amount.quantize(Decimal("0.01"))
    except Exception:
        return None


def _asset_money_display(raw):
    amount = _asset_money_value(raw)
    if amount is None:
        return None
    try:
        return f"Rs. {amount:,.2f}"
    except Exception:
        return str(amount)


def _asset_date_only(raw):
    dt_val = _to_datetime(raw)
    if dt_val is None:
        return None
    try:
        return dt_val.date()
    except Exception:
        return None


def _asset_date_display(raw):
    dt_val = _to_datetime(raw)
    if dt_val is None:
        return None
    return dt_val.strftime("%Y-%m-%d")


def _asset_coverage_type(raw) -> str:
    text = _asset_clean_text(raw)
    lookup = {item.upper(): item for item in ASSET_COVERAGE_TYPES}
    return lookup.get(text.upper(), "")


def _asset_coverage_priority(coverage_type, expiry_date):
    cov = _asset_coverage_type(coverage_type)
    if not cov:
        return "red", None, True
    if cov == "Not Covered":
        return "green", None, False
    expiry = _asset_date_only(expiry_date)
    if expiry is None:
        return "red", None, True
    today = datetime.now(tz=LOCAL_TZ).date()
    days_left = int((expiry - today).days)
    if days_left < 0:
        return "red", days_left, False
    if days_left <= 15:
        return "orange", days_left, False
    if days_left <= 30:
        return "yellow", days_left, False
    if days_left <= 90:
        return "blue", days_left, False
    return "green", days_left, False


def _asset_serialize_value(value):
    if value is None:
        return None
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, datetime):
        return value.strftime("%Y-%m-%d %H:%M:%S")
    if hasattr(value, "strftime") and value.__class__.__name__.lower() == "date":
        return value.strftime("%Y-%m-%d")
    if isinstance(value, pd.Timestamp):
        if pd.isna(value):
            return None
        return value.to_pydatetime().strftime("%Y-%m-%d %H:%M:%S")
    if isinstance(value, memoryview):
        return value.tobytes().decode(errors="ignore")
    if isinstance(value, bytes):
        return value.decode(errors="ignore")
    if hasattr(value, "item") and not isinstance(value, (str, bytes, bytearray)):
        try:
            return value.item()
        except Exception:
            pass
    return value


def _asset_records(df: pd.DataFrame):
    if df is None or df.empty:
        return []
    out = []
    for row in df.to_dict(orient="records"):
        out.append({str(k): _asset_serialize_value(v) for k, v in row.items()})
    return out


def ensure_asset_movement_log_table():
    global _ASSET_MOVEMENT_TABLE_READY
    if _ASSET_MOVEMENT_TABLE_READY:
        return True
    with _ASSET_BOOTSTRAP_LOCK:
        if _ASSET_MOVEMENT_TABLE_READY:
            return True
        conn = _asset_db_connection()
        if not conn:
            return False
        try:
            try:
                conn.autocommit = False
            except Exception:
                pass
            cursor = conn.cursor()
            cursor.execute(
                """
                IF OBJECT_ID('dbo.HID_Asset_Movement_Log', 'U') IS NULL
                BEGIN
                    CREATE TABLE dbo.HID_Asset_Movement_Log (
                        MovementLogID INT IDENTITY(1,1) NOT NULL PRIMARY KEY,
                        AssetID INT NOT NULL,
                        MovementType VARCHAR(32) NOT NULL,
                        FromEntityType VARCHAR(32) NULL,
                        FromEntityKey VARCHAR(100) NULL,
                        FromEntityLabel NVARCHAR(255) NULL,
                        ToEntityType VARCHAR(32) NULL,
                        ToEntityKey VARCHAR(100) NULL,
                        ToEntityLabel NVARCHAR(255) NULL,
                        LocationID INT NULL,
                        StatusBefore INT NULL,
                        StatusAfter INT NULL,
                        Remarks NVARCHAR(1000) NULL,
                        CreatedByUserName NVARCHAR(255) NULL,
                        CreatedByAccountId INT NULL,
                        CreatedAt DATETIME NOT NULL CONSTRAINT DF_HID_Asset_Movement_Log_CreatedAt DEFAULT (GETDATE())
                    );
                END;

                IF NOT EXISTS (
                    SELECT 1
                    FROM sys.indexes
                    WHERE object_id = OBJECT_ID('dbo.HID_Asset_Movement_Log')
                      AND name = 'IX_HID_Asset_Movement_Log_AssetID_CreatedAt'
                )
                BEGIN
                    CREATE INDEX IX_HID_Asset_Movement_Log_AssetID_CreatedAt
                    ON dbo.HID_Asset_Movement_Log (AssetID, CreatedAt DESC, MovementLogID DESC);
                END;

                IF NOT EXISTS (
                    SELECT 1
                    FROM sys.indexes
                    WHERE object_id = OBJECT_ID('dbo.HID_Asset_Movement_Log')
                      AND name = 'IX_HID_Asset_Movement_Log_CreatedAt'
                )
                BEGIN
                    CREATE INDEX IX_HID_Asset_Movement_Log_CreatedAt
                    ON dbo.HID_Asset_Movement_Log (CreatedAt DESC, MovementLogID DESC);
                END;
                """
            )
            conn.commit()
            _ASSET_MOVEMENT_TABLE_READY = True
            return True
        except Exception as exc:
            try:
                conn.rollback()
            except Exception:
                pass
            print(f"Asset movement log bootstrap failed: {exc}")
            return False
        finally:
            try:
                conn.close()
            except Exception:
                pass

ASSET_PO_LOOKUP_UNITS = ("AHLSTORE", "CANCERUNITSTORE")


def fetch_asset_po_details_from_store_units(po_no: str, units=None):
    """
    Search PO details from store DBs for Asset Management PO autofill.

    Searches AHLSTORE and CANCERUNITSTORE by default.
    Returns one or more matching PO headers so the UI can fill:
      - PO No.
      - PO Date
      - Supplier
      - Asset Value / PO Amount
    """
    po_text = _asset_clean_text(po_no, 80)
    if not po_text:
        return {
            "status": "error",
            "message": "Please enter a PO number.",
            "rows": [],
        }

    search_units = []
    for unit in (units or ASSET_PO_LOOKUP_UNITS):
        unit_key = str(unit or "").strip().upper()
        if unit_key in ASSET_PO_LOOKUP_UNITS and unit_key not in search_units:
            search_units.append(unit_key)

    if not search_units:
        search_units = list(ASSET_PO_LOOKUP_UNITS)

    rows = []
    errors = []

    for unit in search_units:
        conn = get_sql_connection(unit)
        if not conn:
            errors.append(f"{unit}: connection failed")
            continue

        try:
            def q_ident(name):
                return "[" + str(name or "").replace("]", "]]") + "]"

            po_table = _resolve_table_name(conn, ["IVPoMst", "IvPoMst", "IVPOMST"]) or "IVPoMst"
            supplier_table = _resolve_table_name(conn, ["IVSupplier", "IvSupplier", "IVSUPPLIER"])

            po_id_col = _resolve_column(conn, po_table, ["ID", "Id", "POID", "POId"]) or "ID"
            po_no_col = _resolve_column(conn, po_table, ["PONo", "PoNo", "PO_No"]) or "PONo"
            po_date_col = _resolve_column(conn, po_table, ["PODate", "PoDate", "PO_Date"]) or "PODate"
            supplier_id_col = _resolve_column(conn, po_table, ["SupplierID", "SupplierId", "Supplier_ID"])
            amount_col = _resolve_column(conn, po_table, ["NetAmount", "PONetAmount", "GrandTotal", "TotalAmount", "Amount"])
            status_col = _resolve_column(conn, po_table, ["Status", "POStatus"])

            if not po_id_col or not po_no_col:
                errors.append(f"{unit}: PO table columns not available")
                continue

            supplier_join = ""
            supplier_name_select = "CAST(N'' AS NVARCHAR(255)) AS SupplierName"
            supplier_id_select = "CAST(0 AS INT) AS StoreSupplierID"
            if supplier_id_col:
                supplier_id_select = f"CAST(ISNULL(pm.{q_ident(supplier_id_col)}, 0) AS INT) AS StoreSupplierID"
                if supplier_table:
                    supplier_pk_col = _resolve_column(conn, supplier_table, ["ID", "Id", "SupplierID", "SupplierId"]) or "ID"
                    supplier_name_col = _resolve_column(conn, supplier_table, ["Name", "SupplierName", "Supplier_Name"])
                    supplier_join = (
                        f"LEFT JOIN dbo.{q_ident(supplier_table)} sm WITH (NOLOCK) "
                        f"ON sm.{q_ident(supplier_pk_col)} = pm.{q_ident(supplier_id_col)}"
                    )
                    if supplier_name_col:
                        supplier_name_select = f"LTRIM(RTRIM(ISNULL(sm.{q_ident(supplier_name_col)}, N''))) AS SupplierName"

            po_date_select = f"CAST(pm.{q_ident(po_date_col)} AS DATE) AS PODate" if po_date_col else "CAST(NULL AS DATE) AS PODate"
            amount_select = f"CAST(ISNULL(pm.{q_ident(amount_col)}, 0) AS DECIMAL(18,2))" if amount_col else "CAST(0 AS DECIMAL(18,2))"
            status_select = f"LTRIM(RTRIM(ISNULL(pm.{q_ident(status_col)}, N''))) AS POStatus" if status_col else "CAST(N'' AS NVARCHAR(40)) AS POStatus"

            where_parts = [
                f"LTRIM(RTRIM(ISNULL(pm.{q_ident(po_no_col)}, N''))) = ?",
                f"LTRIM(RTRIM(ISNULL(pm.{q_ident(po_no_col)}, N''))) LIKE ?",
            ]
            params = [unit, po_text, f"%{po_text}%"]
            po_id_search = _to_int(po_text)
            if po_id_search:
                where_parts.append(f"pm.{q_ident(po_id_col)} = ?")
                params.append(po_id_search)

            sql = f"""
            SELECT TOP 20
                  ? AS SourceUnit
                , CAST(pm.{q_ident(po_id_col)} AS INT) AS POID
                , LTRIM(RTRIM(ISNULL(pm.{q_ident(po_no_col)}, N''))) AS PONo
                , {po_date_select}
                , {supplier_id_select}
                , {supplier_name_select}
                , {amount_select} AS POAmount
                , {amount_select} AS PONetAmount
                , {status_select}
            FROM dbo.{q_ident(po_table)} pm WITH (NOLOCK)
            {supplier_join}
            WHERE
                {" OR ".join(where_parts)}
            ORDER BY {("pm." + q_ident(po_date_col) + " DESC, ") if po_date_col else ""}pm.{q_ident(po_id_col)} DESC;
            """
            df = pd.read_sql(sql, conn, params=params)
            if df is None or df.empty:
                continue

            df.columns = [str(c).strip() for c in df.columns]

            for _, row in df.iterrows():
                po_date = row.get("PODate")
                if po_date is not None and not pd.isna(po_date):
                    try:
                        po_date_display = pd.to_datetime(po_date).strftime("%Y-%m-%d")
                    except Exception:
                        po_date_display = str(po_date)[:10]
                else:
                    po_date_display = ""

                po_amount = _safe_float(row.get("PONetAmount"), 0)
                if not po_amount:
                    po_amount = _safe_float(row.get("POAmount"), 0)

                rows.append({
                    "source_unit": str(row.get("SourceUnit") or unit).strip().upper(),
                    "po_id": _to_int(row.get("POID"), 0) or 0,
                    "po_no": _asset_clean_text(row.get("PONo"), 80),
                    "po_date": po_date_display,
                    "store_supplier_id": _to_int(row.get("StoreSupplierID"), 0) or 0,
                    "supplier_name": _asset_clean_text(row.get("SupplierName"), 250),
                    "po_amount": round(float(po_amount or 0), 2),
                    "po_status": _asset_clean_text(row.get("POStatus"), 40),
                })

        except Exception as exc:
            errors.append(f"{unit}: {exc}")
        finally:
            try:
                conn.close()
            except Exception:
                pass

    if not rows:
        unit_label = " or ".join(search_units)
        msg = f"No PO found in {unit_label}."
        if errors:
            msg += " " + " | ".join(errors)
        return {
            "status": "error",
            "message": msg,
            "rows": [],
            "errors": errors,
        }

    return {
        "status": "success",
        "message": f"{len(rows)} PO record(s) found.",
        "rows": rows,
    }




