def _asset_master_value_column_exists(conn) -> bool:
    if conn is None:
        return False
    try:
        cursor = conn.cursor()
        cursor.execute("SELECT CASE WHEN COL_LENGTH('dbo.asset_master', 'asset_value') IS NULL THEN 0 ELSE 1 END;")
        row = cursor.fetchone()
        return bool(row and int(row[0] or 0) == 1)
    except Exception:
        return False


