def _asset_master_search_sql(search_text: str, alias: str = "m"):
    search_value = _asset_clean_text(search_text)
    if not search_value:
        return "", []
    pattern = f"%{search_value}%"
    return (
        f"""
        AND (
            ISNULL({alias}.Code, '') LIKE ?
            OR ISNULL({alias}.Name, '') LIKE ?
            OR ISNULL({alias}.ContactPerson, '') LIKE ?
            OR ISNULL({alias}.Phone1, '') LIKE ?
        )
        """,
        [pattern, pattern, pattern, pattern],
    )


def fetch_asset_manufacturer_master_rows(search_text: str = ""):
    cached = _asset_cache_get("manufacturer_master_rows", search_text or "")
    if cached is not None:
        return cached
    conn = _asset_db_connection()
    if not conn:
        return []
    try:
        search_sql, search_params = _asset_master_search_sql(search_text, "m")
        df = pd.read_sql(
            f"""
            SELECT
                m.ID AS id,
                LTRIM(RTRIM(ISNULL(m.Code, ''))) AS code,
                LTRIM(RTRIM(ISNULL(m.Name, ''))) AS name,
                LTRIM(RTRIM(ISNULL(m.Address, ''))) AS address,
                ISNULL(m.City, 0) AS city_id,
                LTRIM(RTRIM(ISNULL(c.City_Name, ''))) AS city_name,
                ISNULL(m.State, 0) AS state_id,
                LTRIM(RTRIM(ISNULL(s.State_Name, ''))) AS state_name,
                LTRIM(RTRIM(ISNULL(m.Pin, ''))) AS pin,
                LTRIM(RTRIM(ISNULL(m.ContactPerson, ''))) AS contact_person,
                LTRIM(RTRIM(ISNULL(m.ContactDesignation, ''))) AS contact_designation,
                LTRIM(RTRIM(ISNULL(m.Phone1, ''))) AS phone1,
                LTRIM(RTRIM(ISNULL(m.Phone2, ''))) AS phone2,
                LTRIM(RTRIM(ISNULL(m.CellPhone, ''))) AS cellphone,
                LTRIM(RTRIM(ISNULL(m.Email, ''))) AS email,
                LTRIM(RTRIM(ISNULL(m.Web, ''))) AS web,
                LTRIM(RTRIM(ISNULL(m.Note, ''))) AS note,
                LTRIM(RTRIM(ISNULL(m.Society, ''))) AS society,
                LTRIM(RTRIM(ISNULL(m.Landmark, ''))) AS landmark,
                CAST(ISNULL(m.Active, 1) AS INT) AS active
            FROM dbo.ManufacturerUp m WITH (NOLOCK)
            LEFT JOIN dbo.State_Mst s WITH (NOLOCK)
                ON s.State_ID = m.State
            LEFT JOIN dbo.City_Mst c WITH (NOLOCK)
                ON c.City_ID = m.City
            WHERE 1 = 1
            {search_sql}
            ORDER BY m.Name;
            """,
            conn,
            params=search_params or None,
        )
        rows = _asset_records(df)
        _asset_cache_put("manufacturer_master_rows", rows, search_text or "")
        return rows
    except Exception as exc:
        print(f"fetch_asset_manufacturer_master_rows failed: {exc}")
        return []
    finally:
        try:
            conn.close()
        except Exception:
            pass


