def _asset_equipment_id_is_identity(conn):
    try:
        cur = conn.cursor()
        cur.execute(
            """
            SELECT COLUMNPROPERTY(OBJECT_ID('dbo.asset_equipment'), 'equId', 'IsIdentity')
            """
        )
        row = cur.fetchone()
        return bool(row and _to_int(row[0], 0) == 1)
    except Exception:
        return False


