def search_asset_public_employees(query, limit=12, units=None):
    q = _asset_clean_limited(query, 80)
    q_digits = re.sub(r"\D+", "", q)
    if len(q) < 2 and not q_digits:
        return []
    like = f"%{q.lower()}%"
    search_units = _asset_normalize_location_codes(units) or sorted(ASSET_ALLOWED_LOCATION_CODES)
    top_n = max(1, min(_to_int(limit, 12) or 12, 30))
    rows = []
    seen = set()

    for unit in search_units:
        conn = get_sql_connection(unit)
        if not conn:
            continue
        try:
            sql = f"""
                SELECT TOP {top_n}
                    CAST(e.EmpID AS NVARCHAR(50)) AS employee_id,
                    LTRIM(RTRIM(CONCAT(
                        ISNULL(e.FirstName, N''), N' ',
                        ISNULL(e.MiddleName, N''), N' ',
                        ISNULL(e.LastName, N'')
                    ))) AS employee_name,
                    LTRIM(RTRIM(ISNULL(e.Mobile, N''))) AS mobile,
                    LTRIM(RTRIM(ISNULL(dm.Department_Name, N''))) AS department,
                    LTRIM(RTRIM(ISNULL(desig.Designation_Name, N''))) AS designation,
                    CAST(? AS VARCHAR(20)) AS unit
                FROM dbo.employee_mst e WITH (NOLOCK)
                LEFT JOIN dbo.Department_Mst dm WITH (NOLOCK)
                    ON dm.Department_ID = e.Department_ID
                LEFT JOIN dbo.Designation_Mst desig WITH (NOLOCK)
                    ON desig.Designation_ID = e.Designation_ID
                WHERE ISNULL(e.Deactive, 0) = 0
                  AND (
                        (? <> '' AND CAST(e.EmpID AS NVARCHAR(50)) = ?)
                     OR (? <> '' AND LTRIM(RTRIM(ISNULL(e.PersonalNo, N''))) = ?)
                     OR (? <> '' AND LTRIM(RTRIM(ISNULL(e.Mobile, N''))) LIKE ?)
                     OR LOWER(LTRIM(RTRIM(CONCAT(ISNULL(e.FirstName, N''), N' ', ISNULL(e.MiddleName, N''), N' ', ISNULL(e.LastName, N''))))) LIKE ?
                     OR LOWER(LTRIM(RTRIM(ISNULL(e.Short_Name, N'')))) LIKE ?
                  )
                ORDER BY
                    CASE
                        WHEN (? <> '' AND CAST(e.EmpID AS NVARCHAR(50)) = ?) THEN 0
                        WHEN (? <> '' AND LTRIM(RTRIM(ISNULL(e.Mobile, N''))) = ?) THEN 1
                        ELSE 2
                    END,
                    employee_name;
            """
            mobile_query = q_digits or q
            params = [
                unit,
                q_digits, q_digits,
                q, q,
                mobile_query, f"%{mobile_query}%",
                like,
                like,
                q_digits, q_digits,
                mobile_query, mobile_query,
            ]
            df = pd.read_sql(sql, conn, params=params)
            for rec in _asset_records(df):
                emp_id = _asset_clean_text(rec.get("employee_id"))
                unit_key = _asset_upper_text(rec.get("unit"))
                dedupe = (unit_key, emp_id)
                if not emp_id or dedupe in seen:
                    continue
                seen.add(dedupe)
                rows.append(
                    {
                        "employee_id": emp_id,
                        "employee_name": _asset_clean_text(rec.get("employee_name")) or f"Employee {emp_id}",
                        "mobile": _asset_clean_text(rec.get("mobile")),
                        "department": _asset_clean_text(rec.get("department")),
                        "designation": _asset_clean_text(rec.get("designation")),
                        "unit": unit_key,
                        "source": "local",
                    }
                )
                if len(rows) >= top_n:
                    return rows
        except Exception as exc:
            print(f"search_asset_public_employees failed for {unit}: {exc}")
        finally:
            try:
                conn.close()
            except Exception:
                pass
    return rows[:top_n]


def search_asset_public_assets(query="", limit=25, location_codes=None):
    q = _asset_clean_limited(query, 120)

    # Public QR page should not expose/load asset list without a search term.
    if len(q) < 2:
        return []

    filters = {"page": 1, "page_size": max(10, min(_to_int(limit, 25) or 25, 50)), "sort": "asset_code"}
    if q:
        filters["search"] = q

    scoped_locations = [
        _asset_clean_text(code).upper()
        for code in (location_codes or [])
        if _asset_clean_text(code).upper() in {"AHL", "ACI", "BALLIA"}
    ]

    result = fetch_asset_register_rows(location_codes=scoped_locations or None, filters=filters)

    rows = []
    for rec in result.get("rows") or []:
        status_code = _to_int(rec.get("asset_status_code"), 1) or 1
        if status_code in {5, 6}:
            continue

        location_code = _asset_clean_text(rec.get("location_code")).upper()
        if scoped_locations and location_code not in scoped_locations:
            continue

        rows.append(
            {
                "asset_id": _to_int(rec.get("asset_id")),
                "asset_code": _asset_clean_text(rec.get("asset_code")),
                "asset_name": _asset_clean_text(rec.get("equipment_name") or rec.get("model_name") or "Asset"),
                "equipment_name": _asset_clean_text(rec.get("equipment_name") or rec.get("model_name") or "Asset"),
                "machine_type_name": _asset_clean_text(rec.get("machine_type_name")),
                "serial_number": _asset_clean_text(rec.get("serial_number")),
                "location_name": _asset_clean_text(rec.get("location_name")),
                "location_code": location_code,
                "status_label": _asset_clean_text(rec.get("asset_status_label")),
            }
        )

    # Attach current OPEN breakdown ticket, if the searched asset is already under breakdown cycle.
    try:
        asset_ids = {_to_int(row.get("asset_id")) for row in rows if _to_int(row.get("asset_id"))}
        if asset_ids:
            open_tickets = fetch_asset_breakdown_tickets(
                location_codes=scoped_locations or None,
                status="OPEN",
                limit=5000,
            )
            open_ticket_map = {}
            for ticket in open_tickets or []:
                ticket_asset_id = _to_int(ticket.get("asset_id"))
                if ticket_asset_id in asset_ids and ticket_asset_id not in open_ticket_map:
                    open_ticket_map[ticket_asset_id] = ticket

            for row in rows:
                ticket = open_ticket_map.get(_to_int(row.get("asset_id")))
                if ticket:
                    row["has_open_breakdown"] = True
                    row["open_breakdown"] = {
                        "ticket_id": ticket.get("ticket_id"),
                        "ticket_no": ticket.get("ticket_no"),
                        "status": ticket.get("status"),
                        "status_label": ticket.get("status_label") or "Open",
                        "breakdown_datetime_display": ticket.get("breakdown_datetime_display"),
                        "breakdown_reason": ticket.get("breakdown_reason"),
                        "reported_status": ticket.get("reported_status"),
                        "priority": ticket.get("priority"),
                        "expected_technician_visit_display": ticket.get("expected_technician_visit_display"),
                        "repair_verdict_label": ticket.get("repair_verdict_label"),
                        "repair_verdict_reason": ticket.get("repair_verdict_reason"),
                        "created_at_display": ticket.get("created_at_display"),
                    }
                else:
                    row["has_open_breakdown"] = False
                    row["open_breakdown"] = None
    except Exception as exc:
        print(f"Public asset open breakdown status attach failed: {exc}")

    return rows


def create_public_asset_breakdown_complaint(payload):
    payload = payload or {}
    issue = _asset_clean_limited(payload.get("issue_description") or payload.get("breakdown_reason"), 1000)
    reported_status = _asset_clean_limited(payload.get("reported_status"), 80)
    priority = _asset_clean_limited(payload.get("priority") or "Normal", 20)
    if priority not in {"Normal", "Urgent", "Critical"}:
        priority = "Normal"
    if not _to_int(payload.get("asset_id")):
        return {"success": False, "message": "Please select the affected machine/equipment."}, 400
    if not _asset_clean_text(payload.get("employee_id")) or not _asset_clean_text(payload.get("employee_name")):
        return {"success": False, "message": "Please identify the reporting employee."}, 400
    if not issue:
        return {"success": False, "message": "Please describe the issue with the machine/equipment."}, 400
    if not reported_status:
        return {"success": False, "message": "Please select the current machine status."}, 400

    existing_rows = fetch_asset_breakdown_tickets(asset_id=_to_int(payload.get("asset_id")), status="OPEN", limit=1)
    if existing_rows:
        ticket = existing_rows[0]
        current_status = " | ".join(
            part
            for part in [
                ticket.get("ticket_no"),
                ticket.get("asset_code"),
                ticket.get("asset_name"),
                ticket.get("status_label") or "Open",
                f"Opened {ticket.get('breakdown_datetime_display')}" if ticket.get("breakdown_datetime_display") else "",
            ]
            if _asset_clean_text(part)
        )
        return {
            "success": True,
            "status": "success",
            "existing_breakdown": True,
            "complaint_id": ticket.get("ticket_id"),
            "complaint_no": ticket.get("ticket_no"),
            "ticket": ticket,
            "asset_code": ticket.get("asset_code"),
            "asset_name": ticket.get("asset_name"),
            "submitted_at": ticket.get("created_at_display"),
            "current_status": current_status,
            "message": "This equipment is already under breakdown cycle. Current status is shown below.",
        }, 200

    result = create_asset_breakdown_ticket(
        {
            "asset_id": payload.get("asset_id"),
            "breakdown_datetime": _asset_now(),
            "breakdown_reason": issue,
            "complaint_source": "PUBLIC_QR",
            "reported_status": reported_status,
            "priority": priority,
            "employee_id": _asset_clean_limited(payload.get("employee_id"), 50),
            "employee_name": _asset_clean_limited(payload.get("employee_name"), 200),
            "employee_department": _asset_clean_limited(payload.get("employee_department"), 200),
            "employee_designation": _asset_clean_limited(payload.get("employee_designation"), 200),
            "employee_mobile": _asset_clean_limited(payload.get("employee_mobile"), 30),
            "employee_unit": _asset_clean_limited(payload.get("employee_unit"), 20),
            "contact_mobile": _asset_clean_limited(payload.get("contact_mobile"), 30),
        },
        actor_user_id=0,
        actor_username="Public QR / Employee self-reported",
    )
    if result.get("status") != "success":
        return {"success": False, "message": result.get("message") or "Unable to register breakdown complaint."}, 400
    ticket = result.get("ticket") or {}
    return {
        "success": True,
        "status": "success",
        "complaint_id": ticket.get("ticket_id"),
        "complaint_no": ticket.get("ticket_no"),
        "ticket": ticket,
        "asset_code": ticket.get("asset_code"),
        "asset_name": ticket.get("asset_name"),
        "submitted_at": ticket.get("created_at_display"),
        "message": "Breakdown complaint registered successfully.",
    }, 200


def _asset_prepare_frame(df: pd.DataFrame):
    if df is None:
        return pd.DataFrame()
    if df.empty:
        return df.copy()

    out = df.copy()
    for col in out.columns:
        if out[col].dtype == object:
            try:
                out[col] = out[col].apply(lambda value: _asset_clean_text(value) if not pd.isna(value) else "")
            except Exception:
                pass

    date_cols = [
        "purchage_orderDate",
        "invoice_date",
        "insertOn",
        "updateOn",
        "last_movement_at",
        "installation_date",
        "warranty_start_date",
        "warranty_end_date",
        "amc_date",
        "coverage_start_date",
        "coverage_expiry_date",
        "coverage_updated_at",
    ]
    for col in date_cols:
        if col in out.columns:
            out[col] = pd.to_datetime(out[col], errors="coerce")

    int_cols = [
        "asset_id",
        "machine_type",
        "equ_id",
        "brand_id",
        "supplier_id",
        "asset_status",
        "insertBy",
        "updateBy",
        "locationId",
        "asset_srno",
        "status",
        "maintenance_id",
        "maint_status",
        "last_status_before",
        "last_status_after",
        "coverage_history_id",
        "coverage_document_file_id",
        "coverage_updated_by_account_id",
    ]
    for col in int_cols:
        if col in out.columns:
            out[col] = out[col].apply(lambda value: _to_int(value))

    for col in ["amc_value", "amc_tax", "amc_amount", "asset_value"]:
        if col in out.columns:
            out[col] = out[col].apply(lambda value: float(_to_decimal(value, Decimal("0"))) if _asset_clean_text(value) else None)

    if "asset_value" in out.columns:
        out["asset_value_display"] = out["asset_value"].apply(_asset_money_display)
    else:
        out["asset_value"] = None
        out["asset_value_display"] = None

    coverage_type_series = out.get("coverage_type", pd.Series([""] * len(out), index=out.index)).apply(_asset_coverage_type)
    out["coverage_type"] = coverage_type_series
    out["coverage_status_label"] = coverage_type_series.where(coverage_type_series != "", ASSET_COVERAGE_PENDING_LABEL)
    out["coverage_vendor"] = out.get("coverage_vendor", pd.Series([""] * len(out), index=out.index)).apply(_asset_clean_text)
    out["coverage_contract_no"] = out.get("coverage_contract_no", pd.Series([""] * len(out), index=out.index)).apply(_asset_clean_text)
    out["coverage_remarks"] = out.get("coverage_remarks", pd.Series([""] * len(out), index=out.index)).apply(_asset_clean_text)
    for col in ["coverage_start_date", "coverage_expiry_date", "coverage_updated_at"]:
        if col in out.columns:
            out[col] = pd.to_datetime(out[col], errors="coerce")
        else:
            out[col] = pd.NaT
    out["coverage_start_date_display"] = out["coverage_start_date"].apply(
        lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d")
    )
    out["coverage_expiry_date_display"] = out["coverage_expiry_date"].apply(
        lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d")
    )
    out["coverage_updated_at_display"] = out["coverage_updated_at"].apply(
        lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d %H:%M")
    )
    priority_rows = out.apply(lambda row: _asset_coverage_priority(row.get("coverage_type"), row.get("coverage_expiry_date")), axis=1)
    out["coverage_alert_priority"] = priority_rows.apply(lambda item: item[0])
    out["coverage_days_left"] = priority_rows.apply(lambda item: item[1])
    out["coverage_pending_update"] = priority_rows.apply(lambda item: bool(item[2]))
    out["coverage_alert_label"] = out["coverage_alert_priority"].map(ASSET_COVERAGE_ALERT_LABELS).fillna("No Urgent Alert")
    priority_rank = {"red": 1, "orange": 2, "yellow": 3, "blue": 4, "green": 5}
    out["coverage_alert_rank"] = out["coverage_alert_priority"].map(priority_rank).fillna(9).astype(int)

    out["machine_type_name"] = out.apply(
        lambda row: _asset_machine_type_label(row.get("machine_type"), row.get("machine_type_name")),
        axis=1,
    )
    if "equipment_name" in out.columns:
        out["equipment_name"] = out["equipment_name"].replace("", pd.NA).fillna(out.get("model_name", "")).replace("", "Asset")
    if "manufacturer_name" in out.columns:
        out["manufacturer_name"] = out["manufacturer_name"].replace("", "Not tagged")
    if "supplier_name" in out.columns:
        out["supplier_name"] = out["supplier_name"].replace("", "Not tagged")
    if "location_name" in out.columns:
        out["location_name"] = out["location_name"].replace("", "Location not tagged")

    out["asset_status_code"] = out["asset_status"].apply(lambda value: _to_int(value, 1) or 1)
    out["asset_status_label"] = out["asset_status_code"].apply(_asset_status_label)
    out["location_code_upper"] = out.get("location_code", "").apply(_asset_upper_text)

    holder_label = out.get("current_holder_label", pd.Series([""] * len(out), index=out.index)).apply(_asset_clean_text)
    holder_type = out.get("current_holder_type", pd.Series([""] * len(out), index=out.index)).apply(_asset_clean_text)
    holder_key = out.get("current_holder_key", pd.Series([""] * len(out), index=out.index)).apply(_asset_clean_text)

    fallback_holder = out.get("location_name", pd.Series([""] * len(out), index=out.index)).apply(
        lambda value: f"{value} Store" if _asset_clean_text(value) else "Unassigned"
    )
    out["current_holder_label"] = holder_label.where(holder_label != "", fallback_holder)
    out["current_holder_type"] = holder_type.where(holder_type != "", "location")
    out["current_holder_key"] = holder_key.where(holder_key != "", out.get("locationId", "").apply(lambda value: str(_to_int(value) or "")))

    out["warranty_years"] = out.get("warranty", "").apply(_asset_parse_warranty_years)
    out["warranty_start_date_resolved"] = out.get("warranty_start_date")
    if "invoice_date" in out.columns:
        out["warranty_start_date_resolved"] = out["warranty_start_date_resolved"].where(
            out["warranty_start_date_resolved"].notna(),
            out["invoice_date"],
        )

    def _resolve_warranty_end(row):
        explicit_end = row.get("warranty_end_date")
        if not pd.isna(explicit_end):
            return explicit_end
        start_date = row.get("warranty_start_date_resolved")
        years = _to_int(row.get("warranty_years"))
        if pd.isna(start_date) or not years:
            return pd.NaT
        try:
            return start_date + pd.DateOffset(years=int(years))
        except Exception:
            return pd.NaT

    out["warranty_end_date_resolved"] = out.apply(_resolve_warranty_end, axis=1)

    today_local = datetime.now(tz=LOCAL_TZ).date()

    def _days_to_warranty(value):
        if value is None or pd.isna(value):
            return None
        try:
            return int((value.date() - today_local).days)
        except Exception:
            return None

    out["days_to_warranty_end"] = out["warranty_end_date_resolved"].apply(_days_to_warranty)

    def _bucket(days_left):
        if days_left is None:
            return "unknown"
        if days_left < 0:
            return "expired"
        if days_left <= 30:
            return "due_30"
        if days_left <= 90:
            return "due_90"
        return "covered"

    out["warranty_bucket"] = out["days_to_warranty_end"].apply(_bucket)
    out["warranty_bucket_label"] = out["warranty_bucket"].map(ASSET_WARRANTY_BUCKET_LABELS).fillna("Unknown")

    for src_col, dst_col in [
        ("purchage_orderDate", "purchase_order_date_display"),
        ("invoice_date", "invoice_date_display"),
        ("warranty_start_date_resolved", "warranty_start_date_display"),
        ("warranty_end_date_resolved", "warranty_end_date_display"),
        ("last_movement_at", "last_movement_at_display"),
        ("installation_date", "installation_date_display"),
        ("amc_date", "amc_date_display"),
    ]:
        if src_col in out.columns:
            out[dst_col] = out[src_col].apply(
                lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d")
            )

    return out


def _fetch_asset_master_frame(location_codes=None, asset_id=None):
    scope_codes_for_cache = _asset_normalize_location_codes(location_codes)
    asset_id_val = _to_int(asset_id)
    cached = _asset_cache_get("asset_master_frame", scope_codes_for_cache, asset_id_val or "")
    if cached is not None:
        return cached

    ensure_asset_movement_log_table()
    ensure_asset_master_value_column()
    ensure_asset_coverage_tables()
    conn = _asset_db_connection()
    if not conn:
        return pd.DataFrame()

    asset_value_select = "am.asset_value" if _asset_master_value_column_exists(conn) else "CAST(NULL AS DECIMAL(18, 2))"
    scope_sql, params = _asset_scope_sql(location_codes)
    if asset_id_val:
        scope_sql += " AND am.asset_id = ? "
        params.append(asset_id_val)

    sql = f"""
        WITH LatestMovement AS (
            SELECT
                MovementLogID,
                AssetID,
                MovementType,
                FromEntityType,
                FromEntityKey,
                FromEntityLabel,
                ToEntityType,
                ToEntityKey,
                ToEntityLabel,
                LocationID,
                StatusBefore,
                StatusAfter,
                Remarks,
                CreatedByUserName,
                CreatedByAccountId,
                CreatedAt,
                ROW_NUMBER() OVER (
                    PARTITION BY AssetID
                    ORDER BY CreatedAt DESC, MovementLogID DESC
                ) AS rn
            FROM dbo.HID_Asset_Movement_Log WITH (NOLOCK)
        ),
        LatestMaintenance AS (
            SELECT
                id,
                asset_id,
                equ_id,
                model_no,
                serial_no,
                installation_date,
                installation_location,
                warranty_start_date,
                warranty_end_date,
                installedby_name,
                installedby_mobile,
                amc_status,
                amc_date,
                amc_value,
                amc_tax,
                amc_amount,
                service_eng_name,
                service_eng_mobile,
                service_eng_email,
                insertOn,
                insertBy,
                updateOn,
                updateBy,
                maint_status,
                ROW_NUMBER() OVER (
                    PARTITION BY asset_id
                    ORDER BY ISNULL(updateOn, insertOn) DESC, id DESC
                ) AS rn
            FROM dbo.asset_maintenance WITH (NOLOCK)
        ),
        ActiveCoverage AS (
            SELECT
                CoverageHistoryID,
                AssetID,
                CoverageType,
                Vendor,
                StartDate,
                ExpiryDate,
                ContractNo,
                Remarks,
                DocumentFileID,
                UpdatedByAccountId,
                UpdatedByUserName,
                UpdatedAt,
                ROW_NUMBER() OVER (
                    PARTITION BY AssetID
                    ORDER BY UpdatedAt DESC, CoverageHistoryID DESC
                ) AS rn
            FROM dbo.HID_Asset_Coverage_History WITH (NOLOCK)
            WHERE ISNULL(IsActive, 1) = 1
        )
        SELECT
            am.asset_id,
            am.machine_type,
            am.equ_id,
            am.model_name,
            am.brand_id,
            am.serial_number,
            am.purchage_orderDate,
            am.purchage_orderNo,
            am.supplier_id,
            am.invoice_number,
            am.invoice_date,
            {asset_value_select} AS asset_value,
            am.warranty,
            am.asset_code,
            ISNULL(am.asset_status, 1) AS asset_status,
            am.insertBy,
            am.insertOn,
            am.updateBy,
            am.updateOn,
            am.locationId,
            am.asset_srno,
            am.status,
            mt.machineTypeName AS machine_type_name,
            eq.equName AS equipment_name,
            manu.Name AS manufacturer_name,
            manu.Code AS manufacturer_code,
            sup.Name AS supplier_name,
            sup.Code AS supplier_code,
            loc.location_code,
            loc.location_name,
            lm.MovementType AS last_movement_type,
            lm.FromEntityType AS current_from_entity_type,
            lm.FromEntityKey AS current_from_entity_key,
            lm.FromEntityLabel AS current_from_entity_label,
            lm.ToEntityType AS current_holder_type,
            lm.ToEntityKey AS current_holder_key,
            lm.ToEntityLabel AS current_holder_label,
            lm.CreatedAt AS last_movement_at,
            lm.Remarks AS last_movement_remarks,
            lm.StatusBefore AS last_status_before,
            lm.StatusAfter AS last_status_after,
            maint.id AS maintenance_id,
            maint.installation_date,
            maint.installation_location,
            maint.warranty_start_date,
            maint.warranty_end_date,
            maint.installedby_name,
            maint.installedby_mobile,
            maint.amc_status,
            maint.amc_date,
            maint.amc_value,
            maint.amc_tax,
            maint.amc_amount,
            maint.service_eng_name,
            maint.service_eng_mobile,
            maint.service_eng_email,
            maint.maint_status,
            cov.CoverageHistoryID AS coverage_history_id,
            cov.CoverageType AS coverage_type,
            cov.Vendor AS coverage_vendor,
            cov.StartDate AS coverage_start_date,
            cov.ExpiryDate AS coverage_expiry_date,
            cov.ContractNo AS coverage_contract_no,
            cov.Remarks AS coverage_remarks,
            cov.DocumentFileID AS coverage_document_file_id,
            cov.UpdatedByAccountId AS coverage_updated_by_account_id,
            cov.UpdatedByUserName AS coverage_updated_by_username,
            cov.UpdatedAt AS coverage_updated_at
        FROM dbo.asset_master am WITH (NOLOCK)
        LEFT JOIN dbo.asset_MachineTypeMst mt WITH (NOLOCK)
            ON mt.id = am.machine_type
        LEFT JOIN dbo.asset_equipment eq WITH (NOLOCK)
            ON eq.equId = am.equ_id
        LEFT JOIN dbo.ManufacturerUp manu WITH (NOLOCK)
            ON manu.ID = am.brand_id
        LEFT JOIN dbo.SupplierUp sup WITH (NOLOCK)
            ON sup.ID = am.supplier_id
        LEFT JOIN dbo.asset_locationMst loc WITH (NOLOCK)
            ON loc.location_id = am.locationId
        LEFT JOIN LatestMovement lm
            ON lm.AssetID = am.asset_id
           AND lm.rn = 1
        LEFT JOIN LatestMaintenance maint
            ON maint.asset_id = am.asset_id
           AND maint.rn = 1
        LEFT JOIN ActiveCoverage cov
            ON cov.AssetID = am.asset_id
           AND cov.rn = 1
        WHERE ISNULL(am.status, 1) = 1
        {scope_sql}
        ORDER BY am.asset_id DESC;
    """

    try:
        df = pd.read_sql(sql, conn, params=params or None)
        prepared = _asset_prepare_frame(df)
        _asset_cache_put("asset_master_frame", prepared, scope_codes_for_cache, asset_id_val or "")
        return prepared
    except Exception as exc:
        print(f"_fetch_asset_master_frame failed: {exc}")
        return pd.DataFrame()
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _apply_asset_filters(df: pd.DataFrame, filters=None):
        filters = filters or {}
        if df is None or df.empty:
            return pd.DataFrame(columns=df.columns if df is not None else [])

        out = df.copy()
        search = _asset_clean_text(filters.get("search"))
        if search:
            search_mask = pd.Series(False, index=out.index)
            search_cols = [
                "asset_code",
                "equipment_name",
                "model_name",
                "machine_type_name",
                "manufacturer_name",
                "supplier_name",
                "serial_number",
                "invoice_number",
                "asset_value_display",
                "asset_value",
                "location_name",
                "location_code",
                "current_holder_label",
                "coverage_status_label",
                "coverage_vendor",
                "coverage_contract_no",
                "coverage_remarks",
            ]

            escaped = re.escape(search)
            compact_search = re.sub(r"[^a-z0-9]+", "", search.lower())

            for col in search_cols:
                if col not in out.columns:
                    continue

                col_text = out[col].astype(str)

                # Normal search: exact visible text match.
                search_mask = search_mask | col_text.str.contains(escaped, case=False, na=False)

                # Compact search: xray matches X-Ray / X Ray / X.Ray etc.
                if compact_search:
                    compact_col = col_text.str.lower().str.replace(r"[^a-z0-9]+", "", regex=True)
                    search_mask = search_mask | compact_col.str.contains(compact_search, na=False)

            out = out[search_mask]

        machine_type_id = _to_int(filters.get("machine_type"))
        if machine_type_id:
            out = out[out["machine_type"] == machine_type_id]

        equ_id = _to_int(filters.get("equ_id"))
        if equ_id:
            out = out[out["equ_id"] == equ_id]

        brand_id = _to_int(filters.get("brand_id"))
        if brand_id:
            out = out[out["brand_id"] == brand_id]

        supplier_id = _to_int(filters.get("supplier_id"))
        if supplier_id:
            out = out[out["supplier_id"] == supplier_id]

        status_code = _to_int(filters.get("status_code"))
        if status_code:
            out = out[out["asset_status_code"] == status_code]

        location_code = _asset_upper_text(filters.get("location_code"))
        if location_code:
            out = out[out["location_code_upper"] == location_code]

        assignment_type = _asset_clean_text(filters.get("assignment_type")).lower()
        if assignment_type:
            out = out[out["current_holder_type"].astype(str).str.lower() == assignment_type]

        warranty_bucket = _asset_clean_text(filters.get("warranty_bucket")).lower()
        if warranty_bucket:
            out = out[out["warranty_bucket"].astype(str).str.lower() == warranty_bucket]

        coverage_type = _asset_clean_text(filters.get("coverage_type"))
        if coverage_type:
            out = out[out["coverage_type"].astype(str).str.lower() == coverage_type.lower()]

        coverage_alert = _asset_clean_text(filters.get("coverage_alert")).lower()
        if coverage_alert:
            out = out[out["coverage_alert_priority"].astype(str).str.lower() == coverage_alert]

        sort_key = _asset_clean_text(filters.get("sort"), "asset_code").lower()
        direction = _asset_clean_text(filters.get("direction"), "asc").lower()
        sort_map = {
            "asset_code": "asset_code",
            "equipment": "equipment_name",
            "machine_type": "machine_type_name",
            "manufacturer": "manufacturer_name",
            "supplier": "supplier_name",
            "invoice_date": "invoice_date",
            "warranty_end": "warranty_end_date_resolved",
            "value": "asset_value",
            "coverage": "coverage_type",
            "coverage_expiry": "coverage_expiry_date",
            "location": "location_name",
            "status": "asset_status_code",
            "holder": "current_holder_label",
            "updated": "updateOn",
            "created": "insertOn",
        }
        sort_col = sort_map.get(sort_key, "asset_code")
        if sort_col in out.columns:
            out = out.sort_values(
                by=sort_col,
                ascending=(direction != "desc"),
                na_position="last",
                kind="mergesort",
            )

        return out


def fetch_asset_register_rows(location_codes=None, filters=None):
    filters = filters or {}
    df = _fetch_asset_master_frame(location_codes=location_codes)
    total_count = int(len(df))
    filtered = _apply_asset_filters(df, filters)
    filtered_count = int(len(filtered))

    page = max(1, _to_int(filters.get("page"), 1) or 1)
    page_size = _to_int(filters.get("page_size"), 50) or 50
    page_size = min(max(page_size, 10), 5000)
    start = (page - 1) * page_size
    end = start + page_size
    page_df = filtered.iloc[start:end].copy()

    return {
        "rows": _asset_records(page_df),
        "total_count": total_count,
        "filtered_count": filtered_count,
        "page": page,
        "page_size": page_size,
        "pages": max(1, ((filtered_count - 1) // page_size) + 1) if filtered_count else 1,
    }


def fetch_asset_summary(location_codes=None, filters=None):
    base_df = _fetch_asset_master_frame(location_codes=location_codes)
    df = _apply_asset_filters(base_df, filters)
    asset_value_total = Decimal("0")
    if not df.empty and "asset_value" in df.columns:
        asset_value_total = _to_decimal(
            pd.to_numeric(df["asset_value"], errors="coerce").fillna(0).sum(),
            Decimal("0"),
        )

    summary = {
        "total_assets": int(len(df)),
        "total_asset_value": float(asset_value_total),
        "total_asset_value_display": _asset_money_display(asset_value_total),
        "active_count": int((df.get("asset_status_code", pd.Series(dtype=int)) == 1).sum()),
        "in_use_count": int((df.get("asset_status_code", pd.Series(dtype=int)) == 2).sum()),
        "in_store_count": int((df.get("asset_status_code", pd.Series(dtype=int)) == 3).sum()),
        "repair_count": int((df.get("asset_status_code", pd.Series(dtype=int)) == 4).sum()),
        "disposed_count": int((df.get("asset_status_code", pd.Series(dtype=int)) == 5).sum()),
        "lost_count": int((df.get("asset_status_code", pd.Series(dtype=int)) == 6).sum()),
        "expiring_30_count": int((df.get("warranty_bucket", pd.Series(dtype=str)) == "due_30").sum()),
        "expiring_90_count": int((df.get("warranty_bucket", pd.Series(dtype=str)) == "due_90").sum()),
        "expired_count": int((df.get("warranty_bucket", pd.Series(dtype=str)) == "expired").sum()),
        "status_counts": [],
        "location_counts": [],
        "machine_type_counts": [],
        "warranty_alerts": [],
        "repair_alerts": [],
        "coverage_alert_counts": [],
        "coverage_alerts": [],
    }

    if df.empty:
        for code, label in ASSET_STATUS_LABELS.items():
            summary["status_counts"].append({"status_code": code, "status_label": label, "count": 0})
        for priority in ["red", "orange", "yellow", "blue", "green"]:
            summary["coverage_alert_counts"].append(
                {"priority": priority, "label": ASSET_COVERAGE_ALERT_LABELS.get(priority, priority.title()), "count": 0}
            )
        return summary

    for code, label in ASSET_STATUS_LABELS.items():
        summary["status_counts"].append(
            {
                "status_code": code,
                "status_label": label,
                "count": int((df["asset_status_code"] == code).sum()),
            }
        )

    for priority in ["red", "orange", "yellow", "blue", "green"]:
        summary["coverage_alert_counts"].append(
            {
                "priority": priority,
                "label": ASSET_COVERAGE_ALERT_LABELS.get(priority, priority.title()),
                "count": int((df["coverage_alert_priority"] == priority).sum()) if "coverage_alert_priority" in df.columns else 0,
            }
        )

    location_df = (
        df.groupby(["location_code_upper", "location_name"], dropna=False)
        .size()
        .reset_index(name="count")
        .sort_values(["count", "location_name"], ascending=[False, True])
    )
    location_df["location_code"] = location_df["location_code_upper"]
    summary["location_counts"] = _asset_records(location_df[["location_code", "location_name", "count"]])

    machine_df = (
        df.groupby(["machine_type", "machine_type_name"], dropna=False)
        .size()
        .reset_index(name="count")
        .sort_values(["count", "machine_type_name"], ascending=[False, True])
    )
    summary["machine_type_counts"] = _asset_records(machine_df[["machine_type", "machine_type_name", "count"]])

    warranty_alerts = df[df["warranty_bucket"].isin(["expired", "due_30", "due_90"])].copy()
    if not warranty_alerts.empty:
        warranty_alerts = warranty_alerts.sort_values(
            by=["days_to_warranty_end", "warranty_end_date_resolved", "asset_code"],
            ascending=[True, True, True],
            na_position="last",
        )
        summary["warranty_alerts"] = _asset_records(
            warranty_alerts[
                [
                    "asset_id",
                    "asset_code",
                    "equipment_name",
                    "manufacturer_name",
                    "location_name",
                    "warranty_bucket_label",
                    "days_to_warranty_end",
                    "warranty_end_date_display",
                    "asset_status_label",
                ]
            ].head(8)
        )

    repair_alerts = df[df["asset_status_code"] == 4].copy()
    if not repair_alerts.empty:
        repair_alerts = repair_alerts.sort_values(
            by=["last_movement_at", "asset_code"],
            ascending=[False, True],
            na_position="last",
        )
        summary["repair_alerts"] = _asset_records(
            repair_alerts[
                [
                    "asset_id",
                    "asset_code",
                    "equipment_name",
                    "current_holder_label",
                    "location_name",
                    "last_movement_at_display",
                    "last_movement_remarks",
                ]
            ].head(8)
        )

    coverage_alerts = df[df.get("coverage_alert_priority", pd.Series(dtype=str)).isin(["red", "orange", "yellow", "blue"])].copy()
    if not coverage_alerts.empty:
        coverage_alerts = coverage_alerts.sort_values(
            by=["coverage_alert_rank", "coverage_days_left", "coverage_expiry_date", "asset_code"],
            ascending=[True, True, True, True],
            na_position="first",
        )
        summary["coverage_alerts"] = _asset_records(
            coverage_alerts[
                [
                    "asset_id",
                    "asset_code",
                    "equipment_name",
                    "location_code",
                    "location_name",
                    "coverage_status_label",
                    "coverage_vendor",
                    "coverage_expiry_date_display",
                    "coverage_days_left",
                    "coverage_alert_priority",
                    "coverage_alert_label",
                    "coverage_remarks",
                ]
            ].head(12)
        )

    return summary


