def fetch_expiry_alert_assets_by_unit(unit_code, threshold_days=None, include_expired=True, include_pending=True):
    unit = _asset_upper_text(unit_code)
    rows = fetch_asset_register_rows([unit], {"page": 1, "page_size": 10000}).get("rows") or []
    out = []
    threshold = _to_int(threshold_days)
    for row in rows:
        cov_type = _asset_coverage_type(row.get("coverage_type"))
        days_left = _to_int(row.get("coverage_days_left"))
        is_pending = bool(row.get("coverage_pending_update")) or not cov_type
        if is_pending:
            if include_pending:
                out.append(row)
            continue
        if cov_type == "Not Covered":
            continue
        if days_left is None:
            if include_pending:
                out.append(row)
            continue
        if days_left < 0:
            if include_expired:
                out.append(row)
            continue
        if threshold is not None and days_left <= threshold:
            out.append(row)
    return out


def fetch_asset_coverage_recipients(unit_code=None, only_active=True, role_names=None):
    ensure_asset_coverage_tables()
    unit = _asset_upper_text(unit_code)
    normalized_roles = {
        _asset_clean_text(role).upper()
        for role in (role_names or [])
        if _asset_clean_text(role)
    }
    conn = _asset_db_connection()
    if not conn:
        return []
    try:
        params = []
        where = ["1 = 1"]
        if only_active:
            where.append("ISNULL(IsActive, 1) = 1")
        if unit:
            where.append("UPPER(LTRIM(RTRIM(UnitCode))) = ?")
            params.append(unit)
        if normalized_roles:
            placeholders = ",".join("?" for _ in normalized_roles)
            where.append(f"UPPER(LTRIM(RTRIM(RoleName))) IN ({placeholders})")
            params.extend(sorted(normalized_roles))
        df = pd.read_sql(
            f"""
            SELECT
                RecipientID AS recipient_id,
                UnitCode AS unit_code,
                RoleName AS role_name,
                Name AS name,
                Email AS email,
                IsActive AS is_active,
                CreatedAt AS created_at,
                CreatedBy AS created_by,
                UpdatedAt AS updated_at,
                UpdatedBy AS updated_by
            FROM dbo.HID_Asset_Coverage_Recipients WITH (NOLOCK)
            WHERE {" AND ".join(where)}
            ORDER BY UnitCode, RoleName, Name, Email;
            """,
            conn,
            params=params,
        )
        return _asset_records(df)
    except Exception as exc:
        print(f"fetch_asset_coverage_recipients failed: {exc}")
        return []
    finally:
        try:
            conn.close()
        except Exception:
            pass


def upsert_asset_coverage_recipient(name, email, unit_code, role_name, actor_username=None):
    ensure_asset_coverage_tables()
    name_val = _asset_clean_text(name)
    email_val = _asset_clean_text(email).lower()
    unit_val = _asset_upper_text(unit_code)
    role_val = _asset_clean_text(role_name)
    if not name_val or not email_val or not unit_val or not role_val:
        return {"status": "error", "message": "Name, email, unit, and role are required."}
    if "@" not in email_val or "." not in email_val.rsplit("@", 1)[-1]:
        return {"status": "error", "message": "Invalid email address."}
    if unit_val not in ASSET_ALLOWED_LOCATION_CODES:
        return {"status": "error", "message": "Invalid asset unit."}

    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        cursor = conn.cursor()
        cursor.execute(
            """
            SELECT TOP 1 RecipientID
            FROM dbo.HID_Asset_Coverage_Recipients WITH (UPDLOCK, HOLDLOCK)
            WHERE UPPER(LTRIM(RTRIM(UnitCode))) = ?
              AND UPPER(LTRIM(RTRIM(RoleName))) = ?
              AND UPPER(LTRIM(RTRIM(Email))) = ?
            ORDER BY RecipientID DESC;
            """,
            (unit_val, role_val.upper(), email_val.upper()),
        )
        row = _cursor_fetchone_safe(cursor)
        if row:
            cursor.execute(
                """
                UPDATE dbo.HID_Asset_Coverage_Recipients
                SET Name = ?, Email = ?, RoleName = ?, IsActive = 1, UpdatedAt = GETDATE(), UpdatedBy = ?
                WHERE RecipientID = ?;
                """,
                (name_val, email_val, role_val, _asset_clean_text(actor_username), int(row[0])),
            )
        else:
            cursor.execute(
                """
                INSERT INTO dbo.HID_Asset_Coverage_Recipients
                    (UnitCode, RoleName, Name, Email, IsActive, CreatedAt, CreatedBy)
                VALUES (?, ?, ?, ?, 1, GETDATE(), ?);
                """,
                (unit_val, role_val, name_val, email_val, _asset_clean_text(actor_username)),
            )
        conn.commit()
        return {"status": "success", "message": "Asset coverage recipient saved."}
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to save asset coverage recipient: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


