def fetch_asset_movement_rows(location_codes=None, asset_ids=None, limit=5000):
    ensure_asset_movement_log_table()
    scope_codes = _asset_normalize_location_codes(location_codes)
    asset_id_values = _to_int_list(asset_ids)
    use_cache = len(asset_id_values) <= 100
    if use_cache:
        cached = _asset_cache_get("movement_rows", scope_codes, asset_id_values, limit or 5000)
        if cached is not None:
            return cached
    conn = _asset_db_connection()
    if not conn:
        return []

    params = []
    top_n = max(1, min(_to_int(limit, 5000) or 5000, 50000))
    scope_sql, scope_params = _asset_scope_sql(location_codes)
    params.extend(scope_params)

    asset_filter_join_sql = ""
    temp_filter_created = False
    temp_filter_cursor = None
    if asset_id_values:
        try:
            temp_filter_cursor = conn.cursor()
            try:
                temp_filter_cursor.fast_executemany = True
            except Exception:
                pass
            temp_filter_cursor.execute(
                """
                CREATE TABLE #AssetMovementFilter (
                    AssetID INT NOT NULL PRIMARY KEY
                );
                """
            )
            temp_filter_cursor.executemany(
                "INSERT INTO #AssetMovementFilter (AssetID) VALUES (?)",
                [(asset_id,) for asset_id in asset_id_values],
            )
            asset_filter_join_sql = """
                INNER JOIN #AssetMovementFilter af
                    ON af.AssetID = ml.AssetID
            """
            temp_filter_created = True
        except Exception as exc:
            try:
                if temp_filter_cursor is not None:
                    temp_filter_cursor.execute("DROP TABLE IF EXISTS #AssetMovementFilter;")
            except Exception:
                pass
            print(f"fetch_asset_movement_rows temp filter setup failed: {exc}")
            try:
                conn.close()
            except Exception:
                pass
            return []

    sql = f"""
        SELECT TOP {top_n}
            ml.MovementLogID AS movement_log_id,
            ml.AssetID AS asset_id,
            am.asset_code,
            COALESCE(NULLIF(eq.equName, ''), NULLIF(am.model_name, ''), 'Asset') AS equipment_name,
            ml.MovementType AS movement_type,
            ml.FromEntityType AS from_entity_type,
            ml.FromEntityKey AS from_entity_key,
            ml.FromEntityLabel AS from_entity_label,
            ml.ToEntityType AS to_entity_type,
            ml.ToEntityKey AS to_entity_key,
            ml.ToEntityLabel AS to_entity_label,
            ml.StatusBefore AS status_before,
            ml.StatusAfter AS status_after,
            ml.Remarks AS remarks,
            ml.CreatedByUserName AS created_by_username,
            ml.CreatedByAccountId AS created_by_account_id,
            ml.CreatedAt AS created_at,
            loc.location_code,
            loc.location_name
        FROM dbo.HID_Asset_Movement_Log ml WITH (NOLOCK)
        {asset_filter_join_sql}
        INNER JOIN dbo.asset_master am WITH (NOLOCK)
            ON am.asset_id = ml.AssetID
        LEFT JOIN dbo.asset_equipment eq WITH (NOLOCK)
            ON eq.equId = am.equ_id
        LEFT JOIN dbo.asset_locationMst loc WITH (NOLOCK)
            ON loc.location_id = am.locationId
        WHERE 1 = 1
        {scope_sql}
        ORDER BY ml.CreatedAt DESC, ml.MovementLogID DESC;
    """
    try:
        df = pd.read_sql(sql, conn, params=params or None)
        if df is None or df.empty:
            return []
        df["created_at"] = pd.to_datetime(df["created_at"], errors="coerce")
        df["status_before_label"] = df["status_before"].apply(_asset_status_label)
        df["status_after_label"] = df["status_after"].apply(_asset_status_label)
        df["created_at_display"] = df["created_at"].apply(
            lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d %H:%M")
        )

        def _movement_summary(row):
            move_type = _asset_upper_text(row.get("movement_type"))
            to_label = _asset_clean_text(row.get("to_entity_label"))
            from_label = _asset_clean_text(row.get("from_entity_label"))
            status_after = _asset_clean_text(row.get("status_after_label"))
            if move_type == "ISSUE":
                return f"Issued to {to_label}" if to_label else "Asset issued"
            if move_type == "TRANSFER":
                if from_label and to_label:
                    return f"Transferred from {from_label} to {to_label}"
                if to_label:
                    return f"Transferred to {to_label}"
                return "Asset transferred"
            if move_type == "RETURN":
                return f"Returned to {to_label}" if to_label else "Asset returned"
            if move_type == "STATUS":
                return f"Status changed to {status_after}" if status_after else "Status updated"
            return move_type.title() if move_type else "Movement updated"

        df["movement_summary"] = df.apply(_movement_summary, axis=1)
        rows = _asset_records(df)
        if use_cache:
            _asset_cache_put("movement_rows", rows, scope_codes, asset_id_values, limit or 5000)
        return rows
    except Exception as exc:
        print(f"fetch_asset_movement_rows failed: {exc}")
        return []
    finally:
        if temp_filter_created:
            try:
                cleanup_cursor = conn.cursor()
                cleanup_cursor.execute("DROP TABLE IF EXISTS #AssetMovementFilter;")
            except Exception:
                pass
        try:
            conn.close()
        except Exception:
            pass


def fetch_asset_recent_activity(location_codes=None, limit=12):
    scope_codes = _asset_normalize_location_codes(location_codes)
    cached = _asset_cache_get("recent_activity", scope_codes, limit or 12)
    if cached is not None:
        return cached
    rows = fetch_asset_movement_rows(location_codes=location_codes, limit=limit)
    if rows:
        _asset_cache_put("recent_activity", rows, scope_codes, limit or 12)
        return rows

    conn = _asset_db_connection()
    if not conn:
        return []
    scope_sql, params = _asset_scope_sql(location_codes)
    top_n = max(1, min(_to_int(limit, 12) or 12, 100))
    sql = f"""
        SELECT TOP {top_n}
            am.asset_id,
            am.asset_code,
            COALESCE(NULLIF(eq.equName, ''), NULLIF(am.model_name, ''), 'Asset') AS equipment_name,
            am.insertOn AS created_at,
            loc.location_code,
            loc.location_name,
            'CREATED' AS movement_type,
            'Asset added to register' AS movement_summary
        FROM dbo.asset_master am WITH (NOLOCK)
        LEFT JOIN dbo.asset_equipment eq WITH (NOLOCK)
            ON eq.equId = am.equ_id
        LEFT JOIN dbo.asset_locationMst loc WITH (NOLOCK)
            ON loc.location_id = am.locationId
        WHERE ISNULL(am.status, 1) = 1
        {scope_sql}
        ORDER BY am.insertOn DESC, am.asset_id DESC;
    """
    try:
        df = pd.read_sql(sql, conn, params=params or None)
        if df is None or df.empty:
            return []
        df["created_at"] = pd.to_datetime(df["created_at"], errors="coerce")
        df["created_at_display"] = df["created_at"].apply(
            lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d %H:%M")
        )
        rows = _asset_records(df)
        _asset_cache_put("recent_activity", rows, scope_codes, limit or 12)
        return rows
    except Exception as exc:
        print(f"fetch_asset_recent_activity fallback failed: {exc}")
        return []
    finally:
        try:
            conn.close()
        except Exception:
            pass


