def _asset_coverage_payload_values(payload):
    payload = payload or {}
    coverage_type = _asset_coverage_type(payload.get("coverage_type"))
    vendor = _asset_clean_text(payload.get("vendor") or payload.get("coverage_vendor"))
    start_date = _asset_date_only(payload.get("start_date") or payload.get("coverage_start_date"))
    expiry_date = _asset_date_only(payload.get("expiry_date") or payload.get("coverage_expiry_date"))
    contract_no = _asset_clean_text(payload.get("contract_no") or payload.get("coverage_contract_no"))
    remarks = _asset_clean_text(payload.get("remarks") or payload.get("coverage_remarks"))
    document_file_id = _to_int(payload.get("document_file_id") or payload.get("coverage_document_file_id"))
    return {
        "coverage_type": coverage_type,
        "vendor": vendor,
        "start_date": start_date,
        "expiry_date": expiry_date,
        "contract_no": contract_no,
        "remarks": remarks,
        "document_file_id": document_file_id,
    }


def _validate_asset_coverage_payload(payload):
    values = _asset_coverage_payload_values(payload)
    missing = []
    if not values["coverage_type"]:
        missing.append("Coverage Status")
        return values, missing
    if values["coverage_type"] == "Not Covered":
        if not values["remarks"]:
            missing.append("Reason / Remarks")
        return values, missing
    if not values["vendor"]:
        missing.append("Vendor / Company")
    if not values["start_date"]:
        missing.append("Coverage Start Date")
    if not values["expiry_date"]:
        missing.append("Coverage Expiry Date")
    return values, missing


def _insert_asset_coverage_history_conn(cursor, asset_id, values, actor_user_id=None, actor_username=None):
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        raise ValueError("Invalid asset id.")
    cursor.execute(
        """
        UPDATE dbo.HID_Asset_Coverage_History
        SET IsActive = 0
        WHERE AssetID = ? AND ISNULL(IsActive, 1) = 1;
        """,
        (asset_id_val,),
    )
    cursor.execute(
        """
        INSERT INTO dbo.HID_Asset_Coverage_History (
            AssetID,
            CoverageType,
            Vendor,
            StartDate,
            ExpiryDate,
            ContractNo,
            Remarks,
            DocumentFileID,
            UpdatedByAccountId,
            UpdatedByUserName,
            UpdatedAt,
            IsActive
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, GETDATE(), 1);
        SELECT CAST(SCOPE_IDENTITY() AS INT);
        """,
        (
            asset_id_val,
            values.get("coverage_type"),
            values.get("vendor") or None,
            values.get("start_date"),
            values.get("expiry_date"),
            values.get("contract_no") or None,
            values.get("remarks") or None,
            values.get("document_file_id"),
            _to_int(actor_user_id, 0) or None,
            _asset_clean_text(actor_username) or None,
        ),
    )
    row = _cursor_fetchone_safe(cursor)
    return int(row[0]) if row and row[0] is not None else None


def save_asset_coverage(asset_id, payload, actor_user_id=None, actor_username=None):
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        return {"status": "error", "message": "Invalid asset id."}
    values, missing = _validate_asset_coverage_payload(payload)
    if missing:
        return {"status": "error", "message": f"Missing required fields: {', '.join(missing)}", "code": "required"}
    ensure_asset_coverage_tables()
    asset_frame = _fetch_asset_master_frame(asset_id=asset_id_val)
    if asset_frame is None or asset_frame.empty:
        return {"status": "error", "message": "Asset not found."}

    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cursor = conn.cursor()
        history_id = _insert_asset_coverage_history_conn(
            cursor,
            asset_id_val,
            values,
            actor_user_id=actor_user_id,
            actor_username=actor_username,
        )
        conn.commit()
        invalidate_asset_management_cache()
        detail = fetch_asset_detail(asset_id_val)
        return {
            "status": "success",
            "message": "Coverage details saved successfully.",
            "coverage_history_id": history_id,
            "coverage": detail.get("coverage") if detail else {},
            "detail": detail,
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to save coverage: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_asset_coverage_history(asset_id):
    ensure_asset_coverage_tables()
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        return []
    conn = _asset_db_connection()
    if not conn:
        return []
    try:
        df = pd.read_sql(
            """
            SELECT
                CoverageHistoryID AS coverage_history_id,
                AssetID AS asset_id,
                CoverageType AS coverage_type,
                Vendor AS vendor,
                StartDate AS start_date,
                ExpiryDate AS expiry_date,
                ContractNo AS contract_no,
                Remarks AS remarks,
                DocumentFileID AS document_file_id,
                UpdatedByAccountId AS updated_by_account_id,
                UpdatedByUserName AS updated_by_username,
                UpdatedAt AS updated_at,
                CAST(ISNULL(IsActive, 1) AS INT) AS is_active
            FROM dbo.HID_Asset_Coverage_History WITH (NOLOCK)
            WHERE AssetID = ?
            ORDER BY UpdatedAt DESC, CoverageHistoryID DESC;
            """,
            conn,
            params=[asset_id_val],
        )
        if df is None or df.empty:
            return []
        df["start_date"] = pd.to_datetime(df["start_date"], errors="coerce")
        df["expiry_date"] = pd.to_datetime(df["expiry_date"], errors="coerce")
        df["updated_at"] = pd.to_datetime(df["updated_at"], errors="coerce")
        df["start_date_display"] = df["start_date"].apply(lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d"))
        df["expiry_date_display"] = df["expiry_date"].apply(lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d"))
        df["updated_at_display"] = df["updated_at"].apply(lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d %H:%M"))
        return _asset_records(df)
    except Exception as exc:
        print(f"fetch_asset_coverage_history failed: {exc}")
        return []
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_asset_detail(asset_id, location_codes=None):
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        return None
    frame = _fetch_asset_master_frame(location_codes=location_codes, asset_id=asset_id_val)
    if frame is None or frame.empty:
        return None
    asset_record = _asset_records(frame)[0]
    maintenance = {
        "maintenance_id": asset_record.get("maintenance_id"),
        "installation_date": asset_record.get("installation_date_display"),
        "installation_location": asset_record.get("installation_location"),
        "warranty_start_date": asset_record.get("warranty_start_date_display"),
        "warranty_end_date": asset_record.get("warranty_end_date_display"),
        "installedby_name": asset_record.get("installedby_name"),
        "installedby_mobile": asset_record.get("installedby_mobile"),
        "amc_status": asset_record.get("amc_status"),
        "amc_date": asset_record.get("amc_date_display"),
        "amc_value": asset_record.get("amc_value"),
        "amc_tax": asset_record.get("amc_tax"),
        "amc_amount": asset_record.get("amc_amount"),
        "service_eng_name": asset_record.get("service_eng_name"),
        "service_eng_mobile": asset_record.get("service_eng_mobile"),
        "service_eng_email": asset_record.get("service_eng_email"),
        "maint_status": asset_record.get("maint_status"),
    }
    coverage = {
        "coverage_history_id": asset_record.get("coverage_history_id"),
        "coverage_type": asset_record.get("coverage_type"),
        "coverage_status_label": asset_record.get("coverage_status_label"),
        "vendor": asset_record.get("coverage_vendor"),
        "start_date": asset_record.get("coverage_start_date_display"),
        "expiry_date": asset_record.get("coverage_expiry_date_display"),
        "contract_no": asset_record.get("coverage_contract_no"),
        "remarks": asset_record.get("coverage_remarks"),
        "document_file_id": asset_record.get("coverage_document_file_id"),
        "updated_by_username": asset_record.get("coverage_updated_by_username"),
        "updated_at": asset_record.get("coverage_updated_at_display"),
        "alert_priority": asset_record.get("coverage_alert_priority"),
        "alert_label": asset_record.get("coverage_alert_label"),
        "days_left": asset_record.get("coverage_days_left"),
        "pending_update": bool(asset_record.get("coverage_pending_update")),
    }
    return {
        "asset": asset_record,
        "maintenance": maintenance,
        "coverage": coverage,
        "coverage_history": fetch_asset_coverage_history(asset_id_val),
        "attachments": fetch_asset_attachments(asset_id_val),
        "history": fetch_asset_movement_history(asset_id_val, location_codes=location_codes),
    }


def _asset_equipment_abbr(equipment_name) -> str:
    cleaned = re.sub(r"[^A-Za-z0-9]", "", _asset_clean_text(equipment_name)).upper()
    return (cleaned[:3] or "AST")


def _asset_generate_code(cursor, machine_type_id, equ_id, invoice_date, location_id):
    cursor.execute("SELECT TOP 1 equName FROM dbo.asset_equipment WITH (NOLOCK) WHERE equId = ?", (_to_int(equ_id),))
    equ_row = cursor.fetchone()
    equipment_name = equ_row[0] if equ_row and equ_row[0] is not None else "AST"

    cursor.execute(
        "SELECT TOP 1 location_code, location_name FROM dbo.asset_locationMst WITH (NOLOCK) WHERE location_id = ?",
        (_to_int(location_id),),
    )
    loc_row = cursor.fetchone()
    location_code = _asset_upper_text(loc_row[0] if loc_row else "", "AHL") or "AHL"

    cursor.execute(
        """
        SELECT ISNULL(MAX(asset_srno), 0) + 1
        FROM dbo.asset_master WITH (UPDLOCK, HOLDLOCK)
        WHERE locationId = ?
        """,
        (_to_int(location_id),),
    )
    sr_row = cursor.fetchone()
    asset_srno = int(sr_row[0]) if sr_row and sr_row[0] is not None else 1

    year_val = None
    dt = _to_datetime(invoice_date)
    if dt is not None:
        year_val = int(dt.year)
    if not year_val:
        year_val = int(_asset_now().year)

    machine_code = "IT"
    machine_type = _to_int(machine_type_id)
    if machine_type == 1:
        machine_code = "M"
    elif machine_type == 2:
        machine_code = "NM"

    asset_code = f"{location_code}/{year_val}/{machine_code}/{_asset_equipment_abbr(equipment_name)}{asset_srno}"
    return asset_srno, asset_code


def _asset_insert_direct(cursor, payload, actor_user_id=None, include_asset_value=True):
    machine_type = _to_int(payload.get("machine_type"))
    equ_id = _to_int(payload.get("equ_id"))
    model_name = _asset_clean_text(payload.get("model_name"))
    brand_id = _to_int(payload.get("brand_id"))
    serial_number = _asset_clean_text(payload.get("serial_number"))
    po_no = _asset_clean_text(payload.get("purchage_orderNo"))
    po_date = _to_datetime(payload.get("purchage_orderDate"))
    supplier_id = _to_int(payload.get("supplier_id"))
    invoice_number = _asset_clean_text(payload.get("invoice_number"))
    invoice_date = _to_datetime(payload.get("invoice_date")) or _asset_now()
    asset_value = _asset_money_value(payload.get("asset_value"))
    warranty = _asset_warranty_years_param(payload.get("warranty"))
    asset_status = _to_int(payload.get("asset_status"), 1) or 1
    location_id = _to_int(payload.get("locationId"))
    row_status = _to_int(payload.get("status"), 1) or 1
    insert_by = _to_int(payload.get("insertBy"), _to_int(actor_user_id, 0) or 0) or 0
    update_by = _to_int(payload.get("updateBy"), _to_int(actor_user_id, 0) or insert_by) or insert_by
    now_dt = _asset_now()
    insert_on = _to_datetime(payload.get("insertOn")) or now_dt
    update_on = _to_datetime(payload.get("updateOn")) or now_dt

    asset_srno, asset_code = _asset_generate_code(cursor, machine_type, equ_id, invoice_date, location_id)
    if include_asset_value:
        cursor.execute(
            """
        INSERT INTO dbo.asset_master (
            machine_type, equ_id, model_name, brand_id, serial_number,
            purchage_orderDate, purchage_orderNo, supplier_id, invoice_number, invoice_date,
            asset_value, warranty, asset_code, asset_status, insertBy, insertOn, updateBy, updateOn,
            locationId, asset_srno, status
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);
        SELECT CAST(SCOPE_IDENTITY() AS INT);
        """,
        (
            machine_type,
            equ_id,
            model_name,
            brand_id,
            serial_number,
            po_date,
            po_no,
            supplier_id,
            invoice_number,
            invoice_date,
            asset_value,
            warranty,
            asset_code,
            asset_status,
            insert_by,
            insert_on,
            update_by,
            update_on,
            location_id,
            asset_srno,
            row_status,
        ),
        )
    else:
        cursor.execute(
            """
        INSERT INTO dbo.asset_master (
            machine_type, equ_id, model_name, brand_id, serial_number,
            purchage_orderDate, purchage_orderNo, supplier_id, invoice_number, invoice_date,
            warranty, asset_code, asset_status, insertBy, insertOn, updateBy, updateOn,
            locationId, asset_srno, status
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);
        SELECT CAST(SCOPE_IDENTITY() AS INT);
        """,
            (
                machine_type,
                equ_id,
                model_name,
                brand_id,
                serial_number,
                po_date,
                po_no,
                supplier_id,
                invoice_number,
                invoice_date,
                warranty,
                asset_code,
                asset_status,
                insert_by,
                insert_on,
                update_by,
                update_on,
                location_id,
                asset_srno,
                row_status,
            ),
        )
    row = _cursor_fetchone_safe(cursor)
    if not row or row[0] is None:
        raise RuntimeError("Asset insert did not return the new asset id")
    return int(row[0]), asset_code


def create_asset_record(payload, actor_user_id=None, actor_username=None, coverage_payload=None):
    payload = payload or {}
    ensure_asset_master_value_column()
    ensure_asset_coverage_tables()
    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}

    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cursor = conn.cursor()
        value_column_available = _asset_master_value_column_exists(conn)

        created_asset_id = None
        asset_code = ""
        location_id = _to_int(payload.get("locationId"))
        asset_value = _asset_money_value(payload.get("asset_value"))
        use_proc = location_id in {1, 2}
        if use_proc:
            try:
                cursor.execute(
                    """
                    EXEC dbo.usp_addAssetMst ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?
                    """,
                    (
                        0,
                        _to_int(payload.get("machine_type")),
                        _to_int(payload.get("equ_id")),
                        _asset_clean_text(payload.get("model_name")),
                        _to_int(payload.get("brand_id")),
                        _asset_clean_text(payload.get("serial_number")),
                        _asset_clean_text(payload.get("purchage_orderNo")),
                        _to_datetime(payload.get("purchage_orderDate")),
                        _to_int(payload.get("supplier_id")),
                        _asset_clean_text(payload.get("invoice_number")),
                        _to_datetime(payload.get("invoice_date")) or _asset_now(),
                        _asset_warranty_years_param(payload.get("warranty")),
                        _to_int(payload.get("asset_status"), 1) or 1,
                        _to_int(payload.get("insertBy"), _to_int(actor_user_id, 0) or 0) or 0,
                        _to_datetime(payload.get("insertOn")) or _asset_now(),
                        _to_int(payload.get("updateBy"), _to_int(actor_user_id, 0) or 0) or 0,
                        _to_datetime(payload.get("updateOn")) or _asset_now(),
                        location_id,
                        _to_int(payload.get("status"), 1) or 1,
                    ),
                )
                proc_row = _cursor_fetchone_safe(cursor)
                asset_code = _asset_clean_text(proc_row[1] if proc_row and len(proc_row) > 1 else "")
                if asset_code:
                    cursor.execute(
                        """
                        SELECT TOP 1 asset_id, asset_code
                        FROM dbo.asset_master WITH (NOLOCK)
                        WHERE asset_code = ?
                        ORDER BY asset_id DESC
                        """,
                        (asset_code,),
                    )
                    found = cursor.fetchone()
                    if found and found[0] is not None:
                        created_asset_id = int(found[0])
                        asset_code = _asset_clean_text(found[1])
                if not created_asset_id:
                    raise RuntimeError("Asset procedure completed but inserted row could not be located.")
                if value_column_available:
                    cursor.execute(
                        """
                        UPDATE dbo.asset_master
                        SET asset_value = ?, updateBy = ?, updateOn = ?
                        WHERE asset_id = ?
                        """,
                        (
                            asset_value,
                            _to_int(actor_user_id, 0) or 0,
                            _asset_now(),
                            created_asset_id,
                        ),
                    )
            except Exception:
                try:
                    conn.rollback()
                except Exception:
                    pass
                cursor = conn.cursor()
                value_column_available = _asset_master_value_column_exists(conn)
                created_asset_id, asset_code = _asset_insert_direct(
                    cursor,
                    payload,
                    actor_user_id=actor_user_id,
                    include_asset_value=value_column_available,
                )
        else:
            created_asset_id, asset_code = _asset_insert_direct(
                cursor,
                payload,
                actor_user_id=actor_user_id,
                include_asset_value=value_column_available,
            )

        if coverage_payload:
            coverage_values, coverage_missing = _validate_asset_coverage_payload(coverage_payload)
            if coverage_missing:
                raise RuntimeError(f"Missing coverage fields: {', '.join(coverage_missing)}")
            _insert_asset_coverage_history_conn(
                cursor,
                created_asset_id,
                coverage_values,
                actor_user_id=actor_user_id,
                actor_username=actor_username,
            )

        conn.commit()
        invalidate_asset_management_cache()
        detail = fetch_asset_detail(created_asset_id)
        return {
            "status": "success",
            "message": "Asset added successfully.",
            "asset_id": created_asset_id,
            "asset_code": asset_code,
            "detail": detail,
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to create asset: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def update_asset_record(asset_id, payload, actor_user_id=None):
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        return {"status": "error", "message": "Invalid asset id."}

    ensure_asset_master_value_column()
    existing_frame = _fetch_asset_master_frame(asset_id=asset_id_val)
    if existing_frame is None or existing_frame.empty:
        return {"status": "error", "message": "Asset not found."}
    existing = existing_frame.iloc[0].to_dict()

    def _pick(key):
        val = payload.get(key) if isinstance(payload, dict) else None
        if val in (None, ""):
            return existing.get(key)
        return val

    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cursor = conn.cursor()
        value_column_available = _asset_master_value_column_exists(conn)
        cursor.execute(
            """
            EXEC dbo.usp_updateAssetUp ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?
            """,
            (
                asset_id_val,
                _to_int(_pick("machine_type")),
                _to_int(_pick("equ_id")),
                _asset_clean_text(_pick("model_name")),
                _to_int(_pick("brand_id")),
                _asset_clean_text(_pick("serial_number")),
                _asset_clean_text(_pick("purchage_orderNo")),
                _to_datetime(_pick("purchage_orderDate")),
                _to_int(_pick("supplier_id")),
                _asset_clean_text(_pick("invoice_number")),
                _to_datetime(_pick("invoice_date")),
                _asset_warranty_years_param(_pick("warranty")),
                _to_int(payload.get("asset_status"), existing.get("asset_status_code")) or existing.get("asset_status_code"),
                _to_int(existing.get("insertBy"), 0) or 0,
                _to_datetime(existing.get("insertOn")),
                _to_int(actor_user_id, 0) or _to_int(existing.get("updateBy"), 0) or 0,
                _asset_now(),
                _to_int(_pick("locationId")),
            ),
        )
        if value_column_available:
            cursor.execute(
                """
                UPDATE dbo.asset_master
                SET asset_status = ?, asset_value = ?, updateBy = ?, updateOn = ?
                WHERE asset_id = ?
                """,
                (
                    _to_int(payload.get("asset_status"), existing.get("asset_status_code")) or existing.get("asset_status_code"),
                    _asset_money_value(_pick("asset_value")),
                    _to_int(actor_user_id, 0) or _to_int(existing.get("updateBy"), 0) or 0,
                    _asset_now(),
                    asset_id_val,
                ),
            )
        else:
            cursor.execute(
                """
                UPDATE dbo.asset_master
                SET asset_status = ?, updateBy = ?, updateOn = ?
                WHERE asset_id = ?
                """,
                (
                    _to_int(payload.get("asset_status"), existing.get("asset_status_code")) or existing.get("asset_status_code"),
                    _to_int(actor_user_id, 0) or _to_int(existing.get("updateBy"), 0) or 0,
                    _asset_now(),
                    asset_id_val,
                ),
            )
        conn.commit()
        invalidate_asset_management_cache()
        return {
            "status": "success",
            "message": "Asset updated successfully.",
            "detail": fetch_asset_detail(asset_id_val),
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to update asset: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def upsert_asset_maintenance(asset_id, payload, actor_user_id=None):
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        return {"status": "error", "message": "Invalid asset id."}

    asset_frame = _fetch_asset_master_frame(asset_id=asset_id_val)
    if asset_frame is None or asset_frame.empty:
        return {"status": "error", "message": "Asset not found."}
    asset_row = asset_frame.iloc[0].to_dict()

    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cursor = conn.cursor()
        cursor.execute(
            "SELECT TOP 1 id FROM dbo.asset_maintenance WITH (UPDLOCK, HOLDLOCK) WHERE asset_id = ? ORDER BY id DESC",
            (asset_id_val,),
        )
        existing = cursor.fetchone()
        now_dt = _asset_now()
        actor_id = _to_int(actor_user_id, 0) or 0

        maintenance_payload = payload or {}
        base_equ_id = _to_int(asset_row.get("equ_id"))
        base_model = _asset_clean_text(asset_row.get("model_name"))
        base_serial = _asset_clean_text(asset_row.get("serial_number"))
        warranty_start = _to_datetime(maintenance_payload.get("warranty_start_date")) or _to_datetime(asset_row.get("warranty_start_date_resolved"))
        warranty_end = _to_datetime(maintenance_payload.get("warranty_end_date")) or _to_datetime(asset_row.get("warranty_end_date_resolved"))

        if existing and existing[0] is not None:
            cursor.execute(
                """
                UPDATE dbo.asset_maintenance
                SET equ_id = ?,
                    model_no = ?,
                    serial_no = ?,
                    installation_date = ?,
                    installation_location = ?,
                    warranty_start_date = ?,
                    warranty_end_date = ?,
                    installedby_name = ?,
                    installedby_mobile = ?,
                    amc_status = ?,
                    amc_date = ?,
                    amc_value = ?,
                    amc_tax = ?,
                    amc_amount = ?,
                    service_eng_name = ?,
                    service_eng_mobile = ?,
                    service_eng_email = ?,
                    updateOn = ?,
                    updateBy = ?,
                    maint_status = ?
                WHERE id = ?
                """,
                (
                    _to_int(maintenance_payload.get("equ_id"), base_equ_id) or base_equ_id,
                    _asset_clean_text(maintenance_payload.get("model_no"), base_model),
                    _asset_clean_text(maintenance_payload.get("serial_no"), base_serial),
                    _to_datetime(maintenance_payload.get("installation_date")),
                    _asset_clean_text(maintenance_payload.get("installation_location")),
                    warranty_start,
                    warranty_end,
                    _asset_clean_text(maintenance_payload.get("installedby_name")),
                    _asset_clean_text(maintenance_payload.get("installedby_mobile")),
                    _asset_clean_text(maintenance_payload.get("amc_status")),
                    _to_datetime(maintenance_payload.get("amc_date")),
                    _to_decimal(maintenance_payload.get("amc_value"), Decimal("0")),
                    _to_decimal(maintenance_payload.get("amc_tax"), Decimal("0")),
                    _to_decimal(maintenance_payload.get("amc_amount"), Decimal("0")),
                    _asset_clean_text(maintenance_payload.get("service_eng_name")),
                    _asset_clean_text(maintenance_payload.get("service_eng_mobile")),
                    _asset_clean_text(maintenance_payload.get("service_eng_email")),
                    now_dt,
                    actor_id,
                    _to_int(maintenance_payload.get("maint_status"), 1) or 1,
                    int(existing[0]),
                ),
            )
        else:
            cursor.execute(
                """
                INSERT INTO dbo.asset_maintenance (
                    asset_id, equ_id, model_no, serial_no, installation_date, installation_location,
                    warranty_start_date, warranty_end_date, installedby_name, installedby_mobile,
                    amc_status, amc_date, amc_value, amc_tax, amc_amount,
                    service_eng_name, service_eng_mobile, service_eng_email,
                    insertOn, insertBy, updateOn, updateBy, maint_status
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    asset_id_val,
                    _to_int(maintenance_payload.get("equ_id"), base_equ_id) or base_equ_id,
                    _asset_clean_text(maintenance_payload.get("model_no"), base_model),
                    _asset_clean_text(maintenance_payload.get("serial_no"), base_serial),
                    _to_datetime(maintenance_payload.get("installation_date")),
                    _asset_clean_text(maintenance_payload.get("installation_location")),
                    warranty_start,
                    warranty_end,
                    _asset_clean_text(maintenance_payload.get("installedby_name")),
                    _asset_clean_text(maintenance_payload.get("installedby_mobile")),
                    _asset_clean_text(maintenance_payload.get("amc_status")),
                    _to_datetime(maintenance_payload.get("amc_date")),
                    _to_decimal(maintenance_payload.get("amc_value"), Decimal("0")),
                    _to_decimal(maintenance_payload.get("amc_tax"), Decimal("0")),
                    _to_decimal(maintenance_payload.get("amc_amount"), Decimal("0")),
                    _asset_clean_text(maintenance_payload.get("service_eng_name")),
                    _asset_clean_text(maintenance_payload.get("service_eng_mobile")),
                    _asset_clean_text(maintenance_payload.get("service_eng_email")),
                    now_dt,
                    actor_id,
                    now_dt,
                    actor_id,
                    _to_int(maintenance_payload.get("maint_status"), 1) or 1,
                ),
            )

        conn.commit()
        invalidate_asset_management_cache()
        detail = fetch_asset_detail(asset_id_val)
        return {
            "status": "success",
            "message": "Maintenance details saved successfully.",
            "maintenance": detail.get("maintenance") if detail else None,
            "detail": detail,
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to save maintenance: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def add_asset_attachment(asset_id, file_name, file_url):
    asset_id_val = _to_int(asset_id)
    if not asset_id_val or not _asset_clean_text(file_name) or not _asset_clean_text(file_url):
        return {"status": "error", "message": "Attachment details are incomplete."}

    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cursor = conn.cursor()
        cursor.execute(
            "EXEC dbo.usp_AssetAddFile ?, ?, ?",
            (asset_id_val, _asset_clean_text(file_name), _asset_clean_text(file_url)),
        )
        cursor.execute(
            """
            SELECT TOP 1 file_id, assetId AS asset_id, fileName AS file_name, fileUrl AS file_url
            FROM dbo.asset_FileUpload WITH (NOLOCK)
            WHERE assetId = ? AND fileUrl = ?
            ORDER BY file_id DESC
            """,
            (asset_id_val, _asset_clean_text(file_url)),
        )
        row = cursor.fetchone()
        conn.commit()
        attachment = None
        if row:
            attachment = {
                "file_id": row[0],
                "asset_id": row[1],
                "file_name": row[2],
                "file_url": row[3],
            }
        return {
            "status": "success",
            "message": "Attachment uploaded successfully.",
            "attachment": attachment,
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to save attachment: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def record_asset_movement(asset_id, movement, actor_username=None, actor_account_id=None):
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        return {"status": "error", "message": "Invalid asset id."}

    ensure_asset_movement_log_table()
    asset_frame = _fetch_asset_master_frame(asset_id=asset_id_val)
    if asset_frame is None or asset_frame.empty:
        return {"status": "error", "message": "Asset not found."}
    asset_row = asset_frame.iloc[0].to_dict()
    movement = movement or {}

    movement_type = _asset_upper_text(movement.get("movement_type"))
    if movement_type not in {"ISSUE", "RETURN", "TRANSFER", "STATUS"}:
        return {"status": "error", "message": "Unsupported movement type."}

    status_before = _to_int(asset_row.get("asset_status_code"), 1) or 1
    status_after = _to_int(movement.get("status_after"), status_before) or status_before
    location_id = _to_int(movement.get("location_id"), asset_row.get("locationId")) or _to_int(asset_row.get("locationId"))

    from_entity_type = _asset_clean_text(movement.get("from_entity_type"), asset_row.get("current_holder_type") or "location")
    from_entity_key = _asset_clean_text(movement.get("from_entity_key"), asset_row.get("current_holder_key") or str(location_id or ""))
    from_entity_label = _asset_clean_text(
        movement.get("from_entity_label"),
        asset_row.get("current_holder_label") or f"{_asset_clean_text(asset_row.get('location_name'))} Store",
    )

    to_entity_type = _asset_clean_text(movement.get("to_entity_type"))
    to_entity_key = _asset_clean_text(movement.get("to_entity_key"))
    to_entity_label = _asset_clean_text(movement.get("to_entity_label"))
    remarks = _asset_clean_text(movement.get("remarks"))

    if movement_type == "RETURN":
        if not to_entity_type:
            to_entity_type = "location"
        if not to_entity_key:
            to_entity_key = str(location_id or "")
        if not to_entity_label:
            to_entity_label = _asset_clean_text(asset_row.get("location_name")) or "Store"
        if status_after == status_before:
            status_after = 3

    if movement_type == "STATUS":
        if not to_entity_type:
            to_entity_type = asset_row.get("current_holder_type") or "location"
        if not to_entity_key:
            to_entity_key = _asset_clean_text(asset_row.get("current_holder_key"), str(location_id or ""))
        if not to_entity_label:
            to_entity_label = _asset_clean_text(asset_row.get("current_holder_label")) or _asset_clean_text(asset_row.get("location_name")) or "Store"

    if movement_type in {"ISSUE", "TRANSFER"} and (not to_entity_type or not to_entity_label):
        return {"status": "error", "message": "Destination assignment is required."}

    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cursor = conn.cursor()
        cursor.execute(
            """
            INSERT INTO dbo.HID_Asset_Movement_Log (
                AssetID,
                MovementType,
                FromEntityType,
                FromEntityKey,
                FromEntityLabel,
                ToEntityType,
                ToEntityKey,
                ToEntityLabel,
                LocationID,
                StatusBefore,
                StatusAfter,
                Remarks,
                CreatedByUserName,
                CreatedByAccountId,
                CreatedAt
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, GETDATE());
            SELECT CAST(SCOPE_IDENTITY() AS INT);
            """,
            (
                asset_id_val,
                movement_type,
                from_entity_type or None,
                from_entity_key or None,
                from_entity_label or None,
                to_entity_type or None,
                to_entity_key or None,
                to_entity_label or None,
                location_id,
                status_before,
                status_after,
                remarks or None,
                _asset_clean_text(actor_username),
                _to_int(actor_account_id),
            ),
        )
        movement_row = _cursor_fetchone_safe(cursor)
        cursor.execute(
            """
            UPDATE dbo.asset_master
            SET asset_status = ?, updateBy = ?, updateOn = ?, locationId = ?
            WHERE asset_id = ?
            """,
            (
                status_after,
                _to_int(actor_account_id, 0) or _to_int(asset_row.get("updateBy"), 0) or 0,
                _asset_now(),
                location_id,
                asset_id_val,
            ),
        )
        conn.commit()
        invalidate_asset_management_cache()
        movement_log_id = int(movement_row[0]) if movement_row and movement_row[0] is not None else None
        detail = fetch_asset_detail(asset_id_val)
        return {
            "status": "success",
            "message": f"{movement_type.title()} saved successfully.",
            "movement_log_id": movement_log_id,
            "detail": detail,
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to save movement: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def ensure_asset_notification_tables():
    global _ASSET_NOTIFICATION_TABLE_READY
    if _ASSET_NOTIFICATION_TABLE_READY:
        return True
    with _ASSET_BOOTSTRAP_LOCK:
        if _ASSET_NOTIFICATION_TABLE_READY:
            return True
        conn = _asset_db_connection()
        if not conn:
            return False
        try:
            try:
                conn.autocommit = False
            except Exception:
                pass
            cursor = conn.cursor()
            cursor.execute(
                """
                IF OBJECT_ID('dbo.HID_Asset_Notification', 'U') IS NULL
                BEGIN
                    CREATE TABLE dbo.HID_Asset_Notification (
                        NotificationID INT IDENTITY(1,1) NOT NULL PRIMARY KEY,
                        AssetID INT NOT NULL,
                        MovementLogID INT NULL,
                        TargetUnitCode VARCHAR(20) NOT NULL,
                        NotificationType VARCHAR(40) NOT NULL,
                        Title NVARCHAR(200) NOT NULL,
                        Message NVARCHAR(1000) NULL,
                        LinkUrl NVARCHAR(500) NULL,
                        Status VARCHAR(24) NOT NULL CONSTRAINT DF_HID_Asset_Notification_Status DEFAULT ('OPEN'),
                        CreatedByUserName NVARCHAR(255) NULL,
                        CreatedAt DATETIME NOT NULL CONSTRAINT DF_HID_Asset_Notification_CreatedAt DEFAULT (GETDATE())
                    );
                END;

                IF OBJECT_ID('dbo.HID_Asset_Notification_User', 'U') IS NULL
                BEGIN
                    CREATE TABLE dbo.HID_Asset_Notification_User (
                        NotificationUserID INT IDENTITY(1,1) NOT NULL PRIMARY KEY,
                        NotificationID INT NOT NULL,
                        UserName NVARCHAR(255) NOT NULL,
                        ReadAt DATETIME NULL,
                        AcceptedAt DATETIME NULL,
                        AcceptedByAccountId INT NULL,
                        UpdatedAt DATETIME NOT NULL CONSTRAINT DF_HID_Asset_Notification_User_UpdatedAt DEFAULT (GETDATE())
                    );
                END;

                IF NOT EXISTS (
                    SELECT 1 FROM sys.indexes
                    WHERE object_id = OBJECT_ID('dbo.HID_Asset_Notification')
                      AND name = 'IX_HID_Asset_Notification_TargetUnit_CreatedAt'
                )
                BEGIN
                    CREATE INDEX IX_HID_Asset_Notification_TargetUnit_CreatedAt
                    ON dbo.HID_Asset_Notification (TargetUnitCode, CreatedAt DESC, NotificationID DESC);
                END;

                IF NOT EXISTS (
                    SELECT 1 FROM sys.indexes
                    WHERE object_id = OBJECT_ID('dbo.HID_Asset_Notification')
                      AND name = 'UX_HID_Asset_Notification_Movement_Target_Type'
                )
                BEGIN
                    CREATE UNIQUE INDEX UX_HID_Asset_Notification_Movement_Target_Type
                    ON dbo.HID_Asset_Notification (MovementLogID, TargetUnitCode, NotificationType)
                    WHERE MovementLogID IS NOT NULL;
                END;

                IF NOT EXISTS (
                    SELECT 1 FROM sys.indexes
                    WHERE object_id = OBJECT_ID('dbo.HID_Asset_Notification_User')
                      AND name = 'UX_HID_Asset_Notification_User'
                )
                BEGIN
                    CREATE UNIQUE INDEX UX_HID_Asset_Notification_User
                    ON dbo.HID_Asset_Notification_User (NotificationID, UserName);
                END;
                """
            )
            conn.commit()
            _ASSET_NOTIFICATION_TABLE_READY = True
            return True
        except Exception as exc:
            try:
                conn.rollback()
            except Exception:
                pass
            print(f"Asset notification table bootstrap failed: {exc}")
            return False
        finally:
            try:
                conn.close()
            except Exception:
                pass


def fetch_asset_location_record(location_id):
    loc_id = _to_int(location_id)
    if not loc_id:
        return None
    for row in fetch_asset_locations(None):
        if _to_int(row.get("id")) == loc_id:
            return row
    return None


def create_asset_issue_notification(asset_id, movement_log_id, target_unit_code, title, message, link_url, actor_username=None):
    asset_id_val = _to_int(asset_id)
    unit = _asset_upper_text(target_unit_code)
    if not asset_id_val or unit not in ASSET_ALLOWED_LOCATION_CODES:
        return {"status": "skipped", "message": "Invalid asset notification target."}
    if not ensure_asset_notification_tables():
        return {"status": "skipped", "message": "Asset notification table is unavailable."}

    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        try:
            conn.autocommit = False
        except Exception:
            pass
        cursor = conn.cursor()
        cursor.execute(
            """
            DECLARE @ExistingID INT = NULL;
            IF ? IS NOT NULL
            BEGIN
                SELECT @ExistingID = NotificationID
                FROM dbo.HID_Asset_Notification WITH (UPDLOCK, HOLDLOCK)
                WHERE MovementLogID = ?
                  AND TargetUnitCode = ?
                  AND NotificationType = 'CROSS_UNIT_ISSUE';
            END;

            IF @ExistingID IS NULL
            BEGIN
                INSERT INTO dbo.HID_Asset_Notification (
                    AssetID, MovementLogID, TargetUnitCode, NotificationType,
                    Title, Message, LinkUrl, CreatedByUserName, CreatedAt
                )
                VALUES (?, ?, ?, 'CROSS_UNIT_ISSUE', ?, ?, ?, ?, GETDATE());
                SELECT CAST(SCOPE_IDENTITY() AS INT) AS NotificationID;
            END
            ELSE
            BEGIN
                SELECT @ExistingID AS NotificationID;
            END;
            """,
            (
                _to_int(movement_log_id),
                _to_int(movement_log_id),
                unit,
                asset_id_val,
                _to_int(movement_log_id),
                unit,
                _asset_clean_text(title, 200),
                _asset_clean_text(message, 1000),
                _asset_clean_text(link_url, 500),
                _asset_clean_text(actor_username),
            ),
        )
        row = _cursor_fetchone_safe(cursor)
        conn.commit()
        return {
            "status": "success",
            "notification_id": int(row[0]) if row and row[0] is not None else None,
            "message": "Asset notification created.",
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to create asset notification: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _asset_notification_row_dict(row):
    rec = {str(k): _asset_serialize_value(v) for k, v in dict(row).items()}
    rec["notification_id"] = _to_int(rec.get("notification_id"))
    rec["asset_id"] = _to_int(rec.get("asset_id"))
    rec["movement_log_id"] = _to_int(rec.get("movement_log_id"))
    rec["is_read"] = bool(_to_int(rec.get("is_read"), 0))
    rec["is_accepted"] = bool(_to_int(rec.get("is_accepted"), 0))
    return rec


def fetch_asset_notifications(location_codes=None, username=None, unread_only=False, limit=20):
    if not ensure_asset_notification_tables():
        return []
    scope_codes = _asset_normalize_location_codes(location_codes)
    if scope_codes is not None and not scope_codes:
        return []
    user = _asset_clean_text(username)
    top_n = max(1, min(_to_int(limit, 20) or 20, 100))
    scope_sql = ""
    params = [user]
    if scope_codes is not None:
        placeholders = ",".join("?" for _ in scope_codes)
        scope_sql = f" AND UPPER(LTRIM(RTRIM(n.TargetUnitCode))) IN ({placeholders}) "
        params.extend(scope_codes)
    unread_sql = " AND nu.ReadAt IS NULL AND nu.AcceptedAt IS NULL " if unread_only else ""

    conn = _asset_db_connection()
    if not conn:
        return []
    try:
        sql = f"""
            SELECT TOP {top_n}
                n.NotificationID AS notification_id,
                n.AssetID AS asset_id,
                n.MovementLogID AS movement_log_id,
                n.TargetUnitCode AS target_unit_code,
                n.NotificationType AS notification_type,
                n.Title AS title,
                n.Message AS message,
                n.LinkUrl AS link_url,
                n.Status AS status,
                n.CreatedByUserName AS created_by_username,
                n.CreatedAt AS created_at,
                am.asset_code,
                COALESCE(NULLIF(eq.equName, ''), NULLIF(am.model_name, ''), 'Asset') AS asset_name,
                CASE WHEN nu.ReadAt IS NULL THEN 0 ELSE 1 END AS is_read,
                CASE WHEN nu.AcceptedAt IS NULL THEN 0 ELSE 1 END AS is_accepted,
                nu.ReadAt AS read_at,
                nu.AcceptedAt AS accepted_at
            FROM dbo.HID_Asset_Notification n WITH (NOLOCK)
            INNER JOIN dbo.asset_master am WITH (NOLOCK)
                ON am.asset_id = n.AssetID
            LEFT JOIN dbo.asset_equipment eq WITH (NOLOCK)
                ON eq.equId = am.equ_id
            LEFT JOIN dbo.HID_Asset_Notification_User nu WITH (NOLOCK)
                ON nu.NotificationID = n.NotificationID
               AND LOWER(LTRIM(RTRIM(nu.UserName))) = LOWER(LTRIM(RTRIM(?)))
            WHERE ISNULL(n.Status, 'OPEN') = 'OPEN'
              {scope_sql}
              {unread_sql}
            ORDER BY n.CreatedAt DESC, n.NotificationID DESC;
        """
        df = pd.read_sql(sql, conn, params=params or None)
        if df is None or df.empty:
            return []
        df["created_at"] = pd.to_datetime(df["created_at"], errors="coerce")
        df["created_at_display"] = df["created_at"].apply(
            lambda value: None if value is None or pd.isna(value) else value.strftime("%Y-%m-%d %H:%M")
        )
        return [_asset_notification_row_dict(row) for row in df.to_dict(orient="records")]
    except Exception as exc:
        print(f"fetch_asset_notifications failed: {exc}")
        return []
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_asset_notification(notification_id, location_codes=None, username=None):
    rows = fetch_asset_notifications(location_codes=location_codes, username=username, unread_only=False, limit=1000)
    target_id = _to_int(notification_id)
    for row in rows:
        if _to_int(row.get("notification_id")) == target_id:
            return row
    return None


def _upsert_asset_notification_user(notification_id, username, *, read=False, accepted=False, account_id=None):
    notification_id_val = _to_int(notification_id)
    user = _asset_clean_text(username)
    if not notification_id_val or not user:
        return {"status": "error", "message": "Invalid notification/user."}
    if not ensure_asset_notification_tables():
        return {"status": "error", "message": "Asset notification table is unavailable."}
    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        cursor = conn.cursor()
        cursor.execute(
            """
            IF EXISTS (
                SELECT 1 FROM dbo.HID_Asset_Notification_User
                WHERE NotificationID = ? AND LOWER(LTRIM(RTRIM(UserName))) = LOWER(LTRIM(RTRIM(?)))
            )
            BEGIN
                UPDATE dbo.HID_Asset_Notification_User
                SET
                    ReadAt = CASE WHEN ? = 1 AND ReadAt IS NULL THEN GETDATE() ELSE ReadAt END,
                    AcceptedAt = CASE WHEN ? = 1 AND AcceptedAt IS NULL THEN GETDATE() ELSE AcceptedAt END,
                    AcceptedByAccountId = CASE WHEN ? = 1 THEN ? ELSE AcceptedByAccountId END,
                    UpdatedAt = GETDATE()
                WHERE NotificationID = ? AND LOWER(LTRIM(RTRIM(UserName))) = LOWER(LTRIM(RTRIM(?)));
            END
            ELSE
            BEGIN
                INSERT INTO dbo.HID_Asset_Notification_User (
                    NotificationID, UserName, ReadAt, AcceptedAt, AcceptedByAccountId, UpdatedAt
                )
                VALUES (
                    ?, ?, CASE WHEN ? = 1 THEN GETDATE() ELSE NULL END,
                    CASE WHEN ? = 1 THEN GETDATE() ELSE NULL END,
                    CASE WHEN ? = 1 THEN ? ELSE NULL END,
                    GETDATE()
                );
            END;
            """,
            (
                notification_id_val,
                user,
                1 if read or accepted else 0,
                1 if accepted else 0,
                1 if accepted else 0,
                _to_int(account_id),
                notification_id_val,
                user,
                notification_id_val,
                user,
                1 if read or accepted else 0,
                1 if accepted else 0,
                1 if accepted else 0,
                _to_int(account_id),
            ),
        )
        conn.commit()
        return {"status": "success", "message": "Notification updated."}
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to update notification: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def mark_asset_notification_read(notification_id, username):
    return _upsert_asset_notification_user(notification_id, username, read=True)


def accept_asset_notification(notification_id, username, account_id=None):
    return _upsert_asset_notification_user(notification_id, username, read=True, accepted=True, account_id=account_id)


def ensure_asset_breakdown_tables():
    global _ASSET_BREAKDOWN_TABLE_READY
    if _ASSET_BREAKDOWN_TABLE_READY:
        return True
    with _ASSET_BOOTSTRAP_LOCK:
        if _ASSET_BREAKDOWN_TABLE_READY:
            return True
        conn = _asset_db_connection()
        if not conn:
            return False
        try:
            cursor = conn.cursor()
            cursor.execute(
                """
                IF OBJECT_ID('dbo.HID_Asset_Breakdown_Ticket', 'U') IS NULL
                BEGIN
                    CREATE TABLE dbo.HID_Asset_Breakdown_Ticket (
                        TicketID INT IDENTITY(1,1) NOT NULL PRIMARY KEY,
                        TicketNo NVARCHAR(40) NOT NULL,
                        AssetID INT NOT NULL,
                        UnitCode NVARCHAR(20) NOT NULL,
                        BreakdownDateTime DATETIME NOT NULL,
                        BreakdownReason NVARCHAR(1000) NOT NULL,
                        ExpectedTechnicianVisit DATETIME NULL,
                        Status NVARCHAR(30) NOT NULL DEFAULT ('OPEN'),
                        RepairDoneDate DATETIME NULL,
                        RepairVerdict BIT NULL,
                        RepairVerdictReason NVARCHAR(1000) NULL,
                        NonRepairable BIT NOT NULL DEFAULT (0),
                        CreatedByUserName NVARCHAR(255) NULL,
                        CreatedByAccountId INT NULL,
                        CreatedAt DATETIME NOT NULL DEFAULT (GETDATE()),
                        UpdatedByUserName NVARCHAR(255) NULL,
                        UpdatedByAccountId INT NULL,
                        UpdatedAt DATETIME NULL,
                        ClosedAt DATETIME NULL,
                        InitialEmailSentAt DATETIME NULL,
                        InitialEmailStatus NVARCHAR(40) NULL
                    );
                    CREATE UNIQUE INDEX UX_HID_Asset_Breakdown_Ticket_TicketNo
                    ON dbo.HID_Asset_Breakdown_Ticket (TicketNo);
                    CREATE INDEX IX_HID_Asset_Breakdown_Ticket_Open
                    ON dbo.HID_Asset_Breakdown_Ticket (Status, UnitCode, BreakdownDateTime);
                END;

                IF OBJECT_ID('dbo.HID_Asset_Breakdown_Reminder_Run', 'U') IS NULL
                BEGIN
                    CREATE TABLE dbo.HID_Asset_Breakdown_Reminder_Run (
                        RunID INT IDENTITY(1,1) NOT NULL PRIMARY KEY,
                        RunDate DATE NOT NULL,
                        RunType NVARCHAR(60) NOT NULL,
                        UnitCode NVARCHAR(20) NOT NULL DEFAULT (''),
                        StartedAt DATETIME NOT NULL DEFAULT (GETDATE()),
                        FinishedAt DATETIME NULL,
                        Status NVARCHAR(20) NOT NULL DEFAULT ('running'),
                        Message NVARCHAR(1000) NULL
                    );
                    CREATE UNIQUE INDEX UX_HID_Asset_Breakdown_Reminder_Run
                    ON dbo.HID_Asset_Breakdown_Reminder_Run (RunDate, RunType, UnitCode);
                END;

                IF OBJECT_ID('dbo.HID_Asset_Action_Otp', 'U') IS NULL
                BEGIN
                    CREATE TABLE dbo.HID_Asset_Action_Otp (
                        OtpID INT IDENTITY(1,1) NOT NULL PRIMARY KEY,
                        AssetID INT NOT NULL,
                        TicketID INT NULL,
                        UnitCode NVARCHAR(20) NOT NULL,
                        ActionType NVARCHAR(60) NOT NULL,
                        OtpHash NVARCHAR(128) NOT NULL,
                        ExpiresAt DATETIME NOT NULL,
                        IsUsed BIT NOT NULL DEFAULT (0),
                        RequestedByUserName NVARCHAR(255) NULL,
                        RequestedByAccountId INT NULL,
                        RequestedAt DATETIME NOT NULL DEFAULT (GETDATE()),
                        UsedAt DATETIME NULL,
                        UsedByUserName NVARCHAR(255) NULL
                    );
                    CREATE INDEX IX_HID_Asset_Action_Otp_Asset
                    ON dbo.HID_Asset_Action_Otp (AssetID, ActionType, IsUsed, ExpiresAt DESC);
                END;

                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ComplaintSource') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ComplaintSource VARCHAR(40) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ReportedStatus') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ReportedStatus NVARCHAR(80) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'Priority') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD Priority VARCHAR(20) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ReporterEmployeeID') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ReporterEmployeeID NVARCHAR(50) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ReporterEmployeeName') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ReporterEmployeeName NVARCHAR(200) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ReporterDepartment') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ReporterDepartment NVARCHAR(200) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ReporterDesignation') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ReporterDesignation NVARCHAR(200) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ReporterMobile') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ReporterMobile NVARCHAR(30) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ReporterUnit') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ReporterUnit VARCHAR(20) NULL;
                IF COL_LENGTH('dbo.HID_Asset_Breakdown_Ticket', 'ContactMobile') IS NULL
                    ALTER TABLE dbo.HID_Asset_Breakdown_Ticket ADD ContactMobile NVARCHAR(30) NULL;
                """
            )
            conn.commit()
            _ASSET_BREAKDOWN_TABLE_READY = True
            return True
        except Exception as exc:
            try:
                conn.rollback()
            except Exception:
                pass
            print(f"Asset breakdown table bootstrap failed: {exc}")
            return False
        finally:
            try:
                conn.close()
            except Exception:
                pass


def _asset_ticket_no(ticket_id):
    return f"BD-{int(ticket_id):06d}"


def _asset_breakdown_row_dict(row):
    out = dict(row or {})
    for col in ["breakdown_datetime", "expected_technician_visit", "repair_done_date", "created_at", "updated_at", "closed_at"]:
        val = out.get(col)
        dt_val = _to_datetime(val)
        out[f"{col}_display"] = dt_val.strftime("%Y-%m-%d %H:%M") if dt_val else None
        out[f"{col}_input"] = dt_val.strftime("%Y-%m-%dT%H:%M") if dt_val else ""
    out["status_label"] = {
        "OPEN": "Open",
        "REPAIRED": "Repair Completed",
        "NON_REPAIRABLE": "Non-Repairable",
    }.get(_asset_upper_text(out.get("status")), _asset_clean_text(out.get("status")) or "Open")
    if _asset_upper_text(out.get("status")) == "OPEN" and out.get("repair_verdict") in {False, 0, "0"}:
        out["status_label"] = "Repair Not Done"
    out["repair_verdict_label"] = (
        "Yes" if out.get("repair_verdict") in {True, 1, "1"} else
        "No" if out.get("repair_verdict") in {False, 0, "0"} and out.get("repair_verdict") is not None else
        ""
    )
    return out


def _asset_breakdown_records_from_df(df):
    rows = _asset_records(df)
    return [_asset_breakdown_row_dict(row) for row in rows]


def fetch_asset_breakdown_tickets(location_codes=None, status=None, asset_id=None, limit=500):
    ensure_asset_breakdown_tables()
    unit_codes = _asset_normalize_location_codes(location_codes)
    if unit_codes is None:
        unit_codes = sorted(ASSET_ALLOWED_LOCATION_CODES)
    asset_id_val = _to_int(asset_id)
    if not unit_codes and not asset_id_val:
        return []
    conn = _asset_db_connection()
    if not conn:
        return []
    try:
        params = []
        where = []
        if unit_codes:
            placeholders = ",".join("?" for _ in unit_codes)
            where.append(f"UPPER(LTRIM(RTRIM(ISNULL(loc.location_code, bt.UnitCode)))) IN ({placeholders})")
            params.extend(unit_codes)
        status_key = _asset_upper_text(status)
        if status_key:
            if status_key == "CLOSED":
                where.append("bt.Status IN ('REPAIRED', 'NON_REPAIRABLE')")
            elif status_key == "OPEN":
                where.append("bt.Status = 'OPEN'")
            else:
                where.append("bt.Status = ?")
                params.append(status_key)
        if asset_id_val:
            where.append("bt.AssetID = ?")
            params.append(asset_id_val)
        top_limit = max(1, min(_to_int(limit, 500) or 500, 5000))
        sql = f"""
            SELECT TOP {top_limit}
                bt.TicketID AS ticket_id,
                bt.TicketNo AS ticket_no,
                bt.AssetID AS asset_id,
                am.asset_code,
                eq.equName AS asset_name,
                mt.machineTypeName AS machine_type_name,
                bt.UnitCode AS unit_code,
                bt.BreakdownDateTime AS breakdown_datetime,
                bt.BreakdownReason AS breakdown_reason,
                bt.ExpectedTechnicianVisit AS expected_technician_visit,
                bt.Status AS status,
                bt.RepairDoneDate AS repair_done_date,
                bt.RepairVerdict AS repair_verdict,
                bt.RepairVerdictReason AS repair_verdict_reason,
                bt.NonRepairable AS non_repairable,
                bt.ComplaintSource AS complaint_source,
                bt.ReportedStatus AS reported_status,
                bt.Priority AS priority,
                bt.ReporterEmployeeID AS reporter_employee_id,
                bt.ReporterEmployeeName AS reporter_employee_name,
                bt.ReporterDepartment AS reporter_department,
                bt.ReporterDesignation AS reporter_designation,
                bt.ReporterMobile AS reporter_mobile,
                bt.ReporterUnit AS reporter_unit,
                bt.ContactMobile AS contact_mobile,
                bt.CreatedByUserName AS created_by_username,
                bt.CreatedAt AS created_at,
                bt.UpdatedByUserName AS updated_by_username,
                bt.UpdatedAt AS updated_at,
                bt.ClosedAt AS closed_at
            FROM dbo.HID_Asset_Breakdown_Ticket bt WITH (NOLOCK)
            INNER JOIN dbo.asset_master am WITH (NOLOCK) ON am.asset_id = bt.AssetID
            LEFT JOIN dbo.asset_locationMst loc WITH (NOLOCK) ON loc.location_id = am.locationId
            LEFT JOIN dbo.asset_equipment eq WITH (NOLOCK) ON eq.equId = am.equ_id
            LEFT JOIN dbo.asset_MachineTypeMst mt WITH (NOLOCK) ON mt.id = am.machine_type
            WHERE {" AND ".join(where)}
            ORDER BY CASE WHEN bt.Status = 'OPEN' THEN 0 ELSE 1 END, bt.BreakdownDateTime DESC, bt.TicketID DESC;
        """
        df = pd.read_sql(sql, conn, params=params)
        return _asset_breakdown_records_from_df(df)
    except Exception as exc:
        print(f"fetch_asset_breakdown_tickets failed: {exc}")
        return []
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_asset_breakdown_ticket(ticket_id, location_codes=None):
    rows = fetch_asset_breakdown_tickets(location_codes=location_codes, limit=5000)
    ticket_id_val = _to_int(ticket_id)
    return next((row for row in rows if _to_int(row.get("ticket_id")) == ticket_id_val), None)


def fetch_open_asset_breakdowns_by_unit(unit_code, limit=5000):
    unit = _asset_upper_text(unit_code)
    return [
        row for row in fetch_asset_breakdown_tickets(location_codes=[unit], status="OPEN", limit=limit)
        if _asset_upper_text(row.get("unit_code")) == unit
    ]


def create_asset_breakdown_ticket(payload, actor_user_id=None, actor_username=None):
    ensure_asset_breakdown_tables()
    asset_id_val = _to_int((payload or {}).get("asset_id") or (payload or {}).get("assetId"))
    breakdown_dt = _to_datetime((payload or {}).get("breakdown_datetime") or (payload or {}).get("breakdown_date_time"))
    reason = _asset_clean_text((payload or {}).get("breakdown_reason"), 1000)
    expected_dt = _to_datetime((payload or {}).get("expected_technician_visit"))
    if not asset_id_val or not breakdown_dt or not reason:
        return {"status": "error", "message": "Asset, breakdown date/time, and reason are required."}
    asset_frame = _fetch_asset_master_frame(asset_id=asset_id_val)
    if asset_frame is None or asset_frame.empty:
        return {"status": "error", "message": "Asset not found."}
    asset = _asset_records(asset_frame)[0]
    unit = _asset_upper_text(asset.get("location_code"))
    if not unit:
        return {"status": "error", "message": "Asset unit is not available."}
    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        cursor = conn.cursor()
        cursor.execute(
            """
            INSERT INTO dbo.HID_Asset_Breakdown_Ticket (
                TicketNo, AssetID, UnitCode, BreakdownDateTime, BreakdownReason, ExpectedTechnicianVisit,
                Status, ComplaintSource, ReportedStatus, Priority, ReporterEmployeeID, ReporterEmployeeName,
                ReporterDepartment, ReporterDesignation, ReporterMobile, ReporterUnit, ContactMobile,
                CreatedByUserName, CreatedByAccountId, CreatedAt
            )
            VALUES ('PENDING', ?, ?, ?, ?, ?, 'OPEN', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, GETDATE());
            SELECT CAST(SCOPE_IDENTITY() AS INT);
            """,
            (
                asset_id_val,
                unit,
                breakdown_dt,
                reason,
                expected_dt,
                _asset_clean_limited((payload or {}).get("complaint_source"), 40) or None,
                _asset_clean_limited((payload or {}).get("reported_status"), 80) or None,
                _asset_clean_limited((payload or {}).get("priority"), 20) or None,
                _asset_clean_limited((payload or {}).get("employee_id"), 50) or None,
                _asset_clean_limited((payload or {}).get("employee_name"), 200) or None,
                _asset_clean_limited((payload or {}).get("employee_department"), 200) or None,
                _asset_clean_limited((payload or {}).get("employee_designation"), 200) or None,
                _asset_clean_limited((payload or {}).get("employee_mobile"), 30) or None,
                _asset_clean_limited((payload or {}).get("employee_unit"), 20) or None,
                _asset_clean_limited((payload or {}).get("contact_mobile"), 30) or None,
                _asset_clean_text(actor_username),
                _to_int(actor_user_id),
            ),
        )
        row = _cursor_fetchone_safe(cursor)
        ticket_id = int(row[0]) if row and row[0] is not None else None
        ticket_no = _asset_ticket_no(ticket_id)
        cursor.execute("UPDATE dbo.HID_Asset_Breakdown_Ticket SET TicketNo = ? WHERE TicketID = ?", (ticket_no, ticket_id))
        cursor.execute(
            "UPDATE dbo.asset_master SET asset_status = 4, updateBy = ?, updateOn = ? WHERE asset_id = ?",
            (_to_int(actor_user_id, 0) or 0, _asset_now(), asset_id_val),
        )
        conn.commit()
        invalidate_asset_management_cache()
        ticket = fetch_asset_breakdown_ticket(ticket_id, location_codes=[unit])
        return {"status": "success", "message": f"Breakdown ticket {ticket_no} opened.", "ticket": ticket}
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to open breakdown ticket: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


