def close_asset_breakdown_ticket(ticket_id, payload, actor_user_id=None, actor_username=None):
    ensure_asset_breakdown_tables()
    payload = payload or {}
    ticket_id_val = _to_int(ticket_id)
    repair_done = _to_datetime(payload.get("repair_done_date"))
    expected_visit_supplied = "expected_technician_visit" in payload
    expected_visit = _to_datetime(payload.get("expected_technician_visit")) if expected_visit_supplied else None
    verdict_raw = _asset_clean_text(payload.get("repair_verdict")).lower()
    verdict = None
    if verdict_raw in {"yes", "true", "1"}:
        verdict = 1
    elif verdict_raw in {"no", "false", "0"}:
        verdict = 0
    reason = _asset_clean_text(payload.get("repair_verdict_reason"), 1000)
    non_repairable = str(payload.get("non_repairable") or "").strip().lower() in {"1", "true", "yes", "on"}
    otp_code = _asset_clean_text(payload.get("otp_code"))
    if not ticket_id_val:
        return {"status": "error", "message": "Breakdown ticket is required."}
    ticket = fetch_asset_breakdown_ticket(ticket_id_val)
    if not ticket:
        return {"status": "error", "message": "Breakdown ticket not found."}
    if _asset_upper_text(ticket.get("status")) != "OPEN":
        return {"status": "error", "message": "Breakdown ticket is already closed."}
    if not expected_visit_supplied:
        expected_visit = _to_datetime(ticket.get("expected_technician_visit"))
    if verdict is None and not repair_done:
        existing_expected_visit = _to_datetime(ticket.get("expected_technician_visit"))
        if not expected_visit_supplied or (expected_visit is None and existing_expected_visit is None):
            return {"status": "error", "message": "Enter expected technician visit or choose a repair verdict."}
        conn = _asset_db_connection()
        if not conn:
            return {"status": "error", "message": "Unable to connect to asset database."}
        try:
            cursor = conn.cursor()
            cursor.execute(
                """
                UPDATE dbo.HID_Asset_Breakdown_Ticket
                SET ExpectedTechnicianVisit = ?, UpdatedByUserName = ?, UpdatedByAccountId = ?, UpdatedAt = GETDATE()
                WHERE TicketID = ?;
                """,
                (
                    expected_visit,
                    _asset_clean_text(actor_username),
                    _to_int(actor_user_id),
                    ticket_id_val,
                ),
            )
            conn.commit()
            invalidate_asset_management_cache()
            return {
                "status": "success",
                "message": f"Expected technician visit updated for {ticket.get('ticket_no')}.",
                "ticket": fetch_asset_breakdown_ticket(ticket_id_val),
            }
        except Exception as exc:
            try:
                conn.rollback()
            except Exception:
                pass
            return {"status": "error", "message": f"Unable to update expected visit: {exc}"}
        finally:
            try:
                conn.close()
            except Exception:
                pass
    if not repair_done or verdict is None:
        return {"status": "error", "message": "Repair update date and repair verdict are required for a repair outcome."}
    if verdict == 0 and not reason:
        return {"status": "error", "message": "Repair verdict reason is required when repair verdict is No."}
    if non_repairable:
        verified = verify_asset_action_otp(
            asset_id=ticket.get("asset_id"),
            action_type="NON_REPAIRABLE",
            otp_code=otp_code,
            ticket_id=ticket_id_val,
            actor_username=actor_username,
            consume=True,
        )
        if verified.get("status") != "success":
            return {"status": "otp_required", "message": verified.get("message") or "Valid Asset-Purchase OTP is required."}
    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        closes_ticket = bool(non_repairable or verdict == 1)
        status = "NON_REPAIRABLE" if non_repairable else "REPAIRED" if verdict == 1 else "OPEN"
        asset_status = 5 if non_repairable else 1 if verdict == 1 else 4
        cursor = conn.cursor()
        cursor.execute(
            """
            UPDATE dbo.HID_Asset_Breakdown_Ticket
            SET Status = ?, RepairDoneDate = ?, RepairVerdict = ?, RepairVerdictReason = ?,
                ExpectedTechnicianVisit = ?, NonRepairable = ?, UpdatedByUserName = ?, UpdatedByAccountId = ?,
                UpdatedAt = GETDATE(), ClosedAt = CASE WHEN ? = 1 THEN GETDATE() ELSE NULL END
            WHERE TicketID = ?;
            """,
            (
                status,
                repair_done,
                verdict,
                reason or None,
                expected_visit,
                1 if non_repairable else 0,
                _asset_clean_text(actor_username),
                _to_int(actor_user_id),
                1 if closes_ticket else 0,
                ticket_id_val,
            ),
        )
        cursor.execute(
            "UPDATE dbo.asset_master SET asset_status = ?, updateBy = ?, updateOn = ? WHERE asset_id = ?",
            (asset_status, _to_int(actor_user_id, 0) or 0, _asset_now(), _to_int(ticket.get("asset_id"))),
        )
        conn.commit()
        invalidate_asset_management_cache()
        message = (
            f"Breakdown ticket {ticket.get('ticket_no')} closed as non-repairable."
            if non_repairable else
            f"Breakdown ticket {ticket.get('ticket_no')} closed as repaired."
            if verdict == 1 else
            f"Repair update saved for {ticket.get('ticket_no')}; ticket remains open."
        )
        return {"status": "success", "message": message, "ticket": fetch_asset_breakdown_ticket(ticket_id_val)}
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to update breakdown ticket: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _hash_asset_otp(code):
    return hashlib.sha256(_asset_clean_text(code).encode("utf-8")).hexdigest()


def create_asset_action_otp(asset_id, action_type, ticket_id=None, actor_user_id=None, actor_username=None, ttl_minutes=15):
    ensure_asset_breakdown_tables()
    asset_id_val = _to_int(asset_id)
    if not asset_id_val:
        return {"status": "error", "message": "Invalid asset id."}
    asset_frame = _fetch_asset_master_frame(asset_id=asset_id_val)
    if asset_frame is None or asset_frame.empty:
        return {"status": "error", "message": "Asset not found."}
    asset = _asset_records(asset_frame)[0]
    unit = _asset_upper_text(asset.get("location_code"))
    code = f"{random.randint(100000, 999999)}"
    expires_at = datetime.now(tz=LOCAL_TZ).replace(tzinfo=None) + timedelta(minutes=max(5, _to_int(ttl_minutes, 15) or 15))
    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        cursor = conn.cursor()
        cursor.execute(
            """
            UPDATE dbo.HID_Asset_Action_Otp
            SET IsUsed = 1, UsedAt = GETDATE(), UsedByUserName = ?
            WHERE AssetID = ? AND ActionType = ? AND IsUsed = 0;
            """,
            (_asset_clean_text(actor_username), asset_id_val, _asset_upper_text(action_type)),
        )
        cursor.execute(
            """
            INSERT INTO dbo.HID_Asset_Action_Otp (
                AssetID, TicketID, UnitCode, ActionType, OtpHash, ExpiresAt,
                RequestedByUserName, RequestedByAccountId, RequestedAt
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, GETDATE());
            SELECT CAST(SCOPE_IDENTITY() AS INT);
            """,
            (
                asset_id_val,
                _to_int(ticket_id),
                unit,
                _asset_upper_text(action_type),
                _hash_asset_otp(code),
                expires_at,
                _asset_clean_text(actor_username),
                _to_int(actor_user_id),
            ),
        )
        row = _cursor_fetchone_safe(cursor)
        conn.commit()
        return {
            "status": "success",
            "message": "OTP generated.",
            "otp_id": int(row[0]) if row and row[0] is not None else None,
            "otp_code": code,
            "expires_at": expires_at.strftime("%Y-%m-%d %H:%M"),
            "asset": asset,
            "unit_code": unit,
        }
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to generate OTP: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def verify_asset_action_otp(asset_id, action_type, otp_code, ticket_id=None, actor_username=None, consume=True):
    ensure_asset_breakdown_tables()
    asset_id_val = _to_int(asset_id)
    code_hash = _hash_asset_otp(otp_code)
    if not asset_id_val or not _asset_clean_text(otp_code):
        return {"status": "error", "message": "Enter the Asset-Purchase OTP."}
    conn = _asset_db_connection()
    if not conn:
        return {"status": "error", "message": "Unable to connect to asset database."}
    try:
        cursor = conn.cursor()
        params = [asset_id_val, _asset_upper_text(action_type), code_hash]
        ticket_clause = ""
        ticket_id_val = _to_int(ticket_id)
        if ticket_id_val:
            ticket_clause = " AND (TicketID = ? OR TicketID IS NULL)"
            params.append(ticket_id_val)
        cursor.execute(
            f"""
            SELECT TOP 1 OtpID
            FROM dbo.HID_Asset_Action_Otp WITH (UPDLOCK, HOLDLOCK)
            WHERE AssetID = ? AND ActionType = ? AND OtpHash = ?
              AND IsUsed = 0 AND ExpiresAt >= GETDATE()
              {ticket_clause}
            ORDER BY RequestedAt DESC, OtpID DESC;
            """,
            params,
        )
        row = _cursor_fetchone_safe(cursor)
        if not row:
            conn.rollback()
            return {"status": "error", "message": "Invalid or expired OTP."}
        otp_id = int(row[0])
        if consume:
            cursor.execute(
                """
                UPDATE dbo.HID_Asset_Action_Otp
                SET IsUsed = 1, UsedAt = GETDATE(), UsedByUserName = ?
                WHERE OtpID = ?;
                """,
                (_asset_clean_text(actor_username), otp_id),
            )
        conn.commit()
        return {"status": "success", "message": "OTP verified.", "otp_id": otp_id}
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Unable to verify OTP: {exc}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def begin_asset_breakdown_reminder_run(run_date=None, run_type="daily", unit_code=""):
    ensure_asset_breakdown_tables()
    target_date = _asset_date_only(run_date) or datetime.now(tz=LOCAL_TZ).date()
    run_type_val = _asset_clean_text(run_type, "daily") or "daily"
    unit_val = _asset_upper_text(unit_code)
    conn = _asset_db_connection()
