def search_pharmacy_sale_items(unit: str, query: str = "", limit: int = 30, store_id: int = PHARMACY_SALE_STORE_ID):
    unit_norm = str(unit or "").strip().upper()
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT:
        print(f"Pharmacy sale item search is only available for {PHARMACY_SALE_ALLOWED_UNIT}")
        return pd.DataFrame()

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy sale item search: could not connect to {unit_norm}")
        return None

    try:
        sql = """
        SET NOCOUNT ON;

        DECLARE @Search NVARCHAR(120) = ?;
        DECLARE @ResultLimit INT = ?;
        DECLARE @StoreID INT = ?;
        DECLARE @SearchLike NVARCHAR(140) = CASE
            WHEN LTRIM(RTRIM(ISNULL(@Search, N''))) = N'' THEN N''
            ELSE N'%' + LOWER(LTRIM(RTRIM(@Search))) + N'%'
        END;

        WITH stock_by_item AS (
            SELECT
                  CAST(ss.ItemID AS INT) AS ItemID
                , SUM(CAST(ISNULL(ss.Qty, 0) AS DECIMAL(18, 4))) AS StockQty
            FROM dbo.StoreStock ss WITH (NOLOCK)
            INNER JOIN dbo.IVBatch b WITH (NOLOCK)
                ON b.ID = ss.BatchID
            WHERE
                ss.StoreID = @StoreID
                AND ISNULL(ss.Qty, 0) > 0
                AND CAST(ISNULL(b.ExpiryDate, '19000101') AS DATE) >= CAST(GETDATE() AS DATE)
            GROUP BY ss.ItemID
        )
        SELECT TOP (@ResultLimit)
              CAST(i.ID AS INT) AS ItemID
            , LTRIM(RTRIM(ISNULL(i.Code, N''))) AS ItemCode
            , LTRIM(RTRIM(ISNULL(i.Name, N''))) AS ItemName
            , LTRIM(RTRIM(ISNULL(i.DescriptiveName, N''))) AS DescriptiveName
            , CAST(ISNULL(i.SalesPrice, 0) AS FLOAT) AS SalesPrice
            , CAST(ISNULL(i.StandardRate, 0) AS FLOAT) AS StandardRate
            , CAST(ISNULL(i.PackSizeID, 0) AS INT) AS PackSizeID
            , CAST(ISNULL(s.StockQty, 0) AS FLOAT) AS StockQty
        FROM dbo.IVItem i WITH (NOLOCK)
        INNER JOIN stock_by_item s
            ON s.ItemID = i.ID
        WHERE
            ISNULL(i.Active, 1) = 1
            AND (
                @SearchLike = N''
                OR LOWER(LTRIM(RTRIM(ISNULL(i.Name, N'')))) LIKE @SearchLike
                OR LOWER(LTRIM(RTRIM(ISNULL(i.DescriptiveName, N'')))) LIKE @SearchLike
                OR LOWER(LTRIM(RTRIM(ISNULL(i.Code, N'')))) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), i.ID)) LIKE @SearchLike
            )
        ORDER BY LTRIM(RTRIM(ISNULL(i.Name, N''))), i.ID;
        """
        df = pd.read_sql(sql, conn, params=[_pharmacy_sale_clean_text(query), max(1, min(int(limit or 30), 100)), int(store_id or PHARMACY_SALE_STORE_ID)])
        if df is None or df.empty:
            return pd.DataFrame(columns=["ItemID", "ItemCode", "ItemName", "DescriptiveName", "SalesPrice", "StandardRate", "PackSizeID", "StockQty"])
        df.columns = [str(col).strip() for col in df.columns]
        return df
    except Exception as e:
        print(f"Pharmacy sale item search failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_pharmacy_sale_batches(unit: str, item_id: int, store_id: int = PHARMACY_SALE_STORE_ID):
    unit_norm = str(unit or "").strip().upper()
    item_id_int = int(item_id or 0)
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT or item_id_int <= 0:
        return pd.DataFrame()

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy sale batch search: could not connect to {unit_norm}")
        return None

    try:
        sql = """
        SET NOCOUNT ON;

        SELECT
              CAST(ss.ItemID AS INT) AS ItemID
            , CAST(ss.BatchID AS INT) AS BatchID
            , LTRIM(RTRIM(ISNULL(b.Name, N''))) AS BatchName
            , CAST(ISNULL(b.ExpiryDate, '19000101') AS DATE) AS ExpiryDate
            , CAST(ISNULL(ss.Qty, 0) AS FLOAT) AS StockQty
            , CAST(ISNULL(b.mrp, 0) AS FLOAT) AS MRP
            , CAST(ISNULL(b.Rate, 0) AS FLOAT) AS Rate
            , CAST(ISNULL(b.lendingrate, 0) AS FLOAT) AS LendingRate
            , CAST(ISNULL(b.Actuallendingrate, ISNULL(b.lendingrate, 0)) AS FLOAT) AS ActualLendingRate
            , CAST(ISNULL(i.SalesPrice, 0) AS FLOAT) AS SalesPrice
        FROM dbo.StoreStock ss WITH (NOLOCK)
        INNER JOIN dbo.IVBatch b WITH (NOLOCK)
            ON b.ID = ss.BatchID
        INNER JOIN dbo.IVItem i WITH (NOLOCK)
            ON i.ID = ss.ItemID
        WHERE
            ss.StoreID = ?
            AND ss.ItemID = ?
            AND ISNULL(ss.Qty, 0) > 0
            AND CAST(ISNULL(b.ExpiryDate, '19000101') AS DATE) >= CAST(GETDATE() AS DATE)
        ORDER BY CAST(ISNULL(b.ExpiryDate, '19000101') AS DATE), LTRIM(RTRIM(ISNULL(b.Name, N''))), b.ID;
        """
        df = pd.read_sql(sql, conn, params=[int(store_id or PHARMACY_SALE_STORE_ID), item_id_int])
        if df is None or df.empty:
            return pd.DataFrame(columns=["ItemID", "BatchID", "BatchName", "ExpiryDate", "StockQty", "MRP", "Rate", "LendingRate", "ActualLendingRate", "SalesPrice"])
        df.columns = [str(col).strip() for col in df.columns]
        return df
    except Exception as e:
        print(f"Pharmacy sale batch search failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def search_pharmacy_sale_doctors(unit: str, query: str = "", limit: int = 20):
    unit_norm = str(unit or "").strip().upper()
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT:
        print(f"Pharmacy doctor search is only available for {PHARMACY_SALE_ALLOWED_UNIT}")
        return pd.DataFrame()

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy doctor search: could not connect to {unit_norm}")
        return None

    try:
        query_text = _pharmacy_sale_normalize_search_text(query).lower()
        query_like = f"%{query_text}%"
        query_compact = re.sub(r"[-/\s]", "", query_text)
        query_compact_like = f"%{query_compact}%"
        row_limit = max(1, min(int(limit or 20), 50))

        sql = f"""
        SET NOCOUNT ON;
        SELECT TOP {row_limit}
              CAST(e.EmpID AS INT) AS DoctorID
            , LTRIM(RTRIM(ISNULL(dbo.fn_doctorfullname(e.EmpID), N''))) AS DoctorName
        FROM dbo.employee_mst e WITH (NOLOCK)
        WHERE
            LTRIM(RTRIM(ISNULL(e.EmpType, N''))) = N'Doc'
            AND ISNULL(e.Deactive, 0) = 0
            AND (
                ? = N''
                OR LOWER(LTRIM(RTRIM(ISNULL(dbo.fn_doctorfullname(e.EmpID), N'')))) LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(LTRIM(RTRIM(ISNULL(dbo.fn_doctorfullname(e.EmpID), N'')))), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR CONVERT(NVARCHAR(20), e.EmpID) LIKE ?
            )
        ORDER BY DoctorName, DoctorID;
        """
        df = pd.read_sql(sql, conn, params=[query_text, query_like, query_compact_like, query_like])
        if df is None or df.empty:
            return pd.DataFrame(columns=["DoctorID", "DoctorName"])
        df.columns = [str(col).strip() for col in df.columns]
        df["DoctorName"] = df["DoctorName"].fillna("").astype(str).str.strip()
        df = df[df["DoctorName"] != ""].copy()
        return df.reset_index(drop=True)
    except Exception as e:
        print(f"Pharmacy doctor search failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_pharmacy_sale_payment_modes(unit: str):
    unit_norm = str(unit or "").strip().upper()
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT:
        print(f"Pharmacy payment modes are only available for {PHARMACY_SALE_ALLOWED_UNIT}")
        return pd.DataFrame()

    df = fetch_payment_modes(unit_norm)
    if df is None:
        return None
    if df.empty:
        return pd.DataFrame(columns=["PaymentModeId", "PaymentModeName"])
    df.columns = [str(col).strip() for col in df.columns]
    if "Deactive" in df.columns:
        df = df[~df["Deactive"].fillna(False).astype(bool)].copy()
    keep_cols = [col for col in ["PaymentModeId", "PaymentModeName"] if col in df.columns]
    if len(keep_cols) < 2:
        return pd.DataFrame(columns=["PaymentModeId", "PaymentModeName"])
    return df[keep_cols].sort_values(by=["PaymentModeName", "PaymentModeId"], kind="stable").reset_index(drop=True)


def fetch_pharmacy_sale_print_payload(unit: str, bill_id: int):
    unit_norm = str(unit or "").strip().upper()
    bill_id_int = int(bill_id or 0)
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT or bill_id_int <= 0:
        return None

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy sale print payload: could not connect to {unit_norm}")
        return None

    try:
        header_df = pd.read_sql(
            """
            SET NOCOUNT ON;
            SELECT TOP 1
                  CAST(bm.Bill_ID AS INT) AS BillID
                , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
                , CAST(bm.BillDate AS DATETIME) AS BillDate
                , CAST(ISNULL(bm.GrossAmount, 0) AS FLOAT) AS GrossAmount
                , CAST(ISNULL(bm.DiscountAmount, 0) AS FLOAT) AS DiscountAmount
                , CAST(ISNULL(bm.NetAmount, 0) AS FLOAT) AS NetAmount
                , CAST(ISNULL(bm.DueAmount, 0) AS FLOAT) AS DueAmount
                , CAST(ISNULL(bm.DiscountPercentage, 0) AS FLOAT) AS DiscountPercentage
                , LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))) AS RegistrationNo
                , LTRIM(RTRIM(ISNULL(p.sPatientUHIDNo, N''))) AS SharpSightUHID
                , CAST(ISNULL(bm.TmpPatientId, 0) AS INT) AS TmpPatientID
                , CAST(ISNULL(bm.Visit_ID, 0) AS INT) AS VisitID
                , LTRIM(RTRIM(ISNULL(v.VisitNo, N''))) AS VisitNo
                , LTRIM(RTRIM(ISNULL(v.AdmissionNo, N''))) AS AdmissionNo
                , ISNULL(v.TypeOfVisit, N'') AS TypeOfVisit
                , CAST(ISNULL(v.VisitDate, bm.BillDate) AS DATETIME) AS VisitDate
                , CAST(ISNULL(v.PatientID, dsm.PatientID) AS INT) AS PatientID
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(REPLACE(REPLACE(ISNULL(tp.FirstName, N'') + N' ' + ISNULL(tp.MiddleName, N'') + N' ' + ISNULL(tp.LastName, N''), N'  ', N' '), N'  ', N' '))), N''),
                      ISNULL(dbo.fn_PatientFullName(ISNULL(v.PatientID, dsm.PatientID)), N''),
                      N''
                  ) AS PatientName
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(ISNULL(tp.ExternalReferedBy, N''))), N''),
                      ISNULL(dbo.fn_DoctorFirstName(v.DocInCharge), N''),
                      N''
                  ) AS PrescribedBy
                , CAST(ISNULL(dsm.DrugSaleID, 0) AS INT) AS DrugSaleID
                , LTRIM(RTRIM(ISNULL(dsm.Code, N''))) AS DrugSaleCode
                , CAST(ISNULL(rec.ReceiptCount, 0) AS INT) AS ReceiptCount
                , CAST(ISNULL(rec.ReceivedAmount, 0) AS FLOAT) AS ReceivedAmount
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), bm.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), dsm.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), bm.UpdatedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(80), COALESCE(bm.UpdatedBy, bm.InsertedByUserID, dsm.InsertedByUserID)))), N''),
                      N''
                  ) AS GeneratedBy
                , LTRIM(RTRIM(ISNULL(bm.Remarks, N''))) AS Remarks
            FROM dbo.Billing_Mst bm WITH (NOLOCK)
            LEFT JOIN dbo.DrugSaleMst dsm WITH (NOLOCK)
                ON dsm.BillId = bm.Bill_ID
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = bm.Visit_ID
            LEFT JOIN dbo.Patient p WITH (NOLOCK)
                ON p.PatientId = ISNULL(v.PatientID, dsm.PatientID)
            LEFT JOIN dbo.TMPPatient tp WITH (NOLOCK)
                ON tp.TmpPatientID = bm.TmpPatientId
            OUTER APPLY (
                SELECT
                      COUNT(1) AS ReceiptCount
                    , CAST(ISNULL(SUM(ISNULL(rd.Amount, ISNULL(rm.Amount, 0))), 0) AS FLOAT) AS ReceivedAmount
                FROM dbo.Receipt_Dtls rd WITH (NOLOCK)
                INNER JOIN dbo.Receipt_mst rm WITH (NOLOCK)
                    ON rm.Receipt_ID = rd.Receipt_ID
                WHERE
                    ISNUMERIC(rd.InvoiceNo) = 1
                    AND CAST(rd.InvoiceNo AS INT) = bm.Bill_ID
                    AND LTRIM(RTRIM(ISNULL(rm.ReceiptType, N''))) = N'PH'
                    AND ISNULL(rm.CancelStatus, 0) = 0
            ) rec
            WHERE bm.Bill_ID = ?
              AND LTRIM(RTRIM(ISNULL(bm.BillType, N''))) = N'PH'
            ORDER BY dsm.DrugSaleID DESC, bm.Bill_ID DESC;
            """,
            conn,
            params=[bill_id_int],
        )
        if header_df is None or header_df.empty:
            return None

        detail_df = pd.read_sql(
            """
            SET NOCOUNT ON;
            WITH sale_root AS (
                SELECT TOP 1 CAST(dsm.DrugSaleID AS INT) AS DrugSaleID
                FROM dbo.DrugSaleMst dsm WITH (NOLOCK)
                WHERE dsm.BillId = ?
                ORDER BY dsm.DrugSaleID DESC
            )
            SELECT
                  CAST(dsd.DetailID AS INT) AS DetailID
                , CAST(dsd.DrugID AS INT) AS ItemID
                , LTRIM(RTRIM(ISNULL(i.Name, N''))) AS ItemName
                , LTRIM(RTRIM(ISNULL(dsd.Batch, N''))) AS BatchName
                , CAST(ISNULL(dsd.Expiry, '19000101') AS DATE) AS ExpiryDate
                , CAST(ISNULL(dsd.Qty, 0) AS FLOAT) AS Quantity
                , CAST(ISNULL(dsd.Mrp, 0) AS FLOAT) AS MRP
                , CAST(ISNULL(dsd.Rate, 0) AS FLOAT) AS Rate
                , CAST(ISNULL(COALESCE(dsd.TotalAmt, dsd.CurrentSaleAmount, (ISNULL(dsd.Mrp, 0) * ISNULL(dsd.Qty, 0))), 0) AS FLOAT) AS LineTotal
                , CAST(ISNULL(dsd.BatchID, 0) AS INT) AS BatchID
            FROM sale_root sr
            INNER JOIN dbo.DrugSaleDtl dsd WITH (NOLOCK)
                ON dsd.DrugSaleID = sr.DrugSaleID
            INNER JOIN dbo.IVItem i WITH (NOLOCK)
                ON i.ID = dsd.DrugID
            ORDER BY dsd.DetailID;
            """,
            conn,
            params=[bill_id_int],
        )
        header_df.columns = [str(col).strip() for col in header_df.columns]
        detail_df.columns = [str(col).strip() for col in detail_df.columns] if detail_df is not None else []
        header = header_df.iloc[0].to_dict()
        items = []
        if detail_df is not None and not detail_df.empty:
            for row in detail_df.to_dict(orient="records"):
                items.append(
                    {
                        "detail_id": _to_int(row.get("DetailID"), 0) or 0,
                        "item_id": _to_int(row.get("ItemID"), 0) or 0,
                        "item_name": _pharmacy_sale_clean_text(row.get("ItemName")),
                        "batch_name": _pharmacy_sale_clean_text(row.get("BatchName")),
                        "expiry_date": row.get("ExpiryDate"),
                        "quantity": float(row.get("Quantity") or 0),
                        "mrp": float(row.get("MRP") or 0),
                        "rate": float(row.get("Rate") or 0),
                        "line_total": float(row.get("LineTotal") or 0),
                        "batch_id": _to_int(row.get("BatchID"), 0) or 0,
                    }
                )
        return {
            "bill_id": _to_int(header.get("BillID"), 0) or 0,
            "bill_no": _pharmacy_sale_clean_text(header.get("BillNo")),
            "bill_date": header.get("BillDate"),
            "gross_amount": float(header.get("GrossAmount") or 0),
            "discount_amount": float(header.get("DiscountAmount") or 0),
            "net_amount": float(header.get("NetAmount") or 0),
            "due_amount": float(header.get("DueAmount") or 0),
            "discount_percentage": float(header.get("DiscountPercentage") or 0),
            "registration_no": _pharmacy_sale_clean_text(header.get("RegistrationNo")),
            "sharpsight_uhid": _pharmacy_sale_clean_text(header.get("SharpSightUHID")),
            "tmp_patient_id": _to_int(header.get("TmpPatientID"), 0) or 0,
            "visit_id": _to_int(header.get("VisitID"), 0) or 0,
            "visit_no": _pharmacy_sale_clean_text(header.get("VisitNo")),
            "admission_no": _pharmacy_sale_clean_text(header.get("AdmissionNo")),
            "type_of_visit": _pharmacy_sale_clean_text(header.get("TypeOfVisit")),
            "visit_date": header.get("VisitDate"),
            "patient_id": _to_int(header.get("PatientID"), 0) or 0,
            "patient_name": _pharmacy_sale_clean_text(header.get("PatientName")),
            "prescribed_by": _pharmacy_sale_clean_text(header.get("PrescribedBy")),
            "drug_sale_id": _to_int(header.get("DrugSaleID"), 0) or 0,
            "drug_sale_code": _pharmacy_sale_clean_text(header.get("DrugSaleCode")),
            "receipt_count": _to_int(header.get("ReceiptCount"), 0) or 0,
            "received_amount": float(header.get("ReceivedAmount") or 0),
            "generated_by": _pharmacy_sale_clean_text(header.get("GeneratedBy")),
            "remarks": _pharmacy_sale_clean_text(header.get("Remarks")),
            "items": items,
        }
    except Exception as e:
        print(f"Pharmacy sale print payload failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _pharmacy_sale_resolve_report_dates(from_date=None, to_date=None):
    today = datetime.now(tz=LOCAL_TZ).date()
    start_dt = _to_datetime(from_date)
    end_dt = _to_datetime(to_date)
    start_date = start_dt.date() if start_dt else today
    end_date = end_dt.date() if end_dt else today
    if start_date > end_date:
        start_date, end_date = end_date, start_date
    return start_date.isoformat(), end_date.isoformat()


def fetch_pharmacy_sale_report_rows(unit: str, from_date=None, to_date=None, query: str = "", limit: int = 500):
    unit_norm = str(unit or "").strip().upper()
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT:
        print(f"Pharmacy sale reports are only available for {PHARMACY_SALE_ALLOWED_UNIT}")
        return pd.DataFrame()

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy sale report rows: could not connect to {unit_norm}")
        return None

    try:
        start_iso, end_iso = _pharmacy_sale_resolve_report_dates(from_date, to_date)
        query_text = _pharmacy_sale_normalize_search_text(query).lower()
        query_like = f"%{query_text}%"
        query_compact = re.sub(r"[-/\s]", "", query_text)
        query_compact_like = f"%{query_compact}%"
        row_limit = max(1, min(int(limit or 500), 5000))

        sql = """
        SET NOCOUNT ON;

        WITH base_data AS (
            SELECT
                  CAST(bm.Bill_ID AS INT) AS BillID
                , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
                , CAST(bm.BillDate AS DATETIME) AS BillDate
                , CAST(CONVERT(date, bm.BillDate) AS DATE) AS SaleDate
                , CAST(ISNULL(bm.GrossAmount, 0) AS FLOAT) AS GrossAmount
                , CAST(ISNULL(bm.DiscountAmount, 0) AS FLOAT) AS DiscountAmount
                , CAST(ISNULL(bm.NetAmount, 0) AS FLOAT) AS NetAmount
                , CAST(ISNULL(bm.DueAmount, 0) AS FLOAT) AS DueAmount
                , LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))) AS RegistrationNo
                , LTRIM(RTRIM(ISNULL(p.sPatientUHIDNo, N''))) AS SharpSightUHID
                , CAST(ISNULL(bm.TmpPatientId, 0) AS INT) AS TmpPatientID
                , CAST(ISNULL(bm.Visit_ID, 0) AS INT) AS VisitID
                , LTRIM(RTRIM(ISNULL(v.VisitNo, N''))) AS VisitNo
                , LTRIM(RTRIM(ISNULL(v.AdmissionNo, N''))) AS AdmissionNo
                , LTRIM(RTRIM(ISNULL(v.TypeOfVisit, N''))) AS TypeOfVisit
                , CAST(ISNULL(v.VisitDate, bm.BillDate) AS DATETIME) AS VisitDate
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(REPLACE(REPLACE(ISNULL(tp.FirstName, N'') + N' ' + ISNULL(tp.MiddleName, N'') + N' ' + ISNULL(tp.LastName, N''), N'  ', N' '), N'  ', N' '))), N''),
                      CASE
                        WHEN ISNULL(v.PatientID, dsm.PatientID) IS NULL THEN N''
                        ELSE ISNULL(dbo.fn_PatientFullName(ISNULL(v.PatientID, dsm.PatientID)), N'')
                      END,
                      N''
                  ) AS PatientName
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(ISNULL(tp.ExternalReferedBy, N''))), N''),
                      ISNULL(dbo.fn_DoctorFirstName(v.DocInCharge), N''),
                      N''
                  ) AS PrescribedBy
                , CAST(ISNULL(dsm.DrugSaleID, 0) AS INT) AS DrugSaleID
                , LTRIM(RTRIM(ISNULL(dsm.DrugSaleCode, N''))) AS DrugSaleCode
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), bm.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), dsm.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), bm.UpdatedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(80), COALESCE(bm.UpdatedBy, bm.InsertedByUserID, dsm.InsertedByUserID)))), N''),
                      N''
                  ) AS GeneratedBy
                , CAST(ISNULL(rec.ReceiptCount, 0) AS INT) AS ReceiptCount
                , CAST(ISNULL(rec.ReceivedAmount, 0) AS FLOAT) AS ReceivedAmount
                , CAST(rec.LastReceiptDate AS DATETIME) AS LastReceiptDate
                , CAST(ISNULL(agg.LineCount, 0) AS INT) AS LineCount
                , CAST(ISNULL(agg.TotalQty, 0) AS FLOAT) AS TotalQty
                , LTRIM(RTRIM(ISNULL(bm.Remarks, N''))) AS Remarks
            FROM dbo.Billing_Mst bm WITH (NOLOCK)
            OUTER APPLY (
                SELECT TOP 1
                      CAST(dsm.DrugSaleID AS INT) AS DrugSaleID
                    , CAST(ISNULL(dsm.PatientID, 0) AS INT) AS PatientID
                    , LTRIM(RTRIM(ISNULL(dsm.Code, N''))) AS DrugSaleCode
                    , LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), dsm.InsertedMacName), N''))) AS InsertedMacName
                    , dsm.InsertedByUserID
                FROM dbo.DrugSaleMst dsm WITH (NOLOCK)
                WHERE dsm.BillId = bm.Bill_ID
                ORDER BY dsm.DrugSaleID DESC
            ) dsm
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = bm.Visit_ID
            LEFT JOIN dbo.Patient p WITH (NOLOCK)
                ON p.PatientId = ISNULL(v.PatientID, dsm.PatientID)
            LEFT JOIN dbo.TMPPatient tp WITH (NOLOCK)
                ON tp.TmpPatientID = bm.TmpPatientId
            OUTER APPLY (
                SELECT
                      COUNT(1) AS LineCount
                    , CAST(ISNULL(SUM(ISNULL(dsd.Qty, 0)), 0) AS FLOAT) AS TotalQty
                FROM dbo.DrugSaleDtl dsd WITH (NOLOCK)
                WHERE dsd.DrugSaleID = dsm.DrugSaleID
            ) agg
            OUTER APPLY (
                SELECT
                      COUNT(1) AS ReceiptCount
                    , CAST(ISNULL(SUM(ISNULL(rd.Amount, ISNULL(rm.Amount, 0))), 0) AS FLOAT) AS ReceivedAmount
                    , MAX(rm.Receipt_Date) AS LastReceiptDate
                FROM dbo.Receipt_Dtls rd WITH (NOLOCK)
                INNER JOIN dbo.Receipt_mst rm WITH (NOLOCK)
                    ON rm.Receipt_ID = rd.Receipt_ID
                WHERE
                    ISNUMERIC(rd.InvoiceNo) = 1
                    AND CAST(rd.InvoiceNo AS INT) = bm.Bill_ID
                    AND LTRIM(RTRIM(ISNULL(rm.ReceiptType, N''))) = N'PH'
                    AND ISNULL(rm.CancelStatus, 0) = 0
            ) rec
            WHERE
                LTRIM(RTRIM(ISNULL(bm.BillType, N''))) = N'PH'
                AND CONVERT(date, bm.BillDate) BETWEEN CONVERT(date, ?) AND CONVERT(date, ?)
        ),
        filtered AS (
            SELECT *
            FROM base_data
            WHERE
                ? = N''
                OR LOWER(BillNo) LIKE ?
                OR LOWER(RegistrationNo) LIKE ?
                OR LOWER(SharpSightUHID) LIKE ?
                OR LOWER(PatientName) LIKE ?
                OR LOWER(PrescribedBy) LIKE ?
                OR LOWER(VisitNo) LIKE ?
                OR LOWER(AdmissionNo) LIKE ?
                OR LOWER(DrugSaleCode) LIKE ?
                OR LOWER(GeneratedBy) LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(BillNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(RegistrationNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(SharpSightUHID), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(VisitNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(AdmissionNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
        )
        SELECT TOP (?)
              BillID
            , BillNo
            , BillDate
            , SaleDate
            , GrossAmount
            , DiscountAmount
            , NetAmount
            , DueAmount
            , RegistrationNo
            , SharpSightUHID
            , TmpPatientID
            , VisitID
            , VisitNo
            , AdmissionNo
            , TypeOfVisit
            , VisitDate
            , PatientName
            , PrescribedBy
            , DrugSaleID
            , DrugSaleCode
            , GeneratedBy
            , ReceiptCount
            , ReceivedAmount
            , LastReceiptDate
            , LineCount
            , TotalQty
            , Remarks
        FROM filtered
        ORDER BY BillDate DESC, BillID DESC;
        """

        params = [
            start_iso,
            end_iso,
            query_text,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_compact_like,
            query_compact_like,
            query_compact_like,
            query_compact_like,
            query_compact_like,
            row_limit,
        ]
        df = pd.read_sql(sql, conn, params=params)
        if df is None or df.empty:
            return pd.DataFrame(
                columns=[
                    "BillID", "BillNo", "BillDate", "SaleDate", "GrossAmount", "DiscountAmount", "NetAmount", "DueAmount",
                    "RegistrationNo", "SharpSightUHID", "TmpPatientID", "VisitID", "VisitNo", "AdmissionNo", "TypeOfVisit", "VisitDate",
                    "PatientName", "PrescribedBy", "DrugSaleID", "DrugSaleCode", "GeneratedBy", "ReceiptCount", "ReceivedAmount", "LastReceiptDate", "LineCount", "TotalQty", "Remarks",
                ]
            )
        df.columns = [str(col).strip() for col in df.columns]
        return df
    except Exception as e:
        print(f"Pharmacy sale report rows failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_pharmacy_sale_receipt_context(unit: str, bill_id: int):
    unit_norm = str(unit or "").strip().upper()
    bill_id_int = int(bill_id or 0)
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT or bill_id_int <= 0:
        return None

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy receipt context: could not connect to {unit_norm}")
        return None

    try:
        header_df = pd.read_sql(
            """
            SET NOCOUNT ON;
            SELECT TOP 1
                  CAST(bm.Bill_ID AS INT) AS BillID
                , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
                , CAST(bm.BillDate AS DATETIME) AS BillDate
                , CAST(ISNULL(bm.GrossAmount, 0) AS FLOAT) AS GrossAmount
                , CAST(ISNULL(bm.DiscountAmount, 0) AS FLOAT) AS DiscountAmount
                , CAST(ISNULL(bm.NetAmount, 0) AS FLOAT) AS NetAmount
                , CAST(ISNULL(bm.DueAmount, 0) AS FLOAT) AS DueAmount
                , LTRIM(RTRIM(ISNULL(bm.Registration_No, N''))) AS RegistrationNo
                , LTRIM(RTRIM(ISNULL(p.sPatientUHIDNo, N''))) AS SharpSightUHID
                , CAST(ISNULL(bm.TmpPatientId, 0) AS INT) AS TmpPatientID
                , CAST(ISNULL(bm.Visit_ID, 0) AS INT) AS VisitID
                , LTRIM(RTRIM(ISNULL(v.VisitNo, N''))) AS VisitNo
                , LTRIM(RTRIM(ISNULL(v.AdmissionNo, N''))) AS AdmissionNo
                , LTRIM(RTRIM(ISNULL(v.TypeOfVisit, N''))) AS TypeOfVisit
                , CAST(ISNULL(v.VisitDate, bm.BillDate) AS DATETIME) AS VisitDate
                , CAST(ISNULL(v.PatientID, dsm.PatientID) AS INT) AS PatientID
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(REPLACE(REPLACE(ISNULL(tp.FirstName, N'') + N' ' + ISNULL(tp.MiddleName, N'') + N' ' + ISNULL(tp.LastName, N''), N'  ', N' '), N'  ', N' '))), N''),
                      ISNULL(dbo.fn_PatientFullName(ISNULL(v.PatientID, dsm.PatientID)), N''),
                      N''
                  ) AS PatientName
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(ISNULL(tp.ExternalReferedBy, N''))), N''),
                      ISNULL(dbo.fn_DoctorFirstName(v.DocInCharge), N''),
                      N''
                  ) AS PrescribedBy
                , CAST(ISNULL(rec.ReceiptCount, 0) AS INT) AS ReceiptCount
                , CAST(ISNULL(rec.ReceivedAmount, 0) AS FLOAT) AS ReceivedAmount
                , CAST(rec.LastReceiptDate AS DATETIME) AS LastReceiptDate
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), bm.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), dsm.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), bm.UpdatedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(80), COALESCE(bm.UpdatedBy, bm.InsertedByUserID, dsm.InsertedByUserID)))), N''),
                      N''
                  ) AS GeneratedBy
            FROM dbo.Billing_Mst bm WITH (NOLOCK)
            OUTER APPLY (
                SELECT TOP 1
                      CAST(dsm.DrugSaleID AS INT) AS DrugSaleID
                    , CAST(ISNULL(dsm.PatientID, 0) AS INT) AS PatientID
                    , LTRIM(RTRIM(ISNULL(dsm.InsertedMacName, N''))) AS InsertedMacName
                    , dsm.InsertedByUserID
                FROM dbo.DrugSaleMst dsm WITH (NOLOCK)
                WHERE dsm.BillId = bm.Bill_ID
                ORDER BY dsm.DrugSaleID DESC
            ) dsm
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = bm.Visit_ID
            LEFT JOIN dbo.Patient p WITH (NOLOCK)
                ON p.PatientId = ISNULL(v.PatientID, dsm.PatientID)
            LEFT JOIN dbo.TMPPatient tp WITH (NOLOCK)
                ON tp.TmpPatientID = bm.TmpPatientId
            OUTER APPLY (
                SELECT
                      COUNT(1) AS ReceiptCount
                    , CAST(ISNULL(SUM(ISNULL(rd.Amount, ISNULL(rm.Amount, 0))), 0) AS FLOAT) AS ReceivedAmount
                    , MAX(rm.Receipt_Date) AS LastReceiptDate
                FROM dbo.Receipt_Dtls rd WITH (NOLOCK)
                INNER JOIN dbo.Receipt_mst rm WITH (NOLOCK)
                    ON rm.Receipt_ID = rd.Receipt_ID
                WHERE
                    ISNUMERIC(rd.InvoiceNo) = 1
                    AND CAST(rd.InvoiceNo AS INT) = bm.Bill_ID
                    AND LTRIM(RTRIM(ISNULL(rm.ReceiptType, N''))) = N'PH'
                    AND ISNULL(rm.CancelStatus, 0) = 0
            ) rec
            WHERE bm.Bill_ID = ?
              AND LTRIM(RTRIM(ISNULL(bm.BillType, N''))) = N'PH';
            """,
            conn,
            params=[bill_id_int],
        )
        if header_df is None or header_df.empty:
            return None
        header_df.columns = [str(col).strip() for col in header_df.columns]
        header = header_df.iloc[0].to_dict()

        pm_table = _resolve_sharpsight_payment_mode_table_conn(conn)
        pm_join = ""
        pm_name_expr = "LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), rm.PaymentMode), N'')))"
        if pm_table:
            pm_join = f"""
            LEFT JOIN {pm_table} pm WITH (NOLOCK)
                ON CASE
                    WHEN ISNUMERIC(rm.PaymentMode) = 1 THEN CAST(rm.PaymentMode AS INT)
                    ELSE NULL
                   END = pm.PModeId
            """
            pm_name_expr = "LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), pm.PModeName), CONVERT(NVARCHAR(100), rm.PaymentMode))))"

        receipt_sql = f"""
        SET NOCOUNT ON;
        SELECT
              CAST(rm.Receipt_ID AS INT) AS ReceiptID
            , LTRIM(RTRIM(ISNULL(rm.Receipt_No, N''))) AS ReceiptNo
            , CAST(rm.Receipt_Date AS DATETIME) AS ReceiptDate
            , CAST(ISNULL(rd.Amount, ISNULL(rm.Amount, 0)) AS FLOAT) AS Amount
            , {pm_name_expr} AS PaymentModeName
            , LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(50), rm.PaymentMode), N''))) AS PaymentModeID
            , COALESCE(
                  NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), rm.InsertedMacName))), N''),
                  NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), rm.UpdatedMacName))), N''),
                  NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), u_rec.UserName))), N''),
                  NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(80), COALESCE(rm.InsertedByUserID, rm.UpdatedBy)))), N''),
                  N''
              ) AS ReceivedBy
            , LTRIM(RTRIM(ISNULL(rm.Note, N''))) AS ReceiptNote
        FROM dbo.Receipt_Dtls rd WITH (NOLOCK)
        INNER JOIN dbo.Receipt_mst rm WITH (NOLOCK)
            ON rm.Receipt_ID = rd.Receipt_ID
        {pm_join}
        LEFT JOIN dbo.User_Mst u_rec WITH (NOLOCK)
            ON u_rec.UserID = CASE
                WHEN ISNUMERIC(COALESCE(NULLIF(CONVERT(NVARCHAR(50), rm.InsertedByUserID), N''), NULLIF(CONVERT(NVARCHAR(50), rm.UpdatedBy), N''))) = 1
                    THEN CAST(COALESCE(NULLIF(CONVERT(NVARCHAR(50), rm.InsertedByUserID), N''), NULLIF(CONVERT(NVARCHAR(50), rm.UpdatedBy), N'')) AS INT)
                ELSE NULL
               END
        WHERE
            ISNUMERIC(rd.InvoiceNo) = 1
            AND CAST(rd.InvoiceNo AS INT) = ?
            AND LTRIM(RTRIM(ISNULL(rm.ReceiptType, N''))) = N'PH'
            AND ISNULL(rm.CancelStatus, 0) = 0
        ORDER BY rm.Receipt_Date DESC, rm.Receipt_ID DESC;
        """
        receipt_df = pd.read_sql(receipt_sql, conn, params=[bill_id_int])
        if receipt_df is not None and not receipt_df.empty:
            receipt_df.columns = [str(col).strip() for col in receipt_df.columns]

        tmp_patient_id = _to_int(header.get("TmpPatientID"), 0) or 0
        receipt_rows = []
        if receipt_df is not None and not receipt_df.empty:
            for row in receipt_df.to_dict(orient="records"):
                receipt_rows.append(
                    {
                        "receipt_id": _to_int(row.get("ReceiptID"), 0) or 0,
                        "receipt_no": _pharmacy_sale_clean_text(row.get("ReceiptNo")),
                        "receipt_date": row.get("ReceiptDate"),
                        "amount": float(row.get("Amount") or 0),
                        "payment_mode_id": _to_int(row.get("PaymentModeID"), 0) or 0,
                        "payment_mode_name": _pharmacy_sale_clean_text(row.get("PaymentModeName")),
                        "received_by": _pharmacy_sale_clean_text(row.get("ReceivedBy")),
                        "receipt_note": _pharmacy_sale_clean_text(row.get("ReceiptNote")),
                    }
                )

        return {
            "bill_id": bill_id_int,
            "bill_no": _pharmacy_sale_clean_text(header.get("BillNo")),
            "bill_date": header.get("BillDate"),
            "gross_amount": float(header.get("GrossAmount") or 0),
            "discount_amount": float(header.get("DiscountAmount") or 0),
            "net_amount": float(header.get("NetAmount") or 0),
            "due_amount": float(header.get("DueAmount") or 0),
            "received_amount": float(header.get("ReceivedAmount") or 0),
            "receipt_count": _to_int(header.get("ReceiptCount"), 0) or 0,
            "last_receipt_date": header.get("LastReceiptDate"),
            "registration_no": _pharmacy_sale_clean_text(header.get("RegistrationNo")),
            "sharpsight_uhid": _pharmacy_sale_clean_text(header.get("SharpSightUHID")),
            "tmp_patient_id": tmp_patient_id,
            "visit_id": _to_int(header.get("VisitID"), 0) or 0,
            "visit_no": _pharmacy_sale_clean_text(header.get("VisitNo")),
            "admission_no": _pharmacy_sale_clean_text(header.get("AdmissionNo")),
            "type_of_visit": _pharmacy_sale_clean_text(header.get("TypeOfVisit")),
            "visit_date": header.get("VisitDate"),
            "patient_id": _to_int(header.get("PatientID"), 0) or 0,
            "patient_name": _pharmacy_sale_clean_text(header.get("PatientName")),
            "prescribed_by": _pharmacy_sale_clean_text(header.get("PrescribedBy")),
            "generated_by": _pharmacy_sale_clean_text(header.get("GeneratedBy")),
            "is_walkin": tmp_patient_id > 0,
            "receipt_allowed": _pharmacy_sale_receipt_allowed(header.get("TypeOfVisit"), tmp_patient_id),
            "receipts": receipt_rows,
        }
    except Exception as e:
        print(f"Pharmacy receipt context failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def record_pharmacy_sale_receipt(
    unit: str,
    *,
    bill_id: int,
    amount,
    payment_mode_id: int,
    receipt_date=None,
    note: str = "",
    actor_user_id: int = 0,
    actor_username: str = "",
    actor_ip: str = "",
    inserted_mac_name: str = "",
    inserted_mac_id: str = "",
    lock_timeout_ms: int = 15000,
):
    unit_norm = str(unit or "").strip().upper()
    bill_id_int = int(bill_id or 0)
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT:
        return {"status": "error", "message": f"Pharmacy receipts are only available for {PHARMACY_SALE_ALLOWED_UNIT}."}
    if bill_id_int <= 0:
        return {"status": "error", "message": "A valid bill is required to receive payment."}

    received_amount = _pharmacy_sale_round_money(amount)
    if received_amount <= 0:
        return {"status": "error", "message": "Enter a valid receipt amount greater than zero."}
    payment_mode_int = int(payment_mode_id or 0)
    if payment_mode_int <= 0:
        return {"status": "error", "message": "Select a payment mode before saving the receipt."}

    conn = get_sql_connection(unit_norm)
    if not conn:
        return {"status": "error", "message": f"Could not connect to {unit_norm} for pharmacy receipt."}

    cursor = None
    lock_resource = f"PHARMACY_SALE_SAVE_{unit_norm}_STORE_{PHARMACY_SALE_STORE_ID}"
    receipt_dt = _pharmacy_sale_parse_sale_datetime(receipt_date)
    receipt_dt_str = receipt_dt.strftime("%Y-%m-%d %H:%M:%S")
    actor_user_id = int(actor_user_id or 0)
    actor_username = _pharmacy_sale_clean_text(actor_username) or (str(actor_user_id) if actor_user_id > 0 else "web")
    actor_ip = _pharmacy_sale_clean_text(actor_ip)
    inserted_mac_name = _pharmacy_sale_clean_text(inserted_mac_name) or actor_username
    inserted_mac_id = _pharmacy_sale_clean_text(inserted_mac_id)

    try:
        try:
            conn.autocommit = False
        except Exception:
            pass

        cursor = conn.cursor()
        lock_result = _get_app_lock(cursor, lock_resource, lock_timeout_ms)
        if lock_result.get("error"):
            return {"status": "error", "message": lock_result.get("error")}

        cursor.execute(
            """
            SELECT TOP 1
                  CAST(bm.Bill_ID AS INT) AS BillID
                , LTRIM(RTRIM(ISNULL(bm.BillNo, N''))) AS BillNo
                , CAST(ISNULL(bm.NetAmount, 0) AS DECIMAL(18, 2)) AS NetAmount
                , CAST(ISNULL(bm.DueAmount, 0) AS DECIMAL(18, 2)) AS DueAmount
                , CAST(ISNULL(bm.Visit_ID, 0) AS INT) AS VisitID
                , CAST(ISNULL(bm.TmpPatientId, 0) AS INT) AS TmpPatientID
                , CAST(ISNULL(v.PatientID, dsm.PatientID) AS INT) AS PatientID
                , LTRIM(RTRIM(ISNULL(v.TypeOfVisit, N''))) AS TypeOfVisit
            FROM dbo.Billing_Mst bm WITH (UPDLOCK, HOLDLOCK)
            OUTER APPLY (
                SELECT TOP 1
                      CAST(ISNULL(dsm.PatientID, 0) AS INT) AS PatientID
                FROM dbo.DrugSaleMst dsm WITH (NOLOCK)
                WHERE dsm.BillId = bm.Bill_ID
                ORDER BY dsm.DrugSaleID DESC
            ) dsm
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = bm.Visit_ID
            WHERE bm.Bill_ID = ?
              AND LTRIM(RTRIM(ISNULL(bm.BillType, N''))) = N'PH';
            """,
            (bill_id_int,),
        )
        bill_rows = _rows_as_dicts(cursor) if cursor.description is not None else []
        if not bill_rows:
            raise RuntimeError("Pharmacy bill was not found for receipt entry.")
        bill_row = bill_rows[0]
        tmp_patient_id = int(_to_int(bill_row.get("TmpPatientID"), 0) or 0)
        if not _pharmacy_sale_receipt_allowed(bill_row.get("TypeOfVisit"), tmp_patient_id):
            raise RuntimeError("Receipts are enabled only for OPD / DPV pharmacy bills and self walk-in bills.")

        current_due = _pharmacy_sale_round_money(bill_row.get("DueAmount"))
        if current_due <= 0:
            raise RuntimeError("This bill has no pending due amount left.")
        if received_amount > current_due:
            raise RuntimeError(f"Received amount cannot exceed the pending due amount of {current_due}.")

        payment_row = _pharmacy_sale_get_payment_mode_row(cursor, conn, payment_mode_int)
        if not payment_row:
            raise RuntimeError("Selected payment mode is no longer active.")

        receipt_info = _pharmacy_sale_insert_receipt(
            cursor,
            bill_id=bill_id_int,
            bill_no=_pharmacy_sale_clean_text(bill_row.get("BillNo")),
            patient_id=int(_to_int(bill_row.get("PatientID"), 0) or 0),
            visit_id=int(_to_int(bill_row.get("VisitID"), 0) or 0),
            tmp_patient_id=tmp_patient_id,
            received_amount=received_amount,
            payment_mode_id=payment_mode_int,
            receipt_dt_str=receipt_dt_str,
            actor_user_id=actor_user_id,
            actor_ip=actor_ip,
            inserted_mac_name=inserted_mac_name,
            inserted_mac_id=inserted_mac_id,
            note_text=note,
        )

        new_due = (current_due - received_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        if new_due < 0:
            new_due = Decimal("0.00")
        cursor.execute(
            """
            UPDATE dbo.Billing_Mst
            SET DueAmount = ?, UpdatedBy = ?, UpdatedOn = ?, UpdatedMacName = ?, UpdatedMacID = ?, UpdatedIPAddress = ?
            WHERE Bill_ID = ?
            """,
            (
                float(new_due),
                actor_user_id if actor_user_id > 0 else 0,
                receipt_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                bill_id_int,
            ),
        )

        conn.commit()
        receipt_info.update(
            {
                "status": "success",
                "bill_id": bill_id_int,
                "bill_no": _pharmacy_sale_clean_text(bill_row.get("BillNo")),
                "payment_mode_id": payment_mode_int,
                "payment_mode_name": _pharmacy_sale_clean_text(payment_row.get("PaymentModeName")),
                "due_amount": float(new_due),
            }
        )
        return receipt_info
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": str(e)}
    finally:
        if cursor is not None:
            try:
                _release_app_lock(cursor, lock_resource)
            except Exception:
                pass
        try:
            conn.close()
        except Exception:
            pass


def fetch_pharmacy_issue_print_payload(unit: str, issue_id: int):
    unit_norm = str(unit or "").strip().upper()
    issue_id_int = int(issue_id or 0)
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT or issue_id_int <= 0:
        return None

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy issue print payload: could not connect to {unit_norm}")
        return None

    try:
        header_df = pd.read_sql(
            """
            SET NOCOUNT ON;
            SELECT TOP 1
                  CAST(im.IssueId AS INT) AS IssueID
                , LTRIM(RTRIM(ISNULL(im.IssueNo, N''))) AS IssueNo
                , CAST(im.IssueDate AS DATETIME) AS IssueDate
                , CAST(ISNULL(im.TotalAmount, 0) AS FLOAT) AS GrossAmount
                , CAST(ISNULL(COALESCE(im.Amount, im.dueamount, im.TotalAmount), 0) AS FLOAT) AS NetAmount
                , CAST(ISNULL(COALESCE(im.dueamount, im.Amount, im.TotalAmount), 0) AS FLOAT) AS DueAmount
                , CAST(
                    CASE
                        WHEN ISNULL(im.TotalAmount, 0) > ISNULL(COALESCE(im.Amount, im.dueamount, im.TotalAmount), 0)
                            THEN ISNULL(im.TotalAmount, 0) - ISNULL(COALESCE(im.Amount, im.dueamount, im.TotalAmount), 0)
                        ELSE 0
                    END
                    AS FLOAT
                  ) AS DiscountAmount
                , LTRIM(RTRIM(ISNULL(p.Registration_No, N''))) AS RegistrationNo
                , LTRIM(RTRIM(ISNULL(p.sPatientUHIDNo, N''))) AS SharpSightUHID
                , CAST(ISNULL(im.VisitId, 0) AS INT) AS VisitID
                , LTRIM(RTRIM(ISNULL(v.VisitNo, N''))) AS VisitNo
                , LTRIM(RTRIM(ISNULL(v.AdmissionNo, N''))) AS AdmissionNo
                , ISNULL(v.TypeOfVisit, N'') AS TypeOfVisit
                , CAST(ISNULL(v.VisitDate, im.IssueDate) AS DATETIME) AS VisitDate
                , CAST(ISNULL(im.Patientid, v.PatientID) AS INT) AS PatientID
                , ISNULL(dbo.fn_PatientFullName(ISNULL(im.Patientid, v.PatientID)), N'') AS PatientName
                , ISNULL(dbo.fn_DoctorFirstName(v.DocInCharge), N'') AS PrescribedBy
                , CAST(ISNULL(im.OrderId, 0) AS INT) AS OrderID
                , LTRIM(RTRIM(ISNULL(om.OrdNo, N''))) AS OrderNo
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), im.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), im.UpdatedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), u_gen.UserName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(80), COALESCE(im.UpdatedBy, im.InsertedByUserID)))), N''),
                      N''
                  ) AS GeneratedBy
            FROM dbo.IvPatientIssueMst im WITH (NOLOCK)
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = im.VisitId
            LEFT JOIN dbo.Patient p WITH (NOLOCK)
                ON p.PatientId = ISNULL(im.Patientid, v.PatientID)
            LEFT JOIN dbo.OrderMst om WITH (NOLOCK)
                ON om.OrdId = im.OrderId
            LEFT JOIN dbo.User_Mst u_gen WITH (NOLOCK)
                ON u_gen.UserID = CASE
                    WHEN ISNUMERIC(COALESCE(NULLIF(CONVERT(NVARCHAR(50), im.InsertedByUserID), N''), NULLIF(CONVERT(NVARCHAR(50), im.UpdatedBy), N''))) = 1
                        THEN CAST(COALESCE(NULLIF(CONVERT(NVARCHAR(50), im.InsertedByUserID), N''), NULLIF(CONVERT(NVARCHAR(50), im.UpdatedBy), N'')) AS INT)
                    ELSE NULL
                  END
            WHERE im.IssueId = ?
            ORDER BY im.IssueId DESC;
            """,
            conn,
            params=[issue_id_int],
        )
        if header_df is None or header_df.empty:
            return None

        detail_df = pd.read_sql(
            """
            SET NOCOUNT ON;
            SELECT
                  CAST(d.IssueDtlId AS INT) AS DetailID
                , CAST(d.ItemId AS INT) AS ItemID
                , LTRIM(RTRIM(ISNULL(i.Name, N''))) AS ItemName
                , LTRIM(RTRIM(ISNULL(b.Name, N''))) AS BatchName
                , CAST(ISNULL(b.ExpiryDate, '19000101') AS DATE) AS ExpiryDate
                , CAST(ISNULL(d.Issueqty, 0) AS FLOAT) AS Quantity
                , CAST(ISNULL(d.Mrp, 0) AS FLOAT) AS MRP
                , CAST(ISNULL(d.Rate, 0) AS FLOAT) AS Rate
                , CAST(ISNULL(d.Amount, ISNULL(d.Issueqty, 0) * ISNULL(d.Mrp, 0)) AS FLOAT) AS LineTotal
                , CAST(ISNULL(d.BatchId, 0) AS INT) AS BatchID
            FROM dbo.IvPatientIssueDtl d WITH (NOLOCK)
            INNER JOIN dbo.IVItem i WITH (NOLOCK)
                ON i.ID = d.ItemId
            LEFT JOIN dbo.IVBatch b WITH (NOLOCK)
                ON b.ID = d.BatchId
            WHERE d.Issueid = ?
            ORDER BY d.IssueDtlId;
            """,
            conn,
            params=[issue_id_int],
        )
        header_df.columns = [str(col).strip() for col in header_df.columns]
        detail_df.columns = [str(col).strip() for col in detail_df.columns] if detail_df is not None else []
        header = header_df.iloc[0].to_dict()
        items = []
        if detail_df is not None and not detail_df.empty:
            for row in detail_df.to_dict(orient="records"):
                items.append(
                    {
                        "detail_id": _to_int(row.get("DetailID"), 0) or 0,
                        "item_id": _to_int(row.get("ItemID"), 0) or 0,
                        "item_name": _pharmacy_sale_clean_text(row.get("ItemName")),
                        "batch_name": _pharmacy_sale_clean_text(row.get("BatchName")),
                        "expiry_date": row.get("ExpiryDate"),
                        "quantity": float(row.get("Quantity") or 0),
                        "mrp": float(row.get("MRP") or 0),
                        "rate": float(row.get("Rate") or 0),
                        "line_total": float(row.get("LineTotal") or 0),
                        "batch_id": _to_int(row.get("BatchID"), 0) or 0,
                    }
                )
        gross_amount = float(header.get("GrossAmount") or 0)
        discount_amount = float(header.get("DiscountAmount") or 0)
        net_amount = float(header.get("NetAmount") or 0)
        due_amount = float(header.get("DueAmount") or 0)
        return {
            "issue_id": _to_int(header.get("IssueID"), 0) or 0,
            "issue_no": _pharmacy_sale_clean_text(header.get("IssueNo")),
            "issue_date": header.get("IssueDate"),
            "bill_date": header.get("IssueDate"),
            "gross_amount": gross_amount,
            "discount_amount": discount_amount,
            "net_amount": net_amount,
            "due_amount": due_amount,
            "registration_no": _pharmacy_sale_clean_text(header.get("RegistrationNo")),
            "sharpsight_uhid": _pharmacy_sale_clean_text(header.get("SharpSightUHID")),
            "visit_id": _to_int(header.get("VisitID"), 0) or 0,
            "visit_no": _pharmacy_sale_clean_text(header.get("VisitNo")),
            "admission_no": _pharmacy_sale_clean_text(header.get("AdmissionNo")),
            "type_of_visit": _pharmacy_sale_clean_text(header.get("TypeOfVisit")),
            "visit_date": header.get("VisitDate"),
            "patient_id": _to_int(header.get("PatientID"), 0) or 0,
            "patient_name": _pharmacy_sale_clean_text(header.get("PatientName")),
            "prescribed_by": _pharmacy_sale_clean_text(header.get("PrescribedBy")),
            "order_id": _to_int(header.get("OrderID"), 0) or 0,
            "order_no": _pharmacy_sale_clean_text(header.get("OrderNo")),
            "generated_by": _pharmacy_sale_clean_text(header.get("GeneratedBy")),
            "remarks": "",
            "items": items,
        }
    except Exception as e:
        print(f"Pharmacy issue print payload failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_pharmacy_issue_report_rows(unit: str, from_date=None, to_date=None, query: str = "", limit: int = 500):
    unit_norm = str(unit or "").strip().upper()
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT:
        print(f"Pharmacy issue reports are only available for {PHARMACY_SALE_ALLOWED_UNIT}")
        return pd.DataFrame()

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Pharmacy issue report rows: could not connect to {unit_norm}")
        return None

    try:
        start_iso, end_iso = _pharmacy_sale_resolve_report_dates(from_date, to_date)
        query_text = _pharmacy_sale_normalize_search_text(query).lower()
        query_like = f"%{query_text}%"
        query_compact = re.sub(r"[-/\s]", "", query_text)
        query_compact_like = f"%{query_compact}%"
        row_limit = max(1, min(int(limit or 500), 5000))

        sql = """
        SET NOCOUNT ON;

        WITH base_data AS (
            SELECT
                  CAST(im.IssueId AS INT) AS IssueID
                , LTRIM(RTRIM(ISNULL(im.IssueNo, N''))) AS IssueNo
                , CAST(im.IssueDate AS DATETIME) AS IssueDate
                , CAST(CONVERT(date, im.IssueDate) AS DATE) AS IssueSaleDate
                , CAST(ISNULL(im.TotalAmount, 0) AS FLOAT) AS GrossAmount
                , CAST(
                    CASE
                        WHEN ISNULL(im.TotalAmount, 0) > ISNULL(COALESCE(im.Amount, im.dueamount, im.TotalAmount), 0)
                            THEN ISNULL(im.TotalAmount, 0) - ISNULL(COALESCE(im.Amount, im.dueamount, im.TotalAmount), 0)
                        ELSE 0
                    END
                    AS FLOAT
                  ) AS DiscountAmount
                , CAST(ISNULL(COALESCE(im.Amount, im.dueamount, im.TotalAmount), 0) AS FLOAT) AS NetAmount
                , CAST(ISNULL(COALESCE(im.dueamount, im.Amount, im.TotalAmount), 0) AS FLOAT) AS DueAmount
                , LTRIM(RTRIM(ISNULL(p.Registration_No, N''))) AS RegistrationNo
                , LTRIM(RTRIM(ISNULL(p.sPatientUHIDNo, N''))) AS SharpSightUHID
                , CAST(ISNULL(im.VisitId, 0) AS INT) AS VisitID
                , LTRIM(RTRIM(ISNULL(v.VisitNo, N''))) AS VisitNo
                , LTRIM(RTRIM(ISNULL(v.AdmissionNo, N''))) AS AdmissionNo
                , LTRIM(RTRIM(ISNULL(v.TypeOfVisit, N''))) AS TypeOfVisit
                , CAST(ISNULL(v.VisitDate, im.IssueDate) AS DATETIME) AS VisitDate
                , ISNULL(dbo.fn_PatientFullName(ISNULL(im.Patientid, v.PatientID)), N'') AS PatientName
                , ISNULL(dbo.fn_DoctorFirstName(v.DocInCharge), N'') AS PrescribedBy
                , CAST(ISNULL(im.OrderId, 0) AS INT) AS OrderID
                , LTRIM(RTRIM(ISNULL(om.OrdNo, N''))) AS OrderNo
                , COALESCE(
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), im.InsertedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), im.UpdatedMacName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), u_gen.UserName))), N''),
                      NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(80), COALESCE(im.UpdatedBy, im.InsertedByUserID)))), N''),
                      N''
                  ) AS GeneratedBy
                , CAST(ISNULL(agg.LineCount, 0) AS INT) AS LineCount
                , CAST(ISNULL(agg.TotalQty, 0) AS FLOAT) AS TotalQty
            FROM dbo.IvPatientIssueMst im WITH (NOLOCK)
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = im.VisitId
            LEFT JOIN dbo.Patient p WITH (NOLOCK)
                ON p.PatientId = ISNULL(im.Patientid, v.PatientID)
            LEFT JOIN dbo.OrderMst om WITH (NOLOCK)
                ON om.OrdId = im.OrderId
            LEFT JOIN dbo.User_Mst u_gen WITH (NOLOCK)
                ON u_gen.UserID = CASE
                    WHEN ISNUMERIC(COALESCE(NULLIF(CONVERT(NVARCHAR(50), im.InsertedByUserID), N''), NULLIF(CONVERT(NVARCHAR(50), im.UpdatedBy), N''))) = 1
                        THEN CAST(COALESCE(NULLIF(CONVERT(NVARCHAR(50), im.InsertedByUserID), N''), NULLIF(CONVERT(NVARCHAR(50), im.UpdatedBy), N'')) AS INT)
                    ELSE NULL
                  END
            OUTER APPLY (
                SELECT
                      COUNT(1) AS LineCount
                    , CAST(ISNULL(SUM(ISNULL(d.Issueqty, 0)), 0) AS FLOAT) AS TotalQty
                FROM dbo.IvPatientIssueDtl d WITH (NOLOCK)
                WHERE d.Issueid = im.IssueId
            ) agg
            WHERE CONVERT(date, im.IssueDate) BETWEEN CONVERT(date, ?) AND CONVERT(date, ?)
        ),
        filtered AS (
            SELECT *
            FROM base_data
            WHERE
                ? = N''
                OR LOWER(IssueNo) LIKE ?
                OR LOWER(OrderNo) LIKE ?
                OR LOWER(RegistrationNo) LIKE ?
                OR LOWER(SharpSightUHID) LIKE ?
                OR LOWER(PatientName) LIKE ?
                OR LOWER(VisitNo) LIKE ?
                OR LOWER(AdmissionNo) LIKE ?
                OR LOWER(GeneratedBy) LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(IssueNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(OrderNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(RegistrationNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(SharpSightUHID), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(VisitNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
                OR REPLACE(REPLACE(REPLACE(LOWER(AdmissionNo), N'-', N''), N'/', N''), N' ', N'') LIKE ?
        )
        SELECT TOP (?)
              IssueID
            , IssueNo
            , IssueDate
            , IssueSaleDate
            , GrossAmount
            , DiscountAmount
            , NetAmount
            , DueAmount
            , RegistrationNo
            , SharpSightUHID
            , VisitID
            , VisitNo
            , AdmissionNo
            , TypeOfVisit
            , VisitDate
            , PatientName
            , PrescribedBy
            , OrderID
            , OrderNo
            , GeneratedBy
            , LineCount
            , TotalQty
        FROM filtered
        ORDER BY IssueDate DESC, IssueID DESC;
        """

        params = [
            start_iso,
            end_iso,
            query_text,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_like,
            query_compact_like,
            query_compact_like,
            query_compact_like,
            query_compact_like,
            query_compact_like,
            query_compact_like,
            row_limit,
        ]
        df = pd.read_sql(sql, conn, params=params)
        if df is None or df.empty:
            return pd.DataFrame(
                columns=[
                    "IssueID", "IssueNo", "IssueDate", "IssueSaleDate", "GrossAmount", "DiscountAmount", "NetAmount", "DueAmount",
                    "RegistrationNo", "SharpSightUHID", "VisitID", "VisitNo", "AdmissionNo", "TypeOfVisit", "VisitDate",
                    "PatientName", "PrescribedBy", "OrderID", "OrderNo", "GeneratedBy", "LineCount", "TotalQty",
                ]
            )
        df.columns = [str(col).strip() for col in df.columns]
        return df
    except Exception as e:
        print(f"Pharmacy issue report rows failed for {unit_norm}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _pharmacy_sale_next_manual_id(cursor, table_name: str, column_name: str) -> int:
    cursor.execute(
        f"SELECT CAST(ISNULL(MAX([{column_name}]), 0) + 1 AS INT) FROM {table_name} WITH (UPDLOCK, HOLDLOCK, TABLOCKX)"
    )
    row = _cursor_fetchone_safe(cursor)
    return int(row[0]) if row and row[0] is not None else 1


def _pharmacy_sale_next_order_number(cursor, sale_dt) -> str:
    date_value = sale_dt.date() if isinstance(sale_dt, datetime) else _to_datetime(sale_dt).date()
    date_fragment = date_value.strftime("%d%m%y")
    cursor.execute(
        """
        SELECT CAST(
            ISNULL(
                MAX(
                    CASE
                        WHEN ISNUMERIC(PARSENAME(REPLACE(LTRIM(RTRIM(ISNULL(OrdNo, N''))), N'/', N'.'), 1)) = 1
                            THEN CAST(PARSENAME(REPLACE(LTRIM(RTRIM(ISNULL(OrdNo, N''))), N'/', N'.'), 1) AS INT)
                        ELSE 0
                    END
                ),
                0
            ) + 1
            AS INT
        )
        FROM dbo.OrderMst WITH (UPDLOCK, HOLDLOCK, TABLOCKX)
        WHERE CONVERT(date, OrdDateTime) = ?
          AND LTRIM(RTRIM(ISNULL(OrdNo, N''))) LIKE ?;
        """,
        (date_value.isoformat(), f"ORD/{date_fragment}/%"),
    )
    row = _cursor_fetchone_safe(cursor)
    next_seq = int(row[0]) if row and row[0] is not None else 1
    return f"ORD/{date_fragment}/{next_seq}"


def _pharmacy_sale_next_receipt_number(receipt_id: int) -> str:
    return f"REC-{int(receipt_id or 0)}"


def _pharmacy_sale_insert_tmp_patient(
    cursor,
    *,
    patient_name: str,
    prescribed_by: str,
    sale_dt_str: str,
    actor_user_id: int,
    actor_ip: str,
    inserted_mac_name: str,
    inserted_mac_id: str,
) -> int:
    tmp_patient_id = _pharmacy_sale_next_manual_id(cursor, "dbo.TMPPatient", "TmpPatientID")
    first_name, middle_name, last_name = _pharmacy_sale_split_tmp_patient_name(patient_name)
    cursor.execute(
        """
        INSERT INTO dbo.TMPPatient (
            TmpPatientID, FirstName, MiddleName, LastName, Age, InternalReferedBy, ExternalReferedBy,
            PatientType, Gender, CODE, IssueDate, UpdatedBy, UpdatedON, UpdatedMacName, UpdatedMacID,
            UpdatedIPAddress, InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            int(tmp_patient_id),
            first_name,
            middle_name,
            last_name,
            0.0,
            0,
            _pharmacy_sale_clean_text(prescribed_by)[:50],
            "",
            "",
            "",
            sale_dt_str,
            actor_user_id if actor_user_id > 0 else 0,
            sale_dt_str,
            inserted_mac_name,
            inserted_mac_id,
            actor_ip,
            str(actor_user_id) if actor_user_id > 0 else "",
            sale_dt_str,
            inserted_mac_name,
            inserted_mac_id,
            actor_ip,
        ),
    )
    return int(tmp_patient_id)


def _pharmacy_sale_insert_receipt(
    cursor,
    *,
    bill_id: int,
    bill_no: str,
    patient_id: int,
    visit_id: int,
    tmp_patient_id: int,
    received_amount: Decimal,
    payment_mode_id: int,
    receipt_dt_str: str,
    actor_user_id: int,
    actor_ip: str,
    inserted_mac_name: str,
    inserted_mac_id: str,
    note_text: str = "",
):
    actor_id_text = str(actor_user_id) if actor_user_id > 0 else "0"
    note_value = _pharmacy_sale_clean_text(note_text)[:255] or f"Pharmacy receipt against {bill_no or ('bill ' + str(bill_id))}"
    cursor.execute("SELECT COLUMNPROPERTY(OBJECT_ID('dbo.Receipt_mst'), 'Receipt_ID', 'IsIdentity')")
    mst_identity_row = cursor.fetchone()
    mst_id_is_identity = bool(mst_identity_row and mst_identity_row[0] == 1)
    receipt_id = 0

    if mst_id_is_identity:
        cursor.execute(
            """
            DECLARE @new_receipt TABLE (ReceiptID INT);
            INSERT INTO dbo.Receipt_mst (
                Receipt_No, PatientID, Visit_ID, Amount, Receipt_Date, Receipt_Time, Note,
                PaymentAgainst, PaymentMode, UpdatedOn, UpdatedBy, ReceiptType, TmpPatientId, CancelStatus,
                UpdatedMacName, UpdatedMacID, UpdatedIPAddress, InsertedByUserID, InsertedON, InsertedMacName,
                InsertedMacID, InsertedIPAddress
            )
            OUTPUT INSERTED.Receipt_ID INTO @new_receipt(ReceiptID)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            SELECT TOP 1 ReceiptID FROM @new_receipt;
            """,
            (
                "",
                int(patient_id or 0),
                int(visit_id or 0),
                float(received_amount),
                receipt_dt_str,
                receipt_dt_str,
                note_value,
                "3",
                str(int(payment_mode_id or 0)),
                receipt_dt_str,
                actor_id_text,
                "PH",
                int(tmp_patient_id or 0),
                0,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                actor_id_text,
                receipt_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
            ),
        )
        receipt_id_row = _cursor_fetchone_safe(cursor)
        receipt_id = int(receipt_id_row[0]) if receipt_id_row and receipt_id_row[0] is not None else 0
        if receipt_id <= 0:
            raise RuntimeError("Receipt save did not return a valid receipt ID.")
        receipt_no = _pharmacy_sale_next_receipt_number(receipt_id)
        cursor.execute(
            """
            UPDATE dbo.Receipt_mst
            SET Receipt_No = ?
            WHERE Receipt_ID = ?
            """,
            (receipt_no, int(receipt_id)),
        )
    else:
        receipt_id = _pharmacy_sale_next_manual_id(cursor, "dbo.Receipt_mst", "Receipt_ID")
        receipt_no = _pharmacy_sale_next_receipt_number(receipt_id)
        cursor.execute(
            """
            INSERT INTO dbo.Receipt_mst (
                Receipt_ID, Receipt_No, PatientID, Visit_ID, Amount, Receipt_Date, Receipt_Time, Note,
                PaymentAgainst, PaymentMode, UpdatedOn, UpdatedBy, ReceiptType, TmpPatientId, CancelStatus,
                UpdatedMacName, UpdatedMacID, UpdatedIPAddress, InsertedByUserID, InsertedON, InsertedMacName,
                InsertedMacID, InsertedIPAddress
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                int(receipt_id),
                receipt_no,
                int(patient_id or 0),
                int(visit_id or 0),
                float(received_amount),
                receipt_dt_str,
                receipt_dt_str,
                note_value,
                "3",
                str(int(payment_mode_id or 0)),
                receipt_dt_str,
                actor_id_text,
                "PH",
                int(tmp_patient_id or 0),
                0,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                actor_id_text,
                receipt_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
            ),
        )

    cursor.execute("SELECT COLUMNPROPERTY(OBJECT_ID('dbo.Receipt_Dtls'), 'Receipt_Dtl_ID', 'IsIdentity')")
    dtl_identity_row = cursor.fetchone()
    dtl_id_is_identity = bool(dtl_identity_row and dtl_identity_row[0] == 1)
    receipt_dtl_id = 0

    if dtl_id_is_identity:
        cursor.execute(
            """
            DECLARE @new_receipt_dtl TABLE (ReceiptDtlID INT);
            INSERT INTO dbo.Receipt_Dtls (
                Receipt_ID, Amount, InvoiceNo, UpdatedBy, UpdatedON, UpdatedMacName, UpdatedMacID,
                UpdatedIPAddress, InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress
            )
            OUTPUT INSERTED.Receipt_Dtl_ID INTO @new_receipt_dtl(ReceiptDtlID)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            SELECT TOP 1 ReceiptDtlID FROM @new_receipt_dtl;
            """,
            (
                int(receipt_id),
                float(received_amount),
                str(int(bill_id or 0)),
                actor_user_id if actor_user_id > 0 else 0,
                receipt_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                actor_id_text,
                receipt_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
            ),
        )
        receipt_dtl_id_row = _cursor_fetchone_safe(cursor)
        receipt_dtl_id = int(receipt_dtl_id_row[0]) if receipt_dtl_id_row and receipt_dtl_id_row[0] is not None else 0
    else:
        receipt_dtl_id = _pharmacy_sale_next_manual_id(cursor, "dbo.Receipt_Dtls", "Receipt_Dtl_ID")
        cursor.execute(
            """
            INSERT INTO dbo.Receipt_Dtls (
                Receipt_Dtl_ID, Receipt_ID, Amount, InvoiceNo, UpdatedBy, UpdatedON, UpdatedMacName, UpdatedMacID,
                UpdatedIPAddress, InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                int(receipt_dtl_id),
                int(receipt_id),
                float(received_amount),
                str(int(bill_id or 0)),
                actor_user_id if actor_user_id > 0 else 0,
                receipt_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                actor_id_text,
                receipt_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
            ),
        )

    return {
        "receipt_id": int(receipt_id),
        "receipt_detail_id": int(receipt_dtl_id),
        "receipt_no": receipt_no,
        "received_amount": float(received_amount),
    }


def _pharmacy_sale_get_payment_mode_row(cursor, conn, payment_mode_id: int) -> dict | None:
    payment_mode_int = int(payment_mode_id or 0)
    if cursor is None or conn is None or payment_mode_int <= 0:
        return None

    pm_table = _resolve_sharpsight_payment_mode_table_conn(conn) or "dbo.Paymentmode_mst"
    cursor.execute(
        f"""
        SELECT TOP 1
              CAST(pm.PModeId AS INT) AS PaymentModeID
            , LTRIM(RTRIM(ISNULL(pm.PModeName, N''))) AS PaymentModeName
        FROM {pm_table} pm WITH (NOLOCK)
        WHERE pm.PModeId = ?
          AND ISNULL(pm.Deactive, 0) = 0;
        """,
        (payment_mode_int,),
    )
    rows = _rows_as_dicts(cursor) if cursor.description is not None else []
    return rows[0] if rows else None


def _save_pharmacy_issue_without_billing(
    *,
    conn,
    cursor,
    visit_row: dict,
    visit_id: int,
    sale_dt,
    sale_dt_str: str,
    validated_lines: list[dict],
    gross_total: Decimal,
    discount_total: Decimal,
    rounded_net: Decimal,
    actor_user_id: int,
    actor_username: str,
    actor_ip: str,
    inserted_mac_name: str,
    inserted_mac_id: str,
):
    patient_id = int(visit_row.get("PatientID") or 0)
    doc_in_charge = int(visit_row.get("DocInCharge") or 0)
    order_no = _pharmacy_sale_next_order_number(cursor, sale_dt)
    cursor.execute(
        """
        INSERT INTO dbo.OrderMst (
            OrdNo, OrdDateTime, OrdByDocID, OrdPatientID, OrdVisitID,
            UpdatedBy, UpdatedOn, OrdExecDate, OrdPriority,
            UpdatedMacName, UpdatedMacID, UpdatedIPAddress,
            InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);
        SELECT CAST(SCOPE_IDENTITY() AS INT);
        """,
        (
            order_no,
            sale_dt_str,
            doc_in_charge,
            patient_id,
            int(visit_id or 0),
            actor_user_id if actor_user_id > 0 else 0,
            sale_dt_str,
            sale_dt_str,
            "L",
            inserted_mac_name,
            inserted_mac_id,
            actor_ip,
            str(actor_user_id if actor_user_id > 0 else 0),
            sale_dt_str,
            inserted_mac_name,
            inserted_mac_id,
            actor_ip,
        ),
    )
    order_row = _cursor_fetchone_safe(cursor)
    order_id = int(order_row[0]) if order_row and order_row[0] is not None else 0
    if order_id <= 0:
        raise RuntimeError("Patient order save did not return an order ID.")

    issue_id = _pharmacy_sale_next_manual_id(cursor, "dbo.IvPatientIssueMst", "IssueId")
    issue_no = f"PISN{issue_id}"
    cursor.execute(
        """
        INSERT INTO dbo.IvPatientIssueMst (
            IssueId, IssueNo, IssueDate, Patientid, VisitId, IndentId, BillId,
            TotalAmount, Amount, dueamount, storeid, OrderId,
            UpdatedBy, UpdatedOn, UpdatedMacName, UpdatedMacID, UpdatedIPAddress,
            InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);
        """,
        (
            issue_id,
            issue_no,
            sale_dt_str,
            patient_id,
            int(visit_id or 0),
            0,
            0,
            float(gross_total),
            float(rounded_net),
            float(rounded_net),
            PHARMACY_SALE_STORE_ID,
            order_id,
            actor_user_id if actor_user_id > 0 else 0,
            sale_dt_str,
            inserted_mac_name,
            inserted_mac_id,
            actor_ip,
            str(actor_user_id if actor_user_id > 0 else 0),
            sale_dt_str,
            inserted_mac_name,
            inserted_mac_id,
            actor_ip,
        ),
    )

    next_issue_dtl_id = _pharmacy_sale_next_manual_id(cursor, "dbo.IvPatientIssueDtl", "IssueDtlId")
    for line in validated_lines:
        cursor.execute(
            """
            INSERT INTO dbo.IvPatientIssueDtl (
                IssueDtlId, Issueid, ItemId, BatchId, Issueqty, Rate, Mrp,
                TaxRate, TaxAmount, VAT, VATOn, Amount,
                UpdatedBy, UpdatedOn, UpdatedMacName, UpdatedMacID, UpdatedIPAddress,
                InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);
            """,
            (
                next_issue_dtl_id,
                issue_id,
                int(line["item_id"]),
                int(line["batch_id"]),
                float(line["qty"]),
                float(line["rate"]),
                float(line["mrp"]),
                0.0,
                0.0,
                "",
                "",
                float(line["line_total"]),
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                str(actor_user_id if actor_user_id > 0 else 0),
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
            ),
        )
        next_issue_dtl_id += 1

    for line in validated_lines:
        cursor.execute(
            """
            INSERT INTO dbo.OrderDtl (
                OrdID, ServiceId, ServRendered, ServRenderingDeptID, ServRenderingSubDeptID,
                ServBilled, ServBillId, OrdDateTime, ServCancelID, CancelReasonID, CanceledBy, SampleID,
                OrdQty, Cancelled, Notes, RenderDateTime, RefDocId, BillingClassId, TariffScheme_ID, PatClassID,
                PatOrgID, wardid, OrdSchDateTime, PatientId, WardDeptID, EmergencyFlag, UpdatedBy, UpdatedON,
                UpdatedMacName, UpdatedMacID, UpdatedIPAddress, InsertedByUserID, InsertedON, InsertedMacName,
                InsertedMacID, InsertedIPAddress, HCID, PackageID, RoomId, ServiceAmount, DocID, NetAmount,
                EmergencyAmount, DrugId, StoreID, MarkForPending, ReportAuthorization, AuthorizationDt, AuthorizedBy,
                IsServiceChargeable, BatchId, JE, BedID, StdDiscount, issueId
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);
            """,
            (
                order_id,
                2688,
                1,
                0,
                0,
                0,
                0,
                sale_dt_str,
                0,
                0,
                0,
                0,
                float(line["qty"]),
                0,
                "",
                sale_dt_str,
                0,
                0,
                0,
                0,
                0,
                0,
                sale_dt_str,
                0,
                0,
                0,
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                str(actor_user_id if actor_user_id > 0 else 0),
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                0,
                0,
                0,
                float(line["mrp"]),
                0,
                float(line["line_total"]),
                0.0,
                int(line["item_id"]),
                PHARMACY_SALE_STORE_ID,
                0,
                0,
                sale_dt_str,
                0,
                1,
                int(line["batch_id"]),
                0,
                0,
                0.0,
                issue_id,
            ),
        )

    post_batch_qty: dict[int, Decimal] = {}
    affected_item_ids: set[int] = set()
    for line in validated_lines:
        affected_item_ids.add(int(line["item_id"]))
        cursor.execute(
            """
            UPDATE dbo.StoreStock
            SET Qty = Qty - ?, UpdatedBy = ?, UpdatedON = ?, UpdatedMacName = ?, UpdatedMacID = ?, UpdatedIPAddress = ?
            WHERE StoreID = ? AND ItemID = ? AND BatchID = ? AND Qty >= ?;
            SELECT @@ROWCOUNT;
            """,
            (
                float(line["qty"]),
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                PHARMACY_SALE_STORE_ID,
                int(line["item_id"]),
                int(line["batch_id"]),
                float(line["qty"]),
            ),
        )
        update_row = _cursor_fetchone_safe(cursor)
        updated_count = int(update_row[0]) if update_row and update_row[0] is not None else 0
        if updated_count <= 0:
            raise RuntimeError(
                f"Stock changed while saving {_pharmacy_sale_clean_text(line['item_name'])}; please refresh and try again."
            )
        cursor.execute(
            "SELECT CAST(ISNULL(Qty, 0) AS DECIMAL(18, 4)) FROM dbo.StoreStock WHERE StoreID = ? AND ItemID = ? AND BatchID = ?",
            (PHARMACY_SALE_STORE_ID, int(line["item_id"]), int(line["batch_id"])),
        )
        bal_row = cursor.fetchone()
        post_batch_qty[int(line["batch_id"])] = _pharmacy_sale_round_money(bal_row[0] if bal_row else 0, "0.0001")

    item_store_qty: dict[int, Decimal] = {}
    item_store1_qty: dict[int, Decimal] = {}
    for item_id_val in sorted(affected_item_ids):
        cursor.execute(
            "SELECT CAST(ISNULL(SUM(Qty), 0) AS DECIMAL(18, 4)) FROM dbo.StoreStock WHERE StoreID = ? AND ItemID = ?",
            (PHARMACY_SALE_STORE_ID, item_id_val),
        )
        sub_store_row = cursor.fetchone()
        sub_store_qty = _pharmacy_sale_round_money(sub_store_row[0] if sub_store_row else 0, "0.0001")
        item_store_qty[item_id_val] = sub_store_qty

        cursor.execute(
            "UPDATE dbo.IVItem SET CurrentQty = ?, UpdatedBy = ?, UpdatedOn = ? WHERE ID = ?",
            (float(sub_store_qty), actor_user_id if actor_user_id > 0 else 0, sale_dt_str, item_id_val),
        )

        cursor.execute(
            "SELECT CAST(ISNULL(SUM(Qty), 0) AS DECIMAL(18, 4)) FROM dbo.StoreStock WHERE StoreID = 1 AND ItemID = ?",
            (item_id_val,),
        )
        store1_row = cursor.fetchone()
        item_store1_qty[item_id_val] = _pharmacy_sale_round_money(store1_row[0] if store1_row else 0, "0.0001")

    cursor.execute("SELECT CAST(ISNULL(MAX(ID), 0) AS INT) FROM dbo.IVStockRegister WITH (TABLOCKX, HOLDLOCK)")
    next_stock_register_row = _cursor_fetchone_safe(cursor)
    next_stock_register_id = int(next_stock_register_row[0]) + 1 if next_stock_register_row and next_stock_register_row[0] is not None else 1

    for line in validated_lines:
        item_id_val = int(line["item_id"])
        batch_id_val = int(line["batch_id"])
        cursor.execute(
            """
            INSERT INTO dbo.IVStockRegister (
                ID,
                DocId, DocType, DocDate, ItemID, BatchID, Qty, StoreID,
                UpdatedBy, UpdatedON, UpdatedMacName, UpdatedMacID, UpdatedIPAddress,
                InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress,
                Amount, RunningBalQty, Mrp, AvgMrp, PLB, SubStorePLB, PSL, Lendingrate, Actuallendingrate
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                next_stock_register_id,
                issue_id,
                PHARMACY_ISSUE_STOCK_DOC_TYPE,
                sale_dt_str,
                item_id_val,
                batch_id_val,
                float(line["qty"]),
                PHARMACY_SALE_STORE_ID,
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                float(line["line_total"]),
                float(post_batch_qty.get(batch_id_val, Decimal("0"))),
                float(line["mrp"]),
                float(line["sales_price"]),
                float(item_store1_qty.get(item_id_val, Decimal("0"))),
                float(item_store_qty.get(item_id_val, Decimal("0"))),
                float(line["rate"]),
                float(line["lending_rate"]),
                float(line["actual_lending_rate"]),
            ),
        )
        next_stock_register_id += 1

    conn.commit()
    return {
        "status": "success",
        "transaction_kind": "issue",
        "issue_id": int(issue_id),
        "issue_no": issue_no,
        "order_id": int(order_id),
        "order_no": order_no,
        "gross_amount": float(gross_total),
        "discount_amount": float(discount_total),
        "net_amount": float(rounded_net),
        "due_amount": float(rounded_net),
    }


def save_pharmacy_sale(
    unit: str,
    *,
    visit_id: int,
    visit_bucket: str,
    patient_mode: str = "visit",
    walkin_patient_name: str = "",
    walkin_doctor_name: str = "",
    sale_date=None,
    discount_amount=0,
    remarks: str = "",
    receipt_amount=0,
    receipt_payment_mode_id: int = 0,
    receipt_date=None,
    receipt_note: str = "",
    allow_mrp_override: bool = False,
    items: list[dict] | None = None,
    actor_user_id: int = 0,
    actor_username: str = "",
    actor_ip: str = "",
    inserted_mac_name: str = "",
    inserted_mac_id: str = "",
    lock_timeout_ms: int = 15000,
):
    unit_norm = str(unit or "").strip().upper()
    if unit_norm != PHARMACY_SALE_ALLOWED_UNIT:
        return {"status": "error", "message": f"Pharmacy sale is only available for {PHARMACY_SALE_ALLOWED_UNIT}."}

    conn = get_sql_connection(unit_norm)
    if not conn:
        return {"status": "error", "message": f"Could not connect to {unit_norm} for pharmacy sale."}

    cursor = None
    lock_resource = f"PHARMACY_SALE_SAVE_{unit_norm}_STORE_{PHARMACY_SALE_STORE_ID}"
    sale_dt = _pharmacy_sale_parse_sale_datetime(sale_date)
    merged_items = _pharmacy_sale_merge_items(items or [])
    actor_user_id = int(actor_user_id or 0)
    actor_username = _pharmacy_sale_clean_text(actor_username) or (str(actor_user_id) if actor_user_id > 0 else "web")
    actor_ip = _pharmacy_sale_clean_text(actor_ip)
    inserted_mac_name = _pharmacy_sale_clean_text(inserted_mac_name) or actor_username
    inserted_mac_id = _pharmacy_sale_clean_text(inserted_mac_id)
    visit_id_int = int(visit_id or 0)
    bucket_key = _pharmacy_sale_norm_bucket(visit_bucket)
    patient_mode_key = _pharmacy_sale_clean_text(patient_mode).lower()
    walkin_mode = patient_mode_key in {"walkin", "tmp", "tmp_patient", "self_walkin", "self-walkin"}
    walkin_patient_name = _pharmacy_sale_clean_text(walkin_patient_name)
    walkin_doctor_name = _pharmacy_sale_clean_text(walkin_doctor_name)
    initial_receipt_amount = _pharmacy_sale_round_money(receipt_amount)
    initial_receipt_payment_mode_id = int(receipt_payment_mode_id or 0)
    initial_receipt_note = _pharmacy_sale_clean_text(receipt_note)[:255]
    initial_receipt_dt = _pharmacy_sale_parse_sale_datetime(receipt_date or sale_date)
    initial_receipt_dt_str = initial_receipt_dt.strftime("%Y-%m-%d %H:%M:%S")

    if not walkin_mode and visit_id_int <= 0:
        return {"status": "error", "message": "A valid visit is required for pharmacy sale."}
    if walkin_mode and bucket_key != "OPD":
        return {"status": "error", "message": "Self walk-in pharmacy sale is available only in OPD / DPV."}
    if walkin_mode and not walkin_patient_name:
        return {"status": "error", "message": "Enter the self walk-in patient name before saving."}
    if walkin_mode and not walkin_doctor_name:
        return {"status": "error", "message": "Enter the prescribed-by doctor name before saving."}
    if not merged_items:
        return {"status": "error", "message": "Add at least one valid item before saving the bill."}
    if initial_receipt_amount < 0:
        return {"status": "error", "message": "Receipt amount cannot be negative."}

    try:
        try:
            conn.autocommit = False
        except Exception:
            pass

        cursor = conn.cursor()
        lock_result = _get_app_lock(cursor, lock_resource, lock_timeout_ms)
        if lock_result.get("error"):
            return {"status": "error", "message": lock_result.get("error")}

        tmp_patient_id = 0
        if walkin_mode:
            tmp_patient_id = _pharmacy_sale_insert_tmp_patient(
                cursor,
                patient_name=walkin_patient_name,
                prescribed_by=walkin_doctor_name,
                sale_dt_str=sale_dt.strftime("%Y-%m-%d %H:%M:%S"),
                actor_user_id=actor_user_id,
                actor_ip=actor_ip,
                inserted_mac_name=inserted_mac_name,
                inserted_mac_id=inserted_mac_id,
            )
            visit_row = {
                "VisitID": 0,
                "PatientID": 0,
                "RegistrationNo": "",
                "VisitNo": "",
                "AdmissionNo": "",
                "VisitDate": sale_dt,
                "TypeOfVisit": "OPD",
                "PatientName": walkin_patient_name,
                "ConsultantName": walkin_doctor_name,
                "DocInCharge": 0,
                "PayerTypeId": 0,
                "AgreementTypeId": 0,
                "HasCorpBill": 1,
                "TmpPatientID": int(tmp_patient_id),
                "PrescribedBy": walkin_doctor_name,
            }
        else:
            cursor.execute(
                """
                SELECT TOP 1
                      CAST(v.Visit_ID AS INT) AS VisitID
                    , CAST(v.PatientID AS INT) AS PatientID
                    , LTRIM(RTRIM(ISNULL(p.Registration_No, N''))) AS RegistrationNo
                    , LTRIM(RTRIM(ISNULL(v.VisitNo, N''))) AS VisitNo
                    , LTRIM(RTRIM(ISNULL(v.AdmissionNo, N''))) AS AdmissionNo
                    , CAST(v.VisitDate AS DATETIME) AS VisitDate
                    , ISNULL(v.TypeOfVisit, N'') AS TypeOfVisit
                    , ISNULL(dbo.fn_PatientFullName(v.PatientID), N'') AS PatientName
                    , ISNULL(dbo.fn_DoctorFirstName(v.DocInCharge), N'') AS ConsultantName
                    , CAST(ISNULL(v.DocInCharge, 0) AS INT) AS DocInCharge
                    , CAST(ISNULL(v.PayerTypeId, 0) AS INT) AS PayerTypeId
                    , CAST(ISNULL(v.AgreementTypeId, 0) AS INT) AS AgreementTypeId
                    , CAST(CASE WHEN cb.CBillID IS NULL THEN 0 ELSE 1 END AS INT) AS HasCorpBill
                FROM dbo.Visit v
                INNER JOIN dbo.Patient p
                    ON p.PatientId = v.PatientID
                OUTER APPLY (
                    SELECT TOP 1 CAST(cb.CBill_ID AS INT) AS CBillID
                    FROM dbo.Corp_Bill_Mst cb WITH (NOLOCK)
                    WHERE cb.Visit_ID = v.Visit_ID
                      AND cb.CBill_ID IS NOT NULL
                    ORDER BY cb.CBill_ID DESC
                ) cb
                WHERE v.Visit_ID = ?;
                """,
                (visit_id_int,),
            )
            visit_rows = _rows_as_dicts(cursor) if cursor.description is not None else []
            if not visit_rows:
                raise RuntimeError("Selected visit could not be found.")
            visit_row = visit_rows[0]
            if not _pharmacy_sale_type_matches(bucket_key, visit_row.get("TypeOfVisit")):
                raise RuntimeError("Selected visit does not belong to the chosen OPD/IPD bucket.")

        pair_values_sql = ", ".join("(?, ?)" for _ in merged_items)
        pair_params = []
        for line in merged_items:
            pair_params.extend([int(line["item_id"]), int(line["batch_id"])])

        cursor.execute(
            f"""
            WITH target_pairs AS (
                SELECT CAST(v.ItemID AS INT) AS ItemID, CAST(v.BatchID AS INT) AS BatchID
                FROM (VALUES {pair_values_sql}) v(ItemID, BatchID)
            )
            SELECT
                  CAST(ss.ItemID AS INT) AS ItemID
                , CAST(ss.BatchID AS INT) AS BatchID
                , CAST(ISNULL(ss.Qty, 0) AS DECIMAL(18, 4)) AS StockQty
                , LTRIM(RTRIM(ISNULL(b.Name, N''))) AS BatchName
                , CAST(ISNULL(b.ExpiryDate, '19000101') AS DATETIME) AS ExpiryDate
                , CAST(ISNULL(b.Rate, 0) AS DECIMAL(18, 4)) AS Rate
                , CAST(ISNULL(b.mrp, 0) AS DECIMAL(18, 4)) AS MRP
                , CAST(ISNULL(b.lendingrate, 0) AS DECIMAL(18, 4)) AS LendingRate
                , CAST(ISNULL(b.Actuallendingrate, ISNULL(b.lendingrate, 0)) AS DECIMAL(18, 4)) AS ActualLendingRate
                , CAST(ISNULL(i.SalesPrice, 0) AS DECIMAL(18, 4)) AS SalesPrice
                , LTRIM(RTRIM(ISNULL(i.Name, N''))) AS ItemName
            FROM target_pairs tp
            INNER JOIN dbo.StoreStock ss WITH (UPDLOCK, HOLDLOCK)
                ON ss.ItemID = tp.ItemID
               AND ss.BatchID = tp.BatchID
               AND ss.StoreID = {PHARMACY_SALE_STORE_ID}
            INNER JOIN dbo.IVBatch b WITH (UPDLOCK, HOLDLOCK)
                ON b.ID = ss.BatchID
            INNER JOIN dbo.IVItem i WITH (UPDLOCK, HOLDLOCK)
                ON i.ID = ss.ItemID;
            """,
            pair_params,
        )
        stock_rows = _rows_as_dicts(cursor) if cursor.description is not None else []
        stock_map = {(int(row.get("ItemID") or 0), int(row.get("BatchID") or 0)): row for row in stock_rows}
        if len(stock_map) != len(merged_items):
            raise RuntimeError("One or more selected item batches no longer exist in store stock.")

        validated_lines = []
        gross_total = Decimal("0")
        for line in merged_items:
            key = (int(line["item_id"]), int(line["batch_id"]))
            stock_row = stock_map.get(key)
            if not stock_row:
                raise RuntimeError("One or more selected item batches could not be locked for saving.")
            expiry_dt = stock_row.get("ExpiryDate")
            expiry_date = expiry_dt.date() if isinstance(expiry_dt, datetime) else expiry_dt
            if expiry_date and hasattr(expiry_date, "isoformat"):
                try:
                    if expiry_date < sale_dt.date():
                        raise RuntimeError(f"Batch {stock_row.get('BatchName') or key[1]} for {stock_row.get('ItemName') or key[0]} is expired.")
                except TypeError:
                    pass
            available_qty = _pharmacy_sale_round_money(stock_row.get("StockQty"), "0.0001")
            requested_qty = _pharmacy_sale_round_money(line["qty"], "0.0001")
            if requested_qty <= 0:
                raise RuntimeError("Sale quantity must be greater than zero.")
            if requested_qty > available_qty:
                raise RuntimeError(
                    f"Insufficient stock for {_pharmacy_sale_clean_text(stock_row.get('ItemName'))} / {_pharmacy_sale_clean_text(stock_row.get('BatchName'))}. "
                    f"Available {available_qty}, requested {requested_qty}."
                )
            batch_mrp = _pharmacy_sale_round_money(stock_row.get("MRP"))
            override_mrp = line.get("mrp") if allow_mrp_override else None
            mrp = _pharmacy_sale_round_money(override_mrp if override_mrp is not None else batch_mrp)
            if mrp < 0:
                raise RuntimeError("MRP cannot be negative.")
            rate = _pharmacy_sale_round_money(stock_row.get("Rate"))
            line_total = (requested_qty * mrp).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
            rate_total = (requested_qty * rate).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
            validated_lines.append(
                {
                    "item_id": key[0],
                    "batch_id": key[1],
                    "item_name": _pharmacy_sale_clean_text(stock_row.get("ItemName")),
                    "batch_name": _pharmacy_sale_clean_text(stock_row.get("BatchName")),
                    "expiry_date": expiry_dt,
                    "qty": requested_qty,
                    "rate": rate,
                    "mrp": mrp,
                    "batch_mrp": batch_mrp,
                    "sales_price": _pharmacy_sale_round_money(stock_row.get("SalesPrice")),
                    "lending_rate": _pharmacy_sale_round_money(stock_row.get("LendingRate")),
                    "actual_lending_rate": _pharmacy_sale_round_money(stock_row.get("ActualLendingRate")),
                    "line_total": line_total,
                    "rate_total": rate_total,
                }
            )
            gross_total += line_total

        gross_total = gross_total.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        discount_total = _pharmacy_sale_round_money(discount_amount)
        if discount_total < 0:
            discount_total = Decimal("0.00")
        if discount_total > gross_total:
            discount_total = gross_total
        rounded_net = _pharmacy_sale_round_rupee((gross_total - discount_total).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))
        discount_pct = Decimal("0.00")
        if gross_total > 0:
            discount_pct = ((discount_total * Decimal("100")) / gross_total).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

        sale_dt_str = sale_dt.strftime("%Y-%m-%d %H:%M:%S")
        billing_updated_by = actor_user_id if actor_user_id > 0 else 0
        drug_sale_updated_by = actor_user_id if actor_user_id > 0 else 0
        transaction_mode, admission_status = ("sale", "Self Walk-In") if walkin_mode else _pharmacy_sale_visit_mode_from_row(visit_row)
        if (not walkin_mode) and bucket_key == "IPD" and _pharmacy_sale_clean_text(visit_row.get("TypeOfVisit")).upper() == "IPD":
            live_corp_bill_id = _pharmacy_sale_check_corp_bill(cursor, visit_id_int)
            visit_row["HasCorpBill"] = 1 if live_corp_bill_id > 0 else 0
            transaction_mode, admission_status = _pharmacy_sale_visit_mode_from_row(visit_row)
        receipt_allowed = _pharmacy_sale_receipt_allowed(visit_row.get("TypeOfVisit"), tmp_patient_id)
        payment_mode_row = None
        if initial_receipt_amount > 0:
            if transaction_mode != "sale" or not receipt_allowed:
                raise RuntimeError("Receipts can be collected only for OPD / DPV pharmacy sale bills and self walk-in bills.")
            if initial_receipt_payment_mode_id <= 0:
                raise RuntimeError("Select a payment mode before saving the bill with a receipt.")
            if initial_receipt_amount > rounded_net:
                raise RuntimeError(f"Receipt amount cannot exceed the payable amount of {rounded_net}.")
            payment_mode_row = _pharmacy_sale_get_payment_mode_row(cursor, conn, initial_receipt_payment_mode_id)
            if not payment_mode_row:
                raise RuntimeError("Selected payment mode is no longer active.")

        if transaction_mode == "issue":
            return _save_pharmacy_issue_without_billing(
                conn=conn,
                cursor=cursor,
                visit_row=visit_row,
                visit_id=visit_id_int,
                sale_dt=sale_dt,
                sale_dt_str=sale_dt_str,
                validated_lines=validated_lines,
                gross_total=gross_total,
                discount_total=discount_total,
                rounded_net=rounded_net,
                actor_user_id=actor_user_id,
                actor_username=actor_username,
                actor_ip=actor_ip,
                inserted_mac_name=inserted_mac_name,
                inserted_mac_id=inserted_mac_id,
            )

        cursor.execute(
            """
            SET NOCOUNT ON;
            EXEC dbo.usp_addDrugSaleMst
                @pDrugsaleid=?,
                @pPatientid=?,
                @pSaledate=?,
                @pUpdatedby=?,
                @pUpdatedon=?,
                @pTmppatientid=?,
                @pCode=?,
                @pPrescriptionid=?,
                @pDiscount=?,
                @pDiscreasonid=?,
                @pDiscauthorityid=?,
                @pDiscauthoritytype=?,
                @pvisitid=?,
                @pbillid=?,
                @pInsertedByUserID=?,
                @pInsertedON=?,
                @pInsertedMacName=?,
                @pInsertedMacID=?,
                @pInsertedIPAddress=?,
                @pDiscountRate=?
            """,
            [
                0,
                int(visit_row.get("PatientID") or 0),
                sale_dt_str,
                drug_sale_updated_by,
                sale_dt_str,
                int(tmp_patient_id or 0),
                "",
                0,
                float(discount_total),
                0,
                0,
                " ",
                0 if walkin_mode else visit_id_int,
                0,
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                float(discount_pct),
            ],
        )
        drug_sale_row = _cursor_fetchone_safe(cursor)
        drug_sale_id = int(drug_sale_row[0]) if drug_sale_row and drug_sale_row[0] is not None else 0
        if drug_sale_id <= 0:
            raise RuntimeError("Drug sale master save did not return a sale ID.")

        for line in validated_lines:
            cursor.execute(
                """
                SET NOCOUNT ON;
                EXEC dbo.usp_addDrugSaleDtl
                    @pDrugsaleid=?, @pDetailid=?, @pDrugid=?, @pExpiry=?, @pBatch=?, @pBatchid=?,
                    @pQty=?, @pRate=?, @pDiscount=?, @pPrescriptiondrugid=?, @pPatientrequestid=?,
                    @pInsertedByUserID=?, @pInsertedON=?, @pInsertedMacName=?, @pInsertedMacID=?, @pInsertedIPAddress=?,
                    @pMrp=?, @pTaxRate=?, @pTaxAmount=?, @pVatOn=?, @pVat=?, @pTotalAmt=?, @ptaxId=?, @pED=?,
                    @pNetRate=?, @pCurrentSaleQty=?, @pDiscountRate=?, @pAmount=?
                """,
                [
                    drug_sale_id,
                    0,
                    int(line["item_id"]),
                    line["expiry_date"],
                    line["batch_name"][:50],
                    int(line["batch_id"]),
                    float(line["qty"]),
                    float(line["rate"]),
                    0.0,
                    0,
                    0,
                    actor_user_id if actor_user_id > 0 else 0,
                    sale_dt_str,
                    inserted_mac_name,
                    inserted_mac_id,
                    actor_ip,
                    float(line["mrp"]),
                    0.0,
                    0.0,
                    "",
                    "",
                    float(line["line_total"]),
                    0,
                    0.0,
                    float(line["rate_total"]),
                    float(line["qty"]),
                    0.0,
                    float(line["line_total"]),
                ],
            )
            while cursor.description is None and cursor.nextset():
                continue

        cursor.execute(
            """
            SET NOCOUNT ON;
            EXEC dbo.usp_addPharmacyBilling_Mst
                @pBillId=?, @pRegistrationNo=?, @pVisitId=?, @pBillno=?, @pGrossamount=?, @pDiscountamount=?,
                @pNetamount=?, @pBilltypeid=?, @pDiscreasonid=?, @pDiscauthorityid=?, @pDiscauthoritytype=?,
                @pUpdatedby=?, @billtype=?, @pBilldate=?, @pTmpPatientid=?, @pdrugsaleid=?, @pInsertedByUserID=?,
                @pInsertedON=?, @pInsertedMacName=?, @pInsertedMacID=?, @pInsertedIPAddress=?, @pPayerTypeID=?, @pAgreeMentTypeId=?
            """,
            [
                0,
                "" if walkin_mode else _pharmacy_sale_clean_text(visit_row.get("RegistrationNo")),
                0 if walkin_mode else visit_id_int,
                "",
                float(gross_total),
                float(discount_total),
                float(rounded_net),
                "     ",
                0,
                0,
                " ",
                billing_updated_by,
                "PH",
                sale_dt_str,
                int(tmp_patient_id or 0),
                drug_sale_id,
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                0 if walkin_mode else int(visit_row.get("PayerTypeId") or 0),
                0 if walkin_mode else int(visit_row.get("AgreementTypeId") or 0),
            ],
        )
        bill_row = _cursor_fetchone_safe(cursor)
        bill_id = int(bill_row[0]) if bill_row and bill_row[0] is not None else 0
        if bill_id <= 0:
            raise RuntimeError("Pharmacy billing save did not return a bill ID.")

        return _save_pharmacy_sale_post_billing(
            conn=conn,
            cursor=cursor,
            bill_id=bill_id,
            drug_sale_id=drug_sale_id,
            gross_total=gross_total,
            discount_total=discount_total,
            rounded_net=rounded_net,
            discount_pct=discount_pct,
            validated_lines=validated_lines,
            sale_dt_str=sale_dt_str,
            actor_user_id=actor_user_id,
            actor_username=actor_username,
            actor_ip=actor_ip,
            inserted_mac_name=inserted_mac_name,
            inserted_mac_id=inserted_mac_id,
            remarks=remarks,
            lock_resource=lock_resource,
            tmp_patient_id=int(tmp_patient_id or 0),
            receipt_allowed=receipt_allowed,
            receipt_patient_id=int(visit_row.get("PatientID") or 0),
            receipt_visit_id=0 if walkin_mode else visit_id_int,
            initial_receipt_amount=initial_receipt_amount,
            initial_receipt_payment_mode_id=initial_receipt_payment_mode_id,
            initial_receipt_payment_mode_name=_pharmacy_sale_clean_text(payment_mode_row.get("PaymentModeName")) if payment_mode_row else "",
            initial_receipt_dt_str=initial_receipt_dt_str,
            initial_receipt_note=initial_receipt_note,
        )
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": str(e)}
    finally:
        if cursor is not None:
            try:
                _release_app_lock(cursor, lock_resource)
            except Exception:
                pass
        try:
            conn.close()
        except Exception:
            pass


def _save_pharmacy_sale_post_billing(
    *,
    conn,
    cursor,
    bill_id: int,
    drug_sale_id: int,
    gross_total: Decimal,
    discount_total: Decimal,
    rounded_net: Decimal,
    discount_pct: Decimal,
    validated_lines: list[dict],
    sale_dt_str: str,
    actor_user_id: int,
    actor_username: str,
    actor_ip: str,
    inserted_mac_name: str,
    inserted_mac_id: str,
    remarks: str,
    lock_resource: str,
    tmp_patient_id: int = 0,
    receipt_allowed: bool = False,
    receipt_patient_id: int = 0,
    receipt_visit_id: int = 0,
    initial_receipt_amount: Decimal = Decimal("0.00"),
    initial_receipt_payment_mode_id: int = 0,
    initial_receipt_payment_mode_name: str = "",
    initial_receipt_dt_str: str = "",
    initial_receipt_note: str = "",
):
    for line in validated_lines:
        cursor.execute(
            """
            SET NOCOUNT ON;
            EXEC dbo.usp_addPharmacyBillingDetails
                @pBilldetailid=?, @pBillId=?, @pServiceid=?, @pRate=?, @pQuantity=?, @pAmount=?,
                @pUpdatedby=?, @pUpdatedon=?, @pitemId=?, @pbatchId=?,
                @pInsertedByUserID=?, @pInsertedON=?, @pInsertedMacName=?, @pInsertedMacID=?, @pInsertedIPAddress=?
            """,
            [
                0,
                bill_id,
                int(line["item_id"]),
                float(line["mrp"]),
                float(line["qty"]),
                float(line["line_total"]),
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                int(line["item_id"]),
                int(line["batch_id"]),
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
            ],
        )
        while cursor.description is None and cursor.nextset():
            continue

    cursor.execute(
        "UPDATE dbo.Billing_Mst SET DiscountPercentage = ?, Remarks = ? WHERE Bill_ID = ?",
        (float(discount_pct), _pharmacy_sale_clean_text(remarks), bill_id),
    )

    post_batch_qty: dict[int, Decimal] = {}
    affected_item_ids: set[int] = set()
    for line in validated_lines:
        affected_item_ids.add(int(line["item_id"]))
        cursor.execute(
            """
            UPDATE dbo.StoreStock
            SET Qty = Qty - ?, UpdatedBy = ?, UpdatedON = ?, UpdatedMacName = ?, UpdatedMacID = ?, UpdatedIPAddress = ?
            WHERE StoreID = ? AND ItemID = ? AND BatchID = ? AND Qty >= ?;
            SELECT @@ROWCOUNT;
            """,
            (
                float(line["qty"]),
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                PHARMACY_SALE_STORE_ID,
                int(line["item_id"]),
                int(line["batch_id"]),
                float(line["qty"]),
            ),
        )
        update_row = _cursor_fetchone_safe(cursor)
        updated_count = int(update_row[0]) if update_row and update_row[0] is not None else 0
        if updated_count <= 0:
            raise RuntimeError(
                f"Stock changed while saving {_pharmacy_sale_clean_text(line['item_name'])}; please refresh and try again."
            )
        cursor.execute(
            "SELECT CAST(ISNULL(Qty, 0) AS DECIMAL(18, 4)) FROM dbo.StoreStock WHERE StoreID = ? AND ItemID = ? AND BatchID = ?",
            (PHARMACY_SALE_STORE_ID, int(line["item_id"]), int(line["batch_id"])),
        )
        bal_row = cursor.fetchone()
        post_batch_qty[int(line["batch_id"])] = _pharmacy_sale_round_money(bal_row[0] if bal_row else 0, "0.0001")

    item_store_qty: dict[int, Decimal] = {}
    item_store1_qty: dict[int, Decimal] = {}
    for item_id_val in sorted(affected_item_ids):
        cursor.execute(
            "SELECT CAST(ISNULL(SUM(Qty), 0) AS DECIMAL(18, 4)) FROM dbo.StoreStock WHERE StoreID = ? AND ItemID = ?",
            (PHARMACY_SALE_STORE_ID, item_id_val),
        )
        sub_store_row = cursor.fetchone()
        sub_store_qty = _pharmacy_sale_round_money(sub_store_row[0] if sub_store_row else 0, "0.0001")
        item_store_qty[item_id_val] = sub_store_qty

        cursor.execute(
            "UPDATE dbo.IVItem SET CurrentQty = ?, UpdatedBy = ?, UpdatedOn = ? WHERE ID = ?",
            (float(sub_store_qty), actor_user_id if actor_user_id > 0 else 0, sale_dt_str, item_id_val),
        )

        cursor.execute(
            "SELECT CAST(ISNULL(SUM(Qty), 0) AS DECIMAL(18, 4)) FROM dbo.StoreStock WHERE StoreID = 1 AND ItemID = ?",
            (item_id_val,),
        )
        store1_row = cursor.fetchone()
        item_store1_qty[item_id_val] = _pharmacy_sale_round_money(store1_row[0] if store1_row else 0, "0.0001")

    cursor.execute("SELECT CAST(ISNULL(MAX(ID), 0) AS INT) FROM dbo.IVStockRegister WITH (TABLOCKX, HOLDLOCK)")
    next_stock_register_row = _cursor_fetchone_safe(cursor)
    next_stock_register_id = int(next_stock_register_row[0]) + 1 if next_stock_register_row and next_stock_register_row[0] is not None else 1

    for line in validated_lines:
        item_id_val = int(line["item_id"])
        batch_id_val = int(line["batch_id"])
        cursor.execute(
            """
            INSERT INTO dbo.IVStockRegister (
                ID,
                DocId, DocType, DocDate, ItemID, BatchID, Qty, StoreID,
                UpdatedBy, UpdatedON, UpdatedMacName, UpdatedMacID, UpdatedIPAddress,
                InsertedByUserID, InsertedON, InsertedMacName, InsertedMacID, InsertedIPAddress,
                Amount, RunningBalQty, Mrp, AvgMrp, PLB, SubStorePLB, PSL, Lendingrate, Actuallendingrate
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                next_stock_register_id,
                bill_id,
                PHARMACY_SALE_STOCK_DOC_TYPE,
                sale_dt_str,
                item_id_val,
                batch_id_val,
                float(line["qty"]),
                PHARMACY_SALE_STORE_ID,
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                actor_user_id if actor_user_id > 0 else 0,
                sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                float(line["line_total"]),
                float(post_batch_qty.get(batch_id_val, Decimal("0"))),
                float(line["mrp"]),
                float(line["sales_price"]),
                float(item_store1_qty.get(item_id_val, Decimal("0"))),
                float(item_store_qty.get(item_id_val, Decimal("0"))),
                float(line["rate"]),
                float(line["lending_rate"]),
                float(line["actual_lending_rate"]),
            ),
        )
        next_stock_register_id += 1

    cursor.execute("SELECT TOP 1 BillNo FROM dbo.Billing_Mst WHERE Bill_ID = ?", (bill_id,))
    bill_no_row = cursor.fetchone()
    bill_no = _pharmacy_sale_clean_text(bill_no_row[0] if bill_no_row else "")

    received_total = _pharmacy_sale_round_money(initial_receipt_amount)
    remaining_due = rounded_net.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    receipt_id = 0
    receipt_no = ""
    if received_total > 0:
        receipt_info = _pharmacy_sale_insert_receipt(
            cursor,
            bill_id=int(bill_id),
            bill_no=bill_no,
            patient_id=int(receipt_patient_id or 0),
            visit_id=int(receipt_visit_id or 0),
            tmp_patient_id=int(tmp_patient_id or 0),
            received_amount=received_total,
            payment_mode_id=int(initial_receipt_payment_mode_id or 0),
            receipt_dt_str=initial_receipt_dt_str or sale_dt_str,
            actor_user_id=actor_user_id,
            actor_ip=actor_ip,
            inserted_mac_name=inserted_mac_name,
            inserted_mac_id=inserted_mac_id,
            note_text=initial_receipt_note,
        )
        receipt_id = int(receipt_info.get("receipt_id") or 0)
        receipt_no = _pharmacy_sale_clean_text(receipt_info.get("receipt_no"))
        remaining_due = (remaining_due - received_total).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        if remaining_due < 0:
            remaining_due = Decimal("0.00")
        cursor.execute(
            """
            UPDATE dbo.Billing_Mst
            SET DueAmount = ?, UpdatedBy = ?, UpdatedOn = ?, UpdatedMacName = ?, UpdatedMacID = ?, UpdatedIPAddress = ?
            WHERE Bill_ID = ?
            """,
            (
                float(remaining_due),
                actor_user_id if actor_user_id > 0 else 0,
                initial_receipt_dt_str or sale_dt_str,
                inserted_mac_name,
                inserted_mac_id,
                actor_ip,
                int(bill_id),
            ),
        )

    conn.commit()
    return {
        "status": "success",
        "transaction_kind": "sale",
        "bill_id": int(bill_id),
        "bill_no": bill_no,
        "drug_sale_id": int(drug_sale_id),
        "tmp_patient_id": int(tmp_patient_id or 0),
        "gross_amount": float(gross_total),
        "discount_amount": float(discount_total),
        "net_amount": float(rounded_net),
        "due_amount": float(remaining_due),
        "received_amount": float(received_total),
        "receipt_id": int(receipt_id),
        "receipt_no": receipt_no,
        "payment_mode_id": int(initial_receipt_payment_mode_id or 0) if received_total > 0 else 0,
        "payment_mode_name": _pharmacy_sale_clean_text(initial_receipt_payment_mode_name) if received_total > 0 else "",
        "discount_percentage": float(discount_pct),
        "receipt_allowed": bool(receipt_allowed),
    }


def _corp_bill_summary_parse_int(raw_value, default: int, minimum: int | None = None, maximum: int | None = None) -> int:
    try:
        value = int(float(raw_value))
    except Exception:
        value = int(default)
    if minimum is not None:
        value = max(minimum, value)
    if maximum is not None:
        value = min(maximum, value)
    return value


def _corp_bill_summary_norm_status_filter(status_filter: str) -> str:
    key = str(status_filter or "").strip().lower()
    alias_map = {
        "final": "final",
        "nonfinal": "nonfinal",
        "other": "nonfinal",
        "other_status": "nonfinal",
        "pending": "pending",
        "submission_pending": "pending",
        "notworked": "notworked",
        "not_worked": "notworked",
    }
    if key in alias_map:
        return alias_map[key]
    return "all"


def _corp_bill_summary_parse_date_or_none(raw_value):
    txt = str(raw_value or "").strip()
    if not txt:
        return None
    txt = txt[:10]
    try:
        return datetime.strptime(txt, "%Y-%m-%d").date().isoformat()
    except Exception:
        return None


def _corp_bill_summary_date_scope_label(unit: str) -> str:
    unit_key = str(unit or "").strip().upper()
    if unit_key in {"AHL", "ACI"}:
        return "Submit Date first; fallback to Bill Date when Submit Date is blank"
    if unit_key == "SHARPSIGHT":
        return "Submit Date first; fallback to legacy bill date fields when Submit Date is blank"
    return "Bill Date"


def _corp_bill_summary_status_counts_from_meta(raw_meta) -> dict:
    meta = raw_meta if isinstance(raw_meta, dict) else {}
    return {
        "final_submitted": _corp_bill_summary_parse_int(
            meta.get("final_submitted_count", meta.get("final_submitted")),
            0,
            0,
            None,
        ),
        "submission_pending": _corp_bill_summary_parse_int(
            meta.get("submission_pending_count", meta.get("submission_pending")),
            0,
            0,
            None,
        ),
        "not_worked": _corp_bill_summary_parse_int(
            meta.get("not_worked_count", meta.get("not_worked")),
            0,
            0,
            None,
        ),
        "other_status": _corp_bill_summary_parse_int(
            meta.get("other_status_count", meta.get("other_status")),
            0,
            0,
            None,
        ),
    }


def _is_sharpsight_unit(unit: str) -> bool:
    return str(unit or "").strip().upper() == "SHARPSIGHT"


SHARPSIGHT_RECEIPT_SOURCE_COL_CANDIDATES = [
    "BillSourceKey",
    "ReceiptBillSource",
    "BillSource",
]
SHARPSIGHT_RECEIPT_SOURCE_OPENING = "OPENING"
SHARPSIGHT_RECEIPT_SOURCE_AHL = "BILL_MST_AHL"
SHARPSIGHT_RECEIPT_SOURCE_UNKNOWN = "UNKNOWN"
CORP_RECEIPT_SOURCE_BILL_MST = "BILL_MST_POST"


def _table_columns_map_conn(conn, table_name: str) -> dict:
    if not conn or not table_name:
        return {}
    parts = [p.strip() for p in str(table_name).split(".") if str(p or "").strip()]
    if len(parts) == 1:
        schema_name, bare_name = "dbo", parts[0]
    else:
        schema_name, bare_name = parts[-2], parts[-1]
    try:
        cur = conn.cursor()
        cur.execute(
            """
            SELECT COLUMN_NAME
            FROM INFORMATION_SCHEMA.COLUMNS
            WHERE TABLE_SCHEMA = ? AND TABLE_NAME = ?
            ORDER BY ORDINAL_POSITION
            """,
            (schema_name, bare_name),
        )
        rows = cur.fetchall()
    except Exception:
        return {}
    return {
        str(getattr(row, "COLUMN_NAME", row[0]) or "").strip().lower(): str(getattr(row, "COLUMN_NAME", row[0]) or "").strip()
        for row in rows
        if str(getattr(row, "COLUMN_NAME", row[0]) or "").strip()
    }


def _pick_table_col_conn(conn, table_name: str, candidates: list[str]) -> str | None:
    cols_map = _table_columns_map_conn(conn, table_name)
    for cand in candidates or []:
        key = str(cand or "").strip().lower()
        if key and key in cols_map:
            return cols_map[key]
    return None


def _corp_receipt_bill_source_key_for_unit(unit: str) -> str:
    return SHARPSIGHT_RECEIPT_SOURCE_AHL if _is_sharpsight_unit(unit) else CORP_RECEIPT_SOURCE_BILL_MST


def _corp_receipt_against_label(source_key: str | None) -> str:
    return "Opening" if str(source_key or "").strip().upper() == SHARPSIGHT_RECEIPT_SOURCE_OPENING else "Bill"


def _resolve_corporate_bill_table_conn(conn, unit: str) -> str | None:
    if _is_sharpsight_unit(unit):
        return "dbo.Corp_Bill_Mst_AHL"
    for cand in ("dbo.Corp_Bill_Mst", "dbo.Corp_BillMst"):
        try:
            pd.read_sql(f"SELECT TOP 0 * FROM {cand}", conn)
            return cand
        except Exception:
            continue
    return None


def _ensure_corporate_receipt_source_column_conn(conn) -> dict:
    result = {"column": None, "added": False}
    if not conn:
        return result

    existing = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", SHARPSIGHT_RECEIPT_SOURCE_COL_CANDIDATES)
    if existing:
        result["column"] = existing
        return result

    cur = conn.cursor()
    try:
        cur.execute("ALTER TABLE dbo.Corp_Receipt_Dtl ADD [BillSourceKey] NVARCHAR(40) NULL")
        try:
            conn.commit()
        except Exception:
            pass
        result["column"] = "BillSourceKey"
        result["added"] = True
    except Exception:
        try:
            conn.rollback()
        except Exception:
            pass
        existing = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", SHARPSIGHT_RECEIPT_SOURCE_COL_CANDIDATES)
        if existing:
            result["column"] = existing
    return result


def _ensure_sharpsight_receipt_source_column_conn(conn) -> dict:
    return _ensure_corporate_receipt_source_column_conn(conn)


def _backfill_sharpsight_receipt_source_conn(conn, source_col: str | None = None) -> dict:
    result = {
        "column": None,
        "opening_overlap_marked": 0,
        "ahl_overlap_marked": 0,
        "opening_only_marked": 0,
        "ahl_only_marked": 0,
        "unknown_marked": 0,
    }
    if not conn:
        return result

    source_name = str(source_col or "").strip() or (_ensure_sharpsight_receipt_source_column_conn(conn).get("column") or "")
    if not source_name:
        return result
    result["column"] = source_name

    blank_expr = f"ISNULL(NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(40), d.[{source_name}]))), ''), '') = ''"
    receipt_dt_expr = "COALESCE(d.ReceiptDate, m.Receipt_Date)"
    bill_dt_expr = "COALESCE(b.Submit_Date, b.CBill_Date, b.accUpdatedDate, b.visitDate, b.Updated_On)"

    try:
        cur = conn.cursor()
        cur.execute(
            f"""
            SELECT TOP 1 1
            FROM dbo.Corp_Receipt_Dtl d WITH (NOLOCK)
            WHERE {blank_expr}
            """
        )
        if not cur.fetchone():
            return result
    except Exception:
        pass

    statements = [
        (
            "opening_overlap_marked",
            f"""
            UPDATE d
            SET [{source_name}] = ?
            FROM dbo.Corp_Receipt_Dtl d
            LEFT JOIN dbo.Corp_Receipt_Mst m WITH (NOLOCK)
                ON m.Receipt_ID = d.receiptId
            INNER JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            INNER JOIN dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            WHERE {blank_expr}
              AND (
                    {receipt_dt_expr} IS NULL
                    OR {bill_dt_expr} IS NULL
                    OR CAST({receipt_dt_expr} AS DATETIME) < CAST({bill_dt_expr} AS DATETIME)
                  )
            """,
            [SHARPSIGHT_RECEIPT_SOURCE_OPENING],
        ),
        (
            "ahl_overlap_marked",
            f"""
            UPDATE d
            SET [{source_name}] = ?
            FROM dbo.Corp_Receipt_Dtl d
            LEFT JOIN dbo.Corp_Receipt_Mst m WITH (NOLOCK)
                ON m.Receipt_ID = d.receiptId
            INNER JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            INNER JOIN dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            WHERE {blank_expr}
              AND {receipt_dt_expr} IS NOT NULL
              AND {bill_dt_expr} IS NOT NULL
              AND CAST({receipt_dt_expr} AS DATETIME) >= CAST({bill_dt_expr} AS DATETIME)
            """,
            [SHARPSIGHT_RECEIPT_SOURCE_AHL],
        ),
        (
            "opening_only_marked",
            f"""
            UPDATE d
            SET [{source_name}] = ?
            FROM dbo.Corp_Receipt_Dtl d
            INNER JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            LEFT JOIN dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            WHERE {blank_expr}
              AND b.CBill_ID IS NULL
            """,
            [SHARPSIGHT_RECEIPT_SOURCE_OPENING],
        ),
        (
            "ahl_only_marked",
            f"""
            UPDATE d
            SET [{source_name}] = ?
            FROM dbo.Corp_Receipt_Dtl d
            INNER JOIN dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            LEFT JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            WHERE {blank_expr}
              AND o.OPId IS NULL
            """,
            [SHARPSIGHT_RECEIPT_SOURCE_AHL],
        ),
        (
            "unknown_marked",
            f"""
            UPDATE d
            SET [{source_name}] = ?
            FROM dbo.Corp_Receipt_Dtl d
            LEFT JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            LEFT JOIN dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            WHERE {blank_expr}
              AND o.OPId IS NULL
              AND b.CBill_ID IS NULL
            """,
            [SHARPSIGHT_RECEIPT_SOURCE_UNKNOWN],
        ),
    ]

    cur = conn.cursor()
    try:
        for key, sql, params in statements:
            cur.execute(sql, params)
            try:
                result[key] = int(cur.rowcount or 0)
            except Exception:
                result[key] = 0
        try:
            conn.commit()
        except Exception:
            pass
    except Exception:
        try:
            conn.rollback()
        except Exception:
            pass
    return result


