def _backfill_corporate_receipt_source_conn(conn, unit: str, source_col: str | None = None) -> dict:
    if _is_sharpsight_unit(unit):
        return _backfill_sharpsight_receipt_source_conn(conn, source_col)
    return _backfill_non_sharpsight_receipt_source_conn(conn, source_col)


def _corp_bill_summary_dict_rows_from_cursor(cursor):
    if not cursor or not cursor.description:
        return []
    cols = [str(c[0]).strip() for c in cursor.description]
    rows = cursor.fetchall()
    out = []
    for row in rows:
        out.append({cols[i]: row[i] for i in range(len(cols))})
    return out


def _fetch_corporate_bill_summary_page_sp(
    conn,
    *,
    from_date: str | None,
    to_date: str | None,
    visit_type: int,
    status_filter: str,
    patient_subtype: str,
    search_query: str,
    page: int,
    page_size: int,
):
    if not conn:
        return None

    started = time.perf_counter()
    try:
        cur = conn.cursor()
        cur.execute(
            """
            EXEC dbo.usp_CorpBillSummary_Page
                 @FromDate = ?,
                 @ToDate = ?,
                 @VisitType = ?,
                 @StatusFilter = ?,
                 @PatientSubtype = ?,
                 @SearchQuery = ?,
                 @Page = ?,
                 @PageSize = ?
            """,
            [
                from_date,
                to_date,
                int(visit_type),
                str(status_filter or "all"),
                str(patient_subtype or ""),
                str(search_query or ""),
                int(page),
                int(page_size),
            ],
        )

        result_sets = []
        while True:
            if cur.description:
                result_sets.append(_corp_bill_summary_dict_rows_from_cursor(cur))
            if not cur.nextset():
                break

        if not result_sets:
            return None

        rows = list(result_sets[0] or [])
        meta = {}
        if len(result_sets) > 1 and result_sets[1]:
            meta = dict(result_sets[1][0] or {})
        elif rows and isinstance(rows[0], dict):
            first = rows[0]
            if "total_rows" in first:
                try:
                    meta["total_rows"] = int(first.get("total_rows") or 0)
                except Exception:
                    meta["total_rows"] = 0
        available_subtypes = []
        if len(result_sets) > 2 and isinstance(result_sets[2], list):
            for rec in result_sets[2]:
                if not isinstance(rec, dict):
                    continue
                val = str(rec.get("patient_subtype") or rec.get("PatientSubType") or "").strip()
                if val:
                    available_subtypes.append(val)
        if available_subtypes:
            dedup = []
            seen = set()
            for val in available_subtypes:
                key = val.lower()
                if key in seen:
                    continue
                seen.add(key)
                dedup.append(val)
            available_subtypes = dedup

        total_rows = _corp_bill_summary_parse_int(meta.get("total_rows"), len(rows), 0, None)
        total_pages = _corp_bill_summary_parse_int(
            meta.get("total_pages"),
            max(1, (total_rows + max(1, int(page_size)) - 1) // max(1, int(page_size))),
            1,
            None,
        )
        db_ms = round((time.perf_counter() - started) * 1000.0, 1)

        out_meta = {
            "page": _corp_bill_summary_parse_int(meta.get("page"), page, 1, None),
            "page_size": _corp_bill_summary_parse_int(meta.get("page_size"), page_size, 1, 5000),
            "total_rows": int(total_rows),
            "total_pages": int(total_pages),
            "query_engine": "sql_sp",
            "date_scope_label": _corp_bill_summary_date_scope_label("AHL"),
            "status_counts": _corp_bill_summary_status_counts_from_meta(meta),
            "available_patient_subtypes": available_subtypes,
            "timings": {"db_ms": float(db_ms), "total_ms": float(db_ms)},
        }
        return {"status": "success", "rows": rows, "meta": out_meta}
    except Exception:
        return None


def _fetch_corporate_bill_summary_page_sql(
    conn,
    *,
    from_date: str | None,
    to_date: str | None,
    visit_type: int,
    status_filter: str,
    patient_subtype: str,
    search_query: str,
    page: int,
    page_size: int,
):
    if not conn:
        return {"status": "error", "message": "Database connection unavailable"}

    started = time.perf_counter()
    try:
        sql = """
        SET NOCOUNT ON;
        DECLARE @FromDate DATE = ?;
        DECLARE @ToDate DATE = ?;
        DECLARE @VisitType INT = ?;
        DECLARE @StatusFilter NVARCHAR(20) = ?;
        DECLARE @PatientSubtype NVARCHAR(200) = ?;
        DECLARE @SearchQuery NVARCHAR(200) = ?;
        DECLARE @Page INT = ?;
        DECLARE @PageSize INT = ?;

        IF @Page < 1 SET @Page = 1;
        IF @PageSize < 1 SET @PageSize = 25;

        DECLARE @StatusNorm NVARCHAR(20) = LOWER(LTRIM(RTRIM(ISNULL(@StatusFilter, N'all'))));
        DECLARE @SubtypeNorm NVARCHAR(200) = LOWER(LTRIM(RTRIM(ISNULL(@PatientSubtype, N''))));
        DECLARE @SearchLower NVARCHAR(200) = LOWER(LTRIM(RTRIM(ISNULL(@SearchQuery, N''))));
        DECLARE @SearchLike NVARCHAR(220) = N'%' + @SearchLower + N'%';

        ;WITH base AS (
            SELECT
                CAST(ISNULL(cb.CBill_ID, 0) AS INT) AS CBill_ID,
                CAST(NULLIF(COALESCE(v.Visit_ID, bm.Visit_ID, cb.Visit_ID), 0) AS INT) AS Visit_ID,
                CAST(NULLIF(COALESCE(v.PatientID, cb.PatientID), 0) AS INT) AS PatientID,
                CAST(ISNULL(bm.Bill_ID, 0) AS INT) AS Bill_ID,
                CAST(bm.BillDate AS DATETIME) AS BillDate,
                CAST(cb.CBill_Date AS DATETIME) AS CBill_Date,
                CAST(cb.Submit_Date AS DATETIME) AS Submit_Date,
                CAST(COALESCE(cb.Submit_Date, bm.BillDate) AS DATETIME) AS FilterDate,
                CAST(ISNULL(cb.CAmount, 0) AS FLOAT) AS CAmount,
                CAST(ISNULL(cb.Due_Amt, ISNULL(cb.dueAmount, 0)) AS FLOAT) AS DueAmount,
                CAST(
                    CASE
                        WHEN ISNULL(cb.Old_Bill_Amt, 0) <> 0 THEN ISNULL(cb.Old_Bill_Amt, 0)
                        ELSE ISNULL(bm.NetAmount, 0)
                    END
                AS FLOAT) AS Old_Bill_Amt,
                CAST(COALESCE(cb.Old_Bill_Date, bm.BillDate) AS DATETIME) AS Old_Bill_Date,
                LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), cb.Status), N''))) AS StatusRaw,
                CASE
                    WHEN UPPER(LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), cb.Status), N'')))) IN (N'Y', N'1', N'TRUE', N'YES', N'FINAL', N'FINAL SUBMITTED')
                         OR UPPER(LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), cb.Status), N'')))) LIKE N'%FINAL%'
                        THEN 1
                    ELSE 0
                END AS IsFinalStatus,
                ISNULL(
                    NULLIF(CONVERT(NVARCHAR(80), cb.CBill_NO), N''),
                    ISNULL(NULLIF(CONVERT(NVARCHAR(80), cb.Bill_No), N''), CONVERT(NVARCHAR(80), bm.Bill_ID))
                ) AS BillNo,
                CAST(ISNULL(v.VisitTypeID, 0) AS INT) AS VisitTypeID,
                ISNULL(CONVERT(NVARCHAR(120), v.TypeOfVisit), N'') AS TypeOfVisit,
                v.VisitDate,
                v.DischargeDate,
                CAST(NULLIF(v.PatientID, 0) AS INT) AS VisitPatientID,
                CAST(NULLIF(v.PatientType_ID, 0) AS INT) AS VisitPatientTypeID,
                CAST(NULLIF(v.PatientSubType_ID, 0) AS INT) AS VisitPatientSubTypeID,
                CAST(NULLIF(v.DocInCharge, 0) AS INT) AS DocInChargeID,
                CAST(NULLIF(v.DepartmentID, 0) AS INT) AS DepartmentID,
                CAST(ISNULL(v.DischargeType, 0) AS INT) AS DischargeTypeID,
                CASE
                    WHEN UPPER(LTRIM(RTRIM(CONVERT(NVARCHAR(20), ISNULL(bm.CancelStatus, N''))))) IN (N'1', N'TRUE', N'YES', N'Y')
                        THEN 1
                    ELSE 0
                END AS CancelStatusNorm,
                CASE
                    WHEN ISNULL(v.VisitTypeID, 0) = 1 OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%IPD%' THEN 1
                    ELSE 0
                END AS IsIPDLike,
                CASE
                    WHEN ISNULL(v.VisitTypeID, 0) = 2 OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%OPD%' THEN 1
                    ELSE 0
                END AS IsOPDLike,
                CASE
                    WHEN ISNULL(v.VisitTypeID, 0) = 3
                         OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%DPV%'
                         OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%DAY%'
                        THEN 1
                    ELSE 0
                END AS IsDPVLike,
                CASE
                    WHEN v.PatientID IS NULL THEN N''
                    ELSE ISNULL(dbo.fn_regno(v.PatientID), N'')
                END AS Registration_No,
                CASE
                    WHEN v.PatientSubType_ID IS NULL THEN N''
                    ELSE ISNULL(dbo.fn_patsub_type(v.PatientSubType_ID), N'')
                END AS PatientSubTypeName
            FROM dbo.Billing_Mst bm WITH (NOLOCK)
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = bm.Visit_ID
            LEFT JOIN dbo.Corp_Bill_Mst cb WITH (NOLOCK)
                ON cb.Bill_ID = bm.Bill_ID
            WHERE
                UPPER(LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(30), bm.BillType), N'')))) = N'P'
                AND v.Visit_ID IS NOT NULL
                AND ISNULL(v.DepartmentID, 0) <> 7
        )
        SELECT
            b.CBill_ID,
            b.Visit_ID,
            b.PatientID,
            b.Bill_ID,
            b.BillDate,
            b.CBill_Date,
            b.Submit_Date,
            b.FilterDate,
            b.CAmount,
            b.DueAmount,
            b.Old_Bill_Amt,
            b.Old_Bill_Date,
            b.StatusRaw,
            b.IsFinalStatus,
            b.BillNo,
            b.VisitTypeID,
            b.TypeOfVisit,
            b.VisitDate,
            b.DischargeDate,
            b.VisitPatientID,
            b.VisitPatientTypeID,
            b.VisitPatientSubTypeID,
            b.DocInChargeID,
            b.DepartmentID,
            b.Registration_No,
            b.PatientSubTypeName,
            CASE
                WHEN ISNULL(b.IsFinalStatus, 0) = 1 THEN N'Final Submitted'
                WHEN UPPER(LTRIM(RTRIM(ISNULL(b.StatusRaw, N'')))) = N'N' THEN N'Submission Pending'
                WHEN LTRIM(RTRIM(ISNULL(b.StatusRaw, N''))) = N'' THEN N'Not Worked'
                ELSE N'Submission Pending'
            END AS StatusLabel
        INTO #corp_bill_scoped
        FROM base b
        WHERE
            b.FilterDate IS NOT NULL
            AND (@FromDate IS NULL OR CAST(b.FilterDate AS DATE) >= @FromDate)
            AND (@ToDate IS NULL OR CAST(b.FilterDate AS DATE) <= @ToDate)
            AND (
                (@VisitType = 0 AND (
                    (ISNULL(b.IsIPDLike, 0) = 1 AND ISNULL(b.DischargeTypeID, 0) = 2 AND ISNULL(b.CancelStatusNorm, 0) = 0)
                    OR (ISNULL(b.IsOPDLike, 0) = 1 AND ISNULL(b.CancelStatusNorm, 0) = 0)
                    OR (ISNULL(b.IsDPVLike, 0) = 1)
                ))
                OR (@VisitType = 1 AND ISNULL(b.IsIPDLike, 0) = 1 AND ISNULL(b.DischargeTypeID, 0) = 2 AND ISNULL(b.CancelStatusNorm, 0) = 0)
                OR (@VisitType = 2 AND ISNULL(b.IsOPDLike, 0) = 1 AND ISNULL(b.CancelStatusNorm, 0) = 0)
                OR (@VisitType = 3 AND ISNULL(b.IsDPVLike, 0) = 1)
            )
            AND (
                @SubtypeNorm = N''
                OR LOWER(ISNULL(b.PatientSubTypeName, N'')) = @SubtypeNorm
            )
            AND (
                @SearchLower = N''
                OR LOWER(ISNULL(b.BillNo, N'')) LIKE @SearchLike
                OR LOWER(ISNULL(b.Registration_No, N'')) LIKE @SearchLike
                OR LOWER(ISNULL(b.TypeOfVisit, N'')) LIKE @SearchLike
                OR LOWER(ISNULL(b.PatientSubTypeName, N'')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.FilterDate AS DATE), 23)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.FilterDate AS DATE), 105)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.FilterDate AS DATE), 103)) LIKE @SearchLike
                OR LOWER(REPLACE(CONVERT(NVARCHAR(11), CAST(b.FilterDate AS DATE), 106), N' ', N'-')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(19), CAST(b.FilterDate AS DATETIME), 120)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.Submit_Date AS DATE), 23)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.Submit_Date AS DATE), 105)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.Submit_Date AS DATE), 103)) LIKE @SearchLike
                OR LOWER(REPLACE(CONVERT(NVARCHAR(11), CAST(b.Submit_Date AS DATE), 106), N' ', N'-')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(19), CAST(b.Submit_Date AS DATETIME), 120)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.BillDate AS DATE), 23)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.BillDate AS DATE), 105)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.BillDate AS DATE), 103)) LIKE @SearchLike
                OR LOWER(REPLACE(CONVERT(NVARCHAR(11), CAST(b.BillDate AS DATE), 106), N' ', N'-')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(19), CAST(b.BillDate AS DATETIME), 120)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.Bill_ID, 0))) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.CBill_ID, 0))) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.Visit_ID, 0))) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.PatientID, 0))) LIKE @SearchLike
                OR LOWER(
                    CASE
                        WHEN COALESCE(b.VisitPatientID, b.PatientID) IS NULL THEN N''
                        ELSE ISNULL(dbo.fn_patientfullname(COALESCE(b.VisitPatientID, b.PatientID)), N'')
                    END
                ) LIKE @SearchLike
            )
        OPTION (RECOMPILE);

        SELECT
            s.CBill_ID,
            s.Visit_ID,
            s.PatientID,
            s.Bill_ID,
            s.BillDate,
            s.CBill_Date,
            s.Submit_Date,
            s.FilterDate,
            s.CAmount,
            s.DueAmount,
            s.Old_Bill_Amt,
            s.Old_Bill_Date,
            s.StatusRaw,
            s.IsFinalStatus,
            s.BillNo,
            s.VisitTypeID,
            s.TypeOfVisit,
            s.VisitDate,
            s.DischargeDate,
            s.VisitPatientID,
            s.VisitPatientTypeID,
            s.VisitPatientSubTypeID,
            s.DocInChargeID,
            s.DepartmentID,
            s.Registration_No,
            s.PatientSubTypeName,
            s.StatusLabel
        INTO #corp_bill_filtered
        FROM #corp_bill_scoped s
        WHERE
            @StatusNorm = N'all'
            OR (@StatusNorm = N'final' AND ISNULL(s.IsFinalStatus, 0) = 1)
            OR (@StatusNorm = N'nonfinal' AND ISNULL(s.IsFinalStatus, 0) = 0)
            OR (@StatusNorm = N'pending' AND LOWER(LTRIM(RTRIM(ISNULL(s.StatusLabel, N'')))) = N'submission pending')
            OR (@StatusNorm = N'notworked' AND LOWER(LTRIM(RTRIM(ISNULL(s.StatusLabel, N'')))) = N'not worked')
        OPTION (RECOMPILE);

        CREATE CLUSTERED INDEX IX_corp_bill_filtered_order
            ON #corp_bill_filtered(FilterDate DESC, CBill_ID DESC, Bill_ID DESC);

        SELECT
            filtered.total_rows,
            scoped.scoped_total_rows,
            scoped.final_submitted_count,
            scoped.submission_pending_count,
            scoped.not_worked_count,
            scoped.other_status_count
        FROM (SELECT COUNT(1) AS total_rows FROM #corp_bill_filtered) filtered
        CROSS JOIN (
            SELECT
                COUNT(1) AS scoped_total_rows,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) = N'final submitted' THEN 1 ELSE 0 END) AS final_submitted_count,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) = N'submission pending' THEN 1 ELSE 0 END) AS submission_pending_count,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) = N'not worked' THEN 1 ELSE 0 END) AS not_worked_count,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) <> N'final submitted' THEN 1 ELSE 0 END) AS other_status_count
            FROM #corp_bill_scoped
        ) scoped;

        ;WITH numbered AS (
            SELECT
                f.*,
                ROW_NUMBER() OVER (ORDER BY f.FilterDate DESC, f.CBill_ID DESC, f.Bill_ID DESC) AS rn
            FROM #corp_bill_filtered f
        )
        SELECT
            n.CBill_ID,
            n.Visit_ID,
            n.PatientID,
            ISNULL(NULLIF(n.Registration_No, N''), N'Unknown') AS Registration_No,
            ISNULL(NULLIF(n.BillNo, N''), CONVERT(NVARCHAR(80), ISNULL(NULLIF(n.Bill_ID, 0), n.CBill_ID))) AS BillNo,
            CAST(ISNULL(n.CAmount, 0) AS FLOAT) AS CAmount,
            CAST(ISNULL(n.DueAmount, 0) AS FLOAT) AS DueAmount,
            CAST(ISNULL(n.Old_Bill_Amt, 0) AS FLOAT) AS Old_Bill_Amt,
            n.Old_Bill_Date,
            ISNULL(NULLIF(n.StatusLabel, N''), N'Submission Pending') AS [Status],
            n.BillDate,
            n.CBill_Date,
            n.Submit_Date,
            n.VisitDate,
            n.DischargeDate,
            CASE
                WHEN COALESCE(n.VisitPatientID, n.PatientID) IS NULL THEN N''
                ELSE ISNULL(dbo.fn_patientfullname(COALESCE(n.VisitPatientID, n.PatientID)), N'')
            END AS PatientName,
            ISNULL(n.TypeOfVisit, N'') AS TypeOfVisit,
            CASE
                WHEN n.VisitPatientTypeID IS NULL THEN N''
                ELSE ISNULL(dbo.fn_pat_type(n.VisitPatientTypeID), N'')
            END AS PatientType,
            CASE
                WHEN n.VisitPatientSubTypeID IS NULL THEN N''
                ELSE ISNULL(n.PatientSubTypeName, N'')
            END AS PatientSubType,
            CASE
                WHEN n.DocInChargeID IS NULL THEN N''
                ELSE ISNULL(dbo.fn_doctorfirstname(n.DocInChargeID), N'')
            END AS DocInCharge,
            CASE
                WHEN n.DepartmentID IS NULL THEN N''
                ELSE ISNULL(dbo.fn_dept(n.DepartmentID), N'')
            END AS Dept
        FROM numbered n
        WHERE n.rn BETWEEN ((@Page - 1) * @PageSize + 1) AND (@Page * @PageSize)
        ORDER BY n.rn;

        SELECT DISTINCT
            LTRIM(RTRIM(ISNULL(PatientSubTypeName, N''))) AS patient_subtype
        FROM #corp_bill_filtered
        WHERE LTRIM(RTRIM(ISNULL(PatientSubTypeName, N''))) <> N''
        ORDER BY patient_subtype;
        """

        cur = conn.cursor()
        cur.execute(
            sql,
            [
                from_date,
                to_date,
                int(visit_type),
                str(status_filter or "all"),
                str(patient_subtype or ""),
                str(search_query or ""),
                int(page),
                int(page_size),
            ],
        )

        total_rows = 0
        scoped_total_rows = 0
        status_counts = {
            "final_submitted": 0,
            "submission_pending": 0,
            "not_worked": 0,
            "other_status": 0,
        }
        page_rows = []
        available_subtypes = []
        set_index = 0
        while True:
            if cur.description:
                rows = _corp_bill_summary_dict_rows_from_cursor(cur)
                if set_index == 0:
                    if rows:
                        first_meta = rows[0] or {}
                        total_rows = _corp_bill_summary_parse_int(first_meta.get("total_rows"), 0, 0, None)
                        scoped_total_rows = _corp_bill_summary_parse_int(first_meta.get("scoped_total_rows"), total_rows, 0, None)
                        status_counts = _corp_bill_summary_status_counts_from_meta(first_meta)
                elif set_index == 1:
                    page_rows = rows
                elif set_index == 2:
                    for rec in rows:
                        val = str(rec.get("patient_subtype") or "").strip()
                        if val:
                            available_subtypes.append(val)
                set_index += 1
            if not cur.nextset():
                break

        if available_subtypes:
            dedup = []
            seen = set()
            for val in available_subtypes:
                key = val.lower()
                if key in seen:
                    continue
                seen.add(key)
                dedup.append(val)
            available_subtypes = dedup

        total_pages = max(1, (int(total_rows) + int(page_size) - 1) // int(page_size)) if int(page_size) > 0 else 1
        db_ms = round((time.perf_counter() - started) * 1000.0, 1)
        return {
            "status": "success",
            "rows": page_rows,
            "meta": {
                "page": int(page),
                "page_size": int(page_size),
                "total_rows": int(total_rows),
                "scoped_total_rows": int(scoped_total_rows),
                "total_pages": int(total_pages),
                "query_engine": "python_sql",
                "date_scope_label": _corp_bill_summary_date_scope_label("AHL"),
                "status_counts": status_counts,
                "available_patient_subtypes": available_subtypes,
                "timings": {"db_ms": float(db_ms), "total_ms": float(db_ms)},
            },
        }
    except Exception as e:
        return {"status": "error", "message": f"Failed to fetch corporate bill summary page: {e}"}


def _fetch_sharpsight_corporate_bill_summary_page_sql(
    conn,
    *,
    from_date: str | None,
    to_date: str | None,
    visit_type: int,
    status_filter: str,
    patient_subtype: str,
    search_query: str,
    page: int,
    page_size: int,
):
    if not conn:
        return {"status": "error", "message": "Database connection unavailable"}

    started = time.perf_counter()
    try:
        sql = """
        SET NOCOUNT ON;
        DECLARE @FromDate DATE = ?;
        DECLARE @ToDate DATE = ?;
        DECLARE @VisitType INT = ?;
        DECLARE @StatusFilter NVARCHAR(20) = ?;
        DECLARE @PatientSubtype NVARCHAR(200) = ?;
        DECLARE @SearchQuery NVARCHAR(200) = ?;
        DECLARE @Page INT = ?;
        DECLARE @PageSize INT = ?;

        IF @Page < 1 SET @Page = 1;
        IF @PageSize < 1 SET @PageSize = 25;

        DECLARE @StatusNorm NVARCHAR(20) = LOWER(LTRIM(RTRIM(ISNULL(@StatusFilter, N'all'))));
        DECLARE @SubtypeNorm NVARCHAR(200) = LOWER(LTRIM(RTRIM(ISNULL(@PatientSubtype, N''))));
        DECLARE @SearchLower NVARCHAR(200) = LOWER(LTRIM(RTRIM(ISNULL(@SearchQuery, N''))));
        DECLARE @SearchLike NVARCHAR(220) = N'%' + @SearchLower + N'%';

        ;WITH base AS (
            SELECT
                CAST(ISNULL(b.CBill_ID, 0) AS INT) AS CBill_ID,
                CAST(NULLIF(COALESCE(v.Visit_ID, b.Visit_ID), 0) AS INT) AS Visit_ID,
                CAST(NULLIF(COALESCE(v.PatientID, b.PatientID), 0) AS INT) AS PatientID,
                CAST(ISNULL(b.Bill_ID, 0) AS INT) AS Bill_ID,
                CAST(COALESCE(b.Old_Bill_Date, b.CBill_Date, b.visitDate, v.VisitDate) AS DATETIME) AS BillDate,
                CAST(b.CBill_Date AS DATETIME) AS CBill_Date,
                CAST(b.Submit_Date AS DATETIME) AS Submit_Date,
                CAST(COALESCE(b.Submit_Date, b.Old_Bill_Date, b.CBill_Date, b.visitDate, v.VisitDate) AS DATETIME) AS FilterDate,
                CAST(ISNULL(b.CAmount, 0) AS FLOAT) AS CAmount,
                CAST(ISNULL(NULLIF(b.Due_Amt, 0), ISNULL(NULLIF(b.dueAmount, 0), ISNULL(b.CAmount, 0))) AS FLOAT) AS DueAmount,
                CAST(
                    CASE
                        WHEN ISNULL(b.Old_Bill_Amt, 0) <> 0 THEN ISNULL(b.Old_Bill_Amt, 0)
                        ELSE ISNULL(b.CAmount, 0)
                    END
                AS FLOAT) AS Old_Bill_Amt,
                CAST(COALESCE(b.Old_Bill_Date, b.CBill_Date, b.visitDate, v.VisitDate) AS DATETIME) AS Old_Bill_Date,
                LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), b.Status), N''))) AS StatusRaw,
                CASE
                    WHEN UPPER(LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), b.Status), N'')))) IN (N'Y', N'1', N'TRUE', N'YES', N'FINAL', N'FINAL SUBMITTED')
                         OR UPPER(LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(100), b.Status), N'')))) LIKE N'%FINAL%'
                        THEN 1
                    ELSE 0
                END AS IsFinalStatus,
                ISNULL(
                    NULLIF(CONVERT(NVARCHAR(80), b.CBill_NO), N''),
                    ISNULL(NULLIF(CONVERT(NVARCHAR(80), b.Bill_No), N''), CONVERT(NVARCHAR(80), b.CBill_ID))
                ) AS BillNo,
                CAST(ISNULL(v.VisitTypeID, 0) AS INT) AS VisitTypeID,
                ISNULL(CONVERT(NVARCHAR(120), v.TypeOfVisit), N'') AS TypeOfVisit,
                CAST(COALESCE(b.visitDate, v.VisitDate) AS DATETIME) AS VisitDate,
                CAST(COALESCE(b.dischargeDate, v.DischargeDate) AS DATETIME) AS DischargeDate,
                CAST(NULLIF(COALESCE(v.PatientID, b.PatientID), 0) AS INT) AS VisitPatientID,
                CAST(NULLIF(COALESCE(v.PatientType_ID, b.PatientTypeId), 0) AS INT) AS VisitPatientTypeID,
                CAST(NULLIF(COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo), 0) AS INT) AS VisitPatientSubTypeID,
                CAST(NULLIF(v.DocInCharge, 0) AS INT) AS DocInChargeID,
                CAST(NULLIF(v.DepartmentID, 0) AS INT) AS DepartmentID,
                CAST(ISNULL(v.DischargeType, 0) AS INT) AS DischargeTypeID,
                CAST(0 AS INT) AS CancelStatusNorm,
                CASE
                    WHEN ISNULL(v.VisitTypeID, 0) = 1
                         OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%IPD%'
                         OR UPPER(ISNULL(b.CBill_NO, N'')) LIKE N'%IPD%'
                         OR UPPER(ISNULL(b.Bill_No, N'')) LIKE N'%IPD%'
                        THEN 1
                    ELSE 0
                END AS IsIPDLike,
                CASE
                    WHEN ISNULL(v.VisitTypeID, 0) = 2
                         OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%OPD%'
                         OR UPPER(ISNULL(b.CBill_NO, N'')) LIKE N'%OPD%'
                         OR UPPER(ISNULL(b.Bill_No, N'')) LIKE N'%OPD%'
                        THEN 1
                    ELSE 0
                END AS IsOPDLike,
                CASE
                    WHEN ISNULL(v.VisitTypeID, 0) = 3
                         OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%DPV%'
                         OR UPPER(ISNULL(v.TypeOfVisit, N'')) LIKE N'%DAY%'
                         OR UPPER(ISNULL(b.CBill_NO, N'')) LIKE N'%DPV%'
                         OR UPPER(ISNULL(b.Bill_No, N'')) LIKE N'%DPV%'
                        THEN 1
                    ELSE 0
                END AS IsDPVLike,
                CASE
                    WHEN COALESCE(v.PatientID, b.PatientID) IS NULL THEN ISNULL(NULLIF(CONVERT(NVARCHAR(80), b.regSrNo), N''), N'')
                    ELSE ISNULL(dbo.fn_regno(COALESCE(v.PatientID, b.PatientID)), N'')
                END AS Registration_No,
                CASE
                    WHEN COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo) IS NULL THEN N''
                    ELSE ISNULL(dbo.fn_patsub_type(COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo)), N'')
                END AS PatientSubTypeName,
                ISNULL(CONVERT(NVARCHAR(120), b.Doc_nm), N'') AS DocNameRaw
            FROM dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = b.Visit_ID
        )
        SELECT
            b.CBill_ID,
            b.Visit_ID,
            b.PatientID,
            b.Bill_ID,
            b.BillDate,
            b.CBill_Date,
            b.Submit_Date,
            b.FilterDate,
            b.CAmount,
            b.DueAmount,
            b.Old_Bill_Amt,
            b.Old_Bill_Date,
            b.StatusRaw,
            b.IsFinalStatus,
            b.BillNo,
            b.VisitTypeID,
            b.TypeOfVisit,
            b.VisitDate,
            b.DischargeDate,
            b.VisitPatientID,
            b.VisitPatientTypeID,
            b.VisitPatientSubTypeID,
            b.DocInChargeID,
            b.DepartmentID,
            b.Registration_No,
            b.PatientSubTypeName,
            b.DocNameRaw,
            CASE
                WHEN ISNULL(b.IsFinalStatus, 0) = 1 THEN N'Final Submitted'
                WHEN UPPER(LTRIM(RTRIM(ISNULL(b.StatusRaw, N'')))) = N'N' THEN N'Submission Pending'
                WHEN LTRIM(RTRIM(ISNULL(b.StatusRaw, N''))) = N'' THEN N'Not Worked'
                ELSE N'Submission Pending'
            END AS StatusLabel
        INTO #corp_bill_scoped
        FROM base b
        WHERE
            b.FilterDate IS NOT NULL
            AND (@FromDate IS NULL OR CAST(b.FilterDate AS DATE) >= @FromDate)
            AND (@ToDate IS NULL OR CAST(b.FilterDate AS DATE) <= @ToDate)
            AND (
                (@VisitType = 0 AND (
                    (ISNULL(b.IsIPDLike, 0) = 1 AND (ISNULL(b.DischargeTypeID, 0) = 2 OR b.DischargeDate IS NOT NULL) AND ISNULL(b.CancelStatusNorm, 0) = 0)
                    OR (ISNULL(b.IsOPDLike, 0) = 1 AND ISNULL(b.CancelStatusNorm, 0) = 0)
                    OR (ISNULL(b.IsDPVLike, 0) = 1)
                ))
                OR (@VisitType = 1 AND ISNULL(b.IsIPDLike, 0) = 1 AND (ISNULL(b.DischargeTypeID, 0) = 2 OR b.DischargeDate IS NOT NULL) AND ISNULL(b.CancelStatusNorm, 0) = 0)
                OR (@VisitType = 2 AND ISNULL(b.IsOPDLike, 0) = 1 AND ISNULL(b.CancelStatusNorm, 0) = 0)
                OR (@VisitType = 3 AND ISNULL(b.IsDPVLike, 0) = 1)
            )
            AND (
                @SubtypeNorm = N''
                OR LOWER(ISNULL(b.PatientSubTypeName, N'')) = @SubtypeNorm
            )
            AND (
                @SearchLower = N''
                OR LOWER(ISNULL(b.BillNo, N'')) LIKE @SearchLike
                OR LOWER(ISNULL(b.Registration_No, N'')) LIKE @SearchLike
                OR LOWER(ISNULL(b.TypeOfVisit, N'')) LIKE @SearchLike
                OR LOWER(ISNULL(b.PatientSubTypeName, N'')) LIKE @SearchLike
                OR LOWER(ISNULL(b.DocNameRaw, N'')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.FilterDate AS DATE), 23)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.FilterDate AS DATE), 105)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.FilterDate AS DATE), 103)) LIKE @SearchLike
                OR LOWER(REPLACE(CONVERT(NVARCHAR(11), CAST(b.FilterDate AS DATE), 106), N' ', N'-')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(19), CAST(b.FilterDate AS DATETIME), 120)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.Submit_Date AS DATE), 23)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.Submit_Date AS DATE), 105)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.Submit_Date AS DATE), 103)) LIKE @SearchLike
                OR LOWER(REPLACE(CONVERT(NVARCHAR(11), CAST(b.Submit_Date AS DATE), 106), N' ', N'-')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(19), CAST(b.Submit_Date AS DATETIME), 120)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.BillDate AS DATE), 23)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.BillDate AS DATE), 105)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(10), CAST(b.BillDate AS DATE), 103)) LIKE @SearchLike
                OR LOWER(REPLACE(CONVERT(NVARCHAR(11), CAST(b.BillDate AS DATE), 106), N' ', N'-')) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(19), CAST(b.BillDate AS DATETIME), 120)) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.Bill_ID, 0))) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.CBill_ID, 0))) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.Visit_ID, 0))) LIKE @SearchLike
                OR LOWER(CONVERT(NVARCHAR(40), ISNULL(b.PatientID, 0))) LIKE @SearchLike
                OR LOWER(
                    CASE
                        WHEN COALESCE(b.VisitPatientID, b.PatientID) IS NULL THEN N''
                        ELSE ISNULL(dbo.fn_patientfullname(COALESCE(b.VisitPatientID, b.PatientID)), N'')
                    END
                ) LIKE @SearchLike
            )
        OPTION (RECOMPILE);

        SELECT
            s.CBill_ID,
            s.Visit_ID,
            s.PatientID,
            s.Bill_ID,
            s.BillDate,
            s.CBill_Date,
            s.Submit_Date,
            s.FilterDate,
            s.CAmount,
            s.DueAmount,
            s.Old_Bill_Amt,
            s.Old_Bill_Date,
            s.StatusRaw,
            s.IsFinalStatus,
            s.BillNo,
            s.VisitTypeID,
            s.TypeOfVisit,
            s.VisitDate,
            s.DischargeDate,
            s.VisitPatientID,
            s.VisitPatientTypeID,
            s.VisitPatientSubTypeID,
            s.DocInChargeID,
            s.DepartmentID,
            s.Registration_No,
            s.PatientSubTypeName,
            s.DocNameRaw,
            s.StatusLabel
        INTO #corp_bill_filtered
        FROM #corp_bill_scoped s
        WHERE
            @StatusNorm = N'all'
            OR (@StatusNorm = N'final' AND ISNULL(s.IsFinalStatus, 0) = 1)
            OR (@StatusNorm = N'nonfinal' AND ISNULL(s.IsFinalStatus, 0) = 0)
            OR (@StatusNorm = N'pending' AND LOWER(LTRIM(RTRIM(ISNULL(s.StatusLabel, N'')))) = N'submission pending')
            OR (@StatusNorm = N'notworked' AND LOWER(LTRIM(RTRIM(ISNULL(s.StatusLabel, N'')))) = N'not worked')
        OPTION (RECOMPILE);

        CREATE CLUSTERED INDEX IX_corp_bill_filtered_order
            ON #corp_bill_filtered(FilterDate DESC, CBill_ID DESC, Bill_ID DESC);

        SELECT
            filtered.total_rows,
            scoped.scoped_total_rows,
            scoped.final_submitted_count,
            scoped.submission_pending_count,
            scoped.not_worked_count,
            scoped.other_status_count
        FROM (SELECT COUNT(1) AS total_rows FROM #corp_bill_filtered) filtered
        CROSS JOIN (
            SELECT
                COUNT(1) AS scoped_total_rows,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) = N'final submitted' THEN 1 ELSE 0 END) AS final_submitted_count,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) = N'submission pending' THEN 1 ELSE 0 END) AS submission_pending_count,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) = N'not worked' THEN 1 ELSE 0 END) AS not_worked_count,
                SUM(CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(StatusLabel, N'')))) <> N'final submitted' THEN 1 ELSE 0 END) AS other_status_count
            FROM #corp_bill_scoped
        ) scoped;

        ;WITH numbered AS (
            SELECT
                f.*,
                ROW_NUMBER() OVER (ORDER BY f.FilterDate DESC, f.CBill_ID DESC, f.Bill_ID DESC) AS rn
            FROM #corp_bill_filtered f
        )
        SELECT
            n.CBill_ID,
            n.Visit_ID,
            n.PatientID,
            ISNULL(NULLIF(n.Registration_No, N''), N'Unknown') AS Registration_No,
            ISNULL(NULLIF(n.BillNo, N''), CONVERT(NVARCHAR(80), ISNULL(NULLIF(n.Bill_ID, 0), n.CBill_ID))) AS BillNo,
            CAST(ISNULL(n.CAmount, 0) AS FLOAT) AS CAmount,
            CAST(ISNULL(n.DueAmount, 0) AS FLOAT) AS DueAmount,
            CAST(ISNULL(n.Old_Bill_Amt, 0) AS FLOAT) AS Old_Bill_Amt,
            n.Old_Bill_Date,
            ISNULL(NULLIF(n.StatusLabel, N''), N'Submission Pending') AS [Status],
            n.BillDate,
            n.CBill_Date,
            n.Submit_Date,
            n.VisitDate,
            n.DischargeDate,
            CASE
                WHEN COALESCE(n.VisitPatientID, n.PatientID) IS NULL THEN N''
                ELSE ISNULL(dbo.fn_patientfullname(COALESCE(n.VisitPatientID, n.PatientID)), N'')
            END AS PatientName,
            ISNULL(n.TypeOfVisit, N'') AS TypeOfVisit,
            CASE
                WHEN n.VisitPatientTypeID IS NULL THEN N''
                ELSE ISNULL(dbo.fn_pat_type(n.VisitPatientTypeID), N'')
            END AS PatientType,
            CASE
                WHEN n.VisitPatientSubTypeID IS NULL THEN N''
                ELSE ISNULL(n.PatientSubTypeName, N'')
            END AS PatientSubType,
            CASE
                WHEN n.DocInChargeID IS NULL THEN ISNULL(n.DocNameRaw, N'')
                ELSE ISNULL(dbo.fn_doctorfirstname(n.DocInChargeID), N'')
            END AS DocInCharge,
            CASE
                WHEN n.DepartmentID IS NULL THEN N''
                ELSE ISNULL(dbo.fn_dept(n.DepartmentID), N'')
            END AS Dept
        FROM numbered n
        WHERE n.rn BETWEEN ((@Page - 1) * @PageSize + 1) AND (@Page * @PageSize)
        ORDER BY n.rn;

        SELECT DISTINCT
            LTRIM(RTRIM(ISNULL(PatientSubTypeName, N''))) AS patient_subtype
        FROM #corp_bill_filtered
        WHERE LTRIM(RTRIM(ISNULL(PatientSubTypeName, N''))) <> N''
        ORDER BY patient_subtype;
        """

        cur = conn.cursor()
        cur.execute(
            sql,
            [
                from_date,
                to_date,
                int(visit_type),
                str(status_filter or "all"),
                str(patient_subtype or ""),
                str(search_query or ""),
                int(page),
                int(page_size),
            ],
        )

        total_rows = 0
        scoped_total_rows = 0
        status_counts = {
            "final_submitted": 0,
            "submission_pending": 0,
            "not_worked": 0,
            "other_status": 0,
        }
        page_rows = []
        available_subtypes = []
        set_index = 0
        while True:
            if cur.description:
                rows = _corp_bill_summary_dict_rows_from_cursor(cur)
                if set_index == 0:
                    if rows:
                        first_meta = rows[0] or {}
                        total_rows = _corp_bill_summary_parse_int(first_meta.get("total_rows"), 0, 0, None)
                        scoped_total_rows = _corp_bill_summary_parse_int(first_meta.get("scoped_total_rows"), total_rows, 0, None)
                        status_counts = _corp_bill_summary_status_counts_from_meta(first_meta)
                elif set_index == 1:
                    page_rows = rows
                elif set_index == 2:
                    for rec in rows:
                        val = str(rec.get("patient_subtype") or "").strip()
                        if val:
                            available_subtypes.append(val)
                set_index += 1
            if not cur.nextset():
                break

        if available_subtypes:
            dedup = []
            seen = set()
            for val in available_subtypes:
                key = val.lower()
                if key in seen:
                    continue
                seen.add(key)
                dedup.append(val)
            available_subtypes = dedup

        total_pages = max(1, (int(total_rows) + int(page_size) - 1) // int(page_size)) if int(page_size) > 0 else 1
        db_ms = round((time.perf_counter() - started) * 1000.0, 1)
        return {
            "status": "success",
            "rows": page_rows,
            "meta": {
                "page": int(page),
                "page_size": int(page_size),
                "total_rows": int(total_rows),
                "scoped_total_rows": int(scoped_total_rows),
                "total_pages": int(total_pages),
                "query_engine": "python_sql",
                "date_scope_label": _corp_bill_summary_date_scope_label("SHARPSIGHT"),
                "status_counts": status_counts,
                "available_patient_subtypes": available_subtypes,
                "timings": {"db_ms": float(db_ms), "total_ms": float(db_ms)},
            },
        }
    except Exception as e:
        return {"status": "error", "message": f"Failed to fetch SharpSight corporate bill summary page: {e}"}


def fetch_corporate_bill_summary_page(
    unit: str,
    from_date: str | None = None,
    to_date: str | None = None,
    visit_type: int = 0,
    status_filter: str = "all",
    patient_subtype: str = "",
    search_query: str = "",
    page: int = 1,
    page_size: int = 25,
    prefer_sp: bool = True,
):
    unit_key = str(unit or "").strip().upper()
    if unit_key not in {"AHL", "ACI", "SHARPSIGHT"}:
        return {"status": "error", "message": "Unit not supported for paged corporate bill summary"}

    vt = _corp_bill_summary_parse_int(visit_type, 0, 0, 3)
    pg = _corp_bill_summary_parse_int(page, 1, 1, None)
    pg_size = _corp_bill_summary_parse_int(page_size, 25, 10, 200)
    sf = _corp_bill_summary_norm_status_filter(status_filter)
    subtype = str(patient_subtype or "").strip()
    q = str(search_query or "").strip()
    from_iso = _corp_bill_summary_parse_date_or_none(from_date)
    to_iso = _corp_bill_summary_parse_date_or_none(to_date)

    conn = get_sql_connection(unit_key)
    if not conn:
        return {"status": "error", "message": f"Could not connect to {unit_key} for corporate bill summary"}
    try:
        if _is_sharpsight_unit(unit_key):
            return _fetch_sharpsight_corporate_bill_summary_page_sql(
                conn,
                from_date=from_iso,
                to_date=to_iso,
                visit_type=vt,
                status_filter=sf,
                patient_subtype=subtype,
                search_query=q,
                page=pg,
                page_size=pg_size,
            )

        if bool(prefer_sp) and sf in {"all", "final", "nonfinal"}:
            sp_payload = _fetch_corporate_bill_summary_page_sp(
                conn,
                from_date=from_iso,
                to_date=to_iso,
                visit_type=vt,
                status_filter=sf,
                patient_subtype=subtype,
                search_query=q,
                page=pg,
                page_size=pg_size,
            )
            if isinstance(sp_payload, dict) and str(sp_payload.get("status") or "").lower() == "success":
                return sp_payload

        return _fetch_corporate_bill_summary_page_sql(
            conn,
            from_date=from_iso,
            to_date=to_iso,
            visit_type=vt,
            status_filter=sf,
            patient_subtype=subtype,
            search_query=q,
            page=pg,
            page_size=pg_size,
        )
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_corporate_bill_summary_rows_for_export(
    unit: str,
    from_date: str | None = None,
    to_date: str | None = None,
    visit_type: int = 0,
    status_filter: str = "all",
    patient_subtype: str = "",
    search_query: str = "",
    prefer_sp: bool = True,
):
    unit_key = str(unit or "").strip().upper()
    if unit_key not in {"AHL", "ACI", "SHARPSIGHT"}:
        return {"status": "error", "message": "Unit not supported for this export flow"}

    vt = _corp_bill_summary_parse_int(visit_type, 0, 0, 3)
    sf = _corp_bill_summary_norm_status_filter(status_filter)
    subtype = str(patient_subtype or "").strip()
    q = str(search_query or "").strip()
    from_iso = _corp_bill_summary_parse_date_or_none(from_date)
    to_iso = _corp_bill_summary_parse_date_or_none(to_date)
    _ = prefer_sp  # Kept for call compatibility; export uses the full-filter SQL path.
    # Excel allows 1,048,576 rows per sheet; keep room for title/header rows.
    export_page_size = 1_048_000

    started = time.perf_counter()
    conn = get_sql_connection(unit_key)
    if not conn:
        return {"status": "error", "message": f"Could not connect to {unit_key} for corporate bill summary export"}
    try:
        if _is_sharpsight_unit(unit_key):
            payload = _fetch_sharpsight_corporate_bill_summary_page_sql(
                conn,
                from_date=from_iso,
                to_date=to_iso,
                visit_type=vt,
                status_filter=sf,
                patient_subtype=subtype,
                search_query=q,
                page=1,
                page_size=export_page_size,
            )
        else:
            # Use the local SQL path for export because it supports every status
            # filter and the Submit-Date-first date scope in one database pass.
            payload = _fetch_corporate_bill_summary_page_sql(
                conn,
                from_date=from_iso,
                to_date=to_iso,
                visit_type=vt,
                status_filter=sf,
                patient_subtype=subtype,
                search_query=q,
                page=1,
                page_size=export_page_size,
            )
    finally:
        try:
            conn.close()
        except Exception:
            pass

    if not isinstance(payload, dict) or str(payload.get("status") or "").lower() != "success":
        return payload if isinstance(payload, dict) else {"status": "error", "message": "Failed to fetch rows for export"}

    all_rows = payload.get("rows")
    all_rows = all_rows if isinstance(all_rows, list) else []
    aggregate_meta = payload.get("meta") if isinstance(payload.get("meta"), dict) else {}
    source_total_rows = _corp_bill_summary_parse_int(aggregate_meta.get("total_rows"), len(all_rows), 0, None)
    if source_total_rows > len(all_rows):
        return {
            "status": "error",
            "message": (
                f"Export has {source_total_rows:,} rows, which is above Excel's single-sheet limit. "
                "Please narrow the date range or filters and export again."
            ),
        }

    timings = aggregate_meta.get("timings") if isinstance(aggregate_meta.get("timings"), dict) else {}
    timings["export_fetch_ms"] = round((time.perf_counter() - started) * 1000.0, 1)

    return {
        "status": "success",
        "rows": all_rows,
        "meta": {
            "total_rows": int(len(all_rows)),
            "scoped_total_rows": _corp_bill_summary_parse_int(aggregate_meta.get("scoped_total_rows"), len(all_rows), 0, None),
            "total_pages_fetched": 1,
            "query_engine": str(aggregate_meta.get("query_engine") or ""),
            "date_scope_label": str(aggregate_meta.get("date_scope_label") or _corp_bill_summary_date_scope_label(unit_key)),
            "status_counts": _corp_bill_summary_status_counts_from_meta(aggregate_meta.get("status_counts") or aggregate_meta),
            "available_patient_subtypes": aggregate_meta.get("available_patient_subtypes") if isinstance(aggregate_meta.get("available_patient_subtypes"), list) else [],
            "timings": timings,
        },
    }


# ===================== Corporate Receipt Reconciliation =====================
CORP_RECON_WRITEOFF_CANDIDATES = [
    "WriteOffAmt",
    "WriteOffAmount",
    "WriteOff_Amt",
    "Write_Off_Amt",
    "WriteOff",
    "writeoffAmt",
    "writeoffamount",
]
CORP_RECON_AUDITED_CANDIDATES = [
    "Audited",
    "IsAudited",
    "AuditOk",
    "AuditFlag",
]
_CORP_RECON_SCHEMA_READY_UNITS = set()
_CORP_RECON_SCHEMA_READY_META = {}
_CORP_RECON_SCHEMA_READY_LOCK = Lock()
_CORP_RECON_PROC_META = {}
_CORP_RECON_PROC_META_LOCK = Lock()
_CORP_RECON_RECEIPT_SOURCE_READY = {}
_CORP_RECON_RECEIPT_SOURCE_READY_LOCK = Lock()


def _ensure_corporate_writeoff_columns_conn(conn) -> dict:
    """
    Ensure write-off amount column exists in:
      - dbo.Corp_Receipt_Mst
      - dbo.CorpOpening
    Returns discovered column names and whether a new column was added.
    """
    result = {
        "receipt_column": None,
        "opening_column": None,
        "receipt_added": False,
        "opening_added": False,
    }
    if not conn:
        return result

    def _table_cols_map(table_name: str) -> dict:
        return _table_columns_map_conn(conn, table_name)

    def _pick_col(cols_map: dict) -> str | None:
        for cand in CORP_RECON_WRITEOFF_CANDIDATES:
            key = str(cand).strip().lower()
            if key in cols_map:
                return cols_map[key]
        return None

    def _ensure_for_table(table_name: str, result_col_key: str, result_added_key: str):
        cols_map = _table_cols_map(table_name)
        col_name = _pick_col(cols_map)
        if not col_name:
            try:
                cur = conn.cursor()
                cur.execute(f"ALTER TABLE {table_name} ADD [WriteOffAmt] FLOAT NULL")
                conn.commit()
                result[result_added_key] = True
            except Exception:
                try:
                    conn.rollback()
                except Exception:
                    pass
            cols_map = _table_cols_map(table_name)
            col_name = _pick_col(cols_map)
        result[result_col_key] = col_name

    _ensure_for_table("dbo.Corp_Receipt_Mst", "receipt_column", "receipt_added")
    _ensure_for_table("dbo.CorpOpening", "opening_column", "opening_added")
    return result


def _ensure_corporate_bill_audited_column_conn(conn) -> dict:
    """
    Ensure audit approval flag column exists in dbo.Corp_Bill_Mst.
    Returns discovered column name and whether a new column was added.
    """
    result = {
        "bill_audited_column": None,
        "bill_audited_added": False,
    }
    if not conn:
        return result

    def _table_cols_map(table_name: str) -> dict:
        return _table_columns_map_conn(conn, table_name)

    def _pick_col(cols_map: dict) -> str | None:
        for cand in CORP_RECON_AUDITED_CANDIDATES:
            key = str(cand or "").strip().lower()
            if key and key in cols_map:
                return cols_map[key]
        return None

    cols_map = _table_cols_map("dbo.Corp_Bill_Mst")
    col_name = _pick_col(cols_map)
    if not col_name:
        try:
            cur = conn.cursor()
            cur.execute("ALTER TABLE dbo.Corp_Bill_Mst ADD [Audited] BIT NULL")
            conn.commit()
            result["bill_audited_added"] = True
        except Exception:
            try:
                conn.rollback()
            except Exception:
                pass
        cols_map = _table_cols_map("dbo.Corp_Bill_Mst")
        col_name = _pick_col(cols_map)
    result["bill_audited_column"] = col_name
    return result


def _ensure_corporate_recon_schema_once(conn, unit: str):
    unit_key = str(unit or "").strip().upper()
    if not unit_key:
        unit_key = "DEFAULT"

    with _CORP_RECON_SCHEMA_READY_LOCK:
        if unit_key in _CORP_RECON_SCHEMA_READY_UNITS:
            cached = _CORP_RECON_SCHEMA_READY_META.get(unit_key)
            if isinstance(cached, dict):
                return {
                    "writeoff": dict((cached.get("writeoff") or {})),
                    "audited": dict((cached.get("audited") or {})),
                }
            return None

    writeoff_info = _ensure_corporate_writeoff_columns_conn(conn)
    audited_info = _ensure_corporate_bill_audited_column_conn(conn)
    schema_info = {
        "writeoff": dict(writeoff_info or {}),
        "audited": dict(audited_info or {}),
    }

    with _CORP_RECON_SCHEMA_READY_LOCK:
        _CORP_RECON_SCHEMA_READY_UNITS.add(unit_key)
        _CORP_RECON_SCHEMA_READY_META[unit_key] = schema_info

    return {
        "writeoff": dict((schema_info.get("writeoff") or {})),
        "audited": dict((schema_info.get("audited") or {})),
    }


def _ensure_corporate_receipt_source_ready_once(conn, unit: str) -> dict:
    unit_key = str(unit or "").strip().upper() or "DEFAULT"
    with _CORP_RECON_RECEIPT_SOURCE_READY_LOCK:
        cached = _CORP_RECON_RECEIPT_SOURCE_READY.get(unit_key)
        if isinstance(cached, dict):
            return dict(cached)

    info = _ensure_corporate_receipt_source_column_conn(conn) or {}
    source_col = str(info.get("column") or "").strip() or None
    if source_col:
        _backfill_corporate_receipt_source_conn(conn, unit, source_col)

    payload = {"column": source_col}
    with _CORP_RECON_RECEIPT_SOURCE_READY_LOCK:
        _CORP_RECON_RECEIPT_SOURCE_READY[unit_key] = dict(payload)
    return dict(payload)


def _get_corporate_recon_proc_meta(conn, unit: str) -> dict:
    unit_key = str(unit or "").strip().upper() or "DEFAULT"
    with _CORP_RECON_PROC_META_LOCK:
        cached = _CORP_RECON_PROC_META.get(unit_key)
        if isinstance(cached, dict):
            return dict(cached)

    schema_info = _ensure_corporate_recon_schema_once(conn, unit) or {}
    writeoff_info = dict((schema_info or {}).get("writeoff") or {})
    audited_info = dict((schema_info or {}).get("audited") or {})

    bill_cols_map = _table_columns_map_conn(conn, "dbo.Corp_Bill_Mst")
    mst_cols_map = _table_columns_map_conn(conn, "dbo.Corp_Receipt_Mst")
    dtl_cols_map = _table_columns_map_conn(conn, "dbo.Corp_Receipt_Dtl")

    def _pick_from_map(cols_map: dict, candidates: list[str]) -> str | None:
        for cand in candidates or []:
            key = str(cand or "").strip().lower()
            if key and key in cols_map:
                return cols_map[key]
        return None

    receipt_source_info = _ensure_corporate_receipt_source_ready_once(conn, unit) or {}
    receipt_source_col = str(receipt_source_info.get("column") or "").strip() or _pick_from_map(dtl_cols_map, ["BillSourceKey"])
    receipt_writeoff_col = (writeoff_info.get("receipt_column") or "").strip() or None
    opening_writeoff_col = (writeoff_info.get("opening_column") or "").strip() or None
    bill_audited_col = (audited_info.get("bill_audited_column") or "").strip() or None
    bill_updated_by_col = _pick_from_map(bill_cols_map, ["Updated_By", "UpdatedBy", "updated_by"])
    bill_updated_on_col = _pick_from_map(
        bill_cols_map,
        ["Updated_On", "UpdatedOn", "ModifiedOn", "accUpdatedDate", "AccUpdatedDate"],
    )
    dtl_receipt_date_col = _pick_from_map(dtl_cols_map, ["ReceiptDate"])
    dtl_inserted_by_col = _pick_from_map(dtl_cols_map, ["insertedBy", "InsertedBy", "Inserted_By"])
    rebate_col = _pick_from_map(mst_cols_map, ["rebateDiscountAmt", "RebateDiscountAmt"])
    tds_col = _pick_from_map(mst_cols_map, ["TDSAmt", "TdsAmt", "tdsAmt", "TDS_AMT"])

    payload = {
        "receipt_source_col": receipt_source_col,
        "receipt_writeoff_col": receipt_writeoff_col,
        "opening_writeoff_col": opening_writeoff_col,
        "bill_audited_col": bill_audited_col,
        "bill_updated_by_col": bill_updated_by_col,
        "bill_updated_on_col": bill_updated_on_col,
        "dtl_receipt_date_col": dtl_receipt_date_col,
        "dtl_inserted_by_col": dtl_inserted_by_col,
        "rebate_col": rebate_col,
        "tds_col": tds_col,
        "canonical_required": {
            "receipt_source_col": (receipt_source_col or "").strip().lower() == "billsourcekey",
            "receipt_writeoff_col": (receipt_writeoff_col or "").strip().lower() == "writeoffamt",
            "opening_writeoff_col": (opening_writeoff_col or "").strip().lower() == "writeoffamt",
            "bill_audited_col": (bill_audited_col or "").strip().lower() == "audited",
            "rebate_col": (rebate_col or "").strip().lower() == "rebatediscountamt",
            "tds_col": (tds_col or "").strip().lower() == "tdsamt",
        },
    }

    with _CORP_RECON_PROC_META_LOCK:
        _CORP_RECON_PROC_META[unit_key] = dict(payload)
    return dict(payload)


def fetch_corporate_reconciliation_page(
    unit: str,
    *,
    cutoff_date: str = "2025-03-31",
    bill_from: str | None = None,
    bill_to: str | None = None,
    receipt_from: str | None = None,
    receipt_to: str | None = None,
    include_cancelled: bool = False,
    q: str = "",
    kpi_filter: str = "",
    bill_source: str = "",
    patient_subtype: str = "",
    sort_by: str = "balance_all_time",
    sort_dir: str = "desc",
    page: int = 1,
    page_size: int = 25,
):
    """
    Preferred fast path for corporate reconciliation.
    Calls SQL stored procedure dbo.usp_CorpRecon_Page when available.

    Expected proc contract: returns one row with JSON columns:
      rows_json, receipt_details_json, kpis_json, meta_json, suspense_json (optional)
    """
    conn = get_sql_connection(unit)
    if not conn:
        return None

    try:
        def _reconcile_active_writeoff_targets(rows_payload, details_payload):
            if not isinstance(rows_payload, list) or not rows_payload:
                return rows_payload
            details_map = details_payload if isinstance(details_payload, dict) else {}

            def _row_bill_key(row: dict) -> str:
                bill_key = str((row or {}).get("bill_key") or "").strip()
                if bill_key:
                    return bill_key
                source_key = str(
                    (row or {}).get("bill_source_key")
                    or (row or {}).get("bill_source")
                    or ""
                ).strip().upper()
                bill_id_val = row.get("bill_id")
                try:
                    bill_id_int = int(float(bill_id_val))
                except Exception:
                    return ""
                if source_key:
                    return f"BILL-{source_key}-{bill_id_int}"
                return f"BILL-{bill_id_int}"

            def _best_active_receipt_id(detail_rows) -> int | None:
                if not isinstance(detail_rows, list) or not detail_rows:
                    return None
                best_candidate = None
                for rec in detail_rows:
                    if not isinstance(rec, dict):
                        continue
                    try:
                        cancel_status = int(float(rec.get("cancel_status") or 0))
                    except Exception:
                        cancel_status = 0
                    if cancel_status == 1:
                        continue
                    try:
                        receipt_id = int(float(rec.get("receipt_id") or 0))
                    except Exception:
                        receipt_id = 0
                    if receipt_id <= 0:
                        continue
                    receipt_date = str(rec.get("receipt_date") or "").strip()
                    candidate = (receipt_date, receipt_id)
                    if best_candidate is None or candidate > best_candidate:
                        best_candidate = candidate
                return int(best_candidate[1]) if best_candidate else None

            for row in rows_payload:
                if not isinstance(row, dict):
                    continue
                source_key = str(
                    row.get("bill_source_key")
                    or row.get("bill_source")
                    or ""
                ).strip().upper()
                if source_key != _corp_receipt_bill_source_key_for_unit(unit):
                    continue
                row["writeoff_target_receipt_id"] = _best_active_receipt_id(
                    details_map.get(_row_bill_key(row))
                )
            return rows_payload

        unit_key = str(unit or "").strip().upper()
        if unit_key in {"AHL", "ACI"}:
            receipt_writeoff_col = "WriteOffAmt"
            opening_writeoff_col = "WriteOffAmt"
            bill_audited_col = "Audited"
            bill_updated_by_col = "Updated_By"
            bill_updated_on_col = "Updated_On"
            dtl_receipt_date_col = "ReceiptDate"
            dtl_inserted_by_col = "insertedBy"
            rebate_col = "rebateDiscountAmt"
            tds_col = "TDSAmt"
        elif unit_key == "SHARPSIGHT":
            schema_info = _ensure_corporate_writeoff_columns_conn(conn) or {}
            bill_cols_map = _table_columns_map_conn(conn, "dbo.Corp_Bill_Mst_AHL")
            mst_cols_map = _table_columns_map_conn(conn, "dbo.Corp_Receipt_Mst")
            dtl_cols_map = _table_columns_map_conn(conn, "dbo.Corp_Receipt_Dtl")

            def _pick_from_map(cols_map: dict, candidates: list[str]) -> str | None:
                for cand in candidates or []:
                    key = str(cand or "").strip().lower()
                    if key and key in cols_map:
                        return cols_map[key]
                return None

            receipt_writeoff_col = (
                str((schema_info or {}).get("receipt_column") or "").strip()
                or _pick_from_map(mst_cols_map, CORP_RECON_WRITEOFF_CANDIDATES)
                or "WriteOffAmt"
            )
            opening_writeoff_col = str((schema_info or {}).get("opening_column") or "").strip() or None
            bill_audited_col = None
            bill_updated_by_col = _pick_from_map(
                bill_cols_map,
                ["accUserId", "Updated_By", "UpdatedBy", "updated_by"],
            )
            bill_updated_on_col = _pick_from_map(
                bill_cols_map,
                ["accUpdatedDate", "Updated_On", "UpdatedOn", "ModifiedOn", "AccUpdatedDate"],
            )
            dtl_receipt_date_col = _pick_from_map(dtl_cols_map, ["ReceiptDate"])
            dtl_inserted_by_col = _pick_from_map(dtl_cols_map, ["insertedBy", "InsertedBy", "Inserted_By"])
            rebate_col = _pick_from_map(mst_cols_map, ["rebateDiscountAmt", "RebateDiscountAmt"])
            tds_col = _pick_from_map(mst_cols_map, ["TDSAmt", "TdsAmt", "tdsAmt", "TDS_AMT"])
        else:
            _ensure_corporate_receipt_source_ready_once(conn, unit)
            proc_meta = _get_corporate_recon_proc_meta(conn, unit) or {}
            receipt_writeoff_col = proc_meta.get("receipt_writeoff_col")
            opening_writeoff_col = proc_meta.get("opening_writeoff_col")
            bill_audited_col = proc_meta.get("bill_audited_col")
            bill_updated_by_col = proc_meta.get("bill_updated_by_col")
            bill_updated_on_col = proc_meta.get("bill_updated_on_col")
            dtl_receipt_date_col = proc_meta.get("dtl_receipt_date_col")
            dtl_inserted_by_col = proc_meta.get("dtl_inserted_by_col")
            rebate_col = proc_meta.get("rebate_col")
            tds_col = proc_meta.get("tds_col")
            canonical_required = dict(proc_meta.get("canonical_required") or {})
            if not all(canonical_required.values()):
                return None

        kpi_filter_key = str(kpi_filter or "").strip().lower()

        sql = """
        EXEC dbo.usp_CorpRecon_Page
             @CutoffDate = ?,
             @BillFrom = ?,
             @BillTo = ?,
             @ReceiptFrom = ?,
             @ReceiptTo = ?,
             @IncludeCancelled = ?,
             @Q = ?,
             @BillSource = ?,
             @PatientSubtype = ?,
             @SortBy = ?,
             @SortDir = ?,
             @Page = ?,
             @PageSize = ?,
             @ReceiptWriteoffColumn = ?,
             @OpeningWriteoffColumn = ?,
             @BillAuditedColumn = ?,
             @BillUpdatedByColumn = ?,
             @BillUpdatedOnColumn = ?,
             @DtlReceiptDateColumn = ?,
             @DtlInsertedByColumn = ?,
             @RebateDiscountColumn = ?,
             @TdsAmountColumn = ?
        """
        params = [
            cutoff_date,
            bill_from or None,
            bill_to or None,
            receipt_from or None,
            receipt_to or None,
            1 if include_cancelled else 0,
            str(q or ""),
            str(bill_source or ""),
            str(patient_subtype or ""),
            str(sort_by or "balance_all_time"),
            str(sort_dir or "desc"),
            int(page or 1),
            int(page_size or 25),
            receipt_writeoff_col,
            opening_writeoff_col,
            bill_audited_col,
            bill_updated_by_col,
            bill_updated_on_col,
            dtl_receipt_date_col,
            dtl_inserted_by_col,
            rebate_col,
            tds_col,
        ]
        if kpi_filter_key:
            sql += ",\n             @KpiFilter = ?"
            params.append(kpi_filter_key)

        cur = conn.cursor()
        cur.execute(sql, params)

        result_sets = []
        while True:
            if cur.description:
                cols = [str(c[0]).strip() for c in cur.description]
                rows = cur.fetchall()
                result_sets.append(
                    [
                        {cols[i]: row[i] for i in range(len(cols))}
                        for row in rows
                    ]
                )
            if not cur.nextset():
                break

        if not result_sets:
            return None

        first_set = result_sets[0]
        first_cols = set(first_set[0].keys()) if first_set and isinstance(first_set[0], dict) else set()
        json_contract = {"rows_json", "receipt_details_json", "kpis_json", "meta_json"}
        if json_contract.issubset(first_cols):
            row = first_set[0] if first_set else {}

            def _load_json(name: str, default):
                raw = row.get(name)
                if raw in (None, ""):
                    return default
                try:
                    return json.loads(raw)
                except Exception:
                    return default

            def _unwrap_obj(value, default):
                if isinstance(value, dict):
                    return value
                if isinstance(value, list) and value and isinstance(value[0], dict):
                    return value[0]
                return default

            rows_payload = _load_json("rows_json", [])
            if not isinstance(rows_payload, list):
                rows_payload = []

            details_payload = _load_json("receipt_details_json", {})
            if isinstance(details_payload, list):
                details_map = {}
                for rec in details_payload:
                    if not isinstance(rec, dict):
                        continue
                    bill_key = str(rec.get("bill_key") or "").strip()
                    if not bill_key:
                        bill_id_val = rec.get("bill_id")
                        source_key = str(
                            rec.get("receipt_bill_source_key")
                            or rec.get("bill_source_key")
                            or ""
                        ).strip().upper()
                        try:
                            if source_key:
                                bill_key = f"BILL-{source_key}-{int(bill_id_val)}"
                            else:
                                bill_key = f"BILL-{int(bill_id_val)}"
                        except Exception:
                            bill_key = ""
                    if not bill_key:
                        continue
                    rec_copy = dict(rec)
                    rec_copy.pop("bill_key", None)
                    details_map.setdefault(bill_key, []).append(rec_copy)
                details_payload = details_map
            elif not isinstance(details_payload, dict):
                details_payload = {}

            kpis_payload = _unwrap_obj(_load_json("kpis_json", {}), {})

            meta_payload = _unwrap_obj(_load_json("meta_json", {}), {})
            if not isinstance(meta_payload, dict):
                meta_payload = {}
            for arr_key in ("available_sources", "available_patient_subtypes"):
                arr_val = meta_payload.get(arr_key)
                if isinstance(arr_val, str):
                    try:
                        parsed_arr = json.loads(arr_val)
                        if isinstance(parsed_arr, list):
                            meta_payload[arr_key] = parsed_arr
                    except Exception:
                        pass
            if not isinstance(meta_payload.get("available_sources"), list):
                meta_payload["available_sources"] = []
            if not isinstance(meta_payload.get("available_patient_subtypes"), list):
                meta_payload["available_patient_subtypes"] = []
            meta_payload.setdefault("has_receipt_writeoff_column", bool(receipt_writeoff_col))
            meta_payload.setdefault("has_opening_writeoff_column", bool(opening_writeoff_col))
            meta_payload.setdefault("has_bill_audited_column", bool(bill_audited_col))
            meta_payload.setdefault("used_sql_sp", True)
            rows_payload = _reconcile_active_writeoff_targets(rows_payload, details_payload)

            out = {
                "status": "success",
                "unit": str(unit or "").upper(),
                "cutoff_date": cutoff_date,
                "rows": rows_payload,
                "receipt_details": details_payload,
                "kpis": kpis_payload,
                "meta": meta_payload,
            }
            suspense_obj = _unwrap_obj(_load_json("suspense_json", None), None)
            if isinstance(suspense_obj, dict):
                out["suspense"] = suspense_obj
            return out

        rows_payload = first_set if isinstance(first_set, list) else []
        details_rows = result_sets[1] if len(result_sets) > 1 and isinstance(result_sets[1], list) else []
        kpis_payload = result_sets[2][0] if len(result_sets) > 2 and result_sets[2] else {}
        meta_payload = result_sets[3][0] if len(result_sets) > 3 and result_sets[3] else {}
        sources_rows = result_sets[4] if len(result_sets) > 4 and isinstance(result_sets[4], list) else []
        subtypes_rows = result_sets[5] if len(result_sets) > 5 and isinstance(result_sets[5], list) else []
        subtype_summary_rows = []
        suspense_row = {}
        if len(result_sets) > 6 and isinstance(result_sets[6], list):
            rs7 = result_sets[6]
            rs7_first = rs7[0] if rs7 else {}
            if isinstance(rs7_first, dict) and "suspense_count" in rs7_first:
                suspense_row = rs7_first
            else:
                subtype_summary_rows = rs7
                if len(result_sets) > 7 and isinstance(result_sets[7], list) and result_sets[7]:
                    rs8_first = result_sets[7][0]
                    if isinstance(rs8_first, dict):
                        suspense_row = rs8_first

        details_payload = {}
        for rec in details_rows:
            if not isinstance(rec, dict):
                continue
            bill_key = str(rec.get("bill_key") or "").strip()
            if not bill_key:
                bill_id_val = rec.get("bill_id")
                source_key = str(
                    rec.get("receipt_bill_source_key")
                    or rec.get("bill_source_key")
                    or ""
                ).strip().upper()
                try:
                    if source_key:
                        bill_key = f"BILL-{source_key}-{int(bill_id_val)}"
                    else:
                        bill_key = f"BILL-{int(bill_id_val)}"
                except Exception:
                    bill_key = ""
            if not bill_key:
                continue
            rec_copy = dict(rec)
            rec_copy.pop("bill_key", None)
            details_payload.setdefault(bill_key, []).append(rec_copy)

        if not isinstance(kpis_payload, dict):
            kpis_payload = {}
        if not isinstance(meta_payload, dict):
            meta_payload = {}

        meta_payload["available_sources"] = [
            str((r or {}).get("bill_source") or "").strip()
            for r in sources_rows
            if str((r or {}).get("bill_source") or "").strip()
        ]
        meta_payload["available_patient_subtypes"] = [
            str((r or {}).get("patient_subtype") or "").strip()
            for r in subtypes_rows
            if str((r or {}).get("patient_subtype") or "").strip()
        ]
        normalized_subtype_summary = []
        for row in (subtype_summary_rows or []):
            if not isinstance(row, dict):
                continue
            subtype_name = str((row or {}).get("subtype") or "").strip()
            if not subtype_name:
                continue
            try:
                bills_val = int((row or {}).get("bills") or 0)
            except Exception:
                bills_val = 0
            has_corporate_col = "corporate_bills" in row
            has_opening_col = "opening_bills" in row
            try:
                corporate_val = int((row or {}).get("corporate_bills") or 0)
            except Exception:
                corporate_val = 0
            try:
                opening_val = int((row or {}).get("opening_bills") or 0)
            except Exception:
                opening_val = 0
            if bills_val > 0 and not has_corporate_col and not has_opening_col:
                # Backward-compatible default for older proc versions.
                corporate_val = bills_val
                opening_val = 0
            try:
                settled_val = int((row or {}).get("settled_count") or 0)
            except Exception:
                settled_val = 0
            has_settled_corp_col = "settled_corporate_count" in row
            has_settled_open_col = "settled_opening_count" in row
            try:
                settled_corporate_val = int((row or {}).get("settled_corporate_count") or 0)
            except Exception:
                settled_corporate_val = 0
            try:
                settled_opening_val = int((row or {}).get("settled_opening_count") or 0)
            except Exception:
                settled_opening_val = 0
            if settled_val > 0 and not has_settled_corp_col and not has_settled_open_col:
                settled_corporate_val = settled_val
                settled_opening_val = 0
            try:
                partial_val = int((row or {}).get("partial_count") or 0)
            except Exception:
                partial_val = 0
            has_partial_corp_col = "partial_corporate_count" in row
            has_partial_open_col = "partial_opening_count" in row
            try:
                partial_corporate_val = int((row or {}).get("partial_corporate_count") or 0)
            except Exception:
                partial_corporate_val = 0
            try:
                partial_opening_val = int((row or {}).get("partial_opening_count") or 0)
            except Exception:
                partial_opening_val = 0
            if partial_val > 0 and not has_partial_corp_col and not has_partial_open_col:
                partial_corporate_val = partial_val
                partial_opening_val = 0
            try:
                unpaid_val = int((row or {}).get("unpaid_count") or 0)
            except Exception:
                unpaid_val = 0
            has_unpaid_corp_col = "unpaid_corporate_count" in row
            has_unpaid_open_col = "unpaid_opening_count" in row
            try:
                unpaid_corporate_val = int((row or {}).get("unpaid_corporate_count") or 0)
            except Exception:
                unpaid_corporate_val = 0
            try:
                unpaid_opening_val = int((row or {}).get("unpaid_opening_count") or 0)
            except Exception:
                unpaid_opening_val = 0
            if unpaid_val > 0 and not has_unpaid_corp_col and not has_unpaid_open_col:
                unpaid_corporate_val = unpaid_val
                unpaid_opening_val = 0
            try:
                overpaid_val = int((row or {}).get("overpaid_count") or 0)
            except Exception:
                overpaid_val = 0
            has_overpaid_corp_col = "overpaid_corporate_count" in row
            has_overpaid_open_col = "overpaid_opening_count" in row
            try:
                overpaid_corporate_val = int((row or {}).get("overpaid_corporate_count") or 0)
            except Exception:
                overpaid_corporate_val = 0
            try:
                overpaid_opening_val = int((row or {}).get("overpaid_opening_count") or 0)
            except Exception:
                overpaid_opening_val = 0
            if overpaid_val > 0 and not has_overpaid_corp_col and not has_overpaid_open_col:
                overpaid_corporate_val = overpaid_val
                overpaid_opening_val = 0
            try:
                closing_qty_val = int((row or {}).get("closing_qty") or 0)
            except Exception:
                closing_qty_val = 0
            if "closing_qty" not in row:
                closing_qty_val = partial_val + unpaid_val + overpaid_val
            try:
                closing_val = float((row or {}).get("closing_balance") or 0.0)
            except Exception:
                closing_val = 0.0
            normalized_subtype_summary.append(
                {
                    "subtype": subtype_name,
                    "bills": bills_val,
                    "bill_amount": float((row or {}).get("bill_amount") or 0.0),
                    "corporate_bills": corporate_val,
                    "opening_bills": opening_val,
                    "receipt_all_time": float((row or {}).get("receipt_all_time") or 0.0),
                    "tds_all_time": float((row or {}).get("tds_all_time") or 0.0),
                    "rebate_discount_all_time": float((row or {}).get("rebate_discount_all_time") or 0.0),
                    "writeoff_all_time": float((row or {}).get("writeoff_all_time") or 0.0),
                    "settled_total_all_time": float((row or {}).get("settled_total_all_time") or 0.0),
                    "settled_count": settled_val,
                    "settled_corporate_count": settled_corporate_val,
                    "settled_opening_count": settled_opening_val,
                    "partial_count": partial_val,
                    "partial_corporate_count": partial_corporate_val,
                    "partial_opening_count": partial_opening_val,
                    "unpaid_count": unpaid_val,
                    "unpaid_corporate_count": unpaid_corporate_val,
                    "unpaid_opening_count": unpaid_opening_val,
                    "overpaid_count": overpaid_val,
                    "overpaid_corporate_count": overpaid_corporate_val,
                    "overpaid_opening_count": overpaid_opening_val,
                    "closing_qty": closing_qty_val,
                    "closing_balance": closing_val,
                }
            )
        meta_payload["subtype_closing_summary"] = normalized_subtype_summary
        meta_payload["subtype_closing_scope"] = "full_filter" if normalized_subtype_summary else "page"
        meta_payload.setdefault("has_receipt_writeoff_column", bool(receipt_writeoff_col))
        meta_payload.setdefault("has_opening_writeoff_column", bool(opening_writeoff_col))
        meta_payload.setdefault("has_bill_audited_column", bool(bill_audited_col))
        meta_payload.setdefault("used_sql_sp", True)
        meta_payload.setdefault("suspense_count", int((suspense_row or {}).get("suspense_count") or 0))
        rows_payload = _reconcile_active_writeoff_targets(rows_payload, details_payload)

        out = {
            "status": "success",
            "unit": str(unit or "").upper(),
            "cutoff_date": cutoff_date,
            "rows": rows_payload,
            "receipt_details": details_payload,
            "kpis": kpis_payload,
            "meta": meta_payload,
        }
        if suspense_row:
            out["suspense"] = {
                "meta": {
                    "count": int((suspense_row or {}).get("suspense_count") or 0),
                    "reason": str((suspense_row or {}).get("suspense_reason") or ""),
                }
            }
        return out
    except Exception:
        # Silent fallback to python path when proc is absent or incompatible.
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_corporate_reconciliation_action_page(
    unit: str,
    *,
    action_mode: str,
    q: str = "",
    bill_source: str = "",
    page: int = 1,
    page_size: int = 25,
):
    """
    Fast, paged lookup for reconciliation action desks.

    Supported action_mode values:
      - receipt
      - unsubmit
    """
    conn = get_sql_connection(unit)
    if not conn:
        return None

    try:
        action_key = str(action_mode or "").strip().lower()
        proc_name = {
            "receipt": "dbo.usp_CorpRecon_ReceiptAction_Page",
            "unsubmit": "dbo.usp_CorpRecon_UnsubmitAction_Page",
        }.get(action_key)
        if not proc_name:
            return None

        if str(unit or "").strip().upper() not in {"AHL", "ACI"}:
            _ensure_corporate_receipt_source_ready_once(conn, unit)

        cur = conn.cursor()
        cur.execute(
            f"""
            EXEC {proc_name}
                 @Q = ?,
                 @BillSource = ?,
                 @Page = ?,
                 @PageSize = ?
            """,
            [
                str(q or ""),
                str(bill_source or ""),
                int(page or 1),
                int(page_size or 25),
            ],
        )

        result_sets = []
        while True:
            if cur.description:
                cols = [str(c[0]).strip() for c in cur.description]
                rows = cur.fetchall()
                result_sets.append(
                    [
                        {cols[i]: row[i] for i in range(len(cols))}
                        for row in rows
                    ]
                )
            if not cur.nextset():
                break

        if not result_sets:
            return None

        rows_payload = result_sets[0] if isinstance(result_sets[0], list) else []
        meta_payload = result_sets[1][0] if len(result_sets) > 1 and result_sets[1] else {}
        sources_rows = result_sets[2] if len(result_sets) > 2 and isinstance(result_sets[2], list) else []

        if not isinstance(meta_payload, dict):
            meta_payload = {}

        available_sources = [
            str((r or {}).get("bill_source") or "").strip()
            for r in sources_rows
            if str((r or {}).get("bill_source") or "").strip()
        ]
        if action_key == "unsubmit" and not available_sources:
            available_sources = ["Corporate Bill"]

        meta_payload.setdefault("available_sources", available_sources)
        meta_payload.setdefault("used_sql_sp", True)
        meta_payload.setdefault("action_mode", action_key)

        return {
            "status": "success",
            "unit": str(unit or "").upper(),
            "rows": rows_payload if isinstance(rows_payload, list) else [],
            "meta": meta_payload,
        }
    except Exception:
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _fetch_sharpsight_reconciliation_raw(unit: str, cutoff_date: str = "2025-03-31", bill_ids=None):
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for SharpSight corporate reconciliation")
        return None
    try:
        schema_info = _ensure_corporate_writeoff_columns_conn(conn) or {}
        receipt_source_info = _ensure_sharpsight_receipt_source_column_conn(conn) or {}
        receipt_source_col = str(receipt_source_info.get("column") or "").strip() or None
        receipt_source_backfill = _backfill_sharpsight_receipt_source_conn(conn, receipt_source_col) if receipt_source_col else {}

        normalized_bill_ids = []
        if bill_ids:
            try:
                normalized_bill_ids = sorted(
                    {
                        int(v)
                        for v in list(bill_ids)
                        if str(v).strip().lstrip("-").isdigit() and int(v) > 0
                    }
                )
            except Exception:
                normalized_bill_ids = []

        def _pick_col(cols_map: dict, candidates: list[str]):
            for cand in candidates:
                key = str(cand or "").strip().lower()
                if key and key in cols_map:
                    return cols_map[key]
            return None

        def _first_existing_table(candidates: list[str]):
            for table_name in candidates:
                try:
                    pd.read_sql(f"SELECT TOP 0 * FROM {table_name}", conn)
                    return table_name
                except Exception:
                    continue
            return None

        def _table_cols_map(table_name: str) -> dict:
            if not table_name:
                return {}
            try:
                preview_df = pd.read_sql(f"SELECT TOP 0 * FROM {table_name}", conn)
                return {str(c).strip().lower(): str(c).strip() for c in preview_df.columns}
            except Exception:
                return {}

        def _safe_int_expr(raw_expr: str) -> str:
            expr = str(raw_expr or "").strip()
            if not expr:
                return "CAST(NULL AS INT)"
            txt = f"LTRIM(RTRIM(CONVERT(NVARCHAR(100), {expr})))"
            return (
                "CASE "
                f"WHEN {txt} = '' THEN NULL "
                f"WHEN {txt} LIKE '%[^0-9]%' THEN NULL "
                f"ELSE CAST({expr} AS INT) END"
            )

        dtl_cols_map = _table_cols_map("dbo.Corp_Receipt_Dtl")
        mst_cols_map = _table_cols_map("dbo.Corp_Receipt_Mst")
        bill_cols_map = _table_cols_map("dbo.Corp_Bill_Mst_AHL")
        dtl_receipt_date_col = _pick_col(dtl_cols_map, ["ReceiptDate"])
        rebate_discount_col = _pick_col(mst_cols_map, ["rebateDiscountAmt", "RebateDiscountAmt"])
        tds_amt_col = _pick_col(mst_cols_map, ["TDSAmt", "TdsAmt", "tdsAmt", "TDS_AMT"])
        mst_writeoff_col = _pick_col(mst_cols_map, CORP_RECON_WRITEOFF_CANDIDATES) or (schema_info.get("receipt_column"))
        dtl_inserted_by_col = _pick_col(dtl_cols_map, ["insertedBy", "InsertedBy", "Inserted_By"])
        bill_reg_no_col = _pick_col(bill_cols_map, ["Registration_No", "RegistrationNo", "RegNo", "Reg_No"])
        bill_claim_id_col = _pick_col(bill_cols_map, ["ClaimId", "ClaimID", "Claim_Id", "Claim_ID"])
        bill_updated_by_col = _pick_col(bill_cols_map, ["accUserId", "Updated_By", "UpdatedBy", "updated_by"])
        bill_updated_on_col = _pick_col(bill_cols_map, ["accUpdatedDate", "Updated_On", "UpdatedOn", "ModifiedOn"])

        has_dtl_receipt_date = bool(dtl_receipt_date_col)
        has_rebate_discount_amt = bool(rebate_discount_col)
        has_tds_amt = bool(tds_amt_col)
        has_mst_writeoff_amt = bool(mst_writeoff_col)
        receipt_date_expr = f"d.[{dtl_receipt_date_col}]" if dtl_receipt_date_col else "m.Receipt_Date"
        rebate_discount_expr = (
            f"CAST(ISNULL(m.[{rebate_discount_col}], 0) AS FLOAT)"
            if rebate_discount_col
            else "CAST(0 AS FLOAT)"
        )
        tds_amt_expr = (
            f"CAST(ISNULL(m.[{tds_amt_col}], 0) AS FLOAT)"
            if tds_amt_col
            else "CAST(0 AS FLOAT)"
        )
        mst_writeoff_expr = (
            f"CAST(ISNULL(m.[{mst_writeoff_col}], 0) AS FLOAT)"
            if mst_writeoff_col
            else "CAST(0 AS FLOAT)"
        )
        bill_reg_no_expr = (
            f"CAST(ISNULL(CONVERT(NVARCHAR(80), b.[{bill_reg_no_col}]), '') AS NVARCHAR(80))"
            if bill_reg_no_col
            else "CAST('' AS NVARCHAR(80))"
        )
        bill_claim_id_expr = (
            f"CAST(ISNULL(CONVERT(NVARCHAR(120), b.[{bill_claim_id_col}]), '') AS NVARCHAR(120))"
            if bill_claim_id_col
            else "CAST('' AS NVARCHAR(120))"
        )
        bill_updated_on_expr = (
            "CAST(CASE "
            f"WHEN ISDATE(CONVERT(NVARCHAR(50), b.[{bill_updated_on_col}])) = 1 "
            f"THEN CONVERT(DATETIME, b.[{bill_updated_on_col}]) "
            "ELSE NULL END AS DATETIME)"
            if bill_updated_on_col
            else "CAST(NULL AS DATETIME)"
        )
        bill_updated_by_id_expr = (
            _safe_int_expr(f"b.[{bill_updated_by_col}]")
            if bill_updated_by_col
            else "CAST(NULL AS INT)"
        )
        dtl_inserted_by_id_expr = (
            _safe_int_expr(f"d.[{dtl_inserted_by_col}]")
            if dtl_inserted_by_col
            else "CAST(NULL AS INT)"
        )

        pm_table = _first_existing_table([
            "dbo.PaymentMode_Mst",
            "dbo.Paymentmode_mst",
            "dbo.PaymentModeMst",
        ])
        pm_cols = _table_cols_map(pm_table) if pm_table else {}
        pm_id_col = _pick_col(pm_cols, ["PModeID", "PModeId", "PaymentModeID", "Id"]) if pm_cols else None
        pm_name_col = _pick_col(pm_cols, ["PModeName", "PaymentMode", "ModeName", "PaymentModeName"]) if pm_cols else None
        payment_mode_expr = "CONVERT(NVARCHAR(100), m.CPayment_Mode)"
        payment_mode_join = ""
        if pm_table and pm_id_col and pm_name_col:
            payment_mode_join = f"LEFT JOIN {pm_table} pm WITH (NOLOCK) ON pm.[{pm_id_col}] = m.CPayment_Mode"
            payment_mode_expr = (
                f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), pm.[{pm_name_col}]), "
                f"CONVERT(NVARCHAR(100), m.CPayment_Mode))))"
            )

        user_table = _first_existing_table([
            "dbo.User_Mst",
            "dbo.user_mst",
            "dbo.UserMst",
        ])
        user_cols = _table_cols_map(user_table) if user_table else {}
        user_id_col = _pick_col(user_cols, ["UserId", "Userid", "User_ID", "Id", "AccountId"]) if user_cols else None
        user_name_col = _pick_col(user_cols, ["UserName", "User_Name", "Username", "Name", "EmpName"]) if user_cols else None

        bill_user_join = ""
        bill_updated_by_name_expr = "CAST('' AS NVARCHAR(200))"
        if user_table and user_id_col and user_name_col and bill_updated_by_col:
            bill_user_join = f"LEFT JOIN {user_table} u_bill WITH (NOLOCK) ON u_bill.[{user_id_col}] = c.BillUpdatedById"
            bill_updated_by_name_expr = (
                "CASE WHEN c.BillUpdatedById IS NULL THEN '' ELSE "
                f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), u_bill.[{user_name_col}]), "
                "CONVERT(NVARCHAR(100), c.BillUpdatedById)))) END"
            )
        elif bill_updated_by_col:
            bill_updated_by_name_expr = (
                "CASE WHEN c.BillUpdatedById IS NULL THEN '' ELSE "
                "CONVERT(NVARCHAR(100), c.BillUpdatedById) END"
            )

        receipt_user_join = ""
        inserted_by_name_expr = "CAST('' AS NVARCHAR(200))"
        if user_table and user_id_col and user_name_col and dtl_inserted_by_col:
            receipt_user_join = (
                f"LEFT JOIN {user_table} u_dtl WITH (NOLOCK) "
                f"ON u_dtl.[{user_id_col}] = {dtl_inserted_by_id_expr}"
            )
            inserted_by_name_expr = (
                f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), u_dtl.[{user_name_col}]), "
                f"CONVERT(NVARCHAR(100), {dtl_inserted_by_id_expr}))))"
            )
        elif dtl_inserted_by_col:
            inserted_by_name_expr = f"CONVERT(NVARCHAR(100), {dtl_inserted_by_id_expr})"

        bill_scope_clause = ""
        bill_scope_params = []
        if normalized_bill_ids:
            placeholders = ",".join(["?"] * len(normalized_bill_ids))
            bill_scope_clause = f"WHERE c.BillId IN ({placeholders})"
            bill_scope_params = list(normalized_bill_ids)

        bills_sql = f"""
            ;WITH canonical AS (
                SELECT
                    CAST(b.CBill_ID AS INT) AS BillId,
                    CAST('BILL_MST_AHL' AS NVARCHAR(40)) AS BillSource,
                    CAST(COALESCE(b.Submit_Date, b.Old_Bill_Date, b.CBill_Date, b.visitDate, v.VisitDate) AS DATETIME) AS BillDate,
                    CAST(ISNULL(b.CAmount, 0) AS FLOAT) AS BillAmount,
                    CAST(
                        ISNULL(
                            NULLIF(CONVERT(NVARCHAR(80), b.CBill_NO), ''),
                            ISNULL(NULLIF(CONVERT(NVARCHAR(80), b.Bill_No), ''), CONVERT(NVARCHAR(80), b.CBill_ID))
                        ) AS NVARCHAR(80)
                    ) AS BillNo,
                    {bill_claim_id_expr} AS ClaimIdRaw,
                    CASE
                        WHEN COALESCE(v.PatientID, b.PatientID) IS NULL THEN {bill_reg_no_expr}
                        ELSE ISNULL(dbo.fn_regno(COALESCE(v.PatientID, b.PatientID)), '')
                    END AS RegistrationNoRaw,
                    CAST(NULLIF(COALESCE(v.PatientID, b.PatientID), 0) AS INT) AS PatientId,
                    CAST(NULLIF(COALESCE(v.PatientType_ID, b.PatientTypeId), 0) AS INT) AS PatientTypeId,
                    CAST(NULLIF(COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo), 0) AS INT) AS PatientSubTypeId,
                    CAST(NULLIF(COALESCE(v.Visit_ID, b.Visit_ID), 0) AS INT) AS VisitId,
                    CAST(b.Submit_Date AS DATETIME) AS SubmitDateRaw,
                    CAST(b.CBill_Date AS DATETIME) AS CBillDateRaw,
                    CAST(NULL AS DATETIME) AS DueDate,
                    CAST('' AS NVARCHAR(255)) AS SourcePatientName,
                    CAST(ISNULL(b.Status, '') AS NVARCHAR(80)) AS BillStatusRaw,
                    CAST(ISNULL(NULLIF(b.Due_Amt, 0), ISNULL(NULLIF(b.dueAmount, 0), ISNULL(b.CAmount, 0))) AS FLOAT) AS BillDueAmountRaw,
                    CAST(0 AS INT) AS BillAuditedFlag,
                    {bill_updated_on_expr} AS BillUpdatedOnRaw,
                    {bill_updated_by_id_expr} AS BillUpdatedById,
                    ISNULL(v.TypeOfVisit, '') AS TypeOfVisit,
                    CAST(COALESCE(b.visitDate, v.VisitDate) AS DATETIME) AS VisitDate,
                    CAST(COALESCE(b.dischargeDate, v.DischargeDate) AS DATETIME) AS DischargeDate,
                    CASE
                        WHEN COALESCE(v.PatientID, b.PatientID) IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_patientfullname(COALESCE(v.PatientID, b.PatientID)), '')
                    END AS PatientName,
                    CASE
                        WHEN COALESCE(v.PatientType_ID, b.PatientTypeId) IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_pat_type(COALESCE(v.PatientType_ID, b.PatientTypeId)), '')
                    END AS PatientType,
                    CASE
                        WHEN COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo) IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_patsub_type(COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo)), '')
                    END AS PatientSubType,
                    CASE
                        WHEN v.DepartmentID IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_dept(v.DepartmentID), '')
                    END AS Dept,
                    CASE
                        WHEN v.UnitID IS NULL THEN ''
                        ELSE ISNULL(dbo.Fn_subDept(v.UnitID), '')
                    END AS SubDept
                FROM dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                LEFT JOIN dbo.Visit v WITH (NOLOCK)
                    ON v.Visit_ID = b.Visit_ID
            )
            SELECT
                c.BillId,
                c.BillSource,
                c.BillDate,
                c.BillAmount,
                c.BillNo,
                ISNULL(NULLIF(LTRIM(RTRIM(ISNULL(c.ClaimIdRaw, ''))), ''), '') AS ClaimId,
                CASE
                    WHEN c.PatientId IS NOT NULL THEN ISNULL(dbo.fn_regno(c.PatientId), '')
                    WHEN NULLIF(LTRIM(RTRIM(ISNULL(c.RegistrationNoRaw, ''))), '') IS NOT NULL THEN LTRIM(RTRIM(ISNULL(c.RegistrationNoRaw, '')))
                    ELSE ''
                END AS Registration_No,
                c.PatientId,
                c.VisitId,
                c.SubmitDateRaw,
                c.CBillDateRaw,
                c.DueDate,
                c.SourcePatientName,
                c.BillStatusRaw,
                c.BillDueAmountRaw,
                c.BillAuditedFlag,
                c.BillUpdatedOnRaw,
                c.BillUpdatedById,
                {bill_updated_by_name_expr} AS BillUpdatedByName,
                CAST(0 AS FLOAT) AS OpeningReceiptAmt,
                CAST(0 AS INT) AS OpeningReceiptId,
                CAST(0 AS FLOAT) AS OpeningWriteOffAmt,
                c.TypeOfVisit,
                c.VisitDate,
                c.DischargeDate,
                c.PatientName,
                c.PatientType,
                c.PatientSubType,
                c.Dept,
                c.SubDept
            FROM canonical c
            {bill_user_join}
            {bill_scope_clause}
        """
        bills_df = pd.read_sql(bills_sql, conn, params=bill_scope_params or None)

        stored_receipt_source_expr = (
            f"NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(40), d.[{receipt_source_col}]))), '')"
            if receipt_source_col
            else "NULL"
        )
        bill_date_expr = "COALESCE(b.Submit_Date, b.CBill_Date, b.accUpdatedDate, b.visitDate, b.Updated_On)"
        computed_receipt_source_expr = (
            "CASE "
            f"WHEN o.OPId IS NOT NULL AND b.CBill_ID IS NOT NULL AND ({receipt_date_expr} IS NULL OR {bill_date_expr} IS NULL OR CAST({receipt_date_expr} AS DATETIME) < CAST({bill_date_expr} AS DATETIME)) THEN N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' "
            f"WHEN b.CBill_ID IS NOT NULL THEN N'{SHARPSIGHT_RECEIPT_SOURCE_AHL}' "
            f"WHEN o.OPId IS NOT NULL THEN N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' "
            f"ELSE N'{SHARPSIGHT_RECEIPT_SOURCE_UNKNOWN}' END"
        )
        receipt_source_expr = f"COALESCE({stored_receipt_source_expr}, {computed_receipt_source_expr})"

        receipt_where_parts = [f"{receipt_source_expr} = N'{SHARPSIGHT_RECEIPT_SOURCE_AHL}'"]
        receipt_scope_params = []
        if normalized_bill_ids:
            placeholders = ",".join(["?"] * len(normalized_bill_ids))
            receipt_where_parts.append(f"d.billId IN ({placeholders})")
            receipt_scope_params = list(normalized_bill_ids)
        receipt_scope_clause = f"WHERE {' AND '.join(receipt_where_parts)}" if receipt_where_parts else ""

        receipts_sql = f"""
            SELECT
                CAST(d.recDtlId AS INT) AS ReceiptDetailId,
                CAST(d.receiptId AS INT) AS ReceiptId,
                CAST(d.billId AS INT) AS BillId,
                CAST(ISNULL(d.billAmt, 0) AS FLOAT) AS BillAmtDtl,
                CAST(ISNULL(d.receiptAmt, 0) AS FLOAT) AS ReceiptAmtDtl,
                CAST(
                    CASE
                        WHEN ABS(ROUND(ISNULL(d.billAmt, 0) - (ISNULL(d.receiptAmt, 0) + {tds_amt_expr} + {rebate_discount_expr} + {mst_writeoff_expr}), 2)) <= 0.01 THEN 0
                        ELSE ROUND(ISNULL(d.billAmt, 0) - (ISNULL(d.receiptAmt, 0) + {tds_amt_expr} + {rebate_discount_expr} + {mst_writeoff_expr}), 2)
                    END
                    AS FLOAT
                ) AS DueAmtDtl,
                CAST(NULLIF(d.visitId, 0) AS INT) AS DtlVisitId,
                CAST(NULLIF(d.PatientId, 0) AS INT) AS DtlPatientId,
                d.insertedOn AS InsertedOn,
                {dtl_inserted_by_id_expr} AS InsertedById,
                {inserted_by_name_expr} AS InsertedByName,
                {receipt_date_expr} AS ReceiptDate,
                m.Receipt_Date AS ReceiptDateMst,
                ISNULL(CONVERT(NVARCHAR(80), m.CReceipt_No), '') AS ReceiptNo,
                CAST(ISNULL(m.Amount, 0) AS FLOAT) AS ReceiptMstAmount,
                CAST(ISNULL(m.NetAmt, ISNULL(m.Amount, 0)) AS FLOAT) AS ReceiptNetAmt,
                CAST(ISNULL(m.GrossAmt, ISNULL(m.Amount, 0)) AS FLOAT) AS ReceiptGrossAmt,
                {tds_amt_expr} AS TDSAmt,
                {mst_writeoff_expr} AS WriteOffAmt,
                CAST(ISNULL(m.Cancelstatus, 0) AS INT) AS CancelStatus,
                ISNULL(CONVERT(NVARCHAR(120), m.UTRNo), '') AS UTRNo,
                CAST(ISNULL(m.CPayment_Mode, 0) AS INT) AS PaymentModeId,
                {payment_mode_expr} AS PaymentMode,
                {rebate_discount_expr} AS RebateDiscountAmt,
                CAST({receipt_source_expr} AS NVARCHAR(40)) AS ReceiptBillSourceKey,
                CAST(NULLIF(m.VisitID, 0) AS INT) AS MstVisitId,
                CAST(NULLIF(m.PatientID, 0) AS INT) AS MstPatientId
            FROM dbo.Corp_Receipt_Dtl d WITH (NOLOCK)
            INNER JOIN dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            LEFT JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            LEFT JOIN dbo.Corp_Receipt_Mst m WITH (NOLOCK)
                ON d.receiptId = m.Receipt_ID
            {payment_mode_join}
            {receipt_user_join}
            {receipt_scope_clause}
        """
        if receipt_scope_params:
            receipts_df = pd.read_sql(receipts_sql, conn, params=receipt_scope_params)
        else:
            receipts_df = pd.read_sql(receipts_sql, conn)

        if bills_df is None:
            bills_df = pd.DataFrame()
        if receipts_df is None:
            receipts_df = pd.DataFrame()

        if not bills_df.empty:
            bills_df.columns = [c.strip() for c in bills_df.columns]
            bills_df["Unit"] = (unit or "").upper()
        if not receipts_df.empty:
            receipts_df.columns = [c.strip() for c in receipts_df.columns]
            receipts_df["Unit"] = (unit or "").upper()

        return {
            "bills": bills_df,
            "receipts": receipts_df,
            "meta": {
                "has_dtl_receipt_date": bool(has_dtl_receipt_date),
                "has_rebate_discount_amt": bool(has_rebate_discount_amt),
                "has_tds_amt": bool(has_tds_amt),
                "has_receipt_writeoff_amt": bool(has_mst_writeoff_amt),
                "has_opening_writeoff_amt": bool((schema_info or {}).get("opening_column")),
                "has_bill_audited_flag": False,
                "receipt_writeoff_column": mst_writeoff_col,
                "opening_writeoff_column": (schema_info or {}).get("opening_column"),
                "bill_audited_column": None,
                "receipt_source_column": receipt_source_col,
                "receipt_source_backfill": receipt_source_backfill,
                "cutoff_date": cutoff_date,
            },
        }
    except Exception as e:
        print(f"Error fetching SharpSight reconciliation raw ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_corporate_reconciliation_raw(unit: str, cutoff_date: str = "2025-03-31", bill_ids=None):
    """
    Fetch canonical corporate bill universe + linked corporate receipt lines.
    bill_ids (optional): limit to specific bill ids for targeted fetch.
    Returns a dict with:
      - bills: one row per canonical bill
      - receipts: one row per receipt detail linked to billId
      - meta: compatibility flags used by callers
    """
    if _is_sharpsight_unit(unit):
        return _fetch_sharpsight_reconciliation_raw(unit, cutoff_date, bill_ids)

    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for corporate reconciliation")
        return None
    try:
        schema_ensure_info = _ensure_corporate_recon_schema_once(conn, unit) or {}
        audited_schema_info = (schema_ensure_info or {}).get("audited") or {}

        normalized_bill_ids = []
        if bill_ids:
            try:
                normalized_bill_ids = sorted(
                    {
                        int(v)
                        for v in list(bill_ids)
                        if str(v).strip().lstrip("-").isdigit() and int(v) > 0
                    }
                )
            except Exception:
                normalized_bill_ids = []

        def _pick_col(cols_map: dict, candidates: list[str]):
            for cand in candidates:
                key = cand.strip().lower()
                if key in cols_map:
                    return cols_map[key]
            return None

        def _first_existing_table(candidates: list[str]):
            for table_name in candidates:
                try:
                    pd.read_sql(f"SELECT TOP 0 * FROM {table_name}", conn)
                    return table_name
                except Exception:
                    continue
            return None

        def _table_cols_map(table_name: str) -> dict:
            if not table_name:
                return {}
            try:
                preview_df = pd.read_sql(f"SELECT TOP 0 * FROM {table_name}", conn)
                return {str(c).strip().lower(): str(c).strip() for c in preview_df.columns}
            except Exception:
                return {}

        dtl_cols_map = _table_cols_map("dbo.Corp_Receipt_Dtl")
        mst_cols_map = _table_cols_map("dbo.Corp_Receipt_Mst")
        bill_cols_map = _table_cols_map("dbo.Corp_Bill_Mst")
        open_cols_map = _table_cols_map("dbo.CorpOpening")
        dtl_cols = set(dtl_cols_map.keys())
        mst_cols = set(mst_cols_map.keys())

        dtl_receipt_date_col = _pick_col(dtl_cols_map, ["ReceiptDate"])
        rebate_discount_col = _pick_col(mst_cols_map, ["rebateDiscountAmt", "RebateDiscountAmt"])
        tds_amt_col = _pick_col(mst_cols_map, ["TDSAmt", "TdsAmt", "tdsAmt", "TDS_AMT"])
        mst_writeoff_col = _pick_col(mst_cols_map, CORP_RECON_WRITEOFF_CANDIDATES)
        opening_writeoff_col = _pick_col(open_cols_map, CORP_RECON_WRITEOFF_CANDIDATES)
        bill_reg_no_col = _pick_col(bill_cols_map, ["Registration_No", "RegistrationNo", "RegNo", "Reg_No"])
        bill_claim_id_col = _pick_col(bill_cols_map, ["ClaimId", "ClaimID", "Claim_Id", "Claim_ID"])
        opening_reg_no_col = _pick_col(open_cols_map, ["Registration_No", "RegistrationNo", "RegNo", "Reg_No"])
        bill_audited_col = _pick_col(bill_cols_map, CORP_RECON_AUDITED_CANDIDATES) or (
            (audited_schema_info or {}).get("bill_audited_column")
        )
        dtl_inserted_by_col = _pick_col(dtl_cols_map, ["insertedBy", "InsertedBy", "Inserted_By"])
        bill_updated_by_col = _pick_col(bill_cols_map, ["Updated_By", "UpdatedBy", "updated_by"])
        bill_updated_on_col = _pick_col(
            bill_cols_map,
            ["Updated_On", "UpdatedOn", "ModifiedOn", "accUpdatedDate", "AccUpdatedDate"],
        )

        has_dtl_receipt_date = bool(dtl_receipt_date_col)
        has_rebate_discount_amt = bool(rebate_discount_col)
        has_tds_amt = bool(tds_amt_col)
        has_mst_writeoff_amt = bool(mst_writeoff_col)
        has_opening_writeoff_amt = bool(opening_writeoff_col)
        has_bill_audited_flag = bool(bill_audited_col)
        receipt_date_expr = f"d.[{dtl_receipt_date_col}]" if dtl_receipt_date_col else "m.Receipt_Date"
        rebate_discount_expr = (
            f"CAST(ISNULL(m.[{rebate_discount_col}], 0) AS FLOAT)"
            if rebate_discount_col
            else "CAST(0 AS FLOAT)"
        )
        tds_amt_expr = (
            f"CAST(ISNULL(m.[{tds_amt_col}], 0) AS FLOAT)"
            if tds_amt_col
            else "CAST(0 AS FLOAT)"
        )
        mst_writeoff_expr = (
            f"CAST(ISNULL(m.[{mst_writeoff_col}], 0) AS FLOAT)"
            if mst_writeoff_col
            else "CAST(0 AS FLOAT)"
        )
        opening_writeoff_expr = (
            f"CAST(ISNULL(o.[{opening_writeoff_col}], 0) AS FLOAT)"
            if opening_writeoff_col
            else "CAST(0 AS FLOAT)"
        )
        bill_reg_no_expr = (
            f"CAST(ISNULL(CONVERT(NVARCHAR(80), b.[{bill_reg_no_col}]), '') AS NVARCHAR(80))"
            if bill_reg_no_col
            else "CAST('' AS NVARCHAR(80))"
        )
        opening_reg_no_expr = (
            f"CAST(ISNULL(CONVERT(NVARCHAR(80), o.[{opening_reg_no_col}]), '') AS NVARCHAR(80))"
            if opening_reg_no_col
            else "CAST('' AS NVARCHAR(80))"
        )
        bill_claim_id_expr = (
            f"CAST(ISNULL(CONVERT(NVARCHAR(120), b.[{bill_claim_id_col}]), '') AS NVARCHAR(120))"
            if bill_claim_id_col
            else "CAST('' AS NVARCHAR(120))"
        )
        bill_audited_expr = (
            "CAST(CASE "
            f"WHEN LTRIM(RTRIM(CONVERT(NVARCHAR(20), ISNULL(b.[{bill_audited_col}], 0)))) "
            "IN ('1','Y','y','YES','Yes','TRUE','True','true') THEN 1 ELSE 0 END AS INT)"
            if bill_audited_col
            else "CAST(0 AS INT)"
        )
        def _safe_int_expr(raw_expr: str) -> str:
            expr = str(raw_expr or "").strip()
            if not expr:
                return "CAST(NULL AS INT)"
            txt = f"LTRIM(RTRIM(CONVERT(NVARCHAR(100), {expr})))"
            return (
                "CASE "
                f"WHEN {txt} = '' THEN NULL "
                f"WHEN {txt} LIKE '%[^0-9]%' THEN NULL "
                f"ELSE CAST({expr} AS INT) END"
            )

        bill_updated_on_expr = (
            "CAST(CASE "
            f"WHEN ISDATE(CONVERT(NVARCHAR(50), b.[{bill_updated_on_col}])) = 1 "
            f"THEN CONVERT(DATETIME, b.[{bill_updated_on_col}]) "
            "ELSE NULL END AS DATETIME)"
            if bill_updated_on_col
            else "CAST(NULL AS DATETIME)"
        )
        bill_updated_by_id_expr = (
            _safe_int_expr(f"b.[{bill_updated_by_col}]")
            if bill_updated_by_col
            else "CAST(NULL AS INT)"
        )
        dtl_inserted_by_id_expr = (
            _safe_int_expr(f"d.[{dtl_inserted_by_col}]")
            if dtl_inserted_by_col
            else "CAST(NULL AS INT)"
        )

        pm_table = _first_existing_table([
            "dbo.PaymentMode_Mst",
            "dbo.Paymentmode_mst",
            "dbo.PaymentModeMst",
        ])
        pm_cols = _table_cols_map(pm_table) if pm_table else {}
        pm_id_col = _pick_col(pm_cols, ["PModeID", "PaymentModeID", "Id"]) if pm_cols else None
        pm_name_col = _pick_col(pm_cols, ["PModeName", "PaymentMode", "ModeName", "PaymentModeName"]) if pm_cols else None
        payment_mode_expr = "CONVERT(NVARCHAR(100), m.CPayment_Mode)"
        payment_mode_join = ""
        if pm_table and pm_id_col and pm_name_col:
            payment_mode_join = f"LEFT JOIN {pm_table} pm WITH (NOLOCK) ON pm.[{pm_id_col}] = m.CPayment_Mode"
            payment_mode_expr = (
                f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), pm.[{pm_name_col}]), "
                f"CONVERT(NVARCHAR(100), m.CPayment_Mode))))"
            )

        user_table = _first_existing_table([
            "dbo.User_Mst",
            "dbo.user_mst",
            "dbo.UserMst",
        ])
        user_cols = _table_cols_map(user_table) if user_table else {}
        user_id_col = _pick_col(user_cols, ["UserId", "Userid", "User_ID", "Id", "AccountId"]) if user_cols else None
        user_name_col = _pick_col(user_cols, ["UserName", "User_Name", "Username", "Name", "EmpName"]) if user_cols else None

        bill_user_join = ""
        bill_updated_by_name_expr = "CAST('' AS NVARCHAR(200))"
        if user_table and user_id_col and user_name_col:
            bill_user_join = f"LEFT JOIN {user_table} u_bill WITH (NOLOCK) ON u_bill.[{user_id_col}] = c.BillUpdatedById"
            bill_updated_by_name_expr = (
                "CASE WHEN c.BillUpdatedById IS NULL THEN '' ELSE "
                f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), u_bill.[{user_name_col}]), "
                "CONVERT(NVARCHAR(100), c.BillUpdatedById)))) END"
            )
        elif bill_updated_by_col:
            bill_updated_by_name_expr = (
                "CASE WHEN c.BillUpdatedById IS NULL THEN '' ELSE "
                "CONVERT(NVARCHAR(100), c.BillUpdatedById) END"
            )

        receipt_user_join = ""
        inserted_by_name_expr = "CAST('' AS NVARCHAR(200))"
        if user_table and user_id_col and user_name_col and dtl_inserted_by_col:
            receipt_user_join = (
                f"LEFT JOIN {user_table} u_dtl WITH (NOLOCK) "
                f"ON u_dtl.[{user_id_col}] = {dtl_inserted_by_id_expr}"
            )
            inserted_by_name_expr = (
                f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), u_dtl.[{user_name_col}]), "
                f"CONVERT(NVARCHAR(100), {dtl_inserted_by_id_expr}))))"
            )
        elif dtl_inserted_by_col:
            inserted_by_name_expr = f"CONVERT(NVARCHAR(100), {dtl_inserted_by_id_expr})"

        bill_scope_clause = ""
        bill_scope_params = []
        if normalized_bill_ids:
            placeholders = ",".join(["?"] * len(normalized_bill_ids))
            bill_scope_clause = f" AND c.BillId IN ({placeholders})"
            bill_scope_params = list(normalized_bill_ids)

        receipt_source_info = _ensure_corporate_receipt_source_column_conn(conn) or {}
        receipt_source_col = str(receipt_source_info.get("column") or "").strip() or None
        if not receipt_source_col:
            receipt_source_col = _pick_col(dtl_cols_map, SHARPSIGHT_RECEIPT_SOURCE_COL_CANDIDATES)
        receipt_source_backfill = (
            _backfill_corporate_receipt_source_conn(conn, unit, receipt_source_col)
            if receipt_source_col
            else {}
        )
        stored_receipt_source_expr = (
            f"NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(40), d.[{receipt_source_col}]))), '')"
            if receipt_source_col
            else "NULL"
        )
        bill_date_expr = "COALESCE(b.Submit_Date, b.CBill_Date, b.accUpdatedDate, b.visitDate, b.Updated_On)"
        receipt_source_expr = (
            "COALESCE("
            f"{stored_receipt_source_expr}, "
            "CASE "
            f"WHEN o.OPId IS NOT NULL AND b.CBill_ID IS NOT NULL AND ({receipt_date_expr} IS NULL OR {bill_date_expr} IS NULL OR CAST({receipt_date_expr} AS DATETIME) < CAST({bill_date_expr} AS DATETIME)) THEN N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' "
            f"WHEN b.CBill_ID IS NOT NULL THEN N'{CORP_RECEIPT_SOURCE_BILL_MST}' "
            f"WHEN o.OPId IS NOT NULL THEN N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' "
            f"ELSE N'{SHARPSIGHT_RECEIPT_SOURCE_UNKNOWN}' END"
            ")"
        )

        bills_sql = f"""
            ;WITH bill_mst AS (
                SELECT
                    CAST(b.CBill_ID AS INT) AS BillId,
                    CAST(NULLIF(b.Visit_ID, 0) AS INT) AS BillVisitId,
                    CAST(NULLIF(b.PatientID, 0) AS INT) AS BillPatientId,
                    CAST(b.Submit_Date AS DATETIME) AS SubmitDateMst,
                    CAST(b.CBill_Date AS DATETIME) AS CBillDateMst,
                    CAST(COALESCE(b.Submit_Date, b.CBill_Date) AS DATETIME) AS BillDateMst,
                    CAST(ISNULL(b.CAmount, 0) AS FLOAT) AS BillAmountMst,
                    CAST(
                        ISNULL(
                            NULLIF(CONVERT(NVARCHAR(80), b.CBill_NO), ''),
                            NULLIF(CONVERT(NVARCHAR(80), b.Bill_No), '')
                        ) AS NVARCHAR(80)
                    ) AS BillNoMst,
                    {bill_claim_id_expr} AS ClaimIdMst,
                    {bill_reg_no_expr} AS RegistrationNoMst,
                    CAST(NULLIF(b.PatientTypeId, 0) AS INT) AS BillPatientTypeId,
                    CAST(NULLIF(b.PatientTypeIdSrNo, 0) AS INT) AS BillPatientSubTypeId,
                    CAST(ISNULL(b.Due_Amt, ISNULL(b.dueAmount, 0)) AS FLOAT) AS DueAmountMst,
                    CAST(ISNULL(b.Status, '') AS NVARCHAR(80)) AS BillStatusMst,
                    {bill_audited_expr} AS BillAuditedFlag,
                    {bill_updated_on_expr} AS BillUpdatedOnRaw,
                    {bill_updated_by_id_expr} AS BillUpdatedById
                FROM dbo.Corp_Bill_Mst b WITH (NOLOCK)
            ),
            opening AS (
                SELECT
                    CAST(o.OPId AS INT) AS BillId,
                    CAST(NULLIF(o.PatientId, 0) AS INT) AS OpenPatientId,
                    CAST(o.DueDate AS DATETIME) AS BillDateOpening,
                    CAST(o.DueDate AS DATETIME) AS DueDateOpening,
                    CAST(ISNULL(o.DueAmount, 0) AS FLOAT) AS BillAmountOpening,
                    CAST(ISNULL(o.RefNo, '') AS NVARCHAR(80)) AS BillNoOpening,
                    {opening_reg_no_expr} AS OpenRegistrationNo,
                    CAST(ISNULL(o.PatientName, '') AS NVARCHAR(255)) AS OpenPatientName,
                    CAST(NULLIF(o.PatientTypeId, 0) AS INT) AS OpenPatientTypeId,
                    CAST(NULLIF(o.PatientSubTypeId, 0) AS INT) AS OpenPatientSubTypeId,
                    CAST(ISNULL(o.ReceiptAmt, 0) AS FLOAT) AS OpeningReceiptAmt,
                    CAST(ISNULL(o.ReceiptId, 0) AS INT) AS OpeningReceiptId,
                    {opening_writeoff_expr} AS OpeningWriteOffAmt
                FROM dbo.CorpOpening o WITH (NOLOCK)
            ),
            bill_mst_post AS (
                SELECT
                    b.BillId,
                    CAST('BILL_MST_POST' AS NVARCHAR(40)) AS BillSource,
                    b.BillVisitId,
                    b.BillPatientId,
                    b.SubmitDateMst,
                    b.CBillDateMst,
                    b.BillDateMst,
                    b.BillAmountMst,
                    b.BillNoMst,
                    b.ClaimIdMst,
                    b.RegistrationNoMst,
                    b.BillPatientTypeId,
                    b.BillPatientSubTypeId,
                    b.DueAmountMst,
                    b.BillStatusMst,
                    b.BillAuditedFlag,
                    b.BillUpdatedOnRaw,
                    b.BillUpdatedById
                FROM bill_mst b
                WHERE b.BillDateMst > CAST(? AS DATETIME)
            ),
            canonical AS (
                SELECT
                    b.BillId,
                    b.BillSource,
                    b.BillDateMst AS BillDate,
                    b.BillAmountMst AS BillAmount,
                    b.BillNoMst AS BillNo,
                    b.ClaimIdMst AS ClaimIdRaw,
                    b.RegistrationNoMst AS RegistrationNoRaw,
                    b.BillPatientId AS PatientId,
                    b.BillPatientTypeId AS PatientTypeId,
                    b.BillPatientSubTypeId AS PatientSubTypeId,
                    b.BillVisitId AS VisitId,
                    b.SubmitDateMst AS SubmitDateRaw,
                    b.CBillDateMst AS CBillDateRaw,
                    CAST(NULL AS DATETIME) AS DueDate,
                    CAST(N'' AS NVARCHAR(255)) AS SourcePatientName,
                    ISNULL(b.BillStatusMst, '') AS BillStatusRaw,
                    ISNULL(b.DueAmountMst, 0) AS BillDueAmountRaw,
                    ISNULL(b.BillAuditedFlag, 0) AS BillAuditedFlag,
                    b.BillUpdatedOnRaw AS BillUpdatedOnRaw,
                    b.BillUpdatedById AS BillUpdatedById,
                    CAST(0 AS FLOAT) AS OpeningReceiptAmt,
                    CAST(0 AS INT) AS OpeningReceiptId,
                    CAST(0 AS FLOAT) AS OpeningWriteOffAmt
                FROM bill_mst_post b
                UNION ALL
                SELECT
                    o.BillId,
                    CAST('OPENING' AS NVARCHAR(40)) AS BillSource,
                    o.BillDateOpening AS BillDate,
                    o.BillAmountOpening AS BillAmount,
                    o.BillNoOpening AS BillNo,
                    CAST(N'' AS NVARCHAR(120)) AS ClaimIdRaw,
                    o.OpenRegistrationNo AS RegistrationNoRaw,
                    o.OpenPatientId AS PatientId,
                    o.OpenPatientTypeId AS PatientTypeId,
                    o.OpenPatientSubTypeId AS PatientSubTypeId,
                    CAST(NULL AS INT) AS VisitId,
                    CAST(NULL AS DATETIME) AS SubmitDateRaw,
                    CAST(NULL AS DATETIME) AS CBillDateRaw,
                    o.DueDateOpening AS DueDate,
                    ISNULL(o.OpenPatientName, '') AS SourcePatientName,
                    CAST(N'' AS NVARCHAR(80)) AS BillStatusRaw,
                    CAST(0 AS FLOAT) AS BillDueAmountRaw,
                    CAST(0 AS INT) AS BillAuditedFlag,
                    CAST(NULL AS DATETIME) AS BillUpdatedOnRaw,
                    CAST(NULL AS INT) AS BillUpdatedById,
                    ISNULL(o.OpeningReceiptAmt, 0) AS OpeningReceiptAmt,
                    ISNULL(o.OpeningReceiptId, 0) AS OpeningReceiptId,
                    ISNULL(o.OpeningWriteOffAmt, 0) AS OpeningWriteOffAmt
                FROM opening o
            ),
            receipt_visit AS (
                SELECT
                    CAST(d.billId AS INT) AS BillId,
                    CAST({receipt_source_expr} AS NVARCHAR(40)) AS ReceiptBillSourceKey,
                    MAX(CASE WHEN ISNULL(d.visitId, 0) > 0 THEN CAST(d.visitId AS INT) ELSE CAST(ISNULL(m.VisitID, 0) AS INT) END) AS BestVisitId,
                    MAX(CASE WHEN ISNULL(d.PatientId, 0) > 0 THEN CAST(d.PatientId AS INT) ELSE CAST(ISNULL(m.PatientID, 0) AS INT) END) AS BestPatientId
                FROM dbo.Corp_Receipt_Dtl d WITH (NOLOCK)
                LEFT JOIN dbo.Corp_Receipt_Mst m WITH (NOLOCK)
                    ON d.receiptId = m.Receipt_ID
                LEFT JOIN dbo.Corp_Bill_Mst b WITH (NOLOCK)
                    ON b.CBill_ID = d.billId
                LEFT JOIN dbo.CorpOpening o WITH (NOLOCK)
                    ON o.OPId = d.billId
                GROUP BY d.billId, CAST({receipt_source_expr} AS NVARCHAR(40))
            ),
            canonical_enriched AS (
                SELECT
                    c.BillId,
                    c.BillSource,
                    c.BillDate,
                    c.BillAmount,
                    c.BillNo,
                    c.ClaimIdRaw,
                    c.RegistrationNoRaw,
                    CAST(NULLIF(COALESCE(c.PatientId, rv.BestPatientId), 0) AS INT) AS PatientId,
                    CAST(NULLIF(COALESCE(c.VisitId, rv.BestVisitId), 0) AS INT) AS VisitId,
                    c.PatientTypeId,
                    c.PatientSubTypeId,
                    c.SubmitDateRaw,
                    c.CBillDateRaw,
                    c.DueDate,
                    c.SourcePatientName,
                    c.BillStatusRaw,
                    c.BillDueAmountRaw,
                    c.BillAuditedFlag,
                    c.BillUpdatedOnRaw,
                    c.BillUpdatedById,
                    c.OpeningReceiptAmt,
                    c.OpeningReceiptId,
                    c.OpeningWriteOffAmt
                FROM canonical c
                LEFT JOIN receipt_visit rv
                    ON rv.BillId = c.BillId
                   AND UPPER(ISNULL(rv.ReceiptBillSourceKey, '')) = UPPER(ISNULL(c.BillSource, ''))
            )
            SELECT
                c.BillId,
                c.BillSource,
                c.BillDate,
                c.BillAmount,
                c.BillNo,
                ISNULL(NULLIF(LTRIM(RTRIM(ISNULL(c.ClaimIdRaw, ''))), ''), '') AS ClaimId,
                CASE
                    WHEN c.PatientId IS NOT NULL THEN ISNULL(dbo.fn_regno(c.PatientId), '')
                    WHEN NULLIF(LTRIM(RTRIM(ISNULL(c.RegistrationNoRaw, ''))), '') IS NOT NULL THEN LTRIM(RTRIM(ISNULL(c.RegistrationNoRaw, '')))
                    ELSE ''
                END AS Registration_No,
                c.PatientId,
                c.VisitId,
                c.SubmitDateRaw,
                c.CBillDateRaw,
                c.DueDate,
                c.SourcePatientName,
                c.BillStatusRaw,
                c.BillDueAmountRaw,
                c.BillAuditedFlag,
                c.BillUpdatedOnRaw,
                c.BillUpdatedById,
                {bill_updated_by_name_expr} AS BillUpdatedByName,
                c.OpeningReceiptAmt,
                c.OpeningReceiptId,
                c.OpeningWriteOffAmt,
                ISNULL(v.TypeOfVisit, '') AS TypeOfVisit,
                v.VisitDate,
                v.DischargeDate,
                CASE
                    WHEN c.BillSource = 'OPENING' AND ISNULL(c.SourcePatientName, '') <> '' THEN ISNULL(c.SourcePatientName, '')
                    WHEN c.BillSource = 'OPENING' AND c.PatientId IS NOT NULL THEN ISNULL(dbo.fn_patientfullname(c.PatientId), '')
                    WHEN v.PatientID IS NOT NULL THEN ISNULL(dbo.fn_patientfullname(v.PatientID), '')
                    WHEN c.PatientId IS NOT NULL THEN ISNULL(dbo.fn_patientfullname(c.PatientId), '')
                    ELSE ISNULL(c.SourcePatientName, '')
                END AS PatientName,
                CASE
                    WHEN c.BillSource = 'OPENING' AND c.PatientTypeId IS NOT NULL THEN ISNULL(dbo.fn_pat_type(c.PatientTypeId), '')
                    WHEN v.PatientType_ID IS NOT NULL THEN ISNULL(dbo.fn_pat_type(v.PatientType_ID), '')
                    WHEN c.PatientTypeId IS NOT NULL THEN ISNULL(dbo.fn_pat_type(c.PatientTypeId), '')
                    ELSE ''
                END AS PatientType,
                CASE
                    WHEN c.BillSource = 'OPENING' AND c.PatientSubTypeId IS NOT NULL THEN ISNULL(dbo.fn_patsub_type(c.PatientSubTypeId), '')
                    WHEN v.PatientSubType_ID IS NOT NULL THEN ISNULL(dbo.fn_patsub_type(v.PatientSubType_ID), '')
                    WHEN c.PatientSubTypeId IS NOT NULL THEN ISNULL(dbo.fn_patsub_type(c.PatientSubTypeId), '')
                    ELSE ''
                END AS PatientSubType,
                CASE
                    WHEN v.DepartmentID IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_dept(v.DepartmentID), '')
                END AS Dept,
                CASE
                    WHEN v.UnitID IS NULL THEN ''
                    ELSE ISNULL(dbo.Fn_subDept(v.UnitID), '')
                END AS SubDept
            FROM canonical_enriched c
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = c.VisitId
            {bill_user_join}
            WHERE c.BillId IS NOT NULL
            {bill_scope_clause}
        """
        bills_df = pd.read_sql(bills_sql, conn, params=[cutoff_date] + bill_scope_params)

        receipt_scope_clause = ""
        receipt_scope_params = []
        if normalized_bill_ids:
            placeholders = ",".join(["?"] * len(normalized_bill_ids))
            receipt_scope_clause = f"WHERE d.billId IN ({placeholders})"
            receipt_scope_params = list(normalized_bill_ids)

        receipts_sql = f"""
            SELECT
                CAST(d.recDtlId AS INT) AS ReceiptDetailId,
                CAST(d.receiptId AS INT) AS ReceiptId,
                CAST(d.billId AS INT) AS BillId,
                CAST(ISNULL(d.billAmt, 0) AS FLOAT) AS BillAmtDtl,
                CAST(ISNULL(d.receiptAmt, 0) AS FLOAT) AS ReceiptAmtDtl,
                CAST(
                    CASE
                        WHEN ABS(ROUND(ISNULL(d.billAmt, 0) - (ISNULL(d.receiptAmt, 0) + ISNULL(m.TDSAmt, 0) + ISNULL(m.rebateDiscountAmt, 0)), 2)) <= 0.01 THEN 0
                        ELSE ROUND(ISNULL(d.billAmt, 0) - (ISNULL(d.receiptAmt, 0) + ISNULL(m.TDSAmt, 0) + ISNULL(m.rebateDiscountAmt, 0)), 2)
                    END
                    AS FLOAT
                ) AS DueAmtDtl,
                CAST(NULLIF(d.visitId, 0) AS INT) AS DtlVisitId,
                CAST(NULLIF(d.PatientId, 0) AS INT) AS DtlPatientId,
                d.insertedOn AS InsertedOn,
                {dtl_inserted_by_id_expr} AS InsertedById,
                {inserted_by_name_expr} AS InsertedByName,
                {receipt_date_expr} AS ReceiptDate,
                m.Receipt_Date AS ReceiptDateMst,
                ISNULL(CONVERT(NVARCHAR(80), m.CReceipt_No), '') AS ReceiptNo,
                CAST(ISNULL(m.Amount, 0) AS FLOAT) AS ReceiptMstAmount,
                CAST(ISNULL(m.NetAmt, ISNULL(m.Amount, 0)) AS FLOAT) AS ReceiptNetAmt,
                CAST(ISNULL(m.GrossAmt, ISNULL(m.Amount, 0)) AS FLOAT) AS ReceiptGrossAmt,
                {tds_amt_expr} AS TDSAmt,
                {mst_writeoff_expr} AS WriteOffAmt,
                CAST(ISNULL(m.Cancelstatus, 0) AS INT) AS CancelStatus,
                ISNULL(CONVERT(NVARCHAR(120), m.UTRNo), '') AS UTRNo,
                CAST(ISNULL(m.CPayment_Mode, 0) AS INT) AS PaymentModeId,
                {payment_mode_expr} AS PaymentMode,
                {rebate_discount_expr} AS RebateDiscountAmt,
                CAST({receipt_source_expr} AS NVARCHAR(40)) AS ReceiptBillSourceKey,
                CAST(NULLIF(m.VisitID, 0) AS INT) AS MstVisitId,
                CAST(NULLIF(m.PatientID, 0) AS INT) AS MstPatientId
            FROM dbo.Corp_Receipt_Dtl d WITH (NOLOCK)
            LEFT JOIN dbo.Corp_Receipt_Mst m WITH (NOLOCK)
                ON d.receiptId = m.Receipt_ID
            LEFT JOIN dbo.Corp_Bill_Mst b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            LEFT JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            {payment_mode_join}
            {receipt_user_join}
            {receipt_scope_clause}
        """
        if receipt_scope_params:
            receipts_df = pd.read_sql(receipts_sql, conn, params=receipt_scope_params)
        else:
            receipts_df = pd.read_sql(receipts_sql, conn)

        if bills_df is None:
            bills_df = pd.DataFrame()
        if receipts_df is None:
            receipts_df = pd.DataFrame()

        if not bills_df.empty:
            bills_df.columns = [c.strip() for c in bills_df.columns]
            bills_df["Unit"] = (unit or "").upper()
        if not receipts_df.empty:
            receipts_df.columns = [c.strip() for c in receipts_df.columns]
            receipts_df["Unit"] = (unit or "").upper()

        return {
            "bills": bills_df,
            "receipts": receipts_df,
            "meta": {
                "has_dtl_receipt_date": bool(has_dtl_receipt_date),
                "has_rebate_discount_amt": bool(has_rebate_discount_amt),
                "has_tds_amt": bool(has_tds_amt),
                "has_receipt_writeoff_amt": bool(has_mst_writeoff_amt),
                "has_opening_writeoff_amt": bool(has_opening_writeoff_amt),
                "has_bill_audited_flag": bool(has_bill_audited_flag),
                "receipt_writeoff_column": mst_writeoff_col,
                "opening_writeoff_column": opening_writeoff_col,
                "bill_audited_column": bill_audited_col,
                "receipt_source_column": receipt_source_col,
                "receipt_source_backfill": receipt_source_backfill,
                "cutoff_date": cutoff_date,
            },
        }
    except Exception as e:
        print(f"Error fetching corporate reconciliation raw ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def apply_corporate_reconciliation_writeoff(
    unit: str,
    *,
    source_key: str,
    bill_id: int,
    writeoff_amount: float,
    target_receipt_id: int | None = None,
    actor_user_id: int | None = None,
    writeoff_entry_date=None,
):
    """
    Persist write-off amount entry for a corporate reconciliation bill.
    Notes:
      - Updates only write-off column.
      - Does NOT update any due column.
    """
    conn = get_sql_connection(unit)
    if not conn:
        return {"status": "error", "message": f"Could not connect to {unit}"}

    try:
        def _table_cols_map(table_name: str) -> dict:
            if not table_name:
                return {}
            try:
                preview_df = pd.read_sql(f"SELECT TOP 0 * FROM {table_name}", conn)
                return {str(c).strip().lower(): str(c).strip() for c in preview_df.columns}
            except Exception:
                return {}

        def _pick_col(cols_map: dict, candidates: list[str]):
            for cand in candidates:
                key = str(cand or "").strip().lower()
                if key and key in cols_map:
                    return cols_map[key]
            return None

        def _to_pos_int(value):
            try:
                parsed = int(str(value).strip())
            except Exception:
                return None
            return parsed if parsed > 0 else None

        source_norm = str(source_key or "").strip().upper()
        bill_id_int = _to_pos_int(bill_id)
        if not bill_id_int:
            return {"status": "error", "message": "Invalid bill id"}

        try:
            amount = float(writeoff_amount)
        except Exception:
            amount = 0.0
        if amount <= 0:
            return {"status": "error", "message": "Write-off amount must be greater than zero"}

        schema_info = _ensure_corporate_writeoff_columns_conn(conn)

        cursor = conn.cursor()

        if source_norm == "OPENING":
            opening_cols = _table_cols_map("dbo.CorpOpening")
            opening_writeoff_col = _pick_col(opening_cols, CORP_RECON_WRITEOFF_CANDIDATES) or schema_info.get("opening_column")
            opening_updated_on_col = _pick_col(
                opening_cols,
                ["UpdatedOn", "Updated_On", "ModifiedOn", "LastUpdatedOn", "AccUpdatedDate", "accUpdatedDate"],
            )
            if not opening_writeoff_col:
                return {
                    "status": "error",
                    "message": "Write-off column not found in CorpOpening. Add a write-off amount column first.",
                }

            cursor.execute("SELECT TOP 1 1 FROM dbo.CorpOpening WITH (NOLOCK) WHERE OPId = ?", (bill_id_int,))
            if not cursor.fetchone():
                return {"status": "error", "message": f"Opening bill {bill_id_int} not found"}

            opening_set_sql = (
                f"SET [{opening_writeoff_col}] = CAST(ISNULL([{opening_writeoff_col}], 0) AS FLOAT) + ?"
            )
            if opening_updated_on_col:
                opening_set_sql += f", [{opening_updated_on_col}] = GETDATE()"
            cursor.execute(
                f"UPDATE dbo.CorpOpening "
                f"{opening_set_sql} "
                f"WHERE OPId = ?",
                (amount, bill_id_int),
            )
            try:
                conn.commit()
            except Exception:
                pass

            cursor.execute(
                f"SELECT CAST(ISNULL([{opening_writeoff_col}], 0) AS FLOAT) AS WriteOffTotal "
                f"FROM dbo.CorpOpening WITH (NOLOCK) WHERE OPId = ?",
                (bill_id_int,),
            )
            rec = cursor.fetchone()
            new_total = float(rec[0]) if rec and rec[0] is not None else 0.0
            return {
                "status": "success",
                "source_key": source_norm,
                "bill_id": bill_id_int,
                "writeoff_added": float(amount),
                "writeoff_total": new_total,
                "target_receipt_id": None,
                "writeoff_column": opening_writeoff_col,
            }

        if source_norm == _corp_receipt_bill_source_key_for_unit(unit):
            mst_cols = _table_cols_map("dbo.Corp_Receipt_Mst")
            dtl_cols = _table_cols_map("dbo.Corp_Receipt_Dtl")
            mst_writeoff_col = _pick_col(mst_cols, CORP_RECON_WRITEOFF_CANDIDATES) or schema_info.get("receipt_column")
            mst_updated_on_col = _pick_col(
                mst_cols,
                ["Updated_On", "UpdatedOn", "ModifiedOn", "LastUpdatedOn", "accUpdatedDate", "AccUpdatedDate"],
            )
            dtl_receipt_date_col = _pick_col(dtl_cols, ["ReceiptDate"])
            if not mst_writeoff_col:
                return {
                    "status": "error",
                    "message": "Write-off column not found in Corp_Receipt_Mst. Add a write-off amount column first.",
                }

            receipt_id_int = _to_pos_int(target_receipt_id)
            created_receipt_shell = False
            created_receipt_no = None
            if receipt_id_int:
                cursor.execute(
                    "SELECT TOP 1 1 FROM dbo.Corp_Receipt_Dtl WITH (NOLOCK) WHERE billId = ? AND receiptId = ?",
                    (bill_id_int, receipt_id_int),
                )
                if not cursor.fetchone():
                    return {
                        "status": "error",
                        "message": f"Receipt {receipt_id_int} is not linked to bill {bill_id_int}",
                    }
            else:
                receipt_date_expr = f"d.[{dtl_receipt_date_col}]" if dtl_receipt_date_col else "m.Receipt_Date"
                cursor.execute(
                    f"""
                    SELECT TOP 1 CAST(d.receiptId AS INT) AS ReceiptId
                    FROM dbo.Corp_Receipt_Dtl d WITH (NOLOCK)
                    LEFT JOIN dbo.Corp_Receipt_Mst m WITH (NOLOCK)
                        ON d.receiptId = m.Receipt_ID
                    WHERE d.billId = ?
                    ORDER BY
                        CASE WHEN ISNULL(m.Cancelstatus, 0) = 1 THEN 1 ELSE 0 END ASC,
                        ISNULL({receipt_date_expr}, m.Receipt_Date) DESC,
                        d.receiptId DESC
                    """,
                    (bill_id_int,),
                )
                row = cursor.fetchone()
                receipt_id_int = _to_pos_int(row[0]) if row and row[0] not in (None, "") else None
                if not receipt_id_int:
                    shell_result = create_corporate_receipt(
                        unit,
                        bill_id=bill_id_int,
                        bill_source_key=source_norm,
                        receipt_date=writeoff_entry_date or datetime.now(tz=LOCAL_TZ).date().isoformat(),
                        payment_mode=5,
                        approved_amount=0.0,
                        tds_amount=0.0,
                        received_amount=0.0,
                        rebate_amount=0.0,
                        utr_no="",
                        patient_id=None,
                        visit_id=None,
                        user_id=actor_user_id,
                    )
                    if not isinstance(shell_result, dict) or str(shell_result.get("status") or "").lower() != "success":
                        return {
                            "status": "error",
                            "message": (
                                shell_result.get("message")
                                if isinstance(shell_result, dict) and shell_result.get("message")
                                else "Unable to create a linked receipt row for write-off."
                            ),
                        }
                    receipt_id_int = _to_pos_int(shell_result.get("receipt_id"))
                    if not receipt_id_int:
                        return {
                            "status": "error",
                            "message": "Write-off receipt link could not be created.",
                        }
                    created_receipt_shell = True
                    created_receipt_no = str(shell_result.get("receipt_no") or "").strip() or None
                if not receipt_id_int:
                    return {
                        "status": "error",
                        "message": "Unable to resolve receipt target for write-off.",
                    }

            mst_set_sql = (
                f"SET [{mst_writeoff_col}] = CAST(ISNULL([{mst_writeoff_col}], 0) AS FLOAT) + ?"
            )
            if mst_updated_on_col:
                mst_set_sql += f", [{mst_updated_on_col}] = GETDATE()"
            cursor.execute(
                f"UPDATE dbo.Corp_Receipt_Mst "
                f"{mst_set_sql} "
                f"WHERE Receipt_ID = ?",
                (amount, receipt_id_int),
            )
            try:
                conn.commit()
            except Exception:
                pass

            cursor.execute(
                f"SELECT CAST(ISNULL([{mst_writeoff_col}], 0) AS FLOAT) AS WriteOffTotal "
                f"FROM dbo.Corp_Receipt_Mst WITH (NOLOCK) WHERE Receipt_ID = ?",
                (receipt_id_int,),
            )
            rec = cursor.fetchone()
            new_total = float(rec[0]) if rec and rec[0] is not None else 0.0

            return {
                "status": "success",
                "source_key": source_norm,
                "bill_id": bill_id_int,
                "writeoff_added": float(amount),
                "writeoff_total": new_total,
                "target_receipt_id": int(receipt_id_int),
                "created_receipt_shell": bool(created_receipt_shell),
                "created_receipt_no": created_receipt_no,
                "writeoff_column": mst_writeoff_col,
            }

        return {
            "status": "error",
            "message": "Write-off is supported only for Opening and Corporate Bill rows.",
        }

    except Exception as e:
        return {"status": "error", "message": f"Failed to post write-off: {e}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def apply_corporate_reconciliation_suspense_audit(
    unit: str,
    *,
    bill_ids,
    audited: bool = True,
    updated_by_id: int | None = None,
):
    """
    Mark/unmark suspense anomaly bills as audited in dbo.Corp_Bill_Mst.
    """
    conn = get_sql_connection(unit)
    if not conn:
        return {"status": "error", "message": f"Could not connect to {unit}"}

    try:
        normalized_bill_ids = sorted(
            {
                int(v)
                for v in (bill_ids or [])
                if str(v).strip().lstrip("-").isdigit() and int(v) > 0
            }
        )
        if not normalized_bill_ids:
            return {"status": "error", "message": "No valid bill ids supplied"}

        schema_info = _ensure_corporate_bill_audited_column_conn(conn)
        audited_col = (schema_info or {}).get("bill_audited_column")
        if not audited_col:
            return {"status": "error", "message": "Audited column not found in Corp_Bill_Mst."}

        def _table_cols_map(table_name: str) -> dict:
            try:
                preview_df = pd.read_sql(f"SELECT TOP 0 * FROM {table_name}", conn)
                return {str(c).strip().lower(): str(c).strip() for c in preview_df.columns}
            except Exception:
                return {}

        bill_cols = _table_cols_map("dbo.Corp_Bill_Mst")
        updated_on_col = None
        for cand in ["Updated_On", "UpdatedOn", "ModifiedOn", "accUpdatedDate", "AccUpdatedDate"]:
            key = str(cand or "").strip().lower()
            if key in bill_cols:
                updated_on_col = bill_cols[key]
                break
        updated_by_col = None
        for cand in ["Updated_By", "UpdatedBy", "updated_by"]:
            key = str(cand or "").strip().lower()
            if key in bill_cols:
                updated_by_col = bill_cols[key]
                break

        cursor = conn.cursor()
        id_placeholders = ",".join(["?"] * len(normalized_bill_ids))
        cursor.execute(
            f"SELECT CAST(CBill_ID AS INT) AS BillId FROM dbo.Corp_Bill_Mst WITH (NOLOCK) "
            f"WHERE CBill_ID IN ({id_placeholders})",
            tuple(normalized_bill_ids),
        )
        found_rows = cursor.fetchall() or []
        found_ids = sorted({int(r[0]) for r in found_rows if r and r[0] is not None})
        if not found_ids:
            return {
                "status": "success",
                "updated_count": 0,
                "requested_count": len(normalized_bill_ids),
                "matched_bill_ids": [],
                "missing_bill_ids": normalized_bill_ids,
                "audited_value": 1 if audited else 0,
                "audited_column": audited_col,
            }

        set_sql = f"SET [{audited_col}] = ?"
        update_params = [1 if audited else 0]
        if updated_on_col:
            set_sql += f", [{updated_on_col}] = GETDATE()"
        if updated_by_col and updated_by_id is not None and int(updated_by_id) > 0:
            set_sql += f", [{updated_by_col}] = ?"
            update_params.append(int(updated_by_id))

        update_placeholders = ",".join(["?"] * len(found_ids))
        update_params.extend(found_ids)
        cursor.execute(
            f"UPDATE dbo.Corp_Bill_Mst {set_sql} WHERE CBill_ID IN ({update_placeholders})",
            tuple(update_params),
        )
        try:
            conn.commit()
        except Exception:
            pass

        missing_ids = [bid for bid in normalized_bill_ids if bid not in set(found_ids)]
        return {
            "status": "success",
            "updated_count": int(len(found_ids)),
            "requested_count": int(len(normalized_bill_ids)),
            "matched_bill_ids": found_ids,
            "missing_bill_ids": missing_ids,
            "audited_value": 1 if audited else 0,
            "audited_column": audited_col,
        }
    except Exception as e:
        return {"status": "error", "message": f"Failed to update audited flag: {e}"}
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Corporate Updates Feed =====================
def fetch_corporate_updates_raw(unit: str, lookback_hours: int = 24, limit: int = 1200):
    """
    Fetch recent additions/updates from key corporate tables.
    Returns:
      {
        "events": pd.DataFrame([...]),
        "meta": {"from_ts": "...", "as_of": "...", "lookback_hours": int, "limit": int}
      }
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for corporate updates")
        return None
    try:
        def _cols_map(table_name: str) -> dict:
            if not table_name:
                return {}
            try:
                cols_df = pd.read_sql(
                    "SELECT name FROM sys.columns WHERE object_id = OBJECT_ID(?)",
                    conn,
                    params=[table_name],
                )
            except Exception:
                return {}
            if cols_df is None or cols_df.empty:
                return {}
            return {str(c).strip().lower(): str(c).strip() for c in cols_df["name"].tolist() if str(c).strip()}

        def _pick_col(cols_map: dict, candidates: list[str]) -> str | None:
            for cand in candidates:
                key = str(cand or "").strip().lower()
                if key and key in cols_map:
                    return cols_map[key]
            return None

        def _first_existing_table(candidates: list[str]) -> str | None:
            for table_name in candidates:
                try:
                    pd.read_sql(f"SELECT TOP 0 * FROM {table_name}", conn)
                    return table_name
                except Exception:
                    continue
            return None

        def _q_ident(name: str) -> str:
            return f"[{str(name).replace(']', ']]')}]"

        def _safe_int_expr(raw_expr: str) -> str:
            expr = str(raw_expr or "").strip()
            if not expr:
                return "CAST(NULL AS INT)"
            txt = f"LTRIM(RTRIM(CONVERT(NVARCHAR(100), {expr})))"
            return (
                "CASE "
                f"WHEN {txt} = '' THEN NULL "
                f"WHEN {txt} LIKE '%[^0-9]%' THEN NULL "
                f"ELSE CAST({expr} AS INT) END"
            )

        lookback_hours = int(lookback_hours or 24)
        lookback_hours = max(1, min(24 * 90, lookback_hours))
        limit = int(limit or 1200)
        limit = max(100, min(8000, limit))
        per_table_limit = max(50, min(2500, int(limit)))

        now_ts = datetime.now(tz=LOCAL_TZ)
        from_ts = now_ts - timedelta(hours=lookback_hours)
        from_ts_sql = from_ts.strftime("%Y-%m-%d %H:%M:%S")

        user_table = _first_existing_table([
            "dbo.User_Mst",
            "dbo.user_mst",
            "dbo.UserMst",
        ])
        user_cols = _cols_map(user_table) if user_table else {}
        user_id_col = _pick_col(user_cols, ["UserId", "Userid", "User_ID", "Id", "AccountId"]) if user_cols else None
        user_name_col = _pick_col(user_cols, ["UserName", "User_Name", "Username", "Name", "EmpName"]) if user_cols else None

        table_configs = [
            {
                "table_key": "corp_receipt_mst",
                "table_label": "Corp_Receipt_Mst",
                "table_name": "dbo.Corp_Receipt_Mst",
                "pk_candidates": ["Receipt_ID", "receiptId", "ReceiptId", "Id"],
                "add_time_candidates": ["Receipt_Date", "ReceiptDate", "InsertedOn", "CreatedOn"],
                "upd_time_candidates": ["Updated_On", "UpdatedOn", "ModifiedOn"],
                "actor_candidates": ["Updated_By", "UpdatedBy", "InsertedBy"],
                "detail_candidates": ["CReceipt_No", "Amount", "NetAmt", "WriteOffAmt", "rebateDiscountAmt", "CPayment_Mode", "Cancelstatus", "UTRNo"],
            },
            {
                "table_key": "corp_receipt_dtl",
                "table_label": "Corp_Receipt_Dtl",
                "table_name": "dbo.Corp_Receipt_Dtl",
                "pk_candidates": ["recDtlId", "RecDtlId", "Id"],
                "add_time_candidates": ["insertedOn", "ReceiptDate", "CreatedOn"],
                "upd_time_candidates": ["UpdatedOn", "ModifiedOn"],
                "actor_candidates": ["insertedBy", "UpdatedBy", "InsertedBy"],
                "detail_candidates": ["receiptId", "billId", "receiptAmt", "billAmt", "dueAmt", "visitId", "PatientId"],
            },
            {
                "table_key": "corp_bill_mst",
                "table_label": "Corp_Bill_Mst",
                "table_name": "dbo.Corp_Bill_Mst",
                "pk_candidates": ["CBill_ID", "CBillId", "BillId", "Id"],
                "add_time_candidates": ["Submit_Date", "CBill_Date", "CreatedOn"],
                "upd_time_candidates": ["Updated_On", "accUpdatedDate", "ModifiedOn"],
                "actor_candidates": ["Updated_By", "UpdatedBy", "InsertedBy"],
                "detail_candidates": ["CBill_NO", "Bill_No", "CAmount", "Due_Amt", "Status", "Audited", "Visit_ID", "PatientID"],
            },
            {
                "table_key": "corpopening",
                "table_label": "CorpOpening",
                "table_name": "dbo.CorpOpening",
                "pk_candidates": ["OPId", "OpId", "Id"],
                "add_time_candidates": ["DueDate", "CreatedOn", "InsertedOn"],
                "upd_time_candidates": ["UpdatedOn", "ModifiedOn"],
                "actor_candidates": ["UpdatedBy", "InsertedBy"],
                "detail_candidates": ["RefNo", "PatientName", "PatientId", "DueAmount", "ReceiptAmt", "WriteOffAmt", "DueDate", "ReceiptId", "PatientTypeId", "PatientSubTypeId"],
            },
        ]
        if _is_sharpsight_unit(unit):
            table_configs = [
                table_configs[0],
                table_configs[1],
                {
                    "table_key": "corp_bill_mst",
                    "table_label": "Corp_Bill_Mst_AHL",
                    "table_name": "dbo.Corp_Bill_Mst_AHL",
                    "pk_candidates": ["CBill_ID", "CBillId", "BillId", "Id"],
                    "add_time_candidates": ["Submit_Date", "CBill_Date", "Old_Bill_Date", "visitDate"],
                    "upd_time_candidates": ["accUpdatedDate", "Updated_On", "ModifiedOn"],
                    "actor_candidates": ["accUserId", "Updated_By", "UpdatedBy", "InsertedBy"],
                    "detail_candidates": ["CBill_NO", "Bill_No", "CAmount", "Due_Amt", "Status", "Visit_ID", "PatientID", "approvalAmt"],
                },
            ]

        event_frames = []
        for cfg in table_configs:
            table_name = cfg["table_name"]
            cols_map = _cols_map(table_name)
            if not cols_map:
                continue

            pk_col = _pick_col(cols_map, cfg["pk_candidates"])
            if not pk_col:
                continue
            add_time_col = _pick_col(cols_map, cfg["add_time_candidates"])
            upd_time_col = _pick_col(cols_map, cfg["upd_time_candidates"])
            actor_col = _pick_col(cols_map, cfg["actor_candidates"])

            detail_cols = []
            for cand in cfg["detail_candidates"]:
                found = _pick_col(cols_map, [cand])
                if found and found not in detail_cols:
                    detail_cols.append(found)
                if len(detail_cols) >= 6:
                    break

            detail_aliases = []
            detail_select = []
            for idx, col in enumerate(detail_cols):
                alias = f"Detail{idx + 1}"
                detail_aliases.append((alias, col))
                detail_select.append(f"CONVERT(NVARCHAR(300), {_q_ident(col)}) AS {alias}")
            while len(detail_aliases) < 6:
                alias = f"Detail{len(detail_aliases) + 1}"
                detail_aliases.append((alias, ""))
                detail_select.append(f"CAST(NULL AS NVARCHAR(300)) AS {alias}")

            actor_raw_expr = f"CONVERT(NVARCHAR(120), {_q_ident(actor_col)})" if actor_col else "CAST(NULL AS NVARCHAR(120))"
            actor_id_expr = _safe_int_expr(_q_ident(actor_col)) if actor_col else "CAST(NULL AS INT)"
            actor_join_sql = ""
            actor_name_expr = actor_raw_expr
            if actor_col and user_table and user_id_col and user_name_col:
                actor_join_sql = (
                    f"LEFT JOIN {user_table} u_evt WITH (NOLOCK) "
                    f"ON u_evt.[{user_id_col}] = {actor_id_expr}"
                )
                actor_name_expr = (
                    f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), u_evt.[{user_name_col}]), {actor_raw_expr})))"
                )

            def _read_event_block(event_type: str, time_col: str | None):
                if not time_col:
                    return None
                raw_time_expr = f"CONVERT(NVARCHAR(50), {_q_ident(time_col)})"
                time_expr = (
                    "CASE "
                    f"WHEN ISDATE({raw_time_expr}) = 1 THEN CAST({_q_ident(time_col)} AS DATETIME) "
                    "ELSE NULL END"
                )
                where_sql = f"{time_expr} IS NOT NULL AND {time_expr} >= ?"
                if event_type == "update" and add_time_col and add_time_col.lower() != time_col.lower():
                    raw_add_expr = f"CONVERT(NVARCHAR(50), {_q_ident(add_time_col)})"
                    add_expr = (
                        "CASE "
                        f"WHEN ISDATE({raw_add_expr}) = 1 THEN CAST({_q_ident(add_time_col)} AS DATETIME) "
                        "ELSE NULL END"
                    )
                    where_sql += f" AND ({add_expr} IS NULL OR {time_expr} > {add_expr})"
                sql = f"""
                    SELECT TOP {int(per_table_limit)}
                        CAST('{cfg["table_key"]}' AS NVARCHAR(80)) AS TableKey,
                        CAST('{cfg["table_label"]}' AS NVARCHAR(120)) AS TableLabel,
                        CAST('{event_type}' AS NVARCHAR(20)) AS EventType,
                        {time_expr} AS EventTime,
                        CONVERT(NVARCHAR(120), {_q_ident(pk_col)}) AS RecordId,
                        {actor_id_expr} AS ChangedById,
                        {actor_raw_expr} AS ChangedByRaw,
                        {actor_name_expr} AS ChangedBy,
                        {", ".join(detail_select)}
                    FROM {table_name} WITH (NOLOCK)
                    {actor_join_sql}
                    WHERE {where_sql}
                    ORDER BY {time_expr} DESC, {_q_ident(pk_col)} DESC
                """
                try:
                    return pd.read_sql(sql, conn, params=[from_ts_sql])
                except Exception:
                    return None

            add_df = _read_event_block("addition", add_time_col)
            if add_df is not None and not add_df.empty:
                add_df["DetailPairs"] = add_df.apply(
                    lambda row: [
                        {"name": col_name, "value": row.get(alias)}
                        for alias, col_name in detail_aliases
                        if col_name and row.get(alias) not in (None, "", "NULL")
                    ],
                    axis=1,
                )
                event_frames.append(add_df)

            upd_df = _read_event_block("update", upd_time_col)
            if upd_df is not None and not upd_df.empty:
                upd_df["DetailPairs"] = upd_df.apply(
                    lambda row: [
                        {"name": col_name, "value": row.get(alias)}
                        for alias, col_name in detail_aliases
                        if col_name and row.get(alias) not in (None, "", "NULL")
                    ],
                    axis=1,
                )
                event_frames.append(upd_df)

        if event_frames:
            events_df = pd.concat(event_frames, ignore_index=True)
        else:
            events_df = pd.DataFrame(
                columns=[
                    "TableKey",
                    "TableLabel",
                    "EventType",
                    "EventTime",
                    "RecordId",
                    "ChangedBy",
                    "Detail1",
                    "Detail2",
                    "Detail3",
                    "Detail4",
                    "Detail5",
                    "Detail6",
                    "DetailPairs",
                ]
            )

        if not events_df.empty:
            events_df["EventTime"] = pd.to_datetime(events_df["EventTime"], errors="coerce")
            events_df = events_df[events_df["EventTime"].notna()].copy()
            events_df = events_df.sort_values(["EventTime", "RecordId"], ascending=[False, False], na_position="last")
            events_df = events_df.head(limit).copy()
            events_df["Unit"] = (unit or "").upper()

        return {
            "events": events_df,
            "meta": {
                "from_ts": from_ts.isoformat(),
                "as_of": now_ts.isoformat(),
                "lookback_hours": int(lookback_hours),
                "limit": int(limit),
            },
        }
    except Exception as e:
        print(f"Error fetching corporate updates raw ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_corporate_updates_context(
    unit: str,
    bill_ids: list[int] | None = None,
    receipt_ids: list[int] | None = None,
    visit_ids: list[int] | None = None,
    patient_ids: list[int] | None = None,
):
    """
    Fetch lightweight context for updates panel enrichment:
    - bill/opening -> patient + visit context
    - receipt -> linked bill/visit/patient ids
    - visit -> visit type/dates + patient/type/subtype labels
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for corporate updates context")
        return None
    try:
        def _norm_ids(values):
            out = []
            seen = set()
            for raw in values or []:
                try:
                    val = int(raw)
                except Exception:
                    continue
                if val <= 0 or val in seen:
                    continue
                seen.add(val)
                out.append(val)
            return out

        def _chunks(values, size=700):
            seq = list(values or [])
            for i in range(0, len(seq), size):
                yield seq[i : i + size]

        bill_ids = _norm_ids(bill_ids)
        receipt_ids = _norm_ids(receipt_ids)
        visit_ids = _norm_ids(visit_ids)
        patient_ids = _norm_ids(patient_ids)
        is_sharpsight = _is_sharpsight_unit(unit)

        bill_map = {}
        receipt_map = {}
        visit_map = {}

        for chunk in _chunks(bill_ids):
            placeholders = ",".join("?" for _ in chunk)
            if is_sharpsight:
                bill_sql = f"""
                    SELECT
                        CAST(b.CBill_ID AS INT) AS BillId,
                        CAST(NULLIF(COALESCE(v.Visit_ID, b.Visit_ID), 0) AS INT) AS VisitId,
                        CAST(NULLIF(COALESCE(v.PatientID, b.PatientID), 0) AS INT) AS PatientId,
                        ISNULL(v.TypeOfVisit, '') AS TypeOfVisit,
                        CAST(COALESCE(b.visitDate, v.VisitDate) AS DATETIME) AS VisitDate,
                        CAST(COALESCE(b.dischargeDate, v.DischargeDate) AS DATETIME) AS DischargeDate,
                        CASE
                            WHEN COALESCE(v.PatientID, b.PatientID) IS NOT NULL THEN ISNULL(dbo.fn_patientfullname(COALESCE(v.PatientID, b.PatientID)), '')
                            ELSE ''
                        END AS PatientName,
                        CASE
                            WHEN COALESCE(v.PatientType_ID, b.PatientTypeId) IS NOT NULL THEN ISNULL(dbo.fn_pat_type(COALESCE(v.PatientType_ID, b.PatientTypeId)), '')
                            ELSE ''
                        END AS PatientType,
                        CASE
                            WHEN COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo) IS NOT NULL THEN ISNULL(dbo.fn_patsub_type(COALESCE(v.PatientSubType_ID, b.PatientTypeIdSrNo)), '')
                            ELSE ''
                        END AS PatientSubType
                    FROM dbo.Corp_Bill_Mst_AHL b WITH (NOLOCK)
                    LEFT JOIN dbo.Visit v WITH (NOLOCK)
                        ON v.Visit_ID = b.Visit_ID
                    WHERE b.CBill_ID IN ({placeholders})
                """
            else:
                bill_sql = f"""
                    SELECT
                        CAST(b.CBill_ID AS INT) AS BillId,
                        CAST(NULLIF(b.Visit_ID, 0) AS INT) AS VisitId,
                        CAST(NULLIF(b.PatientID, 0) AS INT) AS PatientId,
                        ISNULL(v.TypeOfVisit, '') AS TypeOfVisit,
                        v.VisitDate,
                        v.DischargeDate,
                        CASE
                            WHEN v.PatientID IS NOT NULL THEN ISNULL(dbo.fn_patientfullname(v.PatientID), '')
                            WHEN b.PatientID IS NOT NULL THEN ISNULL(dbo.fn_patientfullname(b.PatientID), '')
                            ELSE ''
                        END AS PatientName,
                        CASE
                            WHEN v.PatientType_ID IS NOT NULL THEN ISNULL(dbo.fn_pat_type(v.PatientType_ID), '')
                            WHEN b.PatientTypeId IS NOT NULL THEN ISNULL(dbo.fn_pat_type(b.PatientTypeId), '')
                            ELSE ''
                        END AS PatientType,
                        CASE
                            WHEN v.PatientSubType_ID IS NOT NULL THEN ISNULL(dbo.fn_patsub_type(v.PatientSubType_ID), '')
                            WHEN b.PatientTypeIdSrNo IS NOT NULL THEN ISNULL(dbo.fn_patsub_type(b.PatientTypeIdSrNo), '')
                            ELSE ''
                        END AS PatientSubType
                    FROM dbo.Corp_Bill_Mst b WITH (NOLOCK)
                    LEFT JOIN dbo.Visit v WITH (NOLOCK)
                        ON v.Visit_ID = b.Visit_ID
                    WHERE b.CBill_ID IN ({placeholders})
                """
            bill_df = pd.read_sql(bill_sql, conn, params=chunk)
            if bill_df is None or bill_df.empty:
                bill_df = pd.DataFrame()
            if not bill_df.empty:
                bill_df["VisitDate"] = pd.to_datetime(bill_df.get("VisitDate"), errors="coerce")
                bill_df["DischargeDate"] = pd.to_datetime(bill_df.get("DischargeDate"), errors="coerce")
                for _, row in bill_df.iterrows():
                    try:
                        bill_id = int(row.get("BillId"))
                    except Exception:
                        continue
                    bill_map[bill_id] = {
                        "bill_id": bill_id,
                        "visit_id": int(row["VisitId"]) if pd.notna(row.get("VisitId")) else None,
                        "patient_id": int(row["PatientId"]) if pd.notna(row.get("PatientId")) else None,
                        "patient_name": str(row.get("PatientName") or "").strip(),
                        "patient_type": str(row.get("PatientType") or "").strip(),
                        "patient_subtype": str(row.get("PatientSubType") or "").strip(),
                        "type_of_visit": str(row.get("TypeOfVisit") or "").strip(),
                        "visit_date": row["VisitDate"].strftime("%Y-%m-%d") if pd.notna(row.get("VisitDate")) else "",
                        "discharge_date": row["DischargeDate"].strftime("%Y-%m-%d") if pd.notna(row.get("DischargeDate")) else "",
                        "source": "BILL",
                    }
            if is_sharpsight:
                continue

            opening_sql = f"""
                SELECT
                    CAST(o.OPId AS INT) AS BillId,
                    CAST(NULLIF(o.PatientId, 0) AS INT) AS PatientId,
                    ISNULL(CONVERT(NVARCHAR(255), o.PatientName), '') AS PatientName,
                    CASE
                        WHEN o.PatientTypeId IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_pat_type(o.PatientTypeId), '')
                    END AS PatientType,
                    CASE
                        WHEN o.PatientSubTypeId IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_patsub_type(o.PatientSubTypeId), '')
                    END AS PatientSubType
                FROM dbo.CorpOpening o WITH (NOLOCK)
                WHERE o.OPId IN ({placeholders})
            """
            opening_df = pd.read_sql(opening_sql, conn, params=chunk)
            if opening_df is None or opening_df.empty:
                continue
            for _, row in opening_df.iterrows():
                try:
                    bill_id = int(row.get("BillId"))
                except Exception:
                    continue
                if bill_id in bill_map:
                    continue
                bill_map[bill_id] = {
                    "bill_id": bill_id,
                    "visit_id": None,
                    "patient_id": int(row["PatientId"]) if pd.notna(row.get("PatientId")) else None,
                    "patient_name": str(row.get("PatientName") or "").strip(),
                    "patient_type": str(row.get("PatientType") or "").strip(),
                    "patient_subtype": str(row.get("PatientSubType") or "").strip(),
                    "type_of_visit": "",
                    "visit_date": "",
                    "discharge_date": "",
                    "source": "OPENING",
                }

        receipt_visit_ids = set()
        for chunk in _chunks(receipt_ids):
            placeholders = ",".join("?" for _ in chunk)
            receipt_sql = f"""
                SELECT
                    CAST(d.receiptId AS INT) AS ReceiptId,
                    MAX(CASE WHEN ISNULL(d.billId, 0) > 0 THEN CAST(d.billId AS INT) ELSE NULL END) AS BillId,
                    MAX(CASE WHEN ISNULL(d.visitId, 0) > 0 THEN CAST(d.visitId AS INT) ELSE NULL END) AS DtlVisitId,
                    MAX(CASE WHEN ISNULL(d.PatientId, 0) > 0 THEN CAST(d.PatientId AS INT) ELSE NULL END) AS DtlPatientId,
                    MAX(CASE WHEN ISNULL(m.VisitID, 0) > 0 THEN CAST(m.VisitID AS INT) ELSE NULL END) AS MstVisitId,
                    MAX(CASE WHEN ISNULL(m.PatientID, 0) > 0 THEN CAST(m.PatientID AS INT) ELSE NULL END) AS MstPatientId
                FROM dbo.Corp_Receipt_Dtl d WITH (NOLOCK)
                LEFT JOIN dbo.Corp_Receipt_Mst m WITH (NOLOCK)
                    ON d.receiptId = m.Receipt_ID
                WHERE d.receiptId IN ({placeholders})
                GROUP BY d.receiptId
            """
            rec_df = pd.read_sql(receipt_sql, conn, params=chunk)
            if rec_df is None or rec_df.empty:
                continue
            for _, row in rec_df.iterrows():
                try:
                    receipt_id = int(row.get("ReceiptId"))
                except Exception:
                    continue
                bill_id = int(row["BillId"]) if pd.notna(row.get("BillId")) else None
                visit_id = None
                for c in ("DtlVisitId", "MstVisitId"):
                    if pd.notna(row.get(c)):
                        visit_id = int(row.get(c))
                        break
                patient_id = None
                for c in ("DtlPatientId", "MstPatientId"):
                    if pd.notna(row.get(c)):
                        patient_id = int(row.get(c))
                        break
                receipt_map[receipt_id] = {
                    "receipt_id": receipt_id,
                    "bill_id": bill_id,
                    "visit_id": visit_id,
                    "patient_id": patient_id,
                }
                if visit_id:
                    receipt_visit_ids.add(visit_id)

        visit_need = set(visit_ids) | set(receipt_visit_ids)
        for entry in bill_map.values():
            vid = entry.get("visit_id")
            if vid:
                visit_need.add(int(vid))

        for chunk in _chunks(_norm_ids(list(visit_need))):
            placeholders = ",".join("?" for _ in chunk)
            visit_sql = f"""
                SELECT
                    CAST(v.Visit_ID AS INT) AS VisitId,
                    CAST(NULLIF(v.PatientID, 0) AS INT) AS PatientId,
                    ISNULL(v.TypeOfVisit, '') AS TypeOfVisit,
                    v.VisitDate,
                    v.DischargeDate,
                    CASE
                        WHEN v.PatientID IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_patientfullname(v.PatientID), '')
                    END AS PatientName,
                    CASE
                        WHEN v.PatientType_ID IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_pat_type(v.PatientType_ID), '')
                    END AS PatientType,
                    CASE
                        WHEN v.PatientSubType_ID IS NULL THEN ''
                        ELSE ISNULL(dbo.fn_patsub_type(v.PatientSubType_ID), '')
                    END AS PatientSubType
                FROM dbo.Visit v WITH (NOLOCK)
                WHERE v.Visit_ID IN ({placeholders})
            """
            visit_df = pd.read_sql(visit_sql, conn, params=chunk)
            if visit_df is None or visit_df.empty:
                continue
            visit_df["VisitDate"] = pd.to_datetime(visit_df.get("VisitDate"), errors="coerce")
            visit_df["DischargeDate"] = pd.to_datetime(visit_df.get("DischargeDate"), errors="coerce")
            for _, row in visit_df.iterrows():
                try:
                    visit_id = int(row.get("VisitId"))
                except Exception:
                    continue
                visit_map[visit_id] = {
                    "visit_id": visit_id,
                    "patient_id": int(row["PatientId"]) if pd.notna(row.get("PatientId")) else None,
                    "patient_name": str(row.get("PatientName") or "").strip(),
                    "patient_type": str(row.get("PatientType") or "").strip(),
                    "patient_subtype": str(row.get("PatientSubType") or "").strip(),
                    "type_of_visit": str(row.get("TypeOfVisit") or "").strip(),
                    "visit_date": row["VisitDate"].strftime("%Y-%m-%d") if pd.notna(row.get("VisitDate")) else "",
                    "discharge_date": row["DischargeDate"].strftime("%Y-%m-%d") if pd.notna(row.get("DischargeDate")) else "",
                }

        return {
            "bill": bill_map,
            "receipt": receipt_map,
            "visit": visit_map,
            "meta": {
                "bill_count": int(len(bill_map)),
                "receipt_count": int(len(receipt_map)),
                "visit_count": int(len(visit_map)),
                "patient_hint_count": int(len(patient_ids)),
            },
        }
    except Exception as e:
        print(f"Error fetching corporate updates context ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def create_corporate_receipt(
    unit: str,
    *,
    bill_id: int,
    bill_source_key: str | None = None,
    receipt_date,
    payment_mode: int,
    approved_amount: float,
    tds_amount: float,
    received_amount: float,
    rebate_amount: float,
    utr_no: str = "",
    patient_id: int | None = None,
    visit_id: int | None = None,
    user_id: int | None = None,
):
    unit_key = str(unit or "").strip().upper()
    conn = get_sql_connection(unit_key)
    if not conn:
        return {"status": "error", "message": f"Could not connect to {unit_key}"}
    receipt_source_info = _ensure_corporate_receipt_source_column_conn(conn) or {}
    receipt_source_col = str(receipt_source_info.get("column") or "").strip() or None

    try:
        bill_id_int = int(bill_id)
    except Exception:
        bill_id_int = 0
    if bill_id_int <= 0:
        return {"status": "error", "message": "Invalid bill id"}

    try:
        receipt_dt = pd.to_datetime(receipt_date, errors="coerce")
    except Exception:
        receipt_dt = pd.NaT
    if pd.isna(receipt_dt):
        return {"status": "error", "message": "Invalid receipt date"}
    receipt_dt_py = receipt_dt.to_pydatetime()

    def _to_float(value):
        try:
            return float(value)
        except Exception:
            return 0.0

    approved_amt = _to_float(approved_amount)
    tds_amt = _to_float(tds_amount)
    received_amt = _to_float(received_amount)
    rebate_amt = _to_float(rebate_amount)
    payment_mode_int = int(payment_mode or 0)
    if payment_mode_int <= 0:
        payment_mode_int = 5

    source_norm = str(bill_source_key or "").strip().upper() or _corp_receipt_bill_source_key_for_unit(unit_key)
    allowed_sources = {SHARPSIGHT_RECEIPT_SOURCE_OPENING, _corp_receipt_bill_source_key_for_unit(unit_key)}
    if source_norm not in allowed_sources:
        return {"status": "error", "message": "Invalid bill source key"}

    if source_norm == SHARPSIGHT_RECEIPT_SOURCE_OPENING:
        bill_df = pd.read_sql(
            """
            SELECT TOP 1
                CAST(o.OPId AS INT) AS BillId,
                CAST(ISNULL(o.DueAmount, 0) AS FLOAT) AS BillAmount,
                CAST(NULL AS INT) AS VisitId,
                CAST(NULLIF(o.PatientId, 0) AS INT) AS PatientId,
                ISNULL(NULLIF(CONVERT(NVARCHAR(80), o.RefNo), ''), CONVERT(NVARCHAR(80), o.OPId)) AS BillNo
            FROM dbo.CorpOpening o WITH (NOLOCK)
            WHERE o.OPId = ?
            """,
            conn,
            params=[bill_id_int],
        )
    else:
        bill_table = _resolve_corporate_bill_table_conn(conn, unit_key)
        if not bill_table:
            return {"status": "error", "message": f"Corporate bill table not found for {unit_key}"}
        bill_df = pd.read_sql(
            f"""
            SELECT TOP 1
                CAST(b.CBill_ID AS INT) AS BillId,
                CAST(ISNULL(b.CAmount, 0) AS FLOAT) AS BillAmount,
                CAST(NULLIF(COALESCE(v.Visit_ID, b.Visit_ID), 0) AS INT) AS VisitId,
                CAST(NULLIF(COALESCE(v.PatientID, b.PatientID), 0) AS INT) AS PatientId,
                ISNULL(
                    NULLIF(CONVERT(NVARCHAR(80), b.CBill_NO), ''),
                    ISNULL(NULLIF(CONVERT(NVARCHAR(80), b.Bill_No), ''), CONVERT(NVARCHAR(80), b.CBill_ID))
                ) AS BillNo
            FROM {bill_table} b WITH (NOLOCK)
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = b.Visit_ID
            WHERE b.CBill_ID = ?
            """,
            conn,
            params=[bill_id_int],
        )
    if bill_df is None or bill_df.empty:
        target_label = "opening" if source_norm == SHARPSIGHT_RECEIPT_SOURCE_OPENING else "bill"
        return {"status": "error", "message": f"Selected {target_label} {bill_id_int} was not found."}

    bill_row = bill_df.iloc[0]
    bill_amount_val = _to_float(bill_row.get("BillAmount"))
    if bill_amount_val <= 0:
        return {"status": "error", "message": "Selected bill has invalid corporate amount."}

    visit_id_val = visit_id if visit_id and int(visit_id) > 0 else bill_row.get("VisitId")
    patient_id_val = patient_id if patient_id and int(patient_id) > 0 else bill_row.get("PatientId")
    try:
        visit_id_val = int(visit_id_val) if pd.notna(visit_id_val) and int(visit_id_val) > 0 else 0
    except Exception:
        visit_id_val = 0
    try:
        patient_id_val = int(patient_id_val) if pd.notna(patient_id_val) and int(patient_id_val) > 0 else 0
    except Exception:
        patient_id_val = 0

    due_amount_val = round(bill_amount_val - (received_amt + tds_amt + rebate_amt), 2)
    if abs(due_amount_val) <= 0.01:
        due_amount_val = 0.0
    try:
        actor_id = int(user_id) if user_id not in (None, "", " ") else 0
    except Exception:
        actor_id = 0
    if actor_id <= 0:
        actor_id = 0

    dtl_has_receipt_date = bool(_pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", ["ReceiptDate"]))
    cursor = conn.cursor()
    cursor.execute(
        """
        SET NOCOUNT ON;
        DECLARE @new_receipt TABLE (ReceiptId INT);
        INSERT INTO dbo.Corp_Receipt_Mst
            (CBill_ID, PatientID, Amount, Receipt_Date, CPayment_Mode, Updated_By, Updated_On, VisitID, Cancelstatus, TDSAmt, GrossAmt, NetAmt, UTRNo, rebateDiscountAmt)
        OUTPUT INSERTED.Receipt_ID INTO @new_receipt(ReceiptId)
        VALUES
            (?, ?, ?, ?, ?, ?, GETDATE(), ?, ?, ?, ?, ?, ?, ?);
        SELECT TOP 1 ReceiptId FROM @new_receipt;
        """,
        (
            0,
            0,
            received_amt,
            receipt_dt_py,
            payment_mode_int,
            actor_id,
            0,
            0,
            tds_amt,
            approved_amt,
            received_amt,
            str(utr_no or "").strip(),
            rebate_amt,
        ),
    )
    while cursor.description is None:
        if not cursor.nextset():
            break
    rec = cursor.fetchone() if cursor.description is not None else None
    receipt_id = int(rec[0]) if rec and rec[0] is not None else 0
    if receipt_id <= 0:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": "Failed to create receipt master row."}

    receipt_no = f"CR-{receipt_dt_py.year % 100:02d}{receipt_id}"
    cursor.execute(
        "UPDATE dbo.Corp_Receipt_Mst SET CReceipt_No = ? WHERE Receipt_ID = ?",
        (receipt_no, receipt_id),
    )

    dtl_columns = ["receiptId", "billId", "billAmt", "receiptAmt", "dueAmt", "visitId", "insertedBy", "insertedOn", "PatientId"]
    dtl_values = [receipt_id, bill_id_int, bill_amount_val, received_amt, due_amount_val, visit_id_val, actor_id, patient_id_val]
    if dtl_has_receipt_date:
        dtl_columns.append("ReceiptDate")
        dtl_values.append(receipt_dt_py)
    if receipt_source_col:
        dtl_columns.append(receipt_source_col)
        dtl_values.append(source_norm)

    dtl_insert_sql = ", ".join(f"[{col}]" for col in dtl_columns)
    dtl_param_sql = ", ".join("GETDATE()" if str(col).strip().lower() == "insertedon" else "?" for col in dtl_columns)
    cursor.execute(
        f"""
        SET NOCOUNT ON;
        DECLARE @new_receipt_dtl TABLE (ReceiptDetailId INT);
        INSERT INTO dbo.Corp_Receipt_Dtl
            ({dtl_insert_sql})
        OUTPUT INSERTED.recDtlId INTO @new_receipt_dtl(ReceiptDetailId)
        VALUES
            ({dtl_param_sql});
        SELECT TOP 1 ReceiptDetailId FROM @new_receipt_dtl;
        """,
        tuple(dtl_values),
    )
    while cursor.description is None:
        if not cursor.nextset():
            break
    rec_dtl = cursor.fetchone() if cursor.description is not None else None
    receipt_detail_id = int(rec_dtl[0]) if rec_dtl and rec_dtl[0] is not None else 0

    try:
        conn.commit()
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": f"Failed to save receipt: {exc}"}

    return {
        "status": "success",
        "receipt_id": int(receipt_id),
        "receipt_detail_id": int(receipt_detail_id),
        "receipt_no": receipt_no,
        "bill_id": int(bill_id_int),
        "bill_no": str(bill_row.get("BillNo") or "").strip(),
        "bill_amount": float(bill_amount_val),
        "received_amount": float(received_amt),
        "approved_amount": float(approved_amt),
        "tds_amount": float(tds_amt),
        "rebate_amount": float(rebate_amt),
        "due_amount": float(due_amount_val),
        "receipt_date": receipt_dt.strftime("%Y-%m-%d"),
        "payment_mode": int(payment_mode_int),
        "patient_id": int(patient_id_val) if patient_id_val > 0 else None,
        "visit_id": int(visit_id_val) if visit_id_val > 0 else None,
        "receipt_source_key": source_norm,
        "receipt_against_source": _corp_receipt_against_label(source_norm),
    }


def _resolve_sharpsight_payment_mode_table_conn(conn):
    for cand in ("dbo.PaymentMode_Mst", "dbo.Paymentmode_mst", "dbo.PaymentModeMst"):
        try:
            pd.read_sql(f"SELECT TOP 0 * FROM {cand}", conn)
            return cand
        except Exception:
            continue
    return None


def _sharpsight_receipt_source_expr(receipt_source_col: str | None, alias: str = "d") -> str:
    col = str(receipt_source_col or "").strip()
    if col:
        return f"COALESCE(NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(40), {alias}.[{col}]))), ''), N'{SHARPSIGHT_RECEIPT_SOURCE_AHL}')"
    return f"N'{SHARPSIGHT_RECEIPT_SOURCE_AHL}'"


def _clean_receipt_user_label(value) -> str:
    txt = str(value or "").strip()
    if txt in {"0", "0.0", "None", "NULL", "null"}:
        return ""
    return txt


def cancel_corporate_receipt(
    unit: str,
    *,
    receipt_id: int | None = None,
    receipt_no: str | None = None,
    canceled_by_id: int | None = None,
    canceled_by_username: str = "",
    cancellation_reason: str = "",
):
    unit_key = str(unit or "").strip().upper()
    receipt_no_txt = str(receipt_no or "").strip()
    try:
        receipt_id_int = int(str(receipt_id).strip()) if receipt_id not in (None, "", " ") else 0
    except Exception:
        receipt_id_int = 0
    try:
        actor_id = int(str(canceled_by_id).strip()) if canceled_by_id not in (None, "", " ") else 0
    except Exception:
        actor_id = 0
    reason_txt = str(cancellation_reason or "").strip()
    if len(reason_txt) > 1000:
        reason_txt = reason_txt[:1000]

    if not unit_key:
        return {"status": "error", "message": "Unit is required."}
    if receipt_id_int <= 0 and not receipt_no_txt:
        return {"status": "error", "message": "A valid receipt_id or receipt_no is required."}

    conn = get_sql_connection(unit_key)
    if not conn:
        return {"status": "error", "message": f"Unable to connect to unit {unit_key}."}

    def _is_cancelled(value) -> bool:
        txt = str(value or "").strip().lower()
        return txt in {"1", "true", "yes", "y", "cancelled", "canceled"}

    def _row_to_dict(cursor, row) -> dict:
        if row is None or cursor is None:
            return {}
        columns = [str(col[0] or "").strip() for col in (cursor.description or [])]
        return {
            columns[idx]: row[idx]
            for idx in range(len(columns))
            if idx < len(row) and columns[idx]
        }

    try:
        try:
            conn.autocommit = False
        except Exception:
            pass

        mst_table = "dbo.Corp_Receipt_Mst"
        dtl_table = "dbo.Corp_Receipt_Dtl"
        mst_receipt_id_col = _pick_table_col_conn(conn, mst_table, ["Receipt_ID", "ReceiptId", "ReceiptID"])
        mst_receipt_no_col = _pick_table_col_conn(conn, mst_table, ["CReceipt_No", "Receipt_No", "ReceiptNo", "CReceiptNo"])
        mst_cancel_status_col = _pick_table_col_conn(conn, mst_table, ["Cancelstatus", "CancelStatus", "Cancel_Status", "Canceled", "Cancelled"])
        mst_canceled_by_col = _pick_table_col_conn(conn, mst_table, ["CanceledBy", "CancelledBy"])
        mst_canceled_on_col = _pick_table_col_conn(conn, mst_table, ["CanceledOn", "CancelledOn", "CancelDate", "CanceledDate", "Cancel_Date"])
        mst_cancel_reason_id_col = _pick_table_col_conn(conn, mst_table, ["CancelReasonid", "CancelReasonID", "CancelReasonId"])
        mst_cancel_reason_text_col = _pick_table_col_conn(conn, mst_table, ["CancellationReason", "CancelReasonText", "CancelRemarks", "CancelRemark", "CancellationRemarks"])
        mst_updated_by_col = _pick_table_col_conn(conn, mst_table, ["Updated_By", "UpdatedBy", "updated_by"])
        mst_updated_on_col = _pick_table_col_conn(conn, mst_table, ["Updated_On", "UpdatedOn", "ModifiedOn"])
        dtl_receipt_id_col = _pick_table_col_conn(conn, dtl_table, ["receiptId", "ReceiptId", "Receipt_ID", "ReceiptID"])
        dtl_bill_id_col = _pick_table_col_conn(conn, dtl_table, ["billId", "BillId", "Bill_ID", "CBill_ID"])
        dtl_cancel_status_col = _pick_table_col_conn(conn, dtl_table, ["Cancelstatus", "CancelStatus", "Cancel_Status", "Canceled", "Cancelled"])
        dtl_canceled_by_col = _pick_table_col_conn(conn, dtl_table, ["CanceledBy", "CancelledBy"])
        dtl_canceled_on_col = _pick_table_col_conn(conn, dtl_table, ["CanceledOn", "CancelledOn", "CancelDate", "CanceledDate", "Cancel_Date"])
        dtl_cancel_reason_id_col = _pick_table_col_conn(conn, dtl_table, ["CancelReasonid", "CancelReasonID", "CancelReasonId"])
        dtl_cancel_reason_text_col = _pick_table_col_conn(conn, dtl_table, ["CancellationReason", "CancelReasonText", "CancelRemarks", "CancelRemark", "CancellationRemarks"])
        dtl_updated_by_col = _pick_table_col_conn(conn, dtl_table, ["Updated_By", "UpdatedBy", "updated_by"])
        dtl_updated_on_col = _pick_table_col_conn(conn, dtl_table, ["Updated_On", "UpdatedOn", "ModifiedOn"])

        if not mst_receipt_id_col or not mst_cancel_status_col:
            try:
                conn.rollback()
            except Exception:
                pass
            return {"status": "error", "message": "Corporate receipt schema is missing cancellation columns."}

        cursor = conn.cursor()
        receipt_no_expr = (
            f"ISNULL(CONVERT(NVARCHAR(80), m.[{mst_receipt_no_col}]), '')"
            if mst_receipt_no_col
            else f"CONVERT(NVARCHAR(80), m.[{mst_receipt_id_col}])"
        )
        cancel_on_expr = (
            f"CAST(m.[{mst_canceled_on_col}] AS DATETIME)"
            if mst_canceled_on_col
            else "CAST(NULL AS DATETIME)"
        )
        where_sql = f"m.[{mst_receipt_id_col}] = ?"
        where_params = [receipt_id_int]
        if receipt_id_int <= 0:
            if not mst_receipt_no_col:
                try:
                    conn.rollback()
                except Exception:
                    pass
                return {"status": "error", "message": "Corporate receipt number column was not found."}
            where_sql = f"m.[{mst_receipt_no_col}] = ?"
            where_params = [receipt_no_txt]

        cursor.execute(
            f"""
            SELECT TOP 1
                CAST(m.[{mst_receipt_id_col}] AS INT) AS ReceiptId,
                {receipt_no_expr} AS ReceiptNo,
                CONVERT(NVARCHAR(20), ISNULL(m.[{mst_cancel_status_col}], 0)) AS CancelStatusRaw,
                {cancel_on_expr} AS CanceledOn
            FROM {mst_table} m WITH (ROWLOCK, UPDLOCK, HOLDLOCK)
            WHERE {where_sql}
            """,
            tuple(where_params),
        )
        receipt_row = _row_to_dict(cursor, cursor.fetchone())
        if not receipt_row:
            try:
                conn.rollback()
            except Exception:
                pass
            return {"status": "error", "message": "Corporate receipt not found."}
        if _is_cancelled(receipt_row.get("CancelStatusRaw")):
            try:
                conn.rollback()
            except Exception:
                pass
            return {"status": "error", "message": "Corporate receipt is already cancelled."}

        receipt_id_int = int(receipt_row.get("ReceiptId") or 0)
        receipt_no_txt = str(receipt_row.get("ReceiptNo") or receipt_no_txt or "").strip()

        linked_bill_ids: list[int] = []
        detail_row_count = 0
        if dtl_receipt_id_col:
            bill_select_expr = (
                f"CAST(d.[{dtl_bill_id_col}] AS INT) AS BillId"
                if dtl_bill_id_col
                else "CAST(NULL AS INT) AS BillId"
            )
            cursor.execute(
                f"""
                SELECT {bill_select_expr}
                FROM {dtl_table} d WITH (ROWLOCK, UPDLOCK, HOLDLOCK)
                WHERE d.[{dtl_receipt_id_col}] = ?
                """,
                (receipt_id_int,),
            )
            detail_rows = cursor.fetchall() or []
            detail_row_count = len(detail_rows)
            if dtl_bill_id_col:
                seen_bill_ids = set()
                for row in detail_rows:
                    try:
                        bill_id_val = int(row[0]) if row and row[0] is not None else 0
                    except Exception:
                        bill_id_val = 0
                    if bill_id_val > 0 and bill_id_val not in seen_bill_ids:
                        seen_bill_ids.add(bill_id_val)
                        linked_bill_ids.append(bill_id_val)

        master_set_clauses: list[str] = []
        master_params: list = []
        master_seen_cols: set[str] = set()

        def _append_master(col_name: str | None, expr: str, value=None):
            key = str(col_name or "").strip().lower()
            if not key or key in master_seen_cols:
                return
            master_seen_cols.add(key)
            master_set_clauses.append(f"[{col_name}] = {expr}")
            if expr == "?":
                master_params.append(value)

        _append_master(mst_cancel_status_col, "?", 1)
        _append_master(mst_cancel_reason_id_col, "?", 1)
        _append_master(mst_canceled_by_col, "?", actor_id)
        _append_master(mst_canceled_on_col, "GETDATE()")
        if reason_txt:
            _append_master(mst_cancel_reason_text_col, "?", reason_txt)
        _append_master(mst_updated_by_col, "?", actor_id)
        _append_master(mst_updated_on_col, "GETDATE()")

        cursor.execute(
            f"UPDATE {mst_table} SET {', '.join(master_set_clauses)} WHERE [{mst_receipt_id_col}] = ?",
            tuple(master_params + [receipt_id_int]),
        )

        detail_rows_updated = 0
        if dtl_receipt_id_col and dtl_cancel_status_col:
            detail_set_clauses: list[str] = []
            detail_params: list = []
            detail_seen_cols: set[str] = set()

            def _append_detail(col_name: str | None, expr: str, value=None):
                key = str(col_name or "").strip().lower()
                if not key or key in detail_seen_cols:
                    return
                detail_seen_cols.add(key)
                detail_set_clauses.append(f"[{col_name}] = {expr}")
                if expr == "?":
                    detail_params.append(value)

            _append_detail(dtl_cancel_status_col, "?", 1)
            _append_detail(dtl_cancel_reason_id_col, "?", 1)
            _append_detail(dtl_canceled_by_col, "?", actor_id)
            _append_detail(dtl_canceled_on_col, "GETDATE()")
            if reason_txt:
                _append_detail(dtl_cancel_reason_text_col, "?", reason_txt)
            _append_detail(dtl_updated_by_col, "?", actor_id)
            _append_detail(dtl_updated_on_col, "GETDATE()")
            cursor.execute(
                f"UPDATE {dtl_table} SET {', '.join(detail_set_clauses)} WHERE [{dtl_receipt_id_col}] = ?",
                tuple(detail_params + [receipt_id_int]),
            )
            detail_rows_updated = int(cursor.rowcount or 0)

        conn.commit()
        return {
            "status": "success",
            "receipt_id": receipt_id_int,
            "receipt_no": receipt_no_txt,
            "cancelled_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "linked_bill_ids": linked_bill_ids,
            "detail_row_count": detail_row_count,
            "detail_rows_updated": detail_rows_updated,
            "reason_column": mst_cancel_reason_text_col,
            "cancelled_by_id": actor_id,
            "cancelled_by_username": str(canceled_by_username or "").strip(),
        }
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_corporate_receipts_day_print(unit: str, entry_date_from, entry_date_to=None, filter_by: str = "entry_date"):
    unit_key = str(unit or "").strip().upper()

    conn = get_sql_connection(unit_key)
    if not conn:
        return None
    try:
        entry_from_dt = pd.to_datetime(entry_date_from, errors="coerce")
        entry_to_dt = pd.to_datetime(entry_date_to if entry_date_to is not None else entry_date_from, errors="coerce")
        filter_mode = "receipt_date" if str(filter_by or "").strip().lower() in {"receipt", "receipt_date", "receiptdate"} else "entry_date"
        if pd.isna(entry_from_dt) or pd.isna(entry_to_dt):
            return None
        if entry_to_dt < entry_from_dt:
            return None

        bill_table = _resolve_corporate_bill_table_conn(conn, unit_key)
        if not bill_table:
            return None

        receipt_source_info = _ensure_corporate_receipt_source_column_conn(conn) or {}
        receipt_source_col = str(receipt_source_info.get("column") or "").strip() or None
        if receipt_source_col:
            _backfill_corporate_receipt_source_conn(conn, unit_key, receipt_source_col)

        pm_table = _resolve_sharpsight_payment_mode_table_conn(conn)
        pm_join = ""
        pm_name_expr = "CONVERT(NVARCHAR(100), m.CPayment_Mode)"
        if pm_table:
            pm_join = f"LEFT JOIN {pm_table} pm WITH (NOLOCK) ON pm.PModeId = m.CPayment_Mode"
            pm_name_expr = "LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), pm.PModeName), CONVERT(NVARCHAR(100), m.CPayment_Mode))))"

        dtl_receipt_date_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", ["ReceiptDate"])
        dtl_inserted_on_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", ["insertedOn", "InsertedOn", "Inserted_On"])
        dtl_inserted_by_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", ["insertedBy", "InsertedBy", "Inserted_By"])
        mst_cancel_status_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Mst", ["Cancelstatus", "CancelStatus", "Cancel_Status", "Canceled", "Cancelled"])
        bill_visit_col = _pick_table_col_conn(conn, bill_table, ["Visit_ID", "VisitID"])
        bill_patient_col = _pick_table_col_conn(conn, bill_table, ["PatientID", "PatientId"])
        bill_patient_type_col = _pick_table_col_conn(conn, bill_table, ["PatientTypeId", "PatientType_ID", "PatientTypeID"])
        bill_patient_subtype_col = _pick_table_col_conn(conn, bill_table, ["PatientTypeIdSrNo", "PatientSubTypeId", "PatientSubType_ID", "PatientSubTypeID"])
        bill_cbill_no_col = _pick_table_col_conn(conn, bill_table, ["CBill_NO", "CBillNo", "BillNo"])
        bill_bill_no_col = _pick_table_col_conn(conn, bill_table, ["Bill_No", "BillNo"])
        bill_date_parts = []
        for cand in ["Submit_Date", "CBill_Date", "accUpdatedDate", "visitDate", "Updated_On"]:
            picked = _pick_table_col_conn(conn, bill_table, [cand])
            if picked:
                bill_date_parts.append(f"b.[{picked}]")
        bill_date_expr = f"COALESCE({', '.join(bill_date_parts)})" if bill_date_parts else "NULL"
        receipt_dt_expr = f"COALESCE(d.[{dtl_receipt_date_col}], m.Receipt_Date)" if dtl_receipt_date_col else "m.Receipt_Date"
        entry_dt_expr = f"COALESCE(d.[{dtl_inserted_on_col}], m.Updated_On, m.Receipt_Date)" if dtl_inserted_on_col else "COALESCE(m.Updated_On, m.Receipt_Date)"
        filter_dt_expr = receipt_dt_expr if filter_mode == "receipt_date" else entry_dt_expr
        inserted_by_id_expr = f"TRY_CAST(d.[{dtl_inserted_by_col}] AS INT)" if dtl_inserted_by_col else "CAST(NULL AS INT)"
        inserted_by_expr = f"ISNULL(CONVERT(NVARCHAR(100), {inserted_by_id_expr}), N'')"
        stored_source_expr = (
            f"NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(40), d.[{receipt_source_col}]))), '')"
            if receipt_source_col
            else "NULL"
        )
        bill_source_key = _corp_receipt_bill_source_key_for_unit(unit_key)
        opening_receipt_match_expr = (
            "CASE "
            "WHEN o.OPId IS NOT NULL AND ISNULL(o.ReceiptId, 0) > 0 AND ISNULL(o.ReceiptId, 0) = ISNULL(d.receiptId, 0) "
            f"THEN N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' "
            "ELSE NULL END"
        )
        receipt_source_expr = (
            "COALESCE("
            f"{opening_receipt_match_expr}, "
            f"{stored_source_expr}, "
            "CASE "
            f"WHEN o.OPId IS NOT NULL AND b.CBill_ID IS NOT NULL AND ({receipt_dt_expr} IS NULL OR {bill_date_expr} IS NULL OR CAST({receipt_dt_expr} AS DATETIME) < CAST({bill_date_expr} AS DATETIME)) THEN N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' "
            f"WHEN b.CBill_ID IS NOT NULL THEN N'{bill_source_key}' "
            f"WHEN o.OPId IS NOT NULL THEN N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' "
            f"ELSE N'{SHARPSIGHT_RECEIPT_SOURCE_UNKNOWN}' END"
            ")"
        )
        receipt_against_expr = (
            "CASE "
            f"WHEN {receipt_source_expr} = N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' THEN N'Opening Balance' "
            f"WHEN {receipt_source_expr} = N'{bill_source_key}' THEN N'Corporate Bill' "
            "ELSE N'Unmapped' END"
        )
        bill_visit_expr = f"b.[{bill_visit_col}]" if bill_visit_col else "NULL"
        bill_patient_expr = f"b.[{bill_patient_col}]" if bill_patient_col else "NULL"
        bill_patient_type_expr = f"b.[{bill_patient_type_col}]" if bill_patient_type_col else "NULL"
        bill_patient_subtype_expr = f"b.[{bill_patient_subtype_col}]" if bill_patient_subtype_col else "NULL"
        bill_no_expr = (
            "ISNULL("
            + (f"NULLIF(CONVERT(NVARCHAR(80), b.[{bill_cbill_no_col}]), '')" if bill_cbill_no_col else "NULL")
            + ", "
            + (
                f"ISNULL(NULLIF(CONVERT(NVARCHAR(80), b.[{bill_bill_no_col}]), ''), CONVERT(NVARCHAR(80), b.CBill_ID))"
                if bill_bill_no_col
                else "CONVERT(NVARCHAR(80), b.CBill_ID)"
            )
            + ")"
        )

        sql = f"""
            SELECT
                CAST(m.Receipt_ID AS INT) AS ReceiptId,
                ISNULL(CONVERT(NVARCHAR(80), m.CReceipt_No), '') AS ReceiptNo,
                CAST(m.Receipt_Date AS DATETIME) AS ReceiptDate,
                CAST({entry_dt_expr} AS DATETIME) AS EntryDateTime,
                CAST(ISNULL(m.GrossAmt, ISNULL(m.Amount, 0)) AS FLOAT) AS GrossAmt,
                CAST(ISNULL(m.TDSAmt, 0) AS FLOAT) AS TDSAmt,
                CAST(ISNULL(m.NetAmt, ISNULL(m.Amount, 0)) AS FLOAT) AS NetAmt,
                CAST(ISNULL(m.rebateDiscountAmt, 0) AS FLOAT) AS RebateAmt,
                CAST(ISNULL(d.billAmt, 0) AS FLOAT) AS BillAmt,
                CAST(ISNULL(d.receiptAmt, 0) AS FLOAT) AS ReceiptAmtDtl,
                CAST(
                    CASE
                        WHEN ABS(ROUND(ISNULL(d.billAmt, 0) - (ISNULL(d.receiptAmt, 0) + ISNULL(m.TDSAmt, 0) + ISNULL(m.rebateDiscountAmt, 0)), 2)) <= 0.01 THEN 0
                        ELSE ROUND(ISNULL(d.billAmt, 0) - (ISNULL(d.receiptAmt, 0) + ISNULL(m.TDSAmt, 0) + ISNULL(m.rebateDiscountAmt, 0)), 2)
                    END
                    AS FLOAT
                ) AS DueAmtDtl,
                CAST(d.billId AS INT) AS BillId,
                CAST({receipt_source_expr} AS NVARCHAR(40)) AS ReceiptSourceKey,
                {receipt_against_expr} AS ReceiptAgainstSource,
                CASE
                    WHEN {receipt_source_expr} = N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}'
                        THEN ISNULL(NULLIF(CONVERT(NVARCHAR(80), o.RefNo), ''), CONVERT(NVARCHAR(80), o.OPId))
                    ELSE {bill_no_expr}
                END AS BillNo,
                CAST(NULLIF(d.visitId, 0) AS INT) AS VisitId,
                CAST(NULLIF(d.PatientId, 0) AS INT) AS PatientId,
                CASE
                    WHEN {receipt_source_expr} = N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' AND ISNULL(CONVERT(NVARCHAR(255), o.PatientName), '') <> ''
                        THEN ISNULL(CONVERT(NVARCHAR(255), o.PatientName), '')
                    WHEN COALESCE(v.PatientID, {bill_patient_expr}, d.PatientId, m.PatientID, o.PatientId) IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_patientfullname(COALESCE(v.PatientID, {bill_patient_expr}, d.PatientId, m.PatientID, o.PatientId)), '')
                END AS PatientName,
                CASE
                    WHEN COALESCE(v.PatientID, {bill_patient_expr}, d.PatientId, m.PatientID, o.PatientId) IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_regno(COALESCE(v.PatientID, {bill_patient_expr}, d.PatientId, m.PatientID, o.PatientId)), '')
                END AS RegistrationNo,
                CASE
                    WHEN {receipt_source_expr} = N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' AND o.PatientTypeId IS NOT NULL
                        THEN ISNULL(dbo.fn_pat_type(o.PatientTypeId), '')
                    WHEN COALESCE(v.PatientType_ID, {bill_patient_type_expr}) IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_pat_type(COALESCE(v.PatientType_ID, {bill_patient_type_expr})), '')
                END AS PatientType,
                CASE
                    WHEN {receipt_source_expr} = N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' AND o.PatientSubTypeId IS NOT NULL
                        THEN ISNULL(dbo.fn_patsub_type(o.PatientSubTypeId), '')
                    WHEN COALESCE(v.PatientSubType_ID, {bill_patient_subtype_expr}) IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_patsub_type(COALESCE(v.PatientSubType_ID, {bill_patient_subtype_expr})), '')
                END AS PatientSubType,
                CASE
                    WHEN {receipt_source_expr} = N'{SHARPSIGHT_RECEIPT_SOURCE_OPENING}' THEN N'Opening Balance'
                    ELSE ISNULL(v.TypeOfVisit, '')
                END AS TypeOfVisit,
                {pm_name_expr} AS PaymentMode,
                ISNULL(CONVERT(NVARCHAR(200), m.UTRNo), '') AS UTRNo,
                ISNULL(CONVERT(NVARCHAR(200), u_upd.UserName), CONVERT(NVARCHAR(100), m.Updated_By)) AS UpdatedBy,
                ISNULL(CONVERT(NVARCHAR(200), u_ins.UserName), {inserted_by_expr}) AS InsertedBy,
                CAST(m.Updated_On AS DATETIME) AS UpdatedOn
            FROM dbo.Corp_Receipt_Mst m WITH (NOLOCK)
            INNER JOIN dbo.Corp_Receipt_Dtl d WITH (NOLOCK)
                ON d.receiptId = m.Receipt_ID
            LEFT JOIN {bill_table} b WITH (NOLOCK)
                ON b.CBill_ID = d.billId
            LEFT JOIN dbo.CorpOpening o WITH (NOLOCK)
                ON o.OPId = d.billId
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = COALESCE(NULLIF(d.visitId, 0), NULLIF(m.VisitID, 0), NULLIF({bill_visit_expr}, 0))
            LEFT JOIN dbo.User_Mst u_upd WITH (NOLOCK)
                ON u_upd.UserID = m.Updated_By
            LEFT JOIN dbo.User_Mst u_ins WITH (NOLOCK)
                ON u_ins.UserID = {inserted_by_id_expr}
            {pm_join}
            WHERE CAST({filter_dt_expr} AS DATE) BETWEEN ? AND ?
              {"AND ISNULL(m.[" + mst_cancel_status_col + "], 0) <> 1" if mst_cancel_status_col else ""}
            ORDER BY {filter_dt_expr}, m.Receipt_ID, d.recDtlId
        """
        df = pd.read_sql(
            sql,
            conn,
            params=[entry_from_dt.strftime("%Y-%m-%d"), entry_to_dt.strftime("%Y-%m-%d")],
        )
        if df is None:
            return None

        def _fmt_dt(value, with_time: bool = False, long_date: bool = False):
            dt = pd.to_datetime(value, errors="coerce")
            if pd.isna(dt):
                return ""
            if with_time:
                return dt.strftime("%d-%m-%Y %H:%M:%S")
            if long_date:
                return dt.strftime("%d %b %Y")
            return dt.strftime("%d-%m-%Y")

        def _fmt_iso_date(value):
            dt = pd.to_datetime(value, errors="coerce")
            if pd.isna(dt):
                return ""
            return dt.strftime("%Y-%m-%d")

        def _safe_int(value, default: int | None = None):
            try:
                if pd.isna(value):
                    return default
            except Exception:
                pass
            if value in (None, ""):
                return default
            try:
                return int(value)
            except Exception:
                try:
                    return int(float(value))
                except Exception:
                    return default

        def _safe_float(value, default: float = 0.0) -> float:
            try:
                if pd.isna(value):
                    return float(default)
            except Exception:
                pass
            if value in (None, ""):
                return float(default)
            try:
                return float(value)
            except Exception:
                return float(default)

        rows = []
        totals = {
            "count": 0,
            "gross_amount": 0.0,
            "tds_amount": 0.0,
            "net_amount": 0.0,
            "rebate_amount": 0.0,
            "receipt_amount": 0.0,
            "bill_amount": 0.0,
            "due_amount": 0.0,
        }
        if not df.empty:
            for _, raw_row in df.iterrows():
                row = raw_row.to_dict()
                filter_date_raw = row.get("ReceiptDate") if filter_mode == "receipt_date" else row.get("EntryDateTime")
                item = {
                    "receipt_id": _safe_int(row.get("ReceiptId"), 0) or 0,
                    "receipt_no": str(row.get("ReceiptNo") or "").strip(),
                    "receipt_date": _fmt_dt(row.get("ReceiptDate")),
                    "receipt_date_iso": _fmt_iso_date(row.get("ReceiptDate")),
                    "entry_datetime": _fmt_dt(row.get("EntryDateTime"), with_time=True),
                    "entry_date_iso": _fmt_iso_date(row.get("EntryDateTime")),
                    "filter_date_iso": _fmt_iso_date(filter_date_raw),
                    "gross_amount": _safe_float(row.get("GrossAmt"), 0.0),
                    "tds_amount": _safe_float(row.get("TDSAmt"), 0.0),
                    "net_amount": _safe_float(row.get("NetAmt"), 0.0),
                    "rebate_amount": _safe_float(row.get("RebateAmt"), 0.0),
                    "bill_amount": _safe_float(row.get("BillAmt"), 0.0),
                    "receipt_amount": _safe_float(row.get("ReceiptAmtDtl"), 0.0),
                    "due_amount": _safe_float(row.get("DueAmtDtl"), 0.0),
                    "receipt_source_key": str(row.get("ReceiptSourceKey") or "").strip(),
                    "receipt_against_source": str(row.get("ReceiptAgainstSource") or "").strip(),
                    "bill_id": _safe_int(row.get("BillId"), 0) or 0,
                    "bill_no": str(row.get("BillNo") or "").strip(),
                    "visit_id": _safe_int(row.get("VisitId"), None),
                    "patient_id": _safe_int(row.get("PatientId"), None),
                    "patient_name": str(row.get("PatientName") or "").strip(),
                    "registration_no": str(row.get("RegistrationNo") or "").strip(),
                    "patient_type": str(row.get("PatientType") or "").strip(),
                    "patient_subtype": str(row.get("PatientSubType") or "").strip(),
                    "type_of_visit": str(row.get("TypeOfVisit") or "").strip(),
                    "payment_mode": str(row.get("PaymentMode") or "").strip(),
                    "utr_no": _clean_utr_text(row.get("UTRNo")),
                    "updated_by": _clean_receipt_user_label(row.get("UpdatedBy")),
                    "inserted_by": _clean_receipt_user_label(row.get("InsertedBy")),
                    "updated_on": _fmt_dt(row.get("UpdatedOn"), with_time=True),
                }
                rows.append(item)
                totals["count"] += 1
                totals["gross_amount"] += item["gross_amount"]
                totals["tds_amount"] += item["tds_amount"]
                totals["net_amount"] += item["net_amount"]
                totals["rebate_amount"] += item["rebate_amount"]
                totals["receipt_amount"] += item["receipt_amount"]
                totals["bill_amount"] += item["bill_amount"]
                totals["due_amount"] += item["due_amount"]

        for key in ("gross_amount", "tds_amount", "net_amount", "rebate_amount", "receipt_amount", "bill_amount", "due_amount"):
            totals[key] = float(round(totals[key], 2))

        is_single_day = entry_from_dt.date() == entry_to_dt.date()
        entry_from_label = _fmt_dt(entry_from_dt, long_date=True)
        entry_to_label = _fmt_dt(entry_to_dt, long_date=True)
        entry_period_label = entry_from_label if is_single_day else f"{entry_from_label} to {entry_to_label}"
        date_filter_base_label = "Receipt Date" if filter_mode == "receipt_date" else "Entry Date"
        date_filter_label = date_filter_base_label if is_single_day else f"{date_filter_base_label} Range"

        return {
            "unit": unit_key,
            "entry_date": entry_from_dt.strftime("%Y-%m-%d"),
            "entry_from": entry_from_dt.strftime("%Y-%m-%d"),
            "entry_to": entry_to_dt.strftime("%Y-%m-%d"),
            "entry_date_label": entry_period_label,
            "entry_from_label": entry_from_label,
            "entry_to_label": entry_to_label,
            "entry_period_label": entry_period_label,
            "entry_meta_label": date_filter_label,
            "date_filter_mode": filter_mode,
            "date_filter_base_label": date_filter_base_label,
            "date_filter_label": date_filter_label,
            "is_single_day": is_single_day,
            "rows": rows,
            "summary": totals,
        }
    except Exception as e:
        print(f"Error fetching corporate receipt register payload ({unit_key}, {entry_date_from}, {entry_date_to}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def unsubmit_corporate_reconciliation_bill(
    unit: str,
    *,
    bill_id: int,
    source_key: str | None = None,
    updated_by_id: int | None = None,
):
    unit_key = str(unit or "").strip().upper()
    expected_source_key = _corp_receipt_bill_source_key_for_unit(unit_key)
    source_norm = str(source_key or expected_source_key).strip().upper() or expected_source_key
    if source_norm != expected_source_key:
        return {
            "status": "error",
            "message": f"Unsubmit is supported only for {expected_source_key} rows in {unit_key}.",
        }

    try:
        bill_id_int = int(str(bill_id).strip())
    except Exception:
        bill_id_int = 0
    if bill_id_int <= 0:
        return {"status": "error", "message": "Invalid bill id supplied."}

    actor_id = None
    if updated_by_id not in (None, "", " "):
        try:
            actor_id = int(str(updated_by_id).strip())
        except Exception:
            actor_id = None
        if actor_id is not None and actor_id <= 0:
            actor_id = None

    conn = get_sql_connection(unit_key)
    if not conn:
        return {"status": "error", "message": f"Unable to connect to unit {unit_key}."}

    def _fmt_iso(value):
        dt = pd.to_datetime(value, errors="coerce")
        if pd.isna(dt):
            return ""
        return dt.strftime("%Y-%m-%d")

    def _row_to_dict(cursor, row):
        out = {}
        if row is None:
            return out
        columns = [str(col[0] or "").strip() for col in (cursor.description or [])]
        for idx, col_name in enumerate(columns):
            if not col_name:
                continue
            out[col_name] = row[idx]
        return out

    try:
        conn.autocommit = False
        bill_table = _resolve_corporate_bill_table_conn(conn, unit_key)
        if not bill_table:
            conn.rollback()
            return {"status": "error", "message": f"Corporate bill table not found for unit {unit_key}."}

        bill_id_col = _pick_table_col_conn(conn, bill_table, ["CBill_ID", "CBillId", "Bill_ID", "BillId"])
        status_col = _pick_table_col_conn(conn, bill_table, ["Status", "status"])
        submit_date_col = _pick_table_col_conn(conn, bill_table, ["Submit_Date", "SubmitDate", "SubmittedOn", "Submitted_Date"])
        bill_no_col = _pick_table_col_conn(conn, bill_table, ["CBill_NO", "CBillNo", "Bill_No", "BillNo"])
        patient_id_col = _pick_table_col_conn(conn, bill_table, ["PatientID", "PatientId", "patientid"])
        visit_id_col = _pick_table_col_conn(conn, bill_table, ["Visit_ID", "VisitID", "visitId", "visitID"])
        updated_by_col = _pick_table_col_conn(
            conn,
            bill_table,
            ["Updated_By", "UpdatedBy", "updated_by", "accUserId"],
        )
        updated_on_col = _pick_table_col_conn(
            conn,
            bill_table,
            ["Updated_On", "UpdatedOn", "ModifiedOn", "accUpdatedDate", "AccUpdatedDate", "LastUpdatedOn"],
        )
        if not bill_id_col or not status_col or not submit_date_col:
            conn.rollback()
            return {
                "status": "error",
                "message": "Corporate bill schema is missing the required status or submit date columns.",
            }

        bill_no_expr = (
            f"CONVERT(NVARCHAR(80), [{bill_no_col}]) AS BillNo"
            if bill_no_col
            else "CAST(NULL AS NVARCHAR(80)) AS BillNo"
        )
        patient_id_expr = (
            f"CAST([{patient_id_col}] AS INT) AS PatientId"
            if patient_id_col
            else "CAST(NULL AS INT) AS PatientId"
        )
        visit_id_expr = (
            f"CAST([{visit_id_col}] AS INT) AS VisitId"
            if visit_id_col
            else "CAST(NULL AS INT) AS VisitId"
        )
        select_sql = f"""
            SELECT TOP 1
                CAST([{bill_id_col}] AS INT) AS BillId,
                {bill_no_expr},
                {patient_id_expr},
                {visit_id_expr},
                CONVERT(NVARCHAR(20), [{status_col}]) AS StatusRaw,
                CAST([{submit_date_col}] AS DATETIME) AS SubmitDateRaw
            FROM {bill_table} WITH (ROWLOCK, UPDLOCK, HOLDLOCK)
            WHERE [{bill_id_col}] = ?
        """

        cursor = conn.cursor()
        cursor.execute(select_sql, (bill_id_int,))
        before_row = cursor.fetchone()
        before_data = _row_to_dict(cursor, before_row)
        if not before_data:
            conn.rollback()
            return {"status": "error", "message": f"Bill {bill_id_int} not found in {bill_table}."}

        before_status = str(before_data.get("StatusRaw") or "").strip().upper()
        before_submit_date = _fmt_iso(before_data.get("SubmitDateRaw"))
        if before_status == "N" and not before_submit_date:
            conn.rollback()
            return {"status": "error", "message": f"Bill {bill_id_int} is already not submitted."}

        set_clauses = [f"[{status_col}] = ?", f"[{submit_date_col}] = NULL"]
        params: list = ["N"]
        if updated_by_col and actor_id is not None:
            set_clauses.append(f"[{updated_by_col}] = ?")
            params.append(actor_id)
        if updated_on_col:
            set_clauses.append(f"[{updated_on_col}] = GETDATE()")
        params.append(bill_id_int)
        cursor.execute(
            f"UPDATE {bill_table} SET {', '.join(set_clauses)} WHERE [{bill_id_col}] = ?",
            tuple(params),
        )
        if int(cursor.rowcount or 0) == 0:
            conn.rollback()
            return {"status": "error", "message": f"Bill {bill_id_int} could not be updated."}

        cursor.execute(select_sql, (bill_id_int,))
        after_row = cursor.fetchone()
        after_data = _row_to_dict(cursor, after_row)
        conn.commit()

        after_status = str(after_data.get("StatusRaw") or "").strip().upper()
        after_submit_date = _fmt_iso(after_data.get("SubmitDateRaw"))
        return {
            "status": "success",
            "unit": unit_key,
            "table_name": bill_table,
            "source_key": expected_source_key,
            "bill_id": int(before_data.get("BillId") or bill_id_int),
            "bill_no": str(before_data.get("BillNo") or "").strip(),
            "patient_id": before_data.get("PatientId"),
            "visit_id": before_data.get("VisitId"),
            "before_status": before_status,
            "after_status": after_status,
            "before_submit_date": before_submit_date,
            "after_submit_date": after_submit_date,
            "updated_by_column": updated_by_col,
            "updated_on_column": updated_on_col,
        }
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def bulk_update_corporate_receipt_dates(unit: str, receipt_ids, new_receipt_date):
    unit_key = str(unit or "").strip().upper()
    unique_receipt_ids = []
    seen_ids = set()
    for raw_val in (receipt_ids or []):
        try:
            parsed = int(str(raw_val).strip())
        except Exception:
            continue
        if parsed <= 0 or parsed in seen_ids:
            continue
        seen_ids.add(parsed)
        unique_receipt_ids.append(parsed)
    if not unique_receipt_ids:
        return {"status": "error", "message": "No valid receipt ids supplied."}

    new_receipt_dt = pd.to_datetime(new_receipt_date, errors="coerce")
    if pd.isna(new_receipt_dt):
        return {"status": "error", "message": "Invalid receipt date supplied."}
    new_receipt_date_py = new_receipt_dt.date()

    conn = get_sql_connection(unit_key)
    if not conn:
        return {"status": "error", "message": f"Unable to connect to unit {unit_key}."}
    try:
        conn.autocommit = False
        mst_receipt_id_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Mst", ["Receipt_ID", "ReceiptId", "ReceiptID"])
        mst_receipt_no_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Mst", ["CReceipt_No", "Receipt_No", "ReceiptNo", "CReceiptNo"])
        mst_receipt_date_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Mst", ["Receipt_Date", "ReceiptDate"])
        dtl_receipt_id_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", ["receiptId", "ReceiptId", "Receipt_ID", "ReceiptID"])
        dtl_receipt_date_col = _pick_table_col_conn(conn, "dbo.Corp_Receipt_Dtl", ["ReceiptDate"])
        if not mst_receipt_id_col or not mst_receipt_date_col:
            conn.rollback()
            return {"status": "error", "message": "Corporate receipt master schema is missing required receipt date columns."}
        if not dtl_receipt_id_col:
            conn.rollback()
            return {"status": "error", "message": "Corporate receipt detail schema is missing the receipt id column."}

        cursor = conn.cursor()
        placeholders = ",".join(["?"] * len(unique_receipt_ids))
        receipt_no_expr = (
            f"ISNULL(CONVERT(NVARCHAR(80), m.[{mst_receipt_no_col}]), '')"
            if mst_receipt_no_col
            else "CONVERT(NVARCHAR(80), m.[{mst_receipt_id_col}])"
        )
        old_receipt_expr = (
            f"COALESCE(MIN(CAST(d.[{dtl_receipt_date_col}] AS DATE)), CAST(m.[{mst_receipt_date_col}] AS DATE))"
            if dtl_receipt_date_col
            else f"CAST(m.[{mst_receipt_date_col}] AS DATE)"
        )
        cursor.execute(
            f"""
            SELECT
                m.[{mst_receipt_id_col}] AS ReceiptId,
                {receipt_no_expr} AS ReceiptNo,
                {old_receipt_expr} AS OldReceiptDate
            FROM dbo.Corp_Receipt_Mst m WITH (ROWLOCK, UPDLOCK, HOLDLOCK)
            LEFT JOIN dbo.Corp_Receipt_Dtl d WITH (ROWLOCK, UPDLOCK, HOLDLOCK)
                ON d.[{dtl_receipt_id_col}] = m.[{mst_receipt_id_col}]
            WHERE m.[{mst_receipt_id_col}] IN ({placeholders})
            GROUP BY m.[{mst_receipt_id_col}], {receipt_no_expr}, CAST(m.[{mst_receipt_date_col}] AS DATE)
            """,
            tuple(unique_receipt_ids),
        )
        rows = cursor.fetchall() or []
        found_ids = {int(getattr(row, "ReceiptId", 0) or 0) for row in rows}
        missing_ids = [rid for rid in unique_receipt_ids if rid not in found_ids]
        if missing_ids:
            conn.rollback()
            return {"status": "error", "message": f"Some receipts were not found: {', '.join(str(x) for x in missing_ids[:10])}"}

        cursor.execute(
            f"UPDATE dbo.Corp_Receipt_Mst SET [{mst_receipt_date_col}] = ? WHERE [{mst_receipt_id_col}] IN ({placeholders})",
            tuple([new_receipt_date_py] + unique_receipt_ids),
        )
        if dtl_receipt_date_col:
            cursor.execute(
                f"UPDATE dbo.Corp_Receipt_Dtl SET [{dtl_receipt_date_col}] = ? WHERE [{dtl_receipt_id_col}] IN ({placeholders})",
                tuple([new_receipt_date_py] + unique_receipt_ids),
            )

        conn.commit()

        def _fmt_iso(value):
            dt = pd.to_datetime(value, errors="coerce")
            if pd.isna(dt):
                return ""
            return dt.strftime("%Y-%m-%d")

        updated_receipts = []
        for row in rows:
            receipt_id_val = int(getattr(row, "ReceiptId", 0) or 0)
            updated_receipts.append(
                {
                    "receipt_id": receipt_id_val,
                    "receipt_no": str(getattr(row, "ReceiptNo", "") or "").strip(),
                    "old_receipt_date": _fmt_iso(getattr(row, "OldReceiptDate", None)),
                    "new_receipt_date": new_receipt_dt.strftime("%Y-%m-%d"),
                }
            )
        return {"status": "success", "updated_receipts": updated_receipts}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"status": "error", "message": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Refund Tracker (Billing MIS) =====================
def fetch_refund_tracker_raw(unit: str, from_date: str, to_date: str):
    """
    Fetch refund tracker rows from refund master + linked receipt details.
    Date filter is driven by refundmst.refundInitializeDate.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for refund tracker")
        return None
    try:
        sql = """
            SET NOCOUNT ON;
            SELECT
                rm.id AS RefundId,
                rm.visitId AS VisitId,
                rm.patientid AS MasterPatientId,
                rm.refundDeductionAmt AS RefundDeductionAmt,
                rm.refundremark AS RefundRemark,
                rm.refundStatus AS RefundStatus,
                rm.refundInitializeDate AS RefundInitializeDate,
                rm.refundInitializeBy AS RefundInitializeBy,
                rm.accountDeductionAmt AS AccountDeductionAmt,
                rm.accountInitializeDate AS AccountInitializeDate,
                rm.accountInitializeBy AS AccountInitializeBy,
                rm.accountRemark AS AccountRemark,
                rm.patientAccountNo AS PatientAccountNo,
                rm.patientBankName AS PatientBankName,
                rm.patientbankIFSC AS PatientBankIFSC,
                rm.patientaccHolderName AS PatientAccHolderName,
                rm.patientRelationName AS PatientRelationName,
                rm.adminStatus AS AdminStatus,
                rm.adminlockDate AS AdminLockDate,
                rm.corpStatus AS CorpStatus,
                rm.corplockDate AS CorpLockDate,
                rm.accountStatus AS AccountStatus,
                rm.accountlockDate AS AccountLockDate,
                rm.corpDeductionAmt AS CorpDeductionAmt,
                rm.corpRefundAmt AS CorpRefundAmt,
                rm.totalReceiveAmt AS TotalReceiveAmt,
                rm.refundAmt AS RefundAmt,
                rm.corpRemarks AS CorpRemarks,
                rm.utrno AS UTRNo,
                v.VisitNo,
                v.VisitDate,
                v.DischargeDate,
                COALESCE(v.PatientID, rm.patientid) AS PatientID,
                CASE
                    WHEN COALESCE(v.PatientID, rm.patientid) IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_regno(COALESCE(v.PatientID, rm.patientid)), '')
                END AS RegNo,
                CASE
                    WHEN COALESCE(v.PatientID, rm.patientid) IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_patientfullname(COALESCE(v.PatientID, rm.patientid)), '')
                END AS PatientName,
                CASE
                    WHEN v.PatientType_ID IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_pat_type(v.PatientType_ID), '')
                END AS PatientType,
                CASE
                    WHEN v.PatientSubType_ID IS NULL THEN ''
                    ELSE ISNULL(dbo.fn_patsub_type(v.PatientSubType_ID), '')
                END AS CorpType,
                rrd.recId AS RecId,
                rrd.refundId AS DetailRefundId,
                rrd.refRecAmount AS RefRecAmount,
                rrd.recDate AS RecDate,
                rrd.oldrecid AS OldReceiptId,
                COALESCE(rc.Receipt_Date, rrd.oldrecDate) AS OldRecDate,
                ISNULL(um.UserName, '') AS LinkedUserName,
                rrd.recDate AS InsertedDate,
                rc.Receipt_ID AS ReceiptId,
                rc.Receipt_No AS ReceiptNo,
                rc.Amount AS ReceiptAmount,
                CASE
                    WHEN pm.PModeName IS NULL OR LTRIM(RTRIM(CONVERT(NVARCHAR(100), pm.PModeName))) = ''
                        THEN ISNULL(CONVERT(NVARCHAR(100), rc.PaymentMode), '')
                    ELSE CONVERT(NVARCHAR(100), pm.PModeName)
                END AS PaymentMode,
                rc.ReceiptType AS ReceiptType,
                rc.CancelStatus AS CancelStatus
            FROM dbo.refundmst rm WITH (NOLOCK)
            LEFT JOIN dbo.visit v WITH (NOLOCK)
                ON v.Visit_ID = rm.visitId
            LEFT JOIN dbo.refundreceivedtl rrd WITH (NOLOCK)
                ON rrd.refundId = rm.id
            LEFT JOIN dbo.receipt_mst rc WITH (NOLOCK)
                ON rc.Receipt_ID = rrd.oldrecid
            LEFT JOIN dbo.paymentmode_mst pm WITH (NOLOCK)
                ON pm.PModeId = rc.PaymentMode
               AND ISNULL(pm.Deactive, 0) = 0
            LEFT JOIN dbo.user_mst um WITH (NOLOCK)
                ON um.UserID = rrd.userid
            WHERE rm.refundInitializeDate >= ?
              AND rm.refundInitializeDate < DATEADD(DAY, 1, CAST(? AS DATETIME))
            ORDER BY
                rm.refundInitializeDate DESC,
                rm.id DESC,
                rrd.recId DESC
        """
        df = pd.read_sql(sql, conn, params=[from_date, to_date])
        if df is None or df.empty:
            return df
        df.columns = [c.strip() for c in df.columns]
        df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"Error fetching refund tracker ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


