def _as_ist_string(ts):
    if pd.isna(ts):
        return None
    try:
        # If naive, localize to IST; if tz-aware, convert to IST
        t = pd.Timestamp(ts)
        if t.tzinfo is None:
            t = t.tz_localize(LOCAL_TZ)
        else:
            t = t.tz_convert(LOCAL_TZ)
        return t.strftime("%Y-%m-%d %H:%M")
    except Exception:
        try:
            return pd.to_datetime(ts, errors="coerce").strftime("%Y-%m-%d %H:%M")
        except Exception:
            return None


def _volume_to_int_or_none(value) -> int | None:
    try:
        if value is None or pd.isna(value):
            return None
        return int(float(value))
    except Exception:
        return None


def _volume_is_admission_visit(value) -> bool:
    visit = _norm_text(value)
    return visit in {"IPD", "DAYCARE", "DAY CARE", "IN PATIENT VISITS", "INPATIENT VISITS"}


def _volume_admission_type_display(code_value, visit_value) -> str:
    if not _volume_is_admission_visit(visit_value):
        return ""
    code_int = _volume_to_int_or_none(code_value)
    return VOLUME_ADMISSION_TYPE_LABELS.get(code_int, VOLUME_ADMISSION_TYPE_FALLBACK)


def _volume_ipd_daycare_flag_from_values(
    visit_type_id,
    visit_value=None,
    visit_date=None,
    discharge_date=None,
    existing_flag=None,
) -> str:
    visit_type_num = _volume_to_int_or_none(visit_type_id) or 0
    if visit_type_num != 1:
        return ""

    visit_label = _norm_text(visit_value)
    flag_label = _norm_text(existing_flag)
    visit_dt = pd.to_datetime(visit_date, errors="coerce")
    discharge_dt = pd.to_datetime(discharge_date, errors="coerce")
    if pd.notna(visit_dt) and pd.notna(discharge_dt):
        try:
            stay_minutes = (discharge_dt - visit_dt).total_seconds() / 60.0
        except Exception:
            stay_minutes = None
        if stay_minutes is not None and math.isfinite(stay_minutes) and stay_minutes >= 0:
            return "Daycare" if stay_minutes <= (VOLUME_DAYCARE_MAX_HOURS * 60) else "IPD"

    if "DAY" in visit_label or flag_label == "DAYCARE":
        return "Daycare"
    return "IPD"


def apply_volume_ipd_daycare_segmentation(details_df: pd.DataFrame) -> pd.DataFrame:
    if details_df is None or details_df.empty or "TypeOfVisit" not in details_df.columns:
        return details_df

    work = details_df.copy()
    visit_type_id_series = (
        pd.to_numeric(work["VisitTypeID"], errors="coerce")
        if "VisitTypeID" in work.columns
        else pd.Series([None] * len(work), index=work.index, dtype="float64")
    )
    visit_series = work["TypeOfVisit"].fillna("").astype(str) if "TypeOfVisit" in work.columns else pd.Series([""] * len(work), index=work.index, dtype="object")
    visit_date_series = (
        pd.to_datetime(work["VisitDate"], errors="coerce")
        if "VisitDate" in work.columns
        else pd.Series([pd.NaT] * len(work), index=work.index, dtype="datetime64[ns]")
    )
    discharge_date_series = (
        pd.to_datetime(work["DischargeDate"], errors="coerce")
        if "DischargeDate" in work.columns
        else pd.Series([pd.NaT] * len(work), index=work.index, dtype="datetime64[ns]")
    )
    existing_flag_series = (
        work["IPD_Daycare_Flag"].fillna("").astype(str)
        if "IPD_Daycare_Flag" in work.columns
        else pd.Series([""] * len(work), index=work.index, dtype="object")
    )

    normalized_visits = []
    for visit_type_id, visit_value, visit_date, discharge_date, existing_flag in zip(
        visit_type_id_series,
        visit_series,
        visit_date_series,
        discharge_date_series,
        existing_flag_series,
    ):
        if (_volume_to_int_or_none(visit_type_id) or 0) == 1:
            normalized_visits.append(
                _volume_ipd_daycare_flag_from_values(
                    visit_type_id,
                    visit_value=visit_value,
                    visit_date=visit_date,
                    discharge_date=discharge_date,
                    existing_flag=existing_flag,
                )
            )
        else:
            normalized_visits.append(str(visit_value or "").strip())
    work["TypeOfVisit"] = normalized_visits
    return work


def _volume_attach_admission_type(conn, df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return df

    out = df.copy()
    existing_col = _find_column(out, ["PType_Chng", "PType Chng", "PTypeChng", "PTypeChange", "PType_Change"])
    if existing_col and existing_col in out.columns:
        out["PType_Chng"] = pd.to_numeric(out[existing_col], errors="coerce")
    elif "PType_Chng" not in out.columns:
        out["PType_Chng"] = pd.Series([None] * len(out), dtype="float64")

    if conn is None:
        return out

    try:
        visit_table = _resolve_table_name(conn, ["Visit", "visit", "Visit_Mst", "VisitMst"])
        if not visit_table:
            return out
        ptype_col = _resolve_column(conn, visit_table, ["PType_Chng", "PTypeChng", "PTypeChange", "PType_Change"])
        if not ptype_col:
            return out

        def _q_ident(name: str) -> str:
            return f"[{str(name).replace(']', ']]')}]"

        visit_table_ref = f"[dbo].{_q_ident(visit_table)}"
        src_visit_id_col = _find_column(out, ["Visit_ID", "VisitId", "VisitID"])
        src_visit_no_col = _find_column(out, ["VisitNo", "Visitno", "Visit_No"])
        db_visit_id_col = _resolve_column(conn, visit_table, ["Visit_ID", "VisitId", "VisitID"])
        db_visit_no_col = _resolve_column(conn, visit_table, ["VisitNo", "Visit_No"])

        def _chunk_values(values: list, chunk_size: int = 500):
            for idx in range(0, len(values), chunk_size):
                yield values[idx:idx + chunk_size]

        if out["PType_Chng"].isna().any() and src_visit_id_col and db_visit_id_col:
            visit_id_series = pd.to_numeric(out[src_visit_id_col], errors="coerce")
            visit_ids = [int(v) for v in visit_id_series.dropna().astype("int64").unique().tolist()]
            if visit_ids:
                id_map: dict[int, int | None] = {}
                for chunk in _chunk_values(visit_ids):
                    placeholders = ",".join("?" for _ in chunk)
                    ptype_expr = (
                        "CASE "
                        f"WHEN NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_q_ident(ptype_col)}))), N'') IS NULL THEN NULL "
                        f"WHEN LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_q_ident(ptype_col)}))) NOT LIKE N'%[^0-9]%' "
                        f"THEN CONVERT(INT, LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_q_ident(ptype_col)})))) "
                        "ELSE NULL END"
                    )
                    sql = f"""
                        SELECT
                            CAST(v.{_q_ident(db_visit_id_col)} AS BIGINT) AS VisitIDKey,
                            {ptype_expr} AS PType_Chng
                        FROM {visit_table_ref} v WITH (NOLOCK)
                        WHERE v.{_q_ident(db_visit_id_col)} IN ({placeholders})
                    """
                    map_df = pd.read_sql(sql, conn, params=chunk)
                    if map_df is None or map_df.empty:
                        continue
                    for _, row in map_df.iterrows():
                        key = _volume_to_int_or_none(row.get("VisitIDKey"))
                        if key is not None and key not in id_map:
                            id_map[key] = _volume_to_int_or_none(row.get("PType_Chng"))
                if id_map:
                    mapped = visit_id_series.map(lambda val: id_map.get(_volume_to_int_or_none(val)))
                    out["PType_Chng"] = out["PType_Chng"].where(out["PType_Chng"].notna(), mapped)

        if out["PType_Chng"].isna().any() and src_visit_no_col and db_visit_no_col:
            visit_no_series = out[src_visit_no_col].fillna("").astype(str).str.strip()
            visit_nos = sorted({val for val in visit_no_series.tolist() if val})
            if visit_nos:
                no_map: dict[str, int | None] = {}
                visit_no_expr = f"LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_q_ident(db_visit_no_col)})))"
                for chunk in _chunk_values(visit_nos):
                    placeholders = ",".join("?" for _ in chunk)
                    ptype_expr = (
                        "CASE "
                        f"WHEN NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_q_ident(ptype_col)}))), N'') IS NULL THEN NULL "
                        f"WHEN LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_q_ident(ptype_col)}))) NOT LIKE N'%[^0-9]%' "
                        f"THEN CONVERT(INT, LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_q_ident(ptype_col)})))) "
                        "ELSE NULL END"
                    )
                    sql = f"""
                        SELECT
                            {visit_no_expr} AS VisitNoKey,
                            {ptype_expr} AS PType_Chng
                        FROM {visit_table_ref} v WITH (NOLOCK)
                        WHERE {visit_no_expr} IN ({placeholders})
                    """
                    map_df = pd.read_sql(sql, conn, params=chunk)
                    if map_df is None or map_df.empty:
                        continue
                    for _, row in map_df.iterrows():
                        key = str(row.get("VisitNoKey") or "").strip()
                        if key and key not in no_map:
                            no_map[key] = _volume_to_int_or_none(row.get("PType_Chng"))
                if no_map:
                    mapped = visit_no_series.map(lambda val: no_map.get(str(val or "").strip()))
                    out["PType_Chng"] = out["PType_Chng"].where(out["PType_Chng"].notna(), mapped)
    except Exception as e:
        print(f"[WARN] volume admission-type enrichment failed: {e}")

    out["PType_Chng"] = pd.to_numeric(out["PType_Chng"], errors="coerce")
    return out

def _volume_q_ident(name: str) -> str:
    return f"[{str(name).replace(']', ']]')}]"


def _volume_table_ref(name: str | None) -> str:
    if not name:
        return ""
    return f"[dbo].{_volume_q_ident(name)}"


def _volume_sql_text_expr(alias: str, col_name: str | None, *, size: int = 255) -> str:
    if not alias or not col_name:
        return f"CAST(N'' AS NVARCHAR({size}))"
    return f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR({size}), {alias}.{_volume_q_ident(col_name)}), N'')))"


def _volume_sql_numeric_expr(alias: str, col_name: str | None, *, sql_type: str = "INT", size: int = 100) -> str:
    if not alias or not col_name:
        return f"CAST(NULL AS {sql_type})"
    text_expr = _volume_sql_text_expr(alias, col_name, size=size)
    return (
        "CASE "
        f"WHEN NULLIF({text_expr}, N'') IS NULL THEN NULL "
        f"WHEN {text_expr} NOT LIKE N'%[^0-9]%' THEN CONVERT({sql_type}, {text_expr}) "
        "ELSE NULL END"
    )


def _volume_sql_try_int_expr(alias: str, col_name: str | None) -> str:
    return _volume_sql_numeric_expr(alias, col_name, sql_type="INT", size=100)


def _volume_fetch_raw_direct_paged(
    unit: str,
    conn,
    from_date: str,
    to_date: str,
    *,
    page_size: int = VOLUME_SQL_FETCH_BATCH_SIZE,
) -> pd.DataFrame:
    if conn is None:
        return pd.DataFrame()

    visit_table = _resolve_table_name(conn, ["Visit", "visit", "Visit_Mst", "VisitMst"])
    patient_table = _resolve_table_name(conn, ["Patient", "patient", "Patient_Mst", "PatientMst"])
    employee_table = _resolve_table_name(conn, ["Employee_Mst", "employee_mst", "EmployeeMst"])
    city_table = _resolve_table_name(conn, ["City_Mst", "city_mst", "CityMaster", "City_Master", "City"])

    visit_id_col = _resolve_column(conn, visit_table, ["Visit_ID", "VisitId", "VisitID"])
    visit_no_col = _resolve_column(conn, visit_table, ["VisitNo", "Visit_No"])
    visit_date_col = _resolve_column(conn, visit_table, ["VisitDate", "Visit_Date"])
    discharge_date_col = _resolve_column(conn, visit_table, ["DischargeDate", "Discharge_Date", "DischargeDateTime"])
    patient_id_col = _resolve_column(conn, visit_table, ["PatientID", "PatientId", "Patient_ID"])
    visit_type_col = _resolve_column(conn, visit_table, ["TypeOfVisit", "VisitType", "Type_Of_Visit"])
    visit_type_id_col = _resolve_column(conn, visit_table, ["VisitTypeID", "VisitTypeId", "VisitType_ID"])
    doc_in_charge_col = _resolve_column(conn, visit_table, ["DocInCharge", "DocIncharge", "DoctorInCharge", "DoctorIncharge"])
    ref_doc_col = _resolve_column(conn, visit_table, ["RefDocID", "RefDocId", "Ref_Doctor", "RefDoctor", "RefDoc"])
    outside_ref_col = _resolve_column(conn, visit_table, ["OutsideRefDoctor", "OutsideRefDr", "ExternalRefDoctor"])
    dept_id_col = _resolve_column(conn, visit_table, ["DepartmentID", "DepartmentId", "Department_ID"])
    patient_type_id_col = _resolve_column(conn, visit_table, ["PatientType_ID", "PatientTypeId", "PatientTypeID"])
    patient_subtype_id_col = _resolve_column(conn, visit_table, ["PatientSubType_ID", "PatientSubTypeId", "PatientSubTypeID"])
    ptype_change_col = _resolve_column(conn, visit_table, ["PType_Chng", "PTypeChng", "PTypeChange", "PType_Change"])

    if not visit_table or not visit_id_col or not visit_date_col:
        raise RuntimeError("Volume direct query schema incomplete")

    patient_pk_col = _resolve_column(conn, patient_table, ["PatientId", "patientId", "PatientID", "Patient_ID"]) if patient_table else None
    patient_gender_col = _resolve_column(conn, patient_table, ["Gender", "Sex", "PatientGender", "GenderName", "Patient_Sex"]) if patient_table else None
    patient_age_col = _resolve_column(conn, patient_table, ["Age", "AgeYears", "Age_Years", "AgeInYears", "PatientAge"]) if patient_table else None
    patient_mobile_col = _resolve_column(conn, patient_table, ["Mobile", "MobileNo", "Phone", "PhoneNo", "ContactNo"]) if patient_table else None
    patient_address1_col = _resolve_column(
        conn,
        patient_table,
        ["Contract_Address", "Address", "Address1", "Address_1", "AddressLine1", "Addr1", "AddressLine"],
    ) if patient_table else None
    patient_address2_col = _resolve_column(
        conn,
        patient_table,
        ["Permanent_Address", "Address2", "Address_2", "AddressLine2", "Addr2", "ParentAddress"],
    ) if patient_table else None
    patient_city_col = _resolve_column(
        conn,
        patient_table,
        ["Contact_City", "Permanent_City", "City_Name", "CityName", "City", "City_ID", "CityId", "PatientCity"],
    ) if patient_table else None

    city_id_col = _resolve_column(conn, city_table, ["City_ID", "CityId", "ID", "Id"]) if city_table else None
    city_name_col = _resolve_column(conn, city_table, ["City_Name", "CityName", "Name"]) if city_table else None

    emp_id_col = _resolve_column(conn, employee_table, ["EmpID", "EmpId", "EmployeeID", "EmployeeId", "ID", "Id"]) if employee_table else None
    emp_dept_col = _resolve_column(conn, employee_table, ["Department_ID", "DepartmentId", "department_id", "departmentid"]) if employee_table else None

    patient_joined = bool(patient_table and patient_pk_col and patient_id_col)
    joins: list[str] = []
    if patient_joined:
        joins.append(
            f"LEFT JOIN {_volume_table_ref(patient_table)} p WITH (NOLOCK) "
            f"ON p.{_volume_q_ident(patient_pk_col)} = v.{_volume_q_ident(patient_id_col)}"
        )

    patient_city_key_expr = _volume_sql_try_int_expr("p", patient_city_col) if patient_joined and patient_city_col else "CAST(NULL AS INT)"
    city_joined = bool(city_table and city_id_col and city_name_col and patient_joined and patient_city_col)
    if city_joined:
        joins.append(
            f"LEFT JOIN {_volume_table_ref(city_table)} c WITH (NOLOCK) "
            f"ON c.{_volume_q_ident(city_id_col)} = {patient_city_key_expr}"
        )

    visit_id_bigint_expr = _volume_sql_numeric_expr("v", visit_id_col, sql_type="BIGINT")
    visit_type_id_expr = _volume_sql_numeric_expr("v", visit_type_id_col, sql_type="INT")
    patient_id_expr = _volume_sql_numeric_expr("v", patient_id_col, sql_type="INT")
    doc_in_charge_expr = _volume_sql_numeric_expr("v", doc_in_charge_col, sql_type="INT")
    ref_doc_id_expr = _volume_sql_numeric_expr("v", ref_doc_col, sql_type="INT")
    dept_id_expr = _volume_sql_numeric_expr("v", dept_id_col, sql_type="INT")
    patient_type_id_expr_num = _volume_sql_numeric_expr("v", patient_type_id_col, sql_type="INT")
    patient_subtype_id_expr_num = _volume_sql_numeric_expr("v", patient_subtype_id_col, sql_type="INT")
    ptype_change_expr = _volume_sql_numeric_expr("v", ptype_change_col, sql_type="INT")

    dept_expr = "CAST(N'' AS NVARCHAR(200))"
    if dept_id_col:
        dept_expr = (
            f"CASE WHEN {dept_id_expr} IS NULL THEN N'' "
            f"ELSE ISNULL(dbo.fn_dept({dept_id_expr}), N'') END"
        )
    elif employee_table and emp_id_col and emp_dept_col and doc_in_charge_col:
        joins.append(
            f"LEFT JOIN {_volume_table_ref(employee_table)} e WITH (NOLOCK) "
            f"ON e.{_volume_q_ident(emp_id_col)} = v.{_volume_q_ident(doc_in_charge_col)}"
        )
        emp_dept_expr = _volume_sql_numeric_expr("e", emp_dept_col, sql_type="INT")
        dept_expr = (
            f"CASE WHEN {emp_dept_expr} IS NULL THEN N'' "
            f"ELSE ISNULL(dbo.fn_dept({emp_dept_expr}), N'') END"
        )

    visit_type_text_expr = _volume_sql_text_expr("v", visit_type_col, size=120)
    discharge_date_expr = (
        f"CAST(v.{_volume_q_ident(discharge_date_col)} AS DATETIME)"
        if discharge_date_col
        else "CAST(NULL AS DATETIME)"
    )
    visit_type_display_expr = f"""
        CASE
            WHEN NULLIF({visit_type_text_expr}, N'') IS NOT NULL THEN {visit_type_text_expr}
            WHEN {visit_type_id_expr} = 2 THEN N'Out Patient Visits'
            WHEN {visit_type_id_expr} = 3 THEN N'Diagnostic Visit'
            WHEN {visit_type_id_expr} = 6 THEN N'Health Checkups'
            WHEN {visit_type_id_expr} = 1 THEN N'IPD'
            ELSE N''
        END
    """
    visit_date_dt_expr = f"CAST(v.{_volume_q_ident(visit_date_col)} AS DATETIME)"
    ipd_daycare_expr = f"""
        CASE
            WHEN {visit_type_id_expr} <> 1 THEN N''
            WHEN {discharge_date_expr} IS NOT NULL
                 AND DATEDIFF(MINUTE, {visit_date_dt_expr}, {discharge_date_expr}) >= 0
                 AND DATEDIFF(MINUTE, {visit_date_dt_expr}, {discharge_date_expr}) <= {VOLUME_DAYCARE_MAX_HOURS * 60}
                THEN N'Daycare'
            WHEN UPPER({visit_type_text_expr}) LIKE N'%DAY%' THEN N'Daycare'
            ELSE N'IPD'
        END
    """

    patient_name_expr = (
        f"CASE WHEN {patient_id_expr} IS NULL THEN N'' "
        f"ELSE ISNULL(dbo.fn_patientfullname({patient_id_expr}), N'') END"
        if patient_id_col
        else "CAST(N'' AS NVARCHAR(255))"
    )
    reg_no_expr = (
        f"CASE WHEN {patient_id_expr} IS NULL THEN N'' "
        f"ELSE ISNULL(dbo.fn_regno({patient_id_expr}), N'') END"
        if patient_id_col
        else "CAST(N'' AS NVARCHAR(80))"
    )
    consultant_expr = (
        f"CASE WHEN {doc_in_charge_expr} IS NULL THEN N'' "
        f"ELSE ISNULL(dbo.fn_DoctorFirstName({doc_in_charge_expr}), N'') END"
        if doc_in_charge_col
        else "CAST(N'' AS NVARCHAR(200))"
    )
    referring_expr = (
        f"CASE WHEN {ref_doc_id_expr} IS NULL THEN N'' "
        f"ELSE ISNULL(dbo.fn_DoctorFirstName({ref_doc_id_expr}), N'') END"
        if ref_doc_col
        else "CAST(N'' AS NVARCHAR(200))"
    )
    outside_ref_raw_expr = _volume_sql_text_expr("v", outside_ref_col, size=200)
    outside_ref_id_expr = _volume_sql_try_int_expr("v", outside_ref_col)
    outside_ref_expr = (
        f"CASE WHEN {outside_ref_id_expr} IS NOT NULL "
        f"THEN ISNULL(dbo.fn_DoctorFirstName({outside_ref_id_expr}), N'') ELSE {outside_ref_raw_expr} END"
        if outside_ref_col
        else "CAST(N'' AS NVARCHAR(200))"
    )

    address1_expr = _volume_sql_text_expr("p", patient_address1_col, size=255)
    address2_expr = _volume_sql_text_expr("p", patient_address2_col, size=255)
    address_expr = f"""
        CASE
            WHEN {address1_expr} <> N'' AND {address2_expr} <> N'' AND UPPER({address1_expr}) = UPPER({address2_expr}) THEN {address1_expr}
            WHEN {address1_expr} <> N'' AND {address2_expr} <> N'' THEN {address1_expr} + N', ' + {address2_expr}
            WHEN {address1_expr} <> N'' THEN {address1_expr}
            ELSE {address2_expr}
        END
    """
    patient_city_expr = _volume_sql_text_expr("p", patient_city_col, size=200) if patient_joined else "CAST(N'' AS NVARCHAR(200))"
    city_name_expr = _volume_sql_text_expr("c", city_name_col, size=200) if city_joined else "CAST(N'' AS NVARCHAR(200))"
    city_expr = f"COALESCE(NULLIF({city_name_expr}, N''), NULLIF({patient_city_expr}, N''), N'')"
    mobile_expr = _volume_sql_text_expr("p", patient_mobile_col, size=50) if patient_joined else "CAST(N'' AS NVARCHAR(50))"
    gender_expr = _volume_sql_text_expr("p", patient_gender_col, size=40) if patient_joined else "CAST(N'' AS NVARCHAR(40))"
    age_expr = _volume_sql_text_expr("p", patient_age_col, size=40) if patient_joined else "CAST(N'' AS NVARCHAR(40))"

    patient_type_expr = (
        f"CASE WHEN {patient_type_id_expr_num} IS NULL THEN N'' "
        f"ELSE ISNULL(dbo.fn_pat_type({patient_type_id_expr_num}), N'') END"
        if patient_type_id_col
        else "CAST(N'' AS NVARCHAR(120))"
    )
    patient_subtype_expr = (
        f"CASE WHEN {patient_subtype_id_expr_num} IS NULL THEN N'' "
        f"ELSE ISNULL(dbo.fn_patsub_type({patient_subtype_id_expr_num}), N'') END"
        if patient_subtype_id_col
        else "CAST(N'' AS NVARCHAR(120))"
    )
    visit_no_expr = _volume_sql_text_expr("v", visit_no_col, size=80)
    join_sql = "\n                ".join(joins)

    batch_size = max(500, min(int(page_size or VOLUME_SQL_FETCH_BATCH_SIZE), 20000))
    visit_table_ref = _volume_table_ref(visit_table)
    last_seen_date = None
    last_seen_visit_id = None
    frames: list[pd.DataFrame] = []

    while True:
        params: list = [from_date, to_date]
        keyset_sql = ""
        if last_seen_date is not None and last_seen_visit_id is not None:
            keyset_sql = (
                f" AND (v.{_volume_q_ident(visit_date_col)} < ? "
                f"OR (v.{_volume_q_ident(visit_date_col)} = ? AND {visit_id_bigint_expr} < ?))"
            )
            params.extend([last_seen_date, last_seen_date, int(last_seen_visit_id)])

        sql = f"""
            SELECT TOP {batch_size}
                {visit_id_bigint_expr} AS Visit_ID,
                {visit_no_expr} AS Visitno,
                CAST(v.{_volume_q_ident(visit_date_col)} AS DATETIME) AS VisitDate,
                {discharge_date_expr} AS DischargeDate,
                {patient_name_expr} AS PatientName,
                {reg_no_expr} AS Registration_No,
                {visit_type_display_expr} AS TypeOfVisit,
                {ipd_daycare_expr} AS IPD_Daycare_Flag,
                {visit_type_id_expr} AS VisitTypeID,
                {consultant_expr} AS DoctorIncharge,
                {referring_expr} AS ReferringDoctor,
                {outside_ref_expr} AS OutsideRefDoctor,
                {address_expr} AS address,
                {city_expr} AS City_Name,
                {patient_type_expr} AS PatientType,
                {patient_subtype_expr} AS PatSubType,
                {mobile_expr} AS Mobile,
                {age_expr} AS Age,
                {gender_expr} AS Gender,
                {dept_expr} AS Dept_Name,
                {ptype_change_expr} AS PType_Chng
            FROM {visit_table_ref} v WITH (NOLOCK)
                {join_sql}
            WHERE v.{_volume_q_ident(visit_date_col)} >= CAST(? AS DATETIME)
              AND v.{_volume_q_ident(visit_date_col)} < DATEADD(DAY, 1, CAST(? AS DATETIME))
              {keyset_sql}
            ORDER BY v.{_volume_q_ident(visit_date_col)} DESC, {visit_id_bigint_expr} DESC;
        """
        page_df = pd.read_sql(sql, conn, params=params)
        if page_df is None or page_df.empty:
            break

        page_df.columns = [str(c).strip() for c in page_df.columns]
        frames.append(page_df)

        if len(page_df) < batch_size:
            break

        tail = page_df.iloc[-1]
        next_date = pd.to_datetime(tail.get("VisitDate"), errors="coerce")
        next_visit_id = _volume_to_int_or_none(tail.get("Visit_ID"))
        if pd.isna(next_date) or next_visit_id is None:
            break
        last_seen_date = next_date.to_pydatetime()
        last_seen_visit_id = int(next_visit_id)

    if not frames:
        return pd.DataFrame()

    valid_frames = []
    column_order = []
    seen_columns = set()
    for frame in frames:
        if frame is None or frame.empty:
            continue
        if frame.dropna(axis=0, how="all").empty:
            continue
        if frame.dropna(axis=1, how="all").shape[1] == 0:
            continue
        for col in frame.columns:
            if col not in seen_columns:
                seen_columns.add(col)
                column_order.append(col)
        valid_frames.append(frame.dropna(axis=1, how="all"))
    if not valid_frames:
        return pd.DataFrame()

    with warnings.catch_warnings():
        warnings.filterwarnings(
            "ignore",
            message="The behavior of DataFrame concatenation with empty or all-NA entries is deprecated.*",
            category=FutureWarning,
        )
        out = pd.concat(valid_frames, ignore_index=True)
    if column_order:
        out = out.reindex(columns=column_order)
    print(
        f"[INFO] Volume direct SQL fetch for {str(unit or '').upper()} "
        f"loaded {len(out):,} rows in {len(valid_frames):,} batch(es)"
    )
    return out

def fetch_volume_raw(units: list[str], from_date: str, to_date: str) -> pd.DataFrame:
    """
    Fetches only the requested date window on EACH allowed unit DB and
    reads the data in SQL batches to avoid oversized single-shot pulls.
    """
    if not units:
        return pd.DataFrame()

    frames = []
    for unit in units:
        conn = None
        try:
            conn = get_sql_connection(unit)  # unit is required in your project
            if not conn:
                print(f"âš ï¸ Volume: could not connect to {unit}")
                continue

            try:
                df = _volume_fetch_raw_direct_paged(unit, conn, from_date, to_date)
            except Exception as direct_err:
                print(f"[WARN] Volume direct SQL fetch failed for {unit}, falling back to proc: {direct_err}")
                sql = "EXEC dbo.usp_RptVisitMarketManagerMIS ?, ?"
                df = pd.read_sql(sql, conn, params=[from_date, to_date])

            if df is not None and not df.empty:
                df.columns = [c.strip() for c in df.columns]
                if "PType_Chng" not in df.columns:
                    df = _volume_attach_admission_type(conn, df)
                df["Unit"] = unit.upper()
                frames.append(df)
        except Exception as e:
            print(f"âŒ Error fetching volume ({unit}): {e}")
        finally:
            try:
                if conn:
                    conn.close()
            except Exception:
                pass

    # Exclude empty/all-NA frames to avoid the pandas FutureWarning
    valid_frames = []
    for f in frames:
        if f is None:
            continue
        if f.dropna(axis=0, how='all').empty:
            continue
        if f.dropna(axis=1, how='all').shape[1] == 0:
            continue
        valid_frames.append(f)

    if not valid_frames:
        return pd.DataFrame()

    return pd.concat(valid_frames, ignore_index=True, copy=False)


def _filter_volume_details_by_visit_date(
    df: pd.DataFrame,
    from_date: str | None = None,
    to_date: str | None = None,
    *,
    visit_date_col: str = "VisitDate",
) -> pd.DataFrame:
    if df is None or df.empty or visit_date_col not in df.columns:
        return df
    start, end = _parse_date_range(from_date, to_date)
    if start is None or end is None:
        return df

    visit_dt = pd.to_datetime(df[visit_date_col], errors="coerce")
    if getattr(visit_dt.dt, "tz", None) is not None:
        visit_dt = visit_dt.dt.tz_convert(LOCAL_TZ).dt.tz_localize(None)
    if visit_dt.notna().sum() == 0:
        return df

    mask = visit_dt.between(start, end, inclusive="both")
    filtered = df.loc[mask].copy()
    if len(filtered) != len(df):
        print(
            f"[INFO] Volume strict date clamp kept {len(filtered):,} of {len(df):,} rows "
            f"for range {from_date} to {to_date}"
        )
    return filtered


def shape_volume_details(
    df_raw: pd.DataFrame,
    from_date: str | None = None,
    to_date: str | None = None,
) -> pd.DataFrame:
    """
    Shapes the raw proc result to the exact columns requested.
    Uses your daycare/IPD flag when VisitTypeID=1, else shows TypeOfVisit.
    """
    if df_raw is None or df_raw.empty:
        return pd.DataFrame(columns=VOLUME_TRACKER_COL_ORDER)

    def get(col):
        return df_raw[col] if col in df_raw.columns else pd.Series([None]*len(df_raw))

    gender_col = _find_column(
        df_raw,
        ["Gender", "Sex", "PatientGender", "GenderName", "SexName", "Sex_Name", "Gender_Name", "Patient_Sex"]
    )
    gender_series = get(gender_col) if gender_col else pd.Series([None] * len(df_raw))
    age_col = _find_column(
        df_raw,
        ["AgeYears", "Age_Years", "AgeYrs", "AgeInYears", "AgeInYrs", "Age (Years)", "PatientAge", "Age", "age"]
    )
    age_series = get(age_col) if age_col else pd.Series([None] * len(df_raw))
    visit_type_id_col = _find_column(
        df_raw,
        ["VisitTypeID", "VisitTypeId", "VisitType_ID", "Visit_Type_ID"]
    )
    visit_type_id_series = get(visit_type_id_col) if visit_type_id_col else pd.Series([None] * len(df_raw))
    ipd_daycare_flag_col = _find_column(df_raw, ["IPD_Daycare_Flag", "IPD Daycare Flag", "IPDDaycareFlag"])
    ipd_daycare_flag_series = get(ipd_daycare_flag_col) if ipd_daycare_flag_col else pd.Series([None] * len(df_raw))
    admission_type_col = _find_column(df_raw, ["PType_Chng", "PType Chng", "PTypeChng", "PTypeChange", "PType_Change"])
    admission_type_code_series = (
        pd.to_numeric(get(admission_type_col), errors="coerce")
        if admission_type_col
        else pd.Series([None] * len(df_raw), dtype="float64")
    )
    visit_date_series = pd.to_datetime(get("VisitDate"), errors="coerce")
    discharge_date_series = pd.to_datetime(get("DischargeDate"), errors="coerce")

    # Build TypeOfVisit display per your rule
    normalized_visit_type_series = []
    for visit_type_id, visit_value, visit_date, discharge_date, existing_flag in zip(
        visit_type_id_series,
        get("TypeOfVisit"),
        visit_date_series,
        discharge_date_series,
        ipd_daycare_flag_series,
    ):
        visit_type_num = _volume_to_int_or_none(visit_type_id) or 0
        if visit_type_num == 1:
            normalized_visit_type_series.append(
                _volume_ipd_daycare_flag_from_values(
                    visit_type_id,
                    visit_value=visit_value,
                    visit_date=visit_date,
                    discharge_date=discharge_date,
                    existing_flag=existing_flag,
                )
            )
        else:
            normalized_visit_type_series.append(str(visit_value or "").strip())

    # Compose details
    details = pd.DataFrame({
        "VisitNo":             get("Visitno"),
        "VisitDate":           visit_date_series,
        "DischargeDate":       discharge_date_series,
        "PatientName":         get("PatientName"),
        "RegNo":               get("Registration_No"),
        "TypeOfVisit":         normalized_visit_type_series,
        "AdmissionType":       "",
        "Consultant":          get("DoctorIncharge"),
        "ReferringConsultant": get("ReferringDoctor"),
        "ExternalRefConsultant": get("OutsideRefDoctor"),
        "Address":             get("address"),
        "City":                get("City_Name"),
        "PatientType":         get("PatientType"),
        "CorpType":            get("PatSubType"),  # from patsubtype
        "PatientContact":      get("Mobile"),
        "Age":                 age_series,
        "Dept":                get("Dept_Name"),
    })

    # Order columns
    details = details[VOLUME_TRACKER_COL_ORDER].copy()
    details["Gender"] = gender_series
    details["VisitTypeID"] = visit_type_id_series
    details["AdmissionTypeCode"] = admission_type_code_series
    details["AdmissionType"] = [
        _volume_admission_type_display(code_value, visit_value)
        for code_value, visit_value in zip(details["AdmissionTypeCode"], details["TypeOfVisit"])
    ]
    details = _filter_volume_details_by_visit_date(details, from_date, to_date, visit_date_col="VisitDate")
    details = apply_volume_ipd_daycare_segmentation(details)

    # Format datetimes as IST display strings
    details["VisitDate"]     = details["VisitDate"].apply(_as_ist_string)
    details["DischargeDate"] = details["DischargeDate"].apply(_as_ist_string)

    # Clean string fields
    for col in ["PatientName","Consultant","ReferringConsultant",
                "ExternalRefConsultant","Address","City","PatientType",
                "CorpType","Dept","PatientContact","RegNo","TypeOfVisit","AdmissionType","Gender"]:
        if col in details.columns:
            details[col] = details[col].astype(str).str.strip().replace({"nan":"", "None":""})

    return details

def get_volume_details(units: list[str], from_date: str, to_date: str) -> pd.DataFrame:
    raw = fetch_volume_raw(units, from_date, to_date)
    return shape_volume_details(raw, from_date=from_date, to_date=to_date)


def fetch_volume_hcv_doctor_visits(unit: str, from_date: str, to_date: str) -> pd.DataFrame:
    """
    Fetch Health Checkup doctor visit rows from Visit_HCV joined to Visit.
    Date filtering is strictly based on master Visit.VisitDate.
    """
    empty = pd.DataFrame(columns=VOLUME_HCV_DOCTOR_COL_ORDER)
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Volume HCV doctor KPI: could not connect to {unit}")
        return empty

    try:
        hcv_table = _resolve_table_name(conn, ["Visit_HCV", "visit_hcv"])
        visit_table = _resolve_table_name(conn, ["Visit", "visit"])
        if not hcv_table or not visit_table:
            return empty

        hcv_id_col = _resolve_column(conn, hcv_table, ["HCVId", "HCVID", "HcvId", "Id"])
        hcv_visit_id_col = _resolve_column(conn, hcv_table, ["VisitId", "VisitID", "Visit_ID"])
        hcv_patient_id_col = _resolve_column(conn, hcv_table, ["PatientId", "PatientID", "Patient_ID"])
        hcv_visit_no_col = _resolve_column(conn, hcv_table, ["VisitNo", "Visit_No"])
        hcv_dept_col = _resolve_column(conn, hcv_table, ["DepartmentId", "DepartmentID", "Department_ID"])
        hcv_doctor_col = _resolve_column(conn, hcv_table, ["DoctorId", "DoctorID", "Doctor_ID"])
        hcv_package_col = _resolve_column(conn, hcv_table, ["PackageId", "PackageID", "Package_ID"])

        visit_id_col = _resolve_column(conn, visit_table, ["Visit_ID", "VisitId", "VisitID"])
        visit_date_col = _resolve_column(conn, visit_table, ["VisitDate", "Visit_Date"])
        visit_no_col = _resolve_column(conn, visit_table, ["VisitNo", "Visit_No"])
        visit_patient_col = _resolve_column(conn, visit_table, ["PatientID", "PatientId", "Patient_ID"])
        visit_subtype_col = _resolve_column(
            conn,
            visit_table,
            ["PatientSubType_ID", "PatientSubTypeId", "PatientSubTypeID"],
        )

        if not hcv_visit_id_col or not visit_id_col or not visit_date_col:
            return empty

        hcv_patient_expr = f"h.[{hcv_patient_id_col}]" if hcv_patient_id_col else "NULL"
        visit_patient_expr = f"v.[{visit_patient_col}]" if visit_patient_col else "NULL"
        patient_expr = f"COALESCE({hcv_patient_expr}, {visit_patient_expr})"
        hcv_visit_no_expr = f"h.[{hcv_visit_no_col}]" if hcv_visit_no_col else "NULL"
        visit_no_expr = f"v.[{visit_no_col}]" if visit_no_col else "NULL"
        merged_visit_no_expr = f"COALESCE({hcv_visit_no_expr}, {visit_no_expr})"

        hcv_id_expr = f"h.[{hcv_id_col}]" if hcv_id_col else "NULL"
        dept_expr = (
            f"CASE WHEN h.[{hcv_dept_col}] IS NULL THEN N'' ELSE dbo.Fn_subDept(h.[{hcv_dept_col}]) END"
            if hcv_dept_col
            else "N''"
        )
        doctor_expr = (
            f"CASE WHEN h.[{hcv_doctor_col}] IS NULL THEN N'' ELSE dbo.fn_doctorfirstname(h.[{hcv_doctor_col}]) END"
            if hcv_doctor_col
            else "N''"
        )
        corp_expr = (
            f"CASE WHEN v.[{visit_subtype_col}] IS NULL THEN N'' ELSE dbo.fn_patsub_type(v.[{visit_subtype_col}]) END"
            if visit_subtype_col
            else "N''"
        )
        package_expr = f"h.[{hcv_package_col}]" if hcv_package_col else "NULL"

        sql = f"""
            SELECT
                {hcv_id_expr} AS HCVId,
                h.[{hcv_visit_id_col}] AS VisitId,
                {patient_expr} AS PatientId,
                {merged_visit_no_expr} AS VisitNo,
                v.[{visit_date_col}] AS VisitDate,
                CASE WHEN {patient_expr} IS NULL THEN N'' ELSE dbo.fn_regno({patient_expr}) END AS RegNo,
                CASE WHEN {patient_expr} IS NULL THEN N'' ELSE dbo.fn_patientfullname({patient_expr}) END AS PatientName,
                {dept_expr} AS Dept,
                {doctor_expr} AS Consultant,
                {corp_expr} AS CorpType,
                {package_expr} AS PackageId
            FROM dbo.[{hcv_table}] h WITH (NOLOCK)
            INNER JOIN dbo.[{visit_table}] v WITH (NOLOCK)
                ON v.[{visit_id_col}] = h.[{hcv_visit_id_col}]
            WHERE CONVERT(VARCHAR(10), v.[{visit_date_col}], 120)
                    BETWEEN CONVERT(VARCHAR(10), ?, 120)
                        AND CONVERT(VARCHAR(10), ?, 120)
            ORDER BY v.[{visit_date_col}] DESC, h.[{hcv_visit_id_col}] DESC
        """
        df = pd.read_sql(sql, conn, params=[from_date, to_date])
        if df is None or df.empty:
            return empty

        df.columns = [str(c).strip() for c in df.columns]
        df["VisitDate"] = pd.to_datetime(df.get("VisitDate"), errors="coerce").apply(_as_ist_string)
        df["Unit"] = (unit or "").strip().upper()

        for col in ["RegNo", "PatientName", "Dept", "Consultant", "CorpType", "VisitNo", "VisitDate"]:
            if col in df.columns:
                df[col] = (
                    df[col]
                    .astype(str)
                    .str.strip()
                    .replace({"nan": "", "None": "", "NaT": ""})
                )

        for col in ["HCVId", "VisitId", "PatientId", "PackageId"]:
            if col in df.columns:
                df[col] = pd.to_numeric(df[col], errors="coerce")

        for col in VOLUME_HCV_DOCTOR_COL_ORDER:
            if col not in df.columns:
                df[col] = None
        return df[VOLUME_HCV_DOCTOR_COL_ORDER].copy()
    except Exception as e:
        print(f"Volume HCV doctor KPI fetch failed ({unit}): {e}")
        return empty
    finally:
        try:
            conn.close()
        except Exception:
            pass

def _empty_volume_discharge_kpi_payload(
    from_date: str | None = None,
    to_date: str | None = None,
    cured_ids: list[int] | None = None,
    lama_ids: list[int] | None = None,
    referred_ids: list[int] | None = None,
    death_ids: list[int] | None = None,
) -> dict:
    return {
        "from_date": from_date or "",
        "to_date": to_date or "",
        "cured_type_ids": list(cured_ids or [1, 2]),
        "lama_type_ids": list(lama_ids or [4, 5, 7, 8]),
        "referred_type_ids": list(referred_ids or [3]),
        "death_type_ids": list(death_ids or [6]),
        "overall": {
            "total_discharges": 0,
            "cured_cases": 0,
            "cured_percent": 0.0,
            "lama_cases": 0,
            "lama_percent": 0.0,
            "referred_cases": 0,
            "referred_percent": 0.0,
            "death_cases": 0,
            "mortality_ratio": 0.0,
            "type_breakdown": [],
            "ward_breakdown": [],
        },
        "units": [],
    }


def fetch_volume_discharge_rows(unit: str, from_date: str, to_date: str) -> pd.DataFrame:
    """
    Fetch latest (deduped) IPD discharge rows in date range.
    Uses VisitTypeID=1 and keeps only latest discharge per Visit_ID
    to avoid duplicate/cancel-recreate discharge records.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Volume discharge KPI: could not connect to {unit}")
        return pd.DataFrame()

    try:
        visit_table = _resolve_table_name(conn, ["Visit", "visit"])
        discharge_table = _resolve_table_name(conn, ["Discharge", "discharge"])
        dischargetype_table = _resolve_table_name(conn, ["DischargeType_Mst", "dischargetype_mst"])

        if not visit_table or not discharge_table:
            print(f"Volume discharge KPI: missing Visit/Discharge table for {unit}")
            return pd.DataFrame()

        visit_id_col = _resolve_column(conn, visit_table, ["Visit_ID", "VisitId", "VisitID"])
        visit_date_col = _resolve_column(conn, visit_table, ["VisitDate", "Visit_Date", "AdmissionDate", "Admission_Date", "AdmitDate", "Admit_Date"])
        visit_type_col = _resolve_column(conn, visit_table, ["VisitTypeID", "VisitTypeId", "VisitType_ID"])
        ward_col = _resolve_column(conn, visit_table, ["WardID", "WardId", "Ward_ID"])
        patient_id_col = _resolve_column(conn, visit_table, ["PatientID", "PatientId", "Patient_ID"])
        doctor_col = _resolve_column(conn, visit_table, ["DocInCharge", "DoctorInCharge", "Doc_In_Charge"])
        dept_col = _resolve_column(conn, visit_table, ["DepartmentID", "DepartmentId", "Department_ID"])
        patient_subtype_col = _resolve_column(conn, visit_table, ["PatientSubType_ID", "PatientSubTypeID", "PatientSubTypeId", "PatSubType_ID", "PatSubTypeID"])
        employee_table = _resolve_table_name(conn, ["Employee_Mst", "employee_mst", "EmployeeMst"])

        dis_visit_id_col = _resolve_column(conn, discharge_table, ["Visit_ID", "VisitId", "VisitID"])
        dis_id_col = _resolve_column(conn, discharge_table, ["Discharge_ID", "DischargeId", "DischargeID"])
        dis_type_id_col = _resolve_column(conn, discharge_table, ["DischargeType_ID", "DischargeTypeId", "DischargeTypeID"])
        dis_type_text_col = _resolve_column(conn, discharge_table, ["DischargeType"])
        dis_cancel_col = _resolve_column(conn, discharge_table, ["CancelStatus", "Cancelled", "Canceled"])
        dis_date_col = _resolve_column(conn, discharge_table, ["Discharge_Date", "DischargeDate"])
        dis_admin_date_col = _resolve_column(conn, discharge_table, ["adminDischargeDate", "AdminDischargeDate"])
        dis_cd_date_col = _resolve_column(conn, discharge_table, ["CDdate", "CDDate"])
        dis_updated_col = _resolve_column(conn, discharge_table, ["UpdatedOn", "Updated_ON"])
        dis_inserted_col = _resolve_column(conn, discharge_table, ["InsertedON", "InsertedOn", "Inserted_ON"])

        dt_id_col = None
        dt_name_col = None
        if dischargetype_table:
            dt_id_col = _resolve_column(conn, dischargetype_table, ["DischargeType_ID", "DischargeTypeId", "DischargeTypeID"])
            dt_name_col = _resolve_column(conn, dischargetype_table, ["DischargeType"])

        required = [visit_id_col, visit_type_col, dis_visit_id_col, dis_id_col]
        if any(not c for c in required):
            print(f"Volume discharge KPI: required columns missing for {unit}")
            return pd.DataFrame()

        discharge_date_cols = [
            c for c in [dis_admin_date_col, dis_date_col, dis_cd_date_col, dis_updated_col, dis_inserted_col]
            if c
        ]
        if not discharge_date_cols:
            print(f"Volume discharge KPI: no discharge date column found for {unit}")
            return pd.DataFrame()

        # SQL Server old-version safe datetime parsing (no TRY_CONVERT dependency).
        date_type_map = {}
        try:
            placeholders = ",".join("?" for _ in discharge_date_cols)
            type_sql = f"""
                SELECT c.name AS ColName, t.name AS TypeName
                FROM sys.columns c
                INNER JOIN sys.types t ON c.user_type_id = t.user_type_id
                WHERE c.object_id = OBJECT_ID(?)
                  AND c.name IN ({placeholders})
            """
            type_df = pd.read_sql(type_sql, conn, params=[discharge_table, *discharge_date_cols])
            if type_df is not None and not type_df.empty:
                for _, trow in type_df.iterrows():
                    cname = str(trow.get("ColName") or "").strip()
                    tname = str(trow.get("TypeName") or "").strip().lower()
                    if cname:
                        date_type_map[cname.lower()] = tname
        except Exception:
            date_type_map = {}

        native_date_types = {
            "date", "datetime", "datetime2", "smalldatetime", "datetimeoffset", "time"
        }
        safe_date_parts = []
        for col in discharge_date_cols:
            part = f"d.[{col}]"
            col_type = date_type_map.get(str(col).lower(), "")
            if col_type in native_date_types:
                safe_date_parts.append(f"CAST({part} AS DATETIME)")
            else:
                safe_date_parts.append(
                    f"(CASE WHEN {part} IS NULL THEN NULL "
                    f"WHEN ISDATE({part}) = 1 THEN CAST({part} AS DATETIME) "
                    f"ELSE NULL END)"
                )
        discharge_date_expr = f"COALESCE({', '.join(safe_date_parts)})"
        if dis_cancel_col:
            cancel_expr = (
                f"(CASE WHEN ISNUMERIC(CAST(d.[{dis_cancel_col}] AS NVARCHAR(30))) = 1 "
                f"THEN CAST(d.[{dis_cancel_col}] AS INT) ELSE 0 END)"
            )
        else:
            cancel_expr = "0"
        dis_type_text_expr = (
            f"CAST(d.[{dis_type_text_col}] AS NVARCHAR(200))" if dis_type_text_col else "NULL"
        )
        dt_name_expr = (
            f"CAST(dt.[{dt_name_col}] AS NVARCHAR(200))" if dt_name_col else "NULL"
        )

        dis_type_id_select = (
            f"CAST(d.[{dis_type_id_col}] AS NVARCHAR(100))" if dis_type_id_col else "NULL"
        )
        dis_type_id_field = "ld.DischargeType_ID"
        dis_type_id_key_expr = f"LTRIM(RTRIM(CAST({dis_type_id_select} AS NVARCHAR(100))))"
        order_col = dis_id_col or dis_visit_id_col

        join_discharge_type = ""
        if dischargetype_table and dt_id_col and dis_type_id_col:
            join_discharge_type = (
                f"LEFT JOIN [dbo].[{dischargetype_table}] dt WITH (NOLOCK) "
                f"ON LTRIM(RTRIM(CAST(dt.[{dt_id_col}] AS NVARCHAR(100)))) = ld.DischargeType_ID_Key"
            )

        visit_type_num_expr = (
            f"(CASE WHEN ISNUMERIC(CAST(v.[{visit_type_col}] AS NVARCHAR(30))) = 1 "
            f"THEN CAST(v.[{visit_type_col}] AS INT) ELSE NULL END)"
        )
        visit_date_expr = f"CAST(v.[{visit_date_col}] AS DATETIME)" if visit_date_col else "NULL"

        ward_expr = "N'Unknown'"
        if ward_col:
            ward_expr = f"CASE WHEN v.[{ward_col}] IS NULL THEN N'Unknown' ELSE dbo.fn_ward_name(v.[{ward_col}]) END"

        patient_expr = "N''"
        regno_expr = "N''"
        if patient_id_col:
            patient_expr = f"CASE WHEN v.[{patient_id_col}] IS NULL THEN N'' ELSE dbo.fn_patientfullname(v.[{patient_id_col}]) END"
            regno_expr = f"CASE WHEN v.[{patient_id_col}] IS NULL THEN N'' ELSE dbo.fn_regno(v.[{patient_id_col}]) END"

        corp_type_expr = "N''"
        if patient_subtype_col:
            corp_type_expr = (
            f"CASE WHEN v.[{patient_subtype_col}] IS NULL THEN N'' "
            f"ELSE ISNULL(dbo.fn_patsub_type(v.[{patient_subtype_col}]), N'') END"
        )

            doctor_expr = "N''"
        if doctor_col:
            doctor_expr = f"CASE WHEN v.[{doctor_col}] IS NULL THEN N'' ELSE dbo.fn_doctorfirstname(v.[{doctor_col}]) END"

        join_employee = ""
        department_expr = "N''"

        if dept_col:
            department_expr = (
                f"CASE WHEN ISNULL(v.[{dept_col}], 0) > 0 "
                f"THEN ISNULL(dbo.fn_dept(v.[{dept_col}]), N'') ELSE N'' END"
            )
        elif employee_table and doctor_col:
            emp_id_col = _resolve_column(conn, employee_table, ["EmpID", "EmpId", "EmployeeID", "EmployeeId", "ID", "Id"])
            emp_dept_col = _resolve_column(conn, employee_table, ["Department_ID", "DepartmentId", "department_id", "departmentid"])
            if emp_id_col and emp_dept_col:
                join_employee = (
                    f"LEFT JOIN [dbo].[{employee_table}] e WITH (NOLOCK) "
                    f"ON e.[{emp_id_col}] = v.[{doctor_col}]"
                )
                department_expr = (
                    f"CASE WHEN ISNULL(e.[{emp_dept_col}], 0) > 0 "
                    f"THEN ISNULL(dbo.fn_dept(e.[{emp_dept_col}]), N'') ELSE N'' END"
                )

        sql = f"""
            ;WITH latest_discharge AS (
                SELECT
                    d.[{dis_visit_id_col}] AS Visit_ID,
                    {dis_type_id_select} AS DischargeType_ID,
                    {dis_type_id_key_expr} AS DischargeType_ID_Key,
                    {dis_type_text_expr} AS DischargeTypeRaw,
                    {discharge_date_expr} AS DischargeDate,
                    {cancel_expr} AS CancelStatus,
                    ROW_NUMBER() OVER (
                        PARTITION BY d.[{dis_visit_id_col}]
                        ORDER BY {discharge_date_expr} DESC, d.[{order_col}] DESC
                    ) AS rn
                FROM [dbo].[{discharge_table}] d WITH (NOLOCK)
                WHERE d.[{dis_visit_id_col}] IS NOT NULL
            )
            SELECT
                ? AS Unit,
                ld.Visit_ID,
                {visit_date_expr} AS VisitDate,
                ld.DischargeDate,
                {dis_type_id_field} AS DischargeType_ID,
                COALESCE(NULLIF({dt_name_expr}, N''), NULLIF(ld.DischargeTypeRaw, N''), N'Unknown') AS DischargeType,
                {ward_expr} AS Ward,
                {department_expr} AS Department,
                {corp_type_expr} AS CorpType,
                {patient_expr} AS Patient,
                {regno_expr} AS Regno,
                {doctor_expr} AS Doctor
            FROM latest_discharge ld
            INNER JOIN [dbo].[{visit_table}] v WITH (NOLOCK)
                ON v.[{visit_id_col}] = ld.Visit_ID
            {join_discharge_type}
            WHERE
                ld.rn = 1
                AND ISNULL(ld.CancelStatus, 0) = 0
                AND {visit_type_num_expr} = 1
                AND ld.DischargeDate >= ?
                AND ld.DischargeDate < DATEADD(DAY, 1, CAST(? AS DATETIME))
            ORDER BY ld.DischargeDate DESC
        """
        df = pd.read_sql(sql, conn, params=[(unit or "").upper(), from_date, to_date])
        if df is None or df.empty:
            return pd.DataFrame()
        df.columns = [str(c).strip() for c in df.columns]
        if "Unit" not in df.columns:
            df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"Volume discharge KPI fetch failed ({unit}): {e}")
        return pd.DataFrame()
    finally:
        try:
            conn.close()
        except Exception:
            pass


def get_volume_discharge_kpi(
    units: list[str],
    from_date: str,
    to_date: str,
    cured_type_ids: list[int] | None = None,
    lama_type_ids: list[int] | None = None,
    referred_type_ids: list[int] | None = None,
    death_type_ids: list[int] | None = None,
    max_records_per_ward: int = 12,
    include_full_rows: bool = False,
) -> dict:
    """
    Build discharge KPI payload for Volume dashboard:
      - total discharges
      - LAMA% = lama_cases / total_discharges * 100
      - Mortality ratio = death_cases / total_discharges * 100
      - breakdown by discharge type and ward
      - sample patient rows (per ward, latest first)
    """
    def _to_int_set(values, default_values):
        base = values if values is not None else default_values
        out = set()
        for v in base:
            try:
                out.add(int(v))
            except Exception:
                continue
        return out or set(default_values)

    cured_ids = sorted(_to_int_set(cured_type_ids, [1, 2]))
    lama_ids = sorted(_to_int_set(lama_type_ids, [4, 5, 7, 8]))
    referred_ids = sorted(_to_int_set(referred_type_ids, [3]))
    death_ids = sorted(_to_int_set(death_type_ids, [6]))
    payload = _empty_volume_discharge_kpi_payload(from_date, to_date, cured_ids, lama_ids, referred_ids, death_ids)

    if not units:
        return payload

    frames = []
    for unit in units:
        df_u = fetch_volume_discharge_rows(unit, from_date, to_date)
        if df_u is not None and not df_u.empty:
            frames.append(df_u)

    if not frames:
        return payload

    df = pd.concat(frames, ignore_index=True, copy=False)
    if df is None or df.empty:
        return payload

    for col in ["Unit", "Ward", "Department", "CorpType", "Patient", "Regno", "Doctor", "DischargeType"]:
        if col not in df.columns:
            df[col] = ""
        df[col] = df[col].fillna("").astype(str).str.strip()

    df["Department"] = df["Department"].replace("", "Unknown Department")
    df["CorpType"] = df["CorpType"].replace("", "General / Self")

    if "DischargeType_ID" not in df.columns:
        df["DischargeType_ID"] = pd.Series([None] * len(df))
    df["DischargeType_ID"] = pd.to_numeric(df["DischargeType_ID"], errors="coerce")
    df["_VisitDateDT"] = pd.to_datetime(df.get("VisitDate"), errors="coerce")
    df["_DischargeDateDT"] = pd.to_datetime(df.get("DischargeDate"), errors="coerce")
    df["Unit"] = df["Unit"].replace("", "UNKNOWN").str.upper()
    df["Ward"] = df["Ward"].replace("", "Unknown")
    df["DischargeType"] = df["DischargeType"].replace("", "Unknown")

    cured_set = set(cured_ids)
    lama_set = set(lama_ids)
    referred_set = set(referred_ids)
    death_set = set(death_ids)
    type_upper = df["DischargeType"].str.upper()
    cured_keywords = r"(?:\bCURED\b|\bRELIEV(?:ED|E)?\b)"
    lama_keywords = r"(?:LAMA|DOR|LEFT AGAINST|PATIENT REFUSED)"
    referred_keywords = r"(?:REFER|REFERRED|REFFERED|REFERR)"
    df["_is_cured"] = (
        df["DischargeType_ID"].isin(cured_set)
        | type_upper.str.contains(cured_keywords, regex=True, na=False)
    )
    df["_is_lama"] = (
        df["DischargeType_ID"].isin(lama_set)
        | type_upper.str.contains(lama_keywords, regex=True, na=False)
    )
    df["_is_referred"] = (
        df["DischargeType_ID"].isin(referred_set)
        | type_upper.str.contains(referred_keywords, regex=True, na=False)
    )
    df["_is_death"] = (
        df["DischargeType_ID"].isin(death_set)
        | type_upper.str.contains("DEATH", regex=False, na=False)
    )

    def _to_int_or_none(value):
        try:
            if pd.isna(value):
                return None
            return int(value)
        except Exception:
            return None

    def _fmt_date(value):
        try:
            if pd.isna(value):
                return ""
            return pd.Timestamp(value).strftime("%Y-%m-%d %H:%M")
        except Exception:
            return ""

    def _rate(part: int, total: int) -> float:
        if not total:
            return 0.0
        return round((float(part) / float(total)) * 100.0, 2)

    def _metrics(frame: pd.DataFrame) -> dict:
        total = int(len(frame))
        cured_cases = int(frame["_is_cured"].sum()) if total else 0
        lama_cases = int(frame["_is_lama"].sum()) if total else 0
        referred_cases = int(frame["_is_referred"].sum()) if total else 0
        death_cases = int(frame["_is_death"].sum()) if total else 0
        return {
            "total_discharges": total,
            "cured_cases": cured_cases,
            "cured_percent": _rate(cured_cases, total),
            "lama_cases": lama_cases,
            "lama_percent": _rate(lama_cases, total),
            "referred_cases": referred_cases,
            "referred_percent": _rate(referred_cases, total),
            "death_cases": death_cases,
            "mortality_ratio": _rate(death_cases, total),
        }

    def _is_cured_type(type_id, type_name: str) -> bool:
        if type_id is not None and type_id in cured_set:
            return True
        return bool(re.search(cured_keywords, str(type_name or "").upper()))

    def _is_lama_type(type_id, type_name: str) -> bool:
        if type_id is not None and type_id in lama_set:
            return True
        return bool(re.search(lama_keywords, str(type_name or "").upper()))

    def _is_death_type(type_id, type_name: str) -> bool:
        if type_id is not None and type_id in death_set:
            return True
        return "DEATH" in str(type_name or "").upper()

    def _is_referred_type(type_id, type_name: str) -> bool:
        if type_id is not None and type_id in referred_set:
            return True
        return bool(re.search(referred_keywords, str(type_name or "").upper()))

    def _type_breakdown(frame: pd.DataFrame) -> list[dict]:
        if frame is None or frame.empty:
            return []
        grp = (
            frame.groupby(["DischargeType_ID", "DischargeType"], dropna=False)
            .size()
            .reset_index(name="Count")
            .sort_values(["Count", "DischargeType"], ascending=[False, True])
        )
        rows = []
        for _, row in grp.iterrows():
            t_id = _to_int_or_none(row.get("DischargeType_ID"))
            t_name = str(row.get("DischargeType") or "").strip() or "Unknown"
            rows.append({
                "discharge_type_id": t_id,
                "discharge_type": t_name,
                "count": int(row.get("Count") or 0),
                "is_cured": _is_cured_type(t_id, t_name),
                "is_lama": _is_lama_type(t_id, t_name),
                "is_referred": _is_referred_type(t_id, t_name),
                "is_mortality": _is_death_type(t_id, t_name),
            })
        return rows

    def _ward_records(frame: pd.DataFrame) -> list[dict]:
        if frame is None or frame.empty:
            return []
        rows = (
            frame.sort_values("_DischargeDateDT", ascending=False)
            .head(max(1, int(max_records_per_ward)))
            .to_dict(orient="records")
        )
        return [
            {
                "patient": str(r.get("Patient") or ""),
                "regno": str(r.get("Regno") or ""),
                "department": str(r.get("Department") or "Unknown Department").strip() or "Unknown Department",
                "doctor": str(r.get("Doctor") or ""),
                "discharge_type": str(r.get("DischargeType") or "Unknown"),
                "visit_date": _fmt_date(r.get("_VisitDateDT")),
                "discharge_date": _fmt_date(r.get("_DischargeDateDT")),
            }
            for r in rows
        ]

    def _all_records(frame: pd.DataFrame) -> list[dict]:
        if frame is None or frame.empty:
            return []
        rows = (
            frame.sort_values("_DischargeDateDT", ascending=False)
            .to_dict(orient="records")
        )
        out = []
        for row in rows:
            type_id = _to_int_or_none(row.get("DischargeType_ID"))
            type_name = str(row.get("DischargeType") or "").strip() or "Unknown"
            out.append({
                "unit": str(row.get("Unit") or "UNKNOWN").strip().upper() or "UNKNOWN",
                "ward": str(row.get("Ward") or "Unknown").strip() or "Unknown",
                "department": str(row.get("Department") or "Unknown Department").strip() or "Unknown Department",
                "corptype": str(row.get("CorpType") or "General / Self").strip() or "General / Self",
                "patient": str(row.get("Patient") or "").strip(),
                "regno": str(row.get("Regno") or "").strip(),
                "doctor": str(row.get("Doctor") or "").strip(),
                "discharge_type": type_name,
                "discharge_type_id": type_id,
                "visit_date": _fmt_date(row.get("_VisitDateDT")),
                "discharge_date": _fmt_date(row.get("_DischargeDateDT")),
                "is_cured": bool(row.get("_is_cured", False)),
                "is_lama": bool(row.get("_is_lama", False)),
                "is_referred": bool(row.get("_is_referred", False)),
                "is_mortality": bool(row.get("_is_death", False)),
            })
        return out

    unit_blocks = []
    for unit_name, unit_df in df.groupby("Unit", dropna=False):
        unit_df = unit_df.copy()
        unit_metrics = _metrics(unit_df)
        unit_block = {
            "unit": str(unit_name or "UNKNOWN"),
            **unit_metrics,
            "type_breakdown": _type_breakdown(unit_df),
            "ward_breakdown": [],
        }

        ward_blocks = []
        for ward_name, ward_df in unit_df.groupby("Ward", dropna=False):
            ward_df = ward_df.copy()
            w_metrics = _metrics(ward_df)
            records = _ward_records(ward_df)
            ward_blocks.append({
                "ward": str(ward_name or "Unknown"),
                **w_metrics,
                "type_breakdown": _type_breakdown(ward_df),
                "records": records,
                "shown_records": len(records),
                "available_records": int(len(ward_df)),
            })

        ward_blocks.sort(
            key=lambda r: (-int(r.get("total_discharges") or 0), str(r.get("ward") or ""))
        )
        unit_block["ward_breakdown"] = ward_blocks
        unit_blocks.append(unit_block)

    unit_blocks.sort(key=lambda r: str(r.get("unit") or ""))

    overall_metrics = _metrics(df)
    overall_ward_breakdown = []
    for (unit_name, ward_name), ward_df in df.groupby(["Unit", "Ward"], dropna=False):
        ward_df = ward_df.copy()
        w_metrics = _metrics(ward_df)
        overall_ward_breakdown.append({
            "unit": str(unit_name or "UNKNOWN"),
            "ward": str(ward_name or "Unknown"),
            **w_metrics,
            "type_breakdown": _type_breakdown(ward_df),
        })

    overall_ward_breakdown.sort(
        key=lambda r: (
            -int(r.get("total_discharges") or 0),
            str(r.get("unit") or ""),
            str(r.get("ward") or ""),
        )
    )

    payload["overall"] = {
        **overall_metrics,
        "type_breakdown": _type_breakdown(df),
        "ward_breakdown": overall_ward_breakdown,
    }
    payload["units"] = unit_blocks
    if include_full_rows:
        payload["all_records"] = _all_records(df)
    return payload


def make_volume_payload(details_df: pd.DataFrame) -> dict:
    """
    Returns chart/table JSON for the UI:
      - visitwise
      - deptwise
      - doctorwise
      - citywise
      - patienttype
      - patienttype_patsubtype
      - details (table rows)
    """
    def _pairs(series: pd.Series):
        if series is None or series.empty:
            return []
        series = series.dropna()
        return [{"name": str(k), "value": int(v)} for k, v in series.items()]

    visitwise = _pairs(details_df["TypeOfVisit"].value_counts()) if "TypeOfVisit" in details_df else []
    deptwise  = _pairs(details_df["Dept"].value_counts()) if "Dept" in details_df else []
    doctorwise= _pairs(details_df["Consultant"].value_counts()) if "Consultant" in details_df else []
    citywise  = _pairs(details_df["City"].value_counts()) if "City" in details_df else []
    patienttype = _pairs(details_df["PatientType"].value_counts()) if "PatientType" in details_df else []

    # PT -> PatSubType
    pt_tree = []
    if "PatientType" in details_df and "CorpType" in details_df:
        g = (details_df.groupby(["PatientType","CorpType"])
              .size().reset_index(name="count"))
        for pt, grp in g.groupby("PatientType"):
            children = [{"name": str(r["CorpType"]), "value": int(r["count"])} for _, r in grp.iterrows()]
            pt_tree.append({"name": str(pt), "children": children, "value": int(grp["count"].sum())})

    details_json = json.loads(details_df.to_json(orient="records"))

    return {
        "meta": {"total": int(len(details_df))},
        "visitwise": visitwise,
        "deptwise": deptwise,
        "doctorwise": doctorwise,
        "citywise": citywise,
        "patienttype": patienttype,
        "patienttype_patsubtype": pt_tree,
        "details": details_json
    }

# ========= Volume Excel writer =========
# ========= SINGLE-SHEET SUMMARY WRITER (unit-aware, normalized) =========
import io, re
import pandas as pd


def _empty_volume_ipd_census_frame() -> pd.DataFrame:
    return pd.DataFrame(columns=VOLUME_IPD_CENSUS_COL_ORDER)


def _volume_ipd_census_status_rank(value: object) -> int:
    return VOLUME_IPD_CENSUS_STATUS_ORDER.get(str(value or "").strip(), 99)


def _normalize_volume_ipd_census_frame(df: pd.DataFrame | None) -> pd.DataFrame:
    if df is None or df.empty:
        return _empty_volume_ipd_census_frame()

    out = df.copy()
    for col in VOLUME_IPD_CENSUS_COL_ORDER:
        if col not in out.columns:
            out[col] = None

    text_cols = [
        "Unit",
        "Department",
        "Doctor",
        "Patient Status",
        "Reg No",
        "Patient Name",
        "Ward Name",
        "Condition",
        "Patient Type",
    ]
    for col in text_cols:
        out[col] = (
            out[col]
            .fillna("")
            .astype(str)
            .replace({"nan": "", "None": "", "NaT": ""})
            .str.strip()
        )

    out["Unit"] = out["Unit"].replace("", "UNKNOWN").str.upper()
    out["Department"] = out["Department"].replace("", "Unknown Department")
    out["Doctor"] = out["Doctor"].replace("", "Unassigned Doctor")
    out["Ward Name"] = out["Ward Name"].replace("", "Unknown Ward")
    out["Patient Status"] = out["Patient Status"].replace("", "Occupied")
    out["Admission Date"] = pd.to_datetime(out["Admission Date"], errors="coerce")
    out["Discharge Date"] = pd.to_datetime(out["Discharge Date"], errors="coerce")

    out["_unit_sort"] = out["Unit"].str.upper()
    out["_dept_sort"] = out["Department"].str.upper()
    out["_doctor_sort"] = out["Doctor"].str.upper()
    out["_status_sort"] = out["Patient Status"].map(_volume_ipd_census_status_rank)
    out["_ward_sort"] = out["Ward Name"].str.upper()
    out["_patient_sort"] = out["Patient Name"].str.upper()
    out["_reg_sort"] = out["Reg No"].str.upper()

    out = out.sort_values(
        [
            "_unit_sort",
            "_dept_sort",
            "_doctor_sort",
            "_status_sort",
            "_ward_sort",
            "_patient_sort",
            "_reg_sort",
        ],
        ascending=[True, True, True, True, True, True, True],
        kind="stable",
    )
    return out[VOLUME_IPD_CENSUS_COL_ORDER].reset_index(drop=True)


def _volume_census_datetime_display(value) -> str:
    try:
        if value is None or pd.isna(value):
            return ""
        ts = pd.Timestamp(value)
        if getattr(ts, "tzinfo", None) is not None:
            ts = ts.tz_convert(LOCAL_TZ)
        return ts.strftime("%d-%b-%Y %I:%M %p").lstrip("0")
    except Exception:
        return ""


def fetch_volume_ipd_census(unit: str, report_date: str) -> pd.DataFrame:
    """
    Daily IPD census grouped into Occupied, New Admission, and Discharge buckets.
    """
    unit_norm = (unit or "").strip().upper()
    report_date_norm = str(report_date or "").strip()
    if not unit_norm or not report_date_norm:
        return _empty_volume_ipd_census_frame()

    conn = get_sql_connection(unit_norm)
    if not conn:
        print(f"Volume IPD census: could not connect to {unit_norm}")
        return _empty_volume_ipd_census_frame()

    try:
        def _q_ident(name: str) -> str:
            return f"[{str(name).replace(']', ']]')}]"

        def _table_ref(name: str | None) -> str:
            return f"[dbo].{_q_ident(name)}" if name else ""

        def _safe_datetime_expr(alias: str, column_name: str | None) -> str:
            if not alias or not column_name:
                return "CAST(NULL AS DATETIME)"
            raw_expr = f"CONVERT(NVARCHAR(50), {alias}.{_q_ident(column_name)})"
            return (
                "CASE "
                f"WHEN {alias}.{_q_ident(column_name)} IS NULL THEN NULL "
                f"WHEN ISDATE({raw_expr}) = 1 THEN CAST({alias}.{_q_ident(column_name)} AS DATETIME) "
                "ELSE NULL END"
            )

        visit_table = _resolve_table_name(conn, ["Visit", "visit", "Visit_Mst", "VisitMst"])
        if not visit_table:
            return _empty_volume_ipd_census_frame()

        employee_table = _resolve_table_name(conn, ["Employee_Mst", "employee_mst", "EmployeeMst"])
        discharge_table = _resolve_table_name(conn, ["Discharge", "discharge"])
        patient_status_table = _resolve_table_name(conn, ["PatientStatus_Detail", "PatientStatusDetail"])
        status_master_table = _resolve_table_name(conn, ["Status_Master", "status_master", "StatusMst"])

        visit_id_col = _resolve_column(conn, visit_table, ["Visit_ID", "VisitId", "VisitID"])
        visit_date_col = _resolve_column(conn, visit_table, ["VisitDate", "Visit_Date", "AdmissionDate", "Admission_Date", "AdmitDate", "Admit_Date"])
        visit_discharge_col = _resolve_column(conn, visit_table, ["DischargeDate", "Discharge_Date", "DischargeDateTime", "Discharge_DateTime"])
        visit_type_id_col = _resolve_column(conn, visit_table, ["VisitTypeID", "VisitTypeId", "VisitType_ID"])
        visit_type_text_col = _resolve_column(conn, visit_table, ["TypeOfVisit", "VisitType", "Type_Of_Visit"])
        patient_id_col = _resolve_column(conn, visit_table, ["PatientID", "PatientId", "Patient_ID"])
        doctor_id_col = _resolve_column(conn, visit_table, ["DocInCharge", "DocIncharge", "DoctorInCharge", "DoctorIncharge"])
        department_id_col = _resolve_column(conn, visit_table, ["DepartmentID", "DepartmentId", "Department_ID"])
        ward_id_col = _resolve_column(conn, visit_table, ["WardID", "WardId", "Ward_ID"])
        ward_text_col = _resolve_column(conn, visit_table, ["Ward_Name", "WardName", "Ward", "WardDesc", "WardDescription"])
        patient_type_id_col = _resolve_column(conn, visit_table, ["PatientType_ID", "PatientTypeId", "PatientTypeID"])
        patient_subtype_id_col = _resolve_column(conn, visit_table, ["PatientSubType_ID", "PatientSubTypeId", "PatientSubTypeID"])

        if not visit_id_col or not visit_date_col:
            return _empty_volume_ipd_census_frame()

        visit_type_filter = "1 = 1"
        if visit_type_id_col:
            visit_type_filter = (
                f"(CASE WHEN ISNUMERIC(CAST(v.{_q_ident(visit_type_id_col)} AS NVARCHAR(30))) = 1 "
                f"THEN CAST(v.{_q_ident(visit_type_id_col)} AS INT) ELSE NULL END) = 1"
            )
        elif visit_type_text_col:
            visit_type_filter = (
                f"UPPER(LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(80), v.{_q_ident(visit_type_text_col)}), N'')))) LIKE N'%IPD%'"
            )

        join_sql = ""
        department_expr = "N'Unknown Department'"
        if department_id_col:
            department_expr = (
                f"CASE WHEN ISNULL(v.{_q_ident(department_id_col)}, 0) > 0 "
                f"THEN ISNULL(dbo.fn_dept(v.{_q_ident(department_id_col)}), N'') ELSE N'' END"
            )
        elif employee_table and doctor_id_col:
            emp_id_col = _resolve_column(conn, employee_table, ["EmpID", "EmpId", "EmployeeID", "EmployeeId", "ID", "Id"])
            emp_dept_col = _resolve_column(conn, employee_table, ["Department_ID", "DepartmentId", "department_id", "departmentid"])
            if emp_id_col and emp_dept_col:
                join_sql += (
                    f" LEFT JOIN {_table_ref(employee_table)} e WITH (NOLOCK)"
                    f" ON e.{_q_ident(emp_id_col)} = v.{_q_ident(doctor_id_col)}"
                )
                department_expr = (
                    f"CASE WHEN ISNULL(e.{_q_ident(emp_dept_col)}, 0) > 0 "
                    f"THEN ISNULL(dbo.fn_dept(e.{_q_ident(emp_dept_col)}), N'') ELSE N'' END"
                )

        patient_name_expr = (
            f"CASE WHEN ISNULL(v.{_q_ident(patient_id_col)}, 0) > 0 "
            f"THEN ISNULL(dbo.fn_patientfullname(v.{_q_ident(patient_id_col)}), N'') ELSE N'' END"
            if patient_id_col
            else "N''"
        )
        reg_no_expr = (
            f"CASE WHEN ISNULL(v.{_q_ident(patient_id_col)}, 0) > 0 "
            f"THEN ISNULL(dbo.fn_regno(v.{_q_ident(patient_id_col)}), N'') ELSE N'' END"
            if patient_id_col
            else "N''"
        )
        doctor_expr = (
            f"CASE WHEN ISNULL(v.{_q_ident(doctor_id_col)}, 0) > 0 "
            f"THEN ISNULL(dbo.fn_doctorfirstname(v.{_q_ident(doctor_id_col)}), N'') ELSE N'' END"
            if doctor_id_col
            else "N''"
        )
        if ward_id_col:
            ward_expr = (
                f"CASE WHEN ISNULL(v.{_q_ident(ward_id_col)}, 0) > 0 "
                f"THEN ISNULL(dbo.fn_ward_name(v.{_q_ident(ward_id_col)}), N'') "
                f"ELSE ISNULL(LTRIM(RTRIM(CONVERT(NVARCHAR(200), v.{_q_ident(ward_text_col)}))), N'') END"
                if ward_text_col
                else (
                    f"CASE WHEN ISNULL(v.{_q_ident(ward_id_col)}, 0) > 0 "
                    f"THEN ISNULL(dbo.fn_ward_name(v.{_q_ident(ward_id_col)}), N'') ELSE N'' END"
                )
            )
        elif ward_text_col:
            ward_expr = f"ISNULL(LTRIM(RTRIM(CONVERT(NVARCHAR(200), v.{_q_ident(ward_text_col)}))), N'')"
        else:
            ward_expr = "N''"

        if patient_subtype_id_col:
            patient_type_expr = (
                f"CASE WHEN ISNULL(v.{_q_ident(patient_subtype_id_col)}, 0) > 0 "
                f"THEN ISNULL(dbo.fn_patsub_type(v.{_q_ident(patient_subtype_id_col)}), N'') ELSE N'' END"
            )
        elif patient_type_id_col:
            patient_type_expr = (
                f"CASE WHEN ISNULL(v.{_q_ident(patient_type_id_col)}, 0) > 0 "
                f"THEN ISNULL(dbo.fn_pat_type(v.{_q_ident(patient_type_id_col)}), N'') ELSE N'' END"
            )
        else:
            patient_type_expr = "N''"

        discharge_date_expr = _safe_datetime_expr("v", visit_discharge_col)
        if discharge_table:
            dis_visit_id_col = _resolve_column(conn, discharge_table, ["Visit_ID", "VisitId", "VisitID"])
            dis_id_col = _resolve_column(conn, discharge_table, ["Discharge_ID", "DischargeId", "DischargeID"])
            dis_date_col = _resolve_column(conn, discharge_table, ["Discharge_Date", "DischargeDate"])
            dis_admin_date_col = _resolve_column(conn, discharge_table, ["adminDischargeDate", "AdminDischargeDate"])
            dis_cd_date_col = _resolve_column(conn, discharge_table, ["CDdate", "CDDate"])
            dis_updated_col = _resolve_column(conn, discharge_table, ["UpdatedOn", "Updated_ON"])
            dis_inserted_col = _resolve_column(conn, discharge_table, ["InsertedON", "InsertedOn", "Inserted_ON"])
            dis_cancel_col = _resolve_column(conn, discharge_table, ["CancelStatus", "Cancelled", "Canceled"])
            discharge_date_cols = [
                col_name
                for col_name in [dis_admin_date_col, dis_date_col, dis_cd_date_col, dis_updated_col, dis_inserted_col]
                if col_name
            ]
            if dis_visit_id_col and discharge_date_cols:
                safe_date_parts = [_safe_datetime_expr("d", col_name) for col_name in discharge_date_cols]
                discharge_apply_date_expr = f"COALESCE({', '.join(safe_date_parts)})"
                cancel_filter = (
                    f" AND (CASE WHEN ISNUMERIC(CAST(d.{_q_ident(dis_cancel_col)} AS NVARCHAR(30))) = 1 "
                    f"THEN CAST(d.{_q_ident(dis_cancel_col)} AS INT) ELSE 0 END) = 0"
                    if dis_cancel_col
                    else ""
                )
                order_expr = f"d.{_q_ident(dis_id_col)} DESC" if dis_id_col else f"d.{_q_ident(dis_visit_id_col)} DESC"
                join_sql += (
                    " OUTER APPLY ("
                    f" SELECT TOP 1 {discharge_apply_date_expr} AS DischargeDate"
                    f" FROM {_table_ref(discharge_table)} d WITH (NOLOCK)"
                    f" WHERE d.{_q_ident(dis_visit_id_col)} = v.{_q_ident(visit_id_col)}"
                    f"{cancel_filter}"
                    f" ORDER BY {discharge_apply_date_expr} DESC, {order_expr}"
                    " ) dx"
                )
                discharge_date_expr = f"COALESCE(dx.DischargeDate, {discharge_date_expr})"

        condition_expr = "N''"
        if patient_status_table:
            ps_visit_id_col = _resolve_column(conn, patient_status_table, ["Visit_Id", "Visit_ID", "VisitId", "VisitID"])
            ps_status_id_col = _resolve_column(conn, patient_status_table, ["StatusId", "StatusID", "Status_Id"])
            ps_id_col = _resolve_column(conn, patient_status_table, ["PatientStatusDetailId", "PatientStatusId", "PatientStatus_ID", "Id", "ID"])
            ps_date_col = _resolve_column(conn, patient_status_table, ["StatusDate", "UpdatedOn", "Updated_ON", "InsertedOn", "InsertedON", "CreatedOn", "EntryDate"])
            direct_condition_col = _resolve_column(conn, patient_status_table, ["StatusDesc", "Status", "Condition", "ClinicalStatus"])

            status_join_sql = ""
            status_select_expr = None
            if status_master_table and ps_status_id_col:
                status_id_col = _resolve_column(conn, status_master_table, ["StatusId", "StatusID", "Status_Id"])
                status_name_col = _resolve_column(conn, status_master_table, ["StatusDesc", "StatusDescription", "Status", "Name"])
                if status_id_col and status_name_col:
                    status_join_sql = (
                        f" LEFT JOIN {_table_ref(status_master_table)} sm WITH (NOLOCK)"
                        f" ON sm.{_q_ident(status_id_col)} = ps.{_q_ident(ps_status_id_col)}"
                    )
                    status_select_expr = f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), sm.{_q_ident(status_name_col)}), N'')))"
            if status_select_expr is None and direct_condition_col:
                status_select_expr = f"LTRIM(RTRIM(ISNULL(CONVERT(NVARCHAR(200), ps.{_q_ident(direct_condition_col)}), N'')))"

            if ps_visit_id_col and status_select_expr:
                order_parts = []
                if ps_date_col:
                    order_parts.append(f"{_safe_datetime_expr('ps', ps_date_col)} DESC")
                if ps_id_col:
                    order_parts.append(f"ps.{_q_ident(ps_id_col)} DESC")
                if not order_parts and ps_status_id_col:
                    order_parts.append(f"ps.{_q_ident(ps_status_id_col)} DESC")
                order_sql = f" ORDER BY {', '.join(order_parts)}" if order_parts else ""
                join_sql += (
                    " OUTER APPLY ("
                    f" SELECT TOP 1 {status_select_expr} AS Condition"
                    f" FROM {_table_ref(patient_status_table)} ps WITH (NOLOCK)"
                    f"{status_join_sql}"
                    f" WHERE ps.{_q_ident(ps_visit_id_col)} = v.{_q_ident(visit_id_col)}"
                    f"{order_sql}"
                    " ) psx"
                )
                condition_expr = "ISNULL(psx.Condition, N'')"

        admission_date_expr = _safe_datetime_expr("v", visit_date_col)
        sql = f"""
            DECLARE @ReportDate DATE = ?;
            ;WITH census_base AS (
                SELECT
                    ? AS Unit,
                    CAST(v.{_q_ident(visit_id_col)} AS INT) AS Visit_ID,
                    {admission_date_expr} AS AdmissionDate,
                    {discharge_date_expr} AS DischargeDate,
                    ISNULL(NULLIF({department_expr}, N''), N'Unknown Department') AS Department,
                    ISNULL(NULLIF({doctor_expr}, N''), N'Unassigned Doctor') AS Doctor,
                    ISNULL(NULLIF({reg_no_expr}, N''), N'') AS RegNo,
                    ISNULL(NULLIF({patient_name_expr}, N''), N'') AS PatientName,
                    ISNULL(NULLIF({ward_expr}, N''), N'Unknown Ward') AS WardName,
                    ISNULL(NULLIF({condition_expr}, N''), N'') AS Condition,
                    ISNULL(NULLIF({patient_type_expr}, N''), N'') AS PatientType
                FROM {_table_ref(visit_table)} v WITH (NOLOCK)
                {join_sql}
                WHERE {visit_type_filter}
                  AND {admission_date_expr} IS NOT NULL
                  AND {admission_date_expr} < DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
            )
            SELECT
                Unit,
                Department,
                Doctor,
                CASE
                    WHEN DischargeDate IS NOT NULL
                     AND DischargeDate >= CAST(@ReportDate AS DATETIME)
                     AND DischargeDate < DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                        THEN N'Discharge'
                    WHEN AdmissionDate >= CAST(@ReportDate AS DATETIME)
                     AND AdmissionDate < DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                        THEN N'New Admission'
                    ELSE N'Occupied'
                END AS [Patient Status],
                RegNo AS [Reg No],
                PatientName AS [Patient Name],
                WardName AS [Ward Name],
                Condition,
                PatientType AS [Patient Type],
                AdmissionDate AS [Admission Date],
                DischargeDate AS [Discharge Date]
            FROM census_base
            WHERE
                (
                    AdmissionDate < CAST(@ReportDate AS DATETIME)
                    AND (
                        DischargeDate IS NULL
                        OR DischargeDate >= DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                    )
                )
                OR (
                    AdmissionDate >= CAST(@ReportDate AS DATETIME)
                    AND AdmissionDate < DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                    AND (
                        DischargeDate IS NULL
                        OR DischargeDate >= DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                    )
                )
                OR (
                    DischargeDate IS NOT NULL
                    AND DischargeDate >= CAST(@ReportDate AS DATETIME)
                    AND DischargeDate < DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                )
            ORDER BY
                Department,
                Doctor,
                CASE
                    WHEN DischargeDate IS NOT NULL
                     AND DischargeDate >= CAST(@ReportDate AS DATETIME)
                     AND DischargeDate < DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                        THEN 2
                    WHEN AdmissionDate >= CAST(@ReportDate AS DATETIME)
                     AND AdmissionDate < DATEADD(DAY, 1, CAST(@ReportDate AS DATETIME))
                        THEN 1
                    ELSE 0
                END,
                WardName,
                PatientName,
                RegNo
        """
        df = pd.read_sql(sql, conn, params=[report_date_norm, unit_norm])
        if df is None or df.empty:
            return _empty_volume_ipd_census_frame()
        df.columns = [str(c).strip() for c in df.columns]
        return _normalize_volume_ipd_census_frame(df)
    except Exception as e:
        print(f"Volume IPD census fetch failed ({unit_norm}): {e}")
        return _empty_volume_ipd_census_frame()
    finally:
        try:
            conn.close()
        except Exception:
            pass


def get_volume_ipd_census(units: list[str], report_date: str) -> pd.DataFrame:
    if not units or not report_date:
        return _empty_volume_ipd_census_frame()

    frames = []
    for unit in units:
        df_u = fetch_volume_ipd_census(unit, report_date)
        if df_u is not None and not df_u.empty:
            frames.append(df_u)
    if not frames:
        return _empty_volume_ipd_census_frame()
    return _normalize_volume_ipd_census_frame(pd.concat(frames, ignore_index=True, copy=False))

def _norm_text(s: str) -> str:
    t = str(s or "").strip()
    if not t: return ""
    t = re.sub(r"\s+", " ", t)         # collapse spaces
    t = re.sub(r"\s*-\s*", "-", t)     # unify hyphens
    return t.upper()

def _city_display_from_key(k: str) -> str:
    return (k or "").title()

def _norm_patienttype(s: str) -> str:
    k = _norm_text(s)
    k = k.replace("(CASH-CATEGORY)", "(CASH CATEGORY)").replace("(CASHLESS-CATEGORY)", "(CASHLESS CATEGORY)")
    if k == "GENERAL":
        k = "GENERAL (CASH CATEGORY)"
    return k

def _visit_friendly(v: str) -> str:
    m = {
        "HCV": "Health Checkups",
        "DPV": "Diagnostic Visit",
        "IPD": "In Patient Visits",
        "OPD": "Out Patient Visits"
    }
    return m.get(v, v)

def _find_column(df: pd.DataFrame, candidates: list[str]) -> str | None:
    if df is None or df.empty:
        return None
    cols = list(df.columns)
    lower_map = {c.lower(): c for c in cols}
    norm_map = {re.sub(r"[^a-z0-9]+", "", c.lower()): c for c in cols}

    for cand in candidates:
        if cand in cols:
            return cand
        cand_lower = cand.lower()
        if cand_lower in lower_map:
            return lower_map[cand_lower]
        cand_norm = re.sub(r"[^a-z0-9]+", "", cand_lower)
        if cand_norm in norm_map:
            return norm_map[cand_norm]

    for cand in candidates:
        cand_norm = re.sub(r"[^a-z0-9]+", "", cand.lower())
        if not cand_norm:
            continue
        for col_norm, orig in norm_map.items():
            if cand_norm in col_norm:
                return orig
    return None

def _parse_age(value):
    if value is None or (isinstance(value, float) and pd.isna(value)):
        return None
    if isinstance(value, (int, float)) and not pd.isna(value):
        return float(value)
    s = str(value).strip()
    if not s or s.lower() in {"nan", "none", "null"}:
        return None
    m = re.search(r"\d+(\.\d+)?", s)
    if not m:
        return None
    try:
        return float(m.group(0))
    except Exception:
        return None

def _norm_gender(value):
    s = str(value).strip().upper()
    if not s or s in {"NAN", "NONE", "NULL"}:
        return None
    if re.fullmatch(r"\d+(\.\d+)?", s):
        try:
            code = int(float(s))
        except Exception:
            code = None
        if code == 1:
            return "Male"
        if code == 2:
            return "Female"
        if code == 3:
            return "Other"
    if "FEMALE" in s or re.search(r"\bF\b", s) or s.startswith("F"):
        return "Female"
    if "MALE" in s or re.search(r"\bM\b", s) or s.startswith("M"):
        return "Male"
    if "OTHER" in s or "TRANS" in s or re.search(r"\bO\b", s) or s.startswith("O"):
        return "Other"
    return None

def _is_ipd(value) -> bool:
    s = _norm_text(value)
    if not s:
        return False
    return ("IPD" in s) or ("IN PATIENT" in s) or ("INPATIENT" in s)

def _parse_date_range(from_date: str | None, to_date: str | None):
    if not from_date or not to_date:
        return None, None
    start = pd.to_datetime(from_date, errors="coerce")
    end = pd.to_datetime(to_date, errors="coerce")
    if pd.isna(start) or pd.isna(end):
        return None, None
    start = start.normalize()
    end = end.normalize() + pd.Timedelta(days=1) - pd.Timedelta(seconds=1)
    return start, end

def _build_mrd_summary(df: pd.DataFrame, vt_col: str, from_date: str | None, to_date: str | None) -> pd.DataFrame:
    gender_col = _find_column(
        df,
        ["Gender", "Sex", "PatientGender", "GenderName", "SexName", "Sex_Name", "Gender_Name", "Patient_Sex"]
    )
    age_col = _find_column(
        df,
        ["AgeYears", "Age_Years", "AgeYrs", "AgeInYears", "AgeInYrs", "Age (Years)", "PatientAge", "Age"]
    )

    if age_col is None:
        return pd.DataFrame()

    genders = df[gender_col].map(_norm_gender) if gender_col else pd.Series([None] * len(df))
    ages = df[age_col].map(_parse_age)
    if ages.notna().sum() == 0:
        return pd.DataFrame()

    visit_type_id_col = _find_column(
        df,
        ["VisitTypeID", "VisitTypeId", "VisitType_ID", "Visit_Type_ID"]
    )
    if visit_type_id_col:
        vt_id = pd.to_numeric(df[visit_type_id_col], errors="coerce")
        ipd_mask = (vt_id == 1)
    else:
        ipd_mask = df[vt_col].map(_is_ipd).fillna(False)

    visit_dt = pd.to_datetime(df.get("VisitDate"), errors="coerce")
    discharge_dt = pd.to_datetime(df.get("DischargeDate"), errors="coerce")

    start, end = _parse_date_range(from_date, to_date)
    if start is not None and end is not None:
        admission_mask = ipd_mask & (visit_dt >= start) & (visit_dt <= end)
        discharge_mask = ipd_mask & (discharge_dt >= start) & (discharge_dt <= end)
    else:
        admission_mask = ipd_mask & visit_dt.notna()
        discharge_mask = ipd_mask & discharge_dt.notna()

    male_mask = (genders == "Male")
    female_mask = (genders == "Female")
    child_mask = ages.notna() & (ages < 18)
    adult_mask = ages.notna() & (ages >= 18) & (ages < 65)
    ger_mask = ages.notna() & (ages >= 65)

    def _count(mask) -> int:
        return int(mask.sum())

    rows = [
        {"Sl. No.": 1, "Category": "IPD Admission Male Children < 18 Yrs", "Numbers": _count(admission_mask & male_mask & child_mask)},
        {"Sl. No.": 2, "Category": "IPD Admission Male Adults < 65 Yrs", "Numbers": _count(admission_mask & male_mask & adult_mask)},
        {"Sl. No.": 3, "Category": "IPD Admission Female Children < 18 Yrs", "Numbers": _count(admission_mask & female_mask & child_mask)},
        {"Sl. No.": 4, "Category": "IPD Admission Female Adults < 65 Yrs", "Numbers": _count(admission_mask & female_mask & adult_mask)},
        {"Sl. No.": 5, "Category": "IPD Admission Geriatric >= 65 Yrs", "Numbers": _count(admission_mask & ger_mask)},
        {"Sl. No.": 6, "Category": "IPD Discharge Male Children < 18 Yrs", "Numbers": _count(discharge_mask & male_mask & child_mask)},
        {"Sl. No.": 7, "Category": "IPD Discharge Male Adults < 65 Yrs", "Numbers": _count(discharge_mask & male_mask & adult_mask)},
        {"Sl. No.": 8, "Category": "IPD Discharge Female Children < 18 Yrs", "Numbers": _count(discharge_mask & female_mask & child_mask)},
        {"Sl. No.": 9, "Category": "IPD Discharge Female Adults < 65 Yrs", "Numbers": _count(discharge_mask & female_mask & adult_mask)},
        {"Sl. No.": 10, "Category": "IPD Discharge Geriatric >= 65 Yrs", "Numbers": _count(discharge_mask & ger_mask)},
    ]
    return pd.DataFrame(rows)

def _volume_discharge_export_frames(discharge_kpi: dict | None) -> dict[str, pd.DataFrame]:
    def _int_metric(source: dict, key: str) -> int:
        try:
            return int(float(source.get(key) or 0))
        except Exception:
            return 0

    def _pct_metric(source: dict, key: str) -> float:
        try:
            return round(float(source.get(key) or 0), 2)
        except Exception:
            return 0.0

    def _yes_no(value) -> str:
        return "Yes" if bool(value) else "No"

    empty = {
        "overall": pd.DataFrame(),
        "units": pd.DataFrame(),
        "wards": pd.DataFrame(),
        "records": pd.DataFrame(),
    }
    if not isinstance(discharge_kpi, dict):
        return empty

    overall = discharge_kpi.get("overall") or {}
    units = discharge_kpi.get("units") or []
    all_records = discharge_kpi.get("all_records") or []

    overall_frame = pd.DataFrame(
        [
            {
                "Scope": "Selected Scope",
                "Total Discharges": _int_metric(overall, "total_discharges"),
                "Cured Cases": _int_metric(overall, "cured_cases"),
                "Cured Ratio (%)": _pct_metric(overall, "cured_percent"),
                "LAMA Cases": _int_metric(overall, "lama_cases"),
                "LAMA Ratio (%)": _pct_metric(overall, "lama_percent"),
                "Referred Cases": _int_metric(overall, "referred_cases"),
                "Referred Ratio (%)": _pct_metric(overall, "referred_percent"),
                "Mortality Cases": _int_metric(overall, "death_cases"),
                "Mortality Ratio (%)": _pct_metric(overall, "mortality_ratio"),
            }
        ]
    )

    unit_rows = []
    ward_rows = []
    for unit_block in units:
        if not isinstance(unit_block, dict):
            continue
        unit_rows.append(
            {
                "Unit": str(unit_block.get("unit") or "UNKNOWN").strip().upper() or "UNKNOWN",
                "Total Discharges": _int_metric(unit_block, "total_discharges"),
                "Cured Cases": _int_metric(unit_block, "cured_cases"),
                "Cured Ratio (%)": _pct_metric(unit_block, "cured_percent"),
                "LAMA Cases": _int_metric(unit_block, "lama_cases"),
                "LAMA Ratio (%)": _pct_metric(unit_block, "lama_percent"),
                "Referred Cases": _int_metric(unit_block, "referred_cases"),
                "Referred Ratio (%)": _pct_metric(unit_block, "referred_percent"),
                "Mortality Cases": _int_metric(unit_block, "death_cases"),
                "Mortality Ratio (%)": _pct_metric(unit_block, "mortality_ratio"),
            }
        )

        for ward_block in (unit_block.get("ward_breakdown") or []):
            if not isinstance(ward_block, dict):
                continue
            ward_rows.append(
                {
                    "Unit": str(unit_block.get("unit") or "UNKNOWN").strip().upper() or "UNKNOWN",
                    "Ward": str(ward_block.get("ward") or "Unknown").strip() or "Unknown",
                    "Total Discharges": _int_metric(ward_block, "total_discharges"),
                    "Cured Cases": _int_metric(ward_block, "cured_cases"),
                    "Cured Ratio (%)": _pct_metric(ward_block, "cured_percent"),
                    "LAMA Cases": _int_metric(ward_block, "lama_cases"),
                    "LAMA Ratio (%)": _pct_metric(ward_block, "lama_percent"),
                    "Referred Cases": _int_metric(ward_block, "referred_cases"),
                    "Referred Ratio (%)": _pct_metric(ward_block, "referred_percent"),
                    "Mortality Cases": _int_metric(ward_block, "death_cases"),
                    "Mortality Ratio (%)": _pct_metric(ward_block, "mortality_ratio"),
                }
            )

    unit_frame = pd.DataFrame(unit_rows)
    ward_frame = pd.DataFrame(ward_rows)
    if not ward_frame.empty:
        ward_frame = ward_frame.sort_values(["Unit", "Total Discharges", "Ward"], ascending=[True, False, True])

    record_rows = []
    for row in all_records:
        if not isinstance(row, dict):
            continue
        record_rows.append(
            {
                "Unit": str(row.get("unit") or "UNKNOWN").strip().upper() or "UNKNOWN",
                "Ward": str(row.get("ward") or "Unknown").strip() or "Unknown",
                "Department": str(row.get("department") or row.get("dept") or "").strip(),
                "CorpType": str(row.get("corptype") or row.get("corp_type") or row.get("CorpType") or "General / Self").strip() or "General / Self",
                "Reg No": str(row.get("regno") or "").strip(),
                "Patient Name": str(row.get("patient") or "").strip(),
                "Doctor Incharge": str(row.get("doctor") or "").strip(),
                "Discharge Type": str(row.get("discharge_type") or "Unknown").strip() or "Unknown",
                "Admission Date": str(row.get("visit_date") or "").strip(),
                "Discharge Date": str(row.get("discharge_date") or "").strip(),
                "Cured": _yes_no(row.get("is_cured")),
                "LAMA": _yes_no(row.get("is_lama")),
                "Referred": _yes_no(row.get("is_referred")),
                "Mortality": _yes_no(row.get("is_mortality")),
            }
        )
    record_frame = pd.DataFrame(record_rows)

    return {
        "overall": overall_frame,
        "units": unit_frame,
        "wards": ward_frame,
        "records": record_frame,
    }


def _make_volume_ipd_census_sheet_name(raw_name: object, used_names: set[str]) -> str:
    base = str(raw_name or "").strip()
    if not base:
        base = "Unknown Department"
    base = re.sub(r"^\s*Department\s+of\s+", "", base, flags=re.IGNORECASE).strip() or base
    base = re.sub(r"[\[\]:*?/\\]+", " ", base)
    base = re.sub(r"\s+", " ", base).strip() or "Department"
    safe = base[:31].rstrip() or "Department"
    candidate = safe
    suffix = 2
    while candidate.upper() in used_names:
        suffix_text = f" {suffix}"
        allowed = max(1, 31 - len(suffix_text))
        candidate = f"{safe[:allowed].rstrip()}{suffix_text}"
        suffix += 1
    used_names.add(candidate.upper())
    return candidate


