CONTRACTED_RATE_ALLOWED_UNITS = {"AHL", "ACI", "BALLIA"}


def _unit_supports_ivitem_contracted_rate(unit: str) -> bool:
    return str(unit or "").strip().upper() in CONTRACTED_RATE_ALLOWED_UNITS


def _ensure_iv_item_contracted_rate_column_conn(conn, manage_transaction: bool = True, unit: str | None = None) -> bool:
    """
    Ensure IVItem has Contracted_Rate for scoped purchase units.
    """
    if not conn:
        return False
    if _schema_ready_contains(IVITEM_CONTRACTED_RATE_READY_UNITS, unit):
        return True
    table_name = _resolve_table_name(conn, ["IVItem", "IvItem", "IVITEM"])
    if not table_name:
        return False
    if _resolve_column(conn, table_name, ["Contracted_Rate", "ContractedRate"]):
        _mark_schema_ready(IVITEM_CONTRACTED_RATE_READY_UNITS, unit)
        return True
    try:
        cur = conn.cursor()
        cur.execute(f"ALTER TABLE dbo.{table_name} ADD Contracted_Rate DECIMAL(18, 2) NULL")
        if manage_transaction:
            conn.commit()
        _mark_schema_ready(IVITEM_CONTRACTED_RATE_READY_UNITS, unit)
        return True
    except Exception:
        if manage_transaction:
            try:
                conn.rollback()
            except Exception:
                pass
        ready = bool(_resolve_column(conn, table_name, ["Contracted_Rate", "ContractedRate"]))
        if ready:
            _mark_schema_ready(IVITEM_CONTRACTED_RATE_READY_UNITS, unit)
        return ready


