def _fetch_master_table(conn, table_candidates, id_candidates, name_candidates, code_candidates=None):
    table_name = _resolve_table_name(conn, table_candidates)
    if not table_name:
        return pd.DataFrame()
    id_col = _resolve_column(conn, table_name, id_candidates)
    name_col = _resolve_column(conn, table_name, name_candidates)
    code_col = _resolve_column(conn, table_name, code_candidates or [])
    if not id_col or not name_col:
        return pd.DataFrame()
    select_cols = [f"{id_col} AS ID", f"{name_col} AS Name"]
    if code_col:
        select_cols.append(f"{code_col} AS Code")
    sql = f"SELECT {', '.join(select_cols)} FROM dbo.{table_name}"
    return pd.read_sql(sql, conn)


def _normalize_unit_master_name(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def _sanitize_unit_code(value: str) -> str:
    raw = str(value or "").strip().upper()
    if not raw:
        return ""
    return re.sub(r"[^A-Z0-9]", "", raw)


def _generate_unit_code_seed(unit_name: str) -> str:
    tokens = re.findall(r"[A-Z0-9]+", str(unit_name or "").upper())
    if not tokens:
        return "UNIT"
    if len(tokens) == 1:
        token = tokens[0]
        if len(token) >= 4:
            return token[:4]
        return token
    acronym = "".join(tok[0] for tok in tokens if tok)
    if len(acronym) >= 2:
        return acronym[:6]
    return (tokens[0] or "UNIT")[:4]


def _normalize_catalog_master_name(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def _normalize_catalog_master_code(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip()).upper()


def _catalog_master_flag_is_inactive(raw_val) -> bool:
    text = str(raw_val or "").strip().lower()
    if text in {"true", "1", "y", "yes"}:
        return True
    try:
        return int(raw_val or 0) != 0
    except Exception:
        return False


def _build_catalog_master_insert_columns(
    conn,
    table_name: str,
    *,
    id_col: str,
    name_col: str,
    name_value: str,
    code_col: str | None = None,
    code_value: str = "",
    parent_col: str | None = None,
    parent_value: int = 0,
    inactive_col: str | None = None,
    include_fallback_meta: bool = False,
    explicit_id: int = 0,
):
    cols = []
    vals = []
    if explicit_id > 0:
        cols.append(id_col)
        vals.append(int(explicit_id))
    if code_col:
        cols.append(code_col)
        vals.append(code_value)
    cols.append(name_col)
    vals.append(name_value)
    if parent_col:
        cols.append(parent_col)
        vals.append(int(parent_value or 0))
    if inactive_col:
        cols.append(inactive_col)
        vals.append(0)
    if include_fallback_meta:
        table_cols = _get_table_columns(conn, table_name)
        now_stamp = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        fallback_defaults = {
            "updatedby": 0,
            "updatedon": now_stamp,
            "updatedmacname": "RID",
            "updatedmacid": "",
            "updatedipaddress": "",
            "insertedbyuserid": 0,
            "insertedon": now_stamp,
            "insertedmacname": "RID",
            "insertedmacid": "",
            "insertedipaddress": "",
        }
        current_cols = {str(c).strip().lower() for c in cols}
        for col_lc, col_default in fallback_defaults.items():
            if col_lc not in table_cols or col_lc in current_cols:
                continue
            real_col = None
            for candidate in table_cols:
                if candidate.lower() == col_lc:
                    real_col = candidate
                    break
            if not real_col:
                continue
            cols.append(real_col)
            vals.append(col_default)
    return cols, vals


def _upsert_catalog_master_record(
    unit: str,
    *,
    table_name: str,
    record_label: str,
    name_value: str,
    code_value: str | None = None,
    record_id: int | None = None,
    parent_col: str | None = None,
    parent_value: int | None = None,
    inactive_col: str | None = None,
    reactivate: bool = True,
):
    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Could not connect to {unit}"}

    name_clean = _normalize_catalog_master_name(name_value)
    if not name_clean:
        return {"error": f"{record_label} name is required.", "code": "required"}
    code_clean = _normalize_catalog_master_code(code_value or "")
    cursor = None
    lock_resource = None
    try:
        target_id = int(record_id or 0)
    except Exception:
        target_id = 0
    try:
        target_parent_id = int(parent_value or 0)
    except Exception:
        target_parent_id = 0

    if parent_col and target_parent_id <= 0:
        return {"error": f"{record_label} parent selection is required.", "code": "required_parent"}

    try:
        object_row = pd.read_sql(
            "SELECT OBJECT_ID(?) AS ObjectId",
            conn,
            params=[f"dbo.{table_name}"],
        )
        object_id = 0
        if object_row is not None and not object_row.empty:
            object_id = int(object_row.iloc[0].get("ObjectId") or 0)
        if object_id <= 0:
            return {"error": f"{table_name} table not found.", "code": "table_not_found"}

        id_col = "ID"
        name_col = "Name"
        code_col = "Code"
        cursor = conn.cursor()
        id_match_expr = f"LTRIM(RTRIM(CAST([{id_col}] AS NVARCHAR(50))))"
        id_is_identity = False
        id_has_default = False
        try:
            cursor.execute(
                """
                SELECT
                    CAST(c.is_identity AS INT) AS IsIdentity,
                    CASE WHEN c.default_object_id = 0 THEN 0 ELSE 1 END AS HasDefault
                FROM sys.columns AS c
                WHERE c.object_id = OBJECT_ID(?) AND c.name = ?
                """,
                (f"dbo.{table_name}", str(id_col)),
            )
            id_meta_row = cursor.fetchone()
            if id_meta_row:
                id_is_identity = bool(id_meta_row[0])
                id_has_default = bool(id_meta_row[1])
        except Exception:
            id_is_identity = False
            id_has_default = False

        code_limits = _fetch_text_column_limits(conn, table_name, [code_col]) if code_col else {}
        code_max_len = None
        if code_limits:
            code_max_len = code_limits.get(str(code_col).strip().lower())
        if code_max_len and code_clean:
            code_clean = code_clean[:code_max_len]

        def _row_to_dict(row_obj):
            if not row_obj:
                return None
            idx = 0
            out = {
                "id": row_obj[idx] if len(row_obj) > idx else None,
                "name": row_obj[idx + 1] if len(row_obj) > (idx + 1) else None,
            }
            idx = 2
            out["code"] = row_obj[idx] if len(row_obj) > idx else ""
            idx += 1
            out["inactive_flag"] = row_obj[idx] if inactive_col and len(row_obj) > idx else 0
            idx += 1 if inactive_col else 0
            out["parent_id"] = row_obj[idx] if parent_col and len(row_obj) > idx else 0
            return out

        def _find_duplicate(exclude_id: int = 0):
            where_parts = ["UPPER(LTRIM(RTRIM(CAST([Name] AS NVARCHAR(200))))) = UPPER(LTRIM(RTRIM(?)))"]
            params = [name_clean]
            if code_clean:
                where_parts.append("UPPER(LTRIM(RTRIM(CAST([Code] AS NVARCHAR(200))))) = UPPER(LTRIM(RTRIM(?)))")
                params.append(code_clean)
            sql = f"""
                SELECT TOP 1
                    [{id_col}] AS ID,
                    [{name_col}] AS Name,
                    [{code_col}] AS Code
                    {f", [{inactive_col}] AS InactiveFlag" if inactive_col else ""}
                    {f", [{parent_col}] AS ParentID" if parent_col else ""}
                FROM dbo.[{table_name}]
                WHERE ({' OR '.join(where_parts)})
            """
            if parent_col:
                sql += f" AND CAST([{parent_col}] AS INT) = ?"
                params.append(target_parent_id)
            if exclude_id > 0:
                sql += f" AND {id_match_expr} <> ?"
                params.append(str(exclude_id))
            sql += """
                ORDER BY
                    CASE
                        WHEN UPPER(LTRIM(RTRIM(CAST([Name] AS NVARCHAR(200))))) = UPPER(LTRIM(RTRIM(?))) THEN 0
                        ELSE 1
                    END,
                    [ID]
            """
            params.append(name_clean)
            cursor.execute(sql, params)
            return _row_to_dict(cursor.fetchone())

        if target_id > 0:
            cursor.execute(
                f"""
                SELECT TOP 1
                    [{id_col}] AS ID,
                    [{name_col}] AS Name,
                    [{code_col}] AS Code
                    {f", [{inactive_col}] AS InactiveFlag" if inactive_col else ""}
                    {f", [{parent_col}] AS ParentID" if parent_col else ""}
                FROM dbo.[{table_name}]
                WHERE {id_match_expr} = ?
                """,
                (str(target_id),),
            )
            existing = _row_to_dict(cursor.fetchone())
            if not existing:
                return {"error": f"{record_label} not found.", "code": "not_found"}

            dup = _find_duplicate(exclude_id=target_id)
            if dup:
                return {
                    "error": f"{record_label} already exists.",
                    "code": "duplicate",
                    "existing_id": int(dup.get("id") or 0) or None,
                }

            final_code = code_clean if code_clean else _normalize_catalog_master_code(existing.get("code"))
            set_parts = [f"[{name_col}] = ?"]
            set_vals = [name_clean]
            set_parts.append(f"[{code_col}] = ?")
            set_vals.append(final_code)
            if parent_col:
                set_parts.append(f"[{parent_col}] = ?")
                set_vals.append(target_parent_id)
            if inactive_col and reactivate:
                set_parts.append(f"[{inactive_col}] = ?")
                set_vals.append(0)
            cursor.execute(
                f"""
                UPDATE dbo.[{table_name}]
                SET {', '.join(set_parts)}
                WHERE {id_match_expr} = ?
                """,
                [*set_vals, str(target_id)],
            )
            conn.commit()
            return {
                "status": "success",
                "mode": "update",
                "record_id": target_id,
                "name": name_clean,
                "code": final_code,
                "parent_id": target_parent_id if parent_col else None,
            }

        dup = _find_duplicate(exclude_id=0)
        if dup:
            dup_id = int(dup.get("id") or 0) if dup.get("id") is not None else 0
            if inactive_col and reactivate and _catalog_master_flag_is_inactive(dup.get("inactive_flag")) and dup_id > 0:
                final_code = code_clean if code_clean else _normalize_catalog_master_code(dup.get("code"))
                set_parts = [
                    f"[{name_col}] = ?",
                    f"[{code_col}] = ?",
                    f"[{inactive_col}] = ?",
                ]
                set_vals = [name_clean, final_code, 0]
                if parent_col:
                    set_parts.append(f"[{parent_col}] = ?")
                    set_vals.append(target_parent_id)
                cursor.execute(
                    f"""
                    UPDATE dbo.[{table_name}]
                    SET {', '.join(set_parts)}
                    WHERE {id_match_expr} = ?
                    """,
                    [*set_vals, str(dup_id)],
                )
                conn.commit()
                return {
                    "status": "success",
                    "mode": "reactivate",
                    "record_id": dup_id,
                    "name": name_clean,
                    "code": final_code,
                    "parent_id": target_parent_id if parent_col else None,
                }
            return {
                "error": f"{record_label} already exists.",
                "code": "duplicate",
                "existing_id": dup_id or None,
            }

        generated_id = 0
        if not id_is_identity and not id_has_default:
            lock_resource = f"{table_name.upper()}_{(unit or '').strip().upper()}_ID"
            lock_result = _get_app_lock(cursor, lock_resource, 10000)
            if lock_result.get("error"):
                return lock_result
            cursor.execute(
                f"SELECT ISNULL(MAX(CAST([{id_col}] AS INT)), 0) + 1 FROM dbo.[{table_name}] WITH (UPDLOCK, HOLDLOCK)"
            )
            next_row = cursor.fetchone()
            generated_id = int(next_row[0]) if next_row and next_row[0] is not None else 1

        insert_cols, insert_vals = _build_catalog_master_insert_columns(
            conn,
            table_name,
            id_col=id_col,
            name_col=name_col,
            name_value=name_clean,
            code_col=code_col,
            code_value=code_clean,
            parent_col=parent_col,
            parent_value=target_parent_id,
            inactive_col=inactive_col,
            include_fallback_meta=False,
            explicit_id=generated_id,
        )
        quoted_cols = ", ".join(f"[{c}]" for c in insert_cols)
        placeholders = ", ".join("?" for _ in insert_vals)
        insert_sql = f"INSERT INTO dbo.[{table_name}] ({quoted_cols}) VALUES ({placeholders})"
        try:
            cursor.execute(insert_sql, insert_vals)
        except Exception:
            try:
                conn.rollback()
            except Exception:
                pass
            insert_cols, insert_vals = _build_catalog_master_insert_columns(
                conn,
                table_name,
                id_col=id_col,
                name_col=name_col,
                name_value=name_clean,
                code_col=code_col,
                code_value=code_clean,
                parent_col=parent_col,
                parent_value=target_parent_id,
                inactive_col=inactive_col,
                include_fallback_meta=True,
                explicit_id=generated_id,
            )
            quoted_cols = ", ".join(f"[{c}]" for c in insert_cols)
            placeholders = ", ".join("?" for _ in insert_vals)
            insert_sql = f"INSERT INTO dbo.[{table_name}] ({quoted_cols}) VALUES ({placeholders})"
            cursor.execute(insert_sql, insert_vals)

        new_id = int(generated_id or 0)
        if new_id <= 0 and id_is_identity:
            cursor.execute("SELECT CAST(SCOPE_IDENTITY() AS INT)")
            row = cursor.fetchone()
            new_id = int(row[0]) if row and row[0] is not None else 0
        if new_id <= 0:
            lookup_params = [name_clean]
            lookup_sql = f"""
                SELECT TOP 1 [{id_col}]
                FROM dbo.[{table_name}]
                WHERE (
                    UPPER(LTRIM(RTRIM(CAST([{name_col}] AS NVARCHAR(200))))) = UPPER(LTRIM(RTRIM(?)))
            """
            if code_clean:
                lookup_sql += " OR UPPER(LTRIM(RTRIM(CAST([Code] AS NVARCHAR(200))))) = UPPER(LTRIM(RTRIM(?)))"
                lookup_params.append(code_clean)
            lookup_sql += ")"
            if parent_col:
                lookup_sql += f" AND CAST([{parent_col}] AS INT) = ?"
                lookup_params.append(target_parent_id)
            lookup_sql += f" ORDER BY CAST([{id_col}] AS INT) DESC"
            cursor.execute(lookup_sql, lookup_params)
            row = cursor.fetchone()
            new_id = int(row[0]) if row and row[0] is not None else 0
        conn.commit()
        return {
            "status": "success",
            "mode": "add",
            "record_id": new_id,
            "name": name_clean,
            "code": code_clean,
            "parent_id": target_parent_id if parent_col else None,
        }
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        _release_app_lock(cursor, lock_resource)
        try:
            conn.close()
        except Exception:
            pass


def _set_catalog_master_active(
    unit: str,
    *,
    table_name: str,
    record_label: str,
    record_id: int,
    inactive_col: str,
    is_active: bool,
):
    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Could not connect to {unit}"}
    try:
        try:
            record_id_val = int(record_id or 0)
        except Exception:
            record_id_val = 0
        if record_id_val <= 0:
            return {"error": f"Invalid {record_label.lower()} id.", "code": "invalid_id"}

        cursor = conn.cursor()
        id_match_expr = "LTRIM(RTRIM(CAST([ID] AS NVARCHAR(50))))"
        cursor.execute(
            f"SELECT TOP 1 [ID] FROM dbo.[{table_name}] WHERE {id_match_expr} = ?",
            (str(record_id_val),),
        )
        if cursor.fetchone() is None:
            return {"error": f"{record_label} not found.", "code": "not_found"}

        cursor.execute(
            f"""
            UPDATE dbo.[{table_name}]
            SET [{inactive_col}] = ?
            WHERE {id_match_expr} = ?
            """,
            (0 if is_active else 1, str(record_id_val)),
        )
        conn.commit()
        return {"status": "success", "record_id": record_id_val, "is_active": 1 if is_active else 0}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_purchase_unit_master(unit: str, include_inactive: bool = False):
    """
    Fetch IV unit master rows used in Purchase and Item Master.
    Returns columns: ID, Code, Name, Deactive (best effort).
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for unit master")
        return None
    try:
        table_name = _resolve_table_name(conn, ["IVUnit", "IvUnit", "IVUnit_Mst", "Unit_Mst"])
        if not table_name:
            return pd.DataFrame(columns=["ID", "Code", "Name", "Deactive"])

        id_col = _resolve_column(conn, table_name, ["ID", "Id", "UnitID", "UnitId"])
        name_col = _resolve_column(conn, table_name, ["Name", "UnitName", "Unit"])
        code_col = _resolve_column(conn, table_name, ["Code", "UnitCode"])
        deactive_col = _resolve_column(conn, table_name, ["Deactive", "DeActive", "IsDeactive", "IsInactive", "Inactive"])
        if not id_col or not name_col:
            return pd.DataFrame(columns=["ID", "Code", "Name", "Deactive"])

        select_cols = [
            f"[{id_col}] AS ID",
            f"[{name_col}] AS Name",
            (f"[{code_col}] AS Code" if code_col else "CAST('' AS NVARCHAR(50)) AS Code"),
            (f"[{deactive_col}] AS Deactive" if deactive_col else "CAST(0 AS INT) AS Deactive"),
        ]
        sql = f"SELECT {', '.join(select_cols)} FROM dbo.[{table_name}]"
        if deactive_col and not include_inactive:
            sql += (
                f" WHERE CASE "
                f"WHEN [{deactive_col}] IS NULL THEN 0 "
                f"WHEN UPPER(LTRIM(RTRIM(CAST([{deactive_col}] AS NVARCHAR(10))))) IN ('1','TRUE','YES','Y') THEN 1 "
                f"ELSE 0 END = 0"
            )
        sql += f" ORDER BY [{name_col}]"

        df = pd.read_sql(sql, conn)
        if df is None or df.empty:
            return df
        df.columns = [str(c).strip() for c in df.columns]
        if "Name" in df.columns:
            df["Name"] = (
                df["Name"]
                .fillna("")
                .astype(str)
                .str.strip()
                .replace({"nan": "", "None": ""})
            )
        if "Code" in df.columns:
            df["Code"] = (
                df["Code"]
                .fillna("")
                .astype(str)
                .str.strip()
                .replace({"nan": "", "None": ""})
            )
        if "Deactive" not in df.columns:
            df["Deactive"] = 0
        return df
    except Exception as e:
        print(f"Error fetching unit master ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def upsert_purchase_unit_master(
    unit: str,
    unit_name: str,
    unit_code: str | None = None,
    unit_id: int | None = None,
    reactivate: bool = True,
):
    """
    Add or update IVUnit row by id/name/code.
    Returns: status/mode/unit_id/name/code or error.
    """
    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Could not connect to {unit}"}

    unit_name_clean = _normalize_unit_master_name(unit_name)
    if not unit_name_clean:
        return {"error": "Unit name is required.", "code": "required"}
    unit_code_clean = _sanitize_unit_code(unit_code or "")
    cursor = None
    lock_resource = None

    try:
        try:
            unit_id_val = int(unit_id or 0)
        except Exception:
            unit_id_val = 0

        table_name = _resolve_table_name(conn, ["IVUnit", "IvUnit", "IVUnit_Mst", "Unit_Mst"])
        if not table_name:
            return {"error": "IVUnit table not found.", "code": "table_not_found"}

        id_col = _resolve_column(conn, table_name, ["ID", "Id", "UnitID", "UnitId"])
        name_col = _resolve_column(conn, table_name, ["Name", "UnitName", "Unit"])
        code_col = _resolve_column(conn, table_name, ["Code", "UnitCode"])
        deactive_col = _resolve_column(conn, table_name, ["Deactive", "DeActive", "IsDeactive", "IsInactive", "Inactive"])
        if not id_col or not name_col:
            return {"error": "IVUnit columns are missing.", "code": "column_not_found"}

        cursor = conn.cursor()
        id_match_expr = f"LTRIM(RTRIM(CAST([{id_col}] AS NVARCHAR(50))))"
        id_is_identity = False
        id_has_default = False
        try:
            cursor.execute(
                """
                SELECT
                    CAST(c.is_identity AS INT) AS IsIdentity,
                    CASE WHEN c.default_object_id = 0 THEN 0 ELSE 1 END AS HasDefault
                FROM sys.columns AS c
                WHERE c.object_id = OBJECT_ID(?) AND c.name = ?
                """,
                (f"dbo.{table_name}", str(id_col)),
            )
            id_meta_row = cursor.fetchone()
            if id_meta_row:
                id_is_identity = bool(id_meta_row[0])
                id_has_default = bool(id_meta_row[1])
        except Exception:
            id_is_identity = False
            id_has_default = False

        def _row_to_dict(row_obj, has_code: bool, has_deactive: bool):
            if not row_obj:
                return None
            idx = 0
            out = {
                "id": row_obj[idx] if len(row_obj) > idx else None,
                "name": row_obj[idx + 1] if len(row_obj) > (idx + 1) else None,
            }
            idx = 2
            out["code"] = row_obj[idx] if has_code and len(row_obj) > idx else ""
            idx = idx + (1 if has_code else 0)
            out["deactive"] = row_obj[idx] if has_deactive and len(row_obj) > idx else 0
            return out

        def _is_deactive(raw_val) -> bool:
            text = str(raw_val or "").strip().lower()
            if text in {"true", "1", "y", "yes"}:
                return True
            try:
                return int(raw_val or 0) != 0
            except Exception:
                return False

        def _find_duplicate(exclude_id: int = 0):
            where_parts = [f"UPPER(LTRIM(RTRIM([{name_col}]))) = UPPER(LTRIM(RTRIM(?)))"]
            params = [unit_name_clean]
            if code_col and unit_code_clean:
                where_parts.append(f"UPPER(LTRIM(RTRIM([{code_col}]))) = UPPER(LTRIM(RTRIM(?)))")
                params.append(unit_code_clean)
            where_sql = " OR ".join(where_parts)
            sql = f"""
                SELECT TOP 1
                    [{id_col}] AS ID,
                    [{name_col}] AS Name
                    {f", [{code_col}] AS Code" if code_col else ""}
                    {f", [{deactive_col}] AS Deactive" if deactive_col else ""}
                FROM dbo.[{table_name}]
                WHERE ({where_sql})
            """
            if exclude_id > 0:
                sql += f" AND {id_match_expr} <> ?"
                params.append(str(exclude_id))
            sql += f"""
                ORDER BY
                    CASE WHEN UPPER(LTRIM(RTRIM([{name_col}]))) = UPPER(LTRIM(RTRIM(?))) THEN 0 ELSE 1 END,
                    [{id_col}]
            """
            params.append(unit_name_clean)
            cursor.execute(sql, params)
            return _row_to_dict(cursor.fetchone(), bool(code_col), bool(deactive_col))

        def _code_exists(code_value: str, exclude_id: int = 0) -> bool:
            if not code_col:
                return False
            code_text = _sanitize_unit_code(code_value)
            if not code_text:
                return False
            sql = f"""
                SELECT TOP 1 1
                FROM dbo.[{table_name}]
                WHERE UPPER(LTRIM(RTRIM([{code_col}]))) = UPPER(LTRIM(RTRIM(?)))
            """
            params = [code_text]
            if exclude_id > 0:
                sql += f" AND {id_match_expr} <> ?"
                params.append(str(exclude_id))
            cursor.execute(sql, params)
            return cursor.fetchone() is not None

        def _next_available_code(seed_name: str, preferred_code: str, exclude_id: int = 0) -> str:
            if not code_col:
                return ""
            max_len = None
            limits = _fetch_text_column_limits(conn, table_name, [code_col])
            if limits:
                max_len = limits.get(str(code_col).strip().lower())
            base = _sanitize_unit_code(preferred_code) or _sanitize_unit_code(_generate_unit_code_seed(seed_name)) or "UNIT"
            if max_len:
                base = base[:max_len] or "U"
            if not _code_exists(base, exclude_id=exclude_id):
                return base
            for idx in range(1, 1000):
                suffix = str(idx)
                if max_len:
                    root = base[:max(1, max_len - len(suffix))]
                else:
                    root = base
                candidate = f"{root}{suffix}"
                if not _code_exists(candidate, exclude_id=exclude_id):
                    return candidate
            return base

        def _build_insert_columns(final_code: str, include_fallback_meta: bool = False, explicit_unit_id: int = 0):
            cols = []
            vals = []
            if explicit_unit_id > 0:
                cols.append(id_col)
                vals.append(int(explicit_unit_id))
            if code_col:
                cols.append(code_col)
                vals.append(final_code)
            cols.append(name_col)
            vals.append(unit_name_clean)
            if deactive_col:
                cols.append(deactive_col)
                vals.append(0)
            if include_fallback_meta:
                table_cols = _get_table_columns(conn, table_name)
                now_stamp = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
                fallback_defaults = {
                    "updatedby": 0,
                    "updatedon": now_stamp,
                    "updatedmacname": "RID",
                    "updatedmacid": "",
                    "updatedipaddress": "",
                    "insertedbyuserid": 0,
                    "insertedon": now_stamp,
                    "insertedmacname": "RID",
                    "insertedmacid": "",
                    "insertedipaddress": "",
                }
                current_cols = {str(c).strip().lower() for c in cols}
                for col_lc, col_default in fallback_defaults.items():
                    if col_lc in table_cols and col_lc not in current_cols:
                        real_col = _resolve_column(conn, table_name, [col_lc]) or _resolve_column(conn, table_name, [col_lc.upper()]) or _resolve_column(conn, table_name, [col_lc.title()])
                        if not real_col:
                            for candidate in table_cols:
                                if candidate.lower() == col_lc:
                                    real_col = candidate
                                    break
                        if not real_col:
                            continue
                        cols.append(real_col)
                        vals.append(col_default)
            return cols, vals

        if unit_id_val > 0:
            cursor.execute(
                f"""
                SELECT TOP 1
                    [{id_col}] AS ID,
                    [{name_col}] AS Name
                    {f", [{code_col}] AS Code" if code_col else ""}
                    {f", [{deactive_col}] AS Deactive" if deactive_col else ""}
                FROM dbo.[{table_name}]
                WHERE {id_match_expr} = ?
                """,
                (str(unit_id_val),),
            )
            existing = _row_to_dict(cursor.fetchone(), bool(code_col), bool(deactive_col))
            if not existing:
                return {"error": "Unit not found.", "code": "not_found"}

            dup = _find_duplicate(exclude_id=unit_id_val)
            if dup:
                return {
                    "error": "Unit already exists.",
                    "code": "duplicate",
                    "existing_id": int(dup.get("id") or 0) or None,
                }

            final_code = ""
            if code_col:
                existing_code = _sanitize_unit_code(existing.get("code"))
                final_code = _sanitize_unit_code(unit_code_clean) or existing_code
                final_code = _next_available_code(unit_name_clean, final_code, exclude_id=unit_id_val)

            set_parts = [f"[{name_col}] = ?"]
            set_vals = [unit_name_clean]
            if code_col:
                set_parts.append(f"[{code_col}] = ?")
                set_vals.append(final_code)
            if deactive_col and reactivate:
                set_parts.append(f"[{deactive_col}] = ?")
                set_vals.append(0)
            set_sql = ", ".join(set_parts)
            set_vals.append(unit_id_val)
            cursor.execute(
                f"""
                UPDATE dbo.[{table_name}]
                SET {set_sql}
                WHERE {id_match_expr} = ?
                """,
                [*set_vals[:-1], str(set_vals[-1])],
            )
            conn.commit()
            return {
                "status": "success",
                "mode": "update",
                "unit_id": unit_id_val,
                "name": unit_name_clean,
                "code": final_code if code_col else "",
            }

        dup = _find_duplicate(exclude_id=0)
        if dup:
            dup_id = int(dup.get("id") or 0) if dup.get("id") is not None else 0
            dup_code = _sanitize_unit_code(dup.get("code"))
            if deactive_col and reactivate and _is_deactive(dup.get("deactive")) and dup_id > 0:
                set_parts = []
                set_vals = []
                if code_col:
                    final_code = _sanitize_unit_code(unit_code_clean) or dup_code or _next_available_code(unit_name_clean, "", exclude_id=dup_id)
                    if final_code:
                        set_parts.append(f"[{code_col}] = ?")
                        set_vals.append(final_code)
                set_parts.append(f"[{name_col}] = ?")
                set_vals.append(unit_name_clean)
                set_parts.append(f"[{deactive_col}] = ?")
                set_vals.append(0)
                set_vals.append(dup_id)
                cursor.execute(
                    f"""
                    UPDATE dbo.[{table_name}]
                    SET {', '.join(set_parts)}
                    WHERE {id_match_expr} = ?
                    """,
                    [*set_vals[:-1], str(set_vals[-1])],
                )
                conn.commit()
                return {
                    "status": "success",
                    "mode": "reactivate",
                    "unit_id": dup_id,
                    "name": unit_name_clean,
                    "code": final_code if code_col else "",
                }
            return {
                "error": "Unit already exists.",
                "code": "duplicate",
                "existing_id": dup_id or None,
            }

        final_code = ""
        if code_col:
            final_code = _next_available_code(unit_name_clean, unit_code_clean)
        generated_unit_id = 0
        if not id_is_identity and not id_has_default:
            lock_resource = f"IVUNIT_ID_{(unit or '').strip().upper()}"
            lock_result = _get_app_lock(cursor, lock_resource, 10000)
            if lock_result.get("error"):
                return lock_result
            cursor.execute(
                f"SELECT ISNULL(MAX(CAST([{id_col}] AS INT)), 0) + 1 FROM dbo.[{table_name}] WITH (UPDLOCK, HOLDLOCK)"
            )
            next_row = cursor.fetchone()
            generated_unit_id = int(next_row[0]) if next_row and next_row[0] is not None else 1

        insert_cols, insert_vals = _build_insert_columns(
            final_code,
            include_fallback_meta=False,
            explicit_unit_id=generated_unit_id,
        )
        quoted_cols = ", ".join(f"[{c}]" for c in insert_cols)
        placeholders = ", ".join("?" for _ in insert_vals)
        insert_sql = f"INSERT INTO dbo.[{table_name}] ({quoted_cols}) VALUES ({placeholders})"
        try:
            cursor.execute(insert_sql, insert_vals)
        except Exception:
            try:
                conn.rollback()
            except Exception:
                pass
            insert_cols, insert_vals = _build_insert_columns(
                final_code,
                include_fallback_meta=True,
                explicit_unit_id=generated_unit_id,
            )
            quoted_cols = ", ".join(f"[{c}]" for c in insert_cols)
            placeholders = ", ".join("?" for _ in insert_vals)
            insert_sql = f"INSERT INTO dbo.[{table_name}] ({quoted_cols}) VALUES ({placeholders})"
            cursor.execute(insert_sql, insert_vals)

        new_id = int(generated_unit_id or 0)
        if new_id <= 0 and id_is_identity:
            cursor.execute("SELECT CAST(SCOPE_IDENTITY() AS INT)")
            row = cursor.fetchone()
            new_id = int(row[0]) if row and row[0] is not None else 0
        if new_id <= 0:
            lookup_params = [unit_name_clean]
            lookup_sql = f"""
                SELECT TOP 1 [{id_col}]
                FROM dbo.[{table_name}]
                WHERE UPPER(LTRIM(RTRIM([{name_col}]))) = UPPER(LTRIM(RTRIM(?)))
            """
            if code_col and final_code:
                lookup_sql += f" OR UPPER(LTRIM(RTRIM([{code_col}]))) = UPPER(LTRIM(RTRIM(?)))"
                lookup_params.append(final_code)
            lookup_sql += f" ORDER BY CAST([{id_col}] AS INT) DESC"
            cursor.execute(lookup_sql, lookup_params)
            row = cursor.fetchone()
            new_id = int(row[0]) if row and row[0] is not None else 0
        conn.commit()
        return {
            "status": "success",
            "mode": "add",
            "unit_id": new_id,
            "name": unit_name_clean,
            "code": final_code if code_col else "",
        }
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        _release_app_lock(cursor, lock_resource)
        try:
            conn.close()
        except Exception:
            pass


def set_purchase_unit_master_active(unit: str, unit_id: int, is_active: bool):
    """
    Toggle unit active state through IVUnit.Deactive (best effort).
    """
    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Could not connect to {unit}"}
    try:
        try:
            unit_id_val = int(unit_id or 0)
        except Exception:
            unit_id_val = 0
        if unit_id_val <= 0:
            return {"error": "Invalid unit id.", "code": "invalid_id"}

        table_name = _resolve_table_name(conn, ["IVUnit", "IvUnit", "IVUnit_Mst", "Unit_Mst"])
        if not table_name:
            return {"error": "IVUnit table not found.", "code": "table_not_found"}
        id_col = _resolve_column(conn, table_name, ["ID", "Id", "UnitID", "UnitId"])
        deactive_col = _resolve_column(conn, table_name, ["Deactive", "DeActive", "IsDeactive", "IsInactive", "Inactive"])
        if not id_col:
            return {"error": "Unit id column not found.", "code": "column_not_found"}
        if not deactive_col:
            return {"error": "Deactive column not found in IVUnit.", "code": "unsupported"}

        cursor = conn.cursor()
        id_match_expr = f"LTRIM(RTRIM(CAST([{id_col}] AS NVARCHAR(50))))"
        cursor.execute(
            f"SELECT TOP 1 [{id_col}] FROM dbo.[{table_name}] WHERE {id_match_expr} = ?",
            (str(unit_id_val),),
        )
        if cursor.fetchone() is None:
            return {"error": "Unit not found.", "code": "not_found"}

        cursor.execute(
            f"""
            UPDATE dbo.[{table_name}]
            SET [{deactive_col}] = ?
            WHERE {id_match_expr} = ?
            """,
            (0 if is_active else 1, str(unit_id_val)),
        )
        conn.commit()
        return {"status": "success", "unit_id": unit_id_val, "is_active": 1 if is_active else 0}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_item_units(unit: str, include_inactive: bool = False):
    """
    Fetch IV unit master for item master entry.
    """
    df = fetch_purchase_unit_master(unit, include_inactive=include_inactive)
    if df is None or df.empty:
        return df
    df = df.copy()
    if "Deactive" in df.columns:
        df = df.drop(columns=["Deactive"])
    return df


