def fetch_item_type_master(unit: str, include_inactive: bool = False):
    """
    Fetch item types from dbo.IVItemType.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for item type master")
        return None
    try:
        sql = """
            SELECT
                t.[ID] AS ID,
                LTRIM(RTRIM(COALESCE(CAST(t.[Code] AS NVARCHAR(50)), ''))) AS Code,
                LTRIM(RTRIM(COALESCE(CAST(t.[Name] AS NVARCHAR(150)), ''))) AS Name,
                CASE WHEN ISNULL(t.[Deactive], 0) = 0 THEN 1 ELSE 0 END AS IsActive
            FROM dbo.[IVItemType] AS t
        """
        params = []
        if not include_inactive:
            sql += " WHERE ISNULL(t.[Deactive], 0) = 0"
        sql += " ORDER BY t.[Name], t.[ID]"
        df = pd.read_sql(sql, conn, params=params)
        if df is None or df.empty:
            return df
        df.columns = [str(c).strip() for c in df.columns]
        return df
    except Exception as e:
        print(f"Error fetching item type master ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_item_group_master(unit: str, include_inactive: bool = False, type_id: int | None = None):
    """
    Fetch item groups from dbo.IvGroup with their linked item type.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for item group master")
        return None
    try:
        sql = """
            SELECT
                g.[ID] AS ID,
                LTRIM(RTRIM(COALESCE(CAST(g.[Code] AS NVARCHAR(50)), ''))) AS Code,
                LTRIM(RTRIM(COALESCE(CAST(g.[Name] AS NVARCHAR(150)), ''))) AS Name,
                CAST(ISNULL(g.[ParentID], 0) AS INT) AS TypeID,
                LTRIM(RTRIM(COALESCE(CAST(t.[Name] AS NVARCHAR(150)), ''))) AS TypeName,
                LTRIM(RTRIM(COALESCE(CAST(t.[Code] AS NVARCHAR(50)), ''))) AS TypeCode,
                CASE WHEN ISNULL(g.[Deactive], 0) = 0 THEN 1 ELSE 0 END AS IsActive
            FROM dbo.[IvGroup] AS g
            LEFT JOIN dbo.[IVItemType] AS t
              ON t.[ID] = g.[ParentID]
        """
        where_parts = []
        params = []
        if not include_inactive:
            where_parts.append("ISNULL(g.[Deactive], 0) = 0")
        try:
            type_id_val = int(type_id or 0)
        except Exception:
            type_id_val = 0
        if type_id_val > 0:
            where_parts.append("CAST(ISNULL(g.[ParentID], 0) AS INT) = ?")
            params.append(type_id_val)
        if where_parts:
            sql += " WHERE " + " AND ".join(where_parts)
        sql += " ORDER BY g.[Name], g.[ID]"
        df = pd.read_sql(sql, conn, params=params)
        if df is None or df.empty:
            return df
        df.columns = [str(c).strip() for c in df.columns]
        return df
    except Exception as e:
        print(f"Error fetching item group master ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_item_subgroup_master(
    unit: str,
    include_inactive: bool = False,
    group_id: int | None = None,
    type_id: int | None = None,
):
    """
    Fetch item subgroups from dbo.IVSubGroup with group/type hierarchy.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for item subgroup master")
        return None
    try:
        sql = """
            SELECT
                sg.[ID] AS ID,
                LTRIM(RTRIM(COALESCE(CAST(sg.[Code] AS NVARCHAR(50)), ''))) AS Code,
                LTRIM(RTRIM(COALESCE(CAST(sg.[Name] AS NVARCHAR(150)), ''))) AS Name,
                CAST(ISNULL(sg.[GroupID], 0) AS INT) AS GroupID,
                LTRIM(RTRIM(COALESCE(CAST(g.[Name] AS NVARCHAR(150)), ''))) AS GroupName,
                CAST(ISNULL(g.[ParentID], 0) AS INT) AS TypeID,
                LTRIM(RTRIM(COALESCE(CAST(t.[Name] AS NVARCHAR(150)), ''))) AS TypeName,
                CASE WHEN ISNULL(sg.[Active], 0) = 0 THEN 1 ELSE 0 END AS IsActive
            FROM dbo.[IVSubGroup] AS sg
            LEFT JOIN dbo.[IvGroup] AS g
              ON g.[ID] = sg.[GroupID]
            LEFT JOIN dbo.[IVItemType] AS t
              ON t.[ID] = g.[ParentID]
        """
        where_parts = []
        params = []
        if not include_inactive:
            where_parts.append("ISNULL(sg.[Active], 0) = 0")
        try:
            group_id_val = int(group_id or 0)
        except Exception:
            group_id_val = 0
        if group_id_val > 0:
            where_parts.append("CAST(ISNULL(sg.[GroupID], 0) AS INT) = ?")
            params.append(group_id_val)
        try:
            type_id_val = int(type_id or 0)
        except Exception:
            type_id_val = 0
        if type_id_val > 0:
            where_parts.append("CAST(ISNULL(g.[ParentID], 0) AS INT) = ?")
            params.append(type_id_val)
        if where_parts:
            sql += " WHERE " + " AND ".join(where_parts)
        sql += " ORDER BY sg.[Name], sg.[ID]"
        df = pd.read_sql(sql, conn, params=params)
        if df is None or df.empty:
            return df
        df.columns = [str(c).strip() for c in df.columns]
        return df
    except Exception as e:
        print(f"Error fetching item subgroup master ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


