def _po_detail_insert_tracking(cursor, table_name: str, po_id_col: str, id_col: str, po_id: int) -> int:
    if not cursor or not table_name or po_id <= 0:
        return 0
    cursor.execute(
        f"SELECT ISNULL(MAX([{id_col}]), 0) FROM dbo.[{table_name}] WHERE [{po_id_col}] = ?",
        (po_id,),
    )
    row = cursor.fetchone()
    return int(row[0] or 0) if row else 0


def _persist_inserted_po_detail_unit_name(
    cursor,
    *,
    table_name: str,
    po_id_col: str,
    id_col: str,
    unit_name_col: str,
    po_id: int,
    previous_max_id: int,
    unit_name,
) -> None:
    if not cursor or not table_name or not unit_name_col or po_id <= 0:
        return
    cursor.execute(
        f"""
        SELECT TOP 1 [{id_col}]
        FROM dbo.[{table_name}]
        WHERE [{po_id_col}] = ? AND [{id_col}] > ?
        ORDER BY [{id_col}] ASC
        """,
        (po_id, previous_max_id),
    )
    inserted_row = cursor.fetchone()
    detail_id = int(inserted_row[0] or 0) if inserted_row else 0
    if detail_id <= 0:
        raise RuntimeError("Unable to locate inserted PO detail row for UnitName persistence.")
    cursor.execute(
        f"UPDATE dbo.[{table_name}] SET [{unit_name_col}] = ? WHERE [{id_col}] = ?",
        (str(unit_name or "").strip() or None, detail_id),
    )


def add_iv_po_dtl(unit: str, params: dict, conn=None, manage_transaction: bool | None = None):
    """
    Executes dbo.usp_addIVPoDtl for a single item row.
    """
    own_conn = conn is None
    db_conn = conn or get_sql_connection(unit)
    if not db_conn:
        return {"error": f"Could not connect to {unit}"}
    if manage_transaction is None:
        manage_transaction = own_conn
    try:
        cursor = db_conn.cursor()
        table_name = _resolve_table_name(db_conn, ["IVPoDtl", "IvPoDtl", "IVPO_DTL", "IV_Po_Dtl"]) or "IVPoDtl"
        po_id_col = _resolve_column(db_conn, table_name, ["POID", "PoID", "PoId", "Poid"]) or "POID"
        id_col = _resolve_column(db_conn, table_name, ["ID", "Id"]) or "ID"
        unit_name_col = None
        po_id = int(params.get("pPoid") or 0)
        previous_max_id = 0
        if "UnitName" in params:
            if not _ensure_iv_po_dtl_unit_name_column_conn(db_conn):
                return {"error": "PO detail UnitName column not available"}
            unit_name_col = _resolve_column(db_conn, table_name, ["UnitName", "Unit", "Unit_Name"]) or "UnitName"
            previous_max_id = _po_detail_insert_tracking(cursor, table_name, po_id_col, id_col, po_id)
        cursor.execute(_PO_DTL_INSERT_SQL, _po_dtl_insert_values(params))
        if unit_name_col:
            _persist_inserted_po_detail_unit_name(
                cursor,
                table_name=table_name,
                po_id_col=po_id_col,
                id_col=id_col,
                unit_name_col=unit_name_col,
                po_id=po_id,
                previous_max_id=previous_max_id,
                unit_name=params.get("UnitName"),
            )
        if manage_transaction:
            db_conn.commit()
        return {"success": True}
    except Exception as e:
        if manage_transaction:
            try:
                db_conn.rollback()
            except Exception:
                pass
        return {"error": str(e)}
    finally:
        if own_conn:
            try:
                db_conn.close()
            except Exception:
                pass


def add_iv_po_dtl_many(unit: str, params_list: list[dict], conn=None, manage_transaction: bool | None = None):
    """
    Executes dbo.usp_addIVPoDtl for multiple rows using a single DB connection.
    Returns per-row errors while continuing remaining rows.
    """
    rows = list(params_list or [])
    if not rows:
        return {"success": True, "success_count": 0, "errors": []}
    own_conn = conn is None
    db_conn = conn or get_sql_connection(unit)
    if not db_conn:
        return {"error": f"Could not connect to {unit}"}
    if manage_transaction is None:
        manage_transaction = own_conn
    try:
        cursor = db_conn.cursor()
        table_name = _resolve_table_name(db_conn, ["IVPoDtl", "IvPoDtl", "IVPO_DTL", "IV_Po_Dtl"]) or "IVPoDtl"
        po_id_col = _resolve_column(db_conn, table_name, ["POID", "PoID", "PoId", "Poid"]) or "POID"
        id_col = _resolve_column(db_conn, table_name, ["ID", "Id"]) or "ID"
        unit_name_col = None
        if any("UnitName" in (params or {}) for params in rows):
            if not _ensure_iv_po_dtl_unit_name_column_conn(db_conn):
                return {"error": "PO detail UnitName column not available"}
            unit_name_col = _resolve_column(db_conn, table_name, ["UnitName", "Unit", "Unit_Name"]) or "UnitName"
        success_count = 0
        errors = []
        for idx, params in enumerate(rows, start=1):
            try:
                po_id = int(params.get("pPoid") or 0)
                previous_max_id = 0
                if unit_name_col:
                    previous_max_id = _po_detail_insert_tracking(cursor, table_name, po_id_col, id_col, po_id)
                cursor.execute(_PO_DTL_INSERT_SQL, _po_dtl_insert_values(params))
                if unit_name_col:
                    _persist_inserted_po_detail_unit_name(
                        cursor,
                        table_name=table_name,
                        po_id_col=po_id_col,
                        id_col=id_col,
                        unit_name_col=unit_name_col,
                        po_id=po_id,
                        previous_max_id=previous_max_id,
                        unit_name=params.get("UnitName"),
                    )
                if manage_transaction:
                    db_conn.commit()
                success_count += 1
            except Exception as e:
                row_no = params.get("_row_no") or idx
                item_name = str(params.get("_item_name") or "").strip()
                label = f"Row {row_no}"
                if item_name:
                    label += f" ({item_name})"
                if manage_transaction:
                    try:
                        db_conn.rollback()
                    except Exception:
                        pass
                    errors.append(f"{label}: {e}")
                    continue
                return {"error": f"{label}: {e}", "errors": [f"{label}: {e}"], "success_count": success_count}
        return {"success": True, "success_count": success_count, "errors": errors}
    except Exception as e:
        if manage_transaction:
            try:
                db_conn.rollback()
            except Exception:
                pass
        return {"error": str(e)}
    finally:
        if own_conn:
            try:
                db_conn.close()
            except Exception:
                pass


def add_work_order_dtl_many(unit: str, params_list: list[dict]):
    """
    Inserts multiple Work Order detail rows into HID_WorkOrder_Detail.
    Returns per-row errors while continuing remaining rows.
    """
    rows = list(params_list or [])
    if not rows:
        return {"success": True, "success_count": 0, "errors": []}
    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Could not connect to {unit}"}
    try:
        if not _ensure_work_order_detail_table_conn(conn):
            return {"error": "HID_WorkOrder_Detail table not available"}
        cursor = conn.cursor()
        success_count = 0
        errors = []
        sql = """
            INSERT INTO dbo.HID_WorkOrder_Detail (
                WOID,
                [LineNo],
                ItemName,
                UnitName,
                Qty,
                Rate,
                DiscountPct,
                TaxableAmount,
                CGSTPct,
                SGSTPct,
                IGSTPct,
                CGSTAmt,
                SGSTAmt,
                IGSTAmt,
                ForAmount,
                NetAmount,
                LineNotes,
                CreatedBy,
                UpdatedBy
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """
        for idx, params in enumerate(rows, start=1):
            try:
                cursor.execute(
                    sql,
                    int(params.get("WOID") or 0),
                    int(params.get("LineNo") or idx),
                    str(params.get("ItemName") or "").strip(),
                    str(params.get("UnitName") or "").strip() or None,
                    float(params.get("Qty") or 0),
                    float(params.get("Rate") or 0),
                    float(params.get("DiscountPct") or 0),
                    float(params.get("TaxableAmount") or 0),
                    float(params.get("CGSTPct") or 0),
                    float(params.get("SGSTPct") or 0),
                    float(params.get("IGSTPct") or 0),
                    float(params.get("CGSTAmt") or 0),
                    float(params.get("SGSTAmt") or 0),
                    float(params.get("IGSTAmt") or 0),
                    float(params.get("ForAmount") or 0),
                    float(params.get("NetAmount") or 0),
                    str(params.get("LineNotes") or "").strip() or None,
                    str(params.get("CreatedBy") or "").strip() or None,
                    str(params.get("UpdatedBy") or "").strip() or None,
                )
                try:
                    conn.commit()
                except Exception:
                    pass
                success_count += 1
            except Exception as e:
                try:
                    conn.rollback()
                except Exception:
                    pass
                row_no = params.get("_row_no") or idx
                item_name = str(params.get("ItemName") or "").strip()
                label = f"Row {row_no}"
                if item_name:
                    label += f" ({item_name})"
                errors.append(f"{label}: {e}")
        return {"success": True, "success_count": success_count, "errors": errors}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Pharmacy: GSS Issue/Return Register =====================
def fetch_pharmacy_gss_issue_register(unit: str, from_date: str, to_date: str):
    """
    Fetch GSS Issue/Return register data for the given date range.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Aƒ?§A?A-AA¨A_A, Pharmacy GSS register: could not connect to {unit}")
        return None
    try:
        sql = "SET NOCOUNT ON; EXEC dbo.usp_rptpatissueregisterGSS @fromdate=?, @todate=?"
        df = pd.read_sql(sql, conn, params=[from_date, to_date])
        if df is None or df.empty:
            return df
        df.columns = [c.strip() for c in df.columns]
        df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"Aƒ?§A?' Pharmacy GSS register fetch failed for {unit}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def fetch_pharmacy_ward_medicine_tat(unit: str, from_date: str, to_date: str):
    """
    Fetch ward medicine TAT lines (indent -> issue -> ward acknowledgement).
    Date filter is applied on indent date.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Pharmacy ward TAT: could not connect to {unit}")
        return None
    try:
        indent_table = _resolve_table_name(conn, ["IVPatientIndentMst", "IvPatientIndentMst"])
        issue_mst_table = _resolve_table_name(conn, ["IvPatientIssueMst", "IVPatientIssueMst"])
        issue_dtl_table = _resolve_table_name(conn, ["IvPatientIssueDtl", "IVPatientIssueDtl"])
        item_table = _resolve_table_name(conn, ["IVItem", "IvItem"])
        user_table = _resolve_table_name(conn, ["User_Mst", "user_mst", "UserMst"])

        if not indent_table or not issue_mst_table or not issue_dtl_table:
            print(
                "Pharmacy ward TAT: missing required tables "
                f"(indent={indent_table}, issue_mst={issue_mst_table}, issue_dtl={issue_dtl_table})"
            )
            return pd.DataFrame()

        indent_id_col = _resolve_column(conn, indent_table, ["IndentID", "IndentId", "Indent_ID", "ID", "Id"])
        indent_no_col = _resolve_column(conn, indent_table, ["IndentNo", "Indent_No", "IndentNumber"])
        indent_date_col = _resolve_column(conn, indent_table, ["IndentDate", "Indent_Date", "InsertedON", "InsertedOn"])
        indent_patient_col = _resolve_column(conn, indent_table, ["PatientID", "PatientId", "Patient_ID"])
        indent_visit_col = _resolve_column(conn, indent_table, ["VisitID", "VisitId", "Visit_ID"])
        indent_cancel_col = _resolve_column(conn, indent_table, ["CancelStatus", "Canceled", "Cancelled", "IsCancel", "IsCanceled"])

        issue_id_col = _resolve_column(conn, issue_mst_table, ["IssueId", "IssueID", "Issue_Id", "ID", "Id"])
        issue_no_col = _resolve_column(conn, issue_mst_table, ["IssueNo", "Issue_No"])
        issue_date_col = _resolve_column(conn, issue_mst_table, ["IssueDate", "Issue_Date", "InsertedON", "InsertedOn"])
        issue_indent_col = _resolve_column(conn, issue_mst_table, ["IndentId", "IndentID", "Indent_ID"])
        issue_patient_col = _resolve_column(conn, issue_mst_table, ["PatientID", "PatientId", "Patient_ID"])
        issue_visit_col = _resolve_column(conn, issue_mst_table, ["VisitID", "VisitId", "Visit_ID"])
        issue_ack_status_col = _resolve_column(conn, issue_mst_table, ["acknowStatus", "AcknowStatus", "AcknowledgementStatus", "Accepted"])

        issue_dtl_id_col = _resolve_column(conn, issue_dtl_table, ["IssueDtlId", "IssueDtlID", "IssueDtl_Id", "ID", "Id"])
        issue_dtl_issue_col = _resolve_column(conn, issue_dtl_table, ["Issueid", "IssueId", "IssueID", "Issue_ID"])
        issue_dtl_item_col = _resolve_column(conn, issue_dtl_table, ["ItemId", "ItemID", "Item_Id"])
        issue_dtl_qty_col = _resolve_column(conn, issue_dtl_table, ["Issueqty", "IssueQty", "Qty", "Quantity"])
        issue_dtl_ack_by_col = _resolve_column(conn, issue_dtl_table, ["acknowBy", "AcknowBy", "AcknowledgedBy"])
        issue_dtl_ack_dt_col = _resolve_column(conn, issue_dtl_table, ["acknowDatetime", "AcknowDatetime", "AcknowledgedOn", "AcknowledgedDate"])

        if not indent_id_col or not indent_date_col or not issue_id_col or not issue_indent_col or not issue_dtl_issue_col:
            print(
                "Pharmacy ward TAT: missing required columns "
                f"(indent_id={indent_id_col}, indent_date={indent_date_col}, issue_id={issue_id_col}, "
                f"issue_indent={issue_indent_col}, issue_dtl_issue={issue_dtl_issue_col})"
            )
            return pd.DataFrame()

        patient_expr_parts = []
        if issue_patient_col:
            patient_expr_parts.append(f"im.{issue_patient_col}")
        if indent_patient_col:
            patient_expr_parts.append(f"ind.{indent_patient_col}")
        if not patient_expr_parts:
            patient_expr = "NULL"
        elif len(patient_expr_parts) == 1:
            patient_expr = patient_expr_parts[0]
        else:
            patient_expr = f"COALESCE({', '.join(patient_expr_parts)})"

        visit_expr_parts = []
        if issue_visit_col:
            visit_expr_parts.append(f"im.{issue_visit_col}")
        if indent_visit_col:
            visit_expr_parts.append(f"ind.{indent_visit_col}")
        if not visit_expr_parts:
            visit_expr = "NULL"
        elif len(visit_expr_parts) == 1:
            visit_expr = visit_expr_parts[0]
        else:
            visit_expr = f"COALESCE({', '.join(visit_expr_parts)})"

        patient_name_expr = (
            f"CASE WHEN {patient_expr} IS NULL THEN NULL ELSE dbo.fn_patientfullname({patient_expr}) END AS PatientName"
            if patient_expr != "NULL"
            else "NULL AS PatientName"
        )
        reg_no_expr = (
            f"CASE WHEN {patient_expr} IS NULL THEN NULL ELSE dbo.fn_regno({patient_expr}) END AS RegistrationNo"
            if patient_expr != "NULL"
            else "NULL AS RegistrationNo"
        )

        issue_no_expr = (
            f"im.{issue_no_col} AS IssueNo"
            if issue_no_col
            else f"CAST(im.{issue_id_col} AS VARCHAR(50)) AS IssueNo"
        )
        indent_no_expr = (
            f"ind.{indent_no_col} AS IndentNo"
            if indent_no_col
            else f"CAST(ind.{indent_id_col} AS VARCHAR(50)) AS IndentNo"
        )
        issue_date_expr = f"im.{issue_date_col} AS IssueDate" if issue_date_col else "NULL AS IssueDate"
        issue_dtl_id_expr = f"dtl.{issue_dtl_id_col} AS IssueDtlId" if issue_dtl_id_col else "NULL AS IssueDtlId"
        issue_qty_expr = f"dtl.{issue_dtl_qty_col} AS IssueQty" if issue_dtl_qty_col else "NULL AS IssueQty"
        ack_by_expr = f"dtl.{issue_dtl_ack_by_col} AS AcknowBy" if issue_dtl_ack_by_col else "NULL AS AcknowBy"
        ack_dt_expr = f"dtl.{issue_dtl_ack_dt_col} AS AcknowDatetime" if issue_dtl_ack_dt_col else "NULL AS AcknowDatetime"
        ack_status_expr = f"im.{issue_ack_status_col} AS AcknowStatus" if issue_ack_status_col else "NULL AS AcknowStatus"

        tat_indent_issue_expr = (
            f"CASE WHEN ind.{indent_date_col} IS NOT NULL AND im.{issue_date_col} IS NOT NULL "
            f"THEN DATEDIFF(MINUTE, ind.{indent_date_col}, im.{issue_date_col}) END AS TatIndentToIssueMinutes"
            if issue_date_col
            else "NULL AS TatIndentToIssueMinutes"
        )
        tat_issue_ack_expr = (
            f"CASE WHEN im.{issue_date_col} IS NOT NULL AND dtl.{issue_dtl_ack_dt_col} IS NOT NULL "
            f"THEN DATEDIFF(MINUTE, im.{issue_date_col}, dtl.{issue_dtl_ack_dt_col}) END AS TatIssueToAckMinutes"
            if issue_date_col and issue_dtl_ack_dt_col
            else "NULL AS TatIssueToAckMinutes"
        )
        tat_indent_ack_expr = (
            f"CASE WHEN ind.{indent_date_col} IS NOT NULL AND dtl.{issue_dtl_ack_dt_col} IS NOT NULL "
            f"THEN DATEDIFF(MINUTE, ind.{indent_date_col}, dtl.{issue_dtl_ack_dt_col}) END AS TatIndentToAckMinutes"
            if issue_dtl_ack_dt_col
            else "NULL AS TatIndentToAckMinutes"
        )

        item_join_sql = ""
        item_id_expr = f"dtl.{issue_dtl_item_col} AS ItemId" if issue_dtl_item_col else "NULL AS ItemId"
        item_code_expr = "NULL AS ItemCode"
        item_name_expr = "NULL AS ItemName"
        if item_table and issue_dtl_item_col:
            item_id_col = _resolve_column(conn, item_table, ["ID", "Id", "ItemID", "ItemId"])
            item_code_col = _resolve_column(conn, item_table, ["Code", "ItemCode"])
            item_name_col = _resolve_column(conn, item_table, ["Name", "ItemName", "DescriptiveName"])
            if item_id_col:
                item_join_sql = f"LEFT JOIN dbo.{item_table} it WITH (NOLOCK) ON it.{item_id_col} = dtl.{issue_dtl_item_col}"
                if item_code_col:
                    item_code_expr = f"it.{item_code_col} AS ItemCode"
                if item_name_col:
                    item_name_expr = f"it.{item_name_col} AS ItemName"

        user_join_sql = ""
        if user_table and issue_dtl_ack_by_col:
            user_id_col = _resolve_column(conn, user_table, ["UserID", "UserId", "ID", "Id"])
            user_name_col = _resolve_column(conn, user_table, ["UserName", "User_Name", "Name", "LoginName"])
            if user_id_col and user_name_col:
                user_join_sql = (
                    f"LEFT JOIN dbo.{user_table} um WITH (NOLOCK) "
                    f"ON LTRIM(RTRIM(CAST(um.{user_id_col} AS NVARCHAR(50)))) = "
                    f"LTRIM(RTRIM(CAST(dtl.{issue_dtl_ack_by_col} AS NVARCHAR(50))))"
                )
                ack_by_expr = (
                    f"COALESCE(NULLIF(LTRIM(RTRIM(CAST(um.{user_name_col} AS NVARCHAR(200)))), ''), "
                    f"NULLIF(LTRIM(RTRIM(CAST(dtl.{issue_dtl_ack_by_col} AS NVARCHAR(200)))), '')) AS AcknowBy"
                )
            else:
                ack_by_expr = (
                    f"NULLIF(LTRIM(RTRIM(CAST(dtl.{issue_dtl_ack_by_col} AS NVARCHAR(200)))), '') AS AcknowBy"
                )

        visit_join_sql = ""
        ward_expr = "NULL AS WardName"
        visit_table = _resolve_table_name(conn, ["Visit", "visit", "Visit_Mst", "VisitMst"])
        if visit_table and visit_expr != "NULL":
            visit_id_col = _resolve_column(conn, visit_table, ["VisitId", "VisitID", "Visit_Id", "ID", "Id"])
            ward_id_col = _resolve_column(conn, visit_table, ["WardId", "WardID", "Ward_Id", "CurrentWardId", "CurrentWardID"])
            if visit_id_col:
                visit_join_sql = f"LEFT JOIN dbo.{visit_table} v WITH (NOLOCK) ON v.{visit_id_col} = {visit_expr}"
                if ward_id_col:
                    ward_expr = f"CASE WHEN v.{ward_id_col} IS NULL THEN NULL ELSE dbo.Fn_Ward_Name(v.{ward_id_col}) END AS WardName"

        where_sql = [f"ind.{indent_date_col} >= ?", f"ind.{indent_date_col} < DATEADD(DAY, 1, ?)"]
        if indent_cancel_col:
            where_sql.append(f"ISNULL(ind.{indent_cancel_col}, 0) = 0")
        where_clause = " AND ".join(where_sql)

        if issue_date_col:
            order_expr = f"ind.{indent_date_col} DESC, im.{issue_date_col} DESC, im.{issue_id_col} DESC"
        else:
            order_expr = f"ind.{indent_date_col} DESC, im.{issue_id_col} DESC"
        if issue_dtl_id_col:
            order_expr += f", dtl.{issue_dtl_id_col} DESC"

        sql = f"""
            SET NOCOUNT ON;
            SELECT
                ind.{indent_id_col} AS IndentID,
                {indent_no_expr},
                ind.{indent_date_col} AS IndentDate,
                im.{issue_id_col} AS IssueId,
                {issue_no_expr},
                {issue_date_expr},
                {issue_dtl_id_expr},
                {visit_expr} AS VisitId,
                {patient_expr} AS PatientId,
                {patient_name_expr},
                {reg_no_expr},
                {ward_expr},
                {item_id_expr},
                {item_code_expr},
                {item_name_expr},
                {issue_qty_expr},
                {ack_status_expr},
                {ack_by_expr},
                {ack_dt_expr},
                {tat_indent_issue_expr},
                {tat_issue_ack_expr},
                {tat_indent_ack_expr}
            FROM dbo.{issue_mst_table} im WITH (NOLOCK)
            INNER JOIN dbo.{indent_table} ind WITH (NOLOCK)
                ON im.{issue_indent_col} = ind.{indent_id_col}
            INNER JOIN dbo.{issue_dtl_table} dtl WITH (NOLOCK)
                ON dtl.{issue_dtl_issue_col} = im.{issue_id_col}
            {item_join_sql}
            {user_join_sql}
            {visit_join_sql}
            WHERE {where_clause}
            ORDER BY {order_expr}
        """

        df = pd.read_sql(sql, conn, params=[from_date, to_date])
        if df is None or df.empty:
            return df
        df.columns = [c.strip() for c in df.columns]
        df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"Pharmacy ward TAT fetch failed for {unit}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Pharmacy: Departmental Issue =====================
def fetch_pharmacy_departmental_issue_rows(
    unit: str,
    from_date: str,
    to_date: str,
    store_id: int | None = None,
):
    """
    Fetch departmental issue / return rows at Department + Item + Batch + Store grain.
    Uses lower-level stock movement rows (ISD/RFD) and resolves department from
    patient issue / material return context when available.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Pharmacy departmental issue: could not connect to {unit}")
        return None

    def _q_ident(name: str) -> str:
        return "[" + str(name or "").replace("]", "]]") + "]"

    try:
        issue_table = _resolve_table_name(conn, ["SMUser_Issue"])
        issue_dtl_table = _resolve_table_name(conn, ["SMUser_Issue_Details"])
        store_table = _resolve_table_name(conn, ["Store", "store"])
        item_table = _resolve_table_name(conn, ["IVItem", "IvItem"])
        batch_table = _resolve_table_name(conn, ["IVBatch", "IvBatch"])
        department_table = _resolve_table_name(conn, ["Department_mst", "Department_Mst", "department_mst"])

        if not issue_table or not issue_dtl_table or not store_table or not item_table:
            print(
                "Pharmacy departmental issue: missing required tables "
                f"(issue={issue_table}, issue_dtl={issue_dtl_table}, store={store_table}, item={item_table})"
            )
            return None

        issue_id_col = _resolve_column(conn, issue_table, ["Issue_Id", "IssueId", "IssueID", "ID", "Id"])
        issue_number_col = _resolve_column(conn, issue_table, ["Issue_Number", "IssueNo", "IssueNO"])
        issue_date_col = _resolve_column(conn, issue_table, ["IssueDate", "Issue_Date"])
        issue_to_store_col = _resolve_column(conn, issue_table, ["StoreId", "StoreID", "Store_Id"])
        issue_from_store_col = _resolve_column(conn, issue_table, ["FromStoreId", "FromStoreID", "FromStore_Id"])

        dtl_issue_id_col = _resolve_column(conn, issue_dtl_table, ["Issue_Id", "IssueId", "IssueID"])
        dtl_item_col = _resolve_column(conn, issue_dtl_table, ["Itemid", "ItemID", "ItemId"])
        dtl_batch_col = _resolve_column(conn, issue_dtl_table, ["Batchid", "BatchID", "BatchId"])
        dtl_qty_col = _resolve_column(conn, issue_dtl_table, ["IssuedQuantity", "IssueQty", "Qty", "Quantity"])
        dtl_rate_col = _resolve_column(conn, issue_dtl_table, ["Rate"])

        store_id_col = _resolve_column(conn, store_table, ["ID", "Id", "StoreID", "StoreId"])
        store_name_col = _resolve_column(conn, store_table, ["Name", "StoreName"])
        store_dept_col = _resolve_column(conn, store_table, ["DepartmentID", "DepartmentId", "Department_Id", "DeptID", "DeptId"])

        item_id_col = _resolve_column(conn, item_table, ["ID", "Id", "ItemID", "ItemId"])
        item_name_col = _resolve_column(conn, item_table, ["Name", "ItemName", "DescriptiveName"])

        batch_id_col = _resolve_column(conn, batch_table, ["ID", "Id", "BatchID", "BatchId"]) if batch_table else None
        batch_name_col = _resolve_column(conn, batch_table, ["Name", "BatchName"]) if batch_table else None
        batch_mrp_col = _resolve_column(conn, batch_table, ["MRP", "Mrp"]) if batch_table else None

        department_id_col = _resolve_column(conn, department_table, ["Department_ID", "DepartmentID", "DepartmentId", "DeptID", "DeptId", "ID", "Id"]) if department_table else None
        department_name_col = _resolve_column(conn, department_table, ["Department_Name", "DepartmentName", "Department", "DeptName", "Dept", "Name"]) if department_table else None

        if not all([issue_id_col, issue_date_col, issue_to_store_col, issue_from_store_col, dtl_issue_id_col, dtl_item_col, dtl_batch_col, dtl_qty_col, store_id_col, store_name_col, item_id_col, item_name_col]):
            print("Pharmacy departmental issue: missing required columns in SM issue/store/item tables")
            return None

        try:
            store_id_val = int(store_id) if store_id is not None and str(store_id).strip() else None
        except Exception:
            store_id_val = None
        if store_id_val not in {None, 2, 3}:
            store_id_val = None

        issue_number_expr = f"s.{_q_ident(issue_number_col)}" if issue_number_col else f"CONVERT(NVARCHAR(50), s.{_q_ident(issue_id_col)})"
        rate_expr = f"ISNULL(d.{_q_ident(dtl_rate_col)}, 0)" if dtl_rate_col else "0"
        mrp_expr = f"ISNULL(b.{_q_ident(batch_mrp_col)}, 0)" if batch_table and batch_mrp_col else "0"
        batch_name_expr = f"LTRIM(RTRIM(CONVERT(NVARCHAR(80), ISNULL(b.{_q_ident(batch_name_col)}, N''))))" if batch_table and batch_name_col else "N''"
        if department_table and department_id_col and department_name_col and store_dept_col:
            dept_name_expr = (
                f"COALESCE("
                f"NULLIF(CASE "
                f"WHEN dept.{_q_ident(department_name_col)} IS NULL THEN NULL "
                f"WHEN LOWER(LTRIM(RTRIM(CAST(dept.{_q_ident(department_name_col)} AS NVARCHAR(200))))) LIKE N'%pharmacy%' THEN NULL "
                f"ELSE LTRIM(RTRIM(CAST(dept.{_q_ident(department_name_col)} AS NVARCHAR(200)))) END, N''), "
                f"NULLIF(LTRIM(RTRIM(CAST(st_to.{_q_ident(store_name_col)} AS NVARCHAR(200)))), N''), "
                f"N'Unknown Department')"
            )
        else:
            dept_name_expr = f"COALESCE(NULLIF(LTRIM(RTRIM(CAST(st_to.{_q_ident(store_name_col)} AS NVARCHAR(200)))), N''), N'Unknown Department')"
        dept_id_expr = (
            f"ISNULL(st_to.{_q_ident(store_dept_col)}, 0)"
            if store_dept_col
            else "0"
        )

        sql = f"""
            SET NOCOUNT ON;

            SELECT
                CAST({dept_id_expr} AS INT) AS DepartmentID,
                CAST({dept_name_expr} AS NVARCHAR(200)) AS DepartmentName,
                CAST(s.{_q_ident(issue_to_store_col)} AS INT) AS IssuedToStoreID,
                CAST(LTRIM(RTRIM(ISNULL(st_to.{_q_ident(store_name_col)}, N''))) AS NVARCHAR(120)) AS IssuedToStoreName,
                CAST(s.{_q_ident(issue_from_store_col)} AS INT) AS IssuedFromStoreID,
                CAST(LTRIM(RTRIM(ISNULL(st_from.{_q_ident(store_name_col)}, N''))) AS NVARCHAR(120)) AS IssuedFromStoreName,
                CAST(i.{_q_ident(item_id_col)} AS INT) AS ItemID,
                CAST(LTRIM(RTRIM(ISNULL(i.{_q_ident(item_name_col)}, N''))) AS NVARCHAR(200)) AS ItemName,
                CAST(ISNULL(d.{_q_ident(dtl_batch_col)}, 0) AS INT) AS BatchID,
                CAST({batch_name_expr} AS NVARCHAR(80)) AS BatchName,
                CAST(MAX(ISNULL({rate_expr}, 0)) AS DECIMAL(18, 4)) AS Rate,
                CAST(MAX(ISNULL({mrp_expr}, 0)) AS DECIMAL(18, 4)) AS MRP,
                CAST(SUM(ISNULL(d.{_q_ident(dtl_qty_col)}, 0)) AS DECIMAL(18, 3)) AS IssuedQty,
                CAST(0 AS DECIMAL(18, 3)) AS ReturnedQty,
                CAST(SUM(ISNULL(d.{_q_ident(dtl_qty_col)}, 0)) AS DECIMAL(18, 3)) AS NetIssuedQty,
                CAST(SUM(ISNULL(d.{_q_ident(dtl_qty_col)}, 0) * ISNULL({rate_expr}, 0)) AS DECIMAL(18, 2)) AS IssuedValueRate,
                CAST(0 AS DECIMAL(18, 2)) AS ReturnedValueRate,
                CAST(SUM(ISNULL(d.{_q_ident(dtl_qty_col)}, 0) * ISNULL({rate_expr}, 0)) AS DECIMAL(18, 2)) AS NetValueRate,
                CAST(MAX(s.{_q_ident(issue_date_col)}) AS DATETIME) AS LastMovementDate,
                CAST(MAX({issue_number_expr}) AS NVARCHAR(60)) AS IssueNumber
            FROM dbo.{_q_ident(issue_table)} s WITH (NOLOCK)
            INNER JOIN dbo.{_q_ident(issue_dtl_table)} d WITH (NOLOCK)
                ON d.{_q_ident(dtl_issue_id_col)} = s.{_q_ident(issue_id_col)}
            LEFT JOIN dbo.{_q_ident(store_table)} st_to WITH (NOLOCK)
                ON st_to.{_q_ident(store_id_col)} = s.{_q_ident(issue_to_store_col)}
            LEFT JOIN dbo.{_q_ident(store_table)} st_from WITH (NOLOCK)
                ON st_from.{_q_ident(store_id_col)} = s.{_q_ident(issue_from_store_col)}
            LEFT JOIN dbo.{_q_ident(item_table)} i WITH (NOLOCK)
                ON i.{_q_ident(item_id_col)} = d.{_q_ident(dtl_item_col)}
            {"LEFT JOIN dbo." + _q_ident(batch_table) + " b WITH (NOLOCK) ON b." + _q_ident(batch_id_col) + " = d." + _q_ident(dtl_batch_col) if batch_table and batch_id_col else ""}
            {"LEFT JOIN dbo." + _q_ident(department_table) + " dept WITH (NOLOCK) ON dept." + _q_ident(department_id_col) + " = st_to." + _q_ident(store_dept_col) if department_table and department_id_col and department_name_col and store_dept_col else ""}
            WHERE
                s.{_q_ident(issue_date_col)} >= ?
                AND s.{_q_ident(issue_date_col)} < DATEADD(DAY, 1, ?)
                AND s.{_q_ident(issue_from_store_col)} IN (2, 3)
                AND (? IS NULL OR s.{_q_ident(issue_from_store_col)} = ?)
            GROUP BY
                {dept_id_expr},
                {dept_name_expr},
                s.{_q_ident(issue_to_store_col)},
                st_to.{_q_ident(store_name_col)},
                s.{_q_ident(issue_from_store_col)},
                st_from.{_q_ident(store_name_col)},
                i.{_q_ident(item_id_col)},
                i.{_q_ident(item_name_col)},
                d.{_q_ident(dtl_batch_col)},
                {batch_name_expr}
            ORDER BY
                s.{_q_ident(issue_from_store_col)},
                {dept_name_expr},
                st_to.{_q_ident(store_name_col)},
                i.{_q_ident(item_name_col)},
                {batch_name_expr};
        """

        df = pd.read_sql(sql, conn, params=[from_date, to_date, store_id_val, store_id_val])
        if df is None or df.empty:
            return df
        df.columns = [str(c).strip() for c in df.columns]
        df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"Pharmacy departmental issue fetch failed for {unit}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def add_iv_po_mst_with_autonumber(
    unit: str,
    params: dict,
    lock_timeout_ms: int = 10000,
    conn=None,
    manage_transaction: bool | None = None,
):
    """
    Generates a new PO number under an app lock, then creates PO master.
    """
    own_conn = conn is None
    db_conn = conn or get_sql_connection(unit)
    if not db_conn:
        return {"error": f"Could not connect to {unit}"}
    if manage_transaction is None:
        manage_transaction = own_conn
    cursor = db_conn.cursor()
    lock_resource = f"IVPO_NO_{(unit or '').strip().upper()}"
    po_no = None
    po_table_name = None
    po_id_col = None
    po_no_col = None
    try:
        po_table_name = _resolve_table_name(db_conn, ["IVPoMst", "IvPoMst", "IVPO_MST", "IV_Po_Mst"])
        if po_table_name:
            po_id_col = _resolve_column(db_conn, po_table_name, ["ID", "Id"]) or "ID"
            po_no_col = _resolve_column(db_conn, po_table_name, ["PONo", "PoNo", "PO_No"]) or "PONo"
        po_id_match_expr = (
            f"LTRIM(RTRIM(CAST([{po_id_col}] AS NVARCHAR(50))))"
            if po_id_col
            else ""
        )

        def _fetch_saved_po_no(target_po_id: int) -> str:
            if not po_table_name or not po_id_col or not po_no_col:
                return ""
            cur = None
            try:
                cur = db_conn.cursor()
                cur.execute(
                    f"""
                    SELECT TOP 1 [{po_no_col}]
                    FROM dbo.[{po_table_name}]
                    WHERE {po_id_match_expr} = ?
                    """,
                    (str(int(target_po_id)),),
                )
                row = cur.fetchone()
                return str(row[0] or "").strip() if row else ""
            except Exception:
                return ""
            finally:
                try:
                    if cur is not None:
                        cur.close()
                except Exception:
                    pass

        def _set_saved_po_no_if_blank(target_po_id: int, po_no_value: str) -> bool:
            if not po_no_value or not po_table_name or not po_id_col or not po_no_col:
                return False
            cur = None
            try:
                cur = db_conn.cursor()
                cur.execute(
                    f"""
                    UPDATE dbo.[{po_table_name}]
                    SET [{po_no_col}] = ?
                    WHERE {po_id_match_expr} = ?
                      AND NULLIF(LTRIM(RTRIM(CAST([{po_no_col}] AS NVARCHAR(100)))), '') IS NULL
                    """,
                    (po_no_value, str(int(target_po_id))),
                )
                if manage_transaction:
                    db_conn.commit()
                return True
            except Exception:
                if manage_transaction:
                    try:
                        db_conn.rollback()
                    except Exception:
                        pass
                return False
            finally:
                try:
                    if cur is not None:
                        cur.close()
                except Exception:
                    pass

        lock_result = _get_app_lock(cursor, lock_resource, lock_timeout_ms)
        if lock_result.get("error"):
            return lock_result
        cursor.execute("EXEC dbo.usp_GetIvPONo")
        row = _cursor_fetchone_safe(cursor)
        try:
            while cursor.nextset():
                pass
        except Exception:
            pass
        po_no = str(row[0]) if row and row[0] is not None else None
        if not po_no:
            return {"error": "Failed to generate PO number"}
        params = dict(params or {})
        params["pPono"] = po_no
        params = _trim_po_mst_params(db_conn, params)
        sql = """
        EXEC dbo.usp_addIVPoMst
            @pId=?,
            @pSupplierid=?,
            @pTenderid=?,
            @pPono=?,
            @pPodate=?,
            @pDeliveryterms=?,
            @pPaymentsterms=?,
            @pOtherterms=?,
            @pTaxid=?,
            @pTax=?,
            @pDiscount=?,
            @pAmount=?,
            @pCreditdays=?,
            @pPocomplete=?,
            @pNotes=?,
            @pPreparedby=?,
            @pCustom1=?,
            @pCustom2=?,
            @pUpdatedby=?,
            @pUpdatedon=?,
            @pSignauthorityperson=?,
            @pSignauthoritypdesig=?,
            @pRefno=?,
            @pSubject=?,
            @pAuthorizationid=?,
            @pPurchaseIndentId=?,
            @pInsertedByUserID=?,
            @pInsertedON=?,
            @pInsertedMacName=?,
            @pInsertedMacID=?,
            @pInsertedIPAddress=?,
            @Against=?,
            @QuotationId=?,
            @TotalFORe=?,
            @TotalExciseAmt=?,
            @AgainstId=?,
            @Status=?
        """
        values = [
            params.get("pId"),
            params.get("pSupplierid"),
            params.get("pTenderid"),
            params.get("pPono"),
            params.get("pPodate"),
            params.get("pDeliveryterms"),
            params.get("pPaymentsterms"),
            params.get("pOtherterms"),
            params.get("pTaxid"),
            params.get("pTax"),
            params.get("pDiscount"),
            params.get("pAmount"),
            params.get("pCreditdays"),
            params.get("pPocomplete"),
            params.get("pNotes"),
            params.get("pPreparedby"),
            params.get("pCustom1"),
            params.get("pCustom2"),
            params.get("pUpdatedby"),
            params.get("pUpdatedon"),
            params.get("pSignauthorityperson"),
            params.get("pSignauthoritypdesig"),
            params.get("pRefno"),
            params.get("pSubject"),
            params.get("pAuthorizationid"),
            params.get("pPurchaseIndentId"),
            params.get("pInsertedByUserID"),
            params.get("pInsertedON"),
            params.get("pInsertedMacName"),
            params.get("pInsertedMacID"),
            params.get("pInsertedIPAddress"),
            params.get("Against"),
            params.get("QuotationId"),
            params.get("TotalFORe"),
            params.get("TotalExciseAmt"),
            params.get("AgainstId"),
            params.get("Status"),
        ]
        insert_cursor = db_conn.cursor()
        try:
            insert_cursor.execute(sql, values)
            row = _cursor_fetchone_safe(insert_cursor)
        finally:
            _cursor_drain_and_close(insert_cursor)
        po_id = None
        if row and row[0] is not None:
            try:
                po_id = int(row[0])
            except Exception:
                po_id = row[0]
        if po_id:
            saved_po_no = _fetch_saved_po_no(int(po_id))
            if not saved_po_no and po_no:
                _set_saved_po_no_if_blank(int(po_id), str(po_no))
                saved_po_no = _fetch_saved_po_no(int(po_id))
            final_po_no = str(saved_po_no or po_no or "").strip()
            _update_iv_po_mst_purchasing_dept_conn(
                db_conn,
                int(po_id),
                params.get("PurchasingDeptId"),
                manage_transaction=False,
            )
            _update_iv_po_mst_special_notes_conn(
                db_conn,
                int(po_id),
                params.get("pSpecialNotes"),
                manage_transaction=False,
            )
            _update_iv_po_mst_cmc_amc_warranty_conn(
                db_conn,
                int(po_id),
                params.get("pCmcAmcWarrantyNotes"),
                manage_transaction=False,
            )
            if "OverallDiscountMode" in params:
                _update_iv_po_mst_overall_discount_mode_conn(
                    db_conn,
                    int(po_id),
                    params.get("OverallDiscountMode"),
                    manage_transaction=False,
                )
            if "OverallDiscountValue" in params:
                _update_iv_po_mst_overall_discount_value_conn(
                    db_conn,
                    int(po_id),
                    params.get("OverallDiscountValue"),
                    manage_transaction=False,
                )
            if "POPrintFormat" in params:
                _update_iv_po_mst_print_format_conn(
                    db_conn,
                    int(po_id),
                    params.get("POPrintFormat"),
                    manage_transaction=False,
                )
            if "WorkOrderBodyHtml" in params:
                _update_iv_po_mst_work_order_body_html_conn(
                    db_conn,
                    int(po_id),
                    params.get("WorkOrderBodyHtml"),
                    manage_transaction=False,
                )
            _update_iv_po_mst_senior_approval_authority_conn(
                db_conn,
                int(po_id),
                params.get("SeniorApprovalAuthorityName"),
                manage_transaction=False,
            )
            _update_iv_po_mst_senior_approval_designation_conn(
                db_conn,
                int(po_id),
                params.get("SeniorApprovalAuthorityDesignation"),
                manage_transaction=False,
            )
            if manage_transaction:
                db_conn.commit()
            return {"po_id": int(po_id), "po_no": final_po_no}
        return {"po_id": None, "po_no": str(po_no or "").strip()}
    except Exception as e:
        if manage_transaction:
            try:
                db_conn.rollback()
            except Exception:
                pass
        return {"error": str(e)}
    finally:
        _release_app_lock(cursor, lock_resource)
        try:
            cursor.close()
        except Exception:
            pass
        if own_conn:
            try:
                db_conn.close()
            except Exception:
                pass


def ensure_purchase_po_number(unit: str, po_id: int, preferred_po_no: str | None = None, lock_timeout_ms: int = 10000):
    """
    Ensures IVPoMst has a non-empty PO number for the provided PO ID.
    """
    try:
        target_po_id = int(po_id)
    except Exception:
        return {"error": "Invalid PO ID"}
    if target_po_id <= 0:
        return {"error": "Invalid PO ID"}

    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Could not connect to {unit}"}

    cursor = conn.cursor()
    lock_resource = f"IVPO_NO_{(unit or '').strip().upper()}"
    lock_acquired = False
    try:
        po_table_name = _resolve_table_name(conn, ["IVPoMst", "IvPoMst", "IVPO_MST", "IV_Po_Mst"])
        if not po_table_name:
            return {"error": "IVPoMst table not found"}
        po_id_col = _resolve_column(conn, po_table_name, ["ID", "Id"]) or "ID"
        po_no_col = _resolve_column(conn, po_table_name, ["PONo", "PoNo", "PO_No"]) or "PONo"
        po_id_match_expr = f"LTRIM(RTRIM(CAST([{po_id_col}] AS NVARCHAR(50))))"

        def _fetch_saved_po_no() -> str:
            try:
                cur = conn.cursor()
                cur.execute(
                    f"""
                    SELECT TOP 1 [{po_no_col}]
                    FROM dbo.[{po_table_name}]
                    WHERE {po_id_match_expr} = ?
                    """,
                    (str(target_po_id),),
                )
                row = cur.fetchone()
                return str(row[0] or "").strip() if row else ""
            except Exception:
                return ""

        current_po_no = _fetch_saved_po_no()
        if current_po_no:
            return {"po_no": current_po_no, "updated": False}

        po_no_value = str(preferred_po_no or "").strip()
        if not po_no_value:
            lock_result = _get_app_lock(cursor, lock_resource, lock_timeout_ms)
            if lock_result.get("error"):
                return lock_result
            lock_acquired = True
            cursor.execute("EXEC dbo.usp_GetIvPONo")
            row = cursor.fetchone()
            po_no_value = str(row[0] or "").strip() if row and row[0] is not None else ""
            if not po_no_value:
                return {"error": "Failed to generate PO number"}

        cur = conn.cursor()
        cur.execute(
            f"""
            UPDATE dbo.[{po_table_name}]
            SET [{po_no_col}] = ?
            WHERE {po_id_match_expr} = ?
              AND NULLIF(LTRIM(RTRIM(CAST([{po_no_col}] AS NVARCHAR(100)))), '') IS NULL
            """,
            (po_no_value, str(target_po_id)),
        )
        try:
            updated = int(cur.rowcount or 0) > 0
        except Exception:
            updated = False
        try:
            conn.commit()
        except Exception:
            pass

        saved_po_no = _fetch_saved_po_no()
        final_po_no = str(saved_po_no or po_no_value).strip()
        return {"po_no": final_po_no, "updated": updated}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        if lock_acquired:
            _release_app_lock(cursor, lock_resource)
        try:
            conn.close()
        except Exception:
            pass


def ensure_work_order_number(unit: str, wo_id: int, preferred_wo_no: str | None = None):
    """
    Ensures IVPoMst stores a Work Order number and DocumentType for the given record.
    """
    try:
        target_wo_id = int(wo_id)
    except Exception:
        return {"error": "Invalid Work Order ID"}
    if target_wo_id <= 0:
        return {"error": "Invalid Work Order ID"}

    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Could not connect to {unit}"}
    try:
        if not _ensure_iv_po_mst_document_type_column_conn(conn):
            return {"error": "DocumentType column not available"}
        table_name, id_col, po_no_col, doc_type_col = _resolve_iv_po_mst_meta(conn)
        if not table_name:
            return {"error": "IVPoMst table not found"}
        wo_no_value = str(preferred_wo_no or "").strip() or f"WO-{target_wo_id}"
        if len(wo_no_value) > 100:
            wo_no_value = wo_no_value[:100]
        cur = conn.cursor()
        cur.execute(
            f"""
            UPDATE dbo.[{table_name}]
            SET [{po_no_col}] = ?,
                [{doc_type_col or 'DocumentType'}] = 'WO'
            WHERE [{id_col}] = ?
            """,
            (wo_no_value, target_wo_id),
        )
        conn.commit()
        return {"wo_no": wo_no_value, "updated": True}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Pharmacy: Itemwise Consumption =====================
def fetch_pharmacy_itemwise_consumption(
    unit: str,
    from_date: str,
    to_date: str,
    doc_type: str | None = None,
    doc_id: int | None = None,
):
    """
    Calls dbo.usp_Itemwiseconsumption @FromDate, @ToDate, @DocType, @DocId.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Pharmacy itemwise consumption: could not connect to {unit}")
        return None
    try:
        sql = "SET NOCOUNT ON; EXEC dbo.usp_Itemwiseconsumption @FromDate=?, @ToDate=?, @DocType=?, @DocId=?"
        params = [
            from_date,
            to_date,
            (doc_type.strip().upper() if doc_type else None),
            doc_id,
        ]
        df = pd.read_sql(sql, conn, params=params)
        if df is None or df.empty:
            return df
        df.columns = [c.strip() for c in df.columns]
        df["Unit"] = (unit or "").upper()
        return df
    except Exception as e:
        print(f"Pharmacy itemwise consumption fetch failed for {unit}: {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


