# ===================== Blood Bank Service-wise Billing =====================
def fetch_bloodbank_service_billing(unit: str, from_date: str, to_date: str):
    """
    Returns combined Blood Bank billing + order rows:
    - Billing rows via dbo.Usp_ServiceWiseBilling_BloodBank
    - Order rows via OrderMst/OrderDtl (+ User_Mst tracking)

    Notes:
    - Order rows include pending/shifted/cancelled status markers.
    - Order date window is anchored to OrderMst.OrdDateTime.
      Shifted/Billing dates are still surfaced in columns for audit trail.
    - Blood Bank service filter is unit-specific for known units:
      AHL -> (2598,2596,2600,4801,2599,6658,2004,2597,662842,6605)
      ACI -> (2598,2596,2600,4801,2599,6658,2004,2597,5535)
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for blood bank service-wise billing")
        return None
    try:
        unit_key = (unit or "").strip().upper()
        shared_ids = (2598, 2596, 2600, 4801, 2599, 6658, 2004, 2597)
        unit_service_ids = {
            "AHL": shared_ids + (662842, 6605),
            "ACI": shared_ids + (5535,),
        }
        bloodbank_service_ids = unit_service_ids.get(unit_key, shared_ids + (6605, 5535))
        bloodbank_service_ids_sql = ",".join(str(int(v)) for v in bloodbank_service_ids)

        billing_frames = []
        billing_sql = "SET NOCOUNT ON; EXEC dbo.Usp_ServiceWiseBilling_BloodBank @fromdate=?, @todate=?"
        # For AHL/ACI we rely on explicit ID-mapped SQL below to avoid cross-unit ID mismatch.
        if unit_key not in {"AHL", "ACI"}:
            try:
                billing_sp_df = pd.read_sql(billing_sql, conn, params=[from_date, to_date])
                if billing_sp_df is not None and not billing_sp_df.empty:
                    billing_sp_df.columns = [c.strip() for c in billing_sp_df.columns]
                    billing_frames.append(billing_sp_df)
            except Exception as sp_err:
                print(f"Blood bank SP fallback engaged for {unit}: {sp_err}")

        billing_fallback_sql = f"""
            SET NOCOUNT ON;

            SELECT
                v.TypeOfVisit AS TypeOfVisit,
                dbo.fn_patientfullname(v.PatientID) AS Patient,
                dbo.fn_regno(v.PatientID) AS RegNo,
                v.VisitNo AS VisitNo,
                s.Service_Name,
                CAST(bd.Rate AS DECIMAL(18,2)) AS Rate,
                CAST(bd.Quantity AS DECIMAL(18,2)) AS Quantity,
                s.Category_Id,
                v.PatientID,
                dbo.Fn_subDept(s.SubDepartmentId) AS Sub_Dept,
                bm.BillDate,
                v.VisitDate,
                v.DischargeDate
            FROM dbo.Billing_Mst bm WITH (NOLOCK)
            INNER JOIN dbo.BillingDetails bd WITH (NOLOCK)
                ON bm.Bill_ID = bd.Bill_ID
            LEFT JOIN dbo.Service_Mst s WITH (NOLOCK)
                ON bd.ServiceID = s.Service_ID
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = bm.Visit_ID
            WHERE bm.BillDate >= ?
              AND bm.BillDate < DATEADD(DAY, 1, ?)
              AND bm.BillType = 'P'
              AND bd.ServiceID IN ({bloodbank_service_ids_sql})
        """
        billing_fb_df = pd.read_sql(billing_fallback_sql, conn, params=[from_date, to_date])
        if billing_fb_df is not None and not billing_fb_df.empty:
            billing_fb_df.columns = [c.strip() for c in billing_fb_df.columns]
            billing_frames.append(billing_fb_df)

        billing_df = pd.concat(billing_frames, ignore_index=True, copy=False) if billing_frames else pd.DataFrame()
        if billing_df is not None and not billing_df.empty:
            billing_df.columns = [c.strip() for c in billing_df.columns]
            billing_df["RecordSource"] = "BILLING"
            billing_df["OrderStatus"] = "Billed"
            billing_df["PendingToBillingFlag"] = 0

        order_sql = """
            SET NOCOUNT ON;

            SELECT
                v.TypeOfVisit AS TypeOfVisit,
                dbo.fn_patientfullname(pctx.EffectivePatientID) AS Patient,
                dbo.fn_regno(pctx.EffectivePatientID) AS RegNo,
                v.VisitNo AS VisitNo,
                s.Service_Name,
                CAST(COALESCE(NULLIF(od.ServiceAmount, 0), bill_line.BillRate, 0) AS DECIMAL(18,2)) AS Rate,
                CAST(COALESCE(NULLIF(od.OrdQty, 0), bill_line.BillQty, 0) AS DECIMAL(18,2)) AS Quantity,
                s.Category_Id,
                pctx.EffectivePatientID AS PatientID,
                dbo.Fn_subDept(s.SubDepartmentId) AS Sub_Dept,
                bm.BillDate,
                v.VisitDate,
                v.DischargeDate,
                om.OrdId AS OrderId,
                om.OrdNo AS OrderNo,
                om.OrdVoucherNo AS OrderVoucherNo,
                om.OrdDateTime AS OrderDateTime,
                od.OrdDtlID AS OrderDetailId,
                od.ServBilled,
                od.ServBillId,
                CASE
                    WHEN ISNULL(od.Cancelled, 0) = 1 OR ISNULL(om.OrdCanceled, 0) = 1 THEN 1
                    ELSE 0
                END AS IsOrderCancelled,
                COALESCE(od.CancelDateTime, CASE WHEN ISNULL(om.OrdCanceled, 0) = 1 THEN om.UpdatedOn END) AS OrderCancelledAt,
                COALESCE(NULLIF(uc.UserName, ''), CAST(om.InsertedByUserID AS NVARCHAR(80))) AS OrderCreatedBy,
                COALESCE(NULLIF(udc.UserName, ''), NULLIF(umc.UserName, ''), CAST(COALESCE(od.CanceledBy, om.OrdCanceledBy) AS NVARCHAR(80))) AS OrderCancelledBy,
                bm.BillDate AS ShiftedToBillingDate,
                CASE
                    WHEN ISNULL(od.Cancelled, 0) = 1 OR ISNULL(om.OrdCanceled, 0) = 1 THEN 'Cancelled'
                    WHEN ISNULL(od.ServBilled, 0) = 1 OR od.ServBillId IS NOT NULL THEN 'Shifted to Billing'
                    ELSE 'Pending Billing'
                END AS OrderStatus,
                CASE
                    WHEN ISNULL(od.Cancelled, 0) = 1 OR ISNULL(om.OrdCanceled, 0) = 1 THEN 0
                    WHEN ISNULL(od.ServBilled, 0) = 1 OR od.ServBillId IS NOT NULL THEN 0
                    ELSE 1
                END AS PendingToBillingFlag,
                CAST(COALESCE(NULLIF(od.NetAmount, 0),
                        COALESCE(NULLIF(od.ServiceAmount, 0), bill_line.BillRate, 0) * COALESCE(NULLIF(od.OrdQty, 0), bill_line.BillQty, 0), 0) AS DECIMAL(18,2)) AS Amount,
                CASE
                    WHEN ISNULL(od.Cancelled, 0) = 1 OR ISNULL(om.OrdCanceled, 0) = 1
                        THEN CONCAT('Cancelled on ', CONVERT(VARCHAR(16), COALESCE(od.CancelDateTime, om.UpdatedOn), 120))
                    WHEN ISNULL(od.ServBilled, 0) = 1 OR od.ServBillId IS NOT NULL
                        THEN CONCAT('Ordered ', CONVERT(VARCHAR(16), om.OrdDateTime, 120), ' -> Shifted ', CONVERT(VARCHAR(16), bm.BillDate, 120))
                    ELSE CONCAT('Pending since ', CONVERT(VARCHAR(16), om.OrdDateTime, 120))
                END AS ShiftHistory,
                'ORDER' AS RecordSource
            FROM dbo.OrderMst om WITH (NOLOCK)
            INNER JOIN dbo.OrderDtl od WITH (NOLOCK)
                ON om.OrdId = od.OrdID
            LEFT JOIN dbo.Visit v WITH (NOLOCK)
                ON v.Visit_ID = om.OrdVisitID
            LEFT JOIN dbo.Service_Mst s WITH (NOLOCK)
                ON od.ServiceId = s.Service_ID
            LEFT JOIN dbo.Billing_Mst bm WITH (NOLOCK)
                ON bm.Bill_ID = od.ServBillId
            OUTER APPLY (
                SELECT COALESCE(NULLIF(v.PatientID, 0), NULLIF(om.OrdPatientID, 0), NULLIF(od.PatientId, 0)) AS EffectivePatientID
            ) pctx
            OUTER APPLY (
                SELECT TOP 1
                    CAST(bd.Rate AS DECIMAL(18,2)) AS BillRate,
                    CAST(bd.Quantity AS DECIMAL(18,2)) AS BillQty
                FROM dbo.BillingDetails bd WITH (NOLOCK)
                WHERE bd.Bill_ID = od.ServBillId
                  AND bd.ServiceID = od.ServiceId
            ) bill_line
            LEFT JOIN dbo.User_Mst uc WITH (NOLOCK)
                ON uc.UserID = om.InsertedByUserID
            LEFT JOIN dbo.User_Mst umc WITH (NOLOCK)
                ON umc.UserID = om.OrdCanceledBy
            LEFT JOIN dbo.User_Mst udc WITH (NOLOCK)
                ON udc.UserID = od.CanceledBy
            WHERE od.ServiceId IN ({bloodbank_service_ids_sql})
              AND om.OrdDateTime >= ?
              AND om.OrdDateTime < DATEADD(DAY, 1, ?)
        """.format(bloodbank_service_ids_sql=bloodbank_service_ids_sql)
        order_df = pd.read_sql(
            order_sql,
            conn,
            params=[from_date, to_date],
        )
        if order_df is not None and not order_df.empty:
            order_df.columns = [c.strip() for c in order_df.columns]

        frames = []
        if billing_df is not None and not billing_df.empty:
            frames.append(billing_df)
        if order_df is not None and not order_df.empty:
            frames.append(order_df)

        if not frames:
            return pd.DataFrame()

        combined = pd.concat(frames, ignore_index=True, copy=False)
        combined.columns = [c.strip() for c in combined.columns]
        combined["Unit"] = (unit or "").upper()

        # Prefer enriched ORDER rows over plain BILLING rows when both represent same billed item.
        def _norm_text(v):
            return str(v or "").strip().upper()

        def _dedupe_key(row):
            return (
                _norm_text(row.get("RegNo")),
                _norm_text(row.get("VisitNo")),
                _norm_text(row.get("Service_Name")),
                _norm_text(row.get("BillDate")),
                round(float(pd.to_numeric(row.get("Quantity"), errors="coerce") or 0.0), 3),
                round(float(pd.to_numeric(row.get("Rate"), errors="coerce") or 0.0), 2),
                _norm_text(row.get("TypeOfVisit")),
            )

        if not combined.empty:
            src_series = combined.get("RecordSource", pd.Series([""] * len(combined), index=combined.index))
            src_series = src_series.astype(str).str.strip().str.upper()
            combined["_src_priority"] = src_series.map(lambda s: 0 if s == "ORDER" else 1)
            combined["_dedupe_key"] = combined.apply(_dedupe_key, axis=1)
            combined = (
                combined.sort_values(["_src_priority"])
                .drop_duplicates(subset=["_dedupe_key"], keep="first")
                .drop(columns=["_src_priority", "_dedupe_key"], errors="ignore")
                .reset_index(drop=True)
            )

            # Second-pass reconciliation:
            # if an ORDER row is already shifted to billing, hide matching BILLING-only row.
            def _date_only(v):
                dt = pd.to_datetime(v, errors="coerce")
                if pd.notna(dt):
                    return dt.strftime("%Y-%m-%d")
                s = str(v or "").strip()
                return s[:10] if len(s) >= 10 else s

            def _to_float(v, default=0.0):
                num = pd.to_numeric(v, errors="coerce")
                if pd.isna(num):
                    return float(default)
                return float(num)

            def _to_int(v, default=0):
                num = pd.to_numeric(v, errors="coerce")
                if pd.isna(num):
                    return int(default)
                return int(num)

            def _num(v, places):
                return round(_to_float(v, 0.0), places)

            def _recon_amount(row):
                amt = _to_float(row.get("Amount"), float("nan"))
                if not pd.isna(amt):
                    return round(amt, 2)
                return round(
                    _num(row.get("Quantity"), 3) * _num(row.get("Rate"), 2),
                    2,
                )

            def _recon_key(row):
                return (
                    _norm_text(row.get("RegNo")),
                    _to_int(row.get("PatientID"), 0),
                    _norm_text(row.get("VisitNo")),
                    _norm_text(row.get("Service_Name")),
                    _date_only(row.get("BillDate")),
                    _num(row.get("Quantity"), 3),
                    _recon_amount(row),
                )

            def _patient_token(row):
                reg = _norm_text(row.get("RegNo"))
                if reg:
                    return f"REG:{reg}"
                pid = _to_int(row.get("PatientID"), 0)
                if pid > 0:
                    return f"PID:{pid}"
                pname = _norm_text(row.get("Patient"))
                if pname:
                    return f"PAT:{pname}"
                return ""

            def _loose_key(row):
                return (
                    _patient_token(row),
                    _norm_text(row.get("VisitNo")),
                    _norm_text(row.get("Service_Name")),
                    _date_only(row.get("BillDate")),
                )

            src_series = combined.get("RecordSource", pd.Series([""] * len(combined), index=combined.index))
            src_series = src_series.astype(str).str.strip().str.upper()
            status_series = combined.get("OrderStatus", pd.Series([""] * len(combined), index=combined.index))
            status_series = status_series.astype(str).str.strip().str.lower()
            serv_billed = pd.to_numeric(
                combined.get("ServBilled", pd.Series([0] * len(combined), index=combined.index)),
                errors="coerce",
            ).fillna(0).astype(int)
            serv_bill_id = pd.to_numeric(
                combined.get("ServBillId", pd.Series([0] * len(combined), index=combined.index)),
                errors="coerce",
            ).fillna(0).astype(int)

            shifted_order_mask = (
                src_series.eq("ORDER")
                & (serv_billed.eq(1) | serv_bill_id.gt(0) | status_series.str.contains("shift"))
            )
            if shifted_order_mask.any():
                billing_mask = src_series.eq("BILLING")
                shifted_idx = combined.index[shifted_order_mask].tolist()
                billing_idx = combined.index[billing_mask].tolist()

                def _group_by_key(indices, key_fn):
                    grouped = {}
                    for ridx in indices:
                        key = key_fn(combined.loc[ridx])
                        grouped.setdefault(key, []).append(ridx)
                    return grouped

                consumed_shifted = set()
                drop_idx = set()

                # Pass 1: strict pair matching (includes qty/amount).
                strict_shifted = _group_by_key(shifted_idx, _recon_key)
                strict_billing = _group_by_key(billing_idx, _recon_key)
                for key, s_rows in strict_shifted.items():
                    b_rows = strict_billing.get(key, [])
                    pair_count = min(len(s_rows), len(b_rows))
                    if pair_count <= 0:
                        continue
                    consumed_shifted.update(s_rows[:pair_count])
                    drop_idx.update(b_rows[:pair_count])

                # Pass 2: fallback loose matching for remaining pairs (patient+visit+service+bill date).
                rem_shifted = [r for r in shifted_idx if r not in consumed_shifted]
                rem_billing = [r for r in billing_idx if r not in drop_idx]
                loose_shifted = _group_by_key(rem_shifted, _loose_key)
                loose_billing = _group_by_key(rem_billing, _loose_key)
                for key, s_rows in loose_shifted.items():
                    patient_key, visit_key, service_key, bill_date_key = key
                    if not patient_key or not service_key or not bill_date_key:
                        continue
                    b_rows = loose_billing.get(key, [])
                    pair_count = min(len(s_rows), len(b_rows))
                    if pair_count <= 0:
                        continue
                    drop_idx.update(b_rows[:pair_count])

                if drop_idx:
                    combined = combined.drop(index=list(drop_idx)).reset_index(drop=True)
        return combined
    except Exception as e:
        print(f"Error fetching blood bank service-wise billing ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ===================== Billwise Doctor Share =====================
def _billwise_doctorshare_parse_int(raw_value, default: int, minimum: int | None = None, maximum: int | None = None) -> int:
    try:
        value = int(float(raw_value))
    except Exception:
        value = int(default)
    if minimum is not None:
        value = max(minimum, value)
    if maximum is not None:
        value = min(maximum, value)
    return value


def _billwise_doctorshare_jsonify_rows(rows):
    out = []
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        clean = {}
        for key, value in row.items():
            if isinstance(value, Decimal):
                clean[key] = float(value)
            else:
                clean[key] = value
        out.append(clean)
    return out


def _fetch_billwise_doctorshare_page_legacy(
    unit: str,
    from_date: str,
    to_date: str,
    doc_id: int,
    vtype: int,
    page: int = 1,
    page_size: int = 20,
    search_query: str = "",
    include_summary: bool = True,
):
    """
    Fetch paged billwise doctor share data directly from SQL Server.
    Summary/totals are computed server-side; only the requested detail page is returned.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for paged billwise doctor share")
        return None
    try:
        page = _billwise_doctorshare_parse_int(page, 1, 1, None)
        page_size = _billwise_doctorshare_parse_int(page_size, 20, 1, 200)
        search_text = str(search_query or "").strip().lower()
        include_summary_flag = 1 if include_summary else 0

        sql = """
        SET NOCOUNT ON;

        DECLARE @FromDate DATETIME = ?;
        DECLARE @ToDate DATETIME = ?;
        DECLARE @DocId INT = ?;
        DECLARE @VisitType INT = ?;
        DECLARE @Search NVARCHAR(250) = ?;
        DECLARE @Page INT = ?;
        DECLARE @PageSize INT = ?;
        DECLARE @IncludeSummary BIT = ?;

        IF (@FromDate > @ToDate)
        BEGIN
            DECLARE @tmp DATETIME = @FromDate;
            SET @FromDate = @ToDate;
            SET @ToDate = @tmp;
        END;

        SET @Search = LOWER(LTRIM(RTRIM(ISNULL(@Search, ''))));
        SET @Page = CASE WHEN @Page < 1 THEN 1 ELSE @Page END;
        SET @PageSize = CASE WHEN @PageSize < 1 THEN 20 WHEN @PageSize > 200 THEN 200 ELSE @PageSize END;

        DECLARE @ToDateNextDay DATETIME = DATEADD(DAY, 1, CONVERT(DATE, @ToDate));

        ;WITH Base AS
        (
            SELECT
                  v.TypeOfVisit
                , bm.Registration_No
                , bm.BillNo
                , bm.BillDate
                , s.Service_Name
                , bd.Amount
                , docid =
                    CASE v.VisitTypeID
                        WHEN 1 THEN CASE ISNULL(od.DocID, 0) WHEN 0 THEN om.OrdByDocID ELSE od.DocID END
                        WHEN 3 THEN CASE ISNULL(od.DocID, 0) WHEN 0 THEN om.OrdByDocID ELSE od.DocID END
                        ELSE CASE ISNULL(od.DocID, 0) WHEN 0 THEN v.DocInCharge ELSE od.DocID END
                    END
                , v.PatientID
                , vtype = v.VisitTypeID
                , pt.PatientType
                , BillQty = bd.Quantity
                , Rate = bd.Rate
                , v.VisitDate
                , v.DischargeDate
                , v.subdocid
                , DoctorInChargeId = v.DocInCharge
            FROM dbo.Billing_Mst bm
            INNER JOIN dbo.Visit v
                ON v.Visit_ID = bm.Visit_ID
            INNER JOIN dbo.BillingDetails bd
                ON bd.Bill_ID = bm.Bill_ID
            LEFT JOIN dbo.Service_Mst s
                ON s.Service_ID = bd.ServiceID
            LEFT JOIN dbo.OrderDtl od
                ON od.OrdDtlID = bd.OrderDtlId
            LEFT JOIN dbo.OrderMst om
                ON om.OrdId = od.OrdID
            LEFT JOIN dbo.PatientType_mst pt
                ON pt.PatientType_ID = v.PatientType_ID
            WHERE
                bm.CancelStatus = 'false'
                AND bm.BillType = 'P'
                AND s.Category_Id IN (1, 36, 67)
                AND bm.BillDate >= @FromDate
                AND bm.BillDate < @ToDateNextDay
                AND ISNULL(bd.Amount, 0) > 0
        )
        SELECT
              TypeOfVisit
            , Registration_No
            , BillNo
            , BillDate
            , Service_Name
            , Amount
            , DocIdResolved = docid
            , PatientID
            , VisitTypeId = vtype
            , PatientType
            , BillQty
            , Rate
            , VisitDate
            , DischargeDate
            , SecondaryDocId = subdocid
            , DoctorInChargeId
        INTO #DoctorShareData
        FROM Base
        WHERE
            (@DocId = 0 OR docid = @DocId)
            AND (@VisitType = 0 OR vtype = @VisitType);

        SELECT
              TotalRecords = CAST(COUNT(1) AS INT)
            , TotalQuantity = CAST(ISNULL(SUM(CAST(BillQty AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
            , TotalRevenue = CAST(ISNULL(SUM(CAST(Amount AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
        FROM #DoctorShareData;

        IF (@IncludeSummary = 1)
        BEGIN
            SELECT
                  Service_Name = ISNULL(NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(250), Service_Name))), ''), 'Unknown')
                , Quantity = CAST(ISNULL(SUM(CAST(BillQty AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
                , Revenue = CAST(ISNULL(SUM(CAST(Amount AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
                , Records = CAST(COUNT(1) AS INT)
            FROM #DoctorShareData
            GROUP BY ISNULL(NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(250), Service_Name))), ''), 'Unknown')
            ORDER BY Revenue DESC, Service_Name ASC;
        END
        ELSE
        BEGIN
            SELECT
                  CAST(NULL AS NVARCHAR(250)) AS Service_Name
                , CAST(NULL AS DECIMAL(18, 2)) AS Quantity
                , CAST(NULL AS DECIMAL(18, 2)) AS Revenue
                , CAST(NULL AS INT) AS Records
            WHERE 1 = 0;
        END;

        DECLARE @SearchLike NVARCHAR(260) = CASE WHEN @Search = '' THEN NULL ELSE '%' + @Search + '%' END;
        DECLARE @FilteredRecords INT;
        DECLARE @TotalPages INT;
        DECLARE @EffectivePage INT;

        IF (@SearchLike IS NULL)
        BEGIN
            SELECT @FilteredRecords = COUNT(1)
            FROM #DoctorShareData;

            SET @FilteredRecords = ISNULL(@FilteredRecords, 0);
            SET @TotalPages = CASE WHEN @FilteredRecords <= 0 THEN 1 ELSE CAST(CEILING(@FilteredRecords * 1.0 / @PageSize) AS INT) END;
            SET @EffectivePage = CASE WHEN @Page > @TotalPages THEN @TotalPages ELSE @Page END;

            SELECT
                  Page = @EffectivePage
                , PageSize = @PageSize
                , FilteredRecords = @FilteredRecords
                , TotalPages = @TotalPages;

            ;WITH Numbered AS
            (
                SELECT
                      BillDate
                    , BillNo
                    , Registration_No
                    , PatientID
                    , PatientType
                    , TypeOfVisit
                    , DocIdResolved
                    , DoctorInChargeId
                    , SecondaryDocId
                    , Service_Name
                    , BillQty
                    , Rate
                    , Amount
                    , VisitDate
                    , DischargeDate
                    , RowNum = ROW_NUMBER() OVER (ORDER BY BillDate, BillNo, Registration_No)
                FROM #DoctorShareData
            )
            SELECT
                  BillDate
                , BillNo
                , Registration_No
                , PatientName = dbo.fn_PatientFullName(PatientID)
                , PatientType
                , TypeOfVisit
                , DoctorName = dbo.fn_DoctorFirstName(DocIdResolved)
                , DoctorInCharge = dbo.fn_DoctorFirstName(DoctorInChargeId)
                , SecondaryDoc = dbo.fn_DoctorFirstName(SecondaryDocId)
                , Service_Name
                , BillQty
                , Rate
                , Amount
                , VisitDate
                , DischargeDate
            FROM Numbered
            WHERE RowNum BETWEEN ((@EffectivePage - 1) * @PageSize) + 1 AND (@EffectivePage * @PageSize)
            ORDER BY RowNum;
        END
        ELSE
        BEGIN
            SELECT
                  BillDate
                , BillNo
                , Registration_No
                , PatientName = dbo.fn_PatientFullName(PatientID)
                , PatientType
                , TypeOfVisit
                , DoctorName = dbo.fn_DoctorFirstName(DocIdResolved)
                , DoctorInCharge = dbo.fn_DoctorFirstName(DoctorInChargeId)
                , SecondaryDoc = dbo.fn_DoctorFirstName(SecondaryDocId)
                , Service_Name
                , BillQty
                , Rate
                , Amount
                , VisitDate
                , DischargeDate
                , SearchText = LOWER(CONCAT(
                      ISNULL(CONVERT(NVARCHAR(10), BillDate, 23), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(60), BillNo), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(60), Registration_No), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_PatientFullName(PatientID)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(100), PatientType), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(100), TypeOfVisit), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_DoctorFirstName(DocIdResolved)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_DoctorFirstName(DoctorInChargeId)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_DoctorFirstName(SecondaryDocId)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(250), Service_Name), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(50), BillQty), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(50), Rate), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(50), Amount), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(10), VisitDate, 23), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(10), DischargeDate, 23), '')
                  ))
            INTO #DoctorShareSearch
            FROM #DoctorShareData;

            SELECT @FilteredRecords = COUNT(1)
            FROM #DoctorShareSearch
            WHERE SearchText LIKE @SearchLike;

            SET @FilteredRecords = ISNULL(@FilteredRecords, 0);
            SET @TotalPages = CASE WHEN @FilteredRecords <= 0 THEN 1 ELSE CAST(CEILING(@FilteredRecords * 1.0 / @PageSize) AS INT) END;
            SET @EffectivePage = CASE WHEN @Page > @TotalPages THEN @TotalPages ELSE @Page END;

            SELECT
                  Page = @EffectivePage
                , PageSize = @PageSize
                , FilteredRecords = @FilteredRecords
                , TotalPages = @TotalPages;

            SELECT
                  BillDate
                , BillNo
                , Registration_No
                , PatientName
                , PatientType
                , TypeOfVisit
                , DoctorName
                , DoctorInCharge
                , SecondaryDoc
                , Service_Name
                , BillQty
                , Rate
                , Amount
                , VisitDate
                , DischargeDate
            FROM #DoctorShareSearch
            WHERE SearchText LIKE @SearchLike
            ORDER BY BillDate, BillNo, Registration_No
            OFFSET ((@EffectivePage - 1) * @PageSize) ROWS
            FETCH NEXT @PageSize ROWS ONLY;
        END;
        """

        cursor = conn.cursor()
        cursor.execute(
            sql,
            [
                from_date,
                to_date,
                int(doc_id or 0),
                int(vtype or 0),
                search_text,
                int(page),
                int(page_size),
                int(include_summary_flag),
            ],
        )

        result_sets = []
        while True:
            if cursor.description:
                result_sets.append(_corp_bill_summary_dict_rows_from_cursor(cursor))
            if not cursor.nextset():
                break
        try:
            cursor.close()
        except Exception:
            pass

        totals_rows = result_sets[0] if len(result_sets) > 0 else []
        summary_rows = result_sets[1] if len(result_sets) > 1 else []
        meta_rows = result_sets[2] if len(result_sets) > 2 else []
        detail_rows = result_sets[3] if len(result_sets) > 3 else []

        totals_rec = dict(totals_rows[0] or {}) if totals_rows else {}
        meta_rec = dict(meta_rows[0] or {}) if meta_rows else {}

        total_records = _billwise_doctorshare_parse_int(totals_rec.get("TotalRecords"), 0, 0, None)
        filtered_records = _billwise_doctorshare_parse_int(meta_rec.get("FilteredRecords"), total_records, 0, None)
        total_pages = _billwise_doctorshare_parse_int(meta_rec.get("TotalPages"), 1, 1, None)
        current_page = _billwise_doctorshare_parse_int(meta_rec.get("Page"), page, 1, total_pages)
        current_page_size = _billwise_doctorshare_parse_int(meta_rec.get("PageSize"), page_size, 1, 200)

        total_quantity = totals_rec.get("TotalQuantity") or 0
        total_revenue = totals_rec.get("TotalRevenue") or 0
        if isinstance(total_quantity, Decimal):
            total_quantity = float(total_quantity)
        else:
            total_quantity = float(total_quantity or 0)
        if isinstance(total_revenue, Decimal):
            total_revenue = float(total_revenue)
        else:
            total_revenue = float(total_revenue or 0)

        return {
            "page": int(current_page),
            "page_size": int(current_page_size),
            "total_records": int(total_records),
            "filtered_records": int(filtered_records),
            "total_pages": int(total_pages),
            "total_quantity": float(total_quantity),
            "total_revenue": float(total_revenue),
            "service_summary": _billwise_doctorshare_jsonify_rows(summary_rows),
            "details": _billwise_doctorshare_jsonify_rows(detail_rows),
            "search_query": search_text,
        }
    except Exception as e:
        print(f"Error fetching paged billwise doctor share ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _fetch_billwise_doctorshare_page_full(
    unit: str,
    from_date: str,
    to_date: str,
    doc_id: int,
    vtype: int,
    page: int = 1,
    page_size: int = 20,
    search_query: str = "",
    include_summary: bool = True,
):
    """
    Optimized paged doctor share fetch.
    Uses visit-type-specific SQL branches so doctor filtering is pushed deeper into the base scan.
    """
    conn = get_sql_connection(unit)
    if not conn:
        print(f"Could not connect to {unit} for paged billwise doctor share")
        return None
    try:
        page = _billwise_doctorshare_parse_int(page, 1, 1, None)
        page_size = _billwise_doctorshare_parse_int(page_size, 20, 1, 200)
        visit_type = _billwise_doctorshare_parse_int(vtype, 0, 0, None)
        search_text = str(search_query or "").strip().lower()
        include_summary_flag = 1 if include_summary else 0

        if visit_type in {1, 3}:
            base_source_sql = f"""
                SELECT
                      v.TypeOfVisit
                    , bm.Registration_No
                    , bm.BillNo
                    , bm.BillDate
                    , s.Service_Name
                    , bd.Amount
                    , DocIdResolved = CASE ISNULL(od.DocID, 0) WHEN 0 THEN om.OrdByDocID ELSE od.DocID END
                    , v.PatientID
                    , VisitTypeId = v.VisitTypeID
                    , pt.PatientType
                    , BillQty = bd.Quantity
                    , Rate = bd.Rate
                    , v.VisitDate
                    , v.DischargeDate
                    , SecondaryDocId = v.subdocid
                    , DoctorInChargeId = v.DocInCharge
                FROM dbo.Billing_Mst bm
                INNER JOIN dbo.Visit v
                    ON v.Visit_ID = bm.Visit_ID
                INNER JOIN dbo.BillingDetails bd
                    ON bd.Bill_ID = bm.Bill_ID
                INNER JOIN dbo.Service_Mst s
                    ON s.Service_ID = bd.ServiceID
                   AND s.Category_Id IN (1, 36, 67)
                LEFT JOIN dbo.OrderDtl od
                    ON od.OrdDtlID = bd.OrderDtlId
                LEFT JOIN dbo.OrderMst om
                    ON om.OrdId = od.OrdID
                LEFT JOIN dbo.PatientType_mst pt
                    ON pt.PatientType_ID = v.PatientType_ID
                WHERE
                    bm.CancelStatus = 'false'
                    AND bm.BillType = 'P'
                    AND bm.BillDate >= @FromDate
                    AND bm.BillDate < @ToDateNextDay
                    AND ISNULL(bd.Amount, 0) > 0
                    AND v.VisitTypeID = {visit_type}
                    AND (@DocId = 0 OR CASE ISNULL(od.DocID, 0) WHEN 0 THEN om.OrdByDocID ELSE od.DocID END = @DocId)
            """
        elif visit_type in {2, 6}:
            base_source_sql = f"""
                SELECT
                      v.TypeOfVisit
                    , bm.Registration_No
                    , bm.BillNo
                    , bm.BillDate
                    , s.Service_Name
                    , bd.Amount
                    , DocIdResolved = CASE ISNULL(od.DocID, 0) WHEN 0 THEN v.DocInCharge ELSE od.DocID END
                    , v.PatientID
                    , VisitTypeId = v.VisitTypeID
                    , pt.PatientType
                    , BillQty = bd.Quantity
                    , Rate = bd.Rate
                    , v.VisitDate
                    , v.DischargeDate
                    , SecondaryDocId = v.subdocid
                    , DoctorInChargeId = v.DocInCharge
                FROM dbo.Billing_Mst bm
                INNER JOIN dbo.Visit v
                    ON v.Visit_ID = bm.Visit_ID
                INNER JOIN dbo.BillingDetails bd
                    ON bd.Bill_ID = bm.Bill_ID
                INNER JOIN dbo.Service_Mst s
                    ON s.Service_ID = bd.ServiceID
                   AND s.Category_Id IN (1, 36, 67)
                LEFT JOIN dbo.OrderDtl od
                    ON od.OrdDtlID = bd.OrderDtlId
                LEFT JOIN dbo.PatientType_mst pt
                    ON pt.PatientType_ID = v.PatientType_ID
                WHERE
                    bm.CancelStatus = 'false'
                    AND bm.BillType = 'P'
                    AND bm.BillDate >= @FromDate
                    AND bm.BillDate < @ToDateNextDay
                    AND ISNULL(bd.Amount, 0) > 0
                    AND v.VisitTypeID = {visit_type}
                    AND (@DocId = 0 OR CASE ISNULL(od.DocID, 0) WHEN 0 THEN v.DocInCharge ELSE od.DocID END = @DocId)
            """
        else:
            base_source_sql = """
                SELECT
                      v.TypeOfVisit
                    , bm.Registration_No
                    , bm.BillNo
                    , bm.BillDate
                    , s.Service_Name
                    , bd.Amount
                    , DocIdResolved = CASE ISNULL(od.DocID, 0) WHEN 0 THEN om.OrdByDocID ELSE od.DocID END
                    , v.PatientID
                    , VisitTypeId = v.VisitTypeID
                    , pt.PatientType
                    , BillQty = bd.Quantity
                    , Rate = bd.Rate
                    , v.VisitDate
                    , v.DischargeDate
                    , SecondaryDocId = v.subdocid
                    , DoctorInChargeId = v.DocInCharge
                FROM dbo.Billing_Mst bm
                INNER JOIN dbo.Visit v
                    ON v.Visit_ID = bm.Visit_ID
                INNER JOIN dbo.BillingDetails bd
                    ON bd.Bill_ID = bm.Bill_ID
                INNER JOIN dbo.Service_Mst s
                    ON s.Service_ID = bd.ServiceID
                   AND s.Category_Id IN (1, 36, 67)
                LEFT JOIN dbo.OrderDtl od
                    ON od.OrdDtlID = bd.OrderDtlId
                LEFT JOIN dbo.OrderMst om
                    ON om.OrdId = od.OrdID
                LEFT JOIN dbo.PatientType_mst pt
                    ON pt.PatientType_ID = v.PatientType_ID
                WHERE
                    bm.CancelStatus = 'false'
                    AND bm.BillType = 'P'
                    AND bm.BillDate >= @FromDate
                    AND bm.BillDate < @ToDateNextDay
                    AND ISNULL(bd.Amount, 0) > 0
                    AND v.VisitTypeID IN (1, 3)
                    AND (@DocId = 0 OR CASE ISNULL(od.DocID, 0) WHEN 0 THEN om.OrdByDocID ELSE od.DocID END = @DocId)

                UNION ALL

                SELECT
                      v.TypeOfVisit
                    , bm.Registration_No
                    , bm.BillNo
                    , bm.BillDate
                    , s.Service_Name
                    , bd.Amount
                    , DocIdResolved = CASE ISNULL(od.DocID, 0) WHEN 0 THEN v.DocInCharge ELSE od.DocID END
                    , v.PatientID
                    , VisitTypeId = v.VisitTypeID
                    , pt.PatientType
                    , BillQty = bd.Quantity
                    , Rate = bd.Rate
                    , v.VisitDate
                    , v.DischargeDate
                    , SecondaryDocId = v.subdocid
                    , DoctorInChargeId = v.DocInCharge
                FROM dbo.Billing_Mst bm
                INNER JOIN dbo.Visit v
                    ON v.Visit_ID = bm.Visit_ID
                INNER JOIN dbo.BillingDetails bd
                    ON bd.Bill_ID = bm.Bill_ID
                INNER JOIN dbo.Service_Mst s
                    ON s.Service_ID = bd.ServiceID
                   AND s.Category_Id IN (1, 36, 67)
                LEFT JOIN dbo.OrderDtl od
                    ON od.OrdDtlID = bd.OrderDtlId
                LEFT JOIN dbo.PatientType_mst pt
                    ON pt.PatientType_ID = v.PatientType_ID
                WHERE
                    bm.CancelStatus = 'false'
                    AND bm.BillType = 'P'
                    AND bm.BillDate >= @FromDate
                    AND bm.BillDate < @ToDateNextDay
                    AND ISNULL(bd.Amount, 0) > 0
                    AND ISNULL(v.VisitTypeID, 0) NOT IN (1, 3)
                    AND (@DocId = 0 OR CASE ISNULL(od.DocID, 0) WHEN 0 THEN v.DocInCharge ELSE od.DocID END = @DocId)
            """

        sql = f"""
        SET NOCOUNT ON;

        DECLARE @FromDate DATETIME = ?;
        DECLARE @ToDate DATETIME = ?;
        DECLARE @DocId INT = ?;
        DECLARE @Search NVARCHAR(250) = ?;
        DECLARE @Page INT = ?;
        DECLARE @PageSize INT = ?;
        DECLARE @IncludeSummary BIT = ?;

        IF (@FromDate > @ToDate)
        BEGIN
            DECLARE @tmp DATETIME = @FromDate;
            SET @FromDate = @ToDate;
            SET @ToDate = @tmp;
        END;

        SET @Search = LOWER(LTRIM(RTRIM(ISNULL(@Search, ''))));
        SET @Page = CASE WHEN @Page < 1 THEN 1 ELSE @Page END;
        SET @PageSize = CASE WHEN @PageSize < 1 THEN 20 WHEN @PageSize > 200 THEN 200 ELSE @PageSize END;

        DECLARE @ToDateNextDay DATETIME = DATEADD(DAY, 1, CONVERT(DATE, @ToDate));

        ;WITH Base AS
        (
{base_source_sql}
        )
        SELECT
              TypeOfVisit
            , Registration_No
            , BillNo
            , BillDate
            , Service_Name
            , Amount
            , DocIdResolved
            , PatientID
            , VisitTypeId
            , PatientType
            , BillQty
            , Rate
            , VisitDate
            , DischargeDate
            , SecondaryDocId
            , DoctorInChargeId
        INTO #DoctorShareData
        FROM Base;

        SELECT
              TotalRecords = CAST(COUNT(1) AS INT)
            , TotalQuantity = CAST(ISNULL(SUM(CAST(BillQty AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
            , TotalRevenue = CAST(ISNULL(SUM(CAST(Amount AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
        FROM #DoctorShareData;

        IF (@IncludeSummary = 1)
        BEGIN
            SELECT
                  Service_Name = ISNULL(NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(250), Service_Name))), ''), 'Unknown')
                , Quantity = CAST(ISNULL(SUM(CAST(BillQty AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
                , Revenue = CAST(ISNULL(SUM(CAST(Amount AS DECIMAL(18, 4))), 0) AS DECIMAL(18, 2))
                , Records = CAST(COUNT(1) AS INT)
            FROM #DoctorShareData
            GROUP BY ISNULL(NULLIF(LTRIM(RTRIM(CONVERT(NVARCHAR(250), Service_Name))), ''), 'Unknown')
            ORDER BY Revenue DESC, Service_Name ASC;
        END
        ELSE
        BEGIN
            SELECT
                  CAST(NULL AS NVARCHAR(250)) AS Service_Name
                , CAST(NULL AS DECIMAL(18, 2)) AS Quantity
                , CAST(NULL AS DECIMAL(18, 2)) AS Revenue
                , CAST(NULL AS INT) AS Records
            WHERE 1 = 0;
        END;

        DECLARE @SearchLike NVARCHAR(260) = CASE WHEN @Search = '' THEN NULL ELSE '%' + @Search + '%' END;
        DECLARE @FilteredRecords INT;
        DECLARE @TotalPages INT;
        DECLARE @EffectivePage INT;

        IF (@SearchLike IS NULL)
        BEGIN
            SELECT @FilteredRecords = COUNT(1)
            FROM #DoctorShareData;

            SET @FilteredRecords = ISNULL(@FilteredRecords, 0);
            SET @TotalPages = CASE WHEN @FilteredRecords <= 0 THEN 1 ELSE CAST(CEILING(@FilteredRecords * 1.0 / @PageSize) AS INT) END;
            SET @EffectivePage = CASE WHEN @Page > @TotalPages THEN @TotalPages ELSE @Page END;

            SELECT
                  Page = @EffectivePage
                , PageSize = @PageSize
                , FilteredRecords = @FilteredRecords
                , TotalPages = @TotalPages;

            ;WITH Numbered AS
            (
                SELECT
                      BillDate
                    , BillNo
                    , Registration_No
                    , PatientID
                    , PatientType
                    , TypeOfVisit
                    , DocIdResolved
                    , DoctorInChargeId
                    , SecondaryDocId
                    , Service_Name
                    , BillQty
                    , Rate
                    , Amount
                    , VisitDate
                    , DischargeDate
                    , RowNum = ROW_NUMBER() OVER (ORDER BY BillDate, BillNo, Registration_No)
                FROM #DoctorShareData
            )
            SELECT
                  BillDate
                , BillNo
                , Registration_No
                , PatientName = dbo.fn_PatientFullName(PatientID)
                , PatientType
                , TypeOfVisit
                , DoctorName = dbo.fn_DoctorFirstName(DocIdResolved)
                , DoctorInCharge = dbo.fn_DoctorFirstName(DoctorInChargeId)
                , SecondaryDoc = dbo.fn_DoctorFirstName(SecondaryDocId)
                , Service_Name
                , BillQty
                , Rate
                , Amount
                , VisitDate
                , DischargeDate
            FROM Numbered
            WHERE RowNum BETWEEN ((@EffectivePage - 1) * @PageSize) + 1 AND (@EffectivePage * @PageSize)
            ORDER BY RowNum;
        END
        ELSE
        BEGIN
            SELECT
                  BillDate
                , BillNo
                , Registration_No
                , PatientName = dbo.fn_PatientFullName(PatientID)
                , PatientType
                , TypeOfVisit
                , DoctorName = dbo.fn_DoctorFirstName(DocIdResolved)
                , DoctorInCharge = dbo.fn_DoctorFirstName(DoctorInChargeId)
                , SecondaryDoc = dbo.fn_DoctorFirstName(SecondaryDocId)
                , Service_Name
                , BillQty
                , Rate
                , Amount
                , VisitDate
                , DischargeDate
                , SearchText = LOWER(CONCAT(
                      ISNULL(CONVERT(NVARCHAR(10), BillDate, 23), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(60), BillNo), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(60), Registration_No), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_PatientFullName(PatientID)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(100), PatientType), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(100), TypeOfVisit), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_DoctorFirstName(DocIdResolved)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_DoctorFirstName(DoctorInChargeId)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(200), dbo.fn_DoctorFirstName(SecondaryDocId)), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(250), Service_Name), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(50), BillQty), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(50), Rate), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(50), Amount), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(10), VisitDate, 23), ''), ' '
                    , ISNULL(CONVERT(NVARCHAR(10), DischargeDate, 23), '')
                  ))
            INTO #DoctorShareSearch
            FROM #DoctorShareData;

            SELECT @FilteredRecords = COUNT(1)
            FROM #DoctorShareSearch
            WHERE SearchText LIKE @SearchLike;

            SET @FilteredRecords = ISNULL(@FilteredRecords, 0);
            SET @TotalPages = CASE WHEN @FilteredRecords <= 0 THEN 1 ELSE CAST(CEILING(@FilteredRecords * 1.0 / @PageSize) AS INT) END;
            SET @EffectivePage = CASE WHEN @Page > @TotalPages THEN @TotalPages ELSE @Page END;

            SELECT
                  Page = @EffectivePage
                , PageSize = @PageSize
                , FilteredRecords = @FilteredRecords
                , TotalPages = @TotalPages;

            SELECT
                  BillDate
                , BillNo
                , Registration_No
                , PatientName
                , PatientType
                , TypeOfVisit
                , DoctorName
                , DoctorInCharge
                , SecondaryDoc
                , Service_Name
                , BillQty
                , Rate
                , Amount
                , VisitDate
                , DischargeDate
            FROM #DoctorShareSearch
            WHERE SearchText LIKE @SearchLike
            ORDER BY BillDate, BillNo, Registration_No
            OFFSET ((@EffectivePage - 1) * @PageSize) ROWS
            FETCH NEXT @PageSize ROWS ONLY;
        END;
        """

        cursor = conn.cursor()
        cursor.execute(
            sql,
            [
                from_date,
                to_date,
                int(doc_id or 0),
                search_text,
                int(page),
                int(page_size),
                int(include_summary_flag),
            ],
        )

        result_sets = []
        while True:
            if cursor.description:
                result_sets.append(_corp_bill_summary_dict_rows_from_cursor(cursor))
            if not cursor.nextset():
                break
        try:
            cursor.close()
        except Exception:
            pass

        totals_rows = result_sets[0] if len(result_sets) > 0 else []
        summary_rows = result_sets[1] if len(result_sets) > 1 else []
        meta_rows = result_sets[2] if len(result_sets) > 2 else []
        detail_rows = result_sets[3] if len(result_sets) > 3 else []

        totals_rec = dict(totals_rows[0] or {}) if totals_rows else {}
        meta_rec = dict(meta_rows[0] or {}) if meta_rows else {}

        total_records = _billwise_doctorshare_parse_int(totals_rec.get("TotalRecords"), 0, 0, None)
        filtered_records = _billwise_doctorshare_parse_int(meta_rec.get("FilteredRecords"), total_records, 0, None)
        total_pages = _billwise_doctorshare_parse_int(meta_rec.get("TotalPages"), 1, 1, None)
        current_page = _billwise_doctorshare_parse_int(meta_rec.get("Page"), page, 1, total_pages)
        current_page_size = _billwise_doctorshare_parse_int(meta_rec.get("PageSize"), page_size, 1, 200)

        total_quantity = totals_rec.get("TotalQuantity") or 0
        total_revenue = totals_rec.get("TotalRevenue") or 0
        if isinstance(total_quantity, Decimal):
            total_quantity = float(total_quantity)
        else:
            total_quantity = float(total_quantity or 0)
        if isinstance(total_revenue, Decimal):
            total_revenue = float(total_revenue)
        else:
            total_revenue = float(total_revenue or 0)

        return {
            "page": int(current_page),
            "page_size": int(current_page_size),
            "total_records": int(total_records),
            "filtered_records": int(filtered_records),
            "total_pages": int(total_pages),
            "total_quantity": float(total_quantity),
            "total_revenue": float(total_revenue),
            "service_summary": _billwise_doctorshare_jsonify_rows(summary_rows),
            "details": _billwise_doctorshare_jsonify_rows(detail_rows),
            "search_query": search_text,
        }
    except Exception as e:
        print(f"Error fetching paged billwise doctor share ({unit}): {e}")
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass


_BILLWISE_DOCSHARE_SUMMARY_CACHE = {}
_BILLWISE_DOCSHARE_SUMMARY_CACHE_LOCK = Lock()
_BILLWISE_DOCSHARE_SUMMARY_CACHE_TTL_SECONDS = 300


def _billwise_doctorshare_summary_cache_key(unit: str, from_date: str, to_date: str, doc_id: int, vtype: int):
    return (
        str(unit or "").strip().upper(),
        str(from_date or "").strip()[:10],
        str(to_date or "").strip()[:10],
        int(doc_id or 0),
        int(vtype or 0),
    )


def _billwise_doctorshare_clone_summary_payload(payload: dict | None, page: int, page_size: int):
    payload = dict(payload or {})
    total_records = _billwise_doctorshare_parse_int(payload.get("total_records"), 0, 0, None)
    total_pages = 1 if total_records <= 0 else int((total_records + page_size - 1) / page_size)
    current_page = max(1, min(int(page or 1), total_pages))
    service_summary = [dict(row or {}) for row in (payload.get("service_summary") or [])]
    return {
        "page": int(current_page),
        "page_size": int(page_size),
        "total_records": int(total_records),
        "filtered_records": int(total_records),
        "total_pages": int(total_pages),
        "total_quantity": float(payload.get("total_quantity") or 0.0),
        "total_revenue": float(payload.get("total_revenue") or 0.0),
        "service_summary": service_summary,
        "details": [],
        "search_query": "",
        "has_next_page": bool(current_page < total_pages),
    }


